async fn post_enterprise_oidc_execute_validated_login(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<Value>,
) -> Result<Response, AdminError> {
    if let Some(field) = enterprise_oidc_execute_validated_login_forbidden_field(&request) {
        return Ok((
            StatusCode::BAD_REQUEST,
            Json(json!({
                "error": {
                    "code": "enterprise_oidc_raw_material_not_accepted",
                    "message": "OIDC validated-login executor accepts only server-side verified claim summaries, validation booleans, safe hashes, and local binding inputs.",
                    "field": field,
                    "secret_safe": true,
                    "raw_material_echoed": false,
                    "omitted_fields": enterprise_oidc_execute_validated_login_omitted_fields()
                }
            })),
        )
            .into_response());
    }

    let request: EnterpriseOidcExecuteValidatedLoginRequest = serde_json::from_value(request)
        .map_err(|_| {
            AdminError::bad_request(
                "request must match the bounded OIDC validated-login executor schema",
            )
        })?;
    let input = request.into_input()?;
    let jwks_validator = enterprise_oidc_jwks_validator_readback(&input);
    if !input.jwks_validation_passed {
        return Ok((
            StatusCode::BAD_REQUEST,
            Json(json!({
                "error": {
                    "code": "enterprise_oidc_jwks_validation_failed",
                    "message": "OIDC validated-login executor requires fixture-safe server-side JWKS validation metadata before local identity binding can execute.",
                    "secret_safe": true,
                    "raw_material_echoed": false,
                    "runtime_implemented": true,
                    "jwks_validator": jwks_validator,
                    "verified_subject_hash_source": input.verified_subject_hash_source,
                    "binding_executed": false,
                    "session_created": false,
                    "omitted_fields": enterprise_oidc_execute_validated_login_omitted_fields()
                }
            })),
        )
            .into_response());
    }

    let binding_input = EnterpriseIdentityBindingInput {
        provider_type: "oidc".to_string(),
        external_subject_hash: input.external_subject_hash.clone(),
        email: input.email.clone(),
        domain: input.domain.clone(),
        mapped_groups: input.mapped_groups.clone(),
        mapped_roles: input.mapped_roles.clone(),
        fixture_subject_summary_present: input.verified_claims_summary_present,
        apply: input.apply,
    };
    let binding_result = execute_enterprise_identity_binding(
        state.db(),
        &session,
        binding_input,
        "POST /admin/enterprise/identity-connections/oidc/execute-validated-login",
        "enterprise_identity.oidc_validated_login_binding_apply",
        "admin_enterprise_oidc_validated_login_executor",
    )
    .await?;

    Ok(Json(json!({
        "data": {
            "schema": "enterprise_oidc_validated_login_execution.v1",
            "tenant_id": session.tenant_id(),
            "provider_type": "oidc",
            "status": enterprise_oidc_execute_validated_login_status(&binding_result),
            "secret_safe": true,
            "runtime_implemented": true,
            "mockable_executor": true,
            "server_side_simulated_input": true,
            "network_requests": false,
            "token_endpoint_called": false,
            "jwks_fetched": false,
            "raw_tokens_accepted": false,
            "raw_code_accepted": false,
            "raw_claims_accepted": false,
            "client_secret_accepted": false,
            "authorization_header_accepted": false,
            "verified_claims_summary": {
                "issuer_present": input.issuer_present,
                "subject_hash_present": true,
                "email_present": input.email.is_some(),
                "domain": input.domain,
                "audience_client_id_present": input.audience_client_id_present,
                "nonce_valid": input.nonce_valid,
                "expiration_valid": input.expiration_valid,
                "issued_at_checked": input.issued_at_checked,
                "mapped_group_count": input.mapped_groups.len(),
                "mapped_role_count": input.mapped_roles.len(),
                "fixture_summary_present": input.verified_claims_summary_present,
                "raw_subject_returned": false,
                "raw_email_returned": false,
                "raw_claim_values_returned": false
            },
            "jwks_validation_result": true,
            "jwks_validator": jwks_validator,
            "jwt_jwks_parser_fetch_adapter": input.jwt_jwks_parser_fetch_adapter.clone(),
            "jwt_jwks_crypto_parser_result": input.jwt_jwks_crypto_parser_result.clone(),
            "verified_subject_hash_source": input.verified_subject_hash_source,
            "binding_result": binding_result,
            "session_creation_disabled": true,
            "session_created": false,
            "session_blocked_reason": "validated-login executor is limited to local user_identity binding readback/apply; real session creation stays disabled until a reviewed session path is wired.",
            "omitted_fields": enterprise_oidc_execute_validated_login_omitted_fields(),
            "next_step": "Use apply=true only to bind an existing local user_identity. Wire reviewed session creation later after replacing simulated JWKS validation with a real server-side validator."
        }
    }))
    .into_response())
}

async fn post_enterprise_oidc_jwks_validator_executor(
    Extension(session): Extension<AdminSession>,
    Json(request): Json<Value>,
) -> Result<Response, AdminError> {
    if let Some(field) = enterprise_oidc_execute_validated_login_forbidden_field(&request) {
        return Ok((
            StatusCode::BAD_REQUEST,
            Json(json!({
                "error": {
                    "code": "enterprise_oidc_raw_material_not_accepted",
                    "message": "OIDC/JWKS validator executor accepts only fixture-safe JWT header/claims summaries, safe hashes, key fingerprint presence, and signature verification booleans.",
                    "field": field,
                    "secret_safe": true,
                    "raw_material_echoed": false,
                    "omitted_fields": enterprise_oidc_execute_validated_login_omitted_fields()
                }
            })),
        )
            .into_response());
    }

    let request: EnterpriseOidcExecuteValidatedLoginRequest = serde_json::from_value(request)
        .map_err(|_| {
            AdminError::bad_request(
                "request must match the bounded OIDC/JWKS validator executor schema",
            )
        })?;
    let input = request.into_input()?;
    let validator_result = enterprise_oidc_jwks_validator_readback(&input);
    let blocked_reasons = input.jwks_validation_failure_reasons.clone();
    let validator_passed = input.jwks_validation_passed;
    let identity_binding_handoff = enterprise_identity_binding_handoff_readback(
        "oidc",
        validator_passed,
        &blocked_reasons,
        true,
        input.issuer_present,
        input.audience_client_id_present,
        input.verified_group_count,
        input.verified_role_count,
        input.domain.is_some(),
        input.verified_claims_summary_present,
    );
    let session_issue_handoff = enterprise_identity_session_issue_handoff_readback(
        "oidc",
        validator_passed,
        &blocked_reasons,
        false,
        true,
        input.issuer_present,
        input.audience_client_id_present,
        input.verified_group_count,
        input.verified_role_count,
        input.domain.is_some(),
        "oidc_mock_executor",
    );

    Ok(Json(json!({
        "data": {
            "schema": "enterprise_oidc_jwks_validator_executor.v1",
            "tenant_id": session.tenant_id(),
            "provider_type": "oidc",
            "status": if validator_passed { "validator-passed" } else { "validator-blocked" },
            "secret_safe": true,
            "runtime_implemented": true,
            "mockable_executor": true,
            "network_enabled": false,
            "network_call_performed": false,
            "idp_network_called": false,
            "jwks_fetched": false,
            "raw_token_accepted": false,
            "raw_claims_accepted": false,
            "jwks_or_jwk_body_accepted": false,
            "client_secret_accepted": false,
            "authorization_header_accepted": false,
            "private_key_or_certificate_accepted": false,
            "validator_result": validator_result,
            "blocked_reasons": blocked_reasons,
            "identity_binding_handoff": identity_binding_handoff,
            "session_issue_handoff": session_issue_handoff,
            "binding_handoff_readiness": {
                "ready": validator_passed,
                "handoff_target": "POST /admin/enterprise/identity-connections/oidc/execute-validated-login",
                "requires_external_subject_hash": true,
                "external_subject_hash_present": true,
                "requires_existing_local_user_for_apply": true,
                "binding_executed": false,
                "blocked_reasons": if validator_passed { json!([]) } else { json!(input.jwks_validation_failure_reasons) }
            },
            "session_handoff_readiness": {
                "ready": false,
                "handoff_target": "POST /admin/enterprise/identity-sessions/issue-plan",
                "requires_bound_user_identity": true,
                "requires_reviewed_session_path": true,
                "session_creation_disabled": true,
                "session_created": false,
                "blocked_reasons": if validator_passed {
                    json!(["safe_oidc_session_creation_path_not_enabled"])
                } else {
                    json!(["validator_blocked"])
                }
            },
            "omitted_fields": enterprise_oidc_execute_validated_login_omitted_fields(),
            "next_step": if validator_passed {
                "Use this fixture-safe validator result as the handoff readiness signal for execute-validated-login; real IdP/JWKS network validation remains unwired."
            } else {
                "Fix the fixture-safe kid/alg/audience/issuer/exp/nonce/signature/key-fingerprint metadata before local binding or session handoff."
            }
        }
    }))
    .into_response())
}

