async fn post_enterprise_saml_execute_validated_acs(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<Value>,
) -> Result<Response, AdminError> {
    if let Some(field) = enterprise_saml_execute_validated_acs_forbidden_field(&request) {
        return Ok((
            StatusCode::BAD_REQUEST,
            Json(json!({
                "error": {
                    "code": "enterprise_saml_raw_material_not_accepted",
                    "message": "SAML validated ACS executor accepts only simulated successful validation booleans, safe subject hashes, local binding inputs, and fixture-safe verified assertion summaries.",
                    "field": field,
                    "secret_safe": true,
                    "raw_material_echoed": false,
                    "omitted_fields": enterprise_saml_execute_validated_acs_omitted_fields()
                }
            })),
        )
            .into_response());
    }

    let request: EnterpriseSamlExecuteValidatedAcsRequest = serde_json::from_value(request)
        .map_err(|_| {
            AdminError::bad_request(
                "request must match the bounded SAML validated ACS executor schema",
            )
        })?;
    let tenant_id = session.tenant_id();
    let executor_input = request.into_input()?;
    if !executor_input.validator_passed {
        let identity_binding_handoff = enterprise_identity_binding_handoff_readback(
            "saml",
            false,
            &executor_input.blocked_reasons,
            true,
            executor_input.issuer_validation_result,
            executor_input.audience_validation_result,
            executor_input.verified_group_count,
            executor_input.verified_role_count,
            executor_input.domain.is_some(),
            executor_input.fixture_summary_present,
        );
        let session_issue_handoff = enterprise_identity_session_issue_handoff_readback(
            "saml",
            false,
            &executor_input.blocked_reasons,
            false,
            true,
            executor_input.issuer_validation_result,
            executor_input.audience_validation_result,
            executor_input.verified_group_count,
            executor_input.verified_role_count,
            executor_input.domain.is_some(),
            "saml_mock_executor",
        );
        return Ok(Json(json!({
            "data": {
                "schema": "enterprise_saml_execute_validated_acs.v1",
                "tenant_id": tenant_id,
                "provider_type": "saml",
                "status": "saml-validator-failed",
                "secret_safe": true,
                "runtime_implemented": true,
                "mock_executor": false,
                "server_side_simulated_input_only": true,
                "network_requests": false,
                "xml_parsed_by_this_endpoint": false,
                "raw_saml_response_accepted": false,
                "raw_assertion_accepted": false,
                "raw_claim_values_accepted": false,
                "certificate_or_private_key_returned": false,
                "authorization_header_returned": false,
                "saml_validator": executor_input.saml_validator,
                "saml_xml_signature_parser_executor": executor_input.saml_xml_signature_parser_executor,
                "signature_validation": {
                    "signature_validation_result": executor_input.signature_validation_result,
                    "assertion_validation_result": executor_input.assertion_validation_result,
                    "issuer_validation_result": executor_input.issuer_validation_result,
                    "audience_validation_result": executor_input.audience_validation_result,
                    "time_conditions_validation_result": executor_input.time_conditions_validation_result,
                    "failure_reason": executor_input.validator_failure_reason,
                    "raw_xml_returned": false,
                    "certificate_body_returned": false
                },
                "verified_assertion_summary": {
                    "external_subject_hash_present": true,
                    "validator_passed": false,
                    "raw_name_id_returned": false,
                    "raw_email_returned": false,
                    "raw_attribute_values_returned": false
                },
                "identity_binding_handoff": identity_binding_handoff,
                "session_issue_handoff": session_issue_handoff,
                "user_identity_binding_readback": {
                    "status": "not-run-validator-failed",
                    "binding_executed": false,
                    "apply_requested": executor_input.binding_input.apply,
                    "blocked_reason": "saml_validator_failed",
                    "raw_subject_returned": false,
                    "raw_claims_returned": false
                },
                "session_binding": {
                    "session_creation_disabled": true,
                    "session_created": false,
                    "blocked_reason": "saml_validator_failed",
                    "cookie_returned": false
                },
                "omitted_fields": enterprise_saml_execute_validated_acs_omitted_fields(),
                "next_step": "Fix the fixture-safe parsed assertion summary so issuer, audience, name_id_hash, time conditions, signature marker, and attribute mapping presence all pass before binding/session paths run."
            }
        }))
        .into_response());
    }
    let binding = execute_enterprise_identity_binding(
        state.db(),
        &session,
        executor_input.binding_input,
        "POST /admin/enterprise/identity-connections/saml/execute-validated-acs",
        "enterprise_identity.saml_validated_acs_execute",
        "admin_enterprise_saml_validated_acs_executor",
    )
    .await?;
    let binding_status = binding
        .get("status")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let bound_identity_available = matches!(binding_status, "binding-applied" | "binding-exists");
    let identity_binding_handoff = enterprise_identity_binding_handoff_readback(
        "saml",
        true,
        &executor_input.blocked_reasons,
        true,
        executor_input.issuer_validation_result,
        executor_input.audience_validation_result,
        executor_input.verified_group_count,
        executor_input.verified_role_count,
        executor_input.domain.is_some(),
        executor_input.fixture_summary_present,
    );
    let session_issue_handoff = enterprise_identity_session_issue_handoff_readback(
        "saml",
        true,
        &executor_input.blocked_reasons,
        bound_identity_available,
        true,
        executor_input.issuer_validation_result,
        executor_input.audience_validation_result,
        executor_input.verified_group_count,
        executor_input.verified_role_count,
        executor_input.domain.is_some(),
        "saml_mock_executor",
    );

    Ok(Json(json!({
        "data": {
            "schema": "enterprise_saml_execute_validated_acs.v1",
            "tenant_id": tenant_id,
            "provider_type": "saml",
            "status": enterprise_saml_execute_validated_acs_status(&binding),
            "secret_safe": true,
            "runtime_implemented": true,
            "mock_executor": true,
            "server_side_simulated_input_only": true,
            "network_requests": false,
            "xml_parsed_by_this_endpoint": false,
            "raw_saml_response_accepted": false,
            "raw_assertion_accepted": false,
            "raw_claim_values_accepted": false,
            "certificate_or_private_key_returned": false,
            "authorization_header_returned": false,
            "saml_validator": executor_input.saml_validator,
            "saml_xml_signature_parser_executor": executor_input.saml_xml_signature_parser_executor,
            "signature_validation": {
                "signature_validation_result": true,
                "assertion_validation_result": executor_input.assertion_validation_result,
                "issuer_validation_result": executor_input.issuer_validation_result,
                "audience_validation_result": executor_input.audience_validation_result,
                "time_conditions_validation_result": executor_input.time_conditions_validation_result,
                "source": "server_side_simulated_verified_assertion_summary",
                "raw_xml_returned": false,
                "certificate_body_returned": false
            },
            "verified_assertion_summary": {
                "external_subject_hash_present": true,
                "email_present": executor_input.email_present,
                "domain": executor_input.domain,
                "mapped_group_count": executor_input.mapped_group_count,
                "mapped_role_count": executor_input.mapped_role_count,
                "fixture_summary_present": executor_input.fixture_summary_present,
                "raw_name_id_returned": false,
                "raw_email_returned": false,
                "raw_attribute_values_returned": false
            },
            "user_identity_binding_readback": binding,
            "identity_binding_handoff": identity_binding_handoff,
            "session_issue_handoff": session_issue_handoff,
            "session_binding": {
                "session_creation_disabled": true,
                "session_created": false,
                "blocked_reason": "safe_saml_session_creation_path_not_implemented",
                "cookie_returned": false
            },
            "omitted_fields": enterprise_saml_execute_validated_acs_omitted_fields(),
            "next_step": "Use this executor with fixture-safe server-verified assertion summaries to test user_identity binding; enable session creation only after a real SAML validator and safe session path are wired."
        }
    }))
    .into_response())
}

async fn get_enterprise_accounts(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Query(query): Query<EnterpriseAccountsQuery>,
) -> Result<Response, AdminError> {
    let filters = query.into_filters()?;
    let tenant_id = session.tenant_id();
    let row = sqlx::query(
        r#"
        select
          t.id as tenant_id,
          t.name as tenant_name,
          t.slug as tenant_slug,
          t.status as tenant_status,
          t.metadata->>'account_name' as account_name,
          t.metadata->>'account_slug' as account_slug,
          t.metadata->>'account_owner' as account_owner,
          t.metadata->>'admin_contact_email' as admin_contact_email,
          t.metadata->>'enterprise_account_status' as metadata_account_status,
          t.metadata->>'enterprise_plan_tier' as metadata_plan_tier,
          t.metadata->>'account_notes' as account_notes,
          t.metadata->>'enterprise_sales_stage' as metadata_sales_stage,
          t.metadata->>'seat_limit' as seat_limit_text,
          t.metadata->>'monthly_token_quota' as monthly_token_quota_text,
          t.metadata->>'monthly_spend_quota' as monthly_spend_quota_text,
          (select count(*)::bigint from projects p where p.tenant_id = t.id and p.deleted_at is null) as project_count,
          (select count(*)::bigint from projects p where p.tenant_id = t.id and p.status = 'active' and p.deleted_at is null) as active_project_count,
          (select count(*)::bigint from users u where u.tenant_id = t.id and u.deleted_at is null) as user_count,
          (select count(*)::bigint from users u where u.tenant_id = t.id and u.status = 'active' and u.deleted_at is null) as active_user_count,
          (select count(*)::bigint from users u where u.tenant_id = t.id and u.status = 'invited' and u.deleted_at is null) as invited_user_count,
          (select count(*)::bigint from users u where u.tenant_id = t.id and u.status = 'disabled' and u.deleted_at is null) as disabled_user_count,
          (select count(*)::bigint from project_members pm where pm.tenant_id = t.id) as project_member_count,
          (select count(*)::bigint from virtual_keys vk where vk.tenant_id = t.id and vk.status = 'active' and vk.deleted_at is null) as active_virtual_key_count,
          (select count(*)::bigint from api_key_profiles p where p.tenant_id = t.id and p.status = 'active' and p.deleted_at is null) as active_profile_count,
          (select count(*)::bigint from wallets w where w.tenant_id = t.id and w.status = 'active' and w.deleted_at is null) as active_wallet_count,
          (select count(*)::bigint from subscriptions s where s.tenant_id = t.id and s.status in ('trialing', 'active', 'renewed', 'resumed')) as active_subscription_count,
          (
            select s.status
            from subscriptions s
            where s.tenant_id = t.id
            order by
              case
                when s.status in ('trialing', 'active', 'renewed', 'resumed') then 0
                when s.status in ('created', 'payment_failed') then 1
                else 2
              end,
              s.current_period_end desc,
              s.updated_at desc
            limit 1
          ) as latest_subscription_status,
          (
            select p.id
            from subscriptions s
            join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
            where s.tenant_id = t.id
            order by
              case
                when s.status in ('trialing', 'active', 'renewed', 'resumed') then 0
                when s.status in ('created', 'payment_failed') then 1
                else 2
              end,
              s.current_period_end desc,
              s.updated_at desc
            limit 1
          ) as plan_id,
          (
            select p.plan_code
            from subscriptions s
            join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
            where s.tenant_id = t.id
            order by
              case
                when s.status in ('trialing', 'active', 'renewed', 'resumed') then 0
                when s.status in ('created', 'payment_failed') then 1
                else 2
              end,
              s.current_period_end desc,
              s.updated_at desc
            limit 1
          ) as plan_code,
          (
            select p.display_name
            from subscriptions s
            join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
            where s.tenant_id = t.id
            order by
              case
                when s.status in ('trialing', 'active', 'renewed', 'resumed') then 0
                when s.status in ('created', 'payment_failed') then 1
                else 2
              end,
              s.current_period_end desc,
              s.updated_at desc
            limit 1
          ) as plan_display_name,
          (
            select p.billing_interval
            from subscriptions s
            join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
            where s.tenant_id = t.id
            order by
              case
                when s.status in ('trialing', 'active', 'renewed', 'resumed') then 0
                when s.status in ('created', 'payment_failed') then 1
                else 2
              end,
              s.current_period_end desc,
              s.updated_at desc
            limit 1
          ) as billing_interval,
          (
            select p.currency
            from subscriptions s
            join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
            where s.tenant_id = t.id
            order by
              case
                when s.status in ('trialing', 'active', 'renewed', 'resumed') then 0
                when s.status in ('created', 'payment_failed') then 1
                else 2
              end,
              s.current_period_end desc,
              s.updated_at desc
            limit 1
          ) as plan_currency,
          (
            select p.unit_price::text
            from subscriptions s
            join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
            where s.tenant_id = t.id
            order by
              case
                when s.status in ('trialing', 'active', 'renewed', 'resumed') then 0
                when s.status in ('created', 'payment_failed') then 1
                else 2
              end,
              s.current_period_end desc,
              s.updated_at desc
            limit 1
          ) as unit_price,
          (select count(*)::bigint from invoices i where i.tenant_id = t.id) as invoice_count,
          (select count(*)::bigint from invoice_receipts r where r.tenant_id = t.id) as receipt_count,
          (select coalesce(sum(rl.input_tokens + rl.output_tokens + rl.cache_read_tokens + rl.cache_write_tokens + rl.reasoning_tokens), 0)::bigint from request_logs rl where rl.tenant_id = t.id and rl.created_at >= now() - interval '30 days') as total_tokens_30d,
          (select count(*)::bigint from request_logs rl where rl.tenant_id = t.id and rl.created_at >= now() - interval '30 days') as request_count_30d,
          (select count(*)::bigint from request_logs rl where rl.tenant_id = t.id and rl.status = 'succeeded' and rl.created_at >= now() - interval '30 days') as success_count_30d,
          (select coalesce(sum(rl.final_cost), 0)::text from request_logs rl where rl.tenant_id = t.id and rl.created_at >= now() - interval '30 days') as spend_30d,
          (select coalesce(max(rl.currency), 'USD') from request_logs rl where rl.tenant_id = t.id and rl.created_at >= now() - interval '30 days') as usage_currency
        from tenants t
        where t.id = $1
          and t.deleted_at is null
        "#,
    )
    .bind(tenant_id)
    .fetch_optional(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?
    .ok_or_else(|| AdminError::not_found("tenant"))?;

    let seat_limit =
        optional_positive_i64(admin_row_get::<Option<String>>(&row, "seat_limit_text")?);
    let seats_used = admin_row_get::<i64>(&row, "active_user_count")?;
    let monthly_token_quota = optional_positive_i64(admin_row_get::<Option<String>>(
        &row,
        "monthly_token_quota_text",
    )?);
    let monthly_spend_quota = optional_positive_decimal(admin_row_get::<Option<String>>(
        &row,
        "monthly_spend_quota_text",
    )?);
    let total_tokens_30d = admin_row_get::<i64>(&row, "total_tokens_30d")?;
    let spend_30d = admin_row_get::<String>(&row, "spend_30d")?;
    let active_subscription_count = admin_row_get::<i64>(&row, "active_subscription_count")?;
    let active_wallet_count = admin_row_get::<i64>(&row, "active_wallet_count")?;
    let invoice_count = admin_row_get::<i64>(&row, "invoice_count")?;
    let receipt_count = admin_row_get::<i64>(&row, "receipt_count")?;
    let oidc_status = enterprise_identity_connection_status("oidc");
    let saml_status = enterprise_identity_connection_status("saml");
    let sso_status = enterprise_sso_readiness_status(oidc_status, saml_status);
    let billing_status = enterprise_billing_readiness_status(
        active_wallet_count,
        active_subscription_count,
        invoice_count,
        receipt_count,
    );
    let quota_status = enterprise_quota_status(total_tokens_30d, monthly_token_quota);
    let metadata_sales_stage = admin_row_get::<Option<String>>(&row, "metadata_sales_stage")?;
    let sales_stage = enterprise_sales_stage(metadata_sales_stage.as_deref());
    let overall_status =
        enterprise_account_overall_status(sso_status, billing_status, quota_status);
    let next_step =
        enterprise_account_next_step(sales_stage, sso_status, billing_status, quota_status);
    let filter_matched = filters.matches(sales_stage, sso_status, billing_status);
    let tenant_name = admin_row_get::<String>(&row, "tenant_name")?;
    let tenant_slug = admin_row_get::<String>(&row, "tenant_slug")?;
    let account_name = row
        .try_get::<Option<String>, _>("account_name")
        .map_err(|error| AdminError::from(DbError::Query(error)))?
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| tenant_name.clone());
    let account_slug = row
        .try_get::<Option<String>, _>("account_slug")
        .map_err(|error| AdminError::from(DbError::Query(error)))?
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| tenant_slug.clone());
    let plan_id = admin_row_get::<Option<Uuid>>(&row, "plan_id")?;
    let workspace_linkage = if filter_matched {
        enterprise_workspace_linkage_readback(state.db(), tenant_id).await?
    } else {
        json!({
            "source": "projects",
            "filtered_out": true,
            "workspaces": [],
            "tenant_scoped": true,
        })
    };

    let sales_activity = if filter_matched {
        enterprise_sales_activity_readback(state.db(), tenant_id).await?
    } else {
        json!({
            "source": "enterprise_sales_activities",
            "filtered_out": true,
            "recent": [],
            "raw_external_payload_returned": false
        })
    };
    let provisioning_or_invite_handoff = if filter_matched {
        enterprise_provisioning_or_invite_handoff_readback(state.db(), tenant_id, &row, next_step)
            .await?
    } else {
        enterprise_provisioning_or_invite_handoff_filtered_readback(next_step)
    };
    let external_crm_adapter = if filter_matched {
        enterprise_external_crm_adapter_readback(state.db(), tenant_id).await?
    } else {
        enterprise_external_crm_adapter_filtered_readback()
    };
    let external_crm_sync_run = if filter_matched {
        enterprise_crm_latest_sync_run_readback(state.db(), tenant_id).await?
    } else {
        enterprise_crm_sync_run_filtered_readback()
    };
    let retry_worker_handoff_summary = if filter_matched {
        enterprise_crm_retry_worker_handoff_summary(state.db(), tenant_id, false).await?
    } else {
        enterprise_crm_retry_worker_handoff_filtered_summary()
    };
    let accounts = if filter_matched {
        vec![enterprise_account_readback(
            &row,
            tenant_id,
            tenant_name,
            tenant_slug,
            account_name,
            account_slug,
            metadata_sales_stage,
            sales_activity,
            external_crm_adapter,
            external_crm_sync_run,
            retry_worker_handoff_summary,
            sales_stage,
            sso_status,
            oidc_status,
            saml_status,
            billing_status,
            quota_status,
            active_wallet_count,
            active_subscription_count,
            invoice_count,
            receipt_count,
            seat_limit,
            seats_used,
            monthly_token_quota,
            monthly_spend_quota,
            total_tokens_30d,
            spend_30d,
            plan_id,
            workspace_linkage,
            provisioning_or_invite_handoff,
            next_step,
        )?]
    } else {
        Vec::new()
    };

    Ok(Json(json!({
        "data": {
            "schema": "admin_enterprise_accounts_readback.v1",
            "tenant_id": tenant_id,
            "status": overall_status,
            "secret_safe": true,
            "runtime_implemented": true,
            "crm_connected": false,
            "external_sales_system_connected": false,
            "filters": filters.as_json(),
            "filtered_out_count": if filter_matched { 0 } else { 1 },
            "accounts": accounts,
            "omitted_fields": enterprise_accounts_omitted_fields(),
            "next_step": next_step
        }
    }))
    .into_response())
}

async fn get_enterprise_sales_dashboard(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Query(query): Query<EnterpriseSalesDashboardQuery>,
) -> Result<Response, AdminError> {
    let scope = EnterpriseSalesDashboardScope::from_query(query.scope.as_deref())?;
    if scope == EnterpriseSalesDashboardScope::AllTenants && !session.roles().contains(&Role::Owner)
    {
        return Err(AdminError::forbidden(
            "scope=all_tenants requires owner role; use scope=current_tenant for tenant-scoped readback",
        ));
    }

    let all_tenants = scope == EnterpriseSalesDashboardScope::AllTenants;
    let rows = sqlx::query(
        r#"
        select
          t.id as tenant_id,
          t.name as tenant_name,
          t.slug as tenant_slug,
          t.status as tenant_status,
          t.metadata->>'enterprise_account_status' as metadata_account_status,
          t.metadata->>'enterprise_sales_stage' as metadata_sales_stage,
          t.metadata->>'enterprise_plan_tier' as metadata_plan_tier,
          (t.metadata ? 'admin_contact_email') as admin_contact_present,
          (select count(*)::bigint from projects p where p.tenant_id = t.id and p.deleted_at is null) as workspace_count,
          (select count(*)::bigint from projects p where p.tenant_id = t.id and p.status = 'active' and p.deleted_at is null) as active_workspace_count,
          (select count(*)::bigint from users u where u.tenant_id = t.id and u.status = 'active' and u.deleted_at is null) as active_user_count,
          (select count(*)::bigint from users u where u.tenant_id = t.id and u.status = 'invited' and u.deleted_at is null) as invited_user_count,
          (select count(*)::bigint from wallets w where w.tenant_id = t.id and w.status = 'active' and w.deleted_at is null) as active_wallet_count,
          (select count(*)::bigint from subscriptions s where s.tenant_id = t.id and s.status in ('trialing', 'active', 'renewed', 'resumed')) as active_subscription_count,
          (select count(*)::bigint from invoices i where i.tenant_id = t.id) as invoice_count,
          (select count(*)::bigint from invoice_receipts r where r.tenant_id = t.id) as receipt_count,
          (
            select a.status
            from enterprise_external_crm_adapters a
            where a.tenant_id = t.id
            order by a.updated_at desc
            limit 1
          ) as crm_adapter_status,
          (
            select a.secret_ref_present
            from enterprise_external_crm_adapters a
            where a.tenant_id = t.id
            order by a.updated_at desc
            limit 1
          ) as crm_secret_ref_present,
          (
            select r.status
            from enterprise_crm_sync_runs r
            where r.tenant_id = t.id
            order by r.created_at desc
            limit 1
          ) as latest_crm_sync_status,
          (
            select r.refused_reason
            from enterprise_crm_sync_runs r
            where r.tenant_id = t.id
            order by r.created_at desc
            limit 1
          ) as latest_crm_refused_reason,
          (
            select r.metadata #>> '{retry_attempt_readback,status}'
            from enterprise_crm_sync_runs r
            where r.tenant_id = t.id
            order by r.created_at desc
            limit 1
          ) as latest_crm_retry_status,
          (
            select count(*)::bigint
            from enterprise_sales_activities a
            where a.tenant_id = t.id
              and a.status in ('open', 'planned')
          ) as open_sales_activity_count,
          (
            select a.due_at::text
            from enterprise_sales_activities a
            where a.tenant_id = t.id
              and a.status in ('open', 'planned')
              and a.next_action is not null
            order by a.due_at asc nulls last, a.created_at desc
            limit 1
          ) as next_sales_activity_due_at,
          (
            exists (
              select 1
              from enterprise_sales_activities a
              where a.tenant_id = t.id
                and a.status in ('open', 'planned')
                and a.next_action is not null
            )
          ) as sales_activity_next_action_present,
          (
            case
              when exists (
                select 1
                from enterprise_sales_activities a
                where a.tenant_id = t.id
                  and a.status in ('open', 'planned')
                  and a.next_action is not null
                  and a.due_at is not null
                  and a.due_at <= now()
              ) then 'due'
              when exists (
                select 1
                from enterprise_sales_activities a
                where a.tenant_id = t.id
                  and a.status in ('open', 'planned')
                  and a.next_action is not null
              ) then 'scheduled'
              when exists (
                select 1
                from enterprise_sales_activities a
                where a.tenant_id = t.id
                  and a.status in ('open', 'planned')
              ) then 'open-without-next-action'
              else 'none'
            end
          ) as sales_activity_next_action_status
        from tenants t
        where t.deleted_at is null
          and ($1::boolean = true or t.id = $2)
        order by
          case when t.id = $2 then 0 else 1 end,
          t.updated_at desc,
          t.created_at desc
        limit 500
        "#,
    )
    .bind(all_tenants)
    .bind(session.tenant_id())
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let mut accounts_by_status = BTreeMap::<String, i64>::new();
    let mut accounts_by_stage = BTreeMap::<String, i64>::new();
    let mut provisioning_status_counts = BTreeMap::<String, i64>::new();
    let mut invite_status_counts = BTreeMap::<String, i64>::new();
    let mut crm_sync_status_counts = BTreeMap::<String, i64>::new();
    let mut crm_retry_status_counts = BTreeMap::<String, i64>::new();
    let mut sales_activity_next_action_status_counts = BTreeMap::<String, i64>::new();
    let mut blocked_reason_counts = BTreeMap::<String, i64>::new();
    let mut next_action_counts = BTreeMap::<String, i64>::new();
    let mut account_samples = Vec::new();

    for row in &rows {
        let tenant_status = admin_row_get::<String>(row, "tenant_status")?;
        let account_status = enterprise_account_lifecycle_status(
            admin_row_get::<Option<String>>(row, "metadata_account_status")?.as_deref(),
            &tenant_status,
        );
        let sales_stage = enterprise_sales_stage(
            admin_row_get::<Option<String>>(row, "metadata_sales_stage")?.as_deref(),
        );
        let plan_tier = enterprise_plan_tier(
            admin_row_get::<Option<String>>(row, "metadata_plan_tier")?.as_deref(),
            None,
        );
        let active_workspace_count = admin_row_get::<i64>(row, "active_workspace_count")?;
        let invited_user_count = admin_row_get::<i64>(row, "invited_user_count")?;
        let active_wallet_count = admin_row_get::<i64>(row, "active_wallet_count")?;
        let active_subscription_count = admin_row_get::<i64>(row, "active_subscription_count")?;
        let invoice_count = admin_row_get::<i64>(row, "invoice_count")?;
        let receipt_count = admin_row_get::<i64>(row, "receipt_count")?;
        let admin_contact_present = admin_row_get::<bool>(row, "admin_contact_present")?;
        let billing_status = enterprise_billing_readiness_status(
            active_wallet_count,
            active_subscription_count,
            invoice_count,
            receipt_count,
        );
        let crm_adapter_status = admin_row_get::<Option<String>>(row, "crm_adapter_status")?
            .unwrap_or_else(|| "not-configured".to_string());
        let crm_secret_ref_present =
            admin_row_get::<Option<bool>>(row, "crm_secret_ref_present")?.unwrap_or(false);
        let crm_sync_status = admin_row_get::<Option<String>>(row, "latest_crm_sync_status")?
            .unwrap_or_else(|| "not-run".to_string());
        let crm_retry_status = admin_row_get::<Option<String>>(row, "latest_crm_retry_status")?
            .unwrap_or_else(|| "not-attempted".to_string());
        let sales_activity_next_action_status =
            admin_row_get::<String>(row, "sales_activity_next_action_status")?;
        let open_sales_activity_count = admin_row_get::<i64>(row, "open_sales_activity_count")?;
        let sales_activity_next_action_present =
            admin_row_get::<bool>(row, "sales_activity_next_action_present")?;

        bump_count(&mut accounts_by_status, account_status);
        bump_count(&mut accounts_by_stage, sales_stage);
        bump_count(&mut crm_sync_status_counts, &crm_sync_status);
        bump_count(&mut crm_retry_status_counts, &crm_retry_status);
        bump_count(
            &mut sales_activity_next_action_status_counts,
            &sales_activity_next_action_status,
        );

        let provisioning_blockers = enterprise_dashboard_provisioning_blockers(
            &tenant_status,
            active_workspace_count,
            plan_tier,
            admin_contact_present,
        );
        let provisioning_status = if provisioning_blockers.is_empty() {
            "ready"
        } else {
            "blocked"
        };
        bump_count(&mut provisioning_status_counts, provisioning_status);

        let invite_blockers = enterprise_dashboard_invite_blockers(
            &tenant_status,
            active_workspace_count,
            invited_user_count,
        );
        let invite_status = if invite_blockers.is_empty() {
            "ready"
        } else {
            "blocked"
        };
        bump_count(&mut invite_status_counts, invite_status);

        let crm_blockers = enterprise_dashboard_crm_blockers(
            &crm_adapter_status,
            crm_secret_ref_present,
            &crm_sync_status,
            admin_row_get::<Option<String>>(row, "latest_crm_refused_reason")?.as_deref(),
        );

        for reason in provisioning_blockers.iter().chain(invite_blockers.iter()) {
            bump_count(&mut blocked_reason_counts, reason);
            bump_count(
                &mut next_action_counts,
                enterprise_dashboard_next_action_for_reason(reason),
            );
        }
        for reason in &crm_blockers {
            bump_count(&mut blocked_reason_counts, reason);
            bump_count(
                &mut next_action_counts,
                enterprise_dashboard_next_action_for_reason(reason),
            );
        }

        if account_samples.len() < 10 {
            account_samples.push(json!({
                "tenant_id": admin_row_get::<Uuid>(row, "tenant_id")?,
                "tenant_name": admin_row_get::<String>(row, "tenant_name")?,
                "tenant_slug": admin_row_get::<String>(row, "tenant_slug")?,
                "tenant_status": tenant_status,
                "account_status": account_status,
                "sales_stage": sales_stage,
                "plan_tier": plan_tier,
                "provisioning_readiness": provisioning_status,
                "invite_delivery_readiness": invite_status,
                "crm_adapter_status": crm_adapter_status,
                "crm_sync_status": crm_sync_status,
                "crm_retry_status": crm_retry_status,
                "sales_activity_next_action_status": sales_activity_next_action_status,
                "sales_activity_next_action_present": sales_activity_next_action_present,
                "open_sales_activity_count": open_sales_activity_count,
                "next_sales_activity_due_at": admin_row_get::<Option<String>>(row, "next_sales_activity_due_at")?,
                "active_workspace_count": active_workspace_count,
                "active_user_count": admin_row_get::<i64>(row, "active_user_count")?,
                "invited_user_count": invited_user_count,
                "raw_contact_returned": false,
                "raw_email_returned": false,
                "raw_crm_payload_returned": false,
            }));
        }
    }

    let next_actions = next_action_counts
        .iter()
        .map(|(action, count)| json!({ "action": action, "account_count": count }))
        .collect::<Vec<_>>();
    let retry_worker_handoff_summary =
        enterprise_crm_retry_worker_handoff_summary(state.db(), session.tenant_id(), all_tenants)
            .await?;

    Ok(Json(json!({
        "data": {
            "schema": "admin_enterprise_sales_dashboard_readback.v1",
            "tenant_id": session.tenant_id(),
            "scope": scope.as_str(),
            "cross_tenant": all_tenants,
            "cross_tenant_detail_returned": false,
            "secret_safe": true,
            "read_only": true,
            "runtime_implemented": true,
            "source_tables": [
                "tenants",
                "projects",
                "users",
                "wallets",
                "subscriptions",
                "invoices",
                "invoice_receipts",
                "enterprise_external_crm_adapters",
                "enterprise_crm_sync_runs",
                "enterprise_sales_activities"
            ],
            "accounts_total": rows.len(),
            "accounts_by_status": accounts_by_status,
            "accounts_by_stage": accounts_by_stage,
            "provisioning_readiness": {
                "status_counts": provisioning_status_counts,
                "plan_path": "POST /admin/enterprise/accounts/provisioning-plan",
                "apply_path": "POST /admin/enterprise/accounts/provisioning-apply",
                "writes_performed": false
            },
            "invite_delivery_readiness": {
                "status_counts": invite_status_counts,
                "plan_path": "POST /admin/enterprise/accounts/invite-delivery-plan",
                "apply_path": "POST /admin/enterprise/accounts/invite-delivery-apply",
                "email_sent": false,
                "writes_performed": false
            },
            "crm_sync_retry_status_summary": {
                "sync_status_counts": crm_sync_status_counts,
                "retry_status_counts": crm_retry_status_counts,
                "retry_worker_handoff_summary": retry_worker_handoff_summary,
                "network_requests_executed": false,
                "raw_crm_payload_returned": false,
                "readback_path": "GET /admin/enterprise/accounts",
                "write_path": "PATCH /admin/enterprise/accounts"
            },
            "sales_activity_next_action_summary": {
                "status_counts": sales_activity_next_action_status_counts,
                "source": "enterprise_sales_activities",
                "readback_path": "GET /admin/enterprise/accounts",
                "write_path": "PATCH /admin/enterprise/accounts",
                "raw_contact_returned": false,
                "raw_email_returned": false,
                "raw_external_payload_returned": false
            },
            "blocked_reason_counts": blocked_reason_counts,
            "next_actions": next_actions,
            "account_samples": account_samples,
            "sample_limit": 10,
            "omitted_fields": enterprise_sales_dashboard_omitted_fields(),
            "next_step": "Use this aggregate for sales dashboard readback; fetch GET /admin/enterprise/accounts only when a tenant-scoped detail view is needed."
        }
    }))
    .into_response())
}

async fn post_enterprise_account(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<CreateEnterpriseAccountRequest>,
) -> Result<Response, AdminError> {
    let tenant_id = session.tenant_id();
    let ensure_default_workspace = request.ensure_default_workspace.unwrap_or(false);
    let workspace_name = normalize_enterprise_optional_text(
        request.workspace_name.clone(),
        "workspace_name",
        120,
        &mut Vec::new(),
    )?
    .unwrap_or_else(|| "Default Workspace".to_string());
    let write = request.into_write()?;
    if write.field_names.is_empty() && !ensure_default_workspace {
        return Err(AdminError::bad_request(
            "at least one enterprise account field or ensure_default_workspace=true is required",
        ));
    }

    let metadata_patch = write.metadata_patch();
    let has_metadata_patch = metadata_patch
        .as_object()
        .is_some_and(|object| !object.is_empty());
    let mut tx = state
        .db()
        .begin()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let before_row = sqlx::query(
        r#"
        select id, metadata
        from tenants
        where id = $1 and deleted_at is null
        for update
        "#,
    )
    .bind(tenant_id)
    .fetch_optional(&mut *tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?
    .ok_or_else(|| AdminError::not_found("tenant"))?;
    let before_metadata = admin_row_get::<Value>(&before_row, "metadata")?;
    let before = EnterpriseTenantAccountAuditResource {
        tenant_id,
        summary: enterprise_account_metadata_audit_summary(&before_metadata),
    };

    let after_metadata = if has_metadata_patch {
        let after_row = sqlx::query(
            r#"
            update tenants
            set metadata = metadata || $2::jsonb,
                updated_at = now()
            where id = $1 and deleted_at is null
            returning id, metadata
            "#,
        )
        .bind(tenant_id)
        .bind(metadata_patch)
        .fetch_one(&mut *tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
        admin_row_get::<Value>(&after_row, "metadata")?
    } else {
        before_metadata.clone()
    };
    let after = EnterpriseTenantAccountAuditResource {
        tenant_id,
        summary: enterprise_account_metadata_audit_summary(&after_metadata),
    };
    let audit_id = insert_admin_audit_log_tx(
        &mut tx,
        new_admin_audit_log(
            &session,
            "enterprise_account.lifecycle_create",
            Some(&before),
            &after,
            json!({
                "updated_fields": write.field_names,
                "write_path": "POST /admin/enterprise/accounts",
                "readback_path": "GET /admin/enterprise/accounts",
                "local_metadata_written": has_metadata_patch,
                "ensure_default_workspace": ensure_default_workspace,
                "tenant_scoped": true,
                "raw_metadata_logged": false,
                "raw_contact_logged": false,
                "secret_safe": true,
                "omitted_material": enterprise_accounts_omitted_fields()
            }),
            None,
        ),
    )
    .await?;

    let workspace = if ensure_default_workspace {
        Some(ensure_enterprise_default_workspace_tx(&mut tx, tenant_id, &workspace_name).await?)
    } else {
        None
    };
    let sales_activity = if let Some(activity) = &write.sales_activity {
        Some(
            insert_enterprise_sales_activity_tx(
                &mut tx,
                tenant_id,
                session.session_id(),
                audit_id,
                activity,
            )
            .await?,
        )
    } else {
        None
    };
    tx.commit()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(Json(json!({
        "data": {
            "schema": "admin_enterprise_account_lifecycle_create.v1",
            "tenant_id": tenant_id,
            "status": if has_metadata_patch || workspace.is_some() || sales_activity.is_some() { "created-or-updated" } else { "unchanged" },
            "secret_safe": true,
            "runtime_implemented": true,
            "tenant_scoped": true,
            "updated_fields": write.field_names,
            "account": after.summary,
            "workspace": workspace,
            "sales_activity": sales_activity,
            "audit_id": audit_id,
            "readback_path": "GET /admin/enterprise/accounts",
            "patch_path": "PATCH /admin/enterprise/accounts",
            "accepted_fields": enterprise_account_metadata_accepted_fields(),
            "omitted_fields": enterprise_accounts_omitted_fields(),
            "next_step": "Refresh GET /admin/enterprise/accounts to read account status, plan tier, contact hash summary, workspace linkage, sales stage, next action, and audit-backed local lifecycle state."
        }
    }))
    .into_response())
}

