async fn post_enterprise_account_provisioning_apply(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<EnterpriseAccountProvisioningRequest>,
) -> Result<Response, AdminError> {
    let input = request.into_input()?;
    let idempotency_hash = enterprise_account_provisioning_idempotency_hash(&input);
    let mut tx = state
        .db()
        .begin()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    if let Some(row) = find_enterprise_account_provisioning_marker_tx(
        &mut tx,
        session.tenant_id(),
        &idempotency_hash,
    )
    .await?
    {
        let target_tenant_id = admin_row_get::<Option<Uuid>>(&row, "resource_id")?;
        let audit_id = admin_row_get::<Uuid>(&row, "id")?;
        let replay = enterprise_account_provisioning_plan_response(
            state.db(),
            session.tenant_id(),
            &input,
            "replay",
            target_tenant_id,
            Some(audit_id),
        )
        .await?;
        tx.commit()
            .await
            .map_err(|error| AdminError::from(DbError::Query(error)))?;
        return Ok(Json(json!({ "data": replay })).into_response());
    }

    let target = upsert_enterprise_provisioning_tenant_tx(&mut tx, &input).await?;
    let workspace = upsert_enterprise_provisioning_workspace_tx(
        &mut tx,
        target.tenant_id,
        &input.workspace_name,
        &idempotency_hash,
    )
    .await?;
    let admin_user = upsert_enterprise_provisioning_admin_user_tx(
        &mut tx,
        target.tenant_id,
        &input.admin_contact_email,
        input.owner_contact_email.as_deref(),
        &idempotency_hash,
    )
    .await?;
    let membership = upsert_enterprise_provisioning_project_member_tx(
        &mut tx,
        target.tenant_id,
        workspace.workspace_id,
        admin_user.user_id,
    )
    .await?;

    let audit_after = EnterpriseTenantAccountAuditResource {
        tenant_id: target.tenant_id,
        summary: json!({
            "tenant_id": target.tenant_id,
            "tenant_slug": input.tenant_slug,
            "tenant_name": input.tenant_name,
            "workspace_name": input.workspace_name,
            "owner_contact_summary": enterprise_contact_safe_summary(input.owner_contact_email.as_deref()),
            "admin_contact_summary": enterprise_contact_safe_summary(Some(&input.admin_contact_email)),
            "sales_stage": input.sales_stage,
            "plan_tier": input.plan_tier,
            "idempotency_fingerprint": subscription_scheduler_public_fingerprint(&idempotency_hash),
            "raw_contact_returned": false,
            "raw_idempotency_returned": false,
            "secret_safe": true
        }),
    };
    let audit_id = insert_admin_audit_log_tx(
        &mut tx,
        new_admin_audit_log(
            &session,
            "enterprise_account.provisioning_apply",
            None,
            &audit_after,
            json!({
                "idempotency_fingerprint": subscription_scheduler_public_fingerprint(&idempotency_hash),
                "idempotency_hash_present": true,
                "target_tenant_id": target.tenant_id,
                "tenant_slug": input.tenant_slug,
                "tenant_created": target.created,
                "workspace_id": workspace.workspace_id,
                "workspace_created": workspace.created,
                "admin_user_id": admin_user.user_id,
                "admin_user_created": admin_user.created,
                "membership_created": membership.created,
                "write_path": "POST /admin/enterprise/accounts/provisioning-apply",
                "plan_path": "POST /admin/enterprise/accounts/provisioning-plan",
                "readback_path": "GET /admin/enterprise/accounts",
                "local_records_only": true,
                "email_sent": false,
                "raw_email_logged": false,
                "raw_idempotency_logged": false,
                "secret_safe": true,
                "omitted_material": enterprise_account_provisioning_omitted_fields()
            }),
            None,
        ),
    )
    .await?;
    tx.commit()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let data = enterprise_account_provisioning_plan_response(
        state.db(),
        session.tenant_id(),
        &input,
        "apply",
        Some(target.tenant_id),
        Some(audit_id),
    )
    .await?;
    Ok(Json(json!({ "data": data })).into_response())
}

