fn enterprise_saml_validate_acs_plan(tenant_id: &str, request: &Value) -> Value {
    let saml_response_present = request
        .get("saml_response_present")
        .or_else(|| request.get("saml_response_hash_present"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let saml_response_hash_present = request
        .get("saml_response_sha256")
        .or_else(|| request.get("saml_response_hash"))
        .and_then(Value::as_str)
        .is_some_and(|value| !value.trim().is_empty())
        || request
            .get("saml_response_hash_present")
            .and_then(Value::as_bool)
            .unwrap_or(false);
    let assertion_present = request
        .get("assertion_present")
        .or_else(|| request.get("assertion_hash_present"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let assertion_hash_present = request
        .get("assertion_sha256")
        .or_else(|| request.get("assertion_hash"))
        .and_then(Value::as_str)
        .is_some_and(|value| !value.trim().is_empty())
        || request
            .get("assertion_hash_present")
            .and_then(Value::as_bool)
            .unwrap_or(false);
    let idp_certificate_fingerprint_present = request
        .get("idp_certificate_sha256")
        .or_else(|| request.get("certificate_fingerprint"))
        .or_else(|| request.get("idp_certificate_fingerprint"))
        .and_then(Value::as_str)
        .is_some_and(|value| !value.trim().is_empty());
    let metadata_summary_present = request
        .get("metadata_summary")
        .is_some_and(Value::is_object)
        || request
            .get("metadata_url_present")
            .and_then(Value::as_bool)
            .unwrap_or(false)
        || request
            .get("metadata_xml_present")
            .and_then(Value::as_bool)
            .unwrap_or(false);
    let assertion_summary = request
        .get("assertion_summary")
        .or_else(|| request.get("fixture_assertion_summary"))
        .or_else(|| request.get("sample_claims_summary"));
    let assertion_summary_present = assertion_summary.is_some_and(Value::is_object);
    let audience_present = request
        .get("audience_present")
        .and_then(Value::as_bool)
        .unwrap_or(false)
        || assertion_summary
            .and_then(|value| value.get("audience_present"))
            .and_then(Value::as_bool)
            .unwrap_or(false)
        || assertion_summary
            .and_then(|value| value.get("audience_count"))
            .and_then(Value::as_u64)
            .is_some_and(|count| count > 0);
    let name_id_present = request
        .get("name_id_present")
        .and_then(Value::as_bool)
        .unwrap_or(false)
        || assertion_summary
            .and_then(|value| value.get("name_id_present"))
            .and_then(Value::as_bool)
            .unwrap_or(false);
    let issuer_present = request
        .get("issuer_present")
        .and_then(Value::as_bool)
        .unwrap_or(false)
        || assertion_summary
            .and_then(|value| value.get("issuer_present"))
            .and_then(Value::as_bool)
            .unwrap_or(false);
    let attribute_summary_present = assertion_summary
        .and_then(|value| value.get("attribute_count"))
        .and_then(Value::as_u64)
        .is_some_and(|count| count > 0)
        || assertion_summary
            .and_then(|value| value.get("role_value_count"))
            .and_then(Value::as_u64)
            .is_some_and(|count| count > 0)
        || assertion_summary
            .and_then(|value| value.get("group_value_count"))
            .and_then(Value::as_u64)
            .is_some_and(|count| count > 0);

    let saml_config = enterprise_saml_validation_plan();
    let mapping_ready = {
        let roles = enterprise_identity_mapping_summary("saml", "ROLE_MAPPING");
        let groups = enterprise_identity_mapping_summary("saml", "GROUP_MAPPING");
        roles["configured"] == json!(true) || groups["configured"] == json!(true)
    };
    let bounded_input_ready = (saml_response_present || saml_response_hash_present)
        && (assertion_present || assertion_hash_present)
        && issuer_present
        && audience_present
        && name_id_present
        && idp_certificate_fingerprint_present;
    let validation_ready = saml_config["status"] == json!("ready-for-validation-implementation");
    let status = if bounded_input_ready && validation_ready && mapping_ready {
        "ready-for-real-executor-implementation"
    } else {
        "plan-incomplete"
    };

    json!({
        "schema": "enterprise_saml_validate_acs_plan.v1",
        "tenant_id": tenant_id,
        "provider_type": "saml",
        "status": status,
        "secret_safe": true,
        "dry_run_only": true,
        "network_requests": false,
        "xml_parsed": false,
        "signature_verified": false,
        "session_created": false,
        "raw_saml_response_accepted": false,
        "raw_assertion_accepted": false,
        "raw_claim_values_accepted": false,
        "certificate_or_private_key_returned": false,
        "authorization_header_returned": false,
        "input_summary": {
            "saml_response_present": saml_response_present,
            "saml_response_hash_present": saml_response_hash_present,
            "assertion_present": assertion_present,
            "assertion_hash_present": assertion_hash_present,
            "metadata_summary_present": metadata_summary_present,
            "idp_certificate_fingerprint_present": idp_certificate_fingerprint_present,
            "fixture_assertion_summary_present": assertion_summary_present,
            "issuer_present": issuer_present,
            "audience_present": audience_present,
            "name_id_present": name_id_present,
            "attribute_summary_present": attribute_summary_present,
            "raw_values_returned": false
        },
        "xml_signature_validation_plan": {
            "status": if validation_ready && idp_certificate_fingerprint_present { "ready-for-validator" } else { "config-needed" },
            "implemented_now": false,
            "metadata_url_present": !env_trimmed("AI_GATEWAY_SAML_METADATA_URL").is_empty(),
            "metadata_xml_present": !env_trimmed("AI_GATEWAY_SAML_METADATA_XML").is_empty(),
            "idp_certificate_present": !env_trimmed("AI_GATEWAY_SAML_SIGNING_CERT").is_empty()
                || !env_trimmed("AI_GATEWAY_SAML_IDP_CERT").is_empty()
                || !env_trimmed("AI_GATEWAY_SAML_METADATA_XML").is_empty()
                || idp_certificate_fingerprint_present,
            "signature_required": saml_config["signature_required"].as_bool().unwrap_or(true),
            "required_checks": [
                "parse_saml_response_without_returning_xml",
                "locate_signed_response_or_assertion",
                "match_key_info_or_configured_idp_certificate",
                "validate_xml_signature_digest_and_signature_value",
                "reject_unsigned_assertion_when_signature_required",
                "reject_wrapped_or_duplicate_id_assertions"
            ],
            "certificate_body_returned": false,
            "private_key_returned": false,
            "raw_xml_returned": false
        },
        "assertion_validation_plan": {
            "status": if bounded_input_ready { "ready-for-validator" } else { "config-needed" },
            "implemented_now": false,
            "required_checks": [
                "issuer_matches_configured_entity_id_or_allowlist",
                "audience_contains_configured_sp_entity_id",
                "destination_matches_configured_acs_url",
                "name_id_present_and_stable",
                "not_before_not_in_future",
                "not_on_or_after_not_expired",
                "in_response_to_matches_server_side_request_when_present",
                "recipient_matches_acs_url"
            ],
            "issuer_present": issuer_present,
            "audience_present": audience_present,
            "name_id_present": name_id_present,
            "assertion_hash_present": assertion_hash_present,
            "assertion_value_returned": false,
            "name_id_value_returned": false,
            "audience_values_returned": false
        },
        "attribute_mapping_plan": {
            "status": if mapping_ready && attribute_summary_present { "ready-for-verified-attributes" } else if mapping_ready { "attribute-summary-needed" } else { "mapping-config-needed" },
            "accepted_source": "server_verified_saml_assertion_attributes_only",
            "mapped_roles": enterprise_identity_mapping_summary("saml", "ROLE_MAPPING"),
            "mapped_groups": enterprise_identity_mapping_summary("saml", "GROUP_MAPPING"),
            "unknown_roles_default_deny": true,
            "raw_attribute_values_returned": false,
            "raw_role_or_group_values_returned": false
        },
        "user_identity_binding_plan": {
            "status": if name_id_present && issuer_present { "ready-for-verified-assertion" } else { "assertion-subject-needed" },
            "lookup": "user_identities(provider_type, issuer, name_id, tenant_id)",
            "create_user_identity_implemented": false,
            "bind_existing_user_implemented": false,
            "requires_verified_signature_and_assertion": true,
            "raw_name_id_returned": false,
            "raw_email_returned": false
        },
        "session_binding_plan": {
            "status": "disabled-until-signature-and-assertion-validation",
            "session_creation_implemented": false,
            "session_created_in_this_request": false,
            "requires_valid_xml_signature": true,
            "requires_assertion_audience_and_time_validation": true,
            "requires_user_identity_binding": true,
            "cookie_returned": false
        },
        "omitted_fields": enterprise_saml_validate_acs_omitted_fields(),
        "next_step": "Wire a mockable SAML ACS executor behind this bounded plan: parse SAML server-side, validate XML signature and assertion conditions, map verified attributes, bind user_identity, then create a session only after validation."
    })
}

