fn enterprise_saml_validation_plan() -> Value {
    let entity_id_present = !env_trimmed("AI_GATEWAY_SAML_ENTITY_ID").is_empty();
    let metadata_url_present = !env_trimmed("AI_GATEWAY_SAML_METADATA_URL").is_empty();
    let metadata_xml_present = !env_trimmed("AI_GATEWAY_SAML_METADATA_XML").is_empty();
    let acs_url_present = !env_trimmed("AI_GATEWAY_SAML_ACS_URL").is_empty();
    let signing_cert_present = !env_trimmed("AI_GATEWAY_SAML_SIGNING_CERT").is_empty()
        || !env_trimmed("AI_GATEWAY_SAML_IDP_CERT").is_empty()
        || metadata_xml_present;
    let signature_required = !matches!(
        env_trimmed("AI_GATEWAY_SAML_SIGNATURE_REQUIRED")
            .to_ascii_lowercase()
            .as_str(),
        "" | "0" | "false" | "no" | "off"
    );
    let metadata_present = metadata_url_present || metadata_xml_present;
    let config_ready =
        entity_id_present && metadata_present && acs_url_present && signing_cert_present;

    json!({
        "schema": "enterprise_saml_validation_plan.v1",
        "status": if config_ready { "ready-for-validation-implementation" } else { "config-needed" },
        "entity_id_present": entity_id_present,
        "metadata_url_present": metadata_url_present,
        "metadata_xml_present": metadata_xml_present,
        "acs_url_present": acs_url_present,
        "signature_required": signature_required,
        "signature_validation_implemented": false,
        "idp_certificate_present": signing_cert_present,
        "certificate_returned": false,
        "private_key_returned": false,
        "expected_validation_steps": [
            "parse_metadata_presence_or_fetch_server_side",
            "validate_issuer_entity_id",
            "validate_response_destination_and_audience",
            "validate_xml_signature_with_idp_certificate",
            "validate_not_before_not_on_or_after",
            "trusted_attribute_mapping",
            "session_creation_after_validation_only"
        ],
        "acs": {
            "path": "not_implemented",
            "enabled": false,
            "saml_response_accepted": false,
            "session_creation": false
        },
        "network_requests": false,
        "raw_assertion_input_accepted": false,
        "metadata_xml_returned": false,
        "next_step": if config_ready {
            "Implement ACS request handling, XML signature validation, assertion checks, and trusted attribute mapping."
        } else {
            "Set SAML entity_id, metadata URL or XML presence, ACS URL, signing certificate, and role/group mapping env before runtime validation."
        }
    })
}

