fn enterprise_saml_assertion_validator_readback(
    summary: Option<&Value>,
    external_subject_hash: &str,
    metadata_trust_readback: Value,
    xml_signature_validation_readback: Value,
    signature_validation_result: bool,
    assertion_validation_result: bool,
    issuer_validation_result: bool,
    audience_validation_result: bool,
    time_conditions_validation_result: bool,
    mapped_group_count: usize,
    mapped_role_count: usize,
) -> Value {
    let signature_marker_present = summary_bool(summary, &["signature_marker_present"])
        || summary_string_present(summary, &["signature_marker", "signed_assertion_marker"])
        || summary_bool(
            summary,
            &["signed_assertion_present", "signed_response_present"],
        );
    let issuer_present = issuer_validation_result
        && (summary_bool(summary, &["issuer_present"])
            || summary_string_present(summary, &["issuer_hash", "issuer_sha256"]));
    let audience_present = audience_validation_result
        && (summary_bool(summary, &["audience_present"])
            || summary_string_present(summary, &["audience_hash", "audience_sha256"])
            || summary_count_positive(summary, &["audience_count"]));
    let name_id_hash_present = summary_bool(summary, &["name_id_hash_present"])
        || summary_string_present(summary, &["name_id_hash", "name_id_sha256"]);
    let name_id_hash_matches_request = summary
        .and_then(|value| {
            value
                .get("name_id_hash")
                .or_else(|| value.get("name_id_sha256"))
                .and_then(Value::as_str)
        })
        .map(|value| value.trim().eq_ignore_ascii_case(external_subject_hash))
        .unwrap_or(name_id_hash_present);
    let time_conditions_valid = time_conditions_validation_result
        && (summary_bool(summary, &["time_conditions_valid"])
            || (summary_bool(summary, &["not_before_valid"])
                && summary_bool(summary, &["not_on_or_after_valid"])));
    let attribute_mapping_present = mapped_group_count > 0
        || mapped_role_count > 0
        || summary_bool(summary, &["attribute_mapping_present"])
        || summary_count_positive(
            summary,
            &[
                "attribute_count",
                "mapped_group_count",
                "mapped_role_count",
                "group_value_count",
                "role_value_count",
            ],
        );
    let assertion_summary_present = summary.is_some();
    let assertion_validation_passed = assertion_validation_result
        && assertion_summary_present
        && issuer_present
        && audience_present
        && name_id_hash_present
        && name_id_hash_matches_request
        && time_conditions_valid
        && attribute_mapping_present;
    let signature_validation_passed = signature_validation_result && signature_marker_present;
    let metadata_trust_passed = metadata_trust_readback["passed"].as_bool().unwrap_or(false);
    let xml_signature_validation_passed = xml_signature_validation_readback["passed"]
        .as_bool()
        .unwrap_or(false);
    let failure_reason = if !assertion_summary_present {
        Some("parsed_assertion_summary_missing")
    } else if !signature_validation_result {
        Some("signature_validation_result_false")
    } else if !signature_marker_present {
        Some("signature_marker_missing")
    } else if !metadata_trust_passed {
        Some("metadata_cert_trust_chain_not_ready")
    } else if !xml_signature_validation_passed {
        Some("xml_signature_cryptographic_validation_failed")
    } else if !assertion_validation_result {
        Some("assertion_validation_result_false")
    } else if !issuer_present {
        Some("issuer_check_failed_or_missing")
    } else if !audience_present {
        Some("audience_check_failed_or_missing")
    } else if !name_id_hash_present {
        Some("name_id_hash_missing")
    } else if !name_id_hash_matches_request {
        Some("name_id_hash_mismatch")
    } else if !time_conditions_valid {
        Some("time_conditions_check_failed_or_missing")
    } else if !attribute_mapping_present {
        Some("attribute_mapping_presence_missing")
    } else {
        None
    };
    let passed = signature_validation_passed
        && assertion_validation_passed
        && metadata_trust_passed
        && xml_signature_validation_passed;

    json!({
        "runtime_implemented": true,
        "input_source": "fixture_safe_parsed_assertion_summary",
        "passed": passed,
        "failure_reason": failure_reason,
        "verified_subject_hash_source": if name_id_hash_present {
            "parsed_assertion_summary.name_id_hash"
        } else {
            "missing"
        },
        "checks": {
            "signature_marker": {
                "passed": signature_marker_present && signature_validation_result,
                "signature_validation_result": signature_validation_result,
                "marker_present": signature_marker_present
            },
            "metadata_cert_trust_chain": metadata_trust_readback,
            "xml_signature_validation": xml_signature_validation_readback,
            "issuer": {
                "passed": issuer_present,
                "validation_result": issuer_validation_result,
                "presence_or_hash": issuer_present
            },
            "audience": {
                "passed": audience_present,
                "validation_result": audience_validation_result,
                "presence_hash_or_count": audience_present
            },
            "name_id_hash": {
                "passed": name_id_hash_present && name_id_hash_matches_request,
                "present": name_id_hash_present,
                "matches_external_subject_hash": name_id_hash_matches_request,
                "raw_name_id_returned": false
            },
            "time_conditions": {
                "passed": time_conditions_valid,
                "validation_result": time_conditions_validation_result
            },
            "attribute_mapping": {
                "passed": attribute_mapping_present,
                "mapped_group_count": mapped_group_count,
                "mapped_role_count": mapped_role_count,
                "summary_mapping_present": attribute_mapping_present,
                "raw_attribute_values_returned": false
            }
        },
        "binding_path_enabled": passed,
        "session_path_enabled": passed,
        "raw_xml_returned": false,
        "raw_saml_response_returned": false,
        "raw_assertion_returned": false,
        "certificate_body_returned": false,
        "private_key_returned": false
    })
}

fn enterprise_saml_assertion_validator_summary_from_typed_input(
    input: &EnterpriseSamlAssertionValidatorInput,
) -> Value {
    let now = enterprise_oidc_current_unix_seconds();
    let assertion_not_yet_valid = input
        .not_before_unix
        .is_some_and(|not_before| not_before > now + 300);
    let assertion_expired = input
        .not_on_or_after_unix
        .map(|not_on_or_after| not_on_or_after <= now - 300)
        .unwrap_or(true);
    let mapping_group_count = input
        .attribute_mapping_summary
        .as_ref()
        .and_then(|summary| summary.mapped_group_count.or(summary.group_count))
        .unwrap_or(input.group_count.unwrap_or(0));
    let mapping_role_count = input
        .attribute_mapping_summary
        .as_ref()
        .and_then(|summary| summary.mapped_role_count.or(summary.role_count))
        .unwrap_or(input.role_count.unwrap_or(0));

    json!({
        "issuer_present": input.issuer_present.unwrap_or(false)
            || input.issuer_hash.as_deref().is_some_and(|value| !value.trim().is_empty())
            || input.issuer_sha256.as_deref().is_some_and(|value| !value.trim().is_empty()),
        "issuer_hash": input.issuer_hash.as_deref().or(input.issuer_sha256.as_deref()),
        "entity_id_present": input.entity_id_present.unwrap_or(false)
            || input.entity_id_hash.as_deref().is_some_and(|value| !value.trim().is_empty())
            || input.entity_id_sha256.as_deref().is_some_and(|value| !value.trim().is_empty()),
        "entity_id_hash": input.entity_id_hash.as_deref().or(input.entity_id_sha256.as_deref()),
        "audience_present": input.audience_present.unwrap_or(false)
            || input.audience_hash.as_deref().is_some_and(|value| !value.trim().is_empty())
            || input.audience_sha256.as_deref().is_some_and(|value| !value.trim().is_empty())
            || input.audience_count.unwrap_or(0) > 0,
        "audience_hash": input.audience_hash.as_deref().or(input.audience_sha256.as_deref()),
        "audience_count": input.audience_count.unwrap_or(0),
        "name_id_hash_present": input.name_id_hash_present.unwrap_or(false)
            || input.name_id_hash.as_deref().is_some_and(|value| !value.trim().is_empty())
            || input.name_id_sha256.as_deref().is_some_and(|value| !value.trim().is_empty()),
        "name_id_hash": input.name_id_hash.as_deref().or(input.name_id_sha256.as_deref()),
        "not_before_valid": input.not_before_unix.is_some() && !assertion_not_yet_valid,
        "not_on_or_after_valid": input.not_on_or_after_unix.is_some() && !assertion_expired,
        "time_conditions_valid": input.not_before_unix.is_some()
            && input.not_on_or_after_unix.is_some()
            && !assertion_not_yet_valid
            && !assertion_expired,
        "signature_marker_present": input.signature_verified.unwrap_or(false),
        "signature_verified": input.signature_verified.unwrap_or(false),
        "group_value_count": mapping_group_count,
        "role_value_count": mapping_role_count,
        "mapped_group_count": mapping_group_count,
        "mapped_role_count": mapping_role_count,
        "attribute_mapping_present": input
            .attribute_mapping_summary
            .as_ref()
            .and_then(|summary| summary.mapping_configured)
            .unwrap_or(mapping_group_count > 0 || mapping_role_count > 0),
        "raw_values_returned": false
    })
}

fn enterprise_saml_role_group_mapping_result(
    assertion_summary: Option<&Value>,
    mapped_group_count: usize,
    mapped_role_count: usize,
) -> Value {
    let summary_group_count = assertion_summary
        .and_then(|value| {
            value
                .get("mapped_group_count")
                .or_else(|| value.get("group_value_count"))
                .or_else(|| value.get("group_count"))
        })
        .and_then(Value::as_u64)
        .unwrap_or(mapped_group_count as u64);
    let summary_role_count = assertion_summary
        .and_then(|value| {
            value
                .get("mapped_role_count")
                .or_else(|| value.get("role_value_count"))
                .or_else(|| value.get("role_count"))
        })
        .and_then(Value::as_u64)
        .unwrap_or(mapped_role_count as u64);
    let mapping_configured = summary_bool(assertion_summary, &["attribute_mapping_present"])
        || mapped_group_count > 0
        || mapped_role_count > 0
        || summary_group_count > 0
        || summary_role_count > 0;

    json!({
        "schema": "enterprise_saml_role_group_mapping_result.v1",
        "status": if mapping_configured { "mapped-presence-counts-only" } else { "mapping-blocked" },
        "mapping_configured": mapping_configured,
        "group_count": summary_group_count,
        "role_count": summary_role_count,
        "mapped_group_count": mapped_group_count,
        "mapped_role_count": mapped_role_count,
        "raw_groups_returned": false,
        "raw_roles_returned": false,
        "raw_attributes_returned": false,
        "raw_email_returned": false,
        "raw_name_id_returned": false
    })
}

fn enterprise_saml_handoff_readiness(
    validator_passed: bool,
    role_group_mapping_result: &Value,
    fixture_summary_present: bool,
) -> Value {
    let mapping_ready = role_group_mapping_result["mapping_configured"]
        .as_bool()
        .unwrap_or(false);
    json!({
        "schema": "enterprise_saml_binding_session_handoff_readiness.v1",
        "binding_handoff_ready": validator_passed && mapping_ready,
        "session_handoff_ready": false,
        "session_handoff_blocked_reason": "safe_saml_session_creation_path_not_implemented",
        "fixture_assertion_summary_present": fixture_summary_present,
        "requires_real_xml_crypto_validator": true,
        "requires_real_idp_network": false,
        "gap": "[!] real XML crypto validator/IdP-backed validator/session creation remains outside this fixture-safe boundary",
        "raw_token_or_assertion_returned": false,
        "authorization_returned": false,
        "cookie_returned": false
    })
}

fn enterprise_saml_validator_blocked_reasons(
    assertion_validator_result: &Value,
    role_group_mapping_result: &Value,
) -> Vec<String> {
    let mut reasons = Vec::new();
    if !assertion_validator_result["passed"]
        .as_bool()
        .unwrap_or(false)
    {
        reasons.push(
            assertion_validator_result["failure_reason"]
                .as_str()
                .unwrap_or("assertion_validator_failed")
                .to_string(),
        );
    }
    if !role_group_mapping_result["mapping_configured"]
        .as_bool()
        .unwrap_or(false)
    {
        reasons.push("attribute_mapping_summary_missing".to_string());
    }
    reasons.sort();
    reasons.dedup();
    reasons
}

fn enterprise_saml_xml_signature_validation_readback(
    validation: Option<&EnterpriseSamlXmlSignatureValidationRequest>,
) -> Value {
    let Some(validation) = validation else {
        return json!({
            "schema": "enterprise_saml_xml_signature_validation.v1",
            "runtime_implemented": true,
            "passed": false,
            "failure_reason": "xml_signature_validation_missing",
            "signed_info_digest_present": false,
            "canonicalization_alg": null,
            "canonicalization_alg_allowed": false,
            "signature_alg": null,
            "signature_alg_allowed": false,
            "reference_digest_valid": false,
            "signature_value_valid": false,
            "cert_fingerprint_matches_metadata": false,
            "raw_xml_accepted": false,
            "raw_saml_response_accepted": false,
            "certificate_body_accepted": false,
            "private_key_accepted": false,
            "network_requests": false,
            "future_validator": "xml_signature_cryptographic_validator"
        });
    };

    let signed_info_digest_present = validation.signed_info_digest_present;
    let canonicalization_alg = validation
        .canonicalization_alg
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let canonicalization_alg_allowed = canonicalization_alg.as_deref().is_some_and(|value| {
        let normalized = value.to_ascii_uppercase();
        matches!(
            normalized.as_str(),
            "EXCLUSIVE-XML-C14N" | "EXCLUSIVE-XML-C14N11" | "XML-C14N" | "XML-C14N11"
        ) || matches!(
            value,
            "http://www.w3.org/2001/10/xml-exc-c14n#"
                | "http://www.w3.org/2006/12/xml-c14n11"
                | "http://www.w3.org/TR/2001/REC-xml-c14n-20010315"
        )
    });
    let signature_alg = validation
        .signature_alg
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let signature_alg_allowed = signature_alg.as_deref().is_some_and(|value| {
        matches!(
            value.to_ascii_uppercase().as_str(),
            "RS256" | "RS384" | "RS512" | "RSA-SHA256" | "RSA-SHA384" | "RSA-SHA512" | "ES256"
        )
    });
    let passed = signed_info_digest_present
        && canonicalization_alg_allowed
        && signature_alg_allowed
        && validation.reference_digest_valid
        && validation.signature_value_valid
        && validation.cert_fingerprint_matches_metadata;
    let failure_reason = if !signed_info_digest_present {
        Some("signed_info_digest_missing")
    } else if !canonicalization_alg_allowed {
        Some("canonicalization_alg_not_allowed_or_missing")
    } else if !signature_alg_allowed {
        Some("signature_alg_not_allowed_or_missing")
    } else if !validation.reference_digest_valid {
        Some("reference_digest_invalid")
    } else if !validation.signature_value_valid {
        Some("signature_value_invalid")
    } else if !validation.cert_fingerprint_matches_metadata {
        Some("cert_fingerprint_metadata_mismatch")
    } else {
        None
    };

    json!({
        "schema": "enterprise_saml_xml_signature_validation.v1",
        "runtime_implemented": true,
        "passed": passed,
        "failure_reason": failure_reason,
        "signed_info_digest_present": signed_info_digest_present,
        "canonicalization_alg": canonicalization_alg,
        "canonicalization_alg_allowed": canonicalization_alg_allowed,
        "allowed_canonicalization_algs": [
            "EXCLUSIVE-XML-C14N",
            "EXCLUSIVE-XML-C14N11",
            "XML-C14N",
            "XML-C14N11",
            "http://www.w3.org/2001/10/xml-exc-c14n#",
            "http://www.w3.org/2006/12/xml-c14n11",
            "http://www.w3.org/TR/2001/REC-xml-c14n-20010315"
        ],
        "signature_alg": signature_alg,
        "signature_alg_allowed": signature_alg_allowed,
        "allowed_signature_algs": ["RS256", "RS384", "RS512", "RSA-SHA256", "RSA-SHA384", "RSA-SHA512", "ES256"],
        "reference_digest_valid": validation.reference_digest_valid,
        "signature_value_valid": validation.signature_value_valid,
        "cert_fingerprint_matches_metadata": validation.cert_fingerprint_matches_metadata,
        "raw_xml_accepted": false,
        "raw_saml_response_accepted": false,
        "certificate_body_accepted": false,
        "private_key_accepted": false,
        "network_requests": false,
        "future_validator": "xml_signature_cryptographic_validator"
    })
}

fn enterprise_saml_xml_signature_parser_executor_readback(
    request: Option<EnterpriseSamlXmlSignatureParserExecutorRequest>,
) -> Result<Value, AdminError> {
    let Some(request) = request else {
        return Ok(json!({
            "schema": "saml_xml_signature_parser_executor.v1",
            "runtime_implemented": true,
            "executor_boundary": "typed_saml_xml_signature_parser_executor",
            "typed_request_present": false,
            "typed_request_complete": false,
            "readiness": "missing_typed_request",
            "blocked": true,
            "blocked_reasons": [
                "missing_issuer",
                "missing_entity_id",
                "missing_certificate_fingerprint",
                "missing_audience",
                "missing_assertion_subject_hash",
                "signature_not_verified"
            ],
            "network_enabled": false,
            "network_call_performed": false,
            "raw_xml_accepted": false,
            "raw_saml_response_accepted": false,
            "raw_assertion_accepted": false,
            "raw_claims_accepted": false,
            "certificate_body_accepted": false,
            "private_key_accepted": false,
            "authorization_header_accepted": false,
            "parser_input_summary": {
                "issuer_present": false,
                "issuer_hash_present": false,
                "entity_id_present": false,
                "entity_id_hash_present": false,
                "certificate_fingerprint_present": false,
                "assertion_subject_hash_present": false,
                "audience_present": false,
                "not_before_present": false,
                "not_on_or_after_present": false,
                "signature_algorithm_present": false,
                "signature_verified_metadata_present": false,
                "allowed_signature_algorithms": ["RS256", "RS384", "RS512", "RSA-SHA256", "RSA-SHA384", "RSA-SHA512", "ES256"],
                "raw_values_returned": false
            },
            "signature_result_readback": {
                "passed": false,
                "signature_verified": false,
                "signature_algorithm": null,
                "signature_algorithm_supported": false,
                "assertion_time_window_valid": false,
                "xml_parsed": false,
                "raw_xml_returned": false,
                "certificate_body_returned": false
            },
            "omitted_fields": enterprise_saml_xml_signature_parser_omitted_fields()
        }));
    };

    let issuer_hash = normalize_enterprise_oidc_safe_metadata(
        "issuer_hash",
        request.issuer_hash.or(request.issuer_sha256),
        128,
    )?;
    let issuer_present = request.issuer_present.unwrap_or(false) || issuer_hash.is_some();
    let entity_id_hash = normalize_enterprise_oidc_safe_metadata(
        "entity_id_hash",
        request.entity_id_hash.or(request.entity_id_sha256),
        128,
    )?;
    let entity_id_present = request.entity_id_present.unwrap_or(false) || entity_id_hash.is_some();
    let certificate_fingerprint = normalize_enterprise_oidc_safe_metadata(
        "certificate_fingerprint",
        request
            .certificate_fingerprint
            .or(request.certificate_fingerprint_sha256)
            .or(request.idp_certificate_fingerprint),
        160,
    )?;
    let certificate_fingerprint_present = request.certificate_fingerprint_present.unwrap_or(false)
        || certificate_fingerprint.is_some();
    let assertion_subject_hash = request
        .assertion_subject_hash
        .as_deref()
        .map(normalize_enterprise_external_subject_hash)
        .transpose()?;
    let audience_hash = normalize_enterprise_oidc_safe_metadata(
        "audience_hash",
        request.audience_hash.or(request.audience_sha256),
        128,
    )?;
    let audience_present = request.audience_present.unwrap_or(false)
        || audience_hash.is_some()
        || request
            .audience
            .as_deref()
            .is_some_and(|value| !value.trim().is_empty());
    let signature_algorithm = normalize_enterprise_oidc_safe_metadata(
        "signature_algorithm",
        request.signature_algorithm.or(request.signature_alg),
        64,
    )?
    .map(|value| value.to_ascii_uppercase());
    let signature_algorithm_supported = signature_algorithm.as_deref().is_some_and(|value| {
        matches!(
            value,
            "RS256" | "RS384" | "RS512" | "RSA-SHA256" | "RSA-SHA384" | "RSA-SHA512" | "ES256"
        )
    });
    let signature_verified = request.signature_verified.unwrap_or(false);
    let now = enterprise_oidc_current_unix_seconds();
    let not_before_present = request.not_before_unix.is_some();
    let not_on_or_after_present = request.not_on_or_after_unix.is_some();
    let assertion_not_yet_valid = request
        .not_before_unix
        .is_some_and(|not_before| not_before > now + 300);
    let assertion_expired = request
        .not_on_or_after_unix
        .map(|not_on_or_after| not_on_or_after <= now - 300)
        .unwrap_or(true);
    let assertion_time_window_valid = !assertion_not_yet_valid && !assertion_expired;

    let mut blocked_reasons = Vec::new();
    if !issuer_present {
        blocked_reasons.push("missing_issuer".to_string());
    }
    if !entity_id_present {
        blocked_reasons.push("missing_entity_id".to_string());
    }
    if !certificate_fingerprint_present {
        blocked_reasons.push("missing_certificate_fingerprint".to_string());
    }
    if !audience_present {
        blocked_reasons.push("missing_audience".to_string());
    }
    if assertion_subject_hash.is_none() {
        blocked_reasons.push("missing_assertion_subject_hash".to_string());
    }
    if signature_algorithm.is_none() || !signature_algorithm_supported {
        blocked_reasons.push("unsupported_signature_alg".to_string());
    }
    if assertion_expired {
        blocked_reasons.push("expired_assertion".to_string());
    }
    if assertion_not_yet_valid {
        blocked_reasons.push("assertion_not_yet_valid".to_string());
    }
    if !signature_verified {
        blocked_reasons.push("signature_not_verified".to_string());
    }
    blocked_reasons.sort();
    blocked_reasons.dedup();
    let passed = blocked_reasons.is_empty();

    Ok(json!({
        "schema": "saml_xml_signature_parser_executor.v1",
        "runtime_implemented": true,
        "executor_boundary": "typed_saml_xml_signature_parser_executor",
        "typed_request_present": true,
        "typed_request_complete": issuer_present
            && entity_id_present
            && certificate_fingerprint_present
            && audience_present
            && assertion_subject_hash.is_some()
            && signature_algorithm.is_some()
            && request.signature_verified.is_some(),
        "readiness": if passed {
            "parsed_and_verified_from_fixture_safe_metadata"
        } else {
            "blocked"
        },
        "blocked": !passed,
        "blocked_reasons": blocked_reasons,
        "network_enabled": false,
        "network_call_performed": false,
        "raw_xml_accepted": false,
        "raw_saml_response_accepted": false,
        "raw_assertion_accepted": false,
        "raw_claims_accepted": false,
        "certificate_body_accepted": false,
        "private_key_accepted": false,
        "authorization_header_accepted": false,
        "parser_input_summary": {
            "issuer_present": issuer_present,
            "issuer_hash_present": issuer_hash.is_some(),
            "entity_id_present": entity_id_present,
            "entity_id_hash_present": entity_id_hash.is_some(),
            "certificate_fingerprint_present": certificate_fingerprint_present,
            "assertion_subject_hash_present": assertion_subject_hash.is_some(),
            "audience_present": audience_present,
            "audience_hash_present": audience_hash.is_some(),
            "not_before_present": not_before_present,
            "not_on_or_after_present": not_on_or_after_present,
            "signature_algorithm_present": signature_algorithm.is_some(),
            "signature_verified_metadata_present": request.signature_verified.is_some(),
            "allowed_signature_algorithms": ["RS256", "RS384", "RS512", "RSA-SHA256", "RSA-SHA384", "RSA-SHA512", "ES256"],
            "raw_values_returned": false
        },
        "signature_result_readback": {
            "schema": "saml_xml_signature_parser_signature_result.v1",
            "passed": passed,
            "signature_verified": signature_verified,
            "signature_algorithm": signature_algorithm,
            "signature_algorithm_supported": signature_algorithm_supported,
            "assertion_time_window_valid": assertion_time_window_valid,
            "assertion_expired": assertion_expired,
            "assertion_not_yet_valid": assertion_not_yet_valid,
            "issuer_entity_cert_audience_subject_present": issuer_present
                && entity_id_present
                && certificate_fingerprint_present
                && audience_present
                && assertion_subject_hash.is_some(),
            "xml_parsed": false,
            "raw_xml_returned": false,
            "raw_saml_response_returned": false,
            "raw_assertion_returned": false,
            "raw_claims_returned": false,
            "certificate_body_returned": false,
            "authorization_header_returned": false
        },
        "omitted_fields": enterprise_saml_xml_signature_parser_omitted_fields()
    }))
}

fn enterprise_saml_metadata_trust_readback(
    trust: Option<&EnterpriseSamlMetadataTrustRequest>,
) -> Value {
    let Some(trust) = trust else {
        return json!({
            "schema": "enterprise_saml_metadata_cert_trust.v1",
            "runtime_implemented": true,
            "passed": false,
            "failure_reason": "metadata_trust_missing",
            "trust_status": "missing",
            "entity_id_present": false,
            "metadata_url_present": false,
            "metadata_ref_present": false,
            "cert_fingerprint_prefix_present": false,
            "valid_from_present": false,
            "valid_to_present": false,
            "signature_alg": null,
            "signature_alg_allowed": false,
            "metadata_xml_parsed": false,
            "metadata_xml_accepted": false,
            "certificate_body_accepted": false,
            "private_key_accepted": false,
            "network_requests": false,
            "future_validator": "metadata_fetch_and_cert_chain_validator"
        });
    };

    let entity_id_present = trust
        .entity_id
        .as_deref()
        .is_some_and(|value| !value.trim().is_empty())
        || trust.entity_id_present.unwrap_or(false);
    let metadata_url_present = trust
        .metadata_url
        .as_deref()
        .is_some_and(|value| !value.trim().is_empty())
        || trust.metadata_url_present.unwrap_or(false);
    let metadata_ref_present = trust
        .metadata_ref
        .as_deref()
        .is_some_and(|value| !value.trim().is_empty())
        || trust.metadata_ref_present.unwrap_or(false);
    let cert_fingerprint_prefix_present =
        trust
            .cert_fingerprint_prefix
            .as_deref()
            .is_some_and(|value| {
                let value = value.trim();
                !value.is_empty()
                    && value.len() <= 64
                    && value
                        .chars()
                        .all(|ch| ch.is_ascii_hexdigit() || matches!(ch, ':' | '-' | '_'))
            });
    let signature_alg = trust
        .signature_alg
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let signature_alg_allowed = signature_alg.as_deref().is_some_and(|value| {
        matches!(
            value.to_ascii_uppercase().as_str(),
            "RS256" | "RS384" | "RS512" | "RSA-SHA256" | "RSA-SHA384" | "RSA-SHA512" | "ES256"
        )
    });
    let valid_from_present = trust.valid_from_present.unwrap_or(false);
    let valid_to_present = trust.valid_to_present.unwrap_or(false);
    let trust_status = trust
        .trust_status
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("missing");
    let trust_status_passed = matches!(
        trust_status.to_ascii_lowercase().as_str(),
        "ready" | "trusted" | "valid" | "verified"
    );
    let passed = entity_id_present
        && (metadata_url_present || metadata_ref_present)
        && cert_fingerprint_prefix_present
        && valid_from_present
        && valid_to_present
        && signature_alg_allowed
        && trust_status_passed;
    let failure_reason = if !entity_id_present {
        Some("entity_id_missing")
    } else if !metadata_url_present && !metadata_ref_present {
        Some("metadata_url_or_ref_missing")
    } else if !cert_fingerprint_prefix_present {
        Some("cert_fingerprint_prefix_missing_or_invalid")
    } else if !valid_from_present {
        Some("valid_from_missing")
    } else if !valid_to_present {
        Some("valid_to_missing")
    } else if !signature_alg_allowed {
        Some("signature_alg_not_allowed_or_missing")
    } else if !trust_status_passed {
        Some("trust_status_not_ready")
    } else {
        None
    };

    json!({
        "schema": "enterprise_saml_metadata_cert_trust.v1",
        "runtime_implemented": true,
        "passed": passed,
        "failure_reason": failure_reason,
        "entity_id_present": entity_id_present,
        "metadata_url_present": metadata_url_present,
        "metadata_ref_present": metadata_ref_present,
        "cert_fingerprint_prefix_present": cert_fingerprint_prefix_present,
        "cert_fingerprint_prefix": trust.cert_fingerprint_prefix.as_deref().map(str::trim),
        "valid_from_present": valid_from_present,
        "valid_to_present": valid_to_present,
        "signature_alg": signature_alg,
        "signature_alg_allowed": signature_alg_allowed,
        "allowed_signature_algs": ["RS256", "RS384", "RS512", "RSA-SHA256", "RSA-SHA384", "RSA-SHA512", "ES256"],
        "trust_status": trust_status,
        "metadata_xml_parsed": false,
        "metadata_xml_accepted": false,
        "certificate_body_accepted": false,
        "private_key_accepted": false,
        "network_requests": false,
        "future_validator": "metadata_fetch_and_cert_chain_validator"
    })
}

fn summary_bool(summary: Option<&Value>, keys: &[&str]) -> bool {
    keys.iter().any(|key| {
        summary
            .and_then(|value| value.get(*key))
            .and_then(Value::as_bool)
            .unwrap_or(false)
    })
}

fn summary_string_present(summary: Option<&Value>, keys: &[&str]) -> bool {
    keys.iter().any(|key| {
        summary
            .and_then(|value| value.get(*key))
            .and_then(Value::as_str)
            .is_some_and(|value| !value.trim().is_empty())
    })
}

fn summary_count_positive(summary: Option<&Value>, keys: &[&str]) -> bool {
    keys.iter().any(|key| {
        summary
            .and_then(|value| value.get(*key))
            .and_then(Value::as_u64)
            .is_some_and(|count| count > 0)
    })
}

fn summary_count_value(summary: Option<&Value>, keys: &[&str]) -> usize {
    keys.iter()
        .find_map(|key| {
            summary
                .and_then(|value| value.get(*key))
                .and_then(Value::as_u64)
        })
        .unwrap_or(0) as usize
}

fn enterprise_identity_binding_mapping_result(
    provider_type: &str,
    request_group_count: usize,
    request_role_count: usize,
) -> Value {
    let configured_roles = enterprise_identity_mapping_summary(provider_type, "ROLE_MAPPING");
    let configured_groups = enterprise_identity_mapping_summary(provider_type, "GROUP_MAPPING");
    let configured = configured_roles["configured"] == json!(true)
        || configured_groups["configured"] == json!(true);
    json!({
        "status": if configured { "mapped-presence-only" } else { "mapping-config-needed" },
        "provider_type": provider_type,
        "input_group_count": request_group_count,
        "input_role_count": request_role_count,
        "configured_mapped_groups": configured_groups,
        "configured_mapped_roles": configured_roles,
        "values_returned": false,
        "raw_claim_values_returned": false,
        "next_step": if configured {
            "Use these counts only with server-validated OIDC claims or SAML attributes."
        } else {
            "Configure provider role/group mapping before enabling SSO session creation."
        }
    })
}

fn enterprise_identity_binding_status(
    existing_identity: Option<&EnterpriseIdentityRow>,
    email_user: Option<&EnterpriseUserRow>,
    matched_user: Option<&EnterpriseIdentityUserMatch>,
    apply: bool,
) -> &'static str {
    if existing_identity.is_some() {
        "binding-exists"
    } else if email_user.is_some() && apply {
        "ready-to-apply"
    } else if matched_user.is_some() {
        "matched-local-user"
    } else {
        "local-user-not-found"
    }
}

fn enterprise_identity_binding_next_step(status: &str) -> &'static str {
    match status {
        "binding-applied" | "binding-exists" => {
            "Use the same endpoint for idempotent readback after real OIDC/SAML validation; session creation remains disabled here."
        }
        "matched-local-user" | "ready-to-apply" => {
            "Call with apply=true to link this verified subject hash to the matched local user; no user or session will be created."
        }
        _ => {
            "Create or invite the local user through the user management flow first, then re-run this binding plan with a verified subject hash."
        }
    }
}

fn enterprise_identity_session_issue_status(
    identity: Option<&EnterpriseIdentityRow>,
    matched_user_active: bool,
) -> &'static str {
    if identity.is_none() {
        "identity-binding-not-found"
    } else if matched_user_active {
        "session-issue-ready"
    } else {
        "bound-user-not-active"
    }
}

fn normalize_enterprise_session_idempotency_key(value: &str) -> Result<String, AdminError> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return Err(AdminError::bad_request("idempotency_key must not be empty"));
    }
    if trimmed.len() > 128 || looks_like_secret_value(trimmed) {
        return Err(AdminError::bad_request(
            "idempotency_key must be a short non-secret replay key",
        ));
    }
    Ok(sha256_hex(&format!(
        "enterprise-identity-session:explicit-idempotency:v1:{trimmed}"
    )))
}

fn enterprise_identity_session_idempotency_hash(
    tenant_id: Uuid,
    identity: &EnterpriseIdentityRow,
    verified_by: EnterpriseIdentityVerifiedBy,
    explicit_hash: Option<&str>,
) -> String {
    explicit_hash.map(str::to_string).unwrap_or_else(|| {
        sha256_hex(&format!(
            "enterprise-identity-session:default-idempotency:v1:{tenant_id}:{}:{}",
            identity.id,
            verified_by.as_str()
        ))
    })
}

async fn expire_enterprise_identity_sessions_by_idempotency_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    idempotency_key_hash: &str,
) -> Result<(), AdminError> {
    sqlx::query(
        r#"
        update user_sessions
        set status = 'expired'
        where tenant_id = $1
          and metadata->>'enterprise_identity_session_idempotency_key_hash' = $2
          and status = 'active'
          and expires_at <= now()
        "#,
    )
    .bind(tenant_id)
    .bind(idempotency_key_hash)
    .execute(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(())
}

async fn find_enterprise_identity_session_by_idempotency_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    idempotency_key_hash: &str,
) -> Result<Option<EnterpriseIdentitySessionRecord>, AdminError> {
    let row = sqlx::query(
        r#"
        select
          id,
          status,
          expires_at::text as expires_at,
          metadata->>'user_identity_id' as user_identity_id,
          metadata->>'enterprise_identity_verified_by' as verified_by,
          metadata->>'enterprise_identity_session_idempotency_key_hash' as idempotency_key_hash,
          (metadata->>'enterprise_identity_audit_id')::uuid as audit_id
        from user_sessions
        where tenant_id = $1
          and metadata->>'enterprise_identity_session_idempotency_key_hash' = $2
          and status = 'active'
          and revoked_at is null
          and expires_at > now()
        order by created_at desc
        limit 1
        for update
        "#,
    )
    .bind(tenant_id)
    .bind(idempotency_key_hash)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.map(|row| {
        let user_identity_id = row
            .try_get::<Option<Uuid>, _>("user_identity_id")
            .map_err(db_row_error)?
            .ok_or_else(|| {
                AdminError::configuration_error("stored enterprise session identity id is missing")
            })?;
        Ok(EnterpriseIdentitySessionRecord {
            id: row.try_get("id").map_err(db_row_error)?,
            status: row.try_get("status").map_err(db_row_error)?,
            expires_at: row.try_get("expires_at").map_err(db_row_error)?,
            user_identity_id,
            verified_by: row
                .try_get::<Option<String>, _>("verified_by")
                .map_err(db_row_error)?
                .unwrap_or_else(|| "unknown".to_string()),
            idempotency_key_hash: row
                .try_get::<Option<String>, _>("idempotency_key_hash")
                .map_err(db_row_error)?
                .unwrap_or_else(|| idempotency_key_hash.to_string()),
            audit_id: row.try_get("audit_id").map_err(db_row_error)?,
            replayed: true,
        })
    })
    .transpose()
}

async fn insert_enterprise_identity_session_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    identity: &EnterpriseIdentityRow,
    verified_by: EnterpriseIdentityVerifiedBy,
    idempotency_key_hash: &str,
    audit_id: Uuid,
) -> Result<EnterpriseIdentitySessionRecord, AdminError> {
    let generated = generate_session_token();
    let row = sqlx::query(
        r#"
        insert into user_sessions (
          tenant_id, user_id, token_lookup_prefix, token_hash, status,
          user_agent, metadata, expires_at
        )
        values ($1, $2, $3, $4, 'active',
                'enterprise-identity-session-issue-plan',
                $5::jsonb,
                now() + interval '8 hours')
        returning id, status, expires_at::text as expires_at
        "#,
    )
    .bind(tenant_id)
    .bind(identity.user_id)
    .bind(&generated.prefix)
    .bind(&generated.token_hash)
    .bind(json!({
        "schema": "enterprise_identity_session.v1",
        "user_identity_id": identity.id,
        "enterprise_identity_provider_type": identity.provider_type,
        "enterprise_identity_verified_by": verified_by.as_str(),
        "enterprise_identity_session_idempotency_key_hash": idempotency_key_hash,
        "enterprise_identity_audit_id": audit_id,
        "session_token_returned": false,
        "cookie_returned": false,
        "authorization_returned": false,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(EnterpriseIdentitySessionRecord {
        id: row.try_get("id").map_err(db_row_error)?,
        status: row.try_get("status").map_err(db_row_error)?,
        expires_at: row.try_get("expires_at").map_err(db_row_error)?,
        user_identity_id: identity.id,
        verified_by: verified_by.as_str().to_string(),
        idempotency_key_hash: idempotency_key_hash.to_string(),
        audit_id: Some(audit_id),
        replayed: false,
    })
}

fn enterprise_identity_session_issue_plan_response(
    tenant_id: Uuid,
    input: &EnterpriseIdentitySessionIssueInput,
    provider_type: &str,
    identity: Option<&EnterpriseIdentityRow>,
    user: Option<&EnterpriseIdentityUserMatch>,
    status: &str,
    audit_id: Option<Uuid>,
    session_record: Option<&EnterpriseIdentitySessionRecord>,
) -> Value {
    let session_created = session_record.is_some();
    let session_replayed = session_record
        .map(|record| record.replayed)
        .unwrap_or(false);
    let final_status = if session_replayed {
        "session-replayed"
    } else if session_created {
        "session-issued"
    } else {
        status
    };
    json!({
        "schema": "enterprise_identity_session_issue_plan.v1",
        "tenant_id": tenant_id,
        "status": final_status,
        "secret_safe": true,
        "runtime_implemented": true,
        "dry_run": !input.apply,
        "apply_requested": input.apply,
        "provider_type": provider_type,
        "verified_by": input.verified_by.as_str(),
        "session_id": session_record.map(|record| record.id),
        "expires_at": session_record.map(|record| record.expires_at.as_str()),
        "input_summary": enterprise_identity_session_input_summary(input),
        "tenant_user_binding_summary": {
            "tenant_id": tenant_id,
            "matched_user": user.map(|user| user.as_json()).unwrap_or_else(|| json!({
                "status": "not-found",
                "user_id": null,
                "source": "none",
                "email_present": false,
                "display_name_present": false,
                "raw_email_returned": false
            })),
            "user_identity": {
                "status": if identity.is_some() { "bound" } else { "not-found" },
                "identity_id": identity.map(|identity| identity.id),
                "provider_type": provider_type,
                "lookup": "user_identities(id) or user_identities(provider, provider_subject, tenant_id)",
                "external_subject_hash_present": input.external_subject_hash_present(),
                "raw_subject_returned": false,
                "raw_claims_returned": false
            },
            "tenant_boundary_enforced": true,
            "would_create_user": false,
            "create_user_disabled": true
        },
        "role_group_mapping_summary": enterprise_identity_binding_mapping_result(provider_type, 0, 0),
        "session_policy": {
            "status": session_record.map(|record| record.status.as_str()).unwrap_or("not-created"),
            "session_creation_disabled": false,
            "session_creation_disabled_reason": Value::Null,
            "bounded_session_creation_available": true,
            "session_created": session_created,
            "session_id": session_record.map(|record| record.id),
            "session_status": session_record.map(|record| record.status.as_str()),
            "session_expires_at": session_record.map(|record| record.expires_at.as_str()),
            "session_replayed": session_replayed,
            "cookie_returned": false,
            "authorization_returned": false,
            "raw_token_or_assertion_returned": false,
            "raw_session_token_returned": false,
            "idempotency_key_hash_present": session_record
                .map(|record| !record.idempotency_key_hash.is_empty())
                .unwrap_or(input.idempotency_key_hash.is_some()),
            "raw_idempotency_key_returned": false,
            "readback_source": if session_created { "user_sessions" } else { "plan_only" },
            "write_behavior": if session_replayed {
                "idempotent_replay"
            } else if session_created {
                "bounded_user_session_insert"
            } else {
                "dry_run_only"
            }
        },
        "audit_id": audit_id,
        "readback": {
            "readback_path": "POST /admin/enterprise/identity-sessions/issue-plan",
            "audit_readback_path": "GET /admin/audit-logs",
            "session_readback_path": "user_sessions(metadata.enterprise_identity_session_idempotency_key_hash)",
            "audit_action": if session_created {
                "enterprise_identity.session_issued"
            } else {
                "none"
            },
            "audit_marker_written": false,
            "audit_written": audit_id.is_some(),
            "session_creation_disabled": false,
            "session_created": session_created,
            "session_id": session_record.map(|record| record.id),
            "user_identity_id": session_record.map(|record| record.user_identity_id),
            "verified_by": session_record.map(|record| record.verified_by.as_str()),
            "idempotency_key_fingerprint": session_record
                .map(|record| subscription_scheduler_public_fingerprint(&record.idempotency_key_hash)),
            "raw_session_token_returned": false,
            "raw_idempotency_key_returned": false
        },
        "omitted_fields": enterprise_identity_session_issue_omitted_fields(),
        "next_step": enterprise_identity_session_issue_next_step(final_status)
    })
}

fn enterprise_identity_session_input_summary(input: &EnterpriseIdentitySessionIssueInput) -> Value {
    match &input.lookup {
        EnterpriseIdentitySessionLookup::IdentityId { user_identity_id } => json!({
            "lookup_mode": "user_identity_id",
            "user_identity_id": user_identity_id,
            "user_id_present": false,
            "provider_type_present": false,
            "external_subject_hash_present": false,
            "verified_by": input.verified_by.as_str(),
            "idempotency_key_hash_present": input.idempotency_key_hash.is_some(),
            "raw_idempotency_key_returned": false,
            "raw_subject_returned": false
        }),
        EnterpriseIdentitySessionLookup::BoundSubject {
            user_id,
            provider_type,
            ..
        } => json!({
            "lookup_mode": "bound_subject",
            "user_identity_id": null,
            "user_id": user_id,
            "provider_type": provider_type,
            "external_subject_hash_present": true,
            "verified_by": input.verified_by.as_str(),
            "idempotency_key_hash_present": input.idempotency_key_hash.is_some(),
            "raw_idempotency_key_returned": false,
            "raw_subject_returned": false
        }),
    }
}

impl EnterpriseIdentitySessionIssueInput {
    fn external_subject_hash_present(&self) -> bool {
        matches!(
            self.lookup,
            EnterpriseIdentitySessionLookup::BoundSubject { .. }
        )
    }
}

fn enterprise_identity_session_issue_omitted_fields() -> Value {
    json!([
        "raw token",
        "raw assertion",
        "raw claims",
        "raw subject",
        "Authorization",
        "client secret",
        "private key",
        "certificate body",
        "session cookie",
        "bounded session secret"
    ])
}

fn enterprise_identity_session_issue_next_step(status: &str) -> &'static str {
    match status {
        "session-disabled-marker-written" => {
            "Read GET /admin/audit-logs for the disabled-session marker; wire a reviewed enterprise session table/path before issuing real sessions."
        }
        "session-disabled-marker-ready" | "session-issue-ready" => {
            "Call with apply=true to write or replay a bounded local user_sessions record, or keep dry-run until a verified IdP executor is available."
        }
        "bound-user-not-active" => {
            "Restore or activate the bound local user before attempting session issuance."
        }
        _ => {
            "Complete verified subject binding first, then re-run this issue plan with user_identity_id or user_id/provider_type/external_subject_hash."
        }
    }
}

fn enterprise_identity_validation_next_step(provider_type: &str, status: &str) -> &'static str {
    match (provider_type, status) {
        ("oidc", "validation-pending") => {
            "Configuration presence is ready; implement real authorization-code exchange and JWKS ID token validation before enabling callback login."
        }
        ("saml", "validation-pending") => {
            "Configuration presence is ready; implement ACS handling and XML signature/assertion validation before enabling SAML login."
        }
        (_, "config-needed") => {
            "Complete metadata, trust anchors, and role/group mapping config before implementing runtime validation."
        }
        _ => "Enable this provider before creating a validation implementation plan.",
    }
}

impl EnterpriseAccountsQuery {
    fn into_filters(self) -> Result<EnterpriseAccountFilters, AdminError> {
        Ok(EnterpriseAccountFilters {
            sales_stage: match self.sales_stage {
                Some(value) => Some(normalize_enterprise_sales_stage(&value)?),
                None => None,
            },
            sso_status: match self.sso_status {
                Some(value) => Some(normalize_enterprise_sso_status_filter(&value)?),
                None => None,
            },
            billing_status: match self.billing_status {
                Some(value) => Some(normalize_enterprise_billing_status_filter(&value)?),
                None => None,
            },
        })
    }
}

impl EnterpriseAccountFilters {
    fn matches(&self, sales_stage: &str, sso_status: &str, billing_status: &str) -> bool {
        self.sales_stage
            .as_deref()
            .is_none_or(|value| value == sales_stage)
            && self
                .sso_status
                .as_deref()
                .is_none_or(|value| value == sso_status)
            && self
                .billing_status
                .as_deref()
                .is_none_or(|value| value == billing_status)
    }

    fn as_json(&self) -> Value {
        json!({
            "sales_stage": self.sales_stage,
            "sso_status": self.sso_status,
            "billing_status": self.billing_status,
            "supported": {
                "sales_stage": enterprise_sales_stage_values(),
                "sso_status": enterprise_sso_status_values(),
                "billing_status": enterprise_billing_status_values()
            }
        })
    }
}

impl EnterpriseSalesDashboardScope {
    fn from_query(value: Option<&str>) -> Result<Self, AdminError> {
        match value
            .unwrap_or("current_tenant")
            .trim()
            .to_ascii_lowercase()
            .replace('-', "_")
            .as_str()
        {
            "current_tenant" | "current" | "tenant" => Ok(Self::CurrentTenant),
            "all_tenants" | "all" | "cross_tenant" => Ok(Self::AllTenants),
            _ => Err(AdminError::bad_request(
                "scope must be current_tenant or all_tenants",
            )),
        }
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::CurrentTenant => "current_tenant",
            Self::AllTenants => "all_tenants",
        }
    }
}

impl EnterpriseIdentityBindingPlanRequest {
    fn into_input(self) -> Result<EnterpriseIdentityBindingInput, AdminError> {
        let provider_type = normalize_enterprise_identity_provider(&self.provider_type)?;
        let external_subject_hash =
            normalize_enterprise_external_subject_hash(&self.external_subject_hash)?;
        let email = self
            .email
            .map(|value| normalize_enterprise_identity_email(&value))
            .transpose()?;
        let domain = self
            .domain
            .map(|value| normalize_enterprise_identity_domain(&value))
            .transpose()?;
        if let (Some(email), Some(domain)) = (email.as_deref(), domain.as_deref()) {
            let email_domain = email
                .rsplit_once('@')
                .map(|(_, value)| value)
                .unwrap_or_default();
            if email_domain != domain {
                return Err(AdminError::bad_request("domain must match email domain"));
            }
        }
        if contains_forbidden_enterprise_identity_binding_material(&self.fixture_subject_summary) {
            return Err(AdminError::bad_request(
                "fixture_subject_summary must not contain raw token, assertion, claim, subject, secret, Authorization, private key, certificate, or email values",
            ));
        }
        let mapped_groups = normalize_enterprise_identity_label_list(self.mapped_groups)?;
        let mapped_roles = normalize_enterprise_identity_label_list(self.mapped_roles)?;

        Ok(EnterpriseIdentityBindingInput {
            provider_type,
            external_subject_hash,
            email,
            domain,
            mapped_groups,
            mapped_roles,
            fixture_subject_summary_present: self.fixture_subject_summary.is_some(),
            apply: self.apply.unwrap_or(false),
        })
    }
}

impl EnterpriseIdentitySessionIssuePlanRequest {
    fn into_input(self) -> Result<EnterpriseIdentitySessionIssueInput, AdminError> {
        let verified_by = EnterpriseIdentityVerifiedBy::parse(&self.verified_by)?;
        let identity_lookup_requested = self.user_identity_id.is_some();
        let subject_lookup_requested = self.user_id.is_some()
            || self.provider_type.is_some()
            || self.external_subject_hash.is_some();
        if identity_lookup_requested == subject_lookup_requested {
            return Err(AdminError::bad_request(
                "request must provide either user_identity_id or user_id + provider_type + external_subject_hash",
            ));
        }

        let lookup = if let Some(user_identity_id) = self.user_identity_id {
            EnterpriseIdentitySessionLookup::IdentityId { user_identity_id }
        } else {
            let user_id = self.user_id.ok_or_else(|| {
                AdminError::bad_request(
                    "user_id is required with provider_type and external_subject_hash",
                )
            })?;
            let provider_type = normalize_enterprise_identity_provider(
                self.provider_type.as_deref().ok_or_else(|| {
                    AdminError::bad_request(
                        "provider_type is required with user_id and external_subject_hash",
                    )
                })?,
            )?;
            let external_subject_hash = normalize_enterprise_external_subject_hash(
                self.external_subject_hash.as_deref().ok_or_else(|| {
                    AdminError::bad_request(
                        "external_subject_hash is required with user_id and provider_type",
                    )
                })?,
            )?;
            if provider_type != verified_by.provider_type() {
                return Err(AdminError::bad_request(
                    "verified_by marker must match provider_type",
                ));
            }
            EnterpriseIdentitySessionLookup::BoundSubject {
                user_id,
                provider_type,
                external_subject_hash,
            }
        };

        Ok(EnterpriseIdentitySessionIssueInput {
            lookup,
            verified_by,
            idempotency_key_hash: self
                .idempotency_key
                .map(|value| normalize_enterprise_session_idempotency_key(&value))
                .transpose()?,
            apply: self.apply.unwrap_or(false),
        })
    }
}

impl EnterpriseIdentitySessionIssueInput {
    fn user_id(&self) -> Option<Uuid> {
        match self.lookup {
            EnterpriseIdentitySessionLookup::IdentityId { .. } => None,
            EnterpriseIdentitySessionLookup::BoundSubject { user_id, .. } => Some(user_id),
        }
    }

    fn provider_type(&self) -> Option<&str> {
        match &self.lookup {
            EnterpriseIdentitySessionLookup::IdentityId { .. } => None,
            EnterpriseIdentitySessionLookup::BoundSubject { provider_type, .. } => {
                Some(provider_type.as_str())
            }
        }
    }
}

impl EnterpriseIdentityVerifiedBy {
    fn parse(value: &str) -> Result<Self, AdminError> {
        match value.trim() {
            "oidc_mock_executor" => Ok(Self::OidcMockExecutor),
            "saml_mock_executor" => Ok(Self::SamlMockExecutor),
            _ => Err(AdminError::bad_request(
                "verified_by must be oidc_mock_executor or saml_mock_executor",
            )),
        }
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::OidcMockExecutor => "oidc_mock_executor",
            Self::SamlMockExecutor => "saml_mock_executor",
        }
    }

    fn provider_type(self) -> &'static str {
        match self {
            Self::OidcMockExecutor => "oidc",
            Self::SamlMockExecutor => "saml",
        }
    }
}

fn fixture_bool(summary: &Option<Value>, key: &str) -> Option<bool> {
    summary
        .as_ref()
        .and_then(|summary| summary.get(key))
        .and_then(Value::as_bool)
}

fn normalize_enterprise_oidc_jwks_alg(value: &str) -> Result<String, AdminError> {
    let normalized = value.trim().to_ascii_uppercase();
    match normalized.as_str() {
        "RS256" | "ES256" => Ok(normalized),
        _ => Err(AdminError::bad_request(
            "jwks_validation.alg must be RS256 or ES256",
        )),
    }
}

fn normalize_enterprise_oidc_subject_hash_source(value: &str) -> Result<String, AdminError> {
    let normalized = value.trim().to_ascii_lowercase();
    if normalized.is_empty() || normalized.len() > 80 {
        return Err(AdminError::bad_request(
            "verified_subject_hash_source must be a short safe label",
        ));
    }
    if !normalized
        .chars()
        .all(|ch| ch.is_ascii_lowercase() || ch.is_ascii_digit() || ch == '_' || ch == '-')
    {
        return Err(AdminError::bad_request(
            "verified_subject_hash_source must contain only lowercase letters, digits, '_' or '-'",
        ));
    }
    match normalized.as_str() {
        "server_side_verified_id_token_sub_sha256"
        | "fixture_verified_subject_hash"
        | "verified_claims_summary_subject_hash"
        | "external_subject_hash_field" => Ok(normalized),
        _ => Err(AdminError::bad_request(
            "verified_subject_hash_source must be an approved safe source label",
        )),
    }
}

fn normalize_enterprise_oidc_safe_metadata(
    field: &str,
    value: Option<String>,
    max_len: usize,
) -> Result<Option<String>, AdminError> {
    value
        .map(|value| {
            let trimmed = value.trim().to_string();
            if trimmed.is_empty()
                || trimmed.len() > max_len
                || trimmed.contains(char::is_whitespace)
                || looks_like_secret_value(&trimmed)
            {
                return Err(AdminError::bad_request(format!(
                    "{field} must be short non-secret metadata"
                )));
            }
            Ok(trimmed)
        })
        .transpose()
}

fn normalize_enterprise_oidc_issuer_url(
    value: Option<String>,
) -> Result<Option<String>, AdminError> {
    value
        .map(|value| {
            let trimmed = value.trim().trim_end_matches('/').to_ascii_lowercase();
            if trimmed.is_empty()
                || trimmed.len() > 512
                || !trimmed.starts_with("https://")
                || trimmed.contains(char::is_whitespace)
                || looks_like_secret_value(&trimmed)
            {
                return Err(AdminError::bad_request(
                    "issuer_url must be a secret-safe https URL",
                ));
            }
            Ok(trimmed)
        })
        .transpose()
}

fn enterprise_oidc_jwt_jwks_parser_fetch_adapter_readback(
    request: Option<EnterpriseOidcJwtJwksParserFetchRequest>,
    fallback_alg: Option<&str>,
    external_subject_hash: &str,
) -> Result<(Value, Value, bool, Vec<String>), AdminError> {
    let Some(request) = request else {
        let crypto_parser_result = enterprise_oidc_jwt_jwks_crypto_parser_result(
            None,
            None,
            None,
            None,
            None,
            external_subject_hash,
        )?;
        let crypto_parser_passed = crypto_parser_result
            .get("passed")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let crypto_parser_failure_reasons =
            enterprise_oidc_value_string_list(&crypto_parser_result, "failure_reasons");
        return Ok((
            json!({
                "schema": "enterprise_oidc_jwt_jwks_parser_fetch_adapter.v1",
                "implementation": "network_disabled",
                "runtime_implemented": true,
                "executor_boundary": "typed_fetch_parse_executor",
                "network_enabled": false,
                "network_call_enabled": false,
                "network_call_performed": false,
                "raw_id_token_accepted": false,
                "raw_id_token_returned": false,
                "jwks_body_accepted": false,
                "jwks_body_returned": false,
                "client_secret_accepted": false,
                "authorization_header_accepted": false,
                "typed_request_present": false,
                "typed_request_complete": false,
                "readiness": "missing_typed_request",
                "refusal_reason": "jwt_jwks_parser_fetch_request_missing",
                "blocked": true,
                "blocked_reasons": ["missing_issuer", "missing_jwks_uri", "missing_kid", "missing_alg", "missing_audience", "missing_nonce", "missing_subject_hash", "network_disabled"],
                "required_fields": ["issuer_url|issuer", "jwks_uri_ref|jwks_uri", "kid", "alg", "audience", "nonce", "subject_hash"],
                "fetch_request_plan": {
                    "method": "GET",
                    "issuer_present": false,
                    "jwks_uri_present": false,
                    "kid_present": false,
                    "alg_present": false,
                    "audience_present": false,
                    "nonce_present": false,
                    "network_enabled": false,
                    "network_call_performed": false,
                    "would_fetch_jwks": false,
                    "replaceable_fetcher_trait": "EnterpriseOidcJwksFetcher"
                },
                "parser_input_summary": {
                    "raw_id_token_present": false,
                    "raw_jwks_body_present": false,
                    "raw_claims_present": false,
                    "crypto_parser_metadata_present": false,
                    "allowed_algs": ["RS256", "ES256"]
                },
                "crypto_result_readback": crypto_parser_result.clone(),
                "result": {
                    "status": "not_attempted",
                    "parser": "network_disabled",
                    "fetch": "network_disabled",
                    "crypto_parser_result": crypto_parser_result.clone(),
                    "subject_hash_matches_request": false
                }
            }),
            crypto_parser_result,
            crypto_parser_passed,
            crypto_parser_failure_reasons,
        ));
    };

    let issuer_url = normalize_enterprise_oidc_issuer_url(request.issuer_url.or(request.issuer))?;
    let jwks_uri_ref = normalize_enterprise_oidc_safe_metadata(
        "jwks_uri_ref",
        request.jwks_uri_ref.or(request.jwks_uri),
        512,
    )?;
    let kid = normalize_enterprise_oidc_safe_metadata("kid", request.kid, 160)?;
    let audience = normalize_enterprise_oidc_safe_metadata("audience", request.audience, 256)?;
    let nonce = normalize_enterprise_oidc_safe_metadata("nonce", request.nonce, 160)?;
    let alg = normalize_enterprise_oidc_safe_metadata("alg", request.alg, 32)?
        .map(|value| value.to_ascii_uppercase())
        .or_else(|| fallback_alg.map(str::to_string));
    let alg_allowlisted = alg
        .as_deref()
        .is_some_and(|value| matches!(value, "RS256" | "ES256"));
    let subject_hash = request
        .subject_hash
        .as_deref()
        .map(normalize_enterprise_external_subject_hash)
        .transpose()?;
    let subject_hash_matches_request = subject_hash
        .as_deref()
        .is_some_and(|value| value == external_subject_hash);
    let crypto_parser_result = enterprise_oidc_jwt_jwks_crypto_parser_result(
        request.crypto_parser,
        issuer_url.as_deref(),
        kid.as_deref(),
        alg.as_deref(),
        subject_hash.as_deref(),
        external_subject_hash,
    )?;
    let crypto_parser_passed = crypto_parser_result
        .get("passed")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let crypto_parser_failure_reasons =
        enterprise_oidc_value_string_list(&crypto_parser_result, "failure_reasons");
    let mut missing_fields = Vec::new();
    if issuer_url.is_none() {
        missing_fields.push("issuer_url");
    }
    if jwks_uri_ref.is_none() {
        missing_fields.push("jwks_uri_ref");
    }
    if kid.is_none() {
        missing_fields.push("kid");
    }
    if alg.is_none() {
        missing_fields.push("alg");
    }
    if audience.is_none() {
        missing_fields.push("audience");
    }
    if nonce.is_none() {
        missing_fields.push("nonce");
    }
    if subject_hash.is_none() {
        missing_fields.push("subject_hash");
    }
    let typed_request_complete = missing_fields.is_empty();
    let mut blocked_reasons: Vec<String> = missing_fields
        .iter()
        .map(|field| format!("missing_{field}"))
        .collect();
    if alg.is_some() && !alg_allowlisted {
        blocked_reasons.push("unsupported_alg".to_string());
    }
    if typed_request_complete && !subject_hash_matches_request {
        blocked_reasons.push("subject_hash_mismatch".to_string());
    }
    for reason in &crypto_parser_failure_reasons {
        match reason.as_str() {
            "nonce_mismatch" => blocked_reasons.push("nonce_mismatch".to_string()),
            "exp_outside_allowed_window" => {
                blocked_reasons.push("expired_token_metadata".to_string())
            }
            "header_alg_not_allowlisted" => blocked_reasons.push("unsupported_alg".to_string()),
            _ => {}
        }
    }
    blocked_reasons.push("network_disabled".to_string());
    blocked_reasons.sort();
    blocked_reasons.dedup();
    let refusal_reason = blocked_reasons
        .first()
        .map(|reason| reason.as_str())
        .unwrap_or("network_disabled");
    let ready_for_future_network_client =
        typed_request_complete && alg_allowlisted && subject_hash_matches_request;

    Ok((
        json!({
            "schema": "enterprise_oidc_jwt_jwks_parser_fetch_adapter.v1",
            "implementation": "network_disabled",
            "runtime_implemented": true,
            "executor_boundary": "typed_fetch_parse_executor",
            "network_enabled": false,
            "network_call_enabled": false,
            "network_call_performed": false,
            "raw_id_token_accepted": false,
            "raw_id_token_returned": false,
            "jwks_body_accepted": false,
            "jwks_body_returned": false,
            "client_secret_accepted": false,
            "authorization_header_accepted": false,
            "typed_request_present": true,
            "typed_request_complete": typed_request_complete,
            "readiness": if ready_for_future_network_client {
                "ready_for_future_network_client"
            } else {
                "not_ready"
            },
            "blocked": !ready_for_future_network_client,
            "blocked_reasons": blocked_reasons,
            "refusal_reason": refusal_reason,
            "missing_fields": missing_fields,
            "fetch_request_plan": {
                "method": "GET",
                "issuer_present": issuer_url.is_some(),
                "issuer_url": issuer_url,
                "jwks_uri_present": jwks_uri_ref.is_some(),
                "jwks_uri_ref": jwks_uri_ref,
                "kid_present": kid.is_some(),
                "alg_present": alg.is_some(),
                "alg": alg,
                "alg_allowlisted": alg_allowlisted,
                "audience_present": audience.is_some(),
                "nonce_present": nonce.is_some(),
                "network_enabled": false,
                "network_call_performed": false,
                "would_fetch_jwks": false,
                "replaceable_fetcher_trait": "EnterpriseOidcJwksFetcher",
                "blocked_when": ["missing_issuer", "missing_jwks_uri", "missing_kid", "missing_alg", "missing_audience", "missing_nonce", "unsupported_alg", "network_disabled"]
            },
            "parser_input_summary": {
                "raw_id_token_present": false,
                "raw_jwks_body_present": false,
                "raw_claims_present": false,
                "issuer_present": issuer_url.is_some(),
                "jwks_uri_present": jwks_uri_ref.is_some(),
                "kid_present": kid.is_some(),
                "alg_present": alg.is_some(),
                "audience_present": audience.is_some(),
                "nonce_present": nonce.is_some(),
                "subject_hash_present": subject_hash.is_some(),
                "subject_hash_matches_request": subject_hash_matches_request,
                "crypto_parser_metadata_present": crypto_parser_result
                    .get("metadata_present")
                    .and_then(Value::as_bool)
                    .unwrap_or(false),
                "allowed_algs": ["RS256", "ES256"]
            },
            "crypto_result_readback": crypto_parser_result.clone(),
            "request": {
                "issuer_url": issuer_url,
                "jwks_uri_ref": jwks_uri_ref,
                "kid_present": kid.is_some(),
                "alg": alg,
                "audience_present": audience.is_some(),
                "nonce_present": nonce.is_some(),
                "subject_hash_present": subject_hash.is_some(),
                "subject_hash_matches_request": subject_hash_matches_request
            },
            "result": {
                "status": if crypto_parser_passed { "parsed_and_verified_from_fixture_safe_metadata" } else { "failed_or_incomplete" },
                "parser": "network_disabled",
                "fetch": "network_disabled",
                "claims_extracted": false,
                "signature_verified": crypto_parser_result
                    .get("signature_verification")
                    .and_then(|value| value.get("signature_verified"))
                    .and_then(Value::as_bool)
                    .unwrap_or(false),
                "crypto_parser_result": crypto_parser_result.clone(),
                "subject_hash_matches_request": subject_hash_matches_request,
                "future_result_fields": ["issuer", "kid", "alg", "audience", "nonce", "subject_hash", "signature_valid", "expires_at"]
            }
        }),
        crypto_parser_result,
        crypto_parser_passed,
        crypto_parser_failure_reasons,
    ))
}

fn enterprise_oidc_value_string_list(value: &Value, field: &str) -> Vec<String> {
    value
        .get(field)
        .and_then(Value::as_array)
        .map(|values| {
            values
                .iter()
                .filter_map(Value::as_str)
                .map(str::to_string)
                .collect()
        })
        .unwrap_or_default()
}

fn enterprise_oidc_current_unix_seconds() -> i64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_secs() as i64)
        .unwrap_or_default()
}

fn enterprise_oidc_jwt_jwks_crypto_parser_result(
    metadata: Option<EnterpriseOidcJwtJwksCryptoParserMetadata>,
    expected_issuer_url: Option<&str>,
    expected_kid: Option<&str>,
    expected_alg: Option<&str>,
    expected_subject_hash: Option<&str>,
    external_subject_hash: &str,
) -> Result<Value, AdminError> {
    let Some(metadata) = metadata else {
        return Ok(json!({
            "schema": "enterprise_oidc_jwt_jwks_crypto_parser_result.v1",
            "runtime_implemented": true,
            "input_mode": "fixture_safe_parsed_metadata",
            "metadata_present": false,
            "passed": false,
            "status": "metadata_missing",
            "failure_reasons": ["crypto_parser_metadata_missing"],
            "raw_id_token_accepted": false,
            "jwks_body_accepted": false,
            "raw_claims_accepted": false,
            "allowed_algs": ["RS256", "ES256"],
            "time_policy": {
                "clock_skew_seconds": 300,
                "max_token_age_seconds": 86400
            }
        }));
    };

    let header_alg = normalize_enterprise_oidc_safe_metadata(
        "crypto_parser.header_alg",
        metadata.header_alg,
        32,
    )?
    .map(|value| value.to_ascii_uppercase());
    let jwks_key_alg = normalize_enterprise_oidc_safe_metadata(
        "crypto_parser.jwks_key_alg",
        metadata.jwks_key_alg,
        32,
    )?
    .map(|value| value.to_ascii_uppercase());
    let header_kid = normalize_enterprise_oidc_safe_metadata(
        "crypto_parser.header_kid",
        metadata.header_kid,
        160,
    )?;
    let jwks_key_kid = normalize_enterprise_oidc_safe_metadata(
        "crypto_parser.jwks_key_kid",
        metadata.jwks_key_kid,
        160,
    )?;
    let claims_issuer_url = normalize_enterprise_oidc_issuer_url(metadata.claims_issuer_url)?;
    let claims_audience = normalize_enterprise_oidc_safe_metadata(
        "crypto_parser.claims_audience",
        metadata.claims_audience,
        256,
    )?;
    let claims_subject_hash = metadata
        .claims_subject_hash
        .as_deref()
        .map(normalize_enterprise_external_subject_hash)
        .transpose()?;
    let signature_verified = metadata.signature_verified.unwrap_or(false);
    let now = enterprise_oidc_current_unix_seconds();
    let clock_skew_seconds = 300_i64;
    let max_token_age_seconds = 86_400_i64;

    let alg_allowlisted = header_alg
        .as_deref()
        .is_some_and(|value| matches!(value, "RS256" | "ES256"));
    let alg_matches_expected = expected_alg
        .map(|expected| header_alg.as_deref() == Some(expected))
        .unwrap_or(header_alg.is_some());
    let alg_matches_jwks_key = jwks_key_alg
        .as_deref()
        .map(|jwks_alg| header_alg.as_deref() == Some(jwks_alg))
        .unwrap_or(header_alg.is_some());
    let kid_matches_expected = expected_kid
        .map(|expected| header_kid.as_deref() == Some(expected))
        .unwrap_or(header_kid.is_some());
    let kid_matches_jwks_key = jwks_key_kid
        .as_deref()
        .map(|jwks_kid| header_kid.as_deref() == Some(jwks_kid))
        .unwrap_or(header_kid.is_some());
    let issuer_matches_request = expected_issuer_url
        .map(|expected| claims_issuer_url.as_deref() == Some(expected))
        .unwrap_or(claims_issuer_url.is_some());
    let audience_present = claims_audience.is_some();
    let nonce_present = metadata.claims_nonce_present.unwrap_or(false);
    let nonce_matches_request = metadata.claims_nonce_matches_request.unwrap_or(false);
    let subject_hash_matches_request = claims_subject_hash.as_deref().is_some_and(|value| {
        value == external_subject_hash
            && expected_subject_hash
                .map(|expected| value == expected)
                .unwrap_or(true)
    });
    let exp_valid = metadata
        .claims_exp_unix
        .map(|exp| exp >= now - clock_skew_seconds)
        .unwrap_or(false);
    let iat_valid = metadata
        .claims_iat_unix
        .map(|iat| iat <= now + clock_skew_seconds && iat >= now - max_token_age_seconds)
        .unwrap_or(false);

    let mut failure_reasons = Vec::new();
    if header_alg.is_none() {
        failure_reasons.push("header_alg_missing".to_string());
    }
    if !alg_allowlisted {
        failure_reasons.push("header_alg_not_allowlisted".to_string());
    }
    if !alg_matches_expected {
        failure_reasons.push("header_alg_mismatch".to_string());
    }
    if !alg_matches_jwks_key {
        failure_reasons.push("header_alg_not_matched_to_jwks_key".to_string());
    }
    if header_kid.is_none() {
        failure_reasons.push("header_kid_missing".to_string());
    }
    if !kid_matches_expected {
        failure_reasons.push("header_kid_mismatch".to_string());
    }
    if !kid_matches_jwks_key {
        failure_reasons.push("header_kid_not_matched_to_jwks_key".to_string());
    }
    if !issuer_matches_request {
        failure_reasons.push("issuer_mismatch".to_string());
    }
    if !audience_present {
        failure_reasons.push("audience_missing".to_string());
    }
    if !nonce_present {
        failure_reasons.push("nonce_missing".to_string());
    }
    if !nonce_matches_request {
        failure_reasons.push("nonce_mismatch".to_string());
    }
    if !exp_valid {
        failure_reasons.push("exp_outside_allowed_window".to_string());
    }
    if !iat_valid {
        failure_reasons.push("iat_outside_allowed_window".to_string());
    }
    if !subject_hash_matches_request {
        failure_reasons.push("subject_hash_mismatch".to_string());
    }
    if !signature_verified {
        failure_reasons.push("signature_not_verified".to_string());
    }
    let passed = failure_reasons.is_empty();

    Ok(json!({
        "schema": "enterprise_oidc_jwt_jwks_crypto_parser_result.v1",
        "runtime_implemented": true,
        "input_mode": "fixture_safe_parsed_metadata",
        "metadata_present": true,
        "passed": passed,
        "status": if passed { "passed" } else { "failed" },
        "raw_id_token_accepted": false,
        "jwks_body_accepted": false,
        "raw_claims_accepted": false,
        "allowed_algs": ["RS256", "ES256"],
        "time_policy": {
            "clock_skew_seconds": clock_skew_seconds,
            "max_token_age_seconds": max_token_age_seconds,
            "now_unix": now
        },
        "header": {
            "alg": header_alg,
            "kid_present": header_kid.is_some(),
            "kid_matches_request": kid_matches_expected,
            "kid_matches_jwks_key": kid_matches_jwks_key
        },
        "claims": {
            "issuer_present": claims_issuer_url.is_some(),
            "issuer_matches_request": issuer_matches_request,
            "audience_present": audience_present,
            "nonce_present": nonce_present,
            "nonce_matches_request": nonce_matches_request,
            "exp_unix": metadata.claims_exp_unix,
            "exp_valid": exp_valid,
            "iat_unix": metadata.claims_iat_unix,
            "iat_valid": iat_valid,
            "subject_hash_present": claims_subject_hash.is_some(),
            "subject_hash_matches_request": subject_hash_matches_request
        },
        "signature_verification": {
            "signature_verified": signature_verified,
            "alg_allowlisted": alg_allowlisted,
            "alg_matches_request": alg_matches_expected,
            "alg_matches_jwks_key": alg_matches_jwks_key
        },
        "failure_reasons": failure_reasons
    }))
}

impl EnterpriseOidcExecuteValidatedLoginRequest {
    fn into_input(self) -> Result<EnterpriseOidcExecuteValidatedLoginInput, AdminError> {
        let external_subject_hash =
            normalize_enterprise_external_subject_hash(&self.external_subject_hash)?;
        let email = self
            .email
            .map(|value| normalize_enterprise_identity_email(&value))
            .transpose()?;
        let domain = self
            .domain
            .map(|value| normalize_enterprise_identity_domain(&value))
            .transpose()?;
        if let (Some(email), Some(domain)) = (email.as_deref(), domain.as_deref()) {
            let email_domain = email
                .rsplit_once('@')
                .map(|(_, value)| value)
                .unwrap_or_default();
            if email_domain != domain {
                return Err(AdminError::bad_request("domain must match email domain"));
            }
        }
        if self.verified_claims_summary.as_ref().is_some_and(|value| {
            enterprise_identity_binding_forbidden_field(value)
                || enterprise_oidc_execute_validated_login_forbidden_field(value).is_some()
        }) {
            return Err(AdminError::bad_request(
                "verified_claims_summary must contain only fixture-safe presence/count/status fields and no raw claims, subject, email, tokens, JWKS, secrets, Authorization, private keys, or certificate bodies",
            ));
        }
        let mapped_groups = normalize_enterprise_identity_label_list(self.mapped_groups)?;
        let mapped_roles = normalize_enterprise_identity_label_list(self.mapped_roles)?;
        let issuer_present = self.issuer_present.unwrap_or(
            self.verified_claims_summary
                .as_ref()
                .and_then(|summary| summary.get("issuer_present"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
        );
        let audience_client_id_present = self.audience_client_id_present.unwrap_or(
            self.verified_claims_summary
                .as_ref()
                .and_then(|summary| summary.get("audience_client_id_present"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
        );
        let nonce_valid = self.nonce_valid.unwrap_or(
            self.verified_claims_summary
                .as_ref()
                .and_then(|summary| summary.get("nonce_valid"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
        );
        let expiration_valid = self.expiration_valid.unwrap_or(
            self.verified_claims_summary
                .as_ref()
                .and_then(|summary| summary.get("expiration_valid"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
        );
        let issued_at_checked = self.issued_at_checked.unwrap_or(
            self.verified_claims_summary
                .as_ref()
                .and_then(|summary| summary.get("issued_at_checked"))
                .and_then(Value::as_bool)
                .unwrap_or(false),
        );
        let jwks_validation = self.jwks_validation.unwrap_or_default();
        let jwks_key_metadata_present = jwks_validation
            .key_metadata_present
            .or_else(|| fixture_bool(&self.verified_claims_summary, "jwks_key_metadata_present"))
            .unwrap_or(false);
        let jwks_key_fingerprint_present = jwks_validation
            .jwks_key_fingerprint_present
            .or_else(|| {
                fixture_bool(
                    &self.verified_claims_summary,
                    "jwks_key_fingerprint_present",
                )
            })
            .unwrap_or(jwks_key_metadata_present);
        let jwks_kid_present = jwks_validation
            .kid_present
            .or_else(|| fixture_bool(&self.verified_claims_summary, "kid_present"))
            .unwrap_or(false);
        let jwks_kid_matches_key = jwks_validation
            .kid_matches_jwks_key
            .or_else(|| fixture_bool(&self.verified_claims_summary, "kid_matches_jwks_key"))
            .unwrap_or(false);
        let jwks_alg = jwks_validation
            .alg
            .as_deref()
            .map(normalize_enterprise_oidc_jwks_alg)
            .transpose()?;
        let jwks_alg_present = jwks_alg.is_some()
            || jwks_validation
                .alg_present
                .or_else(|| fixture_bool(&self.verified_claims_summary, "alg_present"))
                .unwrap_or(false);
        let jwks_alg_allowlisted = jwks_validation
            .alg_allowlisted
            .or_else(|| fixture_bool(&self.verified_claims_summary, "alg_allowlisted"))
            .unwrap_or(false);
        let jwks_signature_valid = jwks_validation
            .signature_valid
            .or(self.jwks_validation_result)
            .unwrap_or(false);
        let verified_subject_hash_source = jwks_validation
            .verified_subject_hash_source
            .or_else(|| {
                self.verified_claims_summary
                    .as_ref()
                    .and_then(|summary| summary.get("verified_subject_hash_source"))
                    .and_then(Value::as_str)
                    .map(str::to_string)
            })
            .unwrap_or_else(|| "external_subject_hash_field".to_string());
        let verified_subject_hash_source =
            normalize_enterprise_oidc_subject_hash_source(&verified_subject_hash_source)?;
        let (
            jwt_jwks_parser_fetch_adapter,
            jwt_jwks_crypto_parser_result,
            jwt_jwks_crypto_parser_passed,
            jwt_jwks_crypto_parser_failure_reasons,
        ) = enterprise_oidc_jwt_jwks_parser_fetch_adapter_readback(
            self.jwt_jwks_parser_fetch,
            jwks_alg.as_deref(),
            &external_subject_hash,
        )?;
        let mut jwks_validation_failure_reasons = Vec::new();
        if !jwks_key_metadata_present {
            jwks_validation_failure_reasons.push("jwks_key_metadata_missing".to_string());
        }
        if !jwks_key_fingerprint_present {
            jwks_validation_failure_reasons.push("jwks_key_fingerprint_missing".to_string());
        }
        if !jwks_kid_present {
            jwks_validation_failure_reasons.push("kid_missing".to_string());
        }
        if !jwks_kid_matches_key {
            jwks_validation_failure_reasons.push("kid_not_matched_to_jwks_key".to_string());
        }
        if !jwks_alg_present {
            jwks_validation_failure_reasons.push("alg_missing".to_string());
        }
        if !jwks_alg_allowlisted {
            jwks_validation_failure_reasons.push("alg_not_allowlisted".to_string());
        }
        if !jwks_signature_valid {
            jwks_validation_failure_reasons.push("signature_not_verified".to_string());
        }
        if !issuer_present {
            jwks_validation_failure_reasons.push("issuer_not_validated".to_string());
        }
        if !audience_client_id_present {
            jwks_validation_failure_reasons.push("audience_client_id_not_validated".to_string());
        }
        if !nonce_valid {
            jwks_validation_failure_reasons.push("nonce_not_validated".to_string());
        }
        if !expiration_valid {
            jwks_validation_failure_reasons.push("expiration_not_validated".to_string());
        }
        if !issued_at_checked {
            jwks_validation_failure_reasons.push("issued_at_not_checked".to_string());
        }
        if !jwt_jwks_crypto_parser_passed {
            jwks_validation_failure_reasons.push("crypto_parser_failed".to_string());
            jwks_validation_failure_reasons.extend(
                jwt_jwks_crypto_parser_failure_reasons
                    .into_iter()
                    .map(|reason| format!("crypto_parser:{reason}")),
            );
        }
        let jwks_validation_passed = jwks_validation_failure_reasons.is_empty();
        let verified_group_count = summary_count_value(
            self.verified_claims_summary.as_ref(),
            &["mapped_group_count", "group_value_count", "group_count"],
        );
        let verified_role_count = summary_count_value(
            self.verified_claims_summary.as_ref(),
            &["mapped_role_count", "role_value_count", "role_count"],
        );

        Ok(EnterpriseOidcExecuteValidatedLoginInput {
            external_subject_hash,
            email,
            domain,
            mapped_groups,
            mapped_roles,
            verified_claims_summary_present: self.verified_claims_summary.is_some(),
            jwks_validation_passed,
            jwks_key_metadata_present,
            jwks_key_fingerprint_present,
            jwks_kid_present,
            jwks_kid_matches_key,
            jwks_alg_present,
            jwks_alg_allowlisted,
            jwks_signature_valid,
            jwks_alg,
            verified_subject_hash_source,
            jwt_jwks_parser_fetch_adapter,
            jwt_jwks_crypto_parser_result,
            jwt_jwks_crypto_parser_passed,
            jwks_validation_failure_reasons,
            issuer_present,
            audience_client_id_present,
            verified_group_count,
            verified_role_count,
            nonce_valid,
            expiration_valid,
            issued_at_checked,
            apply: self.apply.unwrap_or(false),
        })
    }
}

impl EnterpriseSamlExecuteValidatedAcsRequest {
    fn into_input(self) -> Result<EnterpriseSamlExecuteValidatedAcsInput, AdminError> {
        let assertion_validation_result = self.assertion_validation_result.unwrap_or(true);
        let issuer_validation_result = self.issuer_validation_result.unwrap_or(true);
        let audience_validation_result = self.audience_validation_result.unwrap_or(true);
        let time_conditions_validation_result =
            self.time_conditions_validation_result.unwrap_or(true);

        if contains_forbidden_enterprise_saml_executor_material(&self.verified_assertion_summary)
            || contains_forbidden_enterprise_saml_executor_material(&self.fixture_assertion_summary)
            || contains_forbidden_enterprise_saml_executor_material(&self.parsed_assertion_summary)
        {
            return Err(AdminError::bad_request(
                "SAML assertion summaries must not contain raw SAMLResponse, assertion XML, claim values, subject, email, attributes, secrets, Authorization, private key, or certificate body",
            ));
        }

        let saml_xml_signature_parser_executor =
            enterprise_saml_xml_signature_parser_executor_readback(
                self.saml_xml_signature_parser_executor,
            )?;
        let external_subject_hash =
            normalize_enterprise_external_subject_hash(&self.external_subject_hash)?;
        let parsed_summary = self
            .assertion_validator_input
            .as_ref()
            .map(enterprise_saml_assertion_validator_summary_from_typed_input);
        let parsed_summary_ref = parsed_summary
            .as_ref()
            .or(self.parsed_assertion_summary.as_ref())
            .or(self.verified_assertion_summary.as_ref())
            .or(self.fixture_assertion_summary.as_ref());
        let legacy_parsed_summary = self
            .parsed_assertion_summary
            .as_ref()
            .or(self.verified_assertion_summary.as_ref())
            .or(self.fixture_assertion_summary.as_ref());
        let mapped_groups = normalize_enterprise_identity_label_list(self.mapped_groups)?;
        let mapped_roles = normalize_enterprise_identity_label_list(self.mapped_roles)?;
        let metadata_trust_readback =
            enterprise_saml_metadata_trust_readback(self.metadata_trust.as_ref());
        let xml_signature_validation_readback = enterprise_saml_xml_signature_validation_readback(
            self.xml_signature_validation.as_ref(),
        );
        let saml_validator = enterprise_saml_assertion_validator_readback(
            parsed_summary_ref,
            &external_subject_hash,
            metadata_trust_readback,
            xml_signature_validation_readback,
            self.signature_validation_result,
            assertion_validation_result,
            issuer_validation_result,
            audience_validation_result,
            time_conditions_validation_result,
            mapped_groups.len(),
            mapped_roles.len(),
        );
        let role_group_mapping_result = enterprise_saml_role_group_mapping_result(
            parsed_summary_ref.or(legacy_parsed_summary),
            mapped_groups.len(),
            mapped_roles.len(),
        );
        let validator_passed = saml_validator["passed"].as_bool().unwrap_or(false);
        let validator_failure_reason = saml_validator["failure_reason"]
            .as_str()
            .map(str::to_string);
        let email = self
            .email
            .map(|value| normalize_enterprise_identity_email(&value))
            .transpose()?;
        let domain = self
            .domain
            .map(|value| normalize_enterprise_identity_domain(&value))
            .transpose()?;
        if let (Some(email), Some(domain)) = (email.as_deref(), domain.as_deref()) {
            let email_domain = email
                .rsplit_once('@')
                .map(|(_, value)| value)
                .unwrap_or_default();
            if email_domain != domain {
                return Err(AdminError::bad_request("domain must match email domain"));
            }
        }
        let fixture_summary_present = self.parsed_assertion_summary.is_some()
            || self.assertion_validator_input.is_some()
            || self.verified_assertion_summary.is_some()
            || self.fixture_assertion_summary.is_some();
        let binding_session_handoff_readiness = enterprise_saml_handoff_readiness(
            validator_passed,
            &role_group_mapping_result,
            fixture_summary_present,
        );
        let blocked_reasons =
            enterprise_saml_validator_blocked_reasons(&saml_validator, &role_group_mapping_result);
        let verified_group_count = role_group_mapping_result["group_value_count"]
            .as_u64()
            .unwrap_or(mapped_groups.len() as u64) as usize;
        let verified_role_count = role_group_mapping_result["role_value_count"]
            .as_u64()
            .unwrap_or(mapped_roles.len() as u64) as usize;

        Ok(EnterpriseSamlExecuteValidatedAcsInput {
            assertion_validator_result: saml_validator.clone(),
            saml_validator,
            saml_xml_signature_parser_executor,
            role_group_mapping_result,
            binding_session_handoff_readiness,
            blocked_reasons,
            validator_passed,
            validator_failure_reason,
            signature_validation_result: self.signature_validation_result,
            assertion_validation_result,
            issuer_validation_result,
            audience_validation_result,
            time_conditions_validation_result,
            email_present: email.is_some(),
            domain: domain.clone(),
            mapped_group_count: mapped_groups.len(),
            mapped_role_count: mapped_roles.len(),
            verified_group_count,
            verified_role_count,
            fixture_summary_present,
            binding_input: EnterpriseIdentityBindingInput {
                provider_type: "saml".to_string(),
                external_subject_hash,
                email,
                domain,
                mapped_groups,
                mapped_roles,
                fixture_subject_summary_present: fixture_summary_present,
                apply: self.apply.unwrap_or(false),
            },
        })
    }
}

impl EnterpriseIdentityUserMatch {
    fn from_user(user: &EnterpriseUserRow) -> Self {
        Self {
            user_id: user.id,
            source: "email",
            email_present: user.email_present,
            display_name_present: user.display_name_present,
            status: user.status.clone(),
        }
    }

    fn from_identity(identity: &EnterpriseIdentityRow) -> Self {
        Self {
            user_id: identity.user_id,
            source: "user_identity",
            email_present: identity.email_present,
            display_name_present: identity.display_name_present,
            status: identity.user_status.clone(),
        }
    }

    fn as_json(&self) -> Value {
        json!({
            "status": "matched",
            "user_id": self.user_id,
            "source": self.source,
            "email_present": self.email_present,
            "display_name_present": self.display_name_present,
            "user_status": self.status,
            "raw_email_returned": false
        })
    }
}

async fn find_enterprise_user_identity(
    pool: &PgPool,
    tenant_id: Uuid,
    provider_type: &str,
    external_subject_hash: &str,
) -> Result<Option<EnterpriseIdentityRow>, AdminError> {
    let row = sqlx::query(
        r#"
        select
          ui.id,
          ui.user_id,
          ui.provider as provider_type,
          (u.email is not null and btrim(u.email) <> '') as email_present,
          (u.display_name is not null and btrim(u.display_name) <> '') as display_name_present,
          u.status as user_status
        from user_identities ui
        join users u on u.tenant_id = ui.tenant_id and u.id = ui.user_id
        where ui.tenant_id = $1
          and ui.provider = $2
          and ui.provider_subject = $3
          and u.deleted_at is null
        "#,
    )
    .bind(tenant_id)
    .bind(provider_type)
    .bind(external_subject_hash)
    .fetch_optional(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.map(|row| {
        Ok(EnterpriseIdentityRow {
            id: admin_row_get(&row, "id")?,
            user_id: admin_row_get(&row, "user_id")?,
            provider_type: admin_row_get(&row, "provider_type")?,
            email_present: admin_row_get(&row, "email_present")?,
            display_name_present: admin_row_get(&row, "display_name_present")?,
            user_status: admin_row_get(&row, "user_status")?,
        })
    })
    .transpose()
}

