async fn enterprise_latest_provisioning_marker(
    pool: &PgPool,
    tenant_id: Uuid,
) -> Result<Option<PgRow>, AdminError> {
    sqlx::query(
        r#"
        select id
        from audit_logs
        where action = 'enterprise_account.provisioning_apply'
          and (
            resource_id = $1
            or metadata->>'target_tenant_id' = $2
          )
        order by created_at desc
        limit 1
        "#,
    )
    .bind(tenant_id)
    .bind(tenant_id.to_string())
    .fetch_optional(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))
}

async fn enterprise_latest_invite_delivery_marker(
    pool: &PgPool,
    tenant_id: Uuid,
) -> Result<Option<PgRow>, AdminError> {
    sqlx::query(
        r#"
        select id
        from audit_logs
        where action = 'enterprise_account.invite_delivery_planned'
          and metadata->>'target_tenant_id' = $1
        order by created_at desc
        limit 1
        "#,
    )
    .bind(tenant_id.to_string())
    .fetch_optional(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))
}

fn enterprise_provisioning_or_invite_retry_reason(
    provisioning_status: &str,
    invite_delivery_status: &str,
) -> Option<&'static str> {
    if provisioning_status == "local_records_present_audit_missing" {
        Some("provisioning_audit_ref_missing")
    } else if invite_delivery_status == "send_required" {
        Some("invite_delivery_adapter_not_connected")
    } else {
        None
    }
}

fn enterprise_provisioning_or_invite_refusal_reason(
    provisioning_status: &str,
    invite_delivery_status: &str,
) -> Option<&'static str> {
    if provisioning_status == "not_applied" {
        Some("provisioning_not_applied")
    } else if invite_delivery_status == "no_target_users" {
        Some("invite_target_user_missing")
    } else if invite_delivery_status == "no_invited_users" {
        Some("invite_target_not_in_invited_status")
    } else {
        None
    }
}

fn enterprise_provisioning_or_invite_next_action(
    provisioning_status: &str,
    invite_delivery_status: &str,
    account_next_step: &str,
) -> String {
    if provisioning_status == "not_applied" {
        "Run POST /admin/enterprise/accounts/provisioning-plan, then provisioning-apply if the local plan is acceptable.".to_string()
    } else if provisioning_status == "local_records_present_audit_missing" {
        "Confirm whether the local tenant/workspace/user records came from provisioning-apply before treating the account as provisioned.".to_string()
    } else if invite_delivery_status == "send_required" {
        "Run invite-delivery-plan/apply to create a local delivery marker; no email provider is connected in this slice.".to_string()
    } else if matches!(
        invite_delivery_status,
        "no_target_users" | "no_invited_users"
    ) {
        "Create or identify an invited local admin user before planning invite delivery."
            .to_string()
    } else {
        account_next_step.to_string()
    }
}

fn enterprise_account_sales_readback(
    row: &PgRow,
    metadata_sales_stage: Option<String>,
    sales_stage: &str,
    sales_activity: Value,
    external_crm_adapter: Value,
    mut external_crm_sync_run: Value,
    retry_worker_handoff_summary: Value,
) -> Result<Value, AdminError> {
    let crm_connected = external_crm_adapter
        .get("status")
        .and_then(Value::as_str)
        .is_some_and(|status| status == "enabled");
    if let Some(object) = external_crm_sync_run.as_object_mut() {
        object.insert(
            "retry_worker_handoff_summary".to_string(),
            retry_worker_handoff_summary,
        );
    }
    Ok(json!({
        "stage": sales_stage,
        "source": if metadata_sales_stage.as_deref().is_some_and(|value| !value.trim().is_empty()) {
            "tenant_metadata_allowlist"
        } else {
            "env_allowlist"
        },
        "local_metadata_write_path": "PATCH /admin/enterprise/accounts",
        "account_notes_present": admin_row_get::<Option<String>>(row, "account_notes")?
            .is_some_and(|value| !value.trim().is_empty()),
        "local_crm_adapter": {
            "adapter": "enterprise_sales_activities",
            "write_path": "PATCH /admin/enterprise/accounts",
            "tenant_scoped": true,
            "external_crm_connected": false,
            "raw_external_payload_returned": false
        },
        "external_crm_adapter": external_crm_adapter,
        "external_crm_sync_run": external_crm_sync_run,
        "activity": sales_activity,
        "next_action_reducer": enterprise_account_next_action_reducer(
            sales_stage,
            &sales_activity,
            &external_crm_adapter,
            &external_crm_sync_run,
        ),
        "crm_connected": crm_connected,
        "external_crm_payload_returned": false,
        "next_step": enterprise_sales_next_step(sales_stage),
    }))
}

fn enterprise_account_next_action_reducer(
    sales_stage: &str,
    sales_activity: &Value,
    external_crm_adapter: &Value,
    external_crm_sync_run: &Value,
) -> Value {
    let activity_next_action = sales_activity.get("next_action").and_then(Value::as_str);
    let activity_due_at = sales_activity
        .get("next_action_due_at")
        .and_then(Value::as_str);
    let crm_adapter_status = external_crm_adapter
        .get("status")
        .and_then(Value::as_str)
        .unwrap_or("not-configured");
    let crm_adapter_blocked_reason = external_crm_adapter
        .get("blocked_reason")
        .and_then(Value::as_str);
    let crm_sync_status = external_crm_sync_run
        .get("status")
        .and_then(Value::as_str)
        .unwrap_or("not-run");
    let crm_sync_blocked_reason = external_crm_sync_run
        .get("blocked_reason")
        .or_else(|| external_crm_sync_run.get("refused_reason"))
        .and_then(Value::as_str);
    let crm_retry_status = external_crm_sync_run
        .get("retry_attempt_readback")
        .and_then(|value| value.get("status"))
        .and_then(Value::as_str);

    let (status, source, action, reason) = if let Some(action) = activity_next_action {
        (
            "action-required",
            "enterprise_sales_activities",
            action,
            "open_or_planned_sales_activity",
        )
    } else if sales_stage == "not-connected" {
        (
            "config-needed",
            "tenant_metadata_allowlist",
            "Set a sales_stage or append a local sales_activity through PATCH /admin/enterprise/accounts.",
            "sales_stage_not_connected",
        )
    } else if crm_adapter_status != "enabled" {
        (
            "config-needed",
            "enterprise_external_crm_adapters",
            "Enable a tenant-scoped CRM adapter only when external CRM sync readback is required.",
            "external_crm_adapter_not_enabled",
        )
    } else if let Some(reason) = crm_adapter_blocked_reason {
        (
            "blocked",
            "enterprise_external_crm_adapters",
            enterprise_dashboard_next_action_for_reason(reason),
            reason,
        )
    } else if crm_sync_status == "refused" {
        (
            "blocked",
            "enterprise_crm_sync_runs",
            "Fix the refused CRM sync marker, then request a new bounded sync run.",
            crm_sync_blocked_reason.unwrap_or("external_crm_sync_run_refused"),
        )
    } else if crm_retry_status == Some("scheduled") {
        (
            "action-required",
            "enterprise_crm_sync_runs",
            "Review the scheduled CRM retry marker before running a real external CRM executor.",
            "external_crm_retry_scheduled",
        )
    } else if crm_sync_status == "not-run" {
        (
            "ready-for-local-marker",
            "enterprise_crm_sync_runs",
            "Request a bounded CRM sync marker through PATCH /admin/enterprise/accounts when ready.",
            "external_crm_sync_run_not_requested",
        )
    } else {
        (
            "readback-ready",
            "local_enterprise_account_readback",
            "Review sales stage, local activity, SSO, billing, seats, and quota before changing account state.",
            "local_readback_ready",
        )
    };

    json!({
        "schema": "enterprise_account_next_action_reducer.v1",
        "status": status,
        "source": source,
        "action": action,
        "reason": reason,
        "due_at": activity_due_at,
        "recomputed": true,
        "recompute_source": "enterprise_account_next_action_reducer",
        "readback_path": "GET /admin/enterprise/accounts",
        "write_path": "PATCH /admin/enterprise/accounts",
        "network_requests_executed": false,
        "raw_contact_returned": false,
        "raw_email_returned": false,
        "raw_external_payload_returned": false,
        "raw_idempotency_key_returned": false,
    })
}

async fn enterprise_sales_activity_readback(
    pool: &PgPool,
    tenant_id: Uuid,
) -> Result<Value, AdminError> {
    let rows = sqlx::query(
        r#"
        select id, activity_type, status, summary, owner, next_action, outcome,
          occurred_at::text as occurred_at, due_at::text as due_at, created_at::text as created_at
        from enterprise_sales_activities
        where tenant_id = $1
        order by occurred_at desc, created_at desc
        limit 5
        "#,
    )
    .bind(tenant_id)
    .fetch_all(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let summary_row = sqlx::query(
        r#"
        select
          count(*)::bigint as activity_count,
          (max(occurred_at) filter (where activity_type in ('call', 'email', 'demo', 'followup', 'meeting') and status = 'completed'))::text as last_contact_at,
          (
            select esa.next_action
            from enterprise_sales_activities esa
            where esa.tenant_id = $1
              and esa.next_action is not null
              and esa.status in ('open', 'planned')
            order by esa.due_at asc nulls last, esa.created_at desc
            limit 1
          ) as next_action,
          (
            select esa.due_at::text
            from enterprise_sales_activities esa
            where esa.tenant_id = $1
              and esa.next_action is not null
              and esa.status in ('open', 'planned')
            order by esa.due_at asc nulls last, esa.created_at desc
            limit 1
          ) as next_action_due_at
        from enterprise_sales_activities
        where tenant_id = $1
        "#,
    )
    .bind(tenant_id)
    .fetch_one(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let recent = rows
        .into_iter()
        .map(|row| {
            Ok(json!({
                "id": admin_row_get::<Uuid>(&row, "id")?,
                "activity_type": admin_row_get::<String>(&row, "activity_type")?,
                "status": admin_row_get::<String>(&row, "status")?,
                "outcome": admin_row_get::<Option<String>>(&row, "outcome")?,
                "summary": admin_row_get::<String>(&row, "summary")?,
                "owner": admin_row_get::<Option<String>>(&row, "owner")?,
                "owner_marker": admin_row_get::<Option<String>>(&row, "owner")?,
                "next_action": admin_row_get::<Option<String>>(&row, "next_action")?,
                "occurred_at": admin_row_get::<String>(&row, "occurred_at")?,
                "due_at": admin_row_get::<Option<String>>(&row, "due_at")?,
                "created_at": admin_row_get::<String>(&row, "created_at")?,
                "raw_contact_email_returned": false,
                "raw_external_payload_returned": false,
            }))
        })
        .collect::<Result<Vec<_>, AdminError>>()?;

    Ok(json!({
        "source": "enterprise_sales_activities",
        "write_path": "PATCH /admin/enterprise/accounts",
        "activity_count": admin_row_get::<i64>(&summary_row, "activity_count")?,
        "last_contact_at": admin_row_get::<Option<String>>(&summary_row, "last_contact_at")?,
        "next_action": admin_row_get::<Option<String>>(&summary_row, "next_action")?,
        "next_action_due_at": admin_row_get::<Option<String>>(&summary_row, "next_action_due_at")?,
        "recent": recent,
        "recent_limit": 5,
        "tenant_scoped": true,
        "external_crm_connected": false,
        "raw_contact_email_returned": false,
        "raw_external_payload_returned": false,
    }))
}

async fn enterprise_workspace_linkage_readback(
    pool: &PgPool,
    tenant_id: Uuid,
) -> Result<Value, AdminError> {
    let rows = sqlx::query(
        r#"
        select id, name, status, created_at::text as created_at
        from projects
        where tenant_id = $1
          and deleted_at is null
        order by
          case when status = 'active' then 0 else 1 end,
          created_at desc
        limit 10
        "#,
    )
    .bind(tenant_id)
    .fetch_all(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let workspaces = rows
        .into_iter()
        .map(|row| {
            Ok(json!({
                "workspace_id": admin_row_get::<Uuid>(&row, "id")?,
                "workspace_name": admin_row_get::<String>(&row, "name")?,
                "workspace_status": admin_row_get::<String>(&row, "status")?,
                "created_at": admin_row_get::<String>(&row, "created_at")?,
                "source": "projects",
                "tenant_id": tenant_id,
                "tenant_scoped": true,
                "project_metadata_returned": false,
            }))
        })
        .collect::<Result<Vec<_>, AdminError>>()?;
    let active_workspace_count = workspaces
        .iter()
        .filter(|workspace| {
            workspace
                .get("workspace_status")
                .and_then(Value::as_str)
                .is_some_and(|status| status == "active")
        })
        .count();

    Ok(json!({
        "source": "projects",
        "status": if active_workspace_count > 0 { "linked" } else { "not-linked" },
        "workspace_count": workspaces.len(),
        "active_workspace_count": active_workspace_count,
        "workspaces": workspaces,
        "recent_limit": 10,
        "tenant_scoped": true,
        "readback_path": "GET /admin/enterprise/accounts",
        "create_path": "POST /admin/enterprise/accounts",
        "project_metadata_returned": false,
    }))
}

async fn ensure_enterprise_default_workspace_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    workspace_name: &str,
) -> Result<Value, AdminError> {
    let row = sqlx::query(
        r#"
        insert into projects (tenant_id, name, status, metadata)
        values ($1, $2, 'active', $3)
        on conflict (tenant_id, name) do update
        set status = case
                when projects.status = 'deleted' then 'active'
                else projects.status
            end,
            metadata = projects.metadata || excluded.metadata,
            updated_at = now(),
            deleted_at = null
        returning id, tenant_id, name, status, created_at::text as created_at, updated_at::text as updated_at
        "#,
    )
    .bind(tenant_id)
    .bind(workspace_name)
    .bind(json!({
        "source": "enterprise_account_lifecycle",
        "workspace_kind": "default",
        "secret_safe": true,
        "raw_metadata_stored": false
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(json!({
        "workspace_id": admin_row_get::<Uuid>(&row, "id")?,
        "tenant_id": admin_row_get::<Uuid>(&row, "tenant_id")?,
        "workspace_name": admin_row_get::<String>(&row, "name")?,
        "workspace_status": admin_row_get::<String>(&row, "status")?,
        "created_at": admin_row_get::<String>(&row, "created_at")?,
        "updated_at": admin_row_get::<String>(&row, "updated_at")?,
        "source": "projects",
        "tenant_scoped": true,
        "readback_path": "GET /admin/enterprise/accounts",
        "project_metadata_returned": false,
    }))
}

async fn enterprise_account_provisioning_plan_response(
    pool: &PgPool,
    operator_tenant_id: Uuid,
    input: &EnterpriseAccountProvisioningInput,
    mode: &str,
    applied_tenant_id: Option<Uuid>,
    audit_id: Option<Uuid>,
) -> Result<Value, AdminError> {
    let idempotency_hash = enterprise_account_provisioning_idempotency_hash(input);
    let tenant_row = sqlx::query(
        r#"
        select id, name, slug, status,
          metadata->>'enterprise_sales_stage' as sales_stage,
          metadata->>'enterprise_plan_tier' as plan_tier,
          metadata->>'admin_contact_email' as admin_contact_email,
          metadata->>'account_owner' as account_owner
        from tenants
        where slug = $1 and deleted_at is null
        "#,
    )
    .bind(&input.tenant_slug)
    .fetch_optional(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let target_tenant_id = applied_tenant_id.or_else(|| {
        tenant_row
            .as_ref()
            .and_then(|row| admin_row_get::<Uuid>(row, "id").ok())
    });
    let workspace_exists = if let Some(tenant_id) = target_tenant_id {
        sqlx::query_scalar::<_, bool>(
            "select exists(select 1 from projects where tenant_id = $1 and name = $2 and deleted_at is null)",
        )
        .bind(tenant_id)
        .bind(&input.workspace_name)
        .fetch_one(pool)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?
    } else {
        false
    };
    let admin_user_exists = if let Some(tenant_id) = target_tenant_id {
        sqlx::query_scalar::<_, bool>(
            "select exists(select 1 from users where tenant_id = $1 and lower(email) = lower($2) and deleted_at is null)",
        )
        .bind(tenant_id)
        .bind(&input.admin_contact_email)
        .fetch_one(pool)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?
    } else {
        false
    };
    let marker_exists = sqlx::query_scalar::<_, bool>(
        r#"
        select exists(
          select 1
          from audit_logs
          where tenant_id = $1
            and action = 'enterprise_account.provisioning_apply'
            and metadata->>'idempotency_fingerprint' = $2
        )
        "#,
    )
    .bind(operator_tenant_id)
    .bind(subscription_scheduler_public_fingerprint(&idempotency_hash))
    .fetch_one(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let tenant_exists = tenant_row.is_some();
    let existing_sales_stage = tenant_row.as_ref().and_then(|row| {
        admin_row_get::<Option<String>>(row, "sales_stage")
            .ok()
            .flatten()
    });
    let existing_plan_tier = tenant_row.as_ref().and_then(|row| {
        admin_row_get::<Option<String>>(row, "plan_tier")
            .ok()
            .flatten()
    });

    Ok(json!({
        "schema": "admin_enterprise_account_provisioning_plan.v1",
        "mode": mode,
        "status": if mode == "replay" { "replayed" } else if mode == "apply" { "applied" } else { "planned" },
        "secret_safe": true,
        "runtime_implemented": true,
        "admin_only": true,
        "operator_tenant_id": operator_tenant_id,
        "target_tenant_id": target_tenant_id,
        "tenant": {
            "tenant_slug": input.tenant_slug,
            "tenant_name": input.tenant_name,
            "exists": tenant_exists,
            "would_create": !tenant_exists,
            "would_update": tenant_exists,
            "existing_status": tenant_row.as_ref().and_then(|row| admin_row_get::<String>(row, "status").ok()),
            "source": "tenants"
        },
        "workspace": {
            "workspace_name": input.workspace_name,
            "exists": workspace_exists,
            "would_create": !workspace_exists,
            "would_update": workspace_exists,
            "source": "projects"
        },
        "admin_invite": {
            "admin_contact_summary": enterprise_contact_safe_summary(Some(&input.admin_contact_email)),
            "owner_contact_summary": enterprise_contact_safe_summary(input.owner_contact_email.as_deref()),
            "local_user_exists": admin_user_exists,
            "would_create": !admin_user_exists,
            "would_update": admin_user_exists,
            "email_delivery": "not_attempted",
            "raw_email_returned": false,
            "source": "users/project_members"
        },
        "sales_stage": input.sales_stage,
        "plan_tier": input.plan_tier,
        "metadata_diff": {
            "sales_stage_would_update": existing_sales_stage.as_deref() != Some(input.sales_stage.as_str()),
            "plan_tier_would_update": existing_plan_tier.as_deref() != Some(input.plan_tier.as_str()),
            "contact_would_update": true,
            "raw_metadata_returned": false
        },
        "idempotency": {
            "fingerprint": subscription_scheduler_public_fingerprint(&idempotency_hash),
            "marker_exists": marker_exists,
            "replay_safe": true,
            "raw_key_returned": false,
            "hash_returned": false,
            "marker_source": "audit_logs.metadata.idempotency_fingerprint"
        },
        "db_effects": {
            "would_create": {
                "tenant": !tenant_exists,
                "workspace": !workspace_exists,
                "admin_user_invite": !admin_user_exists,
                "project_membership": !workspace_exists || !admin_user_exists
            },
            "would_update": {
                "tenant_metadata": tenant_exists,
                "workspace_metadata": workspace_exists,
                "admin_user_metadata": admin_user_exists
            },
            "apply_writes": ["tenants", "projects", "users", "project_members", "audit_logs"],
            "bounded_marker_only": false,
            "email_sent": false
        },
        "audit_id": audit_id,
        "plan_path": "POST /admin/enterprise/accounts/provisioning-plan",
        "apply_path": "POST /admin/enterprise/accounts/provisioning-apply",
        "readback_path": "GET /admin/enterprise/accounts",
        "omitted_fields": enterprise_account_provisioning_omitted_fields(),
        "next_step": if mode == "dry_run" {
            "Submit the same request to provisioning-apply when the plan is acceptable; replay uses the idempotency fingerprint and will not duplicate local records."
        } else {
            "Use GET /admin/enterprise/accounts while authenticated as the target tenant admin context to read the tenant account card; no email was sent."
        }
    }))
}

async fn enterprise_invite_delivery_plan_response(
    pool: &PgPool,
    operator_tenant_id: Uuid,
    input: &EnterpriseInviteDeliveryInput,
    mode: &str,
    audit_id: Option<Uuid>,
) -> Result<Value, AdminError> {
    let idempotency_hash = enterprise_invite_delivery_idempotency_hash(input);
    let target =
        enterprise_invite_delivery_target_readback(pool, operator_tenant_id, input).await?;
    let marker_exists = target.existing_marker_id.is_some();
    let status = if mode == "replay" {
        "replayed"
    } else if mode == "apply" {
        "planned"
    } else {
        "planned"
    };
    let delivery_adapter_readiness = if !target.blocked_reasons.is_empty() {
        "blocked"
    } else {
        "local_only"
    };

    Ok(json!({
        "schema": "admin_enterprise_invite_delivery_plan.v1",
        "mode": mode,
        "status": status,
        "secret_safe": true,
        "runtime_implemented": true,
        "admin_only": true,
        "operator_tenant_id": operator_tenant_id,
        "tenant_ref": target.tenant_ref,
        "workspace_ref": target.workspace_ref,
        "target_user_refs": target.target_user_refs,
        "invite_status": target.invite_status,
        "would_send": target.would_send,
        "blocked_reasons": target.blocked_reasons,
        "idempotency_fingerprint": subscription_scheduler_public_fingerprint(&idempotency_hash),
        "delivery_adapter_readiness": delivery_adapter_readiness,
        "delivery_adapter": {
            "mode": "local_only",
            "external_provider_status": "no_provider",
            "provider_request_created": false,
            "email_sent": false,
            "raw_email_returned": false,
            "raw_contact_returned": false
        },
        "idempotency": {
            "fingerprint": subscription_scheduler_public_fingerprint(&idempotency_hash),
            "marker_exists": marker_exists,
            "marker_audit_id": audit_id.or(target.existing_marker_id),
            "replay_safe": true,
            "raw_key_returned": false,
            "hash_returned": false,
            "marker_source": "audit_logs.metadata.idempotency_fingerprint"
        },
        "db_effects": {
            "plan_writes": [],
            "apply_writes": ["audit_logs"],
            "bounded_marker_only": true,
            "creates_or_updates_users": false,
            "creates_or_updates_project_members": false,
            "email_sent": false
        },
        "plan_path": "POST /admin/enterprise/accounts/invite-delivery-plan",
        "apply_path": "POST /admin/enterprise/accounts/invite-delivery-apply",
        "readback_path": "POST /admin/enterprise/accounts/invite-delivery-plan",
        "audit_id": audit_id.or(target.existing_marker_id),
        "omitted_fields": enterprise_invite_delivery_omitted_fields(),
        "next_step": if target.would_send {
            "Display this local-only invite delivery plan to operators; a future email adapter can consume the safe refs and fingerprint without exposing raw contact material."
        } else {
            "Resolve blocked reasons or treat the existing local marker as the delivery readback; no external email provider was called."
        }
    }))
}

async fn enterprise_invite_delivery_target_readback(
    pool: &PgPool,
    operator_tenant_id: Uuid,
    input: &EnterpriseInviteDeliveryInput,
) -> Result<EnterpriseInviteDeliveryReadback, AdminError> {
    let tenant_row = sqlx::query(
        r#"
        select id, slug, name, status
        from tenants
        where ($1::uuid is null or id = $1)
          and ($2::text is null or slug = $2)
          and deleted_at is null
        order by created_at desc
        limit 1
        "#,
    )
    .bind(input.tenant_id)
    .bind(input.tenant_slug.as_deref())
    .fetch_optional(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let tenant_id = tenant_row
        .as_ref()
        .and_then(|row| admin_row_get::<Uuid>(row, "id").ok());
    let mut blocked_reasons = Vec::new();
    if tenant_id.is_none() {
        blocked_reasons.push("tenant_not_found".to_string());
    }

    let workspace_row = if let Some(tenant_id) = tenant_id {
        sqlx::query(
            r#"
            select id, name, status
            from projects
            where tenant_id = $1
              and ($2::uuid is null or id = $2)
              and ($3::text is null or name = $3)
              and deleted_at is null
            order by created_at desc
            limit 1
            "#,
        )
        .bind(tenant_id)
        .bind(input.workspace_id)
        .bind(input.workspace_name.as_deref())
        .fetch_optional(pool)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?
    } else {
        None
    };
    let workspace_id = workspace_row
        .as_ref()
        .and_then(|row| admin_row_get::<Uuid>(row, "id").ok());
    if tenant_id.is_some()
        && (input.workspace_id.is_some() || input.workspace_name.is_some())
        && workspace_id.is_none()
    {
        blocked_reasons.push("workspace_not_found".to_string());
    }

    let user_rows = if let Some(tenant_id) = tenant_id {
        sqlx::query(
            r#"
            select u.id, u.status, u.display_name is not null as display_name_present,
                   exists(
                     select 1 from project_members pm
                     where pm.tenant_id = u.tenant_id
                       and pm.user_id = u.id
                       and ($4::uuid is null or pm.project_id = $4)
                   ) as project_member_exists
            from users u
            where u.tenant_id = $1
              and ($2::uuid is null or u.id = $2)
              and ($3::text is null or lower(u.email) = lower($3))
              and u.deleted_at is null
            order by case when u.status = 'invited' then 0 else 1 end, u.created_at desc
            limit 50
            "#,
        )
        .bind(tenant_id)
        .bind(input.target_user_id)
        .bind(input.target_user_email.as_deref())
        .bind(workspace_id)
        .fetch_all(pool)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?
    } else {
        Vec::new()
    };
    if tenant_id.is_some()
        && (input.target_user_id.is_some() || input.target_user_email.is_some())
        && user_rows.is_empty()
    {
        blocked_reasons.push("target_user_not_found".to_string());
    }

    let mut target_user_refs = Vec::new();
    let mut invited_count = 0usize;
    let mut active_or_disabled_count = 0usize;
    for row in &user_rows {
        let status = admin_row_get::<String>(row, "status")?;
        if status == "invited" {
            invited_count += 1;
        } else {
            active_or_disabled_count += 1;
        }
        target_user_refs.push(json!({
            "user_id": admin_row_get::<Uuid>(row, "id")?,
            "status": status,
            "display_name_present": admin_row_get::<bool>(row, "display_name_present")?,
            "project_member_exists": admin_row_get::<bool>(row, "project_member_exists")?,
            "source": "users/project_members",
            "raw_email_returned": false,
            "user_metadata_returned": false
        }));
    }
    if !user_rows.is_empty() && invited_count == 0 {
        blocked_reasons.push("target_user_not_invited".to_string());
    }

    let idempotency_hash = enterprise_invite_delivery_idempotency_hash(input);
    let marker_row = if tenant_id.is_some() {
        sqlx::query(
            r#"
            select id
            from audit_logs
            where tenant_id = $1
              and action = 'enterprise_account.invite_delivery_planned'
              and metadata->>'idempotency_fingerprint' = $2
            order by created_at desc
            limit 1
            "#,
        )
        .bind(operator_tenant_id)
        .bind(subscription_scheduler_public_fingerprint(&idempotency_hash))
        .fetch_optional(pool)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?
    } else {
        None
    };
    let existing_marker_id = marker_row
        .as_ref()
        .and_then(|row| admin_row_get::<Uuid>(row, "id").ok());
    let invite_status = if !blocked_reasons.is_empty() {
        "blocked"
    } else if existing_marker_id.is_some() {
        "delivery_planned"
    } else if invited_count > 0 {
        "send_required"
    } else if active_or_disabled_count > 0 {
        "already_exists"
    } else {
        "no_target_users"
    };
    let would_send =
        blocked_reasons.is_empty() && existing_marker_id.is_none() && invited_count > 0;

    Ok(EnterpriseInviteDeliveryReadback {
        tenant_id,
        workspace_id,
        tenant_ref: enterprise_invite_delivery_tenant_ref(input, tenant_row.as_ref())?,
        workspace_ref: enterprise_invite_delivery_workspace_ref(input, workspace_row.as_ref())?,
        target_user_refs,
        invite_status,
        would_send,
        blocked_reasons,
        existing_marker_id,
    })
}

async fn find_enterprise_account_provisioning_marker_tx(
    tx: &mut Transaction<'_, Postgres>,
    operator_tenant_id: Uuid,
    idempotency_hash: &str,
) -> Result<Option<PgRow>, AdminError> {
    sqlx::query(
        r#"
        select id, resource_id
        from audit_logs
        where tenant_id = $1
          and action = 'enterprise_account.provisioning_apply'
          and metadata->>'idempotency_fingerprint' = $2
        order by created_at desc
        limit 1
        for update
        "#,
    )
    .bind(operator_tenant_id)
    .bind(subscription_scheduler_public_fingerprint(idempotency_hash))
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))
}

