fn enterprise_invite_delivery_tenant_ref(
    input: &EnterpriseInviteDeliveryInput,
    row: Option<&PgRow>,
) -> Result<Value, AdminError> {
    Ok(match row {
        Some(row) => json!({
            "tenant_id": admin_row_get::<Uuid>(row, "id")?,
            "tenant_slug": admin_row_get::<String>(row, "slug")?,
            "tenant_name_present": !admin_row_get::<String>(row, "name")?.trim().is_empty(),
            "status": admin_row_get::<String>(row, "status")?,
            "exists": true,
            "source": "tenants",
            "tenant_metadata_returned": false
        }),
        None => json!({
            "tenant_id": input.tenant_id,
            "tenant_slug": input.tenant_slug,
            "exists": false,
            "source": "tenants",
            "tenant_metadata_returned": false
        }),
    })
}

fn enterprise_invite_delivery_workspace_ref(
    input: &EnterpriseInviteDeliveryInput,
    row: Option<&PgRow>,
) -> Result<Value, AdminError> {
    Ok(match row {
        Some(row) => json!({
            "workspace_id": admin_row_get::<Uuid>(row, "id")?,
            "workspace_name_present": !admin_row_get::<String>(row, "name")?.trim().is_empty(),
            "status": admin_row_get::<String>(row, "status")?,
            "exists": true,
            "source": "projects",
            "project_metadata_returned": false
        }),
        None => json!({
            "workspace_id": input.workspace_id,
            "workspace_name_present": input.workspace_name.as_ref().is_some_and(|value| !value.trim().is_empty()),
            "exists": false,
            "source": "projects",
            "project_metadata_returned": false
        }),
    })
}

async fn upsert_enterprise_provisioning_tenant_tx(
    tx: &mut Transaction<'_, Postgres>,
    input: &EnterpriseAccountProvisioningInput,
) -> Result<EnterpriseProvisioningTenantWrite, AdminError> {
    let existing =
        sqlx::query("select id from tenants where slug = $1 and deleted_at is null for update")
            .bind(&input.tenant_slug)
            .fetch_optional(&mut **tx)
            .await
            .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let created = existing.is_none();
    let row = sqlx::query(
        r#"
        insert into tenants (name, slug, status, metadata)
        values ($1, $2, 'active', $3)
        on conflict (slug) do update
        set name = excluded.name,
            status = case when tenants.status = 'deleted' then 'active' else tenants.status end,
            metadata = tenants.metadata || excluded.metadata,
            updated_at = now(),
            deleted_at = null
        returning id
        "#,
    )
    .bind(&input.tenant_name)
    .bind(&input.tenant_slug)
    .bind(enterprise_account_provisioning_metadata(input))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;
    Ok(EnterpriseProvisioningTenantWrite {
        tenant_id: admin_row_get(&row, "id")?,
        created,
    })
}

