async fn enterprise_external_crm_adapter_readback(
    pool: &PgPool,
    tenant_id: Uuid,
) -> Result<Value, AdminError> {
    let row = sqlx::query(
        r#"
        select id, provider, status, secret_ref_present, webhook_ref_present, sync_direction,
          last_sync_marker, metadata, disabled_at::text as disabled_at, updated_at::text as updated_at
        from enterprise_external_crm_adapters
        where tenant_id = $1
        "#,
    )
    .bind(tenant_id)
    .fetch_optional(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let Some(row) = row else {
        return Ok(json!({
            "source": "enterprise_external_crm_adapters",
            "status": "not-configured",
            "crm_connected": false,
            "adapter_kind": null,
            "provider": null,
            "endpoint_ref_present": false,
            "secret_ref_present": false,
            "webhook_ref_present": false,
            "sync_direction": null,
            "last_sync_marker_present": false,
            "last_sync_marker": null,
            "typed_client_ready": false,
            "blocked_reason": "external_crm_adapter_not_configured",
            "adapter_readiness": enterprise_crm_adapter_readiness_metadata(
                "not-configured",
                false,
                false,
                false,
            ),
            "readback_path": "GET /admin/enterprise/accounts",
            "write_path": "PATCH /admin/enterprise/accounts",
            "tenant_scoped": true,
            "network_requests_executed": false,
            "secret_returned": false,
            "authorization_header_returned": false,
            "raw_external_payload_returned": false,
        }));
    };

    let status = admin_row_get::<String>(&row, "status")?;
    let provider = admin_row_get::<String>(&row, "provider")?;
    let secret_ref_present = admin_row_get::<bool>(&row, "secret_ref_present")?;
    let webhook_ref_present = admin_row_get::<bool>(&row, "webhook_ref_present")?;
    let metadata = admin_row_get::<Value>(&row, "metadata")?;
    let endpoint_ref_present = metadata
        .get("endpoint_ref_present")
        .and_then(Value::as_bool)
        .unwrap_or(webhook_ref_present);
    let blocked_reason = enterprise_external_crm_adapter_blocked_reason(
        &provider,
        &status,
        secret_ref_present,
        endpoint_ref_present,
    );
    let last_sync_marker = admin_row_get::<Option<String>>(&row, "last_sync_marker")?;
    Ok(json!({
        "source": "enterprise_external_crm_adapters",
        "id": admin_row_get::<Uuid>(&row, "id")?,
        "adapter_kind": provider,
        "provider": provider,
        "status": status,
        "crm_connected": status == "enabled",
        "endpoint_ref_present": endpoint_ref_present,
        "secret_ref_present": secret_ref_present,
        "webhook_ref_present": webhook_ref_present,
        "sync_direction": admin_row_get::<String>(&row, "sync_direction")?,
        "last_sync_marker_present": last_sync_marker.as_deref().is_some_and(|value| !value.trim().is_empty()),
        "last_sync_marker": last_sync_marker,
        "typed_client_ready": blocked_reason.is_none(),
        "blocked_reason": blocked_reason,
        "adapter_readiness": enterprise_crm_adapter_readiness_metadata(
            &provider,
            status == "enabled",
            secret_ref_present,
            endpoint_ref_present,
        ),
        "disabled_at": admin_row_get::<Option<String>>(&row, "disabled_at")?,
        "updated_at": admin_row_get::<String>(&row, "updated_at")?,
        "readback_path": "GET /admin/enterprise/accounts",
        "write_path": "PATCH /admin/enterprise/accounts",
        "tenant_scoped": true,
        "network_requests_executed": false,
        "secret_returned": false,
        "authorization_header_returned": false,
        "raw_external_payload_returned": false,
    }))
}

async fn upsert_enterprise_external_crm_adapter_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    actor_session_id: Uuid,
    audit_id: Uuid,
    adapter: &EnterpriseExternalCrmAdapterWrite,
) -> Result<Value, AdminError> {
    let row = sqlx::query(
        r#"
        insert into enterprise_external_crm_adapters (
          tenant_id, provider, status, secret_ref_present, webhook_ref_present,
          sync_direction, last_sync_marker, actor_session_id, audit_id, disabled_at, metadata
        )
        values (
          $1, $2, $3, $4, $5, $6, $7, $8, $9,
          case when $3 = 'disabled' then now() else null end,
          $10
        )
        on conflict (tenant_id) do update
        set provider = excluded.provider,
            status = excluded.status,
            secret_ref_present = excluded.secret_ref_present,
            webhook_ref_present = excluded.webhook_ref_present,
            sync_direction = excluded.sync_direction,
            last_sync_marker = excluded.last_sync_marker,
            actor_session_id = excluded.actor_session_id,
            audit_id = excluded.audit_id,
            disabled_at = case when excluded.status = 'disabled' then coalesce(enterprise_external_crm_adapters.disabled_at, now()) else null end,
            metadata = enterprise_external_crm_adapters.metadata || excluded.metadata,
            updated_at = now()
        returning id, tenant_id, provider, status, secret_ref_present, webhook_ref_present,
          sync_direction, last_sync_marker, disabled_at::text as disabled_at, updated_at::text as updated_at
        "#,
    )
    .bind(tenant_id)
    .bind(&adapter.provider)
    .bind(&adapter.status)
    .bind(adapter.secret_ref_present)
    .bind(adapter.webhook_ref_present)
    .bind(&adapter.sync_direction)
    .bind(&adapter.last_sync_marker)
    .bind(actor_session_id)
    .bind(audit_id)
    .bind(json!({
        "source": "operator_config",
        "adapter": "enterprise_external_crm_adapters",
        "adapter_kind": &adapter.provider,
        "endpoint_ref_present": adapter.endpoint_ref_present,
        "secret_ref_supplied": adapter.secret_ref_present,
        "webhook_ref_supplied": adapter.webhook_ref_present,
        "typed_client_ready": enterprise_external_crm_adapter_blocked_reason(
            &adapter.provider,
            &adapter.status,
            adapter.secret_ref_present,
            adapter.endpoint_ref_present,
        ).is_none(),
        "blocked_reason": enterprise_external_crm_adapter_blocked_reason(
            &adapter.provider,
            &adapter.status,
            adapter.secret_ref_present,
            adapter.endpoint_ref_present,
        ),
        "raw_external_payload_stored": false,
        "raw_secret_stored": false,
        "network_requests_executed": false,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(json!({
        "id": admin_row_get::<Uuid>(&row, "id")?,
        "tenant_id": admin_row_get::<Uuid>(&row, "tenant_id")?,
        "provider": admin_row_get::<String>(&row, "provider")?,
        "adapter_kind": admin_row_get::<String>(&row, "provider")?,
        "status": admin_row_get::<String>(&row, "status")?,
        "crm_connected": admin_row_get::<String>(&row, "status")? == "enabled",
        "endpoint_ref_present": adapter.endpoint_ref_present,
        "secret_ref_present": admin_row_get::<bool>(&row, "secret_ref_present")?,
        "webhook_ref_present": admin_row_get::<bool>(&row, "webhook_ref_present")?,
        "sync_direction": admin_row_get::<String>(&row, "sync_direction")?,
        "last_sync_marker_present": admin_row_get::<Option<String>>(&row, "last_sync_marker")?.as_deref().is_some_and(|value| !value.trim().is_empty()),
        "last_sync_marker": admin_row_get::<Option<String>>(&row, "last_sync_marker")?,
        "disabled_at": admin_row_get::<Option<String>>(&row, "disabled_at")?,
        "updated_at": admin_row_get::<String>(&row, "updated_at")?,
        "audit_id": audit_id,
        "typed_client_ready": enterprise_external_crm_adapter_blocked_reason(
            &adapter.provider,
            &adapter.status,
            adapter.secret_ref_present,
            adapter.endpoint_ref_present,
        ).is_none(),
        "blocked_reason": enterprise_external_crm_adapter_blocked_reason(
            &adapter.provider,
            &adapter.status,
            adapter.secret_ref_present,
            adapter.endpoint_ref_present,
        ),
        "adapter_readiness": enterprise_crm_adapter_readiness_metadata(
            &adapter.provider,
            adapter.status == "enabled",
            adapter.secret_ref_present,
            adapter.endpoint_ref_present,
        ),
        "readback_path": "GET /admin/enterprise/accounts",
        "tenant_scoped": true,
        "network_requests_executed": false,
        "secret_returned": false,
        "authorization_header_returned": false,
        "raw_external_payload_returned": false,
    }))
}

async fn execute_enterprise_external_crm_sync_run_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    actor_session_id: Uuid,
    audit_id: Uuid,
    sync_run: &EnterpriseExternalCrmSyncRunWrite,
) -> Result<Value, AdminError> {
    let adapter_row = sqlx::query(
        r#"
        select id, provider, status, secret_ref_present, webhook_ref_present, sync_direction, metadata
        from enterprise_external_crm_adapters
        where tenant_id = $1
        for update
        "#,
    )
    .bind(tenant_id)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let Some(adapter_row) = adapter_row else {
        return insert_enterprise_crm_sync_run_tx(
            tx,
            tenant_id,
            None,
            "not-configured",
            sync_run,
            "refused",
            sync_run.sync_marker.as_deref(),
            0,
            0,
            0,
            sync_run.provider_response_summary.as_ref(),
            sync_run.provider_response_parser.as_ref(),
            false,
            false,
            Some("external_crm_adapter_not_configured"),
            actor_session_id,
            audit_id,
        )
        .await;
    };

    let adapter_id = admin_row_get::<Uuid>(&adapter_row, "id")?;
    let provider = admin_row_get::<String>(&adapter_row, "provider")?;
    let status = admin_row_get::<String>(&adapter_row, "status")?;
    let secret_ref_present = admin_row_get::<bool>(&adapter_row, "secret_ref_present")?;
    let webhook_ref_present = admin_row_get::<bool>(&adapter_row, "webhook_ref_present")?;
    let adapter_metadata = admin_row_get::<Value>(&adapter_row, "metadata")?;
    let endpoint_ref_present = adapter_metadata
        .get("endpoint_ref_present")
        .and_then(Value::as_bool)
        .unwrap_or(webhook_ref_present);
    let configured_direction = admin_row_get::<String>(&adapter_row, "sync_direction")?;
    let refused_reason = if let Some(reason) = enterprise_external_crm_adapter_blocked_reason(
        &provider,
        &status,
        secret_ref_present,
        endpoint_ref_present,
    ) {
        Some(reason)
    } else if configured_direction == "write-only" && sync_run.imported_activity_summary.is_some() {
        Some("external_crm_import_refused_for_write_only_adapter")
    } else {
        None
    };

    if let Some(reason) = refused_reason {
        return insert_enterprise_crm_sync_run_tx(
            tx,
            tenant_id,
            Some(adapter_id),
            &provider,
            sync_run,
            "refused",
            sync_run.sync_marker.as_deref(),
            0,
            0,
            0,
            sync_run.provider_response_summary.as_ref(),
            sync_run.provider_response_parser.as_ref(),
            endpoint_ref_present,
            secret_ref_present,
            Some(reason),
            actor_session_id,
            audit_id,
        )
        .await;
    }

    let run_row = sqlx::query(
        r#"
        insert into enterprise_crm_sync_runs (
          tenant_id, adapter_id, provider, direction, status, sync_marker,
          actor_session_id, audit_id, metadata
        )
        values ($1, $2, $3, $4, 'running', $5, $6, $7, $8)
        returning id, started_at::text as started_at
        "#,
    )
    .bind(tenant_id)
    .bind(adapter_id)
    .bind(&provider)
    .bind(&sync_run.direction)
    .bind(&sync_run.sync_marker)
    .bind(actor_session_id)
    .bind(audit_id)
    .bind(json!({
        "source": "enterprise_external_crm_sync_runner",
        "adapter": "enterprise_crm_sync_runs",
        "adapter_request": enterprise_crm_adapter_request_metadata(
            &provider,
            endpoint_ref_present,
            secret_ref_present,
            sync_run,
        ),
        "http_request_plan": enterprise_crm_http_request_plan(
            &provider,
            endpoint_ref_present,
            secret_ref_present,
            sync_run,
            None,
        ),
        "adapter_result": enterprise_crm_adapter_result_metadata(
            true,
            None,
            0,
            0,
            0,
        ),
        "network_requests_executed": false,
        "raw_external_payload_stored": false,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let run_id = admin_row_get::<Uuid>(&run_row, "id")?;

    let imported_activity = if let Some(activity) = &sync_run.imported_activity_summary {
        Some(
            insert_enterprise_crm_imported_activity_tx(
                tx,
                tenant_id,
                actor_session_id,
                audit_id,
                run_id,
                activity,
            )
            .await?,
        )
    } else {
        None
    };
    let imported_activity_count = i32::from(imported_activity.is_some());
    let provider_response_parser = enterprise_crm_provider_response_parser_metadata(
        &provider,
        true,
        None,
        imported_activity_count,
        sync_run.updated_count,
        sync_run.skipped_count,
        sync_run.provider_response_summary.as_ref(),
        sync_run.provider_response_parser.as_ref(),
    );
    let provider_response_reducer = enterprise_crm_provider_response_reducer_metadata(
        &provider,
        true,
        None,
        imported_activity_count,
        sync_run.updated_count,
        sync_run.skipped_count,
        &provider_response_parser,
    );
    let reduced_imported_count = provider_response_reducer
        .get("imported_count")
        .and_then(Value::as_i64)
        .and_then(|value| i32::try_from(value).ok())
        .unwrap_or(imported_activity_count);
    let updated_count = provider_response_reducer
        .get("updated_count")
        .and_then(Value::as_i64)
        .and_then(|value| i32::try_from(value).ok())
        .unwrap_or(sync_run.updated_count);
    let skipped_count = provider_response_reducer
        .get("skipped_count")
        .and_then(Value::as_i64)
        .and_then(|value| i32::try_from(value).ok())
        .unwrap_or(sync_run.skipped_count);
    let next_sync_marker_hash = provider_response_reducer
        .get("next_sync_marker_hash")
        .and_then(Value::as_str)
        .map(ToOwned::to_owned);
    let stored_sync_marker = next_sync_marker_hash
        .as_deref()
        .or(sync_run.sync_marker.as_deref());
    let http_request_plan = enterprise_crm_http_request_plan(
        &provider,
        endpoint_ref_present,
        secret_ref_present,
        sync_run,
        None,
    );
    let retry_policy_readback = enterprise_crm_retry_policy_readback(&provider_response_reducer);
    let retry_attempt_fingerprint = http_request_plan
        .get("idempotency_fingerprint")
        .and_then(Value::as_str)
        .unwrap_or("missing-fingerprint");
    let prior_retry_attempt_count =
        enterprise_crm_prior_retry_attempt_count_tx(tx, tenant_id, retry_attempt_fingerprint)
            .await?;
    let retry_attempt_readback = enterprise_crm_retry_attempt_readback(
        &retry_policy_readback,
        &http_request_plan,
        prior_retry_attempt_count,
        sync_run.provider_response_summary.is_some(),
        sync_run.provider_response_parser.is_some(),
    );
    let http_executor_boundary = enterprise_crm_http_executor_boundary(
        &http_request_plan,
        Some(&retry_policy_readback),
        Some(&retry_attempt_readback),
    );
    let final_metadata = json!({
        "source": "enterprise_external_crm_sync_runner",
        "adapter": "enterprise_crm_sync_runs",
        "adapter_request": enterprise_crm_adapter_request_metadata(
            &provider,
            endpoint_ref_present,
            secret_ref_present,
            sync_run,
        ),
        "http_request_plan": http_request_plan,
        "http_executor_boundary": http_executor_boundary,
        "adapter_result": enterprise_crm_adapter_result_metadata(
            true,
            None,
            imported_activity_count,
            updated_count,
            skipped_count,
        ),
        "provider_response_reducer": provider_response_reducer,
        "provider_response_parser": provider_response_parser,
        "retry_policy_readback": retry_policy_readback,
        "retry_attempt_readback": retry_attempt_readback,
        "network_requests_executed": false,
        "raw_external_payload_stored": false,
        "secret_safe": true
    });

    let row = sqlx::query(
        r#"
        update enterprise_crm_sync_runs
        set status = 'completed',
            completed_at = now(),
            imported_activity_count = $2,
            sync_marker = $5,
            metadata = metadata || $4::jsonb,
            updated_at = now()
        where tenant_id = $1 and id = $3
        returning id, tenant_id, adapter_id, provider, direction, status,
          started_at::text as started_at, completed_at::text as completed_at,
          imported_activity_count, refused_reason, sync_marker, metadata, created_at::text as created_at
        "#,
    )
    .bind(tenant_id)
    .bind(reduced_imported_count)
    .bind(run_id)
    .bind(final_metadata)
    .bind(stored_sync_marker)
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    if let Some(sync_marker) = stored_sync_marker {
        sqlx::query(
            r#"
            update enterprise_external_crm_adapters
            set last_sync_marker = $3, updated_at = now()
            where tenant_id = $1 and id = $2
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .bind(sync_marker)
        .execute(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    }

    enterprise_crm_sync_run_row_readback(&row, imported_activity, audit_id)
}

async fn execute_enterprise_external_crm_sync_run_request_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    actor_session_id: Uuid,
    audit_id: Uuid,
    sync_run: &EnterpriseExternalCrmSyncRunWrite,
) -> Result<Value, AdminError> {
    match sync_run.retry_attempt_mode.as_str() {
        "plan" => {
            execute_enterprise_external_crm_sync_run_tx(
                tx,
                tenant_id,
                actor_session_id,
                audit_id,
                sync_run,
            )
            .await
        }
        "mark_attempted" | "mark_skipped" => {
            mark_enterprise_crm_retry_attempt_tx(tx, tenant_id, audit_id, sync_run).await
        }
        _ => Err(AdminError::bad_request(
            "unsupported external_crm_sync_run.retry_attempt_mode",
        )),
    }
}

async fn mark_enterprise_crm_retry_attempt_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    audit_id: Uuid,
    sync_run: &EnterpriseExternalCrmSyncRunWrite,
) -> Result<Value, AdminError> {
    let current_adapter_blocked_reason =
        enterprise_current_crm_adapter_blocked_reason_tx(tx, tenant_id).await?;

    let row = sqlx::query(
        r#"
        select id, tenant_id, adapter_id, provider, direction, status,
          started_at::text as started_at, completed_at::text as completed_at,
          imported_activity_count, refused_reason, sync_marker, metadata,
          coalesce(audit_id, '00000000-0000-0000-0000-000000000000'::uuid) as audit_id,
          created_at::text as created_at
        from enterprise_crm_sync_runs
        where tenant_id = $1
        order by created_at desc
        limit 1
        for update
        "#,
    )
    .bind(tenant_id)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let Some(row) = row else {
        return Ok(enterprise_crm_retry_attempt_blocked_readback(
            sync_run.retry_attempt_mode.as_str(),
            "external_crm_sync_run_not_requested",
            audit_id,
        ));
    };

    let metadata = admin_row_get::<Value>(&row, "metadata").unwrap_or_else(|_| json!({}));
    let existing_retry_attempt = metadata
        .get("retry_attempt_readback")
        .cloned()
        .unwrap_or_else(|| json!({}));
    let block_reason = current_adapter_blocked_reason.as_deref().or_else(|| {
        existing_retry_attempt
            .get("status")
            .and_then(Value::as_str)
            .filter(|status| *status == "blocked")
            .and_then(|_| existing_retry_attempt.get("reason").and_then(Value::as_str))
    });

    if let Some(reason) = block_reason {
        let readback = enterprise_crm_sync_run_row_readback(&row, None, audit_id)?;
        return Ok(enterprise_crm_sync_run_readback_with_retry_attempt(
            readback,
            enterprise_crm_retry_attempt_local_marker(
                &existing_retry_attempt,
                sync_run.retry_attempt_mode.as_str(),
                sync_run.operator_reason.as_deref(),
                reason,
                None,
            ),
        ));
    }

    if sync_run.retry_attempt_mode == "mark_attempted"
        && existing_retry_attempt.get("status").and_then(Value::as_str) != Some("scheduled")
    {
        let reason = existing_retry_attempt
            .get("reason")
            .and_then(Value::as_str)
            .unwrap_or("retry_attempt_not_scheduled");
        let readback = enterprise_crm_sync_run_row_readback(&row, None, audit_id)?;
        return Ok(enterprise_crm_sync_run_readback_with_retry_attempt(
            readback,
            enterprise_crm_retry_attempt_local_marker(
                &existing_retry_attempt,
                sync_run.retry_attempt_mode.as_str(),
                sync_run.operator_reason.as_deref(),
                reason,
                None,
            ),
        ));
    }

    let updated_row = sqlx::query(
        r#"
        update enterprise_crm_sync_runs
        set metadata = jsonb_set(
              metadata,
              '{retry_attempt_readback}',
              $2::jsonb || jsonb_build_object('attempted_at', now()::text),
              true
            ),
            updated_at = now()
        where tenant_id = $1 and id = $3
        returning id, tenant_id, adapter_id, provider, direction, status,
          started_at::text as started_at, completed_at::text as completed_at,
          imported_activity_count, refused_reason, sync_marker, metadata,
          coalesce(audit_id, '00000000-0000-0000-0000-000000000000'::uuid) as audit_id,
          created_at::text as created_at
        "#,
    )
    .bind(tenant_id)
    .bind(enterprise_crm_retry_attempt_local_marker(
        &existing_retry_attempt,
        sync_run.retry_attempt_mode.as_str(),
        sync_run.operator_reason.as_deref(),
        "local_operator_marker",
        Some("pending_db_timestamp"),
    ))
    .bind(admin_row_get::<Uuid>(&row, "id")?)
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    enterprise_crm_sync_run_row_readback(&updated_row, None, audit_id)
}

async fn enterprise_current_crm_adapter_blocked_reason_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
) -> Result<Option<String>, AdminError> {
    let row = sqlx::query(
        r#"
        select provider, status, secret_ref_present, webhook_ref_present, metadata
        from enterprise_external_crm_adapters
        where tenant_id = $1
        for update
        "#,
    )
    .bind(tenant_id)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let Some(row) = row else {
        return Ok(Some("external_crm_adapter_not_configured".to_string()));
    };
    let metadata = admin_row_get::<Value>(&row, "metadata")?;
    let endpoint_ref_present = metadata
        .get("endpoint_ref_present")
        .and_then(Value::as_bool)
        .unwrap_or(admin_row_get::<bool>(&row, "webhook_ref_present")?);

    Ok(enterprise_external_crm_adapter_blocked_reason(
        &admin_row_get::<String>(&row, "provider")?,
        &admin_row_get::<String>(&row, "status")?,
        admin_row_get::<bool>(&row, "secret_ref_present")?,
        endpoint_ref_present,
    )
    .map(str::to_string))
}

#[allow(clippy::too_many_arguments)]
async fn insert_enterprise_crm_sync_run_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    adapter_id: Option<Uuid>,
    provider: &str,
    sync_run: &EnterpriseExternalCrmSyncRunWrite,
    status: &str,
    sync_marker: Option<&str>,
    imported_activity_count: i32,
    updated_count: i32,
    skipped_count: i32,
    provider_response_summary: Option<&EnterpriseCrmProviderResponseSummaryWrite>,
    provider_response_parser: Option<&EnterpriseCrmProviderResponseParserWrite>,
    endpoint_ref_present: bool,
    secret_ref_present: bool,
    refused_reason: Option<&str>,
    actor_session_id: Uuid,
    audit_id: Uuid,
) -> Result<Value, AdminError> {
    let would_call = refused_reason.is_none();
    let provider_response_parser_present = provider_response_parser.is_some();
    let http_request_plan = enterprise_crm_http_request_plan(
        provider,
        endpoint_ref_present,
        secret_ref_present,
        sync_run,
        refused_reason,
    );
    let provider_response_parser = enterprise_crm_provider_response_parser_metadata(
        provider,
        would_call,
        refused_reason,
        imported_activity_count,
        updated_count,
        skipped_count,
        provider_response_summary,
        provider_response_parser,
    );
    let provider_response_reducer = enterprise_crm_provider_response_reducer_metadata(
        provider,
        would_call,
        refused_reason,
        imported_activity_count,
        updated_count,
        skipped_count,
        &provider_response_parser,
    );
    let retry_policy_readback = enterprise_crm_retry_policy_readback(&provider_response_reducer);
    let retry_attempt_readback = enterprise_crm_retry_attempt_readback(
        &retry_policy_readback,
        &http_request_plan,
        0,
        provider_response_summary.is_some(),
        provider_response_parser_present,
    );
    let http_executor_boundary = enterprise_crm_http_executor_boundary(
        &http_request_plan,
        Some(&retry_policy_readback),
        Some(&retry_attempt_readback),
    );
    let row = sqlx::query(
        r#"
        insert into enterprise_crm_sync_runs (
          tenant_id, adapter_id, provider, direction, status, completed_at,
          imported_activity_count, refused_reason, sync_marker,
          actor_session_id, audit_id, metadata
        )
        values (
          $1, $2, $3, $4, $5, now(), $6, $7, $8, $9, $10, $11
        )
        returning id, tenant_id, adapter_id, provider, direction, status,
          started_at::text as started_at, completed_at::text as completed_at,
          imported_activity_count, refused_reason, sync_marker, metadata, created_at::text as created_at
        "#,
    )
    .bind(tenant_id)
    .bind(adapter_id)
    .bind(provider)
    .bind(&sync_run.direction)
    .bind(status)
    .bind(imported_activity_count)
    .bind(refused_reason)
    .bind(sync_marker)
    .bind(actor_session_id)
    .bind(audit_id)
    .bind(json!({
        "source": "enterprise_external_crm_sync_runner",
        "adapter": "enterprise_crm_sync_runs",
        "adapter_request": enterprise_crm_adapter_request_metadata(
            provider,
            endpoint_ref_present,
            secret_ref_present,
            sync_run,
        ),
        "http_request_plan": http_request_plan,
        "http_executor_boundary": http_executor_boundary,
        "adapter_result": enterprise_crm_adapter_result_metadata(
            would_call,
            refused_reason,
            imported_activity_count,
            updated_count,
            skipped_count,
        ),
        "provider_response_reducer": provider_response_reducer,
        "provider_response_parser": provider_response_parser,
        "retry_policy_readback": retry_policy_readback,
        "retry_attempt_readback": retry_attempt_readback,
        "network_requests_executed": false,
        "raw_external_payload_stored": false,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    enterprise_crm_sync_run_row_readback(&row, None, audit_id)
}

fn enterprise_crm_adapter_request_metadata(
    provider: &str,
    endpoint_ref_present: bool,
    secret_ref_present: bool,
    sync_run: &EnterpriseExternalCrmSyncRunWrite,
) -> Value {
    json!({
        "adapter_kind": provider,
        "endpoint_ref_present": endpoint_ref_present,
        "secret_ref_present": secret_ref_present,
        "operation": &sync_run.operation,
        "direction": &sync_run.direction,
        "external_ids_hash_present": sync_run.external_ids_hash.as_deref().is_some_and(|value| !value.trim().is_empty()),
        "external_ids_hash": &sync_run.external_ids_hash,
        "sync_marker_present": sync_run.sync_marker.as_deref().is_some_and(|value| !value.trim().is_empty()),
        "sync_marker": &sync_run.sync_marker,
        "imported_activity_summary_present": sync_run.imported_activity_summary.is_some(),
    })
}

fn enterprise_crm_http_request_plan(
    provider: &str,
    endpoint_ref_present: bool,
    secret_ref_present: bool,
    sync_run: &EnterpriseExternalCrmSyncRunWrite,
    blocked_reason: Option<&str>,
) -> Value {
    let operation = sync_run.operation.as_str();
    let direction = sync_run.direction.as_str();
    let provider_blocked_reason = blocked_reason.or_else(|| {
        enterprise_external_crm_adapter_blocked_reason(
            provider,
            "enabled",
            secret_ref_present,
            endpoint_ref_present,
        )
    });
    let would_send = provider_blocked_reason.is_none();
    let fingerprint = enterprise_crm_http_request_plan_fingerprint(
        provider,
        operation,
        direction,
        sync_run.external_ids_hash.as_deref(),
        sync_run.sync_marker.as_deref(),
    );

    json!({
        "adapter_kind": provider,
        "operation": operation,
        "direction": direction,
        "method": enterprise_crm_http_method(operation, direction),
        "path_or_endpoint_ref": enterprise_crm_path_or_endpoint_ref(provider, operation),
        "endpoint_ref_present": endpoint_ref_present,
        "headers_required_presence": enterprise_crm_headers_required_presence(provider, secret_ref_present),
        "body_shape": enterprise_crm_body_shape(operation, direction, sync_run),
        "idempotency_fingerprint": fingerprint,
        "would_send": would_send,
        "would_call": would_send,
        "blocked": !would_send,
        "blocked_reason": provider_blocked_reason,
        "network_requests_executed": false,
        "raw_endpoint_url_returned": false,
        "authorization_header_returned": false,
        "secret_returned": false,
        "raw_external_payload_returned": false,
    })
}

fn enterprise_crm_http_executor_boundary(
    http_request_plan: &Value,
    retry_policy_readback: Option<&Value>,
    retry_attempt_readback: Option<&Value>,
) -> Value {
    let retry_recommended = retry_policy_readback
        .and_then(|value| value.get("retry_recommended"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let backoff_reason = retry_policy_readback
        .and_then(|value| value.get("backoff_reason"))
        .and_then(Value::as_str)
        .unwrap_or("not-evaluated");
    let max_attempts = retry_policy_readback
        .and_then(|value| value.get("max_attempts"))
        .and_then(Value::as_i64)
        .unwrap_or(0);
    let next_retry_after_seconds = retry_policy_readback
        .and_then(|value| value.get("next_retry_after_seconds"))
        .cloned()
        .unwrap_or(Value::Null);
    let reset_at_present = retry_policy_readback
        .and_then(|value| value.get("reset_at_present"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let retry_attempt_status = retry_attempt_readback
        .and_then(|value| value.get("status"))
        .and_then(Value::as_str)
        .unwrap_or("not_evaluated");
    let retry_attempt_count = retry_attempt_readback
        .and_then(|value| value.get("attempt_count"))
        .and_then(Value::as_i64)
        .unwrap_or(0);

    json!({
        "schema": "enterprise_crm_http_executor_boundary.v1",
        "implementation": "network_disabled_request_builder_readback",
        "request_builder": {
            "method": http_request_plan
                .get("method")
                .cloned()
                .unwrap_or_else(|| json!("GET")),
            "path_or_endpoint_ref": http_request_plan
                .get("path_or_endpoint_ref")
                .cloned()
                .unwrap_or_else(|| json!("not_configured.endpoint_ref")),
            "endpoint_ref_present": http_request_plan
                .get("endpoint_ref_present")
                .cloned()
                .unwrap_or_else(|| json!(false)),
            "headers_required_presence": http_request_plan
                .get("headers_required_presence")
                .cloned()
                .unwrap_or_else(|| json!({
                    "authorization": false,
                    "authorization_secret_ref_present": false,
                    "content_type_json": true,
                    "provider_version_header": false,
                    "raw_header_values_returned": false
                })),
            "body_shape": http_request_plan
                .get("body_shape")
                .cloned()
                .unwrap_or_else(|| json!({
                    "kind": "query_or_marker_summary",
                    "fields": [],
                    "raw_body_returned": false,
                    "raw_external_payload_returned": false
                })),
            "timeout": {
                "connect_timeout_ms": 2000,
                "request_timeout_ms": 10000,
                "source": "bounded_default_readback"
            },
            "raw_endpoint_url_returned": false,
            "authorization_header_returned": false,
            "secret_returned": false,
            "raw_request_body_returned": false,
            "raw_external_payload_returned": false
        },
        "retry_summary": {
            "retry_recommended": retry_recommended,
            "backoff_reason": backoff_reason,
            "max_attempts": max_attempts,
            "next_retry_after_seconds": next_retry_after_seconds,
            "reset_at_present": reset_at_present,
            "attempt_status": retry_attempt_status,
            "attempt_count": retry_attempt_count
        },
        "network_enabled": false,
        "network_call_performed": false,
        "network_requests_executed": false,
        "would_send_if_enabled": http_request_plan
            .get("would_send")
            .cloned()
            .unwrap_or_else(|| json!(false)),
        "blocked": http_request_plan
            .get("blocked")
            .cloned()
            .unwrap_or_else(|| json!(true)),
        "blocked_reason": http_request_plan
            .get("blocked_reason")
            .cloned()
            .unwrap_or(Value::Null),
        "raw_response_body_returned": false,
        "raw_headers_returned": false,
        "raw_endpoint_url_returned": false,
        "authorization_header_returned": false,
        "secret_returned": false,
        "raw_request_body_returned": false,
        "raw_external_payload_returned": false,
    })
}

fn enterprise_crm_http_request_plan_fingerprint(
    provider: &str,
    operation: &str,
    direction: &str,
    external_ids_hash: Option<&str>,
    sync_marker: Option<&str>,
) -> String {
    sha256_hex(&format!(
        "enterprise-crm-http-request-plan:v1:{provider}:{operation}:{direction}:external_ids_present={}:sync_marker_present={}:external_ids_hash={}:sync_marker_hash={}",
        external_ids_hash.is_some_and(|value| !value.trim().is_empty()),
        sync_marker.is_some_and(|value| !value.trim().is_empty()),
        external_ids_hash.unwrap_or(""),
        sync_marker.unwrap_or("")
    ))
}

#[allow(clippy::too_many_arguments)]
fn enterprise_crm_http_request_plan_for_readback(
    provider: &str,
    operation: &str,
    direction: &str,
    endpoint_ref_present: bool,
    secret_ref_present: bool,
    external_ids_hash_present: bool,
    sync_marker_present: bool,
    imported_activity_summary_present: bool,
    blocked_reason: Option<&str>,
) -> Value {
    let would_send = blocked_reason.is_none();
    json!({
        "adapter_kind": provider,
        "operation": operation,
        "direction": direction,
        "method": enterprise_crm_http_method(operation, direction),
        "path_or_endpoint_ref": enterprise_crm_path_or_endpoint_ref(provider, operation),
        "endpoint_ref_present": endpoint_ref_present,
        "headers_required_presence": enterprise_crm_headers_required_presence(provider, secret_ref_present),
        "body_shape": {
            "kind": if operation == "export-activities" || direction == "write-only" {
                "activity_write_summary"
            } else {
                "query_or_marker_summary"
            },
            "fields": [
                "operation",
                "direction",
                "external_ids_hash_present",
                "sync_marker_present",
                "imported_activity_summary_present",
                "updated_count",
                "skipped_count"
            ],
            "external_ids_hash_present": external_ids_hash_present,
            "sync_marker_present": sync_marker_present,
            "imported_activity_summary_present": imported_activity_summary_present,
            "raw_body_returned": false,
            "raw_external_payload_returned": false
        },
        "idempotency_fingerprint": enterprise_crm_http_request_plan_fingerprint(
            provider,
            operation,
            direction,
            None,
            None,
        ),
        "would_send": would_send,
        "would_call": would_send,
        "blocked": !would_send,
        "blocked_reason": blocked_reason,
        "network_requests_executed": false,
        "raw_endpoint_url_returned": false,
        "authorization_header_returned": false,
        "secret_returned": false,
        "raw_external_payload_returned": false,
    })
}

fn enterprise_crm_http_method(operation: &str, direction: &str) -> &'static str {
    match (operation, direction) {
        ("export-activities", _) | (_, "write-only" | "bidirectional") => "POST",
        ("webhook-readback", _) | ("import-activities", _) | ("sync-activities", _) => "GET",
        _ => "GET",
    }
}

fn enterprise_crm_path_or_endpoint_ref(provider: &str, operation: &str) -> &'static str {
    match (provider, operation) {
        ("hubspot", "export-activities") => "hubspot.crm.engagements.create",
        ("hubspot", _) => "hubspot.crm.objects.activities.search",
        ("salesforce", "export-activities") => "salesforce.sobject.Task.create",
        ("salesforce", _) => "salesforce.soql.Task.query",
        ("pipedrive", "export-activities") => "pipedrive.activities.create",
        ("pipedrive", _) => "pipedrive.activities.list",
        ("zoho", "export-activities") => "zoho.crm.activities.create",
        ("zoho", _) => "zoho.crm.activities.search",
        ("custom-http", _) => "custom_http.endpoint_ref",
        _ => "not_configured.endpoint_ref",
    }
}

fn enterprise_crm_headers_required_presence(provider: &str, secret_ref_present: bool) -> Value {
    json!({
        "authorization": provider != "not-configured" && provider != "custom-http",
        "authorization_secret_ref_present": secret_ref_present,
        "content_type_json": true,
        "provider_version_header": matches!(provider, "salesforce" | "zoho"),
        "raw_header_values_returned": false,
    })
}

fn enterprise_crm_body_shape(
    operation: &str,
    direction: &str,
    sync_run: &EnterpriseExternalCrmSyncRunWrite,
) -> Value {
    json!({
        "kind": if operation == "export-activities" || direction == "write-only" {
            "activity_write_summary"
        } else {
            "query_or_marker_summary"
        },
        "fields": [
            "operation",
            "direction",
            "external_ids_hash_present",
            "sync_marker_present",
            "imported_activity_summary_present",
            "updated_count",
            "skipped_count"
        ],
        "external_ids_hash_present": sync_run.external_ids_hash.as_deref().is_some_and(|value| !value.trim().is_empty()),
        "sync_marker_present": sync_run.sync_marker.as_deref().is_some_and(|value| !value.trim().is_empty()),
        "imported_activity_summary_present": sync_run.imported_activity_summary.is_some(),
        "raw_body_returned": false,
        "raw_external_payload_returned": false,
    })
}

fn enterprise_crm_adapter_readiness_metadata(
    provider: &str,
    enabled: bool,
    secret_ref_present: bool,
    endpoint_ref_present: bool,
) -> Value {
    let blocked_reason = enterprise_external_crm_adapter_blocked_reason(
        provider,
        if enabled { "enabled" } else { "disabled" },
        secret_ref_present,
        endpoint_ref_present,
    );
    json!({
        "adapter_kind": provider,
        "readiness": if blocked_reason.is_none() { "ready-for-request-plan" } else { "blocked" },
        "unsupported_reason": if provider == "custom-http" {
            Some("custom_http_adapter_not_implemented")
        } else {
            None
        },
        "blocked_reason": blocked_reason,
        "network_requests_executed": false,
    })
}

fn enterprise_crm_adapter_result_metadata(
    would_call: bool,
    blocked_reason: Option<&str>,
    imported_count: i32,
    updated_count: i32,
    skipped_count: i32,
) -> Value {
    json!({
        "would_call": would_call,
        "blocked_reason": blocked_reason,
        "imported_count": imported_count,
        "updated_count": updated_count,
        "skipped_count": skipped_count,
    })
}

#[allow(clippy::too_many_arguments)]
fn enterprise_crm_provider_response_parser_metadata(
    provider: &str,
    would_call: bool,
    blocked_reason: Option<&str>,
    fallback_imported_count: i32,
    fallback_updated_count: i32,
    fallback_skipped_count: i32,
    summary: Option<&EnterpriseCrmProviderResponseSummaryWrite>,
    parser: Option<&EnterpriseCrmProviderResponseParserWrite>,
) -> Value {
    let imported_count = parser
        .and_then(|value| value.imported_count)
        .or_else(|| summary.and_then(|value| value.imported_count))
        .unwrap_or(fallback_imported_count);
    let updated_count = parser
        .and_then(|value| value.updated_count)
        .or_else(|| summary.and_then(|value| value.updated_count))
        .unwrap_or(fallback_updated_count);
    let skipped_count = parser
        .and_then(|value| value.skipped_count)
        .or_else(|| summary.and_then(|value| value.skipped_count))
        .unwrap_or(fallback_skipped_count);
    let failed_count = parser
        .and_then(|value| value.failed_count)
        .or_else(|| summary.and_then(|value| value.failed_count))
        .unwrap_or(0);
    let retry_after_seconds = parser.and_then(|value| value.retry_after_seconds);
    let rate_limit_present = parser
        .and_then(|value| value.rate_limit_present)
        .or_else(|| summary.and_then(|value| value.rate_limit_present))
        .unwrap_or(false);
    let rate_limit_reset_present = parser
        .and_then(|value| value.rate_limit_reset_present)
        .or_else(|| summary.and_then(|value| value.rate_limit_reset_present))
        .unwrap_or(false);
    let next_cursor_hash = parser
        .and_then(|value| value.next_cursor_hash.as_deref())
        .or_else(|| summary.and_then(|value| value.next_cursor_hash.as_deref()));
    let next_sync_marker_hash = parser
        .and_then(|value| value.next_sync_marker_hash.as_deref())
        .or_else(|| summary.and_then(|value| value.next_sync_marker_hash.as_deref()));
    let cursor_present = parser
        .and_then(|value| value.cursor_present)
        .unwrap_or_else(|| next_cursor_hash.is_some_and(|value| !value.trim().is_empty()));
    let provider_error_category = parser
        .and_then(|value| value.provider_error_category.as_deref())
        .or_else(|| summary.and_then(|value| value.provider_error_category.as_deref()))
        .unwrap_or("none");
    let status = if !would_call || blocked_reason.is_some() {
        "blocked"
    } else if let Some(parser) = parser {
        parser.status.as_str()
    } else if rate_limit_present || provider_error_category == "rate-limit" {
        "rate-limited"
    } else if matches!(provider_error_category, "auth" | "permission") {
        "auth-error"
    } else if provider_error_category != "none" || failed_count > 0 {
        "provider-error"
    } else if summary.is_some() {
        "success"
    } else {
        "not-provided"
    };
    let safe_next_action = parser
        .and_then(|value| value.safe_next_action.as_deref())
        .unwrap_or_else(|| {
            enterprise_crm_provider_parser_next_action(status, provider_error_category)
        });

    json!({
        "schema": "enterprise_crm_provider_response_parser.v1",
        "input_source": if parser.is_some() {
            "external_crm_sync_run.provider_response_parser"
        } else if summary.is_some() {
            "external_crm_sync_run.provider_response_summary"
        } else {
            "fixture_safe_request_counts"
        },
        "adapter_kind": provider,
        "provider": provider,
        "normalized_provider": if matches!(provider, "hubspot" | "salesforce" | "pipedrive" | "zoho") {
            provider
        } else {
            "not-configured"
        },
        "status": status,
        "blocked": !would_call || blocked_reason.is_some(),
        "blocked_reason": blocked_reason,
        "retry_after": {
            "present": retry_after_seconds.is_some(),
            "seconds": retry_after_seconds,
            "raw_header_returned": false
        },
        "rate_limit": {
            "present": rate_limit_present,
            "reset_present": rate_limit_reset_present,
            "remaining_present": parser.and_then(|value| value.rate_limit_remaining_present).unwrap_or(false),
            "raw_headers_accepted": false,
            "raw_headers_returned": false
        },
        "cursor": {
            "present": cursor_present,
            "next_cursor_hash_present": next_cursor_hash.is_some_and(|value| !value.trim().is_empty()),
            "next_cursor_hash": next_cursor_hash,
            "next_sync_marker_hash_present": next_sync_marker_hash.is_some_and(|value| !value.trim().is_empty()),
            "next_sync_marker_hash": next_sync_marker_hash,
            "raw_cursor_accepted": false,
            "raw_cursor_returned": false
        },
        "external_id_counts": {
            "total": parser.and_then(|value| value.external_id_count).unwrap_or(imported_count + updated_count + skipped_count),
            "created": parser.and_then(|value| value.external_id_created_count).unwrap_or(imported_count),
            "updated": parser.and_then(|value| value.external_id_updated_count).unwrap_or(updated_count),
            "skipped": parser.and_then(|value| value.external_id_skipped_count).unwrap_or(skipped_count),
        },
        "result_counts": {
            "imported": imported_count,
            "updated": updated_count,
            "skipped": skipped_count,
            "failed": failed_count
        },
        "provider_error": {
            "present": provider_error_category != "none",
            "category": provider_error_category
        },
        "safe_next_action": safe_next_action,
        "network_requests_executed": false,
        "raw_response_body_accepted": false,
        "raw_response_body_returned": false,
        "raw_headers_accepted": false,
        "raw_headers_returned": false,
        "raw_payload_accepted": false,
        "raw_external_payload_returned": false,
        "raw_cursor_accepted": false,
        "raw_cursor_returned": false,
        "raw_endpoint_url_returned": false,
        "authorization_header_returned": false,
        "secret_returned": false,
    })
}

fn enterprise_crm_provider_parser_next_action(status: &str, category: &str) -> &'static str {
    match (status, category) {
        ("blocked", _) => "Fix CRM adapter configuration, then request a new bounded sync run.",
        ("rate-limited", _) | (_, "rate-limit") => {
            "Wait for the safe retry-after or reset presence marker before retrying."
        }
        ("auth-error", _) | (_, "auth" | "permission") => {
            "Check the CRM secret reference and provider permissions before retrying."
        }
        ("provider-error", "server" | "unknown") => {
            "Retry after the bounded backoff window if provider errors continue."
        }
        ("provider-error", _) => "Review the safe provider error category before retrying.",
        ("partial", _) => {
            "Review failed item counts, then retry only when the retry policy allows it."
        }
        ("success", _) => "No operator action required.",
        _ => "Request a bounded CRM sync run with fixture-safe response metadata when ready.",
    }
}

fn enterprise_crm_provider_response_reducer_metadata(
    provider: &str,
    would_call: bool,
    blocked_reason: Option<&str>,
    fallback_imported_count: i32,
    fallback_updated_count: i32,
    fallback_skipped_count: i32,
    parser: &Value,
) -> Value {
    let imported_count = parser
        .get("result_counts")
        .and_then(|value| value.get("imported"))
        .and_then(Value::as_i64)
        .and_then(|value| i32::try_from(value).ok())
        .unwrap_or(fallback_imported_count);
    let updated_count = parser
        .get("result_counts")
        .and_then(|value| value.get("updated"))
        .and_then(Value::as_i64)
        .and_then(|value| i32::try_from(value).ok())
        .unwrap_or(fallback_updated_count);
    let skipped_count = parser
        .get("result_counts")
        .and_then(|value| value.get("skipped"))
        .and_then(Value::as_i64)
        .and_then(|value| i32::try_from(value).ok())
        .unwrap_or(fallback_skipped_count);
    let failed_count = parser
        .get("result_counts")
        .and_then(|value| value.get("failed"))
        .and_then(Value::as_i64)
        .and_then(|value| i32::try_from(value).ok())
        .unwrap_or(0);
    let provider_error_category = parser
        .get("provider_error")
        .and_then(|value| value.get("category"))
        .and_then(Value::as_str);
    let provider_error_present = provider_error_category.is_some_and(|value| value != "none");
    let outcome = if !would_call || blocked_reason.is_some() {
        "blocked"
    } else if failed_count > 0 && imported_count == 0 && updated_count == 0 {
        "failed"
    } else if failed_count > 0 {
        "partial"
    } else {
        "succeeded"
    };
    let next_cursor_hash = parser
        .get("cursor")
        .and_then(|value| value.get("next_cursor_hash"))
        .and_then(Value::as_str);
    let next_sync_marker_hash = parser
        .get("cursor")
        .and_then(|value| value.get("next_sync_marker_hash"))
        .and_then(Value::as_str);
    let rate_limit_present = parser
        .get("rate_limit")
        .and_then(|value| value.get("present"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let rate_limit_reset_present = parser
        .get("rate_limit")
        .and_then(|value| value.get("reset_present"))
        .and_then(Value::as_bool)
        .unwrap_or(false);

    json!({
        "schema": "enterprise_crm_provider_response_reducer.v1",
        "adapter_kind": provider,
        "provider": provider,
        "would_call": would_call,
        "outcome": outcome,
        "blocked": !would_call || blocked_reason.is_some(),
        "blocked_reason": blocked_reason,
        "imported_count": imported_count,
        "updated_count": updated_count,
        "skipped_count": skipped_count,
        "failed_count": failed_count,
        "next_cursor_hash_present": next_cursor_hash.is_some_and(|value| !value.trim().is_empty()),
        "next_cursor_hash": next_cursor_hash,
        "next_sync_marker_hash_present": next_sync_marker_hash.is_some_and(|value| !value.trim().is_empty()),
        "next_sync_marker_hash": next_sync_marker_hash,
        "rate_limit": {
            "present": rate_limit_present,
            "reset_present": rate_limit_reset_present,
            "raw_headers_returned": false
        },
        "provider_error": {
            "present": provider_error_present,
            "category": provider_error_category
        },
        "input_source": parser
            .get("input_source")
            .cloned()
            .unwrap_or_else(|| json!("fixture_safe_request_counts")),
        "network_requests_executed": false,
        "raw_response_body_accepted": false,
        "raw_response_body_returned": false,
        "raw_external_payload_returned": false,
        "raw_cursor_returned": false,
        "authorization_header_returned": false,
        "secret_returned": false,
        "raw_endpoint_url_returned": false,
    })
}

async fn enterprise_crm_prior_retry_attempt_count_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    idempotency_fingerprint: &str,
) -> Result<i64, AdminError> {
    let row = sqlx::query(
        r#"
        select count(*)::bigint as attempt_count
        from enterprise_crm_sync_runs
        where tenant_id = $1
          and metadata->'retry_attempt_readback'->>'idempotency_fingerprint' = $2
          and metadata->'retry_attempt_readback'->>'status' = 'scheduled'
        "#,
    )
    .bind(tenant_id)
    .bind(idempotency_fingerprint)
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    admin_row_get::<i64>(&row, "attempt_count")
}

fn enterprise_crm_retry_policy_readback(provider_response_reducer: &Value) -> Value {
    let blocked = provider_response_reducer
        .get("blocked")
        .and_then(Value::as_bool)
        .unwrap_or(true);
    let blocked_reason = provider_response_reducer
        .get("blocked_reason")
        .and_then(Value::as_str);
    let failed_count = provider_response_reducer
        .get("failed_count")
        .and_then(Value::as_i64)
        .unwrap_or(0);
    let provider_error_category = provider_response_reducer
        .get("provider_error")
        .and_then(|value| value.get("category"))
        .and_then(Value::as_str)
        .unwrap_or("none");
    let rate_limit_present = provider_response_reducer
        .get("rate_limit")
        .and_then(|value| value.get("present"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let rate_limit_reset_present = provider_response_reducer
        .get("rate_limit")
        .and_then(|value| value.get("reset_present"))
        .and_then(Value::as_bool)
        .unwrap_or(false);

    let retryable_error = matches!(provider_error_category, "rate-limit" | "server" | "unknown");
    let operator_next_action = if blocked {
        match blocked_reason.unwrap_or("external_crm_adapter_blocked") {
            "external_crm_adapter_disabled" => {
                "Enable the CRM adapter before retrying the sync run."
            }
            "external_crm_secret_ref_missing" => {
                "Attach a CRM secret reference before retrying the sync run."
            }
            "external_crm_endpoint_ref_missing" => {
                "Attach a CRM endpoint reference before retrying the sync run."
            }
            "external_crm_adapter_unsupported" => {
                "Switch to a supported CRM adapter before retrying the sync run."
            }
            "external_crm_sync_run_not_requested" => {
                "Trigger PATCH /admin/enterprise/accounts with external_crm_sync_run when ready."
            }
            "filtered_out" => {
                "Clear filters or inspect the tenant account directly before retrying."
            }
            _ => "Resolve the CRM adapter blocked reason before retrying the sync run.",
        }
    } else if rate_limit_present || provider_error_category == "rate-limit" {
        if rate_limit_reset_present {
            "Wait for the provider reset marker, then retry the CRM sync run."
        } else {
            "Retry the CRM sync run after the bounded backoff window."
        }
    } else if provider_error_category == "server" || provider_error_category == "unknown" {
        "Retry the CRM sync run after the bounded backoff window; inspect provider status if failures continue."
    } else if matches!(provider_error_category, "auth" | "permission") {
        "Fix CRM credentials or permissions before retrying."
    } else if matches!(
        provider_error_category,
        "validation" | "not-found" | "conflict"
    ) {
        "Fix CRM mapping/input data before retrying."
    } else if failed_count > 0 {
        "Inspect failed provider items before retrying."
    } else {
        "No retry needed."
    };
    let backoff_reason = if blocked {
        blocked_reason.unwrap_or("external_crm_adapter_blocked")
    } else if rate_limit_present || provider_error_category == "rate-limit" {
        "provider_rate_limit"
    } else if provider_error_category == "server" {
        "provider_server_error"
    } else if provider_error_category == "unknown" {
        "provider_unknown_error"
    } else if matches!(provider_error_category, "auth" | "permission") {
        "provider_credentials_or_permissions"
    } else if matches!(
        provider_error_category,
        "validation" | "not-found" | "conflict"
    ) {
        "provider_non_retryable_error"
    } else if failed_count > 0 {
        "provider_item_failures"
    } else {
        "none"
    };
    let retry_recommended = !blocked
        && failed_count > 0
        && (retryable_error || rate_limit_present || provider_error_category == "none");
    let next_retry_after_seconds = if retry_recommended && !rate_limit_reset_present {
        if rate_limit_present || provider_error_category == "rate-limit" {
            Some(300)
        } else if provider_error_category == "server" || provider_error_category == "unknown" {
            Some(120)
        } else {
            Some(60)
        }
    } else {
        None
    };

    json!({
        "schema": "enterprise_crm_retry_policy_readback.v1",
        "retry_recommended": retry_recommended,
        "next_retry_after_seconds": next_retry_after_seconds,
        "reset_at_present": rate_limit_reset_present,
        "backoff_reason": backoff_reason,
        "max_attempts": if blocked { 0 } else { 3 },
        "operator_next_action": operator_next_action,
        "rate_limit_handoff": {
            "present": rate_limit_present,
            "reset_at_present": rate_limit_reset_present,
            "next_retry_after_seconds": next_retry_after_seconds,
            "raw_headers_returned": false,
            "raw_reset_at_returned": false
        },
        "network_requests_executed": false,
        "raw_response_body_returned": false,
        "raw_headers_returned": false,
        "authorization_header_returned": false,
        "secret_returned": false,
        "raw_endpoint_url_returned": false,
        "raw_cursor_returned": false,
    })
}

fn enterprise_crm_retry_attempt_readback(
    retry_policy_readback: &Value,
    http_request_plan: &Value,
    prior_scheduled_attempt_count: i64,
    provider_response_summary_present: bool,
    provider_response_parser_present: bool,
) -> Value {
    let retry_recommended = retry_policy_readback
        .get("retry_recommended")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let max_attempts = retry_policy_readback
        .get("max_attempts")
        .and_then(Value::as_i64)
        .unwrap_or(0);
    let backoff_reason = retry_policy_readback
        .get("backoff_reason")
        .and_then(Value::as_str)
        .unwrap_or("none");
    let next_retry_after_seconds = retry_policy_readback
        .get("next_retry_after_seconds")
        .cloned()
        .unwrap_or(Value::Null);
    let reset_at_present = retry_policy_readback
        .get("reset_at_present")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let idempotency_fingerprint = http_request_plan
        .get("idempotency_fingerprint")
        .and_then(Value::as_str)
        .unwrap_or("missing-fingerprint");
    let would_send = http_request_plan
        .get("would_send")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let blocked = http_request_plan
        .get("blocked")
        .and_then(Value::as_bool)
        .unwrap_or(!would_send);
    let attempts_exhausted = max_attempts > 0 && prior_scheduled_attempt_count >= max_attempts;
    let provider_response_metadata_present =
        provider_response_summary_present || provider_response_parser_present;
    let status = if blocked || max_attempts == 0 {
        "blocked"
    } else if retry_recommended && provider_response_metadata_present && !attempts_exhausted {
        "scheduled"
    } else {
        "not_recommended"
    };
    let attempt_count = if status == "scheduled" {
        (prior_scheduled_attempt_count + 1).min(max_attempts)
    } else {
        prior_scheduled_attempt_count.min(max_attempts)
    };
    let reason = if status == "scheduled" {
        backoff_reason
    } else if attempts_exhausted {
        "max_attempts_exhausted"
    } else if blocked {
        http_request_plan
            .get("blocked_reason")
            .and_then(Value::as_str)
            .unwrap_or(backoff_reason)
    } else if !provider_response_metadata_present {
        "provider_response_metadata_missing"
    } else {
        backoff_reason
    };

    json!({
        "schema": "enterprise_crm_retry_attempt_readback.v1",
        "attempt_count": attempt_count,
        "max_attempts": max_attempts,
        "next_retry_after_seconds": next_retry_after_seconds,
        "reset_at_present": reset_at_present,
        "status": status,
        "reason": reason,
        "idempotency_fingerprint": idempotency_fingerprint,
        "provider_response_summary_present": provider_response_summary_present,
        "provider_response_parser_present": provider_response_parser_present,
        "network_requests_executed": false,
        "raw_response_body_returned": false,
        "raw_headers_returned": false,
        "authorization_header_returned": false,
        "secret_returned": false,
        "raw_endpoint_url_returned": false,
        "raw_cursor_returned": false,
    })
}

fn enterprise_crm_retry_attempt_local_marker(
    existing_retry_attempt: &Value,
    retry_attempt_mode: &str,
    operator_reason: Option<&str>,
    reason: &str,
    attempted_at: Option<&str>,
) -> Value {
    let previous_attempt_count = existing_retry_attempt
        .get("next_attempt_count")
        .or_else(|| existing_retry_attempt.get("attempt_count"))
        .and_then(Value::as_i64)
        .unwrap_or(0);
    let max_attempts = existing_retry_attempt
        .get("max_attempts")
        .and_then(Value::as_i64)
        .unwrap_or(0);
    let next_attempt_count = if retry_attempt_mode == "mark_attempted" {
        if max_attempts > 0 {
            (previous_attempt_count + 1).min(max_attempts)
        } else {
            previous_attempt_count + 1
        }
    } else {
        previous_attempt_count
    };
    let idempotency_fingerprint = existing_retry_attempt
        .get("idempotency_fingerprint")
        .and_then(Value::as_str)
        .unwrap_or("missing-fingerprint");
    let status = if retry_attempt_mode == "mark_attempted"
        && existing_retry_attempt.get("status").and_then(Value::as_str) == Some("scheduled")
        && reason == "local_operator_marker"
    {
        "scheduled"
    } else if reason == "local_operator_marker" {
        existing_retry_attempt
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("not_recommended")
    } else {
        "blocked"
    };
    let attempt_status = match (retry_attempt_mode, reason) {
        ("mark_attempted", "local_operator_marker") => "attempted_local_marker",
        ("mark_skipped", "local_operator_marker") => "skipped_local_marker",
        ("mark_skipped", _) => "skipped_blocked",
        _ => "attempt_blocked",
    };

    json!({
        "schema": "enterprise_crm_retry_attempt_readback.v1",
        "attempt_count": next_attempt_count,
        "previous_attempt_count": previous_attempt_count,
        "next_attempt_count": next_attempt_count,
        "max_attempts": max_attempts,
        "next_retry_after_seconds": existing_retry_attempt
            .get("next_retry_after_seconds")
            .cloned()
            .unwrap_or(Value::Null),
        "reset_at_present": existing_retry_attempt
            .get("reset_at_present")
            .and_then(Value::as_bool)
            .unwrap_or(false),
        "status": status,
        "attempt_status": attempt_status,
        "attempted_at": attempted_at,
        "operator_reason": operator_reason,
        "reason": reason,
        "idempotency_fingerprint": idempotency_fingerprint,
        "provider_response_summary_present": existing_retry_attempt
            .get("provider_response_summary_present")
            .and_then(Value::as_bool)
            .unwrap_or(false),
        "provider_response_parser_present": existing_retry_attempt
            .get("provider_response_parser_present")
            .and_then(Value::as_bool)
            .unwrap_or(false),
        "network_requests_executed": false,
        "raw_response_body_returned": false,
        "raw_headers_returned": false,
        "authorization_header_returned": false,
        "secret_returned": false,
        "raw_endpoint_url_returned": false,
        "raw_cursor_returned": false,
    })
}

fn enterprise_crm_sync_run_readback_with_retry_attempt(
    mut readback: Value,
    retry_attempt_readback: Value,
) -> Value {
    if let Some(object) = readback.as_object_mut() {
        object.insert("retry_attempt_readback".to_string(), retry_attempt_readback);
    }
    readback
}

fn enterprise_crm_retry_attempt_blocked_readback(
    retry_attempt_mode: &str,
    reason: &str,
    audit_id: Uuid,
) -> Value {
    let provider_response_parser = enterprise_crm_provider_response_parser_metadata(
        "not-configured",
        false,
        Some(reason),
        0,
        0,
        0,
        None,
        None,
    );
    let provider_response_reducer = enterprise_crm_provider_response_reducer_metadata(
        "not-configured",
        false,
        Some(reason),
        0,
        0,
        0,
        &provider_response_parser,
    );
    let retry_policy_readback = enterprise_crm_retry_policy_readback(&provider_response_reducer);
    let http_request_plan = enterprise_crm_http_request_plan_for_readback(
        "not-configured",
        "sync-activities",
        "read-only",
        false,
        false,
        false,
        false,
        false,
        Some(reason),
    );
    let retry_attempt_readback = enterprise_crm_retry_attempt_local_marker(
        &enterprise_crm_retry_attempt_readback(
            &retry_policy_readback,
            &http_request_plan,
            0,
            false,
            false,
        ),
        retry_attempt_mode,
        None,
        reason,
        None,
    );
    let http_executor_boundary = enterprise_crm_http_executor_boundary(
        &http_request_plan,
        Some(&retry_policy_readback),
        Some(&retry_attempt_readback),
    );
    json!({
        "source": "enterprise_crm_sync_runs",
        "status": "not-run",
        "would_call": false,
        "http_request_plan": http_request_plan,
        "http_executor_boundary": http_executor_boundary,
        "blocked_reason": reason,
        "imported_activity_count": 0,
        "updated_count": 0,
        "skipped_count": 0,
        "failed_count": 0,
        "provider_response_parser": provider_response_parser,
        "provider_response_reducer": provider_response_reducer,
        "retry_policy_readback": retry_policy_readback,
        "retry_attempt_readback": retry_attempt_readback,
        "rate_limit_handoff": retry_policy_readback
            .get("rate_limit_handoff")
            .cloned()
            .unwrap_or_else(|| json!({})),
        "audit_id": audit_id,
        "readback_path": "GET /admin/enterprise/accounts",
        "write_path": "PATCH /admin/enterprise/accounts",
        "tenant_scoped": true,
        "runtime_implemented": true,
        "network_requests_executed": false,
        "secret_returned": false,
        "authorization_header_returned": false,
        "raw_external_payload_returned": false,
    })
}

fn enterprise_crm_sync_run_filtered_readback() -> Value {
    let provider_response_parser = enterprise_crm_provider_response_parser_metadata(
        "not-configured",
        false,
        Some("filtered_out"),
        0,
        0,
        0,
        None,
        None,
    );
    let provider_response_reducer = enterprise_crm_provider_response_reducer_metadata(
        "not-configured",
        false,
        Some("filtered_out"),
        0,
        0,
        0,
        &provider_response_parser,
    );
    let retry_policy_readback = enterprise_crm_retry_policy_readback(&provider_response_reducer);
    let rate_limit_handoff = retry_policy_readback
        .get("rate_limit_handoff")
        .cloned()
        .unwrap_or_else(|| json!({}));
    let http_request_plan = enterprise_crm_http_request_plan_for_readback(
        "not-configured",
        "sync-activities",
        "read-only",
        false,
        false,
        false,
        false,
        false,
        Some("filtered_out"),
    );
    let retry_attempt_readback = enterprise_crm_retry_attempt_readback(
        &retry_policy_readback,
        &http_request_plan,
        0,
        false,
        false,
    );
    let http_executor_boundary = enterprise_crm_http_executor_boundary(
        &http_request_plan,
        Some(&retry_policy_readback),
        Some(&retry_attempt_readback),
    );
    json!({
        "source": "enterprise_crm_sync_runs",
        "filtered_out": true,
        "status": "not-run",
        "would_call": false,
        "http_request_plan": http_request_plan,
        "http_executor_boundary": http_executor_boundary,
        "blocked_reason": "filtered_out",
        "imported_activity_count": 0,
        "updated_count": 0,
        "skipped_count": 0,
        "failed_count": 0,
        "provider_response_parser": provider_response_parser,
        "provider_response_reducer": provider_response_reducer,
        "retry_policy_readback": retry_policy_readback,
        "retry_attempt_readback": retry_attempt_readback,
        "rate_limit_handoff": rate_limit_handoff,
        "network_requests_executed": false,
        "secret_returned": false,
        "authorization_header_returned": false,
        "raw_external_payload_returned": false,
    })
}

