async fn enterprise_crm_retry_worker_handoff_summary(
    pool: &PgPool,
    tenant_id: Uuid,
    all_tenants: bool,
) -> Result<Value, AdminError> {
    let rows = sqlx::query(
        r#"
        select provider, refused_reason,
          metadata #> '{retry_attempt_readback}' as retry_attempt_readback,
          metadata #> '{retry_policy_readback}' as retry_policy_readback
        from enterprise_crm_sync_runs
        where ($1::boolean = true or tenant_id = $2)
        order by created_at desc
        limit 5000
        "#,
    )
    .bind(all_tenants)
    .bind(tenant_id)
    .fetch_all(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let mut scheduled_count = 0_i64;
    let mut blocked_count = 0_i64;
    let mut next_retry_after_seconds_min: Option<i64> = None;
    let mut provider_counts = BTreeMap::<String, BTreeMap<String, i64>>::new();
    let mut status_counts = BTreeMap::<String, i64>::new();
    let mut operator_next_action_counts = BTreeMap::<String, i64>::new();

    for row in &rows {
        let provider = admin_row_get::<String>(row, "provider")
            .unwrap_or_else(|_| "not-configured".to_string());
        let retry_attempt = admin_row_get::<Option<Value>>(row, "retry_attempt_readback")?
            .unwrap_or_else(|| json!({}));
        let retry_policy = admin_row_get::<Option<Value>>(row, "retry_policy_readback")?
            .unwrap_or_else(|| json!({}));
        let status = retry_attempt
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("missing")
            .to_string();

        bump_count(&mut status_counts, &status);
        bump_nested_count(&mut provider_counts, &provider, "total");
        bump_nested_count(&mut provider_counts, &provider, &status);

        if status == "scheduled" {
            scheduled_count += 1;
            if let Some(seconds) = retry_attempt
                .get("next_retry_after_seconds")
                .and_then(Value::as_i64)
            {
                next_retry_after_seconds_min = Some(
                    next_retry_after_seconds_min.map_or(seconds, |current| current.min(seconds)),
                );
            }
        } else if status == "blocked" {
            blocked_count += 1;
        }

        if status == "scheduled" || status == "blocked" {
            let action = retry_policy
                .get("operator_next_action")
                .and_then(Value::as_str)
                .map(str::to_string)
                .or_else(|| {
                    retry_attempt
                        .get("reason")
                        .and_then(Value::as_str)
                        .map(enterprise_dashboard_next_action_for_reason)
                        .map(str::to_string)
                })
                .or_else(|| {
                    admin_row_get::<Option<String>>(row, "refused_reason")
                        .ok()
                        .flatten()
                        .as_deref()
                        .map(enterprise_dashboard_next_action_for_reason)
                        .map(str::to_string)
                })
                .unwrap_or_else(|| {
                    "Review the CRM retry marker before enabling a real retry worker.".to_string()
                });
            bump_count(&mut operator_next_action_counts, &action);
        }
    }

    let operator_next_actions = operator_next_action_counts
        .iter()
        .map(|(action, count)| json!({ "action": action, "retry_marker_count": count }))
        .collect::<Vec<_>>();

    Ok(json!({
        "schema": "enterprise_crm_retry_worker_handoff_summary.v1",
        "source": "enterprise_crm_sync_runs.metadata.retry_attempt_readback",
        "scheduled_count": scheduled_count,
        "blocked_count": blocked_count,
        "next_retry_after_seconds_min": next_retry_after_seconds_min,
        "provider_counts": provider_counts,
        "operator_next_actions": operator_next_actions,
        "status_counts": status_counts,
        "row_limit": 5000,
        "readback_path": "GET /admin/enterprise/accounts",
        "dashboard_readback_path": "GET /admin/enterprise/sales-dashboard",
        "worker_handoff_ready": scheduled_count > 0,
        "tenant_scoped": !all_tenants,
        "cross_tenant": all_tenants,
        "read_only": true,
        "network_requests_executed": false,
        "authorization_header_returned": false,
        "secret_returned": false,
        "raw_endpoint_url_returned": false,
        "raw_cursor_returned": false,
        "raw_external_payload_returned": false,
    }))
}

async fn enterprise_crm_latest_sync_run_readback(
    pool: &PgPool,
    tenant_id: Uuid,
) -> Result<Value, AdminError> {
    let row = sqlx::query(
        r#"
        select id, tenant_id, adapter_id, provider, direction, status,
          started_at::text as started_at, completed_at::text as completed_at,
          imported_activity_count, refused_reason, sync_marker, metadata,
          coalesce(audit_id, '00000000-0000-0000-0000-000000000000'::uuid) as audit_id,
          created_at::text as created_at
        from enterprise_crm_sync_runs
        where tenant_id = $1
        order by created_at desc
        limit 1
        "#,
    )
    .bind(tenant_id)
    .fetch_optional(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let Some(row) = row else {
        let provider_response_parser = enterprise_crm_provider_response_parser_metadata(
            "not-configured",
            false,
            Some("external_crm_sync_run_not_requested"),
            0,
            0,
            0,
            None,
            None,
        );
        let provider_response_reducer = enterprise_crm_provider_response_reducer_metadata(
            "not-configured",
            false,
            Some("external_crm_sync_run_not_requested"),
            0,
            0,
            0,
            &provider_response_parser,
        );
        let retry_policy_readback =
            enterprise_crm_retry_policy_readback(&provider_response_reducer);
        let rate_limit_handoff = retry_policy_readback
            .get("rate_limit_handoff")
            .cloned()
            .unwrap_or_else(|| json!({}));
        let http_request_plan = enterprise_crm_http_request_plan_for_readback(
            "not-configured",
            "sync-activities",
            "read-only",
            false,
            false,
            false,
            false,
            false,
            Some("external_crm_sync_run_not_requested"),
        );
        let retry_attempt_readback = enterprise_crm_retry_attempt_readback(
            &retry_policy_readback,
            &http_request_plan,
            0,
            false,
            false,
        );
        let http_executor_boundary = enterprise_crm_http_executor_boundary(
            &http_request_plan,
            Some(&retry_policy_readback),
            Some(&retry_attempt_readback),
        );
        return Ok(json!({
            "source": "enterprise_crm_sync_runs",
            "status": "not-run",
            "would_call": false,
            "http_request_plan": http_request_plan,
            "http_executor_boundary": http_executor_boundary,
            "blocked_reason": "external_crm_sync_run_not_requested",
            "imported_activity_count": 0,
            "updated_count": 0,
            "skipped_count": 0,
            "failed_count": 0,
            "provider_response_parser": provider_response_parser,
            "provider_response_reducer": provider_response_reducer,
            "retry_policy_readback": retry_policy_readback,
            "retry_attempt_readback": retry_attempt_readback,
            "rate_limit_handoff": rate_limit_handoff,
            "readback_path": "GET /admin/enterprise/accounts",
            "write_path": "PATCH /admin/enterprise/accounts",
            "tenant_scoped": true,
            "runtime_implemented": true,
            "network_requests_executed": false,
            "secret_returned": false,
            "authorization_header_returned": false,
            "raw_external_payload_returned": false,
        }));
    };

    let audit_id = admin_row_get::<Uuid>(&row, "audit_id")?;
    enterprise_crm_sync_run_row_readback(&row, None, audit_id)
}

fn enterprise_crm_sync_run_row_readback(
    row: &PgRow,
    imported_activity: Option<Value>,
    audit_id: Uuid,
) -> Result<Value, AdminError> {
    let metadata = admin_row_get::<Value>(row, "metadata").unwrap_or_else(|_| json!({}));
    let adapter_request = metadata
        .get("adapter_request")
        .cloned()
        .unwrap_or_else(|| {
            json!({
                "adapter_kind": admin_row_get::<String>(row, "provider").unwrap_or_else(|_| "not-configured".to_string()),
                "endpoint_ref_present": false,
                "secret_ref_present": false,
                "operation": "sync-activities",
                "direction": admin_row_get::<String>(row, "direction").unwrap_or_else(|_| "read-only".to_string()),
                "external_ids_hash_present": false,
                "external_ids_hash": null,
                "sync_marker_present": admin_row_get::<Option<String>>(row, "sync_marker").ok().flatten().as_deref().is_some_and(|value| !value.trim().is_empty()),
                "sync_marker": admin_row_get::<Option<String>>(row, "sync_marker").ok().flatten(),
            })
        });
    let fallback_refused_reason = admin_row_get::<Option<String>>(row, "refused_reason")?;
    let adapter_result = metadata.get("adapter_result").cloned().unwrap_or_else(|| {
        json!({
            "would_call": fallback_refused_reason.is_none(),
            "blocked_reason": fallback_refused_reason.clone(),
            "imported_count": admin_row_get::<i32>(row, "imported_activity_count").unwrap_or(0),
            "updated_count": 0,
            "skipped_count": 0,
        })
    });
    let provider = admin_row_get::<String>(row, "provider")?;
    let direction = admin_row_get::<String>(row, "direction")?;
    let operation = adapter_request
        .get("operation")
        .and_then(Value::as_str)
        .unwrap_or("sync-activities");
    let endpoint_ref_present = adapter_request
        .get("endpoint_ref_present")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let secret_ref_present = adapter_request
        .get("secret_ref_present")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let external_ids_hash_present = adapter_request
        .get("external_ids_hash_present")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let sync_marker = admin_row_get::<Option<String>>(row, "sync_marker")?;
    let sync_marker_present = sync_marker
        .as_deref()
        .is_some_and(|value| !value.trim().is_empty());
    let blocked_reason = adapter_result
        .get("blocked_reason")
        .and_then(Value::as_str)
        .or(fallback_refused_reason.as_deref());
    let http_request_plan = metadata
        .get("http_request_plan")
        .cloned()
        .unwrap_or_else(|| {
            enterprise_crm_http_request_plan_for_readback(
                &provider,
                operation,
                &direction,
                endpoint_ref_present,
                secret_ref_present,
                external_ids_hash_present,
                sync_marker_present,
                adapter_request
                    .get("imported_activity_summary_present")
                    .and_then(Value::as_bool)
                    .unwrap_or(false),
                blocked_reason,
            )
        });
    let fallback_imported_count = admin_row_get::<i32>(row, "imported_activity_count").unwrap_or(0);
    let fallback_updated_count = adapter_result
        .get("updated_count")
        .and_then(Value::as_i64)
        .and_then(|value| i32::try_from(value).ok())
        .unwrap_or(0);
    let fallback_skipped_count = adapter_result
        .get("skipped_count")
        .and_then(Value::as_i64)
        .and_then(|value| i32::try_from(value).ok())
        .unwrap_or(0);
    let provider_response_parser = metadata
        .get("provider_response_parser")
        .cloned()
        .unwrap_or_else(|| {
            enterprise_crm_provider_response_parser_metadata(
                &provider,
                blocked_reason.is_none(),
                blocked_reason,
                fallback_imported_count,
                fallback_updated_count,
                fallback_skipped_count,
                None,
                None,
            )
        });
    let provider_response_reducer = metadata
        .get("provider_response_reducer")
        .cloned()
        .unwrap_or_else(|| {
            enterprise_crm_provider_response_reducer_metadata(
                &provider,
                blocked_reason.is_none(),
                blocked_reason,
                fallback_imported_count,
                fallback_updated_count,
                fallback_skipped_count,
                &provider_response_parser,
            )
        });
    let retry_policy_readback = metadata
        .get("retry_policy_readback")
        .cloned()
        .unwrap_or_else(|| enterprise_crm_retry_policy_readback(&provider_response_reducer));
    let retry_attempt_readback = metadata
        .get("retry_attempt_readback")
        .cloned()
        .unwrap_or_else(|| {
            enterprise_crm_retry_attempt_readback(
                &retry_policy_readback,
                &http_request_plan,
                0,
                provider_response_reducer
                    .get("input_source")
                    .and_then(Value::as_str)
                    == Some("external_crm_sync_run.provider_response_summary"),
                provider_response_parser
                    .get("input_source")
                    .and_then(Value::as_str)
                    == Some("external_crm_sync_run.provider_response_parser"),
            )
        });
    let rate_limit_handoff = retry_policy_readback
        .get("rate_limit_handoff")
        .cloned()
        .unwrap_or_else(|| json!({}));
    let http_executor_boundary = metadata
        .get("http_executor_boundary")
        .cloned()
        .unwrap_or_else(|| {
            enterprise_crm_http_executor_boundary(
                &http_request_plan,
                Some(&retry_policy_readback),
                Some(&retry_attempt_readback),
            )
        });
    Ok(json!({
        "source": "enterprise_crm_sync_runs",
        "id": admin_row_get::<Uuid>(row, "id")?,
        "tenant_id": admin_row_get::<Uuid>(row, "tenant_id")?,
        "adapter_id": admin_row_get::<Option<Uuid>>(row, "adapter_id")?,
        "adapter_kind": provider,
        "provider": provider,
        "operation": operation,
        "direction": direction,
        "status": admin_row_get::<String>(row, "status")?,
        "started_at": admin_row_get::<String>(row, "started_at")?,
        "completed_at": admin_row_get::<Option<String>>(row, "completed_at")?,
        "imported_activity_count": admin_row_get::<i32>(row, "imported_activity_count")?,
        "updated_count": adapter_result.get("updated_count").cloned().unwrap_or_else(|| json!(0)),
        "skipped_count": adapter_result.get("skipped_count").cloned().unwrap_or_else(|| json!(0)),
        "failed_count": provider_response_reducer.get("failed_count").cloned().unwrap_or_else(|| json!(0)),
        "refused_reason": admin_row_get::<Option<String>>(row, "refused_reason")?,
        "blocked_reason": blocked_reason,
        "would_call": adapter_result.get("would_call").cloned().unwrap_or_else(|| json!(false)),
        "endpoint_ref_present": endpoint_ref_present,
        "secret_ref_present": secret_ref_present,
        "external_ids_hash_present": external_ids_hash_present,
        "external_ids_hash": adapter_request.get("external_ids_hash").cloned().unwrap_or(Value::Null),
        "adapter_request": adapter_request,
        "adapter_result": adapter_result,
        "http_request_plan": http_request_plan,
        "http_executor_boundary": http_executor_boundary,
        "provider_response_parser": provider_response_parser,
        "provider_response_reducer": provider_response_reducer,
        "retry_policy_readback": retry_policy_readback,
        "retry_attempt_readback": retry_attempt_readback,
        "rate_limit_handoff": rate_limit_handoff,
        "sync_marker_present": sync_marker_present,
        "sync_marker": sync_marker,
        "imported_activity": imported_activity,
        "audit_id": audit_id,
        "readback_path": "GET /admin/enterprise/accounts",
        "write_path": "PATCH /admin/enterprise/accounts",
        "tenant_scoped": true,
        "runtime_implemented": true,
        "network_requests_executed": false,
        "secret_returned": false,
        "authorization_header_returned": false,
        "raw_external_payload_returned": false,
    }))
}

async fn insert_enterprise_sales_activity_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    actor_session_id: Uuid,
    audit_id: Uuid,
    activity: &EnterpriseAccountSalesActivityWrite,
) -> Result<Value, AdminError> {
    let row = sqlx::query(
        r#"
        insert into enterprise_sales_activities (
          tenant_id, activity_type, status, summary, owner, next_action, outcome,
          occurred_at, due_at, actor_session_id, audit_id, metadata
        )
        values (
          $1, $2, $3, $4, $5, $6, $7, coalesce($8::timestamptz, now()),
          $9::timestamptz, $10, $11, $12
        )
        returning id, tenant_id, activity_type, status, summary, owner, next_action, outcome,
          occurred_at::text as occurred_at, due_at::text as due_at, created_at::text as created_at
        "#,
    )
    .bind(tenant_id)
    .bind(&activity.activity_type)
    .bind(&activity.status)
    .bind(&activity.summary)
    .bind(&activity.owner)
    .bind(&activity.next_action)
    .bind(&activity.outcome)
    .bind(&activity.occurred_at)
    .bind(&activity.due_at)
    .bind(actor_session_id)
    .bind(audit_id)
    .bind(json!({
        "source": "local_crm_adapter",
        "adapter": "enterprise_sales_activities",
        "external_reference_hash": activity.external_reference_hash,
        "outcome": activity.outcome,
        "owner_marker_present": activity.owner.is_some(),
        "raw_external_payload_stored": false,
        "raw_contact_email_stored": false,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(json!({
        "id": admin_row_get::<Uuid>(&row, "id")?,
        "tenant_id": admin_row_get::<Uuid>(&row, "tenant_id")?,
        "activity_type": admin_row_get::<String>(&row, "activity_type")?,
        "status": admin_row_get::<String>(&row, "status")?,
        "outcome": admin_row_get::<Option<String>>(&row, "outcome")?,
        "summary": admin_row_get::<String>(&row, "summary")?,
        "owner": admin_row_get::<Option<String>>(&row, "owner")?,
        "owner_marker": admin_row_get::<Option<String>>(&row, "owner")?,
        "next_action": admin_row_get::<Option<String>>(&row, "next_action")?,
        "occurred_at": admin_row_get::<String>(&row, "occurred_at")?,
        "due_at": admin_row_get::<Option<String>>(&row, "due_at")?,
        "created_at": admin_row_get::<String>(&row, "created_at")?,
        "audit_id": audit_id,
        "readback_path": "GET /admin/enterprise/accounts",
        "tenant_scoped": true,
        "external_crm_connected": false,
        "raw_contact_email_returned": false,
        "raw_external_payload_returned": false,
    }))
}

