impl PatchEnterpriseAccountRequest {
    fn into_write(self) -> Result<EnterpriseAccountWrite, AdminError> {
        let mut field_names = Vec::new();
        let account_status = match self.account_status {
            Some(value) => {
                field_names.push("account_status");
                Some(normalize_enterprise_account_status(&value)?)
            }
            None => None,
        };
        let account_name = normalize_enterprise_optional_text(
            self.account_name,
            "account_name",
            120,
            &mut field_names,
        )?;
        let account_slug = normalize_enterprise_optional_slug(self.account_slug, &mut field_names)?;
        let account_owner = normalize_enterprise_optional_text(
            self.account_owner,
            "account_owner",
            120,
            &mut field_names,
        )?;
        let admin_contact_email = self
            .admin_contact_email
            .map(|value| {
                field_names.push("admin_contact_email");
                normalize_enterprise_identity_email(&value)
            })
            .transpose()?;
        let account_notes = normalize_enterprise_optional_text(
            self.account_notes,
            "account_notes",
            500,
            &mut field_names,
        )?;
        let plan_tier = match self.plan_tier {
            Some(value) => {
                field_names.push("plan_tier");
                Some(normalize_enterprise_plan_tier(&value)?)
            }
            None => None,
        };
        let sales_stage = match self.sales_stage {
            Some(value) => {
                field_names.push("sales_stage");
                Some(normalize_enterprise_sales_stage(&value)?)
            }
            None => None,
        };
        let sales_activity = match self.sales_activity {
            Some(value) => {
                field_names.push("sales_activity");
                Some(value.into_write()?)
            }
            None => None,
        };
        let external_crm_adapter = match self.external_crm_adapter {
            Some(value) => {
                field_names.push("external_crm_adapter");
                Some(value.into_write()?)
            }
            None => None,
        };
        let external_crm_sync_run = match self.external_crm_sync_run {
            Some(value) => {
                field_names.push("external_crm_sync_run");
                Some(value.into_write()?)
            }
            None => None,
        };
        let seat_limit = normalize_enterprise_optional_positive_i64(
            self.seat_limit,
            "seat_limit",
            1_000_000,
            &mut field_names,
        )?;
        let monthly_token_quota = normalize_enterprise_optional_positive_i64(
            self.monthly_token_quota,
            "monthly_token_quota",
            10_000_000_000_000,
            &mut field_names,
        )?;
        let monthly_spend_quota = normalize_enterprise_optional_decimal(
            self.monthly_spend_quota,
            "monthly_spend_quota",
            &mut field_names,
        )?;

        Ok(EnterpriseAccountWrite {
            account_status,
            account_name,
            account_slug,
            account_owner,
            admin_contact_email,
            account_notes,
            plan_tier,
            sales_stage,
            sales_activity,
            external_crm_adapter,
            external_crm_sync_run,
            seat_limit,
            monthly_token_quota,
            monthly_spend_quota,
            field_names,
        })
    }
}

