impl EnterpriseAccountProvisioningRequest {
    fn into_input(self) -> Result<EnterpriseAccountProvisioningInput, AdminError> {
        let tenant_slug = normalize_enterprise_provisioning_slug(&self.tenant_slug, "tenant_slug")?;
        let mut fields = Vec::new();
        let tenant_name = normalize_enterprise_optional_text(
            Some(self.tenant_name),
            "tenant_name",
            120,
            &mut fields,
        )?
        .expect("tenant_name is required");
        let workspace_name = normalize_enterprise_optional_text(
            Some(self.workspace_name),
            "workspace_name",
            120,
            &mut fields,
        )?
        .expect("workspace_name is required");
        let owner_contact_email = self
            .owner_contact_email
            .map(|value| normalize_enterprise_identity_email(&value))
            .transpose()?;
        let admin_contact_email = normalize_enterprise_identity_email(&self.admin_contact_email)?;
        let sales_stage = normalize_enterprise_sales_stage(&self.sales_stage)?;
        let plan_tier = normalize_enterprise_plan_tier(&self.plan_tier)?;
        let idempotency_key =
            normalize_enterprise_provisioning_idempotency_key(&self.idempotency_key)?;

        Ok(EnterpriseAccountProvisioningInput {
            tenant_slug,
            tenant_name,
            workspace_name,
            owner_contact_email,
            admin_contact_email,
            sales_stage,
            plan_tier,
            idempotency_key,
        })
    }
}

impl EnterpriseInviteDeliveryRequest {
    fn into_input(self) -> Result<EnterpriseInviteDeliveryInput, AdminError> {
        if self.tenant_id.is_none() && self.tenant_slug.is_none() {
            return Err(AdminError::bad_request(
                "tenant_id or tenant_slug is required for invite delivery planning",
            ));
        }
        let tenant_slug = self
            .tenant_slug
            .map(|value| normalize_enterprise_provisioning_slug(&value, "tenant_slug"))
            .transpose()?;
        let mut fields = Vec::new();
        let workspace_name = normalize_enterprise_optional_text(
            self.workspace_name,
            "workspace_name",
            120,
            &mut fields,
        )?;
        let target_user_email = self
            .target_user_email
            .map(|value| normalize_enterprise_identity_email(&value))
            .transpose()?;
        let delivery_request_id = match (self.idempotency_key, self.delivery_request_id) {
            (Some(value), _) => normalize_enterprise_provisioning_idempotency_key(&value)?,
            (None, Some(value)) => normalize_enterprise_provisioning_idempotency_key(&value)?,
            (None, None) => {
                return Err(AdminError::bad_request(
                    "idempotency_key or delivery_request_id is required",
                ));
            }
        };

        Ok(EnterpriseInviteDeliveryInput {
            tenant_id: self.tenant_id,
            tenant_slug,
            workspace_id: self.workspace_id,
            workspace_name,
            target_user_id: self.target_user_id,
            target_user_email,
            delivery_request_id,
        })
    }
}

impl EnterpriseAccountSalesActivityRequest {
    fn into_write(self) -> Result<EnterpriseAccountSalesActivityWrite, AdminError> {
        let activity_type = normalize_enterprise_sales_activity_type(&self.activity_type)?;
        let status = normalize_enterprise_sales_activity_status(self.status.as_deref())?;
        let outcome = normalize_enterprise_sales_activity_outcome(self.outcome.as_deref())?;
        let mut nested_fields = Vec::new();
        let summary = normalize_enterprise_optional_text(
            Some(self.summary),
            "sales_activity.summary",
            800,
            &mut nested_fields,
        )?
        .expect("summary is required");
        let owner = normalize_enterprise_optional_text(
            self.owner,
            "sales_activity.owner",
            120,
            &mut nested_fields,
        )?;
        let next_action = normalize_enterprise_optional_text(
            self.next_action,
            "sales_activity.next_action",
            240,
            &mut nested_fields,
        )?;
        let occurred_at = normalize_enterprise_optional_timestamp(
            self.occurred_at,
            "sales_activity.occurred_at",
        )?;
        let due_at = normalize_enterprise_optional_timestamp(self.due_at, "sales_activity.due_at")?;
        let external_reference_hash = normalize_enterprise_optional_reference_hash(
            self.external_reference_hash,
            "sales_activity.external_reference_hash",
        )?;
        for (field, value) in [
            ("sales_activity.summary", summary.as_str()),
            ("sales_activity.owner", owner.as_deref().unwrap_or("")),
            (
                "sales_activity.next_action",
                next_action.as_deref().unwrap_or(""),
            ),
        ] {
            reject_enterprise_raw_contact_email(field, value)?;
        }

        Ok(EnterpriseAccountSalesActivityWrite {
            activity_type,
            status,
            outcome,
            summary,
            owner,
            next_action,
            occurred_at,
            due_at,
            external_reference_hash,
        })
    }
}

