impl EnterpriseExternalCrmSyncRunRequest {
    fn into_write(self) -> Result<EnterpriseExternalCrmSyncRunWrite, AdminError> {
        let retry_attempt_mode =
            normalize_enterprise_crm_retry_attempt_mode(self.retry_attempt_mode.as_deref())?;
        let operator_reason = normalize_enterprise_optional_retry_operator_reason(
            self.operator_reason,
            "external_crm_sync_run.operator_reason",
        )?;
        let operation = normalize_enterprise_external_crm_operation(self.operation.as_deref())?;
        let direction =
            normalize_enterprise_external_crm_sync_direction(self.direction.as_deref())?;
        let external_ids_hash = normalize_enterprise_optional_reference_hash(
            self.external_ids_hash,
            "external_crm_sync_run.external_ids_hash",
        )?;
        let sync_marker = normalize_enterprise_optional_reference_hash(
            self.sync_marker,
            "external_crm_sync_run.sync_marker",
        )?;
        let updated_count = normalize_enterprise_optional_nonnegative_i32(
            self.updated_count,
            "external_crm_sync_run.updated_count",
            1_000_000,
        )?
        .unwrap_or(0);
        let skipped_count = normalize_enterprise_optional_nonnegative_i32(
            self.skipped_count,
            "external_crm_sync_run.skipped_count",
            1_000_000,
        )?
        .unwrap_or(0);
        let imported_activity_summary = self
            .imported_activity_summary
            .map(EnterpriseAccountSalesActivityRequest::into_write)
            .transpose()?;
        let provider_response_summary = self
            .provider_response_summary
            .map(EnterpriseCrmProviderResponseSummaryRequest::into_write)
            .transpose()?;
        let provider_response_parser = self
            .provider_response_parser
            .map(EnterpriseCrmProviderResponseParserRequest::into_write)
            .transpose()?;

        Ok(EnterpriseExternalCrmSyncRunWrite {
            retry_attempt_mode,
            operator_reason,
            operation,
            direction,
            external_ids_hash,
            sync_marker,
            updated_count,
            skipped_count,
            imported_activity_summary,
            provider_response_summary,
            provider_response_parser,
        })
    }
}

