impl EnterpriseAccountWrite {
    fn metadata_patch(&self) -> Value {
        let mut object = serde_json::Map::new();
        if let Some(value) = &self.account_status {
            object.insert("enterprise_account_status".to_string(), json!(value));
        }
        if let Some(value) = &self.account_name {
            object.insert("account_name".to_string(), json!(value));
        }
        if let Some(value) = &self.account_slug {
            object.insert("account_slug".to_string(), json!(value));
        }
        if let Some(value) = &self.account_owner {
            object.insert("account_owner".to_string(), json!(value));
        }
        if let Some(value) = &self.admin_contact_email {
            object.insert("admin_contact_email".to_string(), json!(value));
        }
        if let Some(value) = &self.account_notes {
            object.insert("account_notes".to_string(), json!(value));
        }
        if let Some(value) = &self.plan_tier {
            object.insert("enterprise_plan_tier".to_string(), json!(value));
        }
        if let Some(value) = &self.sales_stage {
            object.insert("enterprise_sales_stage".to_string(), json!(value));
        }
        if let Some(value) = self.seat_limit {
            object.insert("seat_limit".to_string(), json!(value.to_string()));
        }
        if let Some(value) = self.monthly_token_quota {
            object.insert("monthly_token_quota".to_string(), json!(value.to_string()));
        }
        if let Some(value) = &self.monthly_spend_quota {
            object.insert("monthly_spend_quota".to_string(), json!(value));
        }
        Value::Object(object)
    }
}

