fn reject_enterprise_secret_like_text(field: &str, value: &str) -> Result<(), AdminError> {
    let lower = value.to_ascii_lowercase();
    let forbidden = [
        "authorization",
        "bearer ",
        "access_token",
        "refresh_token",
        "id_token",
        "client_secret",
        "samlresponse",
        "assertion",
        "provider_payload",
        "provider_key",
        "api_key",
        "secret",
        "token=",
    ];
    if forbidden.iter().any(|marker| lower.contains(marker)) {
        return Err(AdminError::bad_request(format!(
            "{field} must not contain tokens, assertions, secrets, provider payloads, or authorization material"
        )));
    }
    Ok(())
}

fn reject_enterprise_raw_contact_email(field: &str, value: &str) -> Result<(), AdminError> {
    if value.trim().is_empty() {
        return Ok(());
    }
    let contains_email = value
        .split(|ch: char| ch.is_whitespace() || matches!(ch, '<' | '>' | ',' | ';' | '"' | '\''))
        .any(|part| {
            let trimmed =
                part.trim_matches(|ch: char| matches!(ch, '.' | ':' | ')' | '(' | '[' | ']'));
            let Some((local, domain)) = trimmed.split_once('@') else {
                return false;
            };
            !local.is_empty()
                && domain.contains('.')
                && domain
                    .chars()
                    .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '.' | '-'))
        });
    if contains_email {
        return Err(AdminError::bad_request(format!(
            "{field} must not contain raw contact email; use a safe owner marker or contact summary"
        )));
    }
    Ok(())
}

