fn enterprise_external_crm_adapter_blocked_reason(
    provider: &str,
    status: &str,
    secret_ref_present: bool,
    endpoint_ref_present: bool,
) -> Option<&'static str> {
    if status != "enabled" {
        Some("external_crm_adapter_disabled")
    } else if !secret_ref_present {
        Some("external_crm_secret_ref_missing")
    } else if !endpoint_ref_present {
        Some("external_crm_endpoint_ref_missing")
    } else if provider == "custom-http" {
        Some("external_crm_adapter_unsupported")
    } else {
        None
    }
}

