fn enterprise_sales_stage(metadata_stage: Option<&str>) -> &'static str {
    let configured = metadata_stage
        .filter(|value| !value.trim().is_empty())
        .map(str::to_string)
        .unwrap_or_else(|| env_trimmed("AI_GATEWAY_ENTERPRISE_SALES_STAGE"));
    match configured.to_ascii_lowercase().replace('_', "-").as_str() {
        "lead" => "lead",
        "qualified" => "qualified",
        "trial" => "trial",
        "negotiation" => "negotiation",
        "customer" => "customer",
        "churn-risk" => "churn-risk",
        _ => "not-connected",
    }
}

fn enterprise_sales_next_step(stage: &str) -> &'static str {
    match stage {
        "not-connected" => {
            "Set AI_GATEWAY_ENTERPRISE_SALES_STAGE when an operator wants to pin this account in a sales workflow."
        }
        "lead" | "qualified" => {
            "Collect owner, plan, seat, SSO, billing, and quota readiness before moving to trial."
        }
        "trial" => {
            "Review SSO readiness, active seats, API usage, and billing readiness before conversion."
        }
        "negotiation" => {
            "Confirm plan, billing readiness, seat limit, and quota assumptions before marking customer."
        }
        "customer" => "Monitor usage, SSO validation, billing readiness, and quota headroom.",
        "churn-risk" => "Review recent usage, failures, billing state, and next operator action.",
        _ => "Review the account readback and choose the next sales workflow step.",
    }
}

fn enterprise_dashboard_provisioning_blockers(
    tenant_status: &str,
    active_workspace_count: i64,
    plan_tier: &str,
    admin_contact_present: bool,
) -> Vec<&'static str> {
    let mut blockers = Vec::new();
    if tenant_status != "active" {
        blockers.push("tenant_not_active");
    }
    if active_workspace_count == 0 {
        blockers.push("workspace_missing");
    }
    if plan_tier == "not-configured" {
        blockers.push("plan_tier_missing");
    }
    if !admin_contact_present {
        blockers.push("admin_contact_missing");
    }
    blockers
}

fn enterprise_dashboard_invite_blockers(
    tenant_status: &str,
    active_workspace_count: i64,
    invited_user_count: i64,
) -> Vec<&'static str> {
    let mut blockers = Vec::new();
    if tenant_status != "active" {
        blockers.push("tenant_not_active");
    }
    if active_workspace_count == 0 {
        blockers.push("workspace_missing");
    }
    if invited_user_count == 0 {
        blockers.push("no_invited_users");
    }
    blockers
}

fn enterprise_dashboard_crm_blockers(
    adapter_status: &str,
    secret_ref_present: bool,
    sync_status: &str,
    refused_reason: Option<&str>,
) -> Vec<String> {
    let mut blockers = Vec::new();
    if adapter_status != "enabled" {
        blockers.push("external_crm_adapter_not_enabled".to_string());
    }
    if adapter_status == "enabled" && !secret_ref_present {
        blockers.push("external_crm_secret_ref_missing".to_string());
    }
    if sync_status == "not-run" {
        blockers.push("external_crm_sync_run_not_requested".to_string());
    }
    if sync_status == "refused" {
        blockers.push(
            refused_reason
                .filter(|value| !value.trim().is_empty())
                .unwrap_or("external_crm_sync_run_refused")
                .to_string(),
        );
    }
    blockers
}

fn enterprise_dashboard_next_action_for_reason(reason: &str) -> &'static str {
    match reason {
        "tenant_not_active" => {
            "Review or reactivate the tenant before provisioning or invite delivery."
        }
        "workspace_missing" => "Create or link a tenant workspace before provisioning users.",
        "plan_tier_missing" => "Set enterprise_plan_tier before sales handoff.",
        "admin_contact_missing" => {
            "Add an admin contact; dashboard readback will keep raw contact hidden."
        }
        "no_invited_users" => "Plan invite delivery after a target user exists.",
        "external_crm_adapter_not_enabled" => {
            "Configure or enable the CRM adapter when CRM sync readback is required."
        }
        "external_crm_secret_ref_missing" => {
            "Attach a CRM secret reference; do not store or return the secret value."
        }
        "external_crm_sync_run_not_requested" => {
            "Request a bounded CRM sync marker through PATCH /admin/enterprise/accounts when ready."
        }
        _ => "Review the account blocker and run the matching plan/readback endpoint.",
    }
}

fn bump_count(counts: &mut BTreeMap<String, i64>, key: &str) {
    *counts.entry(key.to_string()).or_insert(0) += 1;
}

fn bump_nested_count(
    counts: &mut BTreeMap<String, BTreeMap<String, i64>>,
    key: &str,
    subkey: &str,
) {
    *counts
        .entry(key.to_string())
        .or_default()
        .entry(subkey.to_string())
        .or_insert(0) += 1;
}

fn enterprise_sso_readiness_status(oidc_status: &str, saml_status: &str) -> &'static str {
    if oidc_status == "validation-pending" || saml_status == "validation-pending" {
        "validation-pending"
    } else if oidc_status == "config-needed" || saml_status == "config-needed" {
        "config-needed"
    } else {
        "disabled"
    }
}

fn enterprise_sso_next_step(status: &str) -> &'static str {
    match status {
        "validation-pending" => {
            "Implement real OIDC token/JWKS or SAML assertion/signature validation before enabling SSO login."
        }
        "config-needed" => {
            "Complete enterprise identity metadata and role/group mapping configuration."
        }
        _ => "Enable OIDC or SAML configuration before offering enterprise SSO.",
    }
}

fn enterprise_billing_readiness_status(
    active_wallet_count: i64,
    active_subscription_count: i64,
    invoice_count: i64,
    receipt_count: i64,
) -> &'static str {
    if active_wallet_count == 0 {
        "config-needed"
    } else if active_subscription_count == 0 {
        "plan-needed"
    } else if invoice_count == 0 || receipt_count == 0 {
        "runtime-records-pending"
    } else {
        "local-readback-ready"
    }
}

fn enterprise_billing_next_step(status: &str) -> &'static str {
    match status {
        "config-needed" => {
            "Create or seed an active tenant wallet before treating billing as ready."
        }
        "plan-needed" => {
            "Attach an active subscription plan to the tenant/project for account readback."
        }
        "runtime-records-pending" => {
            "Run local payment/invoice demo or connect a real provider adapter later; merchant integration remains pending."
        }
        _ => {
            "Use this as local billing readback only; real merchant callback, capture, refund, and scheduler stay behind the provider adapter."
        }
    }
}

fn enterprise_plan_status(active_subscription_count: i64, plan_present: bool) -> &'static str {
    if active_subscription_count > 0 {
        "active"
    } else if plan_present {
        "pending"
    } else {
        "not-configured"
    }
}

fn enterprise_account_lifecycle_status(
    metadata_status: Option<&str>,
    tenant_status: &str,
) -> &'static str {
    let configured = metadata_status
        .filter(|value| !value.trim().is_empty())
        .map(str::to_string)
        .unwrap_or_else(|| tenant_status.to_string());
    match configured.to_ascii_lowercase().replace('_', "-").as_str() {
        "prospect" => "prospect",
        "onboarding" => "onboarding",
        "trial" => "trial",
        "active" => "active",
        "suspended" => "suspended",
        "churn-risk" => "churn-risk",
        "closed" | "deleted" => "closed",
        _ => "active",
    }
}

fn enterprise_plan_tier(metadata_tier: Option<&str>, plan_code: Option<&str>) -> &'static str {
    let configured = metadata_tier
        .filter(|value| !value.trim().is_empty())
        .or(plan_code)
        .unwrap_or_default()
        .to_ascii_lowercase()
        .replace('_', "-");
    if configured.contains("enterprise") {
        "enterprise"
    } else if configured.contains("business") {
        "business"
    } else if configured.contains("team") {
        "team"
    } else if configured.contains("free") || configured.contains("starter") {
        "starter"
    } else if configured.contains("custom") {
        "custom"
    } else {
        "not-configured"
    }
}

fn enterprise_quota_status(
    total_tokens_30d: i64,
    monthly_token_quota: Option<i64>,
) -> &'static str {
    match monthly_token_quota {
        Some(limit) if total_tokens_30d >= limit => "exhausted",
        Some(limit) if total_tokens_30d >= (limit * 8 / 10) => "attention",
        Some(_) => "ready",
        None => "config-needed",
    }
}

fn enterprise_account_overall_status(
    sso_status: &str,
    billing_status: &str,
    quota_status: &str,
) -> &'static str {
    if billing_status == "config-needed" || quota_status == "exhausted" {
        "attention"
    } else if sso_status == "validation-pending"
        && matches!(
            billing_status,
            "local-readback-ready" | "runtime-records-pending"
        )
    {
        "trial-ready"
    } else if billing_status == "local-readback-ready" && quota_status == "ready" {
        "customer-ready"
    } else {
        "config-needed"
    }
}

fn enterprise_account_next_step(
    sales_stage: &str,
    sso_status: &str,
    billing_status: &str,
    quota_status: &str,
) -> &'static str {
    if sales_stage == "not-connected" {
        return "Pin the sales stage via AI_GATEWAY_ENTERPRISE_SALES_STAGE or connect a future CRM adapter; current response is local account readback.";
    }
    if sso_status != "validation-pending" {
        return enterprise_sso_next_step(sso_status);
    }
    if billing_status != "local-readback-ready" {
        return enterprise_billing_next_step(billing_status);
    }
    if quota_status == "config-needed" {
        return "Set tenant monthly_token_quota metadata or keep quota as an operator follow-up before using this as a sales backend card.";
    }
    "Use this contract for the sales backend account card; real CRM and enterprise SSO validation remain later adapters."
}

fn optional_positive_i64(value: Option<String>) -> Option<i64> {
    value
        .and_then(|value| value.trim().parse::<i64>().ok())
        .filter(|value| *value > 0)
}

fn optional_positive_decimal(value: Option<String>) -> Option<String> {
    value.and_then(|value| {
        let trimmed = value.trim();
        match trimmed.parse::<f64>() {
            Ok(parsed) if parsed > 0.0 => Some(trimmed.to_string()),
            _ => None,
        }
    })
}

fn enterprise_contact_safe_summary(value: Option<&str>) -> Value {
    let Some(value) = value.map(str::trim).filter(|value| !value.is_empty()) else {
        return json!({
            "present": false,
            "sha256": null,
            "hash_prefix": null,
            "email_domain": null,
            "raw_returned": false,
        });
    };
    let normalized = value.to_ascii_lowercase();
    let hash = sha256_hex(&format!("enterprise-account-contact:v1:{normalized}"));
    let email_domain = normalized
        .rsplit_once('@')
        .map(|(_, domain)| domain.to_string())
        .filter(|domain| !domain.is_empty());
    json!({
        "present": true,
        "sha256": hash,
        "hash_prefix": subscription_scheduler_public_fingerprint(&hash),
        "email_domain": email_domain,
        "raw_returned": false,
    })
}

