fn admin_row_get<T>(row: &PgRow, column: &str) -> Result<T, AdminError>
where
    for<'r> T: sqlx::Decode<'r, Postgres> + sqlx::Type<Postgres>,
{
    row.try_get(column)
        .map_err(|error| AdminError::from(DbError::Query(error)))
}

fn enterprise_identity_connection_status(provider_type: &str) -> &'static str {
    if !enterprise_identity_enabled(provider_type) {
        return "disabled";
    }
    if enterprise_identity_config_needed(provider_type).is_empty() {
        "validation-pending"
    } else {
        "config-needed"
    }
}

fn enterprise_identity_enabled(provider_type: &str) -> bool {
    truthy_env(&enterprise_identity_env(provider_type, "ENABLED"))
}

fn enterprise_identity_metadata_url_present(provider_type: &str) -> bool {
    !env_trimmed(&enterprise_identity_env(provider_type, "METADATA_URL")).is_empty()
        || !env_trimmed(&enterprise_identity_env(provider_type, "JWKS_URI")).is_empty()
        || !env_trimmed(&enterprise_identity_env(
            provider_type,
            "AUTHORIZATION_ENDPOINT",
        ))
        .is_empty()
}

fn enterprise_identity_config_needed(provider_type: &str) -> Vec<&'static str> {
    if !enterprise_identity_enabled(provider_type) {
        return vec!["provider_disabled"];
    }

    let mut missing = Vec::new();
    match provider_type {
        "oidc" => {
            push_missing_env(
                &mut missing,
                "AI_GATEWAY_OIDC_ISSUER",
                &enterprise_identity_env(provider_type, "ISSUER"),
            );
            push_missing_env(
                &mut missing,
                "AI_GATEWAY_OIDC_CLIENT_ID",
                &enterprise_identity_env(provider_type, "CLIENT_ID"),
            );
            push_missing_env(
                &mut missing,
                "AI_GATEWAY_OIDC_AUTHORIZATION_ENDPOINT",
                &enterprise_identity_env(provider_type, "AUTHORIZATION_ENDPOINT"),
            );
            push_missing_env(
                &mut missing,
                "AI_GATEWAY_OIDC_TOKEN_ENDPOINT",
                &enterprise_identity_env(provider_type, "TOKEN_ENDPOINT"),
            );
            push_missing_env(
                &mut missing,
                "AI_GATEWAY_OIDC_JWKS_URI",
                &enterprise_identity_env(provider_type, "JWKS_URI"),
            );
        }
        "saml" => {
            push_missing_env(
                &mut missing,
                "AI_GATEWAY_SAML_ENTITY_ID",
                &enterprise_identity_env(provider_type, "ENTITY_ID"),
            );
            push_missing_env(
                &mut missing,
                "AI_GATEWAY_SAML_METADATA_URL",
                &enterprise_identity_env(provider_type, "METADATA_URL"),
            );
            push_missing_env(
                &mut missing,
                "AI_GATEWAY_SAML_ACS_URL",
                &enterprise_identity_env(provider_type, "ACS_URL"),
            );
        }
        _ => missing.push("unknown_provider_type"),
    }

    if enterprise_identity_mapping_summary(provider_type, "ROLE_MAPPING")["configured"]
        != json!(true)
        && enterprise_identity_mapping_summary(provider_type, "GROUP_MAPPING")["configured"]
            != json!(true)
    {
        missing.push("role_or_group_mapping");
    }

    missing
}

fn push_missing_env(missing: &mut Vec<&'static str>, label: &'static str, value: &str) {
    if value.trim().is_empty() {
        missing.push(label);
    }
}

fn enterprise_identity_mapping_summary(provider_type: &str, suffix: &str) -> Value {
    let value = env_trimmed(&enterprise_identity_env(provider_type, suffix));
    let count = value
        .split(',')
        .map(str::trim)
        .filter(|entry| !entry.is_empty())
        .count();

    json!({
        "configured": count > 0,
        "entry_count": count,
        "values_returned": false
    })
}

fn enterprise_identity_env(provider_type: &str, suffix: &str) -> String {
    format!(
        "AI_GATEWAY_{}_{}",
        provider_type.to_ascii_uppercase(),
        suffix
    )
}

fn env_trimmed(key: &str) -> String {
    std::env::var(key).unwrap_or_default().trim().to_string()
}

fn truthy_env(key: &str) -> bool {
    matches!(
        env_trimmed(key).to_ascii_lowercase().as_str(),
        "1" | "true" | "yes" | "on"
    )
}

async fn get_production_read_model_status(
    State(state): State<Arc<ControlPlaneState>>,
) -> Result<Response, AdminError> {
    let postgres = read_postgres_request_log_model_status(state.db()).await?;
    let clickhouse = secret_safe_clickhouse_read_model_config_status();
    let tokenizer = tokenizer_read_model_status(
        postgres.tokenized_request_count,
        postgres.request_count,
        tokenizer_config_presence_from_env(),
    );
    let backend = production_read_model_backend(&clickhouse);
    let status = production_read_model_status(&backend, &tokenizer, &postgres);
    let next_step = production_read_model_next_step(&backend, &tokenizer, &postgres);
    let smoke_plan = production_read_model_smoke_plan(&backend, &clickhouse, &tokenizer, &postgres);
    let lag_explainability = production_read_model_lag_explainability(
        &backend,
        &clickhouse,
        &tokenizer,
        &postgres,
        &smoke_plan,
        next_step,
    );

    Ok(Json(json!({
        "data": {
            "schema": "admin_production_read_model_status.v1",
            "secret_safe": true,
            "source": "control_plane_config_and_postgres_readback",
            "tenant_id": DEFAULT_TENANT_ID,
            "status": status,
            "backend": backend,
            "postgres": {
                "status": postgres.status,
                "request_count": postgres.request_count,
                "tokenized_request_count": postgres.tokenized_request_count,
                "latest_request_created_at": postgres.latest_request_created_at,
                "latest_completed_at": postgres.latest_completed_at,
                "lag_seconds": postgres.lag_seconds,
                "staleness": postgres.staleness,
                "readback": "request_logs_safe_summary",
                "raw_payload_returned": false
            },
            "clickhouse": clickhouse,
            "tokenizer_status": tokenizer,
            "lag": {
                "source": "postgres_request_logs",
                "latest_request_created_at": postgres.latest_request_created_at,
                "lag_seconds": postgres.lag_seconds,
                "staleness": postgres.staleness
            },
            "contract": {
                "admin_path": "GET /admin/production/read-model/status",
                "frontend_contract": "AdminProductionReadModelStatus",
                "smoke_plan_contract": "admin_production_read_model_smoke_plan.v1",
                "lag_explainability_contract": "admin_production_read_model_lag_explainability.v1",
                "clickhouse_contract": CLICKHOUSE_LOG_STORE_CONTRACT_VERSION,
                "network_requests": false,
                "clickhouse_connected": false,
                "db_url_returned": false,
                "credentials_returned": false,
                "authorization_returned": false,
                "raw_query_returned": false,
                "raw_sql_returned": false,
                "raw_payload_returned": false
            },
            "smoke_plan": smoke_plan,
            "read_model_lag_explainability": lag_explainability,
            "next_step": next_step,
            "omitted_fields": [
                "database_url",
                "clickhouse_endpoint",
                "clickhouse_username",
                "clickhouse_password",
                "clickhouse_token",
                "authorization",
                "raw_request_payload",
                "raw_response_payload",
                "raw_query",
                "raw_sql"
            ]
        }
    }))
    .into_response())
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct PostgresReadModelStatus {
    status: &'static str,
    request_count: i64,
    tokenized_request_count: i64,
    latest_request_created_at: Option<String>,
    latest_completed_at: Option<String>,
    lag_seconds: Option<i64>,
    staleness: &'static str,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct TokenizerConfigPresence {
    backend: bool,
    model: bool,
    config_path: bool,
}

async fn read_postgres_request_log_model_status(
    pool: &PgPool,
) -> Result<PostgresReadModelStatus, AdminError> {
    let row = sqlx::query(
        r#"
select
  count(*)::bigint as request_count,
  coalesce(sum(
    case
      when input_tokens > 0
        or output_tokens > 0
        or cache_read_tokens > 0
        or cache_write_tokens > 0
        or reasoning_tokens > 0
      then 1 else 0
    end
  ), 0)::bigint as tokenized_request_count,
  to_char(max(created_at) at time zone 'utc', 'YYYY-MM-DD"T"HH24:MI:SS"Z"') as latest_request_created_at,
  to_char(max(completed_at) at time zone 'utc', 'YYYY-MM-DD"T"HH24:MI:SS"Z"') as latest_completed_at,
  case
    when max(created_at) is null then null
    else greatest(0::numeric, floor(extract(epoch from (now() - max(created_at)))))::bigint
  end as lag_seconds
from request_logs
where tenant_id = $1
"#,
    )
    .bind(DEFAULT_TENANT_ID)
    .fetch_one(pool)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let request_count = row
        .try_get::<i64, _>("request_count")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let tokenized_request_count = row
        .try_get::<i64, _>("tokenized_request_count")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let latest_request_created_at = row
        .try_get::<Option<String>, _>("latest_request_created_at")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let latest_completed_at = row
        .try_get::<Option<String>, _>("latest_completed_at")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let lag_seconds = row
        .try_get::<Option<i64>, _>("lag_seconds")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(PostgresReadModelStatus {
        status: if request_count > 0 { "ready" } else { "empty" },
        request_count,
        tokenized_request_count,
        latest_request_created_at,
        latest_completed_at,
        lag_seconds,
        staleness: read_model_staleness(lag_seconds),
    })
}

fn secret_safe_clickhouse_read_model_config_status() -> Value {
    match ClickHouseLogStoreConfig::from_env() {
        Ok(config) if config.is_enabled() => {
            let contract = config.write_plan().to_contract_json();
            json!({
                "status": "configured",
                "enabled": true,
                "contract": CLICKHOUSE_LOG_STORE_CONTRACT_VERSION,
                "endpoint_configured": config.endpoint().is_some(),
                "database": contract.get("database").cloned().unwrap_or(Value::Null),
                "table": contract.get("table").cloned().unwrap_or(Value::Null),
                "credentials": contract.get("credentials").cloned().unwrap_or(Value::Null),
                "tls": contract.get("tls").cloned().unwrap_or(Value::Null),
                "sinks": contract.get("sinks").cloned().unwrap_or(Value::Null),
                "wal_service_guard": contract.get("wal_service_guard").cloned().unwrap_or(Value::Null),
                "connectivity_check_enabled": false,
                "network_requests": false,
                "endpoint_returned": false
            })
        }
        Ok(_) => json!({
            "status": "disabled",
            "enabled": false,
            "contract": CLICKHOUSE_LOG_STORE_CONTRACT_VERSION,
            "endpoint_configured": false,
            "connectivity_check_enabled": false,
            "network_requests": false,
            "endpoint_returned": false
        }),
        Err(_) => json!({
            "status": "config-needed",
            "enabled": false,
            "contract": CLICKHOUSE_LOG_STORE_CONTRACT_VERSION,
            "endpoint_configured": false,
            "config_error": "invalid_or_incomplete_clickhouse_log_store_config",
            "connectivity_check_enabled": false,
            "network_requests": false,
            "endpoint_returned": false
        }),
    }
}

fn tokenizer_config_presence_from_env() -> TokenizerConfigPresence {
    TokenizerConfigPresence {
        backend: env_var_present("AI_GATEWAY_TOKENIZER_BACKEND"),
        model: env_var_present("AI_GATEWAY_TOKENIZER_MODEL"),
        config_path: env_var_present("AI_GATEWAY_TOKENIZER_CONFIG"),
    }
}

fn env_var_present(name: &str) -> bool {
    std::env::var(name)
        .map(|value| !value.trim().is_empty())
        .unwrap_or(false)
}

fn tokenizer_read_model_status(
    tokenized_request_count: i64,
    request_count: i64,
    config: TokenizerConfigPresence,
) -> Value {
    let configured = config.backend || config.model || config.config_path;
    let status = if configured {
        "configured"
    } else if tokenized_request_count > 0 {
        "provider-usage-readback"
    } else if request_count > 0 {
        "config-needed"
    } else {
        "no-signal"
    };
    let next_step = match status {
        "configured" => {
            "Use request log token columns for read-model smoke; standalone tokenizer values remain secret-safe and presence-only."
        }
        "provider-usage-readback" => {
            "Provider usage token columns are present; add explicit tokenizer config only if offline estimation is required."
        }
        "config-needed" => {
            "Configure AI_GATEWAY_TOKENIZER_BACKEND or AI_GATEWAY_TOKENIZER_MODEL if production smoke requires offline token estimation."
        }
        _ => {
            "Run a local gateway request or configure tokenizer backend before production read-model smoke."
        }
    };

    json!({
        "status": status,
        "configured": configured,
        "backend_configured": config.backend,
        "model_configured": config.model,
        "config_path_configured": config.config_path,
        "tokenized_request_count": tokenized_request_count,
        "raw_tokenizer_config_returned": false,
        "next_step": next_step
    })
}

fn production_read_model_backend(clickhouse: &Value) -> &'static str {
    match clickhouse.get("status").and_then(Value::as_str) {
        Some("configured") => "clickhouse",
        Some("config-needed") => "config-needed",
        _ => "postgres",
    }
}

fn production_read_model_status(
    backend: &str,
    tokenizer: &Value,
    postgres: &PostgresReadModelStatus,
) -> &'static str {
    if backend == "config-needed" {
        return "config-needed";
    }
    if tokenizer.get("status").and_then(Value::as_str) == Some("config-needed") {
        return "attention";
    }
    if postgres.request_count == 0 {
        return "no-signal";
    }
    "ready"
}

fn production_read_model_next_step(
    backend: &str,
    tokenizer: &Value,
    postgres: &PostgresReadModelStatus,
) -> &'static str {
    if backend == "config-needed" {
        "Fix ClickHouse log store config or disable the ClickHouse backend to use Postgres readback."
    } else if tokenizer.get("status").and_then(Value::as_str) == Some("config-needed") {
        "Configure tokenizer backend/model or rely on provider usage token readback for this smoke."
    } else if postgres.request_count == 0 {
        "Run a gateway request, then read this endpoint again to confirm lag and tokenizer readback."
    } else if backend == "clickhouse" {
        "ClickHouse config is present; live ClickHouse connectivity remains an explicit operator smoke outside this endpoint."
    } else {
        "Postgres read-model readback is available; configure ClickHouse only when production log-store smoke is needed."
    }
}

fn production_read_model_smoke_plan(
    backend: &str,
    clickhouse: &Value,
    tokenizer: &Value,
    postgres: &PostgresReadModelStatus,
) -> Value {
    let clickhouse_configured =
        clickhouse.get("status").and_then(Value::as_str) == Some("configured");
    let tokenizer_configured = tokenizer
        .get("configured")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let has_postgres_signal = postgres.request_count > 0;
    let status = if backend == "config-needed" {
        "blocked"
    } else if clickhouse_configured
        && (tokenizer_configured || postgres.tokenized_request_count > 0)
    {
        "ready-for-operator-smoke"
    } else if has_postgres_signal {
        "readback-ready"
    } else {
        "config-needed"
    };
    let next_step = match status {
        "ready-for-operator-smoke" => {
            "Operator can run a bounded ClickHouse/tokenizer smoke outside this endpoint, then compare request-log readback fields here."
        }
        "readback-ready" => {
            "Use Postgres request-log readback now; configure ClickHouse and tokenizer presence before operator smoke."
        }
        "blocked" => {
            "Fix ClickHouse config presence or disable ClickHouse log store before using this smoke plan."
        }
        _ => {
            "Run a local gateway request and configure ClickHouse/tokenizer presence before operator smoke."
        }
    };

    json!({
        "schema": "admin_production_read_model_smoke_plan.v1",
        "status": status,
        "backend": backend,
        "secret_safe": true,
        "operator_action_required": status != "readback-ready",
        "network_requests": false,
        "clickhouse_connected": false,
        "required_config_presence": {
            "clickhouse_log_store_enabled": clickhouse.get("enabled").cloned().unwrap_or(json!(false)),
            "clickhouse_endpoint_configured": clickhouse.get("endpoint_configured").cloned().unwrap_or(json!(false)),
            "clickhouse_secret_presence": clickhouse.get("credentials").cloned().unwrap_or(json!({
                "redaction": "presence_only"
            })),
            "tokenizer_backend_configured": tokenizer.get("backend_configured").cloned().unwrap_or(json!(false)),
            "tokenizer_model_configured": tokenizer.get("model_configured").cloned().unwrap_or(json!(false)),
            "tokenizer_config_path_configured": tokenizer.get("config_path_configured").cloned().unwrap_or(json!(false)),
            "raw_values_returned": false
        },
        "sample_query_plan": {
            "source": "request_logs_safe_summary",
            "postgres_readback": {
                "table": "request_logs",
                "filters": ["tenant_id", "created_at window"],
                "selected_fields": [
                    "count",
                    "tokenized_request_count",
                    "max(created_at)",
                    "max(completed_at)",
                    "lag_seconds"
                ],
                "raw_payload_selected": false
            },
            "clickhouse_readback": {
                "enabled_when": "clickhouse.status == configured",
                "table": clickhouse.get("table").cloned().unwrap_or(Value::Null),
                "database": clickhouse.get("database").cloned().unwrap_or(Value::Null),
                "selected_fields": [
                    "event count by sink",
                    "latest event timestamp",
                    "request id correlation count"
                ],
                "query_text_returned": false,
                "network_requests": false
            },
            "tokenizer_readback": {
                "status": tokenizer.get("status").cloned().unwrap_or(json!("unknown")),
                "source": if tokenizer_configured { "configured_tokenizer_presence" } else { "provider_usage_token_columns" },
                "tokenized_request_count": tokenizer.get("tokenized_request_count").cloned().unwrap_or(json!(0)),
                "raw_tokenizer_config_returned": false
            }
        },
        "readback_expectations": {
            "postgres_request_count": postgres.request_count,
            "postgres_tokenized_request_count": postgres.tokenized_request_count,
            "postgres_staleness": postgres.staleness,
            "clickhouse_live_result_required_here": false,
            "release_evidence_closure": false
        },
        "forbidden_outputs": [
            "database_url",
            "clickhouse_endpoint",
            "clickhouse_username",
            "clickhouse_password",
            "clickhouse_token",
            "authorization",
            "raw_request_payload",
            "raw_response_payload",
            "raw_query_text"
        ],
        "next_step": next_step
    })
}

fn production_read_model_lag_explainability(
    backend: &str,
    clickhouse: &Value,
    tokenizer: &Value,
    postgres: &PostgresReadModelStatus,
    smoke_plan: &Value,
    safe_next_action: &str,
) -> Value {
    let clickhouse_configured =
        clickhouse.get("status").and_then(Value::as_str) == Some("configured");
    let tokenizer_configured = tokenizer
        .get("configured")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let sample_query_plan = smoke_plan.get("sample_query_plan").unwrap_or(&Value::Null);

    json!({
        "schema": "admin_production_read_model_lag_explainability.v1",
        "secret_safe": true,
        "status": if postgres.request_count > 0 { "readback-present" } else { "no-signal" },
        "backend_selection": {
            "selected_backend": backend,
            "decision_source": "clickhouse_config_presence_and_postgres_safe_readback",
            "postgres_candidate": true,
            "postgres_available": postgres.request_count > 0,
            "clickhouse_candidate": clickhouse_configured,
            "clickhouse_configured": clickhouse_configured,
            "clickhouse_connectivity_checked": false,
            "clickhouse_live_result_present": false,
            "fallback_backend": "postgres",
            "raw_backend_config_returned": false
        },
        "lag_staleness_source": {
            "source": "postgres_request_logs_max_created_at",
            "readback": "request_logs_safe_summary",
            "lag_seconds": postgres.lag_seconds,
            "staleness": postgres.staleness,
            "latest_request_created_at_present": postgres.latest_request_created_at.is_some(),
            "latest_completed_at_present": postgres.latest_completed_at.is_some(),
            "clickhouse_lag_checked": false,
            "raw_timestamp_query_returned": false,
            "raw_payload_returned": false
        },
        "tokenizer_config_presence": {
            "configured": tokenizer_configured,
            "backend_configured": tokenizer.get("backend_configured").cloned().unwrap_or(json!(false)),
            "model_configured": tokenizer.get("model_configured").cloned().unwrap_or(json!(false)),
            "config_path_configured": tokenizer.get("config_path_configured").cloned().unwrap_or(json!(false)),
            "tokenized_request_count": tokenizer.get("tokenized_request_count").cloned().unwrap_or(json!(0)),
            "source": if tokenizer_configured { "configured_tokenizer_presence" } else { "provider_usage_token_columns" },
            "raw_tokenizer_config_returned": false
        },
        "sample_query_plan_presence": {
            "present": sample_query_plan.is_object(),
            "source": sample_query_plan.get("source").cloned().unwrap_or(json!("request_logs_safe_summary")),
            "postgres_plan_present": sample_query_plan.get("postgres_readback").is_some(),
            "clickhouse_plan_present": sample_query_plan.get("clickhouse_readback").is_some(),
            "tokenizer_plan_present": sample_query_plan.get("tokenizer_readback").is_some(),
            "raw_sql_returned": false,
            "raw_query_returned": false,
            "raw_payload_selected": false
        },
        "safe_next_action": safe_next_action,
        "forbidden_outputs": [
            "database_url",
            "credentials",
            "authorization",
            "raw_sql",
            "raw_query",
            "raw_request_payload",
            "raw_response_payload"
        ]
    })
}

fn read_model_staleness(lag_seconds: Option<i64>) -> &'static str {
    match lag_seconds {
        None => "no-signal",
        Some(seconds) if seconds <= 300 => "fresh",
        Some(seconds) if seconds <= 3600 => "stale",
        Some(_) => "very-stale",
    }
}

async fn get_network_security_settings(
    State(state): State<Arc<ControlPlaneState>>,
) -> impl IntoResponse {
    let trusted_proxy_allowlist = state.app().config().server.trusted_proxy_allowlist.clone();
    let status = if trusted_proxy_allowlist.is_empty() {
        "config-needed"
    } else {
        "configured"
    };
    let next_action = if trusted_proxy_allowlist.is_empty() {
        "Set server.trusted_proxy_allowlist in AI_GATEWAY_CONFIG and restart or reload gateway before trusting forwarded client IP headers."
    } else {
        "Review server.trusted_proxy_allowlist before changing reverse proxy topology; changes require gateway restart or reload."
    };

    Json(json!({
        "schema": "admin_network_security_settings.v1",
        "status": status,
        "secret_safe": true,
        "trusted_proxy_config_source": "runtime_config",
        "effective_trusted_proxy_allowlist": trusted_proxy_allowlist,
        "hot_reload_supported": false,
        "recommended_env_keys": ["AI_GATEWAY_CONFIG"],
        "allowlist_handoff": {
            "editable_fields": [
                {
                    "field": "api_key_profiles.ip_allowlist",
                    "apply_path": "PATCH /admin/api-key-profiles/{id}",
                    "readback_path": "GET /admin/api-key-profiles?project_id={project_id}",
                    "effect": "applies immediately to new gateway auth checks after the profile update is committed"
                }
            ],
            "read_only_fields": [
                {
                    "field": "virtual_keys.ip_allowlist",
                    "readback_path": "GET /admin/virtual-keys?project_id={project_id}",
                    "change_path": "create or rotate the virtual key",
                    "effect": "key-level allowlist is evaluated before profile allowlist"
                }
            ],
            "config_file_fields": [
                {
                    "field": "server.trusted_proxy_allowlist",
                    "config_path_env": "AI_GATEWAY_CONFIG",
                    "patch_path": "PATCH /admin/settings/network-security",
                    "patch_behavior": "returns config-needed handoff; runtime value must be changed in the gateway config file",
                    "restart_required": true
                }
            ]
        },
        "config_keys": {
            "config_path_env": "AI_GATEWAY_CONFIG",
            "trusted_proxy_allowlist": "server.trusted_proxy_allowlist"
        },
        "example_generator": {
            "script_path": "scripts/write_network_security_config_example.ps1",
            "default_output_path": ".tmp/network-security/network_security_config_example.yaml",
            "command": "pwsh -NoProfile -ExecutionPolicy Bypass -File .\\scripts\\write_network_security_config_example.ps1",
            "print_only_command": "pwsh -NoProfile -ExecutionPolicy Bypass -File .\\scripts\\write_network_security_config_example.ps1 -PrintOnly",
            "print_only_behavior": "Writes the example YAML to stdout only and does not create or overwrite files.",
            "contains_real_networks_or_secrets": false,
            "example_address_policy": "RFC5737 IPv4 and RFC3849 IPv6 documentation ranges only"
        },
        "next_action": next_action
    }))
}

async fn patch_network_security_settings(Json(request): Json<Value>) -> impl IntoResponse {
    let requested_trusted_proxy_allowlist_count = request
        .get("trusted_proxy_allowlist")
        .and_then(Value::as_array)
        .map(|entries| {
            entries
                .iter()
                .filter(|entry| entry.as_str().is_some())
                .count()
        })
        .unwrap_or(0);

    (
        StatusCode::NOT_IMPLEMENTED,
        Json(json!({
            "error": {
                "code": "config_needed",
                "message": "trusted proxy allowlist is loaded from gateway config; write server.trusted_proxy_allowlist in AI_GATEWAY_CONFIG and restart or reload gateway.",
                "type": "configuration_required"
            },
            "data": {
                "schema": "admin_network_security_settings.v1",
                "status": "config-needed",
                "secret_safe": true,
                "trusted_proxy_config_source": "config-needed",
                "effective_trusted_proxy_allowlist": [],
                "hot_reload_supported": false,
                "recommended_env_keys": ["AI_GATEWAY_CONFIG"],
                "action_result": "config-needed: trusted proxy allowlist is not hot-patched by control-plane; update gateway config and restart or reload.",
                "requested_trusted_proxy_allowlist_count": requested_trusted_proxy_allowlist_count,
                "allowlist_handoff": {
                    "editable_fields": [
                        {
                            "field": "api_key_profiles.ip_allowlist",
                            "apply_path": "PATCH /admin/api-key-profiles/{id}",
                            "readback_path": "GET /admin/api-key-profiles?project_id={project_id}",
                            "effect": "applies immediately to new gateway auth checks after the profile update is committed"
                        }
                    ],
                    "read_only_fields": [
                        {
                            "field": "virtual_keys.ip_allowlist",
                            "readback_path": "GET /admin/virtual-keys?project_id={project_id}",
                            "change_path": "create or rotate the virtual key",
                            "effect": "key-level allowlist is evaluated before profile allowlist"
                        }
                    ],
                    "config_file_fields": [
                        {
                            "field": "server.trusted_proxy_allowlist",
                            "config_path_env": "AI_GATEWAY_CONFIG",
                            "patch_path": "PATCH /admin/settings/network-security",
                            "patch_behavior": "returns config-needed handoff; runtime value must be changed in the gateway config file",
                            "restart_required": true
                        }
                    ]
                },
                "config_keys": {
                    "config_path_env": "AI_GATEWAY_CONFIG",
                    "trusted_proxy_allowlist": "server.trusted_proxy_allowlist"
                },
                "example_generator": {
                    "script_path": "scripts/write_network_security_config_example.ps1",
                    "default_output_path": ".tmp/network-security/network_security_config_example.yaml",
                    "command": "pwsh -NoProfile -ExecutionPolicy Bypass -File .\\scripts\\write_network_security_config_example.ps1",
                    "print_only_command": "pwsh -NoProfile -ExecutionPolicy Bypass -File .\\scripts\\write_network_security_config_example.ps1 -PrintOnly",
                    "print_only_behavior": "Writes the example YAML to stdout only and does not create or overwrite files.",
                    "contains_real_networks_or_secrets": false,
                    "example_address_policy": "RFC5737 IPv4 and RFC3849 IPv6 documentation ranges only"
                },
                "next_action": "Update server.trusted_proxy_allowlist in the config file pointed to by AI_GATEWAY_CONFIG, then restart or reload gateway."
            }
        })),
    )
}

