async fn create_provider(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<CreateProviderRequest>,
) -> Result<Response, AdminError> {
    let metadata = merge_provider_metadata(
        request.metadata.unwrap_or_else(|| json!({})),
        request.provider_type,
        request.base_url,
    )?;
    let repository = repo(&state);
    let provider = repository
        .upsert_provider_with_audit(
            NewProvider {
                tenant_id: DEFAULT_TENANT_ID,
                code: non_empty(request.code, "code")?,
                name: non_empty(request.name, "name")?,
                status: normalize_provider_status(request.status.as_deref()),
                metadata,
            },
            |after| {
                new_admin_audit_log(
                    &session,
                    "provider.create",
                    None,
                    after,
                    json!({
                        "upsert_semantics": true,
                        "transactional_audit": true
                    }),
                    None,
                )
            },
        )
        .await?;

    Ok((StatusCode::CREATED, Json(json!({ "data": provider }))).into_response())
}

async fn get_provider(
    State(state): State<Arc<ControlPlaneState>>,
    Path(id): Path<Uuid>,
) -> Result<Response, AdminError> {
    let provider = repo(&state)
        .get_provider(DEFAULT_TENANT_ID, id)
        .await?
        .ok_or_else(|| AdminError::not_found("provider"))?;

    Ok(Json(json!({ "data": provider })).into_response())
}

async fn list_providers(
    State(state): State<Arc<ControlPlaneState>>,
) -> Result<Response, AdminError> {
    let providers = repo(&state).list_providers(DEFAULT_TENANT_ID).await?;

    Ok(Json(json!({ "data": providers })).into_response())
}

async fn get_provider_health_summary(
    Query(query): Query<ProviderHealthSummaryQuery>,
    State(state): State<Arc<ControlPlaneState>>,
) -> Result<Response, AdminError> {
    let filter = query.into_filter()?;
    let repository = repo(&state);
    let providers = repository.list_providers(DEFAULT_TENANT_ID).await?;
    let channels = repository.list_channels(DEFAULT_TENANT_ID).await?;
    let provider_keys = repository.list_provider_keys(DEFAULT_TENANT_ID).await?;
    let models = repository.list_canonical_models(DEFAULT_TENANT_ID).await?;
    let associations = repository
        .list_model_associations(DEFAULT_TENANT_ID)
        .await?;
    let request_logs = list_health_summary_request_logs(&state, DEFAULT_TENANT_ID, filter).await?;

    Ok(Json(json!({
        "data": health_summary_response(
            &providers,
            &channels,
            &provider_keys,
            &models,
            &associations,
            &request_logs,
            filter,
        )
    }))
    .into_response())
}

async fn get_distribution_readiness(
    State(state): State<Arc<ControlPlaneState>>,
) -> Result<Response, AdminError> {
    let repository = repo(&state);
    let providers = repository.list_providers(DEFAULT_TENANT_ID).await?;
    let channels = repository.list_channels(DEFAULT_TENANT_ID).await?;
    let provider_keys = repository.list_provider_keys(DEFAULT_TENANT_ID).await?;
    let models = repository.list_canonical_models(DEFAULT_TENANT_ID).await?;
    let associations = repository
        .list_model_associations(DEFAULT_TENANT_ID)
        .await?;
    let profiles = repository
        .list_api_key_profiles(DEFAULT_TENANT_ID, Some(DEFAULT_PROJECT_ID))
        .await?;
    let virtual_keys = repository
        .list_virtual_keys(DEFAULT_TENANT_ID, DEFAULT_PROJECT_ID, None)
        .await?;
    let request_logs = repository
        .list_request_logs(
            DEFAULT_TENANT_ID,
            RequestLogListFilter {
                limit: 20,
                status: None,
                model: None,
                canonical_model_id: None,
                channel_id: None,
                virtual_key_id: None,
                api_key_profile_id: None,
                created_from: None,
                created_to: None,
                stream: None,
                error_type: None,
            },
        )
        .await?;
    let price_versions = repository
        .list_price_versions(
            DEFAULT_TENANT_ID,
            PriceVersionListFilter {
                limit: 100,
                price_book_id: None,
                canonical_model_id: None,
                status: None,
            },
        )
        .await?;
    let voucher_distribution_readback =
        voucher_distribution_readback(state.as_ref(), DEFAULT_TENANT_ID, DEFAULT_PROJECT_ID).await;
    let health_filter = ProviderHealthSummaryFilter {
        window_minutes: HEALTH_SUMMARY_DEFAULT_WINDOW_MINUTES,
        sample_limit: 20,
    };
    let health_summary = health_summary_response(
        &providers,
        &channels,
        &provider_keys,
        &models,
        &associations,
        &request_logs,
        health_filter,
    );

    Ok(Json(json!({
        "data": distribution_readiness_response(
            &providers,
            &channels,
            &provider_keys,
            &models,
            &associations,
            &profiles,
            &virtual_keys,
            &request_logs,
            &price_versions,
            voucher_distribution_readback,
            health_summary,
        )
    }))
    .into_response())
}

async fn get_workers_jobs_dashboard(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
) -> Result<Response, AdminError> {
    session
        .require_permission(Permission::BillingRead)
        .map_err(|_| AdminError::forbidden("billing_read permission is required"))?;

    let tenant_id = session.tenant_id();
    let subscription_scheduler =
        workers_dashboard_subscription_scheduler(state.db(), tenant_id).await?;
    let importer_apply_runner = workers_dashboard_importer_apply_runner(&session)?;
    let crm_retry_handoff = workers_dashboard_crm_retry_handoff(state.db(), tenant_id).await?;
    let provider_health_recovery =
        workers_dashboard_provider_health_recovery(state.db(), &state, tenant_id).await?;
    let payment_provider_executor =
        workers_dashboard_payment_provider_executor(state.db(), tenant_id).await?;

    let blocked_count = [
        &subscription_scheduler,
        &importer_apply_runner,
        &crm_retry_handoff,
        &provider_health_recovery,
        &payment_provider_executor,
    ]
    .iter()
    .filter(|section| {
        matches!(
            section.get("status").and_then(Value::as_str),
            Some("blocked" | "not_initialized" | "config_needed")
        )
    })
    .count();
    let actionable_count = [
        &subscription_scheduler,
        &importer_apply_runner,
        &crm_retry_handoff,
        &provider_health_recovery,
        &payment_provider_executor,
    ]
    .iter()
    .filter(|section| {
        section
            .get("count")
            .and_then(Value::as_i64)
            .unwrap_or_default()
            > 0
    })
    .count();

    Ok(Json(json!({
        "data": {
            "schema": "admin_workers_jobs_dashboard.v1",
            "tenant_id": tenant_id,
            "status": if blocked_count > 0 {
                "attention_needed"
            } else if actionable_count > 0 {
                "handoff_ready"
            } else {
                "idle"
            },
            "sections": {
                "subscription_scheduler_supervisor": subscription_scheduler["supervisor"].clone(),
                "pending_scheduled_events": subscription_scheduler["pending_scheduled_events"].clone(),
                "import_apply_runner_handoff": importer_apply_runner,
                "crm_retry_handoff": crm_retry_handoff,
                "provider_health_probe_recovery_handoff": provider_health_recovery,
                "payment_provider_executor_handoff": payment_provider_executor
            },
            "readback_path": "GET /admin/workers/jobs-dashboard",
            "read_only": true,
            "runtime_daemon_started": false,
            "network_requests_executed": false,
            "business_table_writes_performed": false,
            "omitted_fields": [
                "Authorization",
                "session_token",
                "provider_key",
                "provider_key_secret",
                "database_url",
                "raw_payload",
                "raw_sql",
                "raw_webhook_body",
                "raw_metadata"
            ],
            "secret_safe": true,
            "authorization_returned": false,
            "session_token_returned": false,
            "provider_key_returned": false,
            "db_url_returned": false,
            "raw_payload_returned": false,
            "raw_sql_returned": false,
            "raw_webhook_body_returned": false,
            "raw_metadata_returned": false,
            "next_action": if actionable_count > 0 {
                "Open the section-specific readback path to inspect bounded handoff details; this endpoint does not start daemons, execute network calls, or write business tables."
            } else {
                "No claimable worker handoff is present. Use the section-specific plan/readback endpoints to prepare safe local handoff state."
            }
        }
    }))
    .into_response())
}

async fn workers_dashboard_subscription_scheduler(
    db: &PgPool,
    tenant_id: Uuid,
) -> Result<Value, AdminError> {
    let supervisor = subscription_scheduler_supervisor_readback(db, tenant_id, None, None).await?;
    let row = sqlx::query(
        r#"
        select
          count(*) filter (where event_status in ('scheduled', 'replayed'))::bigint as pending_count,
          count(*) filter (where event_status in ('scheduled', 'replayed') and effective_at <= now())::bigint as due_count,
          min(effective_at) filter (where event_status in ('scheduled', 'replayed'))::text as next_run_at,
          count(*) filter (where event_status = 'scheduled')::bigint as scheduled_count,
          count(*) filter (where event_status = 'replayed')::bigint as replayed_count,
          count(*) filter (where event_status = 'refused')::bigint as refused_count
        from subscription_events_or_schedules
        where tenant_id = $1
        "#,
    )
    .bind(tenant_id)
    .fetch_one(db)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let pending_count: i64 = admin_row_get(&row, "pending_count")?;
    let due_count: i64 = admin_row_get(&row, "due_count")?;
    let next_run_at: Option<String> = admin_row_get(&row, "next_run_at")?;
    let status = if due_count > 0 {
        "due_events_available"
    } else if pending_count > 0 {
        "scheduled"
    } else if supervisor
        .get("state_available")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        "idle"
    } else {
        "not_initialized"
    };

    Ok(json!({
        "supervisor": {
            "schema": "admin_workers_jobs_dashboard_section.v1",
            "source": "subscription_scheduler_worker_supervisors",
            "status": supervisor.get("status").and_then(Value::as_str).unwrap_or("not_initialized"),
            "count": supervisor.get("latest_workers").and_then(Value::as_array).map(|items| items.len()).unwrap_or_else(|| usize::from(supervisor.get("state_available").and_then(Value::as_bool).unwrap_or(false))),
            "ref": {
                "readback_path": "GET /admin/subscriptions/scheduler-worker",
                "state_table": "subscription_scheduler_worker_supervisors",
                "state_available": supervisor.get("state_available").and_then(Value::as_bool).unwrap_or(false)
            },
            "next_action": if supervisor.get("state_available").and_then(Value::as_bool).unwrap_or(false) {
                "Review recent supervisor state before running or leasing due events."
            } else {
                "Run the scheduler worker handoff readback or prepare scheduled events; no daemon is started by this dashboard."
            },
            "read_only": true,
            "network_requests_executed": false,
            "business_table_writes_performed": false,
            "secret_safe": true
        },
        "pending_scheduled_events": {
            "schema": "admin_workers_jobs_dashboard_section.v1",
            "source": "subscription_events_or_schedules",
            "status": status,
            "count": pending_count,
            "due_count": due_count,
            "next_run_at": next_run_at,
            "status_counts": {
                "scheduled": admin_row_get::<i64>(&row, "scheduled_count")?,
                "replayed": admin_row_get::<i64>(&row, "replayed_count")?,
                "refused": admin_row_get::<i64>(&row, "refused_count")?
            },
            "ref": {
                "readback_path": "GET /admin/subscriptions/scheduler-worker",
                "run_due_plan_path": "POST /admin/subscriptions/run-due-scheduler-events",
                "claimable_statuses": ["scheduled", "replayed"]
            },
            "next_action": if due_count > 0 {
                "Lease or dry-run due scheduled events from the subscription scheduler worker endpoint; this dashboard does not mutate event rows."
            } else if pending_count > 0 {
                "Wait until next_run_at or inspect the scheduler worker readback; no worker loop is started here."
            } else {
                "Use scheduler-plan apply to create local scheduled rows when subscriptions need renewal/dunning/proration work."
            },
            "read_only": true,
            "network_requests_executed": false,
            "business_table_writes_performed": false,
            "secret_safe": true
        },
        "status": status,
        "count": pending_count
    }))
}

fn workers_dashboard_importer_apply_runner(session: &AdminSession) -> Result<Value, AdminError> {
    let readback = importer_apply_run_readback(None, session)?;
    let blocked_reasons = readback
        .get("blocked_reasons")
        .and_then(Value::as_array)
        .map(|items| items.len())
        .unwrap_or_default();

    Ok(json!({
        "schema": "admin_workers_jobs_dashboard_section.v1",
        "source": "importer_apply_runs/importer_apply_operation_journal",
        "status": readback.get("status").and_then(Value::as_str).unwrap_or("blocked"),
        "count": blocked_reasons,
        "ref": {
            "readback_path": "GET /admin/importer/apply-runs/readback",
            "record_readback_path": "POST /admin/importer/apply-runs/readback",
            "apply_runner_path": "POST /admin/importer/apply-runs"
        },
        "next_action": readback.get("safe_next_action").and_then(Value::as_str).unwrap_or("Review importer apply runner handoff without pasting DB URLs, raw SQL, provider keys, Authorization, or secrets."),
        "read_only": true,
        "network_requests_executed": false,
        "business_table_writes_performed": false,
        "secret_safe": true,
        "db_url_returned": false,
        "raw_sql_returned": false,
        "provider_key_returned": false,
        "authorization_returned": false,
        "raw_payload_returned": false
    }))
}

async fn workers_dashboard_crm_retry_handoff(
    db: &PgPool,
    tenant_id: Uuid,
) -> Result<Value, AdminError> {
    let summary = enterprise_crm_retry_worker_handoff_summary(db, tenant_id, false).await?;
    let scheduled_count = summary
        .get("scheduled_count")
        .and_then(Value::as_i64)
        .unwrap_or_default();
    let blocked_count = summary
        .get("blocked_count")
        .and_then(Value::as_i64)
        .unwrap_or_default();

    Ok(json!({
        "schema": "admin_workers_jobs_dashboard_section.v1",
        "source": "enterprise_crm_sync_runs.metadata.retry_attempt_readback",
        "status": if scheduled_count > 0 {
            "handoff_ready"
        } else if blocked_count > 0 {
            "blocked"
        } else {
            "idle"
        },
        "count": scheduled_count + blocked_count,
        "scheduled_count": scheduled_count,
        "blocked_count": blocked_count,
        "next_retry_after_seconds_min": summary.get("next_retry_after_seconds_min").cloned().unwrap_or(Value::Null),
        "status_counts": summary.get("status_counts").cloned().unwrap_or_else(|| json!({})),
        "ref": {
            "readback_path": "GET /admin/enterprise/accounts",
            "dashboard_readback_path": "GET /admin/enterprise/sales-dashboard"
        },
        "next_action": summary
            .get("operator_next_actions")
            .and_then(Value::as_array)
            .and_then(|items| items.first())
            .and_then(|item| item.get("action"))
            .and_then(Value::as_str)
            .unwrap_or("Review CRM retry handoff markers before enabling any real retry worker."),
        "read_only": true,
        "network_requests_executed": false,
        "business_table_writes_performed": false,
        "authorization_returned": false,
        "provider_secret_returned": false,
        "raw_payload_returned": false,
        "secret_safe": true
    }))
}

async fn workers_dashboard_provider_health_recovery(
    _db: &PgPool,
    state: &Arc<ControlPlaneState>,
    tenant_id: Uuid,
) -> Result<Value, AdminError> {
    let provider_keys = repo(state).list_provider_keys(tenant_id).await?;
    let mut status_counts = BTreeMap::<String, i64>::new();
    let mut recovery_count = 0_i64;
    let mut rotation_needed_count = 0_i64;
    let mut refs = Vec::new();

    for provider_key in &provider_keys {
        bump_count(&mut status_counts, &provider_key.status);
        let recovery_probe = provider_key_recovery_probe_summary(&provider_key.metadata);
        let rotation_needed = provider_key_rotation_needed(provider_key, &recovery_probe);
        if matches!(
            provider_key.status.as_str(),
            "cooldown" | "degraded" | "recovery_probe" | "auth_failed" | "quota_exhausted"
        ) {
            recovery_count += 1;
            if refs.len() < 5 {
                refs.push(json!({
                    "ref": subscription_scheduler_public_fingerprint(&provider_key.id.to_string()),
                    "status": provider_key.status,
                    "last_probe_status": recovery_probe.get("result").cloned().unwrap_or(Value::Null),
                    "safe_next_action": provider_key_safe_next_action(provider_key, &rotation_needed),
                    "raw_provider_key_returned": false
                }));
            }
        }
        if rotation_needed
            .get("needed")
            .and_then(Value::as_bool)
            .unwrap_or(false)
        {
            rotation_needed_count += 1;
        }
    }

    Ok(json!({
        "schema": "admin_workers_jobs_dashboard_section.v1",
        "source": "provider_keys.status/provider_keys.metadata.recovery_probe",
        "status": if rotation_needed_count > 0 {
            "blocked"
        } else if recovery_count > 0 {
            "handoff_ready"
        } else if provider_keys.is_empty() {
            "not_initialized"
        } else {
            "idle"
        },
        "count": recovery_count,
        "provider_key_count": provider_keys.len(),
        "rotation_needed_count": rotation_needed_count,
        "status_counts": status_counts,
        "refs": refs,
        "ref": {
            "health_summary_path": "GET /admin/providers/health-summary",
            "recovery_request_path": "POST /admin/provider-keys/{id}/recovery",
            "rotation_path": "POST /admin/provider-keys/{id}/rotate"
        },
        "next_action": if rotation_needed_count > 0 {
            "Rotate affected provider credentials, then request a non-billable recovery probe readback."
        } else if recovery_count > 0 {
            "Review provider health summary and request recovery probe readback for degraded/cooldown keys."
        } else {
            "Monitor provider health summary; no recovery handoff is currently pending."
        },
        "read_only": true,
        "network_requests_executed": false,
        "business_table_writes_performed": false,
        "provider_key_returned": false,
        "authorization_returned": false,
        "raw_payload_returned": false,
        "secret_safe": true
    }))
}

async fn workers_dashboard_payment_provider_executor(
    db: &PgPool,
    tenant_id: Uuid,
) -> Result<Value, AdminError> {
    let provider = payment_provider_config_default_provider()?;
    let source =
        payment_provider_merchant_credential_source_readback(db, tenant_id, &provider).await?;
    let input = payment_provider_adapter_config_input_for_credential_source(&provider, &source)?;
    let row = sqlx::query(
        r#"
        select
          count(*) filter (where status = 'provider_handoff')::bigint as pending_intent_count,
          count(*) filter (where status = 'intent_created')::bigint as created_intent_count
        from payment_intents
        where tenant_id = $1
        "#,
    )
    .bind(tenant_id)
    .fetch_one(db)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let pending_intent_count: i64 = admin_row_get(&row, "pending_intent_count")?;
    let created_intent_count: i64 = admin_row_get(&row, "created_intent_count")?;
    let config_ready =
        input.adapter_enabled && input.merchant_account_present && input.credential_present;

    Ok(json!({
        "schema": "admin_workers_jobs_dashboard_section.v1",
        "source": "payment_intents/payment_provider_merchant_credentials",
        "status": if !config_ready {
            "config_needed"
        } else if pending_intent_count > 0 {
            "handoff_ready"
        } else {
            "idle"
        },
        "count": pending_intent_count,
        "created_intent_count": created_intent_count,
        "provider": provider,
        "config": {
            "adapter_enabled": input.adapter_enabled,
            "merchant_account_ref_present": input.merchant_account_present,
            "credential_ref_present": input.credential_present,
            "webhook_secret_ref_present": input.webhook_secret_present,
            "credential_value_loaded": false,
            "provider_secret_returned": false
        },
        "ref": {
            "config_status_path": "GET /admin/billing/payment-provider/config-status",
            "executor_path": "POST /admin/billing/payment-provider/executor",
            "subscription_worker_path": "GET /admin/subscriptions/scheduler-worker"
        },
        "next_action": if !config_ready {
            "Configure merchant and credential refs before handing payment intents to the provider executor."
        } else if pending_intent_count > 0 {
            "Fetch provider source-of-truth evidence, then call the payment provider executor with bounded handoff refs."
        } else {
            "No payment provider executor handoff is pending."
        },
        "read_only": true,
        "network_requests_executed": false,
        "business_table_writes_performed": false,
        "provider_key_returned": false,
        "authorization_returned": false,
        "raw_payment_payload_returned": false,
        "raw_provider_payload_returned": false,
        "raw_webhook_body_returned": false,
        "secret_safe": true
    }))
}

async fn get_setup_readback(
    State(state): State<Arc<ControlPlaneState>>,
) -> Result<Response, AdminError> {
    let repository = repo(&state);
    let providers = repository.list_providers(DEFAULT_TENANT_ID).await?;
    let channels = repository.list_channels(DEFAULT_TENANT_ID).await?;
    let provider_keys = repository.list_provider_keys(DEFAULT_TENANT_ID).await?;
    let models = repository.list_canonical_models(DEFAULT_TENANT_ID).await?;
    let associations = repository
        .list_model_associations(DEFAULT_TENANT_ID)
        .await?;
    let profiles = repository
        .list_api_key_profiles(DEFAULT_TENANT_ID, Some(DEFAULT_PROJECT_ID))
        .await?;
    let virtual_keys = repository
        .list_virtual_keys(DEFAULT_TENANT_ID, DEFAULT_PROJECT_ID, None)
        .await?;
    let request_logs = repository
        .list_request_logs(
            DEFAULT_TENANT_ID,
            RequestLogListFilter {
                limit: 20,
                status: None,
                model: Some("mock-gpt-4o-mini".to_string()),
                canonical_model_id: None,
                channel_id: None,
                virtual_key_id: None,
                api_key_profile_id: None,
                created_from: None,
                created_to: None,
                stream: None,
                error_type: None,
            },
        )
        .await?;
    let admin_user_exists = local_admin_user_exists(state.db()).await?;

    Ok(Json(json!({
        "data": setup_readback_response(
            admin_user_exists,
            &providers,
            &channels,
            &provider_keys,
            &models,
            &associations,
            &profiles,
            &virtual_keys,
            &request_logs,
        )
    }))
    .into_response())
}

async fn local_admin_user_exists(db: &PgPool) -> Result<bool, AdminError> {
    let row = sqlx::query(
        r#"
select exists (
  select 1
  from users u
  where u.tenant_id = $1
    and u.id = '00000000-0000-0000-0000-0000000000a1'::uuid
    and u.email = 'admin@example.com'
    and u.status = 'active'
    and u.deleted_at is null
) as admin_exists
"#,
    )
    .bind(DEFAULT_TENANT_ID)
    .fetch_one(db)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.try_get("admin_exists")
        .map_err(|error| AdminError::from(DbError::Query(error)))
}

async fn patch_provider(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Path(id): Path<Uuid>,
    Json(request): Json<PatchProviderRequest>,
) -> Result<Response, AdminError> {
    let repository = repo(&state);
    let current = repository
        .get_provider(DEFAULT_TENANT_ID, id)
        .await?
        .ok_or_else(|| AdminError::not_found("provider"))?;
    let metadata = merge_provider_metadata(
        request.metadata.unwrap_or(current.metadata),
        request.provider_type,
        request.base_url,
    )?;
    let provider = repository
        .update_provider_with_audit(
            DEFAULT_TENANT_ID,
            id,
            UpdateProvider {
                code: request.code.unwrap_or(current.code),
                name: request.name.unwrap_or(current.name),
                status: request
                    .status
                    .map(|status| normalize_provider_status(Some(&status)))
                    .unwrap_or(current.status),
                metadata,
            },
            |before, after| {
                new_admin_audit_log(
                    &session,
                    "provider.update",
                    Some(before),
                    after,
                    json!({ "transactional_audit": true }),
                    None,
                )
            },
        )
        .await?
        .ok_or_else(|| AdminError::not_found("provider"))?;

    Ok(Json(json!({ "data": provider })).into_response())
}

async fn delete_provider(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Path(id): Path<Uuid>,
) -> Result<Response, AdminError> {
    let repository = repo(&state);
    let provider = repository
        .soft_delete_provider_with_audit(DEFAULT_TENANT_ID, id, |before, after| {
            new_admin_audit_log(
                &session,
                "provider.delete",
                Some(before),
                after,
                json!({ "transactional_audit": true }),
                None,
            )
        })
        .await?
        .ok_or_else(|| AdminError::not_found("provider"))?;

    Ok(Json(json!({ "data": provider })).into_response())
}

async fn create_channel(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<CreateChannelRequest>,
) -> Result<Response, AdminError> {
    let endpoint = request
        .endpoint
        .or(request.base_url)
        .ok_or_else(|| AdminError::bad_request("endpoint or base_url is required"))?;
    let protocol_mode = request
        .protocol_mode
        .or(request.protocol)
        .unwrap_or_else(|| "openai_compatible".to_string());
    let repository = repo(&state);
    let channel = repository
        .upsert_channel_with_audit(
            NewChannel {
                tenant_id: DEFAULT_TENANT_ID,
                provider_id: request.provider_id,
                name: non_empty(request.name, "name")?,
                endpoint: validate_admin_provider_endpoint(endpoint)?,
                protocol_mode: normalize_protocol_mode(&protocol_mode),
                status: normalize_enabled_status(request.status.as_deref()),
                region: request.region,
                priority: request.priority.unwrap_or(100),
                weight: request.weight.unwrap_or(100),
                tags: request.tags.unwrap_or_else(|| json!([])),
                model_mappings: request.model_mappings.unwrap_or_else(|| json!({})),
                request_overrides: request.request_overrides.unwrap_or_else(|| json!([])),
                timeout_policy: request.timeout_policy.unwrap_or_else(|| json!({})),
                probe_policy: request.probe_policy.unwrap_or_else(|| json!({})),
                health_score: request.health_score.unwrap_or(1.0),
            },
            |after| {
                new_admin_audit_log(
                    &session,
                    "channel.create",
                    None,
                    after,
                    json!({
                        "upsert_semantics": true,
                        "transactional_audit": true
                    }),
                    None,
                )
            },
        )
        .await?;

    Ok((StatusCode::CREATED, Json(json!({ "data": channel }))).into_response())
}

