async fn request_provider_key_recovery(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    headers: HeaderMap,
    Path(id): Path<Uuid>,
    request: Option<Json<ProviderKeyRecoveryRequest>>,
) -> Result<Response, AdminError> {
    let request = request.map(|Json(request)| request).unwrap_or_default();
    let repository = repo(&state);
    let current = repository
        .get_provider_key(DEFAULT_TENANT_ID, id)
        .await?
        .ok_or_else(|| AdminError::not_found("provider key"))?;

    let target_status = normalize_provider_key_recovery_target(request.target_status.as_deref())?;
    validate_provider_key_recovery_transition(&current.status, &target_status)?;
    let previous_status = current.status.clone();
    let metadata = current.metadata.clone();
    let reason = normalize_provider_key_recovery_reason(request.reason)?;
    let request_context = admin_request_context_from_headers(&headers);

    let audit_previous_status = previous_status.clone();
    let audit_target_status = target_status.clone();
    let audit_reason = reason.clone();
    let provider_key = repository
        .update_provider_key_admin_with_audit(
            DEFAULT_TENANT_ID,
            id,
            &target_status,
            metadata,
            |before, after| {
                new_admin_audit_log(
                    &session,
                    "provider_key.recovery_request",
                    Some(before),
                    after,
                    json!({
                        "controlled_status_transition": true,
                        "previous_status": audit_previous_status,
                        "target_status": audit_target_status,
                        "reason": audit_reason,
                        "upstream_probe": {
                            "executed": false,
                            "mode": "not_implemented"
                        },
                        "credential_material": {
                            "omitted": true
                        }
                    }),
                    Some(request_context.clone()),
                )
            },
        )
        .await?
        .ok_or_else(|| AdminError::not_found("provider key"))?;

    Ok(Json(json!({
        "data": provider_key_recovery_response(
            &provider_key,
            &previous_status,
            &target_status,
            reason.as_deref(),
        )
    }))
    .into_response())
}

async fn rotate_provider_key(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    headers: HeaderMap,
    Path(id): Path<Uuid>,
    Json(request): Json<ProviderKeyRotateRequest>,
) -> Result<Response, AdminError> {
    reject_provider_key_rotate_generated_fields(&request)?;

    let repository = repo(&state);
    let current = repository
        .get_provider_key(DEFAULT_TENANT_ID, id)
        .await?
        .ok_or_else(|| AdminError::not_found("provider key"))?;
    validate_provider_key_rotation_source(&current.status)?;

    let channel = repository
        .get_channel(DEFAULT_TENANT_ID, current.channel_id)
        .await?
        .ok_or_else(|| AdminError::not_found("channel"))?;
    let master_key = load_provider_key_master_key_config()?;
    let new_provider_key_id = Uuid::new_v4();
    let reason = normalize_provider_key_rotation_reason(request.reason.clone())?;
    let request_context = admin_request_context_from_headers(&headers);
    let new_provider_key = build_rotated_provider_key(
        &current,
        &channel,
        request,
        new_provider_key_id,
        reason.as_deref(),
        &master_key,
    )?;

    let audit_reason = reason.clone();
    let (old_provider_key, new_provider_key) = repository
        .rotate_provider_key_with_audit(
            DEFAULT_TENANT_ID,
            id,
            new_provider_key,
            |before, old_after, new_after| {
                new_admin_audit_log(
                    &session,
                    "provider_key.rotate",
                    Some(before),
                    new_after,
                    json!({
                        "runtime_rotate_endpoint_implemented": true,
                        "server_seals_secret": true,
                        "secret_material": "redacted",
                        "credential_material": {
                            "omitted": true,
                            "encrypted_at_rest": true,
                            "fingerprint_returned": false
                        },
                        "old_provider_key_id": old_after.id,
                        "old_key_transition": {
                            "from_status": before.status,
                            "to_status": old_after.status
                        },
                        "new_provider_key_id": new_after.id,
                        "new_key_transition": {
                            "from_status": "pending_create",
                            "to_status": new_after.status
                        },
                        "reason": audit_reason,
                        "production_rotation_closure_allowed": false,
                        "production_closure_blockers": [
                            "kms_or_master_key_custody_policy_missing",
                            "production_live_traffic_readback_missing",
                            "old_key_disable_audit_readback_missing"
                        ]
                    }),
                    Some(request_context.clone()),
                )
            },
        )
        .await?
        .ok_or_else(|| AdminError::not_found("provider key"))?;

    Ok(Json(json!({
        "data": provider_key_rotation_response(
            &old_provider_key,
            &new_provider_key,
            reason.as_deref(),
        )
    }))
    .into_response())
}

