async fn list_virtual_key_leak_candidates(
    State(state): State<Arc<ControlPlaneState>>,
    Query(query): Query<ListVirtualKeyLeakCandidatesQuery>,
) -> Result<Response, AdminError> {
    let filter = ListVirtualKeysQuery {
        project_id: query.project_id,
        status: query.status,
    }
    .into_filter()?;
    let virtual_keys = repo(&state)
        .list_virtual_keys(
            DEFAULT_TENANT_ID,
            filter.project_id,
            filter.status.as_deref(),
        )
        .await?;
    let leak_candidates = virtual_keys
        .iter()
        .filter_map(virtual_key_leak_candidate_response)
        .collect::<Vec<_>>();
    let last_scan_marker = virtual_key_leak_last_scan_marker(&leak_candidates);
    let suspected_leaked = leak_candidates.clone();

    Ok(Json(json!({
        "data": {
            "leak_candidates": leak_candidates,
            "suspected_leaked": suspected_leaked,
            "source_policy": virtual_key_leak_candidate_source_policy(),
            "external_scanner_adapter": virtual_key_external_scanner_adapter_readback(Some(last_scan_marker)),
            "operator_confirmation_required": true,
            "automatic_disable_or_revoke": false,
            "secret_safe": true,
            "payload_omitted": true,
        }
    }))
    .into_response())
}

async fn bulk_virtual_key_leak_action(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<BulkVirtualKeyLeakActionRequest>,
) -> Result<Response, AdminError> {
    let key_ids = normalize_bulk_virtual_key_ids(request.key_ids)?;
    let action = normalize_virtual_key_leak_action(&request.action)?;
    let reason = normalize_virtual_key_leak_reason(request.reason)?;
    let operation_id = Uuid::new_v4();
    let repository = repo(&state);
    let mut results = Vec::with_capacity(key_ids.len());
    let mut audit_log_ids = Vec::new();

    for key_id in key_ids {
        match action {
            VirtualKeyLeakAction::MarkSuspectedLeaked => {
                let marked = mark_virtual_key_suspected_leaked_with_audit(
                    state.as_ref(),
                    &session,
                    key_id,
                    &reason,
                    &request.action,
                )
                .await?
                .map(|(virtual_key, audit_log_id)| {
                    audit_log_ids.push(audit_log_id);
                    virtual_key_leak_action_response(
                        &virtual_key,
                        "suspected_leaked_marked",
                        Some(audit_log_id),
                    )
                })
                .unwrap_or_else(|| virtual_key_leak_action_missing_response(key_id, "not_found"));
                results.push(marked);
            }
            VirtualKeyLeakAction::Disable | VirtualKeyLeakAction::Revoke => {
                let action_name = match action {
                    VirtualKeyLeakAction::Disable => "virtual_key.disable",
                    VirtualKeyLeakAction::Revoke => "virtual_key.revoke",
                    VirtualKeyLeakAction::MarkSuspectedLeaked => unreachable!(),
                };
                let action_result = match action {
                    VirtualKeyLeakAction::Disable => "disabled",
                    VirtualKeyLeakAction::Revoke => "revoked_disabled",
                    VirtualKeyLeakAction::MarkSuspectedLeaked => unreachable!(),
                };
                let audit_reason = reason.clone();
                let requested_action = request.action.clone();
                let virtual_key = repository
                    .update_virtual_key_status_with_audit(
                        DEFAULT_TENANT_ID,
                        key_id,
                        "disabled",
                        |before, after| {
                            new_admin_audit_log(
                                &session,
                                action_name,
                                Some(before),
                                after,
                                json!({
                                    "reason": audit_reason,
                                    "action_result": action_result,
                                    "bulk_leak_action": true,
                                    "requested_action": requested_action,
                                    "status": normalize_virtual_key_status_for_response(&after.status),
                                    "from_status": normalize_virtual_key_status_for_response(&before.status),
                                    "to_status": normalize_virtual_key_status_for_response(&after.status),
                                    "status_changed": before.status != after.status,
                                    "secret_safe": true,
                                    "payload_omitted": true,
                                    "audit_log_write": true,
                                }),
                                None,
                            )
                        },
                    )
                    .await?;
                match virtual_key {
                    Some((virtual_key, audit_log_id)) => {
                        audit_log_ids.push(audit_log_id);
                        results.push(virtual_key_leak_action_response(
                            &virtual_key,
                            action_result,
                            Some(audit_log_id),
                        ));
                    }
                    None => {
                        results.push(virtual_key_leak_action_missing_response(
                            key_id,
                            "not_found",
                        ));
                    }
                }
            }
        }
    }

    let result = bulk_virtual_key_leak_action_result_summary(
        operation_id,
        &request.action,
        &results,
        &audit_log_ids,
    );

    Ok(Json(json!({ "data": results, "result": result })).into_response())
}

async fn handoff_virtual_key_external_scanner_findings(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(raw_request): Json<Value>,
) -> Result<Response, AdminError> {
    if let Some(field) = virtual_key_external_scanner_handoff_forbidden_field(&raw_request) {
        return Ok((
            StatusCode::BAD_REQUEST,
            Json(json!({
                "error": {
                    "code": "virtual_key_external_scanner_raw_material_not_accepted",
                    "message": "External scanner handoff accepts only bounded finding summary metadata.",
                    "field": field,
                    "secret_safe": true,
                    "raw_material_echoed": false,
                    "omitted_fields": virtual_key_external_scanner_handoff_omitted_fields()
                }
            })),
        )
            .into_response());
    }

    let request: VirtualKeyExternalScannerHandoffRequest = serde_json::from_value(raw_request)
        .map_err(|_| {
            AdminError::bad_request(
                "request must match the bounded external scanner finding summary schema",
            )
        })?;
    let summary = normalize_virtual_key_external_scanner_handoff(request)?;
    let result = match summary.virtual_key_id {
        Some(virtual_key_id) => {
            match mark_virtual_key_external_scanner_handoff_with_audit(
                state.as_ref(),
                &session,
                virtual_key_id,
                &summary,
            )
            .await?
            {
                Some((virtual_key, audit_log_id)) => json!({
                    "action_result": "external_scanner_marker_written",
                    "metadata_marker_written": true,
                    "key_id": virtual_key.id,
                    "key_prefix": virtual_key.key_prefix,
                    "status": normalize_virtual_key_status_for_response(&virtual_key.status),
                    "audit_log_id": audit_log_id,
                }),
                None => json!({
                    "action_result": "not_found",
                    "metadata_marker_written": false,
                    "key_id": virtual_key_id,
                    "key_prefix": null,
                    "status": null,
                    "audit_log_id": null,
                }),
            }
        }
        None => json!({
            "action_result": "external_scanner_marker_planned",
            "metadata_marker_written": false,
            "key_id": null,
            "key_prefix": null,
            "status": null,
            "audit_log_id": null,
        }),
    };

    Ok(Json(json!({
        "data": {
            "provider": summary.provider,
            "finding_count": summary.finding_count,
            "key_prefix_present": summary.key_prefix_present,
            "key_hash_present": summary.key_hash_present,
            "repo_ref_hash_present": true,
            "severity": summary.severity,
            "detected_at": summary.detected_at,
            "signature_validated": summary.signature_validated,
            "source": "external_scanner_handoff",
            "safe_markers": ["external_scanner_summary_marker"],
            "result": result,
            "secret_safe": true,
            "payload_omitted": true,
            "raw_findings_accepted": false,
            "raw_findings_returned": false,
            "network_call_performed": false,
            "webhook_signature_verification": "[!] server-side scanner webhook verification not implemented in this local handoff seam"
        }
    }))
    .into_response())
}

