async fn export_request_logs_csv(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    headers: HeaderMap,
    Query(query): Query<ListRequestLogsQuery>,
) -> Result<Response, AdminError> {
    let filter = query.into_filter()?;
    let repository = repo(&state);
    let request_logs = repository
        .list_request_logs(DEFAULT_TENANT_ID, filter.clone())
        .await?;
    let row_count = request_logs.len();
    let csv = request_logs_csv(&request_logs);
    let audit = request_logs_export_audit_log(
        &session,
        &filter,
        row_count,
        admin_request_context_from_headers(&headers),
    );
    let _ = repository.insert_audit_log(audit).await;
    let mut headers = HeaderMap::new();
    headers.insert(
        CONTENT_TYPE,
        HeaderValue::from_static("text/csv; charset=utf-8"),
    );
    headers.insert(
        CONTENT_DISPOSITION,
        HeaderValue::from_static("attachment; filename=\"ai-gateway-request-logs.csv\""),
    );

    Ok((headers, csv).into_response())
}

fn request_logs_export_audit_log(
    session: &AdminSession,
    filter: &RequestLogListFilter,
    row_count: usize,
    request_context: Value,
) -> NewAuditLog {
    let export_audit_readback = request_logs_export_audit_readback(filter, row_count);
    NewAuditLog {
        tenant_id: DEFAULT_TENANT_ID,
        actor_session_id: Some(session.session_id()),
        request_id: None,
        action: "request_logs.export_csv".to_string(),
        resource_type: "request_log_export".to_string(),
        resource_id: None,
        resource_tenant_id: Some(DEFAULT_TENANT_ID),
        before_snapshot: None,
        after_snapshot: Some(json!({
            "format": "csv",
            "row_count": row_count,
            "status": "exported",
            "export_audit_readback": export_audit_readback,
        })),
        metadata: admin_audit_metadata_from_parts(
            session.session_id(),
            session.tenant_id(),
            json!({
                "reason": "admin request log csv export",
                "action_result": "exported",
                "format": "csv",
                "row_count": row_count,
                "filter_summary": request_log_filter_audit_summary(filter),
                "export_audit_readback": export_audit_readback,
                "secret_safe": true,
                "payload_omitted": true,
                "csv_content_logged": false,
                "raw_filters_logged": false,
                "omitted_material": [
                    "csv_content",
                    "raw_query_string",
                    "raw_filters",
                    "raw_request_payload",
                    "raw_response_payload",
                    "raw_payload",
                    "provider_response",
                    "raw_provider_payload",
                    "authorization",
                    "cookie",
                    "provider_key",
                    "api_key_secret",
                    "virtual_key_secret"
                ]
            }),
            Some(request_context),
        ),
    }
}

fn request_logs_export_audit_readback(filter: &RequestLogListFilter, row_count: usize) -> Value {
    json!({
        "schema": "admin_request_logs_export_audit_readback.v1",
        "audit_action": "request_logs.export_csv",
        "audit_readback_path": "GET /admin/audit-logs?action=request_logs.export_csv",
        "audit_id_ref_present": false,
        "audit_id_ref_reason": "csv_endpoint_returns_text_csv_best_effort_audit_id_available_via_audit_logs_readback",
        "resource_ref_present": false,
        "resource_type": "request_log_export",
        "filtered_row_count": row_count,
        "filter_summary": request_log_filter_audit_summary(filter),
        "allowed_columns": REQUEST_LOG_EXPORT_ALLOWED_COLUMNS,
        "redaction_policy": {
            "schema": "metadata_only_export_audit.v1",
            "csv_content_logged": false,
            "raw_filters_logged": false,
            "raw_payload_logged": false,
            "provider_response_logged": false,
            "authorization_logged": false,
            "provider_key_logged": false,
            "api_key_secret_logged": false,
            "policy": "metadata_only_safe_summary_columns"
        },
        "forbidden_material": [
            "csv_content",
            "raw_query_string",
            "raw_filters",
            "raw_request_payload",
            "raw_response_payload",
            "raw_payload",
            "provider_response",
            "raw_provider_payload",
            "authorization",
            "provider_key",
            "api_key_secret",
            "virtual_key_secret"
        ],
        "safe_next_action": "Read GET /admin/audit-logs?action=request_logs.export_csv and compare filtered_row_count plus allowed_columns; use request detail or trace summary for row-level troubleshooting."
    })
}

fn request_log_filter_audit_summary(filter: &RequestLogListFilter) -> Value {
    json!({
        "limit": filter.limit,
        "status_set": filter.status.is_some(),
        "model_set": filter.model.is_some(),
        "canonical_model_id_set": filter.canonical_model_id.is_some(),
        "channel_id_set": filter.channel_id.is_some(),
        "virtual_key_id_set": filter.virtual_key_id.is_some(),
        "api_key_profile_id_set": filter.api_key_profile_id.is_some(),
        "created_from_set": filter.created_from.is_some(),
        "created_to_set": filter.created_to.is_some(),
        "stream_set": filter.stream.is_some(),
        "error_type_set": filter.error_type.is_some(),
    })
}

