async fn get_request_log_detail(
    State(state): State<Arc<ControlPlaneState>>,
    Path(id): Path<Uuid>,
) -> Result<Response, AdminError> {
    let repository = repo(&state);
    let request_log = repository
        .get_request_log(DEFAULT_TENANT_ID, id)
        .await?
        .ok_or_else(|| AdminError::not_found("request log"))?;
    let provider_attempts = repository
        .list_provider_attempts_for_request(DEFAULT_TENANT_ID, id)
        .await?;
    let ledger_entries = repository
        .list_ledger_entries(
            DEFAULT_TENANT_ID,
            LedgerEntryListFilter {
                limit: REQUEST_LOG_DETAIL_LEDGER_LIMIT,
                project_id: None,
                request_id: Some(id),
                wallet_id: None,
            },
        )
        .await?;
    let route_decision_snapshot = request_log.route_decision_snapshot.clone();
    let request_log = RequestLogSummary::from(&request_log);
    let provider_protocol_summary = request_log.provider_protocol_summary.clone();
    let usage_explainability =
        request_usage_explainability_response(&request_log, &provider_attempts, &ledger_entries);
    let preauthorize_and_rate_limit_explainability =
        preauthorize_and_rate_limit_explainability_response(
            &request_log,
            &provider_attempts,
            &ledger_entries,
            &route_decision_snapshot,
        );
    let provider_attempts_explainability =
        provider_attempts_explainability_response(&request_log, &provider_attempts);
    let trace_timeline_readback = trace_timeline_readback_response(
        &request_log,
        &route_decision_snapshot,
        &provider_attempts,
        &ledger_entries,
        &preauthorize_and_rate_limit_explainability,
        &provider_attempts_explainability,
    );

    Ok(Json(json!({
        "data": {
            "request_log": request_log,
            "provider_protocol_summary": provider_protocol_summary,
            "usage_explainability": usage_explainability.clone(),
            "billing_usage_source": usage_explainability,
            "preauthorize_and_rate_limit_explainability": preauthorize_and_rate_limit_explainability,
            "provider_attempts_explainability": provider_attempts_explainability,
            "trace_timeline_readback": trace_timeline_readback,
            "provider_attempts": provider_attempts_safe_response(&provider_attempts),
            "route_decision_snapshot": route_decision_snapshot,
            "ledger": ledger_summary_response(&ledger_entries, REQUEST_LOG_DETAIL_LEDGER_LIMIT),
        }
    }))
    .into_response())
}

fn provider_attempts_safe_response(provider_attempts: &[ProviderAttemptRead]) -> Vec<Value> {
    provider_attempts
        .iter()
        .map(|attempt| {
            json!({
                "id": attempt.id,
                "tenant_id": attempt.tenant_id,
                "request_id": attempt.request_id,
                "provider_id": attempt.provider_id,
                "channel_id": attempt.channel_id,
                "attempt_no": attempt.attempt_no,
                "upstream_model": attempt.upstream_model,
                "status": attempt.status,
                "http_status": attempt.http_status,
                "error_owner": attempt.error_owner,
                "error_code": attempt.error_code,
                "retryable": attempt.retryable,
                "fallback_reason": attempt.fallback_reason,
                "latency_ms": attempt.latency_ms,
                "ttft_ms": attempt.ttft_ms,
                "input_tokens": attempt.input_tokens,
                "output_tokens": attempt.output_tokens,
                "started_at": attempt.started_at,
                "completed_at": attempt.completed_at,
            })
        })
        .collect()
}

fn trace_timeline_readback_response(
    request_log: &RequestLogSummary,
    route_decision_snapshot: &Value,
    provider_attempts: &[ProviderAttemptRead],
    ledger_entries: &[LedgerEntry],
    preauthorize_and_rate_limit_explainability: &Value,
    provider_attempts_explainability: &Value,
) -> Value {
    let route_summary = route_decision_snapshot
        .get("summary")
        .unwrap_or(&Value::Null);
    let route_reject_reason = first_safe_json_string(
        route_summary,
        &["reject_reason", "reject_code", "rejection_reason"],
    );
    let route_selected = request_log.resolved_channel_id.is_some()
        || route_summary
            .get("selected_channel_id")
            .and_then(Value::as_str)
            .is_some();
    let route_status = if route_reject_reason.is_some() {
        "rejected"
    } else if route_selected {
        "selected"
    } else {
        "not_recorded"
    };
    let selected_attempt_no = provider_attempts_explainability
        .get("selected_attempt_no")
        .and_then(Value::as_i64);
    let fallback_attempt_count = provider_attempts_explainability
        .get("fallback_attempt_count")
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let provider_attempt_status = if provider_attempts.is_empty() {
        "not_attempted"
    } else if provider_attempts
        .iter()
        .any(|attempt| attempt.status == "succeeded")
    {
        "succeeded"
    } else {
        "failed_or_exhausted"
    };
    let preauth_status = preauthorize_and_rate_limit_explainability
        .get("preauthorize")
        .and_then(|value| value.get("status"))
        .and_then(Value::as_str)
        .map(health_summary_string)
        .unwrap_or_else(|| "not_recorded".to_string());
    let rate_limit_status = preauthorize_and_rate_limit_explainability
        .get("rate_limit_reservation")
        .and_then(|value| value.get("status"))
        .and_then(Value::as_str)
        .map(health_summary_string)
        .unwrap_or_else(|| "not_recorded".to_string());
    let preauth_safe_next_action = preauthorize_and_rate_limit_explainability
        .get("safe_next_action")
        .and_then(Value::as_str)
        .unwrap_or("inspect_provider_attempts_or_trace_summary_if_issue_persists");
    let provider_safe_next_action = provider_attempts_explainability
        .get("safe_next_action")
        .and_then(Value::as_str)
        .unwrap_or("inspect_trace_summary_and_provider_attempt_rows");
    let ledger_reserve_ref_present = ledger_entries
        .iter()
        .any(|entry| health_summary_string(&entry.entry_type) == "reserve");
    let ledger_settle_ref_present = ledger_entries
        .iter()
        .any(|entry| health_summary_string(&entry.entry_type) == "settle");
    let ledger_ref_present = !ledger_entries.is_empty();
    let ledger_status = if ledger_settle_ref_present {
        "settled"
    } else if ledger_ref_present {
        "ledger_ref_present_without_settle"
    } else if request_log.status == "succeeded"
        && request_log.final_cost.trim() != "0"
        && request_log.final_cost.trim() != "0.00000000"
    {
        "settlement_missing"
    } else {
        "not_recorded_or_zero_cost"
    };
    let stream_finalizer_status = request_log
        .stream_finalizer
        .get("status")
        .and_then(Value::as_str)
        .map(health_summary_string)
        .unwrap_or_else(|| {
            if request_log.stream_end_reason.is_some() || request_log.partial_sent {
                "recorded".to_string()
            } else {
                "not_recorded".to_string()
            }
        });
    let stream_end_reason_present = request_log.stream_end_reason.is_some()
        || request_log
            .stream_finalizer
            .get("end_reason_present")
            .and_then(Value::as_bool)
            .unwrap_or(false);
    let payload_storage_status = if request_log.payload_stored {
        "stored_metadata_only"
    } else {
        "not_stored_metadata_only"
    };

    json!({
        "schema": "admin_request_trace_timeline_readback.v1",
        "secret_safe": true,
        "source": "request_log_detail_compact_safe_readback",
        "raw_material_returned": false,
        "stages": [
            {
                "stage": "auth_key_profile",
                "category": "auth",
                "status": if request_log.virtual_key_id.is_some() { "authenticated" } else { "not_recorded" },
                "latency": trace_timeline_latency(None, None),
                "refs": {
                    "virtual_key_ref_present": request_log.virtual_key_id.is_some(),
                    "api_key_profile_ref_present": request_log.api_key_profile_id.is_some(),
                    "project_ref_present": request_log.project_id.is_some(),
                    "secret_ref_returned": false
                },
                "safe_next_action": if request_log.virtual_key_id.is_some() {
                    "inspect_profile_route_and_rate_limit_policy_refs"
                } else {
                    "confirm_request_was_authenticated_or_rejected_before_key_resolution"
                }
            },
            {
                "stage": "routing_decision",
                "category": "routing",
                "status": route_status,
                "latency": trace_timeline_latency(None, None),
                "refs": {
                    "route_policy_ref_present": request_log.route_policy_version.is_some(),
                    "selected_channel_ref_present": request_log.resolved_channel_id.is_some(),
                    "selected_provider_ref_present": request_log.resolved_provider_id.is_some(),
                    "canonical_model_ref_present": request_log.canonical_model_id.is_some(),
                    "route_reject_reason_present": route_reject_reason.is_some()
                },
                "safe_next_action": if route_reject_reason.is_some() {
                    "review_model_profile_route_policy_then_retry"
                } else {
                    "inspect_provider_attempts_for_selected_route_outcome"
                }
            },
            {
                "stage": "preauthorize_rate_limit",
                "category": "preauth_rate_limit",
                "status": preauth_status,
                "latency": trace_timeline_latency(None, None),
                "refs": {
                    "rate_limit_ref_present": rate_limit_status != "not_recorded",
                    "ledger_reservation_ref_present": ledger_reserve_ref_present,
                    "provider_attempts_blocked": preauthorize_and_rate_limit_explainability
                        .get("preauthorize")
                        .and_then(|value| value.get("provider_attempts_blocked"))
                        .and_then(Value::as_bool)
                        .unwrap_or(false)
                },
                "safe_next_action": preauth_safe_next_action
            },
            {
                "stage": "provider_attempts_fallback",
                "category": "provider",
                "status": provider_attempt_status,
                "latency": trace_timeline_latency(request_log.latency_ms, request_log.ttft_ms),
                "refs": {
                    "attempt_ref_present": !provider_attempts.is_empty(),
                    "attempt_count": provider_attempts.len(),
                    "selected_attempt_no": selected_attempt_no,
                    "fallback_ref_present": fallback_attempt_count > 0,
                    "fallback_attempt_count": fallback_attempt_count,
                    "first_token_ref_present": provider_attempts.iter().any(|attempt| attempt.ttft_ms.is_some())
                },
                "safe_next_action": provider_safe_next_action
            },
            {
                "stage": "stream_finalizer",
                "category": "streaming",
                "status": stream_finalizer_status,
                "latency": trace_timeline_latency(request_log.latency_ms, request_log.ttft_ms),
                "refs": {
                    "stream": request_log.partial_sent || request_log.stream_end_reason.is_some(),
                    "stream_end_reason_ref_present": stream_end_reason_present,
                    "partial_sent": request_log.partial_sent,
                    "usage_ref_present": request_log
                        .stream_finalizer
                        .get("usage_observed")
                        .and_then(Value::as_bool)
                        .unwrap_or(false),
                    "billing_eligibility_ref_present": request_log
                        .stream_finalizer
                        .get("billing_eligible")
                        .and_then(Value::as_bool)
                        .unwrap_or(false)
                },
                "safe_next_action": if request_log.partial_sent {
                    "inspect_stream_end_reason_before_retrying_or_refunding"
                } else {
                    "use_provider_attempt_and_ledger_stages_for_non_stream_outcome"
                }
            },
            {
                "stage": "ledger_settlement",
                "category": "ledger",
                "status": ledger_status,
                "latency": trace_timeline_latency(None, None),
                "refs": {
                    "ledger_ref_present": ledger_ref_present,
                    "reservation_ref_present": ledger_reserve_ref_present,
                    "settle_ref_present": ledger_settle_ref_present,
                    "entry_count": ledger_entries.len(),
                    "price_version_ref_present": ledger_entries.iter().any(|entry| entry.price_version_id.is_some())
                },
                "safe_next_action": if ledger_status == "settlement_missing" {
                    "review_billing_settle_worker_or_ledger_writer_readback"
                } else {
                    "compare_usage_explainability_with_ledger_summary"
                }
            },
            {
                "stage": "payload_preview_policy",
                "category": "payload_policy",
                "status": payload_storage_status,
                "latency": trace_timeline_latency(None, None),
                "refs": {
                    "payload_policy_ref_present": request_log.payload_policy_id.is_some(),
                    "payload_hash_ref_present": request_log.request_body_hash.is_some() || request_log.response_body_hash.is_some(),
                    "payload_stored": request_log.payload_stored,
                    "raw_material_returned": false,
                    "audit_ref_present": false
                },
                "safe_next_action": if request_log.payload_stored {
                    "use_hash_and_redaction_status_or_explicit_payload_preview_endpoint_metadata"
                } else {
                    "inspect_payload_policy_configuration_and_hash_presence"
                }
            }
        ],
        "omitted_fields": [
            "raw_prompt",
            "raw_body",
            "raw_request_payload",
            "raw_response_payload",
            "raw_provider_response",
            "authorization_header",
            "api_key_secret",
            "provider_key",
            "provider_key_id",
            "raw_metadata",
            "payload_object_ref",
            "provider_attempt_metadata",
            "ledger_metadata"
        ]
    })
}

fn trace_timeline_latency(latency_ms: Option<i32>, ttft_ms: Option<i32>) -> Value {
    json!({
        "recorded": latency_ms.is_some() || ttft_ms.is_some(),
        "latency_ms": latency_ms,
        "ttft_ms": ttft_ms,
    })
}

fn request_usage_explainability_response(
    request_log: &RequestLogSummary,
    provider_attempts: &[ProviderAttemptRead],
    ledger_entries: &[LedgerEntry],
) -> Value {
    let provider_protocol_summary = &request_log.provider_protocol_summary;
    let openai_compat = &request_log.openai_compat;
    let adapter_usage_observed = provider_protocol_summary
        .get("usage_observed")
        .and_then(Value::as_bool)
        .or_else(|| {
            openai_compat
                .get("provider_usage_present")
                .and_then(Value::as_bool)
        })
        .or_else(|| openai_compat.get("usage_present").and_then(Value::as_bool))
        .unwrap_or(false);
    let adapter_usage_recorded = provider_protocol_summary
        .get("usage_recorded")
        .and_then(Value::as_bool)
        .or_else(|| openai_compat.get("usage_recorded").and_then(Value::as_bool))
        .unwrap_or(false);
    let prompt_tokens = provider_protocol_summary
        .get("prompt_tokens")
        .and_then(Value::as_i64)
        .unwrap_or(request_log.input_tokens);
    let completion_tokens = provider_protocol_summary
        .get("completion_tokens")
        .and_then(Value::as_i64)
        .unwrap_or(request_log.output_tokens);
    let ledger_entry_present = !ledger_entries.is_empty();
    let price_version_present = ledger_entries
        .iter()
        .any(|entry| entry.price_version_id.is_some());
    let confirmed_ledger_present = ledger_entries
        .iter()
        .any(|entry| health_summary_string(&entry.status) == "confirmed");
    let provider_attempt_token_total = provider_attempts
        .iter()
        .map(|attempt| attempt.input_tokens + attempt.output_tokens)
        .sum::<i64>();
    let request_token_total = request_log.input_tokens + request_log.output_tokens;
    let provider_attempt_usage_present = provider_attempts
        .iter()
        .any(|attempt| attempt.input_tokens > 0 || attempt.output_tokens > 0);
    let fallback_attempt_present = provider_attempts
        .iter()
        .any(|attempt| attempt.fallback_reason.is_some());

    let mut mismatch_reasons = BTreeSet::new();
    if !adapter_usage_observed && request_token_total > 0 {
        mismatch_reasons.insert("adapter_usage_missing_gateway_token_columns_used");
    }
    if provider_attempt_usage_present && provider_attempt_token_total != request_token_total {
        mismatch_reasons.insert("provider_attempt_token_sum_differs_from_request_log");
    }
    if request_log.status == "succeeded" && request_token_total > 0 && !ledger_entry_present {
        mismatch_reasons.insert("succeeded_usage_without_ledger_ref");
    }
    if ledger_entry_present && !price_version_present {
        mismatch_reasons.insert("ledger_ref_without_price_version_ref");
    }
    if request_log.final_cost.trim() != "0"
        && request_log.final_cost.trim() != "0.00000000"
        && !ledger_entry_present
    {
        mismatch_reasons.insert("final_cost_present_without_ledger_ref");
    }
    if fallback_attempt_present {
        mismatch_reasons.insert("provider_fallback_attempt_recorded");
    }
    mismatch_reasons.insert("cache_reasoning_embedding_columns_not_in_detail_projection");

    let rating_status = if confirmed_ledger_present && price_version_present {
        "rated_and_ledger_ref_present"
    } else if ledger_entry_present {
        "ledger_ref_present_rating_ref_partial"
    } else if request_log.final_cost.trim() == "0" || request_log.final_cost.trim() == "0.00000000"
    {
        "not_rated_or_zero_cost"
    } else {
        "rated_without_ledger_ref"
    };

    json!({
        "schema": "admin_request_usage_explainability_v1",
        "secret_safe": true,
        "source": "request_log_detail_safe_read_model",
        "endpoint": request_usage_endpoint_summary(request_log),
        "adapter_usage": {
            "observed": adapter_usage_observed,
            "recorded": adapter_usage_recorded,
            "source": if adapter_usage_observed { "adapter_usage_projection" } else { "not_observed" },
        },
        "gateway_fallback": {
            "used": !adapter_usage_observed && request_token_total > 0,
            "source": if !adapter_usage_observed && request_token_total > 0 {
                "request_logs_token_columns"
            } else {
                "not_used"
            },
        },
        "tokens": {
            "prompt": request_usage_token_source("prompt", Some(prompt_tokens), adapter_usage_observed),
            "completion": request_usage_token_source("completion", Some(completion_tokens), adapter_usage_observed),
            "cache": request_usage_token_source("cache", None, false),
            "reasoning": request_usage_token_source("reasoning", None, false),
            "embedding": request_usage_token_source("embedding", None, false),
        },
        "provider_attempts": {
            "count": provider_attempts.len(),
            "usage_present": provider_attempt_usage_present,
            "token_sum": provider_attempt_token_total,
            "fallback_attempt_present": fallback_attempt_present,
        },
        "rating": {
            "status": rating_status,
            "final_cost": health_summary_string(&request_log.final_cost),
            "currency": health_summary_string(&request_log.currency),
            "price_version_ref_present": price_version_present,
        },
        "ledger": {
            "ref_present": ledger_entry_present,
            "confirmed_ref_present": confirmed_ledger_present,
            "entry_count": ledger_entries.len(),
            "source": "ledger_entries_by_request_id",
        },
        "safe_mismatch_reasons": mismatch_reasons.into_iter().collect::<Vec<_>>(),
        "omitted_fields": [
            "prompt_material",
            "request_body_material",
            "provider_response_material",
            "auth_header_material",
            "provider_credential_material",
            "ledger_usage_snapshot",
            "ledger_policy_snapshot",
            "ledger_metadata"
        ],
    })
}

fn provider_attempts_explainability_response(
    request_log: &RequestLogSummary,
    provider_attempts: &[ProviderAttemptRead],
) -> Value {
    let attempt_count = provider_attempts.len();
    let selected_attempt_no = provider_attempts
        .iter()
        .find(|attempt| attempt.status == "succeeded")
        .or_else(|| provider_attempts.last())
        .map(|attempt| attempt.attempt_no);
    let fallback_attempt_count = provider_attempts
        .iter()
        .filter(|attempt| attempt.fallback_reason.is_some())
        .count();
    let retryable_attempt_count = provider_attempts
        .iter()
        .filter(|attempt| attempt.retryable == Some(true))
        .count();
    let first_token_observed = provider_attempts
        .iter()
        .any(|attempt| attempt.ttft_ms.is_some());
    let latency_observed = provider_attempts
        .iter()
        .any(|attempt| attempt.latency_ms.is_some());

    let sequence = provider_attempts
        .iter()
        .map(|attempt| {
            json!({
                "attempt_no": attempt.attempt_no,
                "role": if Some(attempt.attempt_no) == selected_attempt_no {
                    "selected"
                } else if attempt.fallback_reason.is_some() {
                    "fallback"
                } else {
                    "candidate"
                },
                "provider": {
                    "id": attempt.provider_id,
                    "present": attempt.provider_id.is_some(),
                },
                "channel": {
                    "id": attempt.channel_id,
                    "present": attempt.channel_id.is_some(),
                },
                "status": attempt.status,
                "http_status": attempt.http_status,
                "retryable": attempt.retryable,
                "error_category": provider_attempt_error_category(attempt),
                "error_owner": attempt.error_owner.as_deref().map(health_summary_string),
                "error_code": attempt.error_code.as_deref().map(health_summary_string),
                "fallback_reason": attempt.fallback_reason.as_deref().map(health_summary_string),
                "latency": {
                    "recorded": attempt.latency_ms.is_some(),
                    "latency_ms": attempt.latency_ms,
                    "first_token_recorded": attempt.ttft_ms.is_some(),
                    "ttft_ms": attempt.ttft_ms,
                },
            })
        })
        .collect::<Vec<_>>();
    let fallback_sequence = provider_attempts
        .iter()
        .filter(|attempt| attempt.fallback_reason.is_some())
        .map(|attempt| {
            json!({
                "attempt_no": attempt.attempt_no,
                "provider_id": attempt.provider_id,
                "channel_id": attempt.channel_id,
                "status": attempt.status,
                "fallback_reason": attempt.fallback_reason.as_deref().map(health_summary_string),
                "retryable": attempt.retryable,
                "error_category": provider_attempt_error_category(attempt),
                "first_token_recorded": attempt.ttft_ms.is_some(),
            })
        })
        .collect::<Vec<_>>();

    json!({
        "schema": "admin_provider_attempts_explainability_v1",
        "secret_safe": true,
        "source": "request_log_detail_provider_attempts_safe_projection",
        "attempt_count": attempt_count,
        "selected_attempt_no": selected_attempt_no,
        "fallback_attempt_count": fallback_attempt_count,
        "retryable_attempt_count": retryable_attempt_count,
        "latency_observed": latency_observed,
        "first_token_observed": first_token_observed,
        "selected_fallback_sequence": sequence,
        "fallback_sequence": fallback_sequence,
        "provider_channel_status": {
            "attempts_recorded": attempt_count > 0,
            "selected_provider_id": selected_attempt_no.and_then(|attempt_no| {
                provider_attempts
                    .iter()
                    .find(|attempt| attempt.attempt_no == attempt_no)
                    .and_then(|attempt| attempt.provider_id)
            }),
            "selected_channel_id": selected_attempt_no.and_then(|attempt_no| {
                provider_attempts
                    .iter()
                    .find(|attempt| attempt.attempt_no == attempt_no)
                    .and_then(|attempt| attempt.channel_id)
            }),
            "terminal_status": provider_attempts
                .last()
                .map(|attempt| health_summary_string(&attempt.status))
                .unwrap_or_else(|| "not_recorded".to_string()),
        },
        "safe_next_action": provider_attempts_safe_next_action(
            request_log,
            provider_attempts,
            first_token_observed,
            retryable_attempt_count,
        ),
        "omitted_fields": [
            "endpoint_raw_url",
            "authorization_header",
            "provider_key",
            "provider_key_id",
            "provider_request_id",
            "raw_request_payload",
            "raw_response_payload",
            "raw_provider_response",
            "provider_attempt_metadata"
        ],
    })
}

fn provider_attempt_error_category(attempt: &ProviderAttemptRead) -> String {
    if let Some(owner) = attempt.error_owner.as_deref() {
        let owner = owner.to_ascii_lowercase();
        if owner.contains("provider") {
            return "provider_error".to_string();
        }
        if owner.contains("gateway") {
            return "gateway_error".to_string();
        }
        if owner.contains("client") || owner.contains("request") {
            return "client_error".to_string();
        }
    }
    match attempt.http_status {
        Some(429) => "rate_limited".to_string(),
        Some(400..=499) => "client_error".to_string(),
        Some(500..=599) => "provider_error".to_string(),
        _ if attempt.error_code.is_some() => "classified_by_error_code".to_string(),
        _ if attempt.status == "succeeded" => "none".to_string(),
        _ => "unknown".to_string(),
    }
}

fn provider_attempts_safe_next_action(
    request_log: &RequestLogSummary,
    provider_attempts: &[ProviderAttemptRead],
    first_token_observed: bool,
    retryable_attempt_count: usize,
) -> &'static str {
    if provider_attempts.is_empty() {
        "inspect_preauthorize_rate_limit_or_route_reject_before_provider_call"
    } else if provider_attempts
        .iter()
        .any(|attempt| attempt.status == "succeeded")
    {
        "no_action_request_completed"
    } else if first_token_observed {
        "do_not_blindly_retry_after_first_token_inspect_streaming_partial_delivery"
    } else if retryable_attempt_count > 0 {
        "retry_or_fallback_is_safe_before_first_token_if_policy_allows"
    } else if request_log.status == "failed" {
        "inspect_non_retryable_error_and_provider_channel_health"
    } else {
        "inspect_trace_summary_and_provider_attempt_rows"
    }
}

fn preauthorize_and_rate_limit_explainability_response(
    request_log: &RequestLogSummary,
    provider_attempts: &[ProviderAttemptRead],
    ledger_entries: &[LedgerEntry],
    route_decision_snapshot: &Value,
) -> Value {
    let rate_limit = &request_log.rate_limit_metadata;
    let fallback_reasons = provider_attempts
        .iter()
        .filter_map(|attempt| attempt.fallback_reason.as_deref())
        .filter(|reason| !reason.trim().is_empty())
        .map(health_summary_string)
        .collect::<BTreeSet<_>>();
    let route_summary = route_decision_snapshot
        .get("summary")
        .unwrap_or(&Value::Null);
    let route_reject_reason = first_safe_json_string(
        route_summary,
        &["reject_reason", "reject_code", "rejection_reason"],
    );
    let route_fallback_reason = first_safe_json_string(
        route_summary,
        &["fallback_reason", "fallback_status", "fallback_code"],
    );
    let preauth_reject_reason = preauthorize_reject_reason(request_log);
    let billing_refusal_reason = billing_refusal_reason(request_log, ledger_entries);
    let ledger_reserve_ref_present = ledger_entries
        .iter()
        .any(|entry| health_summary_string(&entry.entry_type) == "reserve");
    let ledger_settle_ref_present = ledger_entries
        .iter()
        .any(|entry| health_summary_string(&entry.entry_type) == "settle");
    let ledger_ref_present = !ledger_entries.is_empty();
    let balance_status = preauthorize_balance_status(request_log, ledger_entries);
    let budget_status = preauthorize_budget_status(request_log);
    let preauth_status = preauthorize_status(request_log, ledger_entries);
    let rate_limit_status = rate_limit
        .get("status")
        .and_then(Value::as_str)
        .map(health_summary_string)
        .unwrap_or_else(|| "not_recorded".to_string());
    let reject_reason = preauth_reject_reason
        .as_deref()
        .or(route_reject_reason.as_deref())
        .or_else(|| request_log.error_code.as_deref())
        .map(health_summary_string);

    json!({
        "schema": "admin_preauthorize_and_rate_limit_explainability_v1",
        "secret_safe": true,
        "source": "request_log_detail_safe_read_model",
        "preauthorize": {
            "status": preauth_status,
            "balance": {
                "status": balance_status,
                "source": "request_log_error_and_ledger_ref_presence",
                "amount_omitted": true,
            },
            "budget": {
                "status": budget_status,
                "source": "request_log_error_code_only",
                "amount_omitted": true,
            },
            "reject_reason": preauth_reject_reason,
            "provider_attempts_blocked": preauth_reject_reason.is_some() && provider_attempts.is_empty(),
        },
        "rate_limit_reservation": {
            "status": rate_limit_status,
            "scope": rate_limit.get("scope").and_then(Value::as_str).unwrap_or("virtual_key"),
            "retry_after_ms": rate_limit.get("retry_after_ms").and_then(Value::as_u64),
            "window_status": rate_limit.get("window_status").and_then(Value::as_str).unwrap_or("not_recorded"),
            "concurrency": rate_limit_dimension_explainability(rate_limit, "concurrency"),
            "rpm": rate_limit_dimension_explainability(rate_limit, "rpm"),
            "tpm": rate_limit_dimension_explainability(rate_limit, "tpm"),
        },
        "fallback_or_reject": {
            "fallback_present": !fallback_reasons.is_empty() || route_fallback_reason.is_some(),
            "fallback_reasons": fallback_reasons.into_iter().collect::<Vec<_>>(),
            "route_fallback_reason": route_fallback_reason,
            "reject_reason": reject_reason,
            "route_reject_reason": route_reject_reason,
            "billing_refusal_reason": billing_refusal_reason,
        },
        "safe_next_action": preauthorize_rate_limit_safe_next_action(
            request_log,
            rate_limit,
            preauth_reject_reason.as_deref(),
            route_reject_reason.as_deref(),
            ledger_ref_present,
        ),
        "ledger_refs": {
            "reservation_ref_present": ledger_reserve_ref_present,
            "settle_ref_present": ledger_settle_ref_present,
            "any_ledger_ref_present": ledger_ref_present,
            "entry_count": ledger_entries.len(),
            "source": "ledger_entries_by_request_id",
        },
        "omitted_fields": [
            "key_material",
            "auth_header_material",
            "request_body_material",
            "response_body_material",
            "wallet_credential_material",
            "provider_credential_material",
            "raw_rate_limit_window",
            "raw_route_decision_snapshot",
            "ledger_metadata",
            "ledger_idempotency_key"
        ],
    })
}

fn preauthorize_status(request_log: &RequestLogSummary, ledger_entries: &[LedgerEntry]) -> String {
    if preauthorize_reject_reason(request_log).is_some() {
        "rejected".to_string()
    } else if !ledger_entries.is_empty() || request_log.status == "succeeded" {
        "authorized_or_not_required".to_string()
    } else {
        "not_recorded".to_string()
    }
}

fn preauthorize_balance_status(
    request_log: &RequestLogSummary,
    ledger_entries: &[LedgerEntry],
) -> String {
    match preauthorize_reject_reason(request_log).as_deref() {
        Some("insufficient_wallet_balance") => "insufficient".to_string(),
        Some("insufficient_budget") => "not_rejected_by_balance".to_string(),
        _ if ledger_entries.iter().any(|entry| entry.wallet_id.is_some()) => {
            "ref_present".to_string()
        }
        _ if request_log.status == "succeeded" => "passed_or_not_required".to_string(),
        _ => "not_recorded".to_string(),
    }
}

fn preauthorize_budget_status(request_log: &RequestLogSummary) -> String {
    match preauthorize_reject_reason(request_log).as_deref() {
        Some("insufficient_budget") => "insufficient".to_string(),
        Some("insufficient_wallet_balance") => "not_rejected_by_budget".to_string(),
        _ if request_log.status == "succeeded" => "passed_or_not_required".to_string(),
        _ => "not_recorded".to_string(),
    }
}

fn preauthorize_reject_reason(request_log: &RequestLogSummary) -> Option<String> {
    let error = request_log
        .error_code
        .as_deref()
        .or(request_log.error_owner.as_deref())
        .unwrap_or_default()
        .to_ascii_lowercase();
    if error.contains("budget") {
        Some("insufficient_budget".to_string())
    } else if error.contains("insufficient_balance")
        || error.contains("insufficient-wallet")
        || error.contains("wallet")
        || error.contains("balance")
    {
        Some("insufficient_wallet_balance".to_string())
    } else {
        None
    }
}

fn billing_refusal_reason(
    request_log: &RequestLogSummary,
    ledger_entries: &[LedgerEntry],
) -> Option<String> {
    if let Some(reason) = preauthorize_reject_reason(request_log) {
        return Some(reason);
    }
    if request_log.final_cost.trim() != "0"
        && request_log.final_cost.trim() != "0.00000000"
        && ledger_entries.is_empty()
    {
        return Some("rated_cost_without_ledger_ref".to_string());
    }
    None
}

fn rate_limit_dimension_explainability(rate_limit: &Value, dimension: &str) -> Value {
    let summary = rate_limit.get(dimension).unwrap_or(&Value::Null);
    json!({
        "status": summary
            .get("status")
            .and_then(Value::as_str)
            .map(health_summary_string)
            .unwrap_or_else(|| "not_recorded".to_string()),
        "limit": summary.get("limit").and_then(Value::as_i64),
        "used": summary.get("used").and_then(Value::as_i64),
        "remaining": summary.get("remaining").and_then(Value::as_i64),
        "required": summary.get("required").and_then(Value::as_i64),
        "retry_after_ms": summary.get("retry_after_ms").and_then(Value::as_u64),
        "window_seconds": summary.get("window_seconds").and_then(Value::as_u64),
        "window_status": summary
            .get("window_status")
            .and_then(Value::as_str)
            .map(health_summary_string)
            .unwrap_or_else(|| "not_recorded".to_string()),
        "reservation_status": match summary.get("status").and_then(Value::as_str) {
            Some("ok") => "reserved_or_available",
            Some("limited") => "rejected",
            Some("not_applied") => "attempted_not_reserved",
            Some("configured") => "configured_not_attempted",
            Some("not_configured") => "not_configured",
            _ => "not_recorded",
        },
    })
}

fn preauthorize_rate_limit_safe_next_action(
    request_log: &RequestLogSummary,
    rate_limit: &Value,
    preauth_reject_reason: Option<&str>,
    route_reject_reason: Option<&str>,
    ledger_ref_present: bool,
) -> &'static str {
    if matches!(preauth_reject_reason, Some("insufficient_wallet_balance")) {
        "top_up_wallet_or_lower_request_cost_then_retry"
    } else if matches!(preauth_reject_reason, Some("insufficient_budget")) {
        "increase_budget_or_wait_for_budget_window_then_retry"
    } else if rate_limit.get("status").and_then(Value::as_str) == Some("limited") {
        "wait_for_retry_after_or_reduce_rpm_tpm_concurrency"
    } else if route_reject_reason.is_some() {
        "review_model_profile_route_policy_then_retry"
    } else if request_log.status == "succeeded" && !ledger_ref_present {
        "review_billing_settle_worker_or_ledger_writer_readback"
    } else {
        "inspect_provider_attempts_or_trace_summary_if_issue_persists"
    }
}

fn first_safe_json_string(value: &Value, fields: &[&str]) -> Option<String> {
    fields
        .iter()
        .find_map(|field| value.get(*field).and_then(Value::as_str))
        .filter(|text| !text.trim().is_empty() && *text != "none")
        .map(health_summary_string)
}

fn request_usage_endpoint_summary(request_log: &RequestLogSummary) -> Value {
    json!({
        "inbound_protocol": request_log.inbound_protocol.as_deref(),
        "outbound_protocol": request_log.outbound_protocol.as_deref(),
        "protocol_mode": request_log.protocol_mode.as_deref(),
        "provider_protocol": request_log
            .provider_protocol_summary
            .get("provider_protocol")
            .and_then(Value::as_str),
        "downstream_protocol": request_log
            .provider_protocol_summary
            .get("downstream_protocol")
            .and_then(Value::as_str),
        "openai_compat_endpoint": request_log
            .openai_compat
            .get("endpoint")
            .and_then(Value::as_str),
        "requested_model_present": request_log.requested_model.is_some(),
        "upstream_model_present": request_log.upstream_model.is_some(),
    })
}

fn request_usage_token_source(category: &str, tokens: Option<i64>, adapter_usage: bool) -> Value {
    let recorded = tokens.is_some();
    let source = match (recorded, adapter_usage) {
        (true, true) => "adapter_usage_projection",
        (true, false) => "gateway_request_log_fallback",
        (false, _) => "not_recorded",
    };
    let reason = match category {
        "cache" | "reasoning" | "embedding" if !recorded => {
            "not_available_in_request_detail_safe_projection"
        }
        _ if recorded => "token_count_recorded",
        _ => "not_recorded",
    };

    json!({
        "tokens": tokens,
        "source": source,
        "recorded": recorded,
        "adapter_usage": adapter_usage,
        "safe_mismatch_reason": reason,
    })
}

