fn request_payload_preview_response(request_log: &RequestLogSummary) -> Value {
    json!({
        "available": false,
        "request_id": request_log.id,
        "payload_stored": request_log.payload_stored,
        "payload_policy_id": request_log.payload_policy_id,
        "redaction_status": request_log.redaction_status,
        "request_body_hash": request_log.request_body_hash,
        "response_body_hash": request_log.response_body_hash,
        "omitted_fields": [
            "raw_request_payload",
            "raw_response_payload",
            "payload_object_ref",
            "raw_prompt",
            "raw_body",
            "raw_provider_response",
            "authorization_header",
            "provider_key"
        ],
        "payload_preview_policy_readback": {
            "schema": "payload_preview_policy_readback.v1",
            "status": if request_log.payload_stored { "stored_metadata_only" } else { "not_stored_metadata_only" },
            "storage_status": if request_log.payload_stored { "stored" } else { "not_stored" },
            "redaction_status": request_log.redaction_status,
            "metadata_only": true,
            "click_to_load_required": true,
            "click_to_load_endpoint": "/admin/request-logs/{id}/payload",
            "raw_material_returned": false,
            "forbidden_raw_fields_policy": {
                "raw_prompt_returned": false,
                "raw_body_returned": false,
                "raw_request_payload_returned": false,
                "raw_response_payload_returned": false,
                "raw_provider_response_returned": false,
                "authorization_header_returned": false,
                "provider_key_returned": false,
                "provider_key_id_returned": false,
                "forbidden_fields": [
                    "raw_prompt",
                    "raw_body",
                    "raw_request_payload",
                    "raw_response_payload",
                    "raw_provider_response",
                    "authorization_header",
                    "provider_key",
                    "provider_key_id",
                    "payload_object_ref"
                ]
            },
            "audit_ref_presence": {
                "audit_ref_present": false,
                "audit_action": "request_log.payload_preview",
                "status": "not_written_for_metadata_only_readback",
                "reason": "this endpoint returns metadata-only readback and does not load raw payload material"
            },
            "safe_next_action": if request_log.payload_stored {
                "Use the hash and redaction status for diagnostics; request raw payload material through an audited break-glass workflow outside this endpoint."
            } else {
                "Inspect payload policy configuration and request hashes; no payload preview object is available for this request."
            },
            "secret_safe": true
        },
        "metadata": {
            "mode": "metadata_only",
            "raw_request_payload_returned": false,
            "raw_response_payload_returned": false,
            "raw_prompt_returned": false,
            "raw_body_returned": false,
            "raw_provider_response_returned": false,
            "authorization_header_returned": false,
            "provider_key_returned": false,
            "audit_ref_present": false
        }
    })
}

fn request_logs_csv(request_logs: &[RequestLogSummary]) -> String {
    let mut csv = String::new();
    push_csv_row(&mut csv, REQUEST_LOG_EXPORT_ALLOWED_COLUMNS);

    for log in request_logs {
        let row = [
            log.id.to_string(),
            log.created_at.clone(),
            log.completed_at.clone().unwrap_or_default(),
            log.status.clone(),
            log.http_status
                .map(|value| value.to_string())
                .unwrap_or_default(),
            log.requested_model.clone().unwrap_or_default(),
            log.canonical_model_id
                .map(|value| value.to_string())
                .unwrap_or_default(),
            log.resolved_channel_id
                .map(|value| value.to_string())
                .unwrap_or_default(),
            log.virtual_key_id
                .map(|value| value.to_string())
                .unwrap_or_default(),
            log.api_key_profile_id
                .map(|value| value.to_string())
                .unwrap_or_default(),
            log.trace_id.clone().unwrap_or_default(),
            log.client_request_id.clone().unwrap_or_default(),
            request_log_stream_summary(log),
            log.latency_ms
                .map(|value| value.to_string())
                .unwrap_or_default(),
            log.ttft_ms
                .map(|value| value.to_string())
                .unwrap_or_default(),
            log.input_tokens.to_string(),
            log.output_tokens.to_string(),
            log.final_cost.clone(),
            log.currency.clone(),
            log.error_owner.clone().unwrap_or_default(),
            log.error_code.clone().unwrap_or_default(),
            log.redaction_status.clone(),
        ];
        push_csv_row(&mut csv, row.iter().map(String::as_str));
    }

    csv
}

fn request_log_stream_summary(log: &RequestLogSummary) -> String {
    if log.partial_sent {
        return log
            .stream_end_reason
            .as_ref()
            .map(|reason| format!("partial/{reason}"))
            .unwrap_or_else(|| "partial".to_string());
    }

    log.stream_end_reason
        .as_ref()
        .map(|reason| format!("stream/{reason}"))
        .unwrap_or_else(|| "non_stream".to_string())
}

fn push_csv_row<'a, I>(csv: &mut String, cells: I)
where
    I: IntoIterator<Item = &'a str>,
{
    let mut first = true;
    for cell in cells {
        if !first {
            csv.push(',');
        }
        first = false;
        csv.push('"');
        for ch in cell.chars() {
            if ch == '"' {
                csv.push('"');
            }
            csv.push(ch);
        }
        csv.push('"');
    }
    csv.push('\n');
}

async fn get_trace_request_summary(
    State(state): State<Arc<ControlPlaneState>>,
    Path(trace_id): Path<String>,
    Query(query): Query<TraceRequestSummaryQuery>,
) -> Result<Response, AdminError> {
    let filter = query.into_filter(trace_id)?;
    let limit = filter.limit;
    let trace_id = filter.trace_id.clone();
    let request_logs = repo(&state)
        .list_request_logs_for_trace(DEFAULT_TENANT_ID, filter)
        .await?;

    if request_logs.is_empty() {
        return Err(AdminError::not_found("request trace"));
    }

    let request_ids = request_logs.iter().map(|log| log.id).collect::<Vec<_>>();
    let ledger_entries =
        list_ledger_entries_for_request_ids(state.as_ref(), DEFAULT_TENANT_ID, &request_ids)
            .await?;

    Ok(Json(json!({
        "data": trace_request_summary_response(&trace_id, &request_logs, limit, &ledger_entries)
    }))
    .into_response())
}

