async fn create_subscription_plan(
    State(state): State<Arc<ControlPlaneState>>,
    Json(request): Json<CreateSubscriptionPlanRequest>,
) -> Result<Response, AdminError> {
    let plan_code = non_empty(request.plan_code, "plan_code")?;
    let display_name = non_empty(request.display_name, "display_name")?;
    let status =
        normalize_subscription_plan_status(request.status.unwrap_or_else(|| "draft".to_string()))?;
    let currency = normalize_subscription_currency(request.currency)?;
    let billing_interval = normalize_subscription_billing_interval(request.billing_interval)?;
    let unit_price = normalize_positive_money_amount("unit_price", request.unit_price)?;
    let included_credit_amount = normalize_non_negative_money_amount(
        "included_credit_amount",
        request.included_credit_amount,
    )?;
    let trial_days = normalize_subscription_trial_days(request.trial_days)?;
    let request_summary = normalize_subscription_plan_json(
        request.request_summary,
        "request_summary",
        subscription_default_request_summary(&billing_interval),
    )?;
    let metadata = normalize_subscription_plan_json(
        request.metadata,
        "metadata",
        subscription_default_metadata(),
    )?;

    let row = sqlx::query(
        r#"
        insert into subscription_plans (
          tenant_id, plan_code, display_name, status, currency, billing_interval,
          unit_price, included_credit_amount, trial_days, request_summary, metadata
        )
        values ($1, $2, $3, $4, $5, $6, $7::numeric, $8::numeric, $9, $10::jsonb, $11::jsonb)
        returning id, tenant_id, plan_code, display_name, status, currency, billing_interval,
          unit_price::text as unit_price, included_credit_amount::text as included_credit_amount,
          trial_days, request_summary, metadata, created_at::text as created_at, updated_at::text as updated_at
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(plan_code)
    .bind(display_name)
    .bind(status)
    .bind(currency)
    .bind(billing_interval)
    .bind(unit_price)
    .bind(included_credit_amount)
    .bind(trial_days)
    .bind(request_summary)
    .bind(metadata)
    .fetch_one(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok((
        StatusCode::CREATED,
        Json(json!({
            "data": subscription_plan_response(row)?,
            "meta": subscription_plan_api_meta("admin_subscription_plan_create.v1")
        })),
    )
        .into_response())
}

async fn patch_subscription_plan(
    State(state): State<Arc<ControlPlaneState>>,
    Path(id): Path<Uuid>,
    Json(request): Json<PatchSubscriptionPlanRequest>,
) -> Result<Response, AdminError> {
    let display_name = request
        .display_name
        .map(|value| non_empty(value, "display_name"))
        .transpose()?;
    let status = request
        .status
        .map(normalize_subscription_plan_status)
        .transpose()?;
    let currency = request
        .currency
        .map(normalize_subscription_currency)
        .transpose()?;
    let billing_interval = request
        .billing_interval
        .map(normalize_subscription_billing_interval)
        .transpose()?;
    let unit_price = request
        .unit_price
        .map(|value| normalize_positive_money_amount("unit_price", value))
        .transpose()?;
    let included_credit_amount = request
        .included_credit_amount
        .map(|value| normalize_non_negative_money_amount("included_credit_amount", value))
        .transpose()?;
    let trial_days = request
        .trial_days
        .map(|value| normalize_subscription_trial_days(Some(value)))
        .transpose()?;
    let request_summary = request
        .request_summary
        .map(|value| normalize_subscription_plan_json(Some(value), "request_summary", json!({})))
        .transpose()?;
    let metadata = request
        .metadata
        .map(|value| normalize_subscription_plan_json(Some(value), "metadata", json!({})))
        .transpose()?;

    let row = sqlx::query(
        r#"
        update subscription_plans
        set
          display_name = coalesce($3, display_name),
          status = coalesce($4, status),
          currency = coalesce($5, currency),
          billing_interval = coalesce($6, billing_interval),
          unit_price = coalesce($7::numeric, unit_price),
          included_credit_amount = coalesce($8::numeric, included_credit_amount),
          trial_days = coalesce($9, trial_days),
          request_summary = coalesce($10::jsonb, request_summary),
          metadata = coalesce($11::jsonb, metadata),
          updated_at = now()
        where tenant_id = $1 and id = $2
        returning id, tenant_id, plan_code, display_name, status, currency, billing_interval,
          unit_price::text as unit_price, included_credit_amount::text as included_credit_amount,
          trial_days, request_summary, metadata, created_at::text as created_at, updated_at::text as updated_at
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(id)
    .bind(display_name)
    .bind(status)
    .bind(currency)
    .bind(billing_interval)
    .bind(unit_price)
    .bind(included_credit_amount)
    .bind(trial_days)
    .bind(request_summary)
    .bind(metadata)
    .fetch_optional(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?
    .ok_or_else(|| AdminError::not_found("subscription plan"))?;

    Ok(Json(json!({
        "data": subscription_plan_response(row)?,
        "meta": subscription_plan_api_meta("admin_subscription_plan_patch.v1")
    }))
    .into_response())
}

async fn plan_subscription_scheduler(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<SubscriptionSchedulerPlanRequest>,
) -> Result<Response, AdminError> {
    let mode = normalize_subscription_scheduler_mode(request.mode)?;
    let apply = mode == "apply";
    session
        .require_permission(if apply {
            Permission::BillingAdjust
        } else {
            Permission::BillingRead
        })
        .map_err(|_| {
            AdminError::forbidden(if apply {
                "billing_adjust permission is required"
            } else {
                "billing_read permission is required"
            })
        })?;
    let action = normalize_subscription_scheduler_action(request.action)?;
    let limit = billing_read_limit(request.limit)?;
    let reason = request
        .reason
        .map(|value| non_empty(value, "reason"))
        .transpose()?;
    if apply && reason.is_none() {
        return Err(AdminError::bad_request("reason is required for apply mode"));
    }
    if action == "proration" && request.target_plan_id.is_none() {
        return Err(AdminError::bad_request(
            "target_plan_id is required when action is proration",
        ));
    }

    let rows = sqlx::query(
        r#"
        select s.id as subscription_id,
               s.project_id,
               s.wallet_id,
               s.plan_id,
               s.package_id,
               s.status,
               s.currency,
               s.current_period_start::text as current_period_start,
               s.current_period_end::text as current_period_end,
               s.current_period_end as renewal_effective_at,
               (s.current_period_end <= now()) as renewal_due,
               (s.current_period_end > now() and s.current_period_end <= now() + interval '7 days') as renewal_upcoming,
               (s.status = 'payment_failed' and now() <= s.current_period_end + interval '3 days') as in_grace,
               (s.status = 'payment_failed' and now() > s.current_period_end + interval '3 days') as in_dunning,
               (s.current_period_end + interval '3 days')::text as grace_ends_at,
               (s.current_period_end + interval '4 days')::text as next_dunning_attempt_at,
               (s.current_period_end + interval '4 days') as dunning_effective_at,
               (s.current_period_end + interval '7 days')::text as expire_at,
               (s.current_period_end + interval '7 days') as expire_effective_at,
               p.plan_code,
               p.billing_interval,
               p.unit_price::text as unit_price,
               p.included_credit_amount::text as included_credit_amount,
               (
                 select count(*)::bigint
                 from subscription_events_or_schedules e
                 where e.tenant_id = s.tenant_id
                   and e.subscription_id = s.id
                   and e.event_status = 'scheduled'
               ) as scheduled_event_count
        from subscriptions s
        join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
        where s.tenant_id = $1
          and ($2::uuid is null or s.id = $2)
          and s.status in ('created', 'trialing', 'active', 'renewed', 'resumed', 'payment_failed')
        order by
          case
            when s.current_period_end <= now() then 0
            when s.status = 'payment_failed' then 1
            else 2
          end,
          s.current_period_end asc,
          s.updated_at desc
        limit $3
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(request.subscription_id)
    .bind(limit)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let mut candidates = Vec::new();
    let mut applied_events = Vec::new();
    for row in rows {
        let candidate =
            subscription_scheduler_candidate_response(&row, &action, request.target_plan_id)?;
        if apply {
            let writes = subscription_scheduler_apply_events(
                state.db(),
                &row,
                &action,
                request.target_plan_id,
                reason.as_deref().unwrap_or("subscription scheduler apply"),
            )
            .await?;
            applied_events.extend(writes);
        }
        candidates.push(candidate);
    }

    Ok(Json(json!({
        "data": {
            "schema": "admin_subscription_scheduler_plan.v1",
            "mode": mode,
            "action": action,
            "tenant_id": DEFAULT_TENANT_ID,
            "subscription_id": request.subscription_id,
            "target_plan_id": request.target_plan_id,
            "candidate_count": candidates.len(),
            "candidates": candidates,
            "apply_result": {
                "applied": apply,
                "scheduled_event_count": applied_events.len(),
                "events": applied_events,
                "writes_limited_to": ["subscription_events_or_schedules"],
                "subscription_rows_updated": false,
                "invoice_order_ledger_credit_writes": false
            },
            "status": if apply { "scheduled" } else { "planned" },
            "next_action": if apply {
                "Scheduled events were written for local scheduler readback. Payment capture, invoice/order creation, ledger settlement, and credit grants remain explicit future runtimes."
            } else {
                "Review candidate next_action values, then call again with mode=apply and a reason to write scheduled events only."
            },
            "secret_safe": true,
            "raw_payment_payload_returned": false,
            "raw_provider_payload_returned": false,
            "authorization_returned": false,
            "raw_idempotency_key_echoed": false
        }
    }))
    .into_response())
}

async fn get_subscription_scheduler_worker_handoff(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Query(query): Query<SubscriptionSchedulerWorkerQuery>,
) -> Result<Response, AdminError> {
    session
        .require_permission(Permission::BillingRead)
        .map_err(|_| AdminError::forbidden("billing_read permission is required"))?;
    let limit = billing_read_limit(query.limit)?;
    let event_status = normalize_subscription_scheduler_worker_status(query.event_status)?;
    let event_type = normalize_subscription_scheduler_worker_event_type(query.event_type)?;
    let worker_id = query
        .worker_id
        .map(|value| non_empty(value, "worker_id"))
        .transpose()?;

    let rows = sqlx::query(
        r#"
        select e.id,
               e.subscription_id,
               e.event_type,
               e.event_status,
               e.effective_at::text as effective_at,
               e.idempotency_key_hash,
               e.credit_grant_id,
               e.ledger_entry_id,
               e.invoice_id,
               e.order_id,
               e.audit_id,
               e.refusal_code,
               e.request_summary,
               e.metadata,
               e.created_at::text as created_at,
               e.updated_at::text as updated_at,
               (e.effective_at <= now()) as due_now,
               s.project_id,
               s.wallet_id,
               s.plan_id,
               s.status as subscription_status,
               s.current_period_start::text as current_period_start,
               s.current_period_end::text as current_period_end,
               p.plan_code,
               p.billing_interval,
               p.currency,
               p.unit_price::text as unit_price,
               p.included_credit_amount::text as included_credit_amount
        from subscription_events_or_schedules e
        join subscriptions s on s.tenant_id = e.tenant_id and s.id = e.subscription_id
        join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
        where e.tenant_id = $1
          and e.event_status = $2
          and e.event_type = any($3::text[])
          and e.effective_at <= now()
        order by
          e.effective_at asc,
          e.updated_at asc
        limit $4
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(&event_status)
    .bind(&event_type)
    .bind(limit)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let mut due_events = Vec::new();
    for row in rows {
        due_events.push(subscription_scheduler_worker_event_response(&row)?);
    }
    let next_run_at = sqlx::query_scalar::<_, Option<String>>(
        r#"
        select min(effective_at)::text
        from subscription_events_or_schedules
        where tenant_id = $1
          and event_status = $2
          and event_type = any($3::text[])
          and effective_at > now()
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(&event_status)
    .bind(&event_type)
    .fetch_one(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let supervisor = subscription_scheduler_supervisor_readback(
        state.db(),
        DEFAULT_TENANT_ID,
        worker_id.as_deref(),
        None,
    )
    .await?;

    Ok(Json(json!({
        "data": {
            "schema": "admin_subscription_scheduler_worker_handoff.v1",
            "tenant_id": DEFAULT_TENANT_ID,
            "status": if due_events.is_empty() { "idle" } else { "due_events_available" },
            "event_status_filter": event_status,
            "event_type_filter": event_type,
            "due_event_count": due_events.len(),
            "due_events": due_events,
            "next_run": {
                "at": next_run_at,
                "source": "subscription_events_or_schedules.effective_at",
                "runtime_daemon_running": false,
                "operator_polling_supported": true
            },
            "supervisor": supervisor,
            "worker_handoff": {
                "lease_endpoint": "/admin/subscriptions/scheduler-events/{id}/lease",
                "execute_endpoint": "/admin/subscriptions/scheduler-events/{id}/execute-plan",
                "run_due_endpoint": "/admin/subscriptions/run-due-scheduler-events",
                "claimable_statuses": ["scheduled", "replayed"],
                "lease_writes_limited_to": ["subscription_events_or_schedules.metadata"],
                "supervisor_state_table": "subscription_scheduler_worker_supervisors",
                "event_status_changed_by_lease": false,
                "subscription_rows_updated": false,
                "invoice_order_ledger_credit_writes": false,
                "payment_capture_executed": false
            },
            "retry_policy": subscription_scheduler_retry_policy(),
            "dunning_policy": subscription_scheduler_dunning_policy(),
            "proration_policy": subscription_scheduler_proration_policy(),
            "next_action": if due_events.is_empty() {
                "No due scheduled/replayed events are available for worker handoff. Use scheduler-plan apply to create local scheduled rows."
            } else {
                "A worker or operator can lease an event for safe readback, then use execute-plan dry_run/apply/refuse/replay. Real payment, invoice/order, ledger, and credit-grant executors remain disabled."
            },
            "secret_safe": true,
            "raw_payment_payload_returned": false,
            "raw_provider_payload_returned": false,
            "authorization_returned": false,
            "raw_invoice_metadata_returned": false,
            "raw_idempotency_key_echoed": false
        }
    }))
    .into_response())
}

async fn run_due_subscription_scheduler_events(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<SubscriptionSchedulerRunDueRequest>,
) -> Result<Response, AdminError> {
    let mode = normalize_subscription_scheduler_execute_mode(request.mode)?;
    let mutates_event_status = mode != "dry_run";
    session
        .require_permission(if mutates_event_status {
            Permission::BillingAdjust
        } else {
            Permission::BillingRead
        })
        .map_err(|_| {
            AdminError::forbidden(if mutates_event_status {
                "billing_adjust permission is required"
            } else {
                "billing_read permission is required"
            })
        })?;

    let tenant_id = audit_log_tenant_id(request.tenant_id)?;
    let limit = billing_read_limit(request.limit)?;
    let event_status_filter =
        normalize_subscription_scheduler_run_due_statuses(request.event_status)?;
    let event_type_filter = normalize_subscription_scheduler_worker_event_type(request.event_type)?;
    let worker_id = request
        .worker_id
        .map(|value| non_empty(value, "worker_id"))
        .transpose()?
        .unwrap_or_else(|| "subscription-scheduler-daemon".to_string());
    let reason = request
        .reason
        .map(|value| non_empty(value, "reason"))
        .transpose()?;
    if mutates_event_status && reason.is_none() {
        return Err(AdminError::bad_request(
            "reason is required when mode is apply, refuse, or replay",
        ));
    }

    let rows = sqlx::query(
        r#"
        select e.id,
               e.subscription_id,
               e.event_type,
               e.event_status,
               e.effective_at::text as effective_at,
               e.idempotency_key_hash,
               e.credit_grant_id,
               e.ledger_entry_id,
               e.invoice_id,
               e.order_id,
               e.audit_id,
               e.refusal_code,
               e.request_summary,
               e.metadata,
               e.created_at::text as created_at,
               e.updated_at::text as updated_at,
               (e.effective_at <= now()) as due_now,
               s.project_id,
               s.wallet_id,
               s.plan_id,
               s.status as subscription_status,
               s.current_period_start::text as current_period_start,
               s.current_period_end::text as current_period_end,
               p.plan_code,
               p.billing_interval,
               p.currency,
               p.unit_price::text as unit_price,
               p.included_credit_amount::text as included_credit_amount
        from subscription_events_or_schedules e
        join subscriptions s on s.tenant_id = e.tenant_id and s.id = e.subscription_id
        join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
        where e.tenant_id = $1
          and e.event_status = any($2::text[])
          and e.event_type = any($3::text[])
          and e.effective_at <= now()
        order by
          e.effective_at asc,
          e.updated_at asc
        limit $4
        "#,
    )
    .bind(tenant_id)
    .bind(&event_status_filter)
    .bind(&event_type_filter)
    .bind(limit)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let mut processed = Vec::new();
    let mut skipped = Vec::new();
    for row in rows {
        let event_id: Uuid = row.try_get("id").map_err(db_row_error)?;
        let before_status: String = row.try_get("event_status").map_err(db_row_error)?;
        let mut event = subscription_scheduler_event_execute_response(&row, &mode, &before_status)?;

        if mutates_event_status {
            let execution = apply_subscription_scheduler_local_execution(
                state.db(),
                tenant_id,
                event_id,
                &mode,
                reason
                    .as_deref()
                    .unwrap_or("subscription scheduler daemon run"),
                &worker_id,
            )
            .await?;

            if execution["event_mutated"].as_bool().unwrap_or(false) {
                let payment_capture_handoff =
                    subscription_scheduler_payment_capture_handoff_readback(
                        state.db(),
                        tenant_id,
                        &row,
                        &execution,
                    )
                    .await?;
                let refund_or_credit_note_handoff =
                    subscription_scheduler_refund_or_credit_note_handoff_readback(
                        state.db(),
                        tenant_id,
                        &row,
                        &execution,
                    )
                    .await?;
                event["event_status"] = execution["event_status"].clone();
                event["updated_at"] = execution["event_updated_at"].clone();
                event["refs"] = execution["refs"].clone();
                event["local_execution_readback"] = execution.clone();
                event["payment_capture_handoff"] = payment_capture_handoff.clone();
                event["payment_provider_executor_handoff"] = payment_capture_handoff.clone();
                event["refund_or_credit_note_handoff"] = refund_or_credit_note_handoff.clone();
                processed.push(json!({
                    "event": event,
                    "status": execution["status"].clone(),
                    "status_transition": {
                        "mutated": true,
                        "from": before_status,
                        "to": execution["event_status"].clone(),
                        "writes_limited_to": execution["writes_limited_to"].clone(),
                        "runtime_implemented": true,
                        "subscription_rows_updated": execution["subscription_rows_updated"].clone(),
                        "ledger_or_credit_readback": execution["ledger_or_credit_readback"].clone(),
                        "invoice_order_readback": execution["invoice_order_readback"].clone(),
                        "dunning_retry_readback": execution["dunning_retry_readback"].clone(),
                        "proration_delta_readback": execution["proration_delta_readback"].clone(),
                        "negative_proration_readback": execution["negative_proration_readback"].clone(),
                        "payment_capture_handoff": payment_capture_handoff.clone(),
                        "refund_or_credit_note_handoff": refund_or_credit_note_handoff.clone(),
                        "payment_capture_executed": false
                    },
                    "payment_capture_handoff": payment_capture_handoff.clone(),
                    "payment_provider_executor_handoff": payment_capture_handoff,
                    "refund_or_credit_note_handoff": refund_or_credit_note_handoff,
                    "invoice_order_readback": execution["invoice_order_readback"].clone(),
                    "dunning_retry_readback": execution["dunning_retry_readback"].clone(),
                    "proration_delta_readback": execution["proration_delta_readback"].clone(),
                    "negative_proration_readback": execution["negative_proration_readback"].clone(),
                    "executor_steps": execution["executor_steps"].clone()
                }));
            } else {
                skipped.push(json!({
                    "event_id": event_id,
                    "reason": "event_status_changed_or_not_claimable",
                    "expected_statuses": ["scheduled", "replayed"],
                    "idempotent_noop": true
                }));
            }
        } else {
            let execution = subscription_scheduler_local_execution_dry_run(&row, &mode)?;
            let payment_capture_handoff = subscription_scheduler_payment_capture_handoff_readback(
                state.db(),
                tenant_id,
                &row,
                &execution,
            )
            .await?;
            let refund_or_credit_note_handoff =
                subscription_scheduler_refund_or_credit_note_handoff_readback(
                    state.db(),
                    tenant_id,
                    &row,
                    &execution,
                )
                .await?;
            event["local_execution_readback"] = execution;
            event["payment_capture_handoff"] = payment_capture_handoff.clone();
            event["payment_provider_executor_handoff"] = payment_capture_handoff.clone();
            event["refund_or_credit_note_handoff"] = refund_or_credit_note_handoff.clone();
            processed.push(json!({
                "event": event,
                "status": "planned",
                "status_transition": {
                    "mutated": false,
                    "from": before_status,
                    "to": before_status,
                    "writes_limited_to": []
                },
                "local_execution_readback": {
                    "runtime_implemented": true,
                    "subscription_rows_updated": 0,
                    "ledger_or_credit_readback": {"status": "dry_run_not_mutated"},
                    "invoice_order_readback": {"status": "dry_run_not_mutated", "payment_capture_executed": false},
                    "dunning_retry_readback": subscription_scheduler_dunning_retry_dry_run_readback(
                        event["event_type"].as_str().unwrap_or("unknown")
                    ),
                    "proration_delta_readback": subscription_scheduler_proration_delta_dry_run_readback(
                        event["event_type"].as_str().unwrap_or("unknown")
                    ),
                    "negative_proration_readback": subscription_scheduler_negative_proration_dry_run_readback(
                        event["event_type"].as_str().unwrap_or("unknown")
                    ),
                    "payment_capture_handoff": payment_capture_handoff.clone(),
                    "payment_capture_executed": false
                },
                "payment_capture_handoff": payment_capture_handoff.clone(),
                "payment_provider_executor_handoff": payment_capture_handoff,
                "refund_or_credit_note_handoff": refund_or_credit_note_handoff
            }));
        }
    }

    let next_run_at = sqlx::query_scalar::<_, Option<String>>(
        r#"
        select min(effective_at)::text
        from subscription_events_or_schedules
        where tenant_id = $1
          and event_status = any($2::text[])
          and event_type = any($3::text[])
          and effective_at > now()
        "#,
    )
    .bind(tenant_id)
    .bind(&event_status_filter)
    .bind(&event_type_filter)
    .fetch_one(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let blocked_count = 0usize;
    let supervisor = subscription_scheduler_upsert_supervisor_run(
        state.db(),
        tenant_id,
        &worker_id,
        &mode,
        &event_status_filter,
        &event_type_filter,
        next_run_at.as_deref(),
        processed.len(),
        skipped.len(),
        blocked_count,
        if blocked_count > 0 { "blocked" } else { "idle" },
    )
    .await?;

    Ok(Json(json!({
        "data": {
            "schema": "admin_subscription_scheduler_run_due_events.v1",
            "mode": mode,
            "tenant_id": tenant_id,
            "limit": limit,
            "worker_id": redact_secrets(&worker_id),
            "event_status_filter": event_status_filter,
            "event_type_filter": event_type_filter,
            "status": if processed.is_empty() { "idle" } else if mutates_event_status { "bounded_status_recorded" } else { "dry_run_planned" },
            "processed_count": processed.len(),
            "skipped_count": skipped.len(),
            "blocked_count": blocked_count,
            "processed": processed,
            "skipped": skipped,
            "blocked": [],
            "supervisor": supervisor,
            "next_run": {
                "at": next_run_at,
                "source": "subscription_events_or_schedules.effective_at",
                "runtime_daemon_running": false,
                "bounded_runner_endpoint": "/admin/subscriptions/run-due-scheduler-events",
                "operator_polling_supported": true
            },
            "policy": {
                "retry": subscription_scheduler_retry_policy(),
                "dunning": subscription_scheduler_dunning_policy(),
                "proration": subscription_scheduler_proration_policy(),
                "apply_requires_reason": true,
                "tenant_scoped": true,
                "limited_by": "limit",
                "claimable_statuses": ["scheduled", "replayed"],
                "modes": ["dry_run", "apply", "refuse", "replay"],
                "supervisor_state_table": "subscription_scheduler_worker_supervisors",
                "supervisor_heartbeat_written": true,
                "writes_limited_to": if mutates_event_status {
                    json!(["subscription_events_or_schedules.event_status", "subscription_events_or_schedules.metadata", "subscription_events_or_schedules.refusal_code", "subscriptions", "payment_orders", "payment_intents", "invoices", "credit_grants", "ledger_entries", "subscription_scheduler_worker_supervisors"])
                } else {
                    json!(["subscription_scheduler_worker_supervisors"])
                },
                "runtime_implemented": true,
                "subscription_rows_updated": "per_event_readback",
                "invoice_order_ledger_credit_writes": "bounded_local_settlement_when_applicable",
                "payment_capture_executed": false
            },
            "omitted_fields": [
                "raw_payment_payload",
                "raw_provider_payload",
                "authorization",
                "raw_invoice_metadata",
                "raw_idempotency_key",
                "provider_secret",
                "full_token"
            ],
            "next_action": if mutates_event_status {
                "Due event statuses and bounded local subscription/ledger/credit mutations were recorded where safe. Real provider capture still requires payment-provider callback evidence."
            } else {
                "Review processed dry-run plans, then call mode=apply/refuse/replay with a reason and a bounded limit to record event execution."
            },
            "secret_safe": true,
            "raw_payment_payload_returned": false,
            "raw_provider_payload_returned": false,
            "authorization_returned": false,
            "raw_invoice_metadata_returned": false,
            "raw_idempotency_key_echoed": false
        }
    }))
    .into_response())
}

async fn execute_subscription_scheduler_event_plan(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Path(event_id): Path<Uuid>,
    Json(request): Json<SubscriptionSchedulerEventExecuteRequest>,
) -> Result<Response, AdminError> {
    let mode = normalize_subscription_scheduler_execute_mode(request.mode)?;
    let mutates_event_status = mode != "dry_run";
    session
        .require_permission(if mutates_event_status {
            Permission::BillingAdjust
        } else {
            Permission::BillingRead
        })
        .map_err(|_| {
            AdminError::forbidden(if mutates_event_status {
                "billing_adjust permission is required"
            } else {
                "billing_read permission is required"
            })
        })?;
    let reason = request
        .reason
        .map(|value| non_empty(value, "reason"))
        .transpose()?;
    if mutates_event_status && reason.is_none() {
        return Err(AdminError::bad_request(
            "reason is required when mode is apply, refuse, or replay",
        ));
    }

    let row = sqlx::query(
        r#"
        select e.id,
               e.subscription_id,
               e.event_type,
               e.event_status,
               e.effective_at::text as effective_at,
               e.idempotency_key_hash,
               e.credit_grant_id,
               e.ledger_entry_id,
               e.invoice_id,
               e.order_id,
               e.audit_id,
               e.refusal_code,
               e.request_summary,
               e.metadata,
               e.created_at::text as created_at,
               e.updated_at::text as updated_at,
               (e.effective_at <= now()) as due_now,
               s.project_id,
               s.wallet_id,
               s.plan_id,
               s.status as subscription_status,
               s.current_period_start::text as current_period_start,
               s.current_period_end::text as current_period_end,
               p.plan_code,
               p.billing_interval,
               p.currency,
               p.unit_price::text as unit_price,
               p.included_credit_amount::text as included_credit_amount
        from subscription_events_or_schedules e
        join subscriptions s on s.tenant_id = e.tenant_id and s.id = e.subscription_id
        join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
        where e.tenant_id = $1
          and e.id = $2
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(event_id)
    .fetch_optional(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?
    .ok_or_else(|| AdminError::not_found("subscription scheduler event"))?;

    let before_status: String = row.try_get("event_status").map_err(db_row_error)?;
    let mut event = subscription_scheduler_event_execute_response(&row, &mode, &before_status)?;

    let local_execution = if mutates_event_status {
        let execution = apply_subscription_scheduler_local_execution(
            state.db(),
            DEFAULT_TENANT_ID,
            event_id,
            &mode,
            reason
                .as_deref()
                .unwrap_or("subscription scheduler execute"),
            "manual-operator",
        )
        .await?;
        event["event_status"] = execution["event_status"].clone();
        event["updated_at"] = execution["event_updated_at"].clone();
        event["refs"] = execution["refs"].clone();
        event["local_execution_readback"] = execution.clone();
        execution
    } else {
        subscription_scheduler_local_execution_dry_run(&row, &mode)?
    };
    let payment_capture_handoff = subscription_scheduler_payment_capture_handoff_readback(
        state.db(),
        DEFAULT_TENANT_ID,
        &row,
        &local_execution,
    )
    .await?;
    let refund_or_credit_note_handoff =
        subscription_scheduler_refund_or_credit_note_handoff_readback(
            state.db(),
            DEFAULT_TENANT_ID,
            &row,
            &local_execution,
        )
        .await?;
    event["payment_capture_handoff"] = payment_capture_handoff.clone();
    event["payment_provider_executor_handoff"] = payment_capture_handoff.clone();
    event["refund_or_credit_note_handoff"] = refund_or_credit_note_handoff.clone();

    Ok(Json(json!({
        "data": {
            "schema": "admin_subscription_scheduler_event_execute_plan.v2",
            "mode": mode,
            "event": event,
            "payment_capture_handoff": payment_capture_handoff.clone(),
            "payment_provider_executor_handoff": payment_capture_handoff.clone(),
            "refund_or_credit_note_handoff": refund_or_credit_note_handoff.clone(),
            "status_transition": {
                "mutated": mutates_event_status,
                "from": before_status,
                "to": if mutates_event_status {
                    subscription_scheduler_execute_target_status(&mode)
                } else {
                    before_status.as_str()
                },
                "writes_limited_to": if mutates_event_status {
                    local_execution["writes_limited_to"].clone()
                } else {
                    json!([])
                },
                "runtime_implemented": true,
                "subscription_rows_updated": local_execution["subscription_rows_updated"].clone(),
                "ledger_or_credit_readback": local_execution["ledger_or_credit_readback"].clone(),
                "invoice_order_readback": local_execution["invoice_order_readback"].clone(),
                "dunning_retry_readback": local_execution["dunning_retry_readback"].clone(),
                "proration_delta_readback": local_execution["proration_delta_readback"].clone(),
                "negative_proration_readback": local_execution["negative_proration_readback"].clone(),
                "payment_capture_handoff": payment_capture_handoff.clone(),
                "refund_or_credit_note_handoff": refund_or_credit_note_handoff.clone(),
                "payment_capture_executed": false
            },
            "executor_steps": local_execution["executor_steps"].clone(),
            "runtime_implemented": true,
            "subscription_rows_updated": local_execution["subscription_rows_updated"].clone(),
            "ledger_or_credit_readback": local_execution["ledger_or_credit_readback"].clone(),
            "invoice_order_readback": local_execution["invoice_order_readback"].clone(),
            "dunning_retry_readback": local_execution["dunning_retry_readback"].clone(),
            "proration_delta_readback": local_execution["proration_delta_readback"].clone(),
            "negative_proration_readback": local_execution["negative_proration_readback"].clone(),
            "refund_or_credit_note_handoff": refund_or_credit_note_handoff,
            "execution_boundary": {
                "worker_handoff_ready": true,
                "worker_can_pick_up_statuses": ["scheduled", "replayed"],
                "current_runtime": "bounded_local_subscription_executor",
                "payment_provider_connected": false,
                "payment_provider_executor_handoff_ready": payment_capture_handoff["ready_for_provider_executor"].as_bool().unwrap_or(false),
                "invoice_creation_executed": local_execution["invoice_order_readback"]["invoice_id"].is_string(),
                "order_creation_executed": local_execution["invoice_order_readback"]["order_id"].is_string(),
                "ledger_settlement_executed": local_execution["ledger_or_credit_readback"]["ledger_entry_id"].is_string(),
                "credit_grant_executed": local_execution["ledger_or_credit_readback"]["credit_grant_id"].is_string(),
                "raw_payment_payload_returned": false,
                "raw_provider_payload_returned": false,
                "authorization_returned": false,
                "raw_invoice_metadata_returned": false,
                "raw_idempotency_key_echoed": false
            },
            "next_action": if mutates_event_status {
                "Event execution was recorded with bounded local subscription/ledger/credit readback where safe. Real payment provider capture still requires provider callback evidence."
            } else {
                "Review the execution_plan and call with mode=apply, refuse, or replay plus reason to run bounded local execution."
            },
            "secret_safe": true,
            "raw_payment_payload_returned": false,
            "raw_provider_payload_returned": false,
            "authorization_returned": false,
            "raw_invoice_metadata_returned": false,
            "raw_idempotency_key_echoed": false
        }
    }))
    .into_response())
}

async fn lease_subscription_scheduler_event(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Path(event_id): Path<Uuid>,
    Json(request): Json<SubscriptionSchedulerEventLeaseRequest>,
) -> Result<Response, AdminError> {
    session
        .require_permission(Permission::BillingAdjust)
        .map_err(|_| AdminError::forbidden("billing_adjust permission is required"))?;
    let worker_id = request
        .worker_id
        .map(|value| non_empty(value, "worker_id"))
        .transpose()?
        .unwrap_or_else(|| "manual-operator".to_string());
    let lease_seconds = request.lease_seconds.unwrap_or(300);
    if !(30..=3600).contains(&lease_seconds) {
        return Err(AdminError::bad_request(
            "lease_seconds must be between 30 and 3600",
        ));
    }
    let reason = request
        .reason
        .map(|value| non_empty(value, "reason"))
        .transpose()?
        .unwrap_or_else(|| "subscription scheduler worker lease".to_string());

    let row = sqlx::query(
        r#"
        update subscription_events_or_schedules
        set metadata = metadata || $3::jsonb,
            updated_at = now()
        where tenant_id = $1
          and id = $2
          and event_status in ('scheduled', 'replayed')
        returning id, subscription_id, event_type, event_status, effective_at::text as effective_at,
                  idempotency_key_hash, metadata, updated_at::text as updated_at,
                  (effective_at <= now()) as due_now
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(event_id)
    .bind(json!({
        "worker_lease": {
            "schema": "admin_subscription_scheduler_worker_lease.v1",
            "worker_id": redact_secrets(&worker_id),
            "reason": redact_secrets(&reason),
            "lease_seconds": lease_seconds,
            "leased_until": format!("now_plus_{lease_seconds}_seconds"),
            "event_status_changed": false,
            "payment_capture_executed": false,
            "invoice_order_ledger_credit_writes": false,
            "raw_payment_payload": "omitted",
            "raw_provider_payload": "omitted",
            "authorization": "omitted",
            "raw_idempotency_key": "omitted"
        }
    }))
    .fetch_optional(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?
    .ok_or_else(|| AdminError::not_found("claimable subscription scheduler event"))?;

    let idempotency_key_hash: String = row.try_get("idempotency_key_hash").map_err(db_row_error)?;
    Ok(Json(json!({
        "data": {
            "schema": "admin_subscription_scheduler_worker_lease.v1",
            "event": {
                "id": row.try_get::<Uuid, _>("id").map_err(db_row_error)?,
                "subscription_id": row.try_get::<Uuid, _>("subscription_id").map_err(db_row_error)?,
                "event_type": row.try_get::<String, _>("event_type").map_err(db_row_error)?,
                "event_status": row.try_get::<String, _>("event_status").map_err(db_row_error)?,
                "effective_at": row.try_get::<String, _>("effective_at").map_err(db_row_error)?,
                "due_now": row.try_get::<bool, _>("due_now").map_err(db_row_error)?,
                "updated_at": row.try_get::<String, _>("updated_at").map_err(db_row_error)?,
                "idempotency_key_fingerprint": subscription_scheduler_public_fingerprint(&idempotency_key_hash)
            },
            "lease": {
                "worker_id": redact_secrets(&worker_id),
                "lease_seconds": lease_seconds,
                "lease_status": "metadata_recorded",
                "writes_limited_to": ["subscription_events_or_schedules.metadata"],
                "event_status_changed": false,
                "claimable_statuses": ["scheduled", "replayed"]
            },
            "next_action": "Use execute-plan dry_run to inspect the boundary-only plan, then apply/refuse/replay with a reason. Lease metadata does not run payment, invoice/order, ledger, or credit-grant work.",
            "secret_safe": true,
            "raw_payment_payload_returned": false,
            "raw_provider_payload_returned": false,
            "authorization_returned": false,
            "raw_invoice_metadata_returned": false,
            "raw_idempotency_key_echoed": false
        }
    }))
    .into_response())
}

