async fn list_admin_wallets(
    State(state): State<Arc<ControlPlaneState>>,
    Query(query): Query<ListAdminWalletsQuery>,
) -> Result<Response, AdminError> {
    let filter = query.into_filter()?;
    let wallet_rows = list_admin_wallet_rows(state.as_ref(), &filter).await?;
    let mut surfaces = Vec::with_capacity(wallet_rows.len());
    for wallet in wallet_rows {
        surfaces.push(
            admin_wallet_credit_surface(
                state.as_ref(),
                wallet,
                ADMIN_WALLET_DEFAULT_LEDGER_WINDOW_DAYS,
            )
            .await?,
        );
    }

    Ok(Json(json!({ "data": surfaces })).into_response())
}

async fn get_admin_wallet(
    State(state): State<Arc<ControlPlaneState>>,
    Path(wallet_id): Path<Uuid>,
    Query(query): Query<GetAdminWalletQuery>,
) -> Result<Response, AdminError> {
    let window_days = query.ledger_window_days()?;
    let wallet = get_admin_wallet_row(state.as_ref(), wallet_id)
        .await?
        .ok_or_else(|| AdminError::not_found("wallet"))?;
    let surface = admin_wallet_credit_surface(state.as_ref(), wallet, window_days).await?;

    Ok(Json(json!({ "data": surface })).into_response())
}

async fn get_billing_wallet_remaining_balance(
    State(state): State<Arc<ControlPlaneState>>,
    Path(wallet_id): Path<Uuid>,
    Query(query): Query<UserRemainingBalanceQuery>,
    principal: Option<Extension<RemainingBalancePrincipal>>,
) -> Result<Response, AdminError> {
    let _tenant_id = query.tenant_id()?;
    let expected_currency = query.currency()?;
    let window_days = query.ledger_window_days()?;
    let wallet = get_admin_wallet_row(state.as_ref(), wallet_id)
        .await?
        .ok_or_else(|| AdminError::not_found("wallet"))?;
    if expected_currency
        .as_ref()
        .is_some_and(|currency| currency != &wallet.currency)
    {
        return Ok((
            StatusCode::BAD_REQUEST,
            Json(json!({
                "data": user_remaining_balance_refusal_response(
                    wallet_id,
                    "currency_mismatch",
                    "currency does not match wallet",
                    principal.as_ref().map(|Extension(principal)| principal),
                )
            })),
        )
            .into_response());
    }

    let surface = admin_wallet_credit_surface(state.as_ref(), wallet, window_days).await?;
    let response = user_remaining_balance_response(
        surface,
        principal.as_ref().map(|Extension(principal)| principal),
    )?;
    Ok(Json(json!({ "data": response })).into_response())
}

async fn list_admin_credit_grants(
    State(state): State<Arc<ControlPlaneState>>,
    Query(query): Query<ListAdminCreditGrantsQuery>,
) -> Result<Response, AdminError> {
    let limit = billing_read_limit(query.limit)?;
    let status = query
        .status
        .map(|status| normalize_credit_grant_status(&status))
        .transpose()?;
    let rows = sqlx::query(
        r#"
        select id, tenant_id, wallet_id, amount::text as amount,
               remaining_amount::text as remaining_amount, currency, source,
               valid_from::text as valid_from, valid_until::text as valid_until,
               status, created_at::text as created_at, updated_at::text as updated_at,
               metadata
        from credit_grants
        where tenant_id = $1
          and ($2::uuid is null or wallet_id = $2)
          and ($3::text is null or status = $3)
        order by created_at desc, id desc
        limit $4
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(query.wallet_id)
    .bind(status)
    .bind(limit)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let grants = rows
        .into_iter()
        .map(admin_credit_grant_response)
        .collect::<Result<Vec<_>, _>>()?;

    Ok(Json(json!({
        "data": grants,
        "meta": {
            "schema": "admin_credit_grants_list.v1",
            "read_only": true,
            "secret_safe": true,
            "money_decimal_strings": true,
        }
    }))
    .into_response())
}

async fn create_admin_credit_grant(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    headers: HeaderMap,
    Json(request): Json<CreateAdminCreditGrantRequest>,
) -> Result<Response, AdminError> {
    let normalized = normalize_create_admin_credit_grant_request(request)?;
    let request_context = admin_request_context_from_headers(&headers);
    let mut tx = state
        .db()
        .begin()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let outcome =
        match execute_create_admin_credit_grant_tx(&mut tx, &session, normalized, request_context)
            .await
        {
            Ok(outcome) => outcome,
            Err(error) => {
                rollback_ledger_adjustment_execute_tx(tx).await;
                return Err(error);
            }
        };

    tx.commit()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let status_code = if outcome["outcome"] == json!("create") {
        StatusCode::CREATED
    } else {
        StatusCode::OK
    };
    Ok((status_code, Json(json!({ "data": outcome }))).into_response())
}

