async fn list_voucher_issuances(
    State(state): State<Arc<ControlPlaneState>>,
    Query(query): Query<VoucherIssuanceListQuery>,
) -> Result<Response, AdminError> {
    let limit = voucher_issuance_list_limit(query.limit)?;
    let status = query
        .status
        .map(|status| normalize_voucher_issuance_status(&status))
        .transpose()?;
    let rows = sqlx::query(
        r#"
        select
          id, tenant_id, project_id, wallet_id, campaign_id, currency,
          amount::text as amount, code_redacted, status, max_redemptions,
          redemption_count, expires_at::text as expires_at, audit_id, metadata,
          (expires_at is not null and expires_at <= now()) as expired_by_time
        from voucher_issuances
        where tenant_id = $1
          and ($2::uuid is null or wallet_id = $2)
          and ($3::uuid is null or project_id = $3)
          and ($4::uuid is null or campaign_id = $4)
          and ($5::text is null or status = $5)
          and ($6::text is null or metadata->>'batch_idempotency_key_hash' = $6)
        order by created_at desc, id desc
        limit $7
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(query.wallet_id)
    .bind(query.project_id)
    .bind(query.campaign_id)
    .bind(status.as_deref())
    .bind(query.batch_idempotency_key_hash.as_deref())
    .bind(limit)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let vouchers = rows
        .into_iter()
        .map(voucher_issuance_row_from_row)
        .collect::<Result<Vec<_>, _>>()?
        .into_iter()
        .map(|voucher| voucher_issuance_summary_response(&voucher))
        .collect::<Vec<_>>();

    Ok(Json(json!({
        "data": {
            "schema": "recharge_voucher_issuance_list.v1",
            "runtime_implemented": true,
            "secret_safe": true,
            "raw_voucher_code_echoed": false,
            "limit": limit,
            "count": vouchers.len(),
            "items": vouchers,
        }
    }))
    .into_response())
}

