async fn create_voucher_issuance_batch(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    headers: HeaderMap,
    Json(request): Json<VoucherIssueBatchRequest>,
) -> Result<Response, AdminError> {
    let batch_idempotency_key = non_empty(request.batch_idempotency_key, "batch_idempotency_key")?;
    let batch_idempotency_key_hash =
        sha256_hex(&format!("voucher-batch:v1:{batch_idempotency_key}"));
    if request.items.is_empty() {
        return Err(AdminError::bad_request(
            "items must contain at least one voucher",
        ));
    }
    if request.items.len() > 100 {
        return Err(AdminError::bad_request(
            "items must not exceed 100 vouchers",
        ));
    }

    let request_context = admin_request_context_from_headers(&headers);
    let mut tx = state
        .db()
        .begin()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let mut seen_codes = BTreeSet::new();
    let mut seen_idempotency_keys = BTreeSet::new();
    let mut items = Vec::with_capacity(request.items.len());

    for (index, item) in request.items.into_iter().enumerate() {
        let raw_code = item.raw_voucher_code.trim().to_string();
        let idempotency_key = item.idempotency_key.trim().to_string();
        if raw_code.is_empty() {
            items.push(voucher_issue_batch_refusal_item(
                index,
                "empty_voucher_code",
                "raw_voucher_code is required",
            ));
            continue;
        }
        if idempotency_key.is_empty() {
            items.push(voucher_issue_batch_refusal_item(
                index,
                "empty_idempotency_key",
                "idempotency_key is required",
            ));
            continue;
        }
        let code_hash = voucher_code_hash(&raw_code)?;
        if !seen_codes.insert(code_hash) {
            items.push(voucher_issue_batch_refusal_item(
                index,
                "duplicate_voucher_code_in_batch",
                "duplicate voucher code in batch",
            ));
            continue;
        }
        if !seen_idempotency_keys.insert(idempotency_key.clone()) {
            items.push(voucher_issue_batch_refusal_item(
                index,
                "duplicate_idempotency_key_in_batch",
                "duplicate idempotency key in batch",
            ));
            continue;
        }

        let issue_request = VoucherIssueRequest {
            tenant_id: request.defaults.tenant_id,
            project_id: request.defaults.project_id,
            wallet_id: request.defaults.wallet_id,
            campaign_id: request.defaults.campaign_id,
            currency: request.defaults.currency.clone(),
            amount: request.defaults.amount.clone(),
            raw_voucher_code: raw_code,
            idempotency_key,
            max_redemptions: request.defaults.max_redemptions,
            expires_at: request.defaults.expires_at.clone(),
            batch_idempotency_key_hash: Some(batch_idempotency_key_hash.clone()),
        };

        let normalized = match normalize_voucher_issue_request(issue_request) {
            Ok(normalized) => normalized,
            Err(error) => {
                items.push(voucher_issue_batch_refusal_item(
                    index,
                    "invalid_voucher_item",
                    error.message,
                ));
                continue;
            }
        };

        let outcome =
            match execute_voucher_issue_tx(&mut tx, &session, normalized, request_context.clone())
                .await
            {
                Ok(outcome) => outcome,
                Err(error) => {
                    rollback_ledger_adjustment_execute_tx(tx).await;
                    return Err(error);
                }
            };
        items.push(voucher_issue_batch_item(index, outcome));
    }

    tx.commit()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let response = voucher_issue_batch_response(&batch_idempotency_key_hash, items);
    Ok((StatusCode::OK, Json(json!({ "data": response }))).into_response())
}

async fn get_voucher_issuance_batch(
    State(state): State<Arc<ControlPlaneState>>,
    Path(batch_hash): Path<String>,
) -> Result<Response, AdminError> {
    let batch_hash = normalize_voucher_batch_hash(batch_hash)?;
    let rows = list_voucher_issuances_by_batch_hash(state.db(), &batch_hash).await?;
    Ok(Json(json!({
        "data": voucher_batch_query_response(&batch_hash, rows)
    }))
    .into_response())
}

async fn revoke_voucher_issuance_batch(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    headers: HeaderMap,
    Path(batch_hash): Path<String>,
) -> Result<Response, AdminError> {
    let batch_hash = normalize_voucher_batch_hash(batch_hash)?;
    let request_context = admin_request_context_from_headers(&headers);
    let operation_id = Uuid::new_v4();
    let mut tx = state
        .db()
        .begin()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let issued_rows = list_issued_voucher_issuances_by_batch_hash_tx(&mut tx, &batch_hash).await?;
    let total_matched_before =
        count_voucher_issuances_by_batch_hash_tx(&mut tx, &batch_hash).await?;
    let revocable_count = issued_rows.len();
    let mut revoked_items = Vec::with_capacity(revocable_count);
    for row in issued_rows {
        let mut item_context = request_context.clone();
        if let Some(object) = item_context.as_object_mut() {
            object.insert("batch_operation_id".to_string(), json!(operation_id));
            object.insert("batch_idempotency_key_hash".to_string(), json!(batch_hash));
        }
        match execute_voucher_revoke_tx(&mut tx, &session, row.id, item_context).await {
            Ok(outcome) => revoked_items.push(outcome),
            Err(error) => {
                rollback_ledger_adjustment_execute_tx(tx).await;
                return Err(error);
            }
        }
    }

    let rows_after = list_voucher_issuances_by_batch_hash_tx(&mut tx, &batch_hash).await?;
    let response = voucher_batch_revoke_response(
        &batch_hash,
        operation_id,
        total_matched_before,
        revocable_count,
        rows_after,
        revoked_items,
    );

    tx.commit()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(Json(json!({ "data": response })).into_response())
}

