async fn dry_run_ledger_adjustment(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<LedgerAdjustmentDryRunRequest>,
) -> Result<Response, AdminError> {
    let repository = repo(&state);
    let mode = normalize_ledger_adjustment_request_mode(request.mode.as_deref())?;
    if mode == LedgerAdjustmentRequestMode::Execute {
        return execute_ledger_adjustment(state.as_ref(), &session, request).await;
    }
    let plan = build_ledger_adjustment_dry_run_plan(&repository, request.clone()).await?;
    if mode == LedgerAdjustmentRequestMode::ExecuteContract {
        let persistent_cutover_state_readback =
            read_billing_ledger_writer_persistent_cutover_state(state.as_ref(), "production").await;
        return Ok(
            ledger_adjustment_execute_contract_response_with_persistent_state(
                plan,
                persistent_cutover_state_readback,
            ),
        );
    }

    Ok(Json(json!({ "data": plan })).into_response())
}

async fn list_ledger_entries_for_request_ids(
    state: &ControlPlaneState,
    tenant_id: Uuid,
    request_ids: &[Uuid],
) -> Result<Vec<LedgerEntry>, AdminError> {
    if request_ids.is_empty() {
        return Ok(Vec::new());
    }

    let mut unique_request_ids = request_ids.to_vec();
    unique_request_ids.sort_unstable();
    unique_request_ids.dedup();

    let rows = sqlx::query(
        r#"
        select
          id, tenant_id, project_id, wallet_id, request_id, virtual_key_id, trace_id,
          related_ledger_entry_id, entry_type, amount::text as amount, currency, status,
          idempotency_key, price_version_id, usage_snapshot, policy_snapshot, metadata,
          occurred_at::text as occurred_at, created_at::text as created_at
        from ledger_entries
        where tenant_id = $1
          and request_id = any($2::uuid[])
        order by created_at desc, id
        limit $3
        "#,
    )
    .bind(tenant_id)
    .bind(unique_request_ids)
    .bind(TRACE_REQUEST_LEDGER_LIMIT)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    rows.into_iter()
        .map(ledger_entry_from_row)
        .collect::<Result<Vec<_>, _>>()
        .map_err(|error| AdminError::from(DbError::Query(error)))
}

#[derive(Debug, Clone)]
struct AdminWalletRow {
    id: Uuid,
    tenant_id: Uuid,
    project_id: Option<Uuid>,
    name: String,
    currency: String,
    status: String,
    balance_floor: String,
    created_at: String,
    updated_at: String,
}

async fn list_admin_wallet_rows(
    state: &ControlPlaneState,
    filter: &AdminWalletListFilter,
) -> Result<Vec<AdminWalletRow>, AdminError> {
    let rows = sqlx::query(
        r#"
        select id, tenant_id, project_id, name, currency, status,
               balance_floor::text as balance_floor,
               created_at::text as created_at,
               updated_at::text as updated_at
        from wallets
        where tenant_id = $1
          and ($2::uuid is null or project_id is not distinct from $2)
          and ($3::text is null or status = $3)
          and ($4::text is null or currency = $4)
          and ($3::text = 'deleted' or deleted_at is null)
        order by updated_at desc, id
        limit $5
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(filter.project_id)
    .bind(filter.status.as_deref())
    .bind(filter.currency.as_deref())
    .bind(filter.limit)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    rows.into_iter().map(admin_wallet_row_from_row).collect()
}

async fn get_admin_wallet_row(
    state: &ControlPlaneState,
    wallet_id: Uuid,
) -> Result<Option<AdminWalletRow>, AdminError> {
    let row = sqlx::query(
        r#"
        select id, tenant_id, project_id, name, currency, status,
               balance_floor::text as balance_floor,
               created_at::text as created_at,
               updated_at::text as updated_at
        from wallets
        where tenant_id = $1 and id = $2
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .fetch_optional(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.map(admin_wallet_row_from_row).transpose()
}

fn admin_wallet_row_from_row(row: PgRow) -> Result<AdminWalletRow, AdminError> {
    Ok(AdminWalletRow {
        id: row
            .try_get("id")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        tenant_id: row
            .try_get("tenant_id")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        project_id: row
            .try_get("project_id")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        name: row
            .try_get("name")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        currency: row
            .try_get("currency")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        status: row
            .try_get("status")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        balance_floor: admin_wallet_money_from_row(&row, "balance_floor")?,
        created_at: row
            .try_get("created_at")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        updated_at: row
            .try_get("updated_at")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
    })
}

async fn admin_wallet_credit_surface(
    state: &ControlPlaneState,
    wallet: AdminWalletRow,
    window_days: i64,
) -> Result<Value, AdminError> {
    let mut credit_grants = admin_wallet_credit_grants_summary(state, wallet.id).await?;
    let credit_max_source_updated_at = credit_grants
        .get("max_source_updated_at")
        .and_then(Value::as_str)
        .map(str::to_string);
    if let Some(object) = credit_grants.as_object_mut() {
        object.remove("max_source_updated_at");
    }
    let mut ledger_balance_window =
        admin_wallet_ledger_balance_window(state, wallet.id, &wallet.currency, window_days).await?;
    let ledger_max_source_updated_at = ledger_balance_window
        .get("max_source_updated_at")
        .and_then(Value::as_str)
        .map(str::to_string);
    if let Some(object) = ledger_balance_window.as_object_mut() {
        object.remove("max_source_updated_at");
    }
    let pending_reserves = admin_wallet_pending_reserves(state, wallet.id).await?;
    let credit_grant_expiration_readback =
        admin_wallet_credit_grant_expiration_readback(state, wallet.id).await?;
    let funding_source_readback =
        admin_wallet_funding_source_readback(state, Some(wallet.id), &[]).await?;
    let ledger_links = admin_wallet_public_ledger_links(state, wallet.id).await?;
    let audit_log_ids = admin_wallet_audit_log_ids(
        state,
        &ledger_links.ledger_entry_ids,
        &ledger_links.request_ids,
    )
    .await?;
    let budget_remaining =
        admin_wallet_budget_remaining_marker(state, wallet.project_id, &wallet.currency).await?;
    let max_source_updated_at = ledger_max_source_updated_at
        .or(credit_max_source_updated_at)
        .unwrap_or_else(|| wallet.updated_at.clone());

    Ok(admin_wallet_credit_surface_response(
        AdminWalletCreditSurfaceParts {
            wallet,
            credit_grants,
            credit_grant_expiration_readback,
            funding_source_readback,
            ledger_balance_window,
            pending_reserves,
            last_ledger_entry_ids: ledger_links.ledger_entry_ids.clone(),
            bounded_links: json!({
                "ledger_entry_ids": ledger_links.ledger_entry_ids,
                "request_ids": ledger_links.request_ids,
                "trace_ids": ledger_links.trace_ids,
                "audit_log_ids": audit_log_ids,
                "link_policy": "public_ids_only",
            }),
            budget_remaining,
            consistency: json!({
                "read_model": "ledger_window_readback",
                "computed_at": ledger_links.computed_at,
                "max_source_updated_at": max_source_updated_at,
                "staleness_status": "current",
                "bounded_window_days": window_days,
                "snapshot_includes_uncommitted_writes": false,
            }),
        },
    ))
}

#[derive(Debug)]
struct AdminWalletCreditSurfaceParts {
    wallet: AdminWalletRow,
    credit_grants: Value,
    credit_grant_expiration_readback: Value,
    funding_source_readback: Value,
    ledger_balance_window: Value,
    pending_reserves: Value,
    budget_remaining: Value,
    last_ledger_entry_ids: Vec<Uuid>,
    bounded_links: Value,
    consistency: Value,
}

fn admin_wallet_credit_surface_response(parts: AdminWalletCreditSurfaceParts) -> Value {
    json!({
        "wallet": {
            "id": parts.wallet.id,
            "tenant_id": parts.wallet.tenant_id,
            "project_id": parts.wallet.project_id,
            "name": redact_secrets(&parts.wallet.name),
            "currency": parts.wallet.currency,
            "status": parts.wallet.status,
            "balance_floor": parts.wallet.balance_floor,
            "created_at": parts.wallet.created_at,
            "updated_at": parts.wallet.updated_at,
        },
        "credit_grants": parts.credit_grants,
        "credit_grant_expiration_readback": parts.credit_grant_expiration_readback,
        "funding_source_readback": parts.funding_source_readback,
        "ledger_balance_window": parts.ledger_balance_window,
        "pending_reserves": parts.pending_reserves,
        "budget_remaining": parts.budget_remaining,
        "last_ledger_entry_ids": parts.last_ledger_entry_ids,
        "bounded_links": parts.bounded_links,
        "consistency": parts.consistency,
        "secret_safe": admin_wallet_secret_safe_marker(),
        "read_only": true,
    })
}

async fn admin_wallet_credit_grants_summary(
    state: &ControlPlaneState,
    wallet_id: Uuid,
) -> Result<Value, AdminError> {
    let aggregate = sqlx::query(
        r#"
        select
          count(*)::bigint as total_count,
          count(*) filter (where status = 'active')::bigint as active_count,
          count(*) filter (where status = 'consumed')::bigint as consumed_count,
          count(*) filter (where status = 'expired')::bigint as expired_count,
          count(*) filter (where status = 'voided')::bigint as voided_count,
          coalesce(sum(amount) filter (where status = 'active'), 0)::text as active_amount_total,
          coalesce(sum(remaining_amount) filter (where status = 'active'), 0)::text as active_remaining_total,
          coalesce(sum(amount) filter (where status = 'expired'), 0)::text as expired_amount_total,
          max(updated_at)::text as max_source_updated_at
        from credit_grants
        where tenant_id = $1 and wallet_id = $2
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .fetch_one(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let grant_rows = sqlx::query(
        r#"
        select id, amount::text as amount, remaining_amount::text as remaining_amount,
               currency, source, status, valid_from::text as valid_from,
               valid_until::text as valid_until, created_at::text as created_at
        from credit_grants
        where tenant_id = $1 and wallet_id = $2
        order by
          case status when 'active' then 0 when 'consumed' then 1 when 'expired' then 2 else 3 end,
          created_at desc,
          id
        limit $3
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .bind(ADMIN_WALLET_CREDIT_GRANT_LIMIT)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let grants = grant_rows
        .into_iter()
        .map(admin_wallet_credit_grant_response)
        .collect::<Result<Vec<_>, _>>()?;

    Ok(json!({
        "total_count": aggregate.try_get::<i64, _>("total_count").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "active_count": aggregate.try_get::<i64, _>("active_count").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "consumed_count": aggregate.try_get::<i64, _>("consumed_count").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "expired_count": aggregate.try_get::<i64, _>("expired_count").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "voided_count": aggregate.try_get::<i64, _>("voided_count").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "active_amount_total": admin_wallet_money_from_row(&aggregate, "active_amount_total")?,
        "active_remaining_total": admin_wallet_money_from_row(&aggregate, "active_remaining_total")?,
        "expired_amount_total": admin_wallet_money_from_row(&aggregate, "expired_amount_total")?,
        "max_source_updated_at": aggregate.try_get::<Option<String>, _>("max_source_updated_at").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "grants": grants,
    }))
}

fn admin_wallet_credit_grant_response(row: PgRow) -> Result<Value, AdminError> {
    Ok(json!({
        "id": row.try_get::<Uuid, _>("id").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "amount": admin_wallet_money_from_row(&row, "amount")?,
        "remaining_amount": admin_wallet_money_from_row(&row, "remaining_amount")?,
        "currency": row.try_get::<String, _>("currency").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "source": redact_secrets(&row.try_get::<String, _>("source").map_err(|error| AdminError::from(DbError::Query(error)))?),
        "status": row.try_get::<String, _>("status").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "valid_from": row.try_get::<String, _>("valid_from").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "valid_until": row.try_get::<Option<String>, _>("valid_until").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "created_at": row.try_get::<String, _>("created_at").map_err(|error| AdminError::from(DbError::Query(error)))?,
    }))
}

async fn admin_wallet_credit_grant_expiration_readback(
    state: &ControlPlaneState,
    wallet_id: Uuid,
) -> Result<Value, AdminError> {
    let aggregate = sqlx::query(
        r#"
        select
          count(*)::bigint as total_count,
          count(*) filter (
            where status = 'active'
              and (valid_until is null or valid_until > now())
          )::bigint as active_count,
          count(*) filter (
            where status = 'expired'
               or (status = 'active' and valid_until is not null and valid_until <= now())
          )::bigint as expired_count,
          count(*) filter (
            where status = 'active'
              and valid_until is not null
              and valid_until > now()
              and valid_until <= now() + interval '30 days'
          )::bigint as expiring_soon_count,
          min(valid_until) filter (
            where status = 'active'
              and valid_until is not null
              and valid_until > now()
          )::text as next_expiration_at,
          bool_or(source in ('voucher_redeem', 'voucher_issue', 'voucher')) as voucher_source_ref_present,
          bool_or(source in ('payment_order_invoice', 'payment_provider_capture', 'local_payment_demo')) as payment_source_ref_present,
          bool_or(source like 'subscription%') as subscription_source_ref_present,
          bool_or(source in ('opening_balance_import', 'import', 'migration')) as import_source_ref_present,
          bool_or(source in ('admin_adjustment', 'manual_adjustment')) as admin_adjustment_source_ref_present
        from credit_grants
        where tenant_id = $1 and wallet_id = $2
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .fetch_one(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let currency_rows = sqlx::query(
        r#"
        select
          currency,
          count(*) filter (
            where status = 'active'
              and (valid_until is null or valid_until > now())
          )::bigint as active_count,
          coalesce(sum(remaining_amount) filter (
            where status = 'active'
              and (valid_until is null or valid_until > now())
          ), 0)::text as available_amount
        from credit_grants
        where tenant_id = $1 and wallet_id = $2
        group by currency
        order by currency
        limit 8
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let available_amount_by_currency = currency_rows
        .into_iter()
        .map(|row| {
            Ok(json!({
                "currency": row.try_get::<String, _>("currency").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "active_count": row.try_get::<i64, _>("active_count").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "available_amount": admin_wallet_money_from_row(&row, "available_amount")?,
            }))
        })
        .collect::<Result<Vec<_>, AdminError>>()?;

    let bounded_grant_rows = sqlx::query(
        r#"
        select id, currency, remaining_amount::text as remaining_amount,
               case
                 when status = 'active' and valid_until is not null and valid_until <= now() then 'expired'
                 else status
               end as effective_status,
               valid_until::text as valid_until
        from credit_grants
        where tenant_id = $1
          and wallet_id = $2
          and (
            status = 'expired'
            or (status = 'active' and valid_until is not null)
          )
        order by
          case
            when status = 'active' and valid_until is not null and valid_until > now() then 0
            when status = 'active' and valid_until is not null and valid_until <= now() then 1
            when status = 'expired' then 2
            else 3
          end,
          valid_until asc nulls last,
          id
        limit $3
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .bind(ADMIN_WALLET_LINK_LIMIT)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let bounded_grants = bounded_grant_rows
        .into_iter()
        .map(|row| {
            let status = row
                .try_get::<String, _>("effective_status")
                .map_err(|error| AdminError::from(DbError::Query(error)))?;
            Ok(json!({
                "credit_grant_id": row.try_get::<Uuid, _>("id").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "currency": row.try_get::<String, _>("currency").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "remaining_amount": admin_wallet_money_from_row(&row, "remaining_amount")?,
                "status": status,
                "valid_until": row.try_get::<Option<String>, _>("valid_until").map_err(|error| AdminError::from(DbError::Query(error)))?,
            }))
        })
        .collect::<Result<Vec<_>, AdminError>>()?;

    let active_count = aggregate
        .try_get::<i64, _>("active_count")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let expired_count = aggregate
        .try_get::<i64, _>("expired_count")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let expiring_soon_count = aggregate
        .try_get::<i64, _>("expiring_soon_count")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let safe_next_action = if expiring_soon_count > 0 {
        "Review expiring grants and notify or top up the wallet before the next expiration."
    } else if active_count == 0 && expired_count > 0 {
        "No active grant balance remains; add credit or ask the user to redeem a valid voucher."
    } else if active_count == 0 {
        "Add credit, redeem a voucher, or confirm the wallet is intentionally unfunded."
    } else {
        "Render current available credit and next expiration from this readback."
    };

    Ok(json!({
        "schema": "credit_grant_expiration_readback.v1",
        "source": "credit_grants",
        "wallet_id": wallet_id,
        "total_count": aggregate.try_get::<i64, _>("total_count").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "active_count": active_count,
        "expired_count": expired_count,
        "expiring_soon_count": expiring_soon_count,
        "expiring_soon_window_days": 30,
        "available_amount_by_currency": available_amount_by_currency,
        "next_expiration_at": aggregate.try_get::<Option<String>, _>("next_expiration_at").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "bounded_grants": bounded_grants,
        "source_refs_presence": {
            "voucher_source_ref_present": aggregate.try_get::<Option<bool>, _>("voucher_source_ref_present").map_err(|error| AdminError::from(DbError::Query(error)))?.unwrap_or(false),
            "payment_source_ref_present": aggregate.try_get::<Option<bool>, _>("payment_source_ref_present").map_err(|error| AdminError::from(DbError::Query(error)))?.unwrap_or(false),
            "subscription_source_ref_present": aggregate.try_get::<Option<bool>, _>("subscription_source_ref_present").map_err(|error| AdminError::from(DbError::Query(error)))?.unwrap_or(false),
            "import_source_ref_present": aggregate.try_get::<Option<bool>, _>("import_source_ref_present").map_err(|error| AdminError::from(DbError::Query(error)))?.unwrap_or(false),
            "admin_adjustment_source_ref_present": aggregate.try_get::<Option<bool>, _>("admin_adjustment_source_ref_present").map_err(|error| AdminError::from(DbError::Query(error)))?.unwrap_or(false),
            "raw_source_ref_returned": false,
        },
        "bounded_ids_only": true,
        "raw_voucher_code_returned": false,
        "raw_voucher_code_hash_returned": false,
        "raw_ledger_metadata_returned": false,
        "authorization_returned": false,
        "api_key_secret_returned": false,
        "provider_key_returned": false,
        "raw_payload_returned": false,
        "safe_next_action": safe_next_action,
        "read_only": true,
        "secret_safe": true,
    }))
}

const ADMIN_WALLET_FUNDING_SOURCE_CATEGORIES: [&str; 5] = [
    "voucher",
    "manual_adjustment",
    "payment_order",
    "subscription_credit",
    "negative_proration_credit",
];

#[derive(Debug)]
struct AdminWalletFundingSourceReadbackRow {
    category: String,
    source_table: String,
    source_id: String,
    wallet_id: Option<Uuid>,
    amount: String,
    currency: String,
    status: String,
    ref_present: bool,
}

#[derive(Debug, Default)]
struct AdminWalletFundingSourceBucket {
    count: i64,
    amount_by_currency: BTreeMap<String, String>,
    statuses: BTreeSet<String>,
    ref_present: bool,
    bounded_refs: Vec<Value>,
}

async fn admin_wallet_funding_source_readback(
    state: &ControlPlaneState,
    wallet_id: Option<Uuid>,
    project_ids: &[Uuid],
) -> Result<Value, AdminError> {
    let rows = sqlx::query(
        r#"
        with scoped_credit_grants as (
          select
            case
              when cg.source in ('voucher_redeem', 'voucher_issue', 'voucher')
                or cg.source like '%voucher%' then 'voucher'
              when cg.source in ('admin_adjustment', 'manual_adjustment')
                or cg.source like '%manual%' then 'manual_adjustment'
              when cg.source like '%proration%' then 'negative_proration_credit'
              when cg.source like 'subscription%' then 'subscription_credit'
              when cg.source in ('payment_order_invoice', 'payment_provider_capture', 'local_payment_demo')
                or cg.source like '%payment%' then 'payment_order'
              else null
            end as category,
            'credit_grants' as source_table,
            cg.id::text as source_id,
            cg.wallet_id,
            cg.amount::text as amount,
            cg.currency,
            cg.status,
            true as ref_present,
            cg.created_at
          from credit_grants cg
          join wallets w on w.tenant_id = cg.tenant_id and w.id = cg.wallet_id
          where cg.tenant_id = $1
            and ($2::uuid is null or cg.wallet_id = $2)
            and (cardinality($3::uuid[]) = 0 or w.project_id = any($3::uuid[]))
        ),
        scoped_manual_ledger as (
          select
            'manual_adjustment' as category,
            'ledger_entries' as source_table,
            le.id::text as source_id,
            le.wallet_id,
            abs(le.amount)::text as amount,
            le.currency,
            le.status,
            true as ref_present,
            le.created_at
          from ledger_entries le
          left join wallets w on w.tenant_id = le.tenant_id and w.id = le.wallet_id
          where le.tenant_id = $1
            and le.entry_type = 'adjust'
            and le.amount > 0
            and ($2::uuid is null or le.wallet_id = $2)
            and (cardinality($3::uuid[]) = 0 or coalesce(le.project_id, w.project_id) = any($3::uuid[]))
        ),
        scoped_payment_orders as (
          select
            'payment_order' as category,
            'payment_orders' as source_table,
            po.id::text as source_id,
            po.wallet_id,
            po.amount::text as amount,
            po.currency,
            po.status,
            (po.credit_grant_id is not null or po.ledger_entry_id is not null or po.invoice_id is not null
              or po.payment_intent_id is not null or po.payment_capture_id is not null) as ref_present,
            po.created_at
          from payment_orders po
          left join wallets w on w.tenant_id = po.tenant_id and w.id = po.wallet_id
          where po.tenant_id = $1
            and ($2::uuid is null or po.wallet_id = $2)
            and (cardinality($3::uuid[]) = 0 or coalesce(po.project_id, w.project_id) = any($3::uuid[]))
        ),
        scoped_subscription_events as (
          select
            case
              when se.event_type = 'prorate' then 'negative_proration_credit'
              else 'subscription_credit'
            end as category,
            'subscription_events_or_schedules' as source_table,
            se.id::text as source_id,
            s.wallet_id,
            coalesce(cg.amount, case when le.amount > 0 then le.amount else 0 end, 0)::text as amount,
            s.currency,
            se.event_status as status,
            (se.credit_grant_id is not null or se.ledger_entry_id is not null or se.invoice_id is not null or se.order_id is not null) as ref_present,
            se.created_at
          from subscription_events_or_schedules se
          join subscriptions s on s.tenant_id = se.tenant_id and s.id = se.subscription_id
          left join credit_grants cg on cg.tenant_id = se.tenant_id and cg.id = se.credit_grant_id
          left join ledger_entries le on le.tenant_id = se.tenant_id and le.id = se.ledger_entry_id
          where se.tenant_id = $1
            and se.event_type in ('renew', 'activate', 'trial_end', 'prorate')
            and ($2::uuid is null or s.wallet_id = $2)
            and (cardinality($3::uuid[]) = 0 or s.project_id = any($3::uuid[]))
        )
        select category, source_table, source_id, wallet_id, amount, currency, status, ref_present
        from (
          select * from scoped_credit_grants where category is not null
          union all
          select * from scoped_manual_ledger
          union all
          select * from scoped_payment_orders
          union all
          select * from scoped_subscription_events
        ) funding_rows
        order by created_at desc, source_id
        limit 200
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .bind(project_ids.to_vec())
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let funding_rows = rows
        .into_iter()
        .map(admin_wallet_funding_source_row_from_pg)
        .collect::<Result<Vec<_>, _>>()?;

    Ok(admin_wallet_funding_source_readback_response(
        wallet_id,
        project_ids,
        funding_rows,
    )?)
}

fn admin_wallet_funding_source_row_from_pg(
    row: PgRow,
) -> Result<AdminWalletFundingSourceReadbackRow, AdminError> {
    Ok(AdminWalletFundingSourceReadbackRow {
        category: row
            .try_get("category")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        source_table: row
            .try_get("source_table")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        source_id: row
            .try_get("source_id")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        wallet_id: row
            .try_get("wallet_id")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        amount: admin_wallet_money_from_row(&row, "amount")?,
        currency: row
            .try_get("currency")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        status: row
            .try_get("status")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
        ref_present: row
            .try_get("ref_present")
            .map_err(|error| AdminError::from(DbError::Query(error)))?,
    })
}

fn admin_wallet_funding_source_readback_response(
    wallet_id: Option<Uuid>,
    project_ids: &[Uuid],
    rows: Vec<AdminWalletFundingSourceReadbackRow>,
) -> Result<Value, AdminError> {
    let mut buckets = ADMIN_WALLET_FUNDING_SOURCE_CATEGORIES
        .iter()
        .map(|category| {
            (
                category.to_string(),
                AdminWalletFundingSourceBucket::default(),
            )
        })
        .collect::<BTreeMap<_, _>>();

    for row in rows {
        let Some(bucket) = buckets.get_mut(&row.category) else {
            continue;
        };
        bucket.count += 1;
        bucket.statuses.insert(redact_secrets(&row.status));
        bucket.ref_present |= row.ref_present;
        let current = bucket
            .amount_by_currency
            .get(&row.currency)
            .cloned()
            .unwrap_or_else(|| "0.00000000".to_string());
        let next =
            fixed_decimal_add_strings(&current, &row.amount, "funding source amount by currency")?;
        bucket.amount_by_currency.insert(row.currency.clone(), next);

        if bucket.bounded_refs.len() < ADMIN_WALLET_LINK_LIMIT as usize {
            bucket.bounded_refs.push(json!({
                "source_table": row.source_table,
                "source_id": row.source_id,
                "wallet_id": row.wallet_id,
                "amount": row.amount,
                "currency": row.currency,
                "status": redact_secrets(&row.status),
            }));
        }
    }

    let mut total_count = 0_i64;
    let mut any_ref_present = false;
    let categories = ADMIN_WALLET_FUNDING_SOURCE_CATEGORIES
        .iter()
        .map(|category| {
            let bucket = buckets.remove(*category).unwrap_or_default();
            total_count += bucket.count;
            any_ref_present |= bucket.ref_present;
            let count = bucket.count;
            let ref_present = bucket.ref_present;
            let amount_by_currency = bucket
                .amount_by_currency
                .into_iter()
                .map(|(currency, amount)| json!({ "currency": currency, "amount": amount }))
                .collect::<Vec<_>>();
            let statuses = bucket.statuses.into_iter().collect::<Vec<_>>();
            let bounded_refs = bucket.bounded_refs;
            json!({
                "category": category,
                "count": count,
                "amount_by_currency": amount_by_currency,
                "ref_present": ref_present,
                "source_status": funding_source_status(count, ref_present),
                "statuses": statuses,
                "bounded_refs": bounded_refs,
                "safe_next_action": funding_source_category_next_action(category, count, ref_present),
            })
        })
        .collect::<Vec<_>>();

    Ok(json!({
        "schema": "admin_wallet_funding_source_readback.v1",
        "source": "credit_grants_ledger_payment_orders_subscription_events",
        "wallet_id": wallet_id,
        "project_ids": project_ids,
        "total_source_count": total_count,
        "categories": categories,
        "source_status": if total_count == 0 { "not_observed" } else if any_ref_present { "ready" } else { "refs_absent" },
        "bounded_ids_only": true,
        "raw_voucher_code_returned": false,
        "raw_voucher_code_hash_returned": false,
        "raw_ledger_metadata_returned": false,
        "authorization_returned": false,
        "api_key_secret_returned": false,
        "provider_key_returned": false,
        "raw_payload_returned": false,
        "safe_next_action": if total_count == 0 {
            "Render the wallet as unfunded or ask the operator to add credit through an approved funding path."
        } else {
            "Render source counts, amounts, statuses, and bounded ids; use source-specific drilldowns for details."
        },
        "read_only": true,
        "secret_safe": true,
    }))
}

fn funding_source_status(count: i64, ref_present: bool) -> &'static str {
    if count == 0 {
        "not_observed"
    } else if ref_present {
        "ready"
    } else {
        "refs_absent"
    }
}

fn funding_source_category_next_action(
    category: &str,
    count: i64,
    ref_present: bool,
) -> &'static str {
    if count == 0 {
        return "No source observed for this category in the bounded readback.";
    }
    if !ref_present {
        return "Source rows exist without linked public refs; show count and amount only.";
    }
    match category {
        "voucher" => "Show voucher funding as redeemed/issued counts and bounded ids only.",
        "manual_adjustment" => {
            "Show manual adjustment funding and link to ledger entries when needed."
        }
        "payment_order" => {
            "Show payment order funding status and use payment/order drilldown for reconciliation."
        }
        "subscription_credit" => {
            "Show subscription credit funding and use subscription readback for lifecycle context."
        }
        "negative_proration_credit" => {
            "Show negative proration credit as subscription-derived credit; do not initiate refund from this readback."
        }
        _ => "Render bounded source summary only.",
    }
}

fn user_remaining_balance_response(
    surface: Value,
    principal: Option<&RemainingBalancePrincipal>,
) -> Result<Value, AdminError> {
    let wallet = surface
        .get("wallet")
        .ok_or_else(|| AdminError::bad_request("wallet surface missing"))?;
    let credit_grants = surface
        .get("credit_grants")
        .ok_or_else(|| AdminError::bad_request("credit grant surface missing"))?;
    let ledger_window = surface
        .get("ledger_balance_window")
        .ok_or_else(|| AdminError::bad_request("ledger balance window missing"))?;

    let active_credit_grant_total = json_money_string(
        credit_grants,
        "active_remaining_total",
        "active credit grant total",
    )?;
    let confirmed_ledger_effect = json_money_string(
        ledger_window,
        "confirmed_net_amount",
        "confirmed ledger effect",
    )?;
    let pending_ledger_effect =
        json_money_string(ledger_window, "pending_amount", "pending ledger effect")?;
    let balance_floor = json_money_string(wallet, "balance_floor", "wallet balance floor")?;
    let pending_confirmed_ledger_window = fixed_decimal_add_strings(
        &confirmed_ledger_effect,
        &pending_ledger_effect,
        "pending/confirmed ledger window",
    )?;
    let active_plus_ledger = fixed_decimal_add_strings(
        &active_credit_grant_total,
        &pending_confirmed_ledger_window,
        "active grant plus ledger window",
    )?;
    let available_to_spend =
        fixed_decimal_subtract_strings(&active_plus_ledger, &balance_floor, "available to spend")?;

    let last_credit_grant_ids = credit_grants
        .get("grants")
        .and_then(Value::as_array)
        .map(|grants| {
            grants
                .iter()
                .take(ADMIN_WALLET_LINK_LIMIT as usize)
                .filter_map(|grant| grant.get("id").and_then(Value::as_str).map(str::to_string))
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let last_ledger_entry_ids = surface
        .get("last_ledger_entry_ids")
        .and_then(Value::as_array)
        .map(|ids| {
            ids.iter()
                .take(ADMIN_WALLET_LINK_LIMIT as usize)
                .filter_map(|id| id.as_str().map(str::to_string))
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();

    let user_api_runtime = principal.is_some();
    let admin_readonly_runtime = principal.is_none();
    let ownership = remaining_balance_ownership_response(principal);

    Ok(json!({
        "schema": "user_remaining_balance_runtime.v1",
        "runtime_implemented": true,
        "contract_only": false,
        "user_api_runtime": user_api_runtime,
        "admin_readonly_runtime": admin_readonly_runtime,
        "ownership_scope_verified": user_api_runtime,
        "ownership": ownership,
        "route_invoked": true,
        "public_route_invoked": true,
        "wallet_id": wallet.get("id").cloned().unwrap_or(Value::Null),
        "tenant_id": wallet.get("tenant_id").cloned().unwrap_or(Value::Null),
        "project_id": wallet.get("project_id").cloned().unwrap_or(Value::Null),
        "currency": wallet.get("currency").cloned().unwrap_or(Value::Null),
        "available_to_spend": available_to_spend,
        "wallet_balance_floor": balance_floor,
        "active_credit_grant_total": active_credit_grant_total,
        "pending_confirmed_ledger_window": pending_confirmed_ledger_window,
        "confirmed_ledger_effect": confirmed_ledger_effect,
        "pending_ledger_effect": pending_ledger_effect,
        "wallet_available_balance": available_to_spend,
        "ledger_balance_window": ledger_window,
        "pending_reserves": surface.get("pending_reserves").cloned().unwrap_or(Value::Null),
        "budget_remaining": surface.get("budget_remaining").cloned().unwrap_or(Value::Null),
        "last_ledger_entry_ids": last_ledger_entry_ids,
        "last_credit_grant_ids": last_credit_grant_ids,
        "credit_grant_expiration_readback": surface.get("credit_grant_expiration_readback").cloned().unwrap_or(Value::Null),
        "funding_source_readback": surface.get("funding_source_readback").cloned().unwrap_or(Value::Null),
        "bounded_links": surface.get("bounded_links").cloned().unwrap_or(Value::Null),
        "formula": {
            "name": "active_credit_grants_plus_pending_confirmed_ledger_minus_wallet_balance_floor",
            "expression": "active_credit_grant_total + pending_confirmed_ledger_window - wallet_balance_floor",
            "money_fields_are_decimal_strings": true,
        },
        "readback": {
            "wallet_row": true,
            "credit_grants": true,
            "ledger_window": true,
            "budget_marker": true,
            "bounded_ids": true,
            "direct_wallet_snapshot_mutation": false,
        },
        "consistency": surface.get("consistency").cloned().unwrap_or(Value::Null),
        "read_only": true,
        "secret_safe": true,
        "paid_gate_changed": false,
    }))
}

fn user_remaining_balance_refusal_response(
    wallet_id: Uuid,
    refusal_code: &'static str,
    message: &'static str,
    principal: Option<&RemainingBalancePrincipal>,
) -> Value {
    let user_api_runtime = principal.is_some();
    json!({
        "schema": "user_remaining_balance_runtime.v1",
        "runtime_implemented": true,
        "contract_only": false,
        "user_api_runtime": user_api_runtime,
        "admin_readonly_runtime": !user_api_runtime,
        "ownership_scope_verified": user_api_runtime,
        "ownership": remaining_balance_ownership_response(principal),
        "route_invoked": true,
        "public_route_invoked": true,
        "wallet_id": wallet_id,
        "status": "refused",
        "refusal_code": refusal_code,
        "message": message,
        "read_only": true,
        "secret_safe": true,
        "paid_gate_changed": false,
    })
}

fn remaining_balance_ownership_response(principal: Option<&RemainingBalancePrincipal>) -> Value {
    match principal {
        Some(principal) => json!({
            "source": principal.source.as_str(),
            "tenant_id": principal.tenant_id,
            "project_id": principal.project_id,
            "wallet_id": principal.wallet_id,
            "currency": principal.currency,
            "user_id": principal.user_id,
            "virtual_key_id": principal.virtual_key_id,
            "server_side_lookup": true,
            "tenant_scope_match": true,
            "project_scope_match": true,
            "wallet_scope_match": true,
            "raw_token_echoed": false,
            "secret_safe": true,
        }),
        None => json!({
            "source": "admin_session",
            "server_side_lookup": false,
            "tenant_scope_match": false,
            "project_scope_match": false,
            "wallet_scope_match": false,
            "raw_token_echoed": false,
            "secret_safe": true,
        }),
    }
}

fn json_money_string(
    value: &Value,
    field: &'static str,
    label: &'static str,
) -> Result<String, AdminError> {
    value
        .get(field)
        .and_then(Value::as_str)
        .ok_or_else(|| AdminError::bad_request(format!("{label} missing")))
        .and_then(admin_wallet_fixed_money_string)
}

fn fixed_decimal_add_strings(
    left: &str,
    right: &str,
    label: &'static str,
) -> Result<String, AdminError> {
    let left = parse_billing_fixed_decimal(left)?;
    let right = parse_billing_fixed_decimal(right)?;
    left.checked_add(right)
        .map(|value| value.to_string())
        .map_err(|_| AdminError::bad_request(format!("{label} overflow")))
}

fn fixed_decimal_subtract_strings(
    left: &str,
    right: &str,
    label: &'static str,
) -> Result<String, AdminError> {
    let left = parse_billing_fixed_decimal(left)?;
    let right = parse_billing_fixed_decimal(right)?;
    let negative_right = FixedDecimal::from_units(-right.units(), right.scale())
        .map_err(|_| AdminError::bad_request(format!("{label} overflow")))?;
    left.checked_add(negative_right)
        .map(|value| value.to_string())
        .map_err(|_| AdminError::bad_request(format!("{label} overflow")))
}

