async fn create_local_payment_demo_order_tx(
    tx: &mut Transaction<'_, Postgres>,
    session: &AdminSession,
    project_id: Option<Uuid>,
    wallet_id: Uuid,
    currency: &str,
    amount: &str,
    reason: &str,
    idempotency_fingerprint: &str,
) -> Result<Value, AdminError> {
    lock_local_payment_demo_wallet_tx(tx, wallet_id, currency).await?;

    if let Some(existing) =
        get_local_payment_demo_order_by_idempotency_tx(tx, idempotency_fingerprint).await?
    {
        return Ok(local_payment_demo_order_response(
            "replayed",
            "order_create",
            existing,
            None,
        ));
    }

    let order_id = Uuid::new_v4();
    let audit_id = insert_admin_audit_log_tx(
        tx,
        new_admin_audit_log(
            session,
            "billing.local_payment_demo.order_create",
            None,
            &LocalPaymentDemoAuditResource {
                tenant_id: DEFAULT_TENANT_ID,
                id: order_id,
                resource_type: "payment_order",
                summary: json!({
                    "schema": LOCAL_PAYMENT_DEMO_SCHEMA,
                    "operation": "order_create",
                    "local_only": true,
                    "merchant_connected": false,
                    "amount": amount,
                    "currency": currency,
                    "wallet_id": wallet_id,
                    "secret_safe": true
                }),
            },
            json!({
                "reason": reason,
                "action_result": "created",
                "status": "pending_payment",
                "operation": "order_create",
                "local_only": true,
                "merchant_connected": false,
                "amount": amount,
                "currency": currency,
                "wallet_id": wallet_id,
                "order_id": order_id,
                "reason_provided": !reason.is_empty(),
                "secret_safe": true,
                "payload_omitted": true,
                "audit_log_write": true,
                "idempotency_key_output": "omitted",
                "raw_metadata_output": "omitted"
            }),
            None,
        ),
    )
    .await?;

    let row = sqlx::query(
        r#"
        insert into payment_orders (
          id, tenant_id, project_id, wallet_id, currency, amount, status, source,
          external_reference_id, idempotency_key_hash, audit_id, request_summary, metadata
        )
        values ($1, $2, $3, $4, $5, $6::numeric, 'pending_payment', $7,
                $8, $9, $10, $11, $12)
        returning
          id, tenant_id, project_id, wallet_id, currency, amount::text as amount,
          status, payment_intent_id, payment_capture_id, invoice_id,
          credit_grant_id, ledger_entry_id, audit_id,
          created_at::text as created_at, updated_at::text as updated_at
        "#,
    )
    .bind(order_id)
    .bind(DEFAULT_TENANT_ID)
    .bind(project_id)
    .bind(wallet_id)
    .bind(currency)
    .bind(amount)
    .bind(LOCAL_PAYMENT_DEMO_SOURCE)
    .bind(format!("local-demo-{order_id}"))
    .bind(idempotency_fingerprint)
    .bind(audit_id)
    .bind(json!({
        "mode": "local_runtime_demo",
        "idempotency_key": "omitted",
        "raw_metadata": "omitted"
    }))
    .bind(json!({
        "operation": "payment_demo_order_create",
        "local_only": true,
        "merchant_connected": false,
        "reason_provided": true,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let order = local_payment_demo_order_from_row(row)?;
    insert_local_payment_demo_event_tx(
        tx,
        &order,
        None,
        None,
        "order_create",
        "applied",
        None,
        Some(audit_id),
    )
    .await?;

    Ok(local_payment_demo_order_response(
        "created",
        "order_create",
        order,
        None,
    ))
}

async fn mark_local_payment_demo_order_paid_tx(
    tx: &mut Transaction<'_, Postgres>,
    session: &AdminSession,
    order_id: Uuid,
    reason: &str,
    payment_fingerprint: &str,
) -> Result<Value, AdminError> {
    let order = get_local_payment_demo_order_for_update_tx(tx, order_id)
        .await?
        .ok_or_else(|| AdminError::not_found("payment order"))?;
    if order.tenant_id != DEFAULT_TENANT_ID {
        return Err(AdminError::not_found("payment order"));
    }
    lock_local_payment_demo_wallet_tx(tx, order.wallet_id, &order.currency).await?;

    if order.status == "paid" {
        let readback_extra = get_local_payment_demo_runtime_readback_extra_tx(tx, order.id).await?;
        return Ok(local_payment_demo_order_response(
            "replayed",
            "mark_paid",
            order,
            Some(merge_json_objects(
                json!({
                "message": "order was already marked paid",
                "no_duplicate_credit_or_ledger_write": true
                }),
                readback_extra,
            )),
        ));
    }
    if order.status != "pending_payment" {
        return Err(AdminError::bad_request(
            "only pending local demo payment orders can be marked paid",
        ));
    }

    if let Some(existing_capture_order_id) =
        get_local_payment_demo_capture_order_id_by_idempotency_tx(tx, payment_fingerprint).await?
    {
        if existing_capture_order_id != order.id {
            return Err(AdminError::bad_request(
                "payment idempotency key already belongs to another local demo order",
            ));
        }
        let replayed = get_local_payment_demo_order_for_update_tx(tx, order.id)
            .await?
            .ok_or_else(|| AdminError::not_found("payment order"))?;
        let readback_extra =
            get_local_payment_demo_runtime_readback_extra_tx(tx, replayed.id).await?;
        return Ok(local_payment_demo_order_response(
            "replayed",
            "mark_paid",
            replayed,
            Some(merge_json_objects(
                json!({
                "message": "payment mark-paid was replayed",
                "no_duplicate_credit_or_ledger_write": true
                }),
                readback_extra,
            )),
        ));
    }

    let provider_reference_redacted = format!("local_demo_{}", &payment_fingerprint[..12]);
    let intent_audit_id = insert_admin_audit_log_tx(
        tx,
        new_admin_audit_log(
            session,
            "billing.local_payment_demo.mark_paid",
            None,
            &LocalPaymentDemoAuditResource {
                tenant_id: DEFAULT_TENANT_ID,
                id: order.id,
                resource_type: "payment_capture",
                summary: json!({
                    "schema": LOCAL_PAYMENT_DEMO_SCHEMA,
                    "operation": "mark_paid",
                    "local_only": true,
                    "merchant_connected": false,
                    "amount": order.amount,
                    "currency": order.currency,
                    "wallet_id": order.wallet_id,
                    "secret_safe": true
                }),
            },
            json!({
                "reason": reason,
                "action_result": "paid",
                "status": "paid",
                "operation": "mark_paid",
                "local_only": true,
                "merchant_connected": false,
                "amount": order.amount,
                "currency": order.currency,
                "wallet_id": order.wallet_id,
                "order_id": order.id,
                "reason_provided": !reason.is_empty(),
                "provider_reference_redacted": provider_reference_redacted,
                "secret_safe": true,
                "payload_omitted": true,
                "audit_log_write": true,
                "idempotency_key_output": "omitted",
                "raw_metadata_output": "omitted"
            }),
            None,
        ),
    )
    .await?;

    let payment_intent_id: Uuid = sqlx::query_scalar(
        r#"
        insert into payment_intents (
          tenant_id, project_id, wallet_id, order_id, provider, provider_reference_hash,
          provider_reference_redacted, currency, amount, status, idempotency_key_hash,
          audit_id, request_summary, metadata
        )
        values ($1, $2, $3, $4, 'local_demo', $5,
                $6, $7, $8::numeric, 'captured', $9,
                $10, $11, $12)
        returning id
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order.project_id)
    .bind(order.wallet_id)
    .bind(order.id)
    .bind(payment_fingerprint)
    .bind(&provider_reference_redacted)
    .bind(&order.currency)
    .bind(&order.amount)
    .bind(local_payment_demo_hash(
        "intent",
        payment_fingerprint.to_string(),
    ))
    .bind(intent_audit_id)
    .bind(json!({
        "provider": "local_demo",
        "provider_payload": "omitted",
        "client_secret": "omitted"
    }))
    .bind(json!({
        "operation": "payment_demo_intent",
        "local_only": true,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let credit_grant_id: Uuid = sqlx::query_scalar(
        r#"
        insert into credit_grants (
          tenant_id, wallet_id, amount, remaining_amount, currency, source,
          valid_from, status, metadata
        )
        values ($1, $2, $3::numeric, $3::numeric, $4, 'payment_order_invoice',
                now(), 'active', $5)
        returning id
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order.wallet_id)
    .bind(&order.amount)
    .bind(&order.currency)
    .bind(json!({
        "operation": LOCAL_PAYMENT_DEMO_LEDGER_OPERATION,
        "payment_order_id": order.id,
        "local_only": true,
        "merchant_connected": false,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let ledger_entry_id: Uuid = sqlx::query_scalar(
        r#"
        insert into ledger_entries (
          tenant_id, project_id, wallet_id, request_id, virtual_key_id, trace_id,
          related_ledger_entry_id, entry_type, amount, currency, status,
          idempotency_key, usage_snapshot, policy_snapshot, metadata
        )
        values ($1, $2, $3, null, null, null,
                null, 'adjust', $4::numeric, $5, 'confirmed',
                $6, '{}'::jsonb, '{}'::jsonb, $7)
        returning id
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order.project_id)
    .bind(order.wallet_id)
    .bind(&order.amount)
    .bind(&order.currency)
    .bind(local_payment_demo_hash("ledger", payment_fingerprint.to_string()))
    .bind(json!({
        "operation": LOCAL_PAYMENT_DEMO_LEDGER_OPERATION,
        "entry_explanation": "local demo payment top-up credited as a confirmed adjust ledger entry",
        "payment_order_id": order.id,
        "credit_grant_id": credit_grant_id,
        "local_only": true,
        "merchant_connected": false,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let payment_capture_id: Uuid = sqlx::query_scalar(
        r#"
        insert into payment_captures (
          tenant_id, project_id, wallet_id, order_id, payment_intent_id,
          provider_reference_hash, provider_reference_redacted, currency, amount, status,
          idempotency_key_hash, credit_grant_id, ledger_entry_id, audit_id,
          request_summary, metadata
        )
        values ($1, $2, $3, $4, $5,
                $6, $7, $8, $9::numeric, 'captured',
                $10, $11, $12, $13,
                $14, $15)
        returning id
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order.project_id)
    .bind(order.wallet_id)
    .bind(order.id)
    .bind(payment_intent_id)
    .bind(payment_fingerprint)
    .bind(&provider_reference_redacted)
    .bind(&order.currency)
    .bind(&order.amount)
    .bind(payment_fingerprint)
    .bind(credit_grant_id)
    .bind(ledger_entry_id)
    .bind(intent_audit_id)
    .bind(json!({
        "provider": "local_demo",
        "provider_payload": "omitted",
        "idempotency_key": "omitted"
    }))
    .bind(json!({
        "operation": "payment_demo_capture",
        "local_only": true,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let invoice_number = format!(
        "LOCAL-DEMO-{}",
        &payment_fingerprint[..16].to_ascii_uppercase()
    );
    let receipt_number = format!(
        "LOCAL-RCT-{}",
        &payment_fingerprint[..16].to_ascii_uppercase()
    );
    let invoice_id: Uuid = sqlx::query_scalar(
        r#"
        insert into invoices (
          tenant_id, project_id, wallet_id, order_id, payment_capture_id,
          invoice_number, currency, total_amount, status, line_items,
          audit_id, request_summary, metadata
        )
        values ($1, $2, $3, $4, $5,
                $6, $7, $8::numeric, 'paid', $9,
                $10, $11, $12)
        returning id
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order.project_id)
    .bind(order.wallet_id)
    .bind(order.id)
    .bind(payment_capture_id)
    .bind(&invoice_number)
    .bind(&order.currency)
    .bind(&order.amount)
    .bind(json!([{
        "description": "Local demo credit top-up placeholder",
        "amount": order.amount,
        "currency": order.currency
    }]))
    .bind(intent_audit_id)
    .bind(json!({
        "invoice_payload": "placeholder_only",
        "pii_payload": "omitted"
    }))
    .bind(json!({
        "operation": "payment_demo_invoice_placeholder",
        "local_only": true,
        "real_invoice_issued": false,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let receipt_id: Uuid = sqlx::query_scalar(
        r#"
        insert into invoice_receipts (
          tenant_id, project_id, wallet_id, invoice_id, payment_capture_id,
          receipt_number, currency, total_amount, status, audit_id,
          request_summary, metadata
        )
        values ($1, $2, $3, $4, $5,
                $6, $7, $8::numeric, 'issued', $9,
                $10, $11)
        returning id
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order.project_id)
    .bind(order.wallet_id)
    .bind(invoice_id)
    .bind(payment_capture_id)
    .bind(&receipt_number)
    .bind(&order.currency)
    .bind(&order.amount)
    .bind(intent_audit_id)
    .bind(json!({
        "receipt_payload": "runtime_skeleton_only",
        "pii_payload": "omitted"
    }))
    .bind(json!({
        "operation": "payment_demo_receipt_skeleton",
        "local_only": true,
        "real_legal_receipt_issued": false,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    sqlx::query(
        r#"
        update payment_captures
        set invoice_id = $3,
            receipt_id = $4,
            updated_at = now()
        where tenant_id = $1 and id = $2
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(payment_capture_id)
    .bind(invoice_id)
    .bind(receipt_id)
    .execute(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let paid = sqlx::query(
        r#"
        update payment_orders
        set status = 'paid',
            payment_intent_id = $3,
            payment_capture_id = $4,
            invoice_id = $5,
            credit_grant_id = $6,
            ledger_entry_id = $7,
            updated_at = now()
        where tenant_id = $1 and id = $2
        returning
          id, tenant_id, project_id, wallet_id, currency, amount::text as amount,
          status, payment_intent_id, payment_capture_id, invoice_id,
          credit_grant_id, ledger_entry_id, audit_id,
          created_at::text as created_at, updated_at::text as updated_at
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order.id)
    .bind(payment_intent_id)
    .bind(payment_capture_id)
    .bind(invoice_id)
    .bind(credit_grant_id)
    .bind(ledger_entry_id)
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let paid_order = local_payment_demo_order_from_row(paid)?;

    let reconciliation_id: Uuid = sqlx::query_scalar(
        r#"
        insert into payment_reconciliations (
          tenant_id, project_id, wallet_id, order_id, payment_capture_id, invoice_id,
          ledger_entry_id, refund_id, currency, payment_amount, invoice_amount, ledger_amount,
          status, audit_id, request_summary, metadata
        )
        values ($1, $2, $3, $4, $5, $6,
                $7, null, $8, $9::numeric, $9::numeric, $9::numeric,
                'matched', $10, $11, $12)
        returning id
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order.project_id)
    .bind(order.wallet_id)
    .bind(order.id)
    .bind(payment_capture_id)
    .bind(invoice_id)
    .bind(ledger_entry_id)
    .bind(&order.currency)
    .bind(&order.amount)
    .bind(intent_audit_id)
    .bind(json!({"mode": "local_runtime_demo"}))
    .bind(json!({
        "operation": "payment_demo_reconciliation",
        "matched": true,
        "local_only": true,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let capture_event_id = insert_local_payment_demo_event_tx(
        tx,
        &paid_order,
        Some(payment_intent_id),
        Some(payment_capture_id),
        "capture_confirm",
        "applied",
        None,
        Some(intent_audit_id),
    )
    .await?;

    let reconciliation_event_id = insert_local_payment_demo_event_tx(
        tx,
        &paid_order,
        Some(payment_intent_id),
        Some(payment_capture_id),
        "reconciliation",
        "matched",
        None,
        Some(intent_audit_id),
    )
    .await?;

    Ok(local_payment_demo_order_response(
        "paid",
        "mark_paid",
        paid_order,
        Some(json!({
            "credit_grant_id": credit_grant_id,
            "ledger_entry_id": ledger_entry_id,
            "invoice_id": invoice_id,
            "invoice_number": invoice_number,
            "invoice_status": "paid",
            "invoice_placeholder_only": false,
            "receipt_id": receipt_id,
            "receipt_number": receipt_number,
            "receipt_status": "issued",
            "reconciliation_id": reconciliation_id,
            "reconciliation_status": "matched",
            "capture_event_id": capture_event_id,
            "reconciliation_event_id": reconciliation_event_id,
            "ledger_explanation": "confirmed adjust entry credits the wallet for this local demo payment",
            "provider_reference": provider_reference_redacted
        })),
    ))
}

async fn lock_local_payment_demo_wallet_tx(
    tx: &mut Transaction<'_, Postgres>,
    wallet_id: Uuid,
    currency: &str,
) -> Result<(), AdminError> {
    let row = sqlx::query(
        r#"
        select currency
        from wallets
        where tenant_id = $1 and id = $2 and status in ('active', 'suspended')
        for update
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?
    .ok_or_else(|| AdminError::not_found("wallet"))?;
    let wallet_currency: String = row
        .try_get("currency")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    if wallet_currency != currency {
        return Err(AdminError::bad_request(
            "payment demo currency must match wallet currency",
        ));
    }
    Ok(())
}

async fn get_local_payment_demo_order_by_idempotency_tx(
    tx: &mut Transaction<'_, Postgres>,
    idempotency_fingerprint: &str,
) -> Result<Option<LocalPaymentDemoOrderRow>, AdminError> {
    let sql = local_payment_demo_order_select_sql(
        "tenant_id = $1 and idempotency_key_hash = $2",
        "for update",
    );
    let row = sqlx::query(&sql)
        .bind(DEFAULT_TENANT_ID)
        .bind(idempotency_fingerprint)
        .fetch_optional(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.map(local_payment_demo_order_from_row).transpose()
}

async fn get_local_payment_demo_order_for_update_tx(
    tx: &mut Transaction<'_, Postgres>,
    order_id: Uuid,
) -> Result<Option<LocalPaymentDemoOrderRow>, AdminError> {
    let sql = local_payment_demo_order_select_sql("tenant_id = $1 and id = $2", "for update");
    let row = sqlx::query(&sql)
        .bind(DEFAULT_TENANT_ID)
        .bind(order_id)
        .fetch_optional(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.map(local_payment_demo_order_from_row).transpose()
}

async fn get_local_payment_demo_capture_order_id_by_idempotency_tx(
    tx: &mut Transaction<'_, Postgres>,
    payment_fingerprint: &str,
) -> Result<Option<Uuid>, AdminError> {
    let row = sqlx::query(
        r#"
        select order_id
        from payment_captures
        where tenant_id = $1 and idempotency_key_hash = $2
        for update
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(payment_fingerprint)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.map(|row| {
        row.try_get("order_id")
            .map_err(|error| AdminError::from(DbError::Query(error)))
    })
    .transpose()
}

fn local_payment_demo_order_select_sql(where_clause: &str, lock_clause: &str) -> String {
    format!(
        r#"
        select
          id, tenant_id, project_id, wallet_id, currency, amount::text as amount,
          status, payment_intent_id, payment_capture_id, invoice_id,
          credit_grant_id, ledger_entry_id, audit_id,
          created_at::text as created_at, updated_at::text as updated_at
        from payment_orders
        where {where_clause}
          and source = '{LOCAL_PAYMENT_DEMO_SOURCE}'
        {lock_clause}
        "#
    )
}

