async fn insert_local_payment_demo_event_tx(
    tx: &mut Transaction<'_, Postgres>,
    order: &LocalPaymentDemoOrderRow,
    payment_intent_id: Option<Uuid>,
    payment_capture_id: Option<Uuid>,
    event_type: &'static str,
    outcome: &'static str,
    refusal_code: Option<&'static str>,
    audit_id: Option<Uuid>,
) -> Result<Uuid, AdminError> {
    let row = sqlx::query(
        r#"
        insert into payment_events (
          tenant_id, project_id, wallet_id, order_id, payment_intent_id,
          payment_capture_id, event_type, outcome, refusal_code,
          idempotency_key_hash, audit_id, request_summary, metadata
        )
        values ($1, $2, $3, $4, $5,
                $6, $7, $8, $9,
                null, $10, $11, $12)
        returning id
        "#,
    )
    .bind(order.tenant_id)
    .bind(order.project_id)
    .bind(order.wallet_id)
    .bind(order.id)
    .bind(payment_intent_id)
    .bind(payment_capture_id)
    .bind(event_type)
    .bind(outcome)
    .bind(refusal_code)
    .bind(audit_id)
    .bind(json!({
        "mode": "local_runtime_demo",
        "idempotency_key": "omitted"
    }))
    .bind(json!({
        "operation": format!("payment_demo_{event_type}"),
        "local_only": true,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.try_get("id")
        .map_err(|error| AdminError::from(DbError::Query(error)))
}

fn merge_json_objects(primary: Value, secondary: Option<Value>) -> Value {
    let Some(Value::Object(secondary_map)) = secondary else {
        return primary;
    };
    let Value::Object(mut primary_map) = primary else {
        return Value::Object(secondary_map);
    };
    for (key, value) in secondary_map {
        primary_map.entry(key).or_insert(value);
    }
    Value::Object(primary_map)
}

async fn get_local_payment_demo_runtime_readback_extra_tx(
    tx: &mut Transaction<'_, Postgres>,
    order_id: Uuid,
) -> Result<Option<Value>, AdminError> {
    let invoice_row = sqlx::query(
        r#"
        select
          id, invoice_number, status, currency, total_amount::text as total_amount,
          payment_capture_id, audit_id, created_at::text as issued_at
        from invoices
        where tenant_id = $1 and order_id = $2
        order by created_at desc
        limit 1
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order_id)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let Some(invoice_row) = invoice_row else {
        return Ok(None);
    };

    let invoice_id: Uuid = invoice_row
        .try_get("id")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let invoice_number: String = invoice_row
        .try_get("invoice_number")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let invoice_status: String = invoice_row
        .try_get("status")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let invoice_currency: String = invoice_row
        .try_get("currency")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let invoice_amount = admin_wallet_fixed_money_string(
        invoice_row
            .try_get::<String, _>("total_amount")
            .map_err(|error| AdminError::from(DbError::Query(error)))?
            .as_str(),
    )?;
    let invoice_payment_capture_id: Option<Uuid> = invoice_row
        .try_get("payment_capture_id")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let invoice_audit_id: Option<Uuid> = invoice_row
        .try_get("audit_id")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let invoice_issued_at: String = invoice_row
        .try_get("issued_at")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let receipt_row = sqlx::query(
        r#"
        select
          id, receipt_number, status, currency, total_amount::text as total_amount,
          payment_capture_id, audit_id, created_at::text as issued_at
        from invoice_receipts
        where tenant_id = $1 and invoice_id = $2
        order by created_at desc
        limit 1
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(invoice_id)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let reconciliation_row = sqlx::query(
        r#"
        select
          id, status, payment_capture_id, invoice_id, ledger_entry_id, refund_id,
          currency, payment_amount::text as payment_amount,
          invoice_amount::text as invoice_amount,
          ledger_amount::text as ledger_amount,
          audit_id, created_at::text as matched_at
        from payment_reconciliations
        where tenant_id = $1 and order_id = $2
        order by created_at desc
        limit 1
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order_id)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let event_rows = sqlx::query(
        r#"
        select id, event_type, outcome, created_at::text as created_at
        from payment_events
        where tenant_id = $1
          and order_id = $2
          and event_type in ('capture_confirm', 'reconciliation')
        order by created_at asc
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(order_id)
    .fetch_all(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let receipt = match receipt_row {
        Some(row) => {
            let receipt_amount = admin_wallet_fixed_money_string(
                row.try_get::<String, _>("total_amount")
                    .map_err(|error| AdminError::from(DbError::Query(error)))?
                    .as_str(),
            )?;
            json!({
                "receipt_id": row.try_get::<Uuid, _>("id").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "receipt_number": row.try_get::<String, _>("receipt_number").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "receipt_status": row.try_get::<String, _>("status").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "receipt_amount": receipt_amount,
                "receipt_currency": row.try_get::<String, _>("currency").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "receipt_issued_at": row.try_get::<String, _>("issued_at").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "receipt_payment_capture_id": row.try_get::<Option<Uuid>, _>("payment_capture_id").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "receipt_audit_id": row.try_get::<Option<Uuid>, _>("audit_id").map_err(|error| AdminError::from(DbError::Query(error)))?
            })
        }
        None => Value::Null,
    };

    let reconciliation = match reconciliation_row {
        Some(row) => {
            let payment_amount = admin_wallet_fixed_money_string(
                row.try_get::<String, _>("payment_amount")
                    .map_err(|error| AdminError::from(DbError::Query(error)))?
                    .as_str(),
            )?;
            let invoice_amount_readback = admin_wallet_fixed_money_string(
                row.try_get::<String, _>("invoice_amount")
                    .map_err(|error| AdminError::from(DbError::Query(error)))?
                    .as_str(),
            )?;
            let ledger_amount = admin_wallet_fixed_money_string(
                row.try_get::<String, _>("ledger_amount")
                    .map_err(|error| AdminError::from(DbError::Query(error)))?
                    .as_str(),
            )?;
            json!({
                "reconciliation_id": row.try_get::<Uuid, _>("id").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "reconciliation_status": row.try_get::<String, _>("status").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "reconciliation_matched_at": row.try_get::<String, _>("matched_at").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "reconciliation_payment_capture_id": row.try_get::<Option<Uuid>, _>("payment_capture_id").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "reconciliation_invoice_id": row.try_get::<Option<Uuid>, _>("invoice_id").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "reconciliation_ledger_entry_id": row.try_get::<Option<Uuid>, _>("ledger_entry_id").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "reconciliation_refund_id": row.try_get::<Option<Uuid>, _>("refund_id").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "reconciliation_currency": row.try_get::<String, _>("currency").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "reconciliation_payment_amount": payment_amount,
                "reconciliation_invoice_amount": invoice_amount_readback,
                "reconciliation_ledger_amount": ledger_amount,
                "reconciliation_audit_id": row.try_get::<Option<Uuid>, _>("audit_id").map_err(|error| AdminError::from(DbError::Query(error)))?
            })
        }
        None => Value::Null,
    };

    let mut capture_event_id = Value::Null;
    let mut reconciliation_event_id = Value::Null;
    let provider_event_refs = event_rows
        .into_iter()
        .map(|row| {
            let id: Uuid = row
                .try_get("id")
                .map_err(|error| AdminError::from(DbError::Query(error)))?;
            let event_type: String = row
                .try_get("event_type")
                .map_err(|error| AdminError::from(DbError::Query(error)))?;
            if event_type == "capture_confirm" {
                capture_event_id = json!(id);
            } else if event_type == "reconciliation" {
                reconciliation_event_id = json!(id);
            }
            Ok(json!({
                "event_id": id,
                "event_type": event_type,
                "outcome": row.try_get::<String, _>("outcome").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "created_at": row.try_get::<String, _>("created_at").map_err(|error| AdminError::from(DbError::Query(error)))?,
                "source": "local_payment_demo_event_log"
            }))
        })
        .collect::<Result<Vec<_>, AdminError>>()?;

    let mut extra = json!({
        "invoice_id": invoice_id,
        "invoice_number": invoice_number,
        "invoice_status": invoice_status,
        "invoice_amount": invoice_amount,
        "invoice_currency": invoice_currency,
        "invoice_issued_at": invoice_issued_at,
        "invoice_payment_capture_id": invoice_payment_capture_id,
        "invoice_audit_id": invoice_audit_id,
        "receipt": receipt,
        "reconciliation_readback": reconciliation,
        "capture_event_id": capture_event_id,
        "reconciliation_event_id": reconciliation_event_id,
        "provider_event_refs": provider_event_refs
    });

    if let Some(receipt_object) = extra.get("receipt").and_then(Value::as_object).cloned() {
        if let Some(value) = receipt_object.get("receipt_id") {
            extra["receipt_id"] = value.clone();
        }
        if let Some(value) = receipt_object.get("receipt_number") {
            extra["receipt_number"] = value.clone();
        }
        if let Some(value) = receipt_object.get("receipt_status") {
            extra["receipt_status"] = value.clone();
        }
        if let Some(value) = receipt_object.get("receipt_issued_at") {
            extra["receipt_issued_at"] = value.clone();
        }
        if let Some(value) = receipt_object.get("receipt_payment_capture_id") {
            extra["receipt_payment_capture_id"] = value.clone();
        }
        if let Some(value) = receipt_object.get("receipt_audit_id") {
            extra["receipt_audit_id"] = value.clone();
        }
    }
    if let Some(reconciliation_object) = extra
        .get("reconciliation_readback")
        .and_then(Value::as_object)
        .cloned()
    {
        if let Some(value) = reconciliation_object.get("reconciliation_id") {
            extra["reconciliation_id"] = value.clone();
        }
        if let Some(value) = reconciliation_object.get("reconciliation_status") {
            extra["reconciliation_status"] = value.clone();
        }
        if let Some(value) = reconciliation_object.get("reconciliation_matched_at") {
            extra["reconciliation_matched_at"] = value.clone();
        }
    }

    Ok(Some(extra))
}

fn local_payment_demo_order_response(
    outcome: &'static str,
    operation: &'static str,
    order: LocalPaymentDemoOrderRow,
    extra: Option<Value>,
) -> Value {
    let extra_value = extra.unwrap_or(Value::Null);
    let provider_reference = extra_value
        .get("provider_reference")
        .cloned()
        .unwrap_or(Value::Null);
    let invoice_number = extra_value
        .get("invoice_number")
        .cloned()
        .unwrap_or(Value::Null);
    let invoice_status = extra_value
        .get("invoice_status")
        .cloned()
        .unwrap_or_else(|| {
            if order.invoice_id.is_some() {
                json!("paid")
            } else {
                json!("not_created")
            }
        });
    let invoice_issued_at = extra_value
        .get("invoice_issued_at")
        .cloned()
        .unwrap_or(Value::Null);
    let invoice_payment_capture_id = extra_value
        .get("invoice_payment_capture_id")
        .cloned()
        .unwrap_or_else(|| json!(order.payment_capture_id));
    let invoice_audit_id = extra_value
        .get("invoice_audit_id")
        .cloned()
        .unwrap_or(Value::Null);
    let receipt_id = extra_value
        .get("receipt_id")
        .cloned()
        .unwrap_or(Value::Null);
    let receipt_number = extra_value
        .get("receipt_number")
        .cloned()
        .unwrap_or(Value::Null);
    let receipt_status = extra_value
        .get("receipt_status")
        .cloned()
        .unwrap_or_else(|| {
            if order.status == "paid" {
                json!("issued")
            } else {
                json!("not_created")
            }
        });
    let receipt_issued_at = extra_value
        .get("receipt_issued_at")
        .cloned()
        .unwrap_or(Value::Null);
    let receipt_payment_capture_id = extra_value
        .get("receipt_payment_capture_id")
        .cloned()
        .unwrap_or_else(|| json!(order.payment_capture_id));
    let receipt_audit_id = extra_value
        .get("receipt_audit_id")
        .cloned()
        .unwrap_or(Value::Null);
    let reconciliation_id = extra_value
        .get("reconciliation_id")
        .cloned()
        .unwrap_or(Value::Null);
    let reconciliation_status = extra_value
        .get("reconciliation_status")
        .cloned()
        .unwrap_or_else(|| {
            if order.status == "paid" {
                json!("matched")
            } else {
                json!("pending_payment")
            }
        });
    let reconciliation_matched_at = extra_value
        .get("reconciliation_matched_at")
        .cloned()
        .unwrap_or(Value::Null);
    let capture_event_id = extra_value
        .get("capture_event_id")
        .cloned()
        .unwrap_or(Value::Null);
    let reconciliation_event_id = extra_value
        .get("reconciliation_event_id")
        .cloned()
        .unwrap_or(Value::Null);
    let provider_event_refs = extra_value
        .get("provider_event_refs")
        .cloned()
        .unwrap_or_else(|| {
            let mut refs = Vec::new();
            if capture_event_id != Value::Null {
                refs.push(json!({
                    "event_id": capture_event_id,
                    "event_type": "capture_confirm",
                    "source": "local_payment_demo_event_log"
                }));
            }
            if reconciliation_event_id != Value::Null {
                refs.push(json!({
                    "event_id": reconciliation_event_id,
                    "event_type": "reconciliation",
                    "source": "local_payment_demo_event_log"
                }));
            }
            json!(refs)
        });
    let provider_reference_redacted = provider_reference != Value::Null;
    let payment_refs_present =
        order.payment_intent_id.is_some() && order.payment_capture_id.is_some();
    let ledger_refs_present = order.credit_grant_id.is_some() && order.ledger_entry_id.is_some();
    let invoice_present = order.invoice_id.is_some();
    let receipt_present = receipt_id != Value::Null;
    let reconciliation_present = reconciliation_id != Value::Null;
    let invoice_receipt_reconciliation_status = if order.status == "paid"
        && payment_refs_present
        && ledger_refs_present
        && invoice_present
        && receipt_present
        && reconciliation_present
    {
        "matched"
    } else if order.status == "paid" {
        "incomplete_readback"
    } else {
        "pending_payment"
    };
    let invoice_receipt_reconciliation_safe_next_action =
        match invoice_receipt_reconciliation_status {
            "matched" => "display_runtime_invoice_receipt_reconciliation_readback",
            "incomplete_readback" => "review_local_demo_runtime_refs_before_display",
            _ => "mark_order_paid_to_create_runtime_invoice_receipt_reconciliation_readback",
        };
    let refs = json!({
        "order_id": order.id,
        "payment_intent_id": order.payment_intent_id,
        "payment_capture_id": order.payment_capture_id,
        "credit_grant_id": order.credit_grant_id,
        "ledger_entry_id": order.ledger_entry_id,
        "invoice_id": order.invoice_id,
        "receipt_id": receipt_id.clone(),
        "reconciliation_id": reconciliation_id.clone(),
        "capture_event_id": capture_event_id.clone(),
        "reconciliation_event_id": reconciliation_event_id.clone(),
        "audit_id": order.audit_id
    });
    json!({
        "schema": LOCAL_PAYMENT_DEMO_SCHEMA,
        "outcome": outcome,
        "operation": operation,
        "mode": "local_runtime_demo",
        "local_only": true,
        "merchant_connected": false,
        "production_payment_evidence": false,
        "secret_safe": true,
        "raw_idempotency_key_echoed": false,
        "raw_metadata_echoed": false,
        "raw_provider_payload_echoed": false,
        "contract": local_payment_demo_contract(),
        "order": {
            "id": order.id,
            "tenant_id": order.tenant_id,
            "project_id": order.project_id,
            "wallet_id": order.wallet_id,
            "currency": order.currency,
            "amount": order.amount,
            "status": order.status,
            "source": LOCAL_PAYMENT_DEMO_SOURCE,
            "created_at": order.created_at,
            "updated_at": order.updated_at
        },
        "refs": refs,
        "accounting": {
            "money_scale": DEFAULT_MONEY_SCALE,
            "amount": order.amount,
            "currency": order.currency,
            "credit_source": "payment_order_invoice",
            "ledger_entry_type": "adjust",
            "ledger_status": if order.ledger_entry_id.is_some() { "confirmed" } else { "not_written" },
            "ledger_operation": LOCAL_PAYMENT_DEMO_LEDGER_OPERATION,
            "invoice_policy": "runtime_record_not_legal_tax_invoice",
            "receipt_policy": "runtime_record_not_legal_tax_receipt",
            "reconciliation_policy": "matched_runtime_readback_not_production_finance_reconciliation"
        },
        "payment_refs": {
            "order_id": order.id,
            "payment_intent_id": order.payment_intent_id,
            "payment_capture_id": order.payment_capture_id,
            "provider_reference": provider_reference,
            "provider_reference_redacted": provider_reference_redacted,
            "provider": "local_demo",
            "provider_event_refs": provider_event_refs
        },
        "ledger_refs": {
            "credit_grant_id": order.credit_grant_id,
            "ledger_entry_id": order.ledger_entry_id,
            "ledger_status": if order.ledger_entry_id.is_some() { "confirmed" } else { "not_written" },
            "ledger_entry_type": "adjust",
            "ledger_operation": LOCAL_PAYMENT_DEMO_LEDGER_OPERATION
        },
        "invoice": {
            "invoice_id": order.invoice_id,
            "status": invoice_status,
            "amount": order.amount,
            "currency": order.currency,
            "invoice_number": invoice_number,
            "issued_at": invoice_issued_at,
            "payment_capture_id": invoice_payment_capture_id,
            "audit_id": invoice_audit_id,
            "legal_invoice": false,
            "boundary": "runtime_invoice_record_not_legal_tax_invoice",
            "next_step": if order.invoice_id.is_some() { "display runtime invoice status and safe refs" } else { "mark order paid to create runtime invoice skeleton" }
        },
        "receipt": {
            "receipt_id": receipt_id,
            "status": receipt_status,
            "amount": order.amount,
            "currency": order.currency,
            "receipt_number": receipt_number,
            "issued_at": receipt_issued_at,
            "payment_capture_id": receipt_payment_capture_id,
            "audit_id": receipt_audit_id,
            "legal_receipt": false,
            "boundary": "runtime_receipt_record_not_legal_tax_receipt",
            "next_step": if order.status == "paid" { "display runtime receipt status and safe refs" } else { "mark order paid to create runtime receipt skeleton" }
        },
        "reconciliation": {
            "marker_id": reconciliation_id,
            "status": reconciliation_status,
            "matched": order.status == "paid",
            "amount": order.amount,
            "currency": order.currency,
            "payment_capture_id": order.payment_capture_id,
            "invoice_id": order.invoice_id,
            "ledger_entry_id": order.ledger_entry_id,
            "provider_event_refs": provider_event_refs,
            "matched_at": reconciliation_matched_at,
            "boundary": "local_marker_readback_not_production_finance_reconciliation",
            "next_step": if order.status == "paid" { "readback matched payment/invoice/ledger marker" } else { "mark order paid to create reconciliation marker" }
        },
        "invoice_receipt_reconciliation_readback": {
            "schema": "invoice_receipt_reconciliation_readback.v1",
            "source": "local_payment_demo_runtime_readback",
            "status": invoice_receipt_reconciliation_status,
            "invoice_status": invoice_status,
            "receipt_status": receipt_status,
            "payment_refs_presence": {
                "present": payment_refs_present,
                "payment_intent_id_present": order.payment_intent_id.is_some(),
                "payment_capture_id_present": order.payment_capture_id.is_some(),
                "provider_reference_redacted": provider_reference_redacted,
                "provider_event_refs_present": provider_event_refs.as_array().is_some_and(|refs| !refs.is_empty())
            },
            "ledger_refs_presence": {
                "present": ledger_refs_present,
                "credit_grant_id_present": order.credit_grant_id.is_some(),
                "ledger_entry_id_present": order.ledger_entry_id.is_some(),
                "ledger_status": if order.ledger_entry_id.is_some() { "confirmed" } else { "not_written" }
            },
            "reconciliation_status": reconciliation_status,
            "reconciliation_refs_presence": {
                "present": reconciliation_present,
                "marker_id_present": reconciliation_present,
                "invoice_id_present": invoice_present,
                "receipt_id_present": receipt_present,
                "payment_capture_id_present": order.payment_capture_id.is_some(),
                "ledger_entry_id_present": order.ledger_entry_id.is_some()
            },
            "safe_next_action": invoice_receipt_reconciliation_safe_next_action,
            "local_only": true,
            "merchant_connected": false,
            "production_payment_evidence": false,
            "legal_invoice": false,
            "legal_receipt": false,
            "raw_provider_payload_echoed": false,
            "provider_secret_echoed": false,
            "authorization_echoed": false,
            "raw_idempotency_key_echoed": false,
            "raw_invoice_metadata_echoed": false,
            "secret_safe": true
        },
        "notes": [
            "local runtime demo only",
            "no real merchant handoff or production payment evidence",
            "invoice and receipt are runtime skeleton records, not legal financial documents"
        ],
        "extra": extra_value
    })
}

fn normalize_local_payment_demo_amount(amount: &str) -> Result<String, AdminError> {
    let amount = admin_wallet_fixed_money_string(amount)?;
    if parse_billing_fixed_decimal(&amount)?.units() <= 0 {
        return Err(AdminError::bad_request("amount must be positive"));
    }
    Ok(amount)
}

fn normalize_local_payment_demo_currency(currency: &str) -> Result<String, AdminError> {
    let currency = non_empty(currency.to_string(), "currency")?;
    validate_price_version_currency(&currency)
        .map_err(|_| AdminError::bad_request("currency must be an uppercase currency code"))?;
    Ok(currency)
}

fn normalize_payment_provider_name(provider: &str) -> Result<String, AdminError> {
    let provider = non_empty(provider.to_string(), "provider")?;
    if provider.len() > 64
        || !provider
            .bytes()
            .all(|byte| byte.is_ascii_alphanumeric() || matches!(byte, b'_' | b'-' | b'.'))
    {
        return Err(AdminError::bad_request(
            "provider must be 1-64 ASCII letters, numbers, underscore, dash, or dot",
        ));
    }
    if looks_like_secret_value(&provider) {
        return Err(AdminError::bad_request(
            "provider must not contain credential material",
        ));
    }
    Ok(provider)
}

fn normalize_local_payment_demo_reason(reason: &str) -> Result<String, AdminError> {
    let reason = non_empty(reason.to_string(), "reason")?;
    if reason.len() > LEDGER_ADJUSTMENT_REASON_MAX_BYTES {
        return Err(AdminError::bad_request(format!(
            "reason must be at most {LEDGER_ADJUSTMENT_REASON_MAX_BYTES} bytes"
        )));
    }
    if looks_like_secret_value(&reason) {
        return Err(AdminError::bad_request(
            "reason must not contain credential material",
        ));
    }
    Ok(reason)
}

fn validate_local_payment_demo_scope(tenant_id: Uuid) -> Result<(), AdminError> {
    if tenant_id != DEFAULT_TENANT_ID {
        return Err(AdminError::bad_request(
            "tenant_id must match the current control-plane tenant",
        ));
    }
    Ok(())
}

fn local_payment_demo_hash(kind: &str, value: String) -> String {
    sha256_hex(&format!("local-payment-demo:{kind}:v1:{value}"))
}

fn normalize_voucher_issue_request(
    request: VoucherIssueRequest,
) -> Result<NormalizedVoucherIssueRequest, AdminError> {
    if request.tenant_id != DEFAULT_TENANT_ID {
        return Err(AdminError::bad_request(
            "tenant_id must match the current control-plane tenant",
        ));
    }
    let amount = admin_wallet_fixed_money_string(&request.amount)?;
    if parse_billing_fixed_decimal(&amount)?.units() <= 0 {
        return Err(AdminError::bad_request("amount must be positive"));
    }
    validate_price_version_currency(&request.currency)?;
    let raw_code = non_empty(request.raw_voucher_code, "raw_voucher_code")?;
    let idempotency_key = non_empty(request.idempotency_key, "idempotency_key")?;
    let max_redemptions = request.max_redemptions.unwrap_or(1);
    if max_redemptions < 1 {
        return Err(AdminError::bad_request(
            "max_redemptions must be at least 1",
        ));
    }
    let expires_at = optional_rfc3339_timestamp(request.expires_at, "expires_at")?;
    let code_hash = voucher_code_hash(&raw_code)?;
    let code_lookup_prefix = voucher_code_lookup_prefix(&raw_code)?;
    let code_redacted = voucher_code_redacted(&raw_code)?;
    let idempotency_fingerprint = sha256_hex(&format!("voucher-issue:v1:{idempotency_key}"));
    let request_fingerprint = sha256_hex(&format!(
        "tenant={};project={};wallet={};campaign={};currency={};amount={};code_hash={};max_redemptions={};expires_at={}",
        request.tenant_id,
        request
            .project_id
            .map(|project_id| project_id.to_string())
            .unwrap_or_default(),
        request.wallet_id,
        request
            .campaign_id
            .map(|campaign_id| campaign_id.to_string())
            .unwrap_or_default(),
        request.currency,
        amount,
        code_hash,
        max_redemptions,
        expires_at.as_deref().unwrap_or("")
    ));

    Ok(NormalizedVoucherIssueRequest {
        tenant_id: request.tenant_id,
        project_id: request.project_id,
        wallet_id: request.wallet_id,
        campaign_id: request.campaign_id,
        currency: request.currency,
        amount,
        code_hash,
        code_lookup_prefix,
        code_redacted,
        idempotency_fingerprint,
        request_fingerprint,
        max_redemptions,
        expires_at,
        batch_idempotency_key_hash: request.batch_idempotency_key_hash,
    })
}

fn normalize_voucher_batch_hash(value: String) -> Result<String, AdminError> {
    let hash = non_empty(value, "batch_hash")?.trim().to_ascii_lowercase();
    if hash.len() != 64 || !hash.bytes().all(|byte| byte.is_ascii_hexdigit()) {
        return Err(AdminError::bad_request(
            "batch_hash must be a sha256 hex idempotency hash",
        ));
    }
    Ok(hash)
}

fn normalize_voucher_redeem_request(
    request: VoucherRedeemRequest,
) -> Result<NormalizedVoucherRedeemRequest, AdminError> {
    if request.tenant_id != DEFAULT_TENANT_ID {
        return Err(AdminError::bad_request(
            "tenant_id must match the current control-plane tenant",
        ));
    }
    validate_price_version_currency(&request.currency)?;
    let raw_code = non_empty(request.voucher_code, "voucher_code")?;
    let idempotency_key = non_empty(request.idempotency_key, "idempotency_key")?;
    let code_hash = voucher_code_hash(&raw_code)?;
    let code_lookup_prefix = voucher_code_lookup_prefix(&raw_code)?;
    let code_redacted = voucher_code_redacted(&raw_code)?;
    let idempotency_fingerprint = sha256_hex(&format!("voucher-redeem:v1:{idempotency_key}"));
    let request_fingerprint = sha256_hex(&format!(
        "tenant={};project={};wallet={};currency={};code_hash={};redeemer={}",
        request.tenant_id,
        request
            .project_id
            .map(|project_id| project_id.to_string())
            .unwrap_or_default(),
        request.wallet_id,
        request.currency,
        code_hash,
        request
            .redeemer_user_id
            .map(|redeemer_user_id| redeemer_user_id.to_string())
            .unwrap_or_default()
    ));
    let actor_fingerprint_hash = sha256_hex(&format!(
        "voucher-redeem-actor:v1:{}:{}:{}",
        request.tenant_id, request.wallet_id, idempotency_fingerprint
    ));

    Ok(NormalizedVoucherRedeemRequest {
        tenant_id: request.tenant_id,
        project_id: request.project_id,
        wallet_id: request.wallet_id,
        currency: request.currency,
        code_hash,
        code_lookup_prefix,
        code_redacted,
        idempotency_fingerprint,
        request_fingerprint,
        redeemer_user_id: request.redeemer_user_id,
        actor_fingerprint_hash,
    })
}

async fn execute_voucher_issue_tx(
    tx: &mut Transaction<'_, Postgres>,
    session: &AdminSession,
    request: NormalizedVoucherIssueRequest,
    request_context: Value,
) -> Result<Value, AdminError> {
    lock_credit_grant_idempotency_tx(tx, &request.idempotency_fingerprint).await?;
    if let Some(existing) =
        get_voucher_issuance_by_idempotency_fingerprint_tx(tx, &request.idempotency_fingerprint)
            .await?
    {
        if existing
            .metadata
            .get("request_fingerprint")
            .and_then(Value::as_str)
            == Some(request.request_fingerprint.as_str())
        {
            return Ok(voucher_issue_response(&existing, "replayed"));
        }
        return Ok(voucher_issue_refusal_response(
            "idempotency_conflict",
            Some(request.wallet_id),
            Some(&request.currency),
        ));
    }

    let wallet_currency = lock_credit_grant_wallet_tx(tx, request.wallet_id).await?;
    if wallet_currency.as_deref() != Some(request.currency.as_str()) {
        return Ok(voucher_issue_refusal_response(
            "wallet_currency_mismatch",
            Some(request.wallet_id),
            Some(&request.currency),
        ));
    }

    let voucher = insert_voucher_issuance_tx(tx, &request).await?;
    let audit_resource = VoucherAuditResource {
        tenant_id: voucher.tenant_id,
        id: voucher.id,
        resource_type: "voucher_issuance",
        summary: json!({
            "operation": "voucher_issue",
            "voucher_id": voucher.id,
            "wallet_id": voucher.wallet_id,
            "currency": voucher.currency,
            "amount": voucher.amount,
            "code_redacted": voucher.code_redacted,
            "raw_voucher_code_echoed": false,
            "secret_safe": true,
        }),
    };
    let audit_id = insert_admin_audit_log_tx(
        tx,
        new_admin_audit_log(
            session,
            "voucher.issue",
            None,
            &audit_resource,
            json!({"operation": "voucher_issue", "secret_safe": true}),
            Some(request_context),
        ),
    )
    .await?;
    let voucher = update_voucher_issuance_audit_id_tx(tx, voucher.id, audit_id).await?;
    Ok(voucher_issue_response(&voucher, "issued"))
}

async fn execute_voucher_revoke_tx(
    tx: &mut Transaction<'_, Postgres>,
    session: &AdminSession,
    voucher_id: Uuid,
    request_context: Value,
) -> Result<Value, AdminError> {
    let before = lock_voucher_issuance_by_id_tx(tx, voucher_id)
        .await?
        .ok_or_else(|| AdminError::not_found("voucher_issuance"))?;
    if before.status != "issued" {
        return Err(AdminError::bad_request(format!(
            "voucher_issuance status `{}` cannot be revoked",
            before.status
        )));
    }

    let after = update_voucher_issuance_status_tx(tx, voucher_id, "revoked").await?;
    let before_resource = voucher_audit_resource_from_issuance(&before, "voucher_revoke");
    let after_resource = voucher_audit_resource_from_issuance(&after, "voucher_revoke");
    let audit_id = insert_admin_audit_log_tx(
        tx,
        new_admin_audit_log(
            session,
            "voucher.revoke",
            Some(&before_resource),
            &after_resource,
            json!({"operation": "voucher_revoke", "secret_safe": true}),
            Some(request_context),
        ),
    )
    .await?;
    let voucher = update_voucher_issuance_revoke_audit_id_tx(tx, voucher_id, audit_id).await?;
    Ok(voucher_revoke_response(&voucher, audit_id))
}

async fn execute_voucher_redeem_tx(
    tx: &mut Transaction<'_, Postgres>,
    session: &AdminSession,
    request: NormalizedVoucherRedeemRequest,
    request_context: Value,
) -> Result<Value, AdminError> {
    execute_voucher_redeem_with_actor_tx(
        tx,
        session.session_id(),
        session.tenant_id(),
        request,
        request_context,
    )
    .await
}

async fn execute_voucher_redeem_with_actor_tx(
    tx: &mut Transaction<'_, Postgres>,
    actor_session_id: Uuid,
    actor_tenant_id: Uuid,
    request: NormalizedVoucherRedeemRequest,
    request_context: Value,
) -> Result<Value, AdminError> {
    lock_credit_grant_idempotency_tx(tx, &request.idempotency_fingerprint).await?;
    if let Some(existing) =
        get_voucher_redemption_by_idempotency_fingerprint_tx(tx, &request.idempotency_fingerprint)
            .await?
    {
        if existing
            .metadata
            .get("request_fingerprint")
            .and_then(Value::as_str)
            == Some(request.request_fingerprint.as_str())
        {
            return Ok(voucher_redeem_response(&existing, "replayed"));
        }
        let _ =
            insert_voucher_redeem_attempt_tx(tx, &request, "refused", Some("idempotency_conflict"))
                .await?;
        return Ok(voucher_redeem_refusal_response(
            "idempotency_conflict",
            Some(request.wallet_id),
            Some(&request.currency),
        ));
    }

    let Some(voucher) = lock_voucher_issuance_by_code_hash_tx(tx, &request.code_hash).await? else {
        let _ =
            insert_voucher_redeem_attempt_tx(tx, &request, "refused", Some("voucher_not_found"))
                .await?;
        return Ok(voucher_redeem_refusal_response(
            "voucher_not_found",
            Some(request.wallet_id),
            Some(&request.currency),
        ));
    };

    let refusal_code = voucher_redeem_refusal_code(&request, &voucher);
    if let Some(refusal_code) = refusal_code {
        let _ =
            insert_voucher_redeem_attempt_tx(tx, &request, "refused", Some(refusal_code)).await?;
        return Ok(voucher_redeem_refusal_response(
            refusal_code,
            Some(request.wallet_id),
            Some(&request.currency),
        ));
    }

    let _attempt_id = insert_voucher_redeem_attempt_tx(tx, &request, "accepted", None).await?;
    let credit_grant_id = insert_voucher_credit_grant_tx(tx, &voucher).await?;
    let ledger_entry_id = insert_voucher_ledger_entry_tx(tx, &voucher, credit_grant_id).await?;
    let redemption =
        insert_voucher_redemption_tx(tx, &request, &voucher, credit_grant_id, ledger_entry_id)
            .await?;
    let audit_resource = VoucherAuditResource {
        tenant_id: redemption.tenant_id,
        id: redemption.id,
        resource_type: "voucher_redemption",
        summary: json!({
            "operation": "voucher_redeem",
            "voucher_id": redemption.voucher_id,
            "redemption_id": redemption.id,
            "wallet_id": redemption.wallet_id,
            "currency": redemption.currency,
            "amount": redemption.amount,
            "credit_grant_id": credit_grant_id,
            "ledger_entry_id": ledger_entry_id,
            "raw_voucher_code_echoed": false,
            "secret_safe": true,
        }),
    };
    let audit_id = insert_admin_audit_log_tx(
        tx,
        new_admin_audit_log_from_parts(
            actor_session_id,
            actor_tenant_id,
            "voucher.redeem",
            None,
            &audit_resource,
            json!({"operation": "voucher_redeem", "secret_safe": true}),
            Some(request_context),
        ),
    )
    .await?;
    let redemption = update_voucher_redemption_audit_id_tx(tx, redemption.id, audit_id).await?;
    update_voucher_issuance_after_redeem_tx(tx, voucher.id).await?;
    Ok(voucher_redeem_response(&redemption, "redeemed"))
}

fn normalize_create_admin_credit_grant_request(
    request: CreateAdminCreditGrantRequest,
) -> Result<NormalizedCreateAdminCreditGrantRequest, AdminError> {
    if request.tenant_id != DEFAULT_TENANT_ID {
        return Err(AdminError::bad_request(
            "tenant_id must match the current control-plane tenant",
        ));
    }
    let amount = admin_wallet_fixed_money_string(&request.amount)?;
    if parse_billing_fixed_decimal(&amount)?.units() <= 0 {
        return Err(AdminError::bad_request("amount must be positive"));
    }
    validate_price_version_currency(&request.currency)?;
    let source = non_empty(request.source, "source")?;
    let reason = non_empty(request.reason, "reason")?;
    let actor_type = non_empty(request.actor_type, "actor_type")?;
    let idempotency_key = non_empty(request.idempotency_key, "idempotency_key")?;
    let valid_from = optional_rfc3339_timestamp(request.valid_from, "valid_from")?;
    let valid_until = optional_rfc3339_timestamp(request.valid_until, "valid_until")?;
    let idempotency_fingerprint =
        sha256_hex(&format!("admin-credit-grant-create:v1:{}", idempotency_key));
    let request_fingerprint = sha256_hex(&format!(
        "tenant={};wallet={};amount={};currency={};source={};valid_from={};valid_until={};reason={};actor_id={};actor_type={}",
        request.tenant_id,
        request.wallet_id,
        amount,
        request.currency,
        source,
        valid_from.as_deref().unwrap_or(""),
        valid_until.as_deref().unwrap_or(""),
        reason,
        request.actor_id,
        actor_type
    ));

    Ok(NormalizedCreateAdminCreditGrantRequest {
        tenant_id: request.tenant_id,
        wallet_id: request.wallet_id,
        amount,
        currency: request.currency,
        source,
        valid_from,
        valid_until,
        reason,
        actor_id: request.actor_id,
        actor_type,
        idempotency_fingerprint,
        request_fingerprint,
    })
}

async fn execute_create_admin_credit_grant_tx(
    tx: &mut Transaction<'_, Postgres>,
    session: &AdminSession,
    request: NormalizedCreateAdminCreditGrantRequest,
    request_context: Value,
) -> Result<Value, AdminError> {
    lock_credit_grant_idempotency_tx(tx, &request.idempotency_fingerprint).await?;
    if let Some(existing) =
        get_credit_grant_by_idempotency_fingerprint_tx(tx, &request.idempotency_fingerprint).await?
    {
        let existing_request_fingerprint = existing
            .metadata
            .get("request_fingerprint")
            .and_then(Value::as_str);
        if existing_request_fingerprint == Some(request.request_fingerprint.as_str()) {
            let audit_id = credit_grant_metadata_uuid(&existing.metadata, "create_audit_id");
            return Ok(admin_credit_grant_runtime_response(
                existing, audit_id, "replayed", "replay",
            )?);
        }
        return Ok(admin_credit_grant_refusal_response(
            &request,
            "idempotency_conflict",
        )?);
    }

    let wallet_currency = lock_credit_grant_wallet_tx(tx, request.wallet_id).await?;
    if wallet_currency.as_deref() != Some(request.currency.as_str()) {
        return Ok(admin_credit_grant_refusal_response(
            &request,
            "wallet_currency_mismatch",
        )?);
    }

    let grant = insert_admin_credit_grant_tx(tx, &request).await?;
    let audit_resource = AdminCreditGrantAuditResource {
        tenant_id: grant.tenant_id,
        id: grant.id,
        summary: admin_credit_grant_audit_summary(&grant)?,
    };
    let audit_id = insert_admin_audit_log_tx(
        tx,
        new_admin_audit_log(
            session,
            "credit_grant.create",
            None,
            &audit_resource,
            admin_credit_grant_audit_metadata(&request),
            Some(request_context),
        ),
    )
    .await?;
    let grant = update_credit_grant_metadata_tx(
        tx,
        grant.id,
        json!({
            "create_audit_id": audit_id,
            "create_replay_marker": request.idempotency_fingerprint,
            "create_request_marker": request.request_fingerprint,
        }),
    )
    .await?;

    admin_credit_grant_runtime_response(grant, Some(audit_id), "active", "create")
}

fn normalize_credit_grant_lifecycle_request(
    credit_grant_id: Uuid,
    request: CreditGrantLifecycleRequest,
    operation: CreditGrantLifecycleOperation,
) -> Result<NormalizedCreditGrantLifecycleRequest, AdminError> {
    if request.tenant_id != DEFAULT_TENANT_ID {
        return Err(AdminError::bad_request(
            "tenant_id must match the current control-plane tenant",
        ));
    }
    let currency = request
        .currency
        .map(|currency| {
            validate_price_version_currency(&currency)?;
            Ok::<_, AdminError>(currency)
        })
        .transpose()?;
    let reason = non_empty(request.reason, "reason")?;
    let actor_type = non_empty(request.actor_type, "actor_type")?;
    let idempotency_key = non_empty(request.idempotency_key, "idempotency_key")?;
    let idempotency_fingerprint = sha256_hex(&format!(
        "{}:{}",
        operation.idempotency_scope(),
        idempotency_key
    ));
    let request_fingerprint = sha256_hex(&format!(
        "tenant={};grant={};wallet={};currency={};reason={};actor_id={};actor_type={};operation={}",
        request.tenant_id,
        credit_grant_id,
        request
            .wallet_id
            .map(|wallet_id| wallet_id.to_string())
            .unwrap_or_default(),
        currency.as_deref().unwrap_or(""),
        reason,
        request.actor_id,
        actor_type,
        operation.outcome()
    ));

    Ok(NormalizedCreditGrantLifecycleRequest {
        tenant_id: request.tenant_id,
        credit_grant_id,
        wallet_id: request.wallet_id,
        currency,
        reason,
        actor_id: request.actor_id,
        actor_type,
        operation,
        idempotency_fingerprint,
        request_fingerprint,
    })
}

async fn execute_credit_grant_lifecycle_tx(
    tx: &mut Transaction<'_, Postgres>,
    session: &AdminSession,
    request: NormalizedCreditGrantLifecycleRequest,
    request_context: Value,
) -> Result<Value, AdminError> {
    lock_credit_grant_idempotency_tx(tx, &request.idempotency_fingerprint).await?;
    let grant = lock_credit_grant_by_id_tx(tx, request.credit_grant_id)
        .await?
        .ok_or_else(|| AdminError::not_found("credit grant"))?;

    if let Some(existing) = credit_grant_lifecycle_replay_marker(&grant, request.operation) {
        if existing.idempotency_fingerprint == request.idempotency_fingerprint {
            if existing.request_fingerprint == request.request_fingerprint {
                return admin_credit_grant_runtime_response(
                    grant,
                    Some(existing.audit_id),
                    "replayed",
                    "replay",
                );
            }
            return admin_credit_grant_lifecycle_refusal_response(
                &request,
                Some(&grant),
                "idempotency_conflict",
            );
        }
    }

    if request
        .wallet_id
        .is_some_and(|wallet_id| wallet_id != grant.wallet_id)
        || request
            .currency
            .as_ref()
            .is_some_and(|currency| currency != &grant.currency)
    {
        return admin_credit_grant_lifecycle_refusal_response(
            &request,
            Some(&grant),
            "wallet_currency_mismatch",
        );
    }

    if grant.status == request.operation.target_status() {
        return admin_credit_grant_lifecycle_refusal_response(
            &request,
            Some(&grant),
            match request.operation {
                CreditGrantLifecycleOperation::Expire => "already_expired",
                CreditGrantLifecycleOperation::Revoke => "already_voided",
            },
        );
    }
    if grant.status != "active" {
        return admin_credit_grant_lifecycle_refusal_response(
            &request,
            Some(&grant),
            "credit_grant_status_not_active",
        );
    }

    let updated = update_credit_grant_status_tx(
        tx,
        request.credit_grant_id,
        request.operation.target_status(),
    )
    .await?;
    let before_resource = AdminCreditGrantAuditResource {
        tenant_id: grant.tenant_id,
        id: grant.id,
        summary: admin_credit_grant_audit_summary(&grant)?,
    };
    let after_resource = AdminCreditGrantAuditResource {
        tenant_id: updated.tenant_id,
        id: updated.id,
        summary: admin_credit_grant_audit_summary(&updated)?,
    };
    let audit_id = insert_admin_audit_log_tx(
        tx,
        new_admin_audit_log(
            session,
            request.operation.action(),
            Some(&before_resource),
            &after_resource,
            admin_credit_grant_lifecycle_audit_metadata(&request),
            Some(request_context),
        ),
    )
    .await?;
    let updated = update_credit_grant_metadata_tx(
        tx,
        updated.id,
        json!({
            request.operation.lifecycle_audit_id_key(): audit_id,
            request.operation.lifecycle_replay_marker_key(): request.idempotency_fingerprint,
            request.operation.lifecycle_request_marker_key(): request.request_fingerprint,
        }),
    )
    .await?;

    admin_credit_grant_runtime_response(
        updated,
        Some(audit_id),
        request.operation.target_status(),
        request.operation.outcome(),
    )
}

async fn lock_credit_grant_idempotency_tx(
    tx: &mut Transaction<'_, Postgres>,
    fingerprint: &str,
) -> Result<(), AdminError> {
    let lock_key = i64::from_be_bytes(
        Sha256::digest(fingerprint.as_bytes())[0..8]
            .try_into()
            .expect("sha256 digest has at least 8 bytes"),
    );
    sqlx::query("select pg_advisory_xact_lock($1)")
        .bind(lock_key)
        .execute(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    Ok(())
}

async fn lock_credit_grant_wallet_tx(
    tx: &mut Transaction<'_, Postgres>,
    wallet_id: Uuid,
) -> Result<Option<String>, AdminError> {
    let row = sqlx::query(
        r#"
        select currency
        from wallets
        where tenant_id = $1 and id = $2 and status = 'active'
        for update
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.map(|row| row.try_get("currency"))
        .transpose()
        .map_err(|error| AdminError::from(DbError::Query(error)))
}

