fn voucher_redeem_refusal_code(
    request: &NormalizedVoucherRedeemRequest,
    voucher: &VoucherIssuanceRow,
) -> Option<&'static str> {
    if voucher.status == "expired" || voucher.expired_by_time {
        return Some("voucher_expired");
    }
    if voucher.status == "revoked" {
        return Some("voucher_revoked");
    }
    if voucher.status != "issued" {
        return Some("voucher_not_redeemable");
    }
    if voucher.currency != request.currency {
        return Some("voucher_currency_mismatch");
    }
    if voucher.wallet_id != Some(request.wallet_id) || voucher.project_id != request.project_id {
        return Some("voucher_scope_ownership_mismatch");
    }
    if voucher.redemption_count >= voucher.max_redemptions {
        return Some("voucher_redemption_limit_reached");
    }
    None
}

fn voucher_issue_response(voucher: &VoucherIssuanceRow, status: &str) -> Value {
    json!({
        "schema": "recharge_voucher_runtime.v1",
        "runtime_implemented": true,
        "contract_only": false,
        "route_invoked": true,
        "operation": "voucher_issue",
        "status": status,
        "voucher_id": voucher.id,
        "tenant_id": voucher.tenant_id,
        "project_id": voucher.project_id,
        "wallet_id": voucher.wallet_id,
        "campaign_id": voucher.campaign_id,
        "currency": voucher.currency,
        "amount": voucher.amount,
        "code_hash_present": true,
        "code_lookup_prefix_present": true,
        "code_redacted": voucher.code_redacted,
        "raw_voucher_code_echoed": false,
        "idempotency": {
            "result": if status == "replayed" { "replayed" } else { "applied" },
            "key_hash_present": true,
            "request_hash_present": true,
            "raw_key_echoed": false
        },
        "max_redemptions": voucher.max_redemptions,
        "redemption_count": voucher.redemption_count,
        "expires_at": voucher.expires_at,
        "audit_id": voucher.audit_id,
        "readback": {
            "voucher_issuance_row": true,
            "code_hash": true,
            "code_lookup_prefix": true,
            "code_redacted": true,
            "audit_log": voucher.audit_id.is_some(),
            "credit_grant_or_ledger_effect": false,
            "direct_wallet_snapshot_mutation": false,
            "refusal_no_credit_or_ledger_write": false
        },
        "money_decimal_strings": true,
        "secret_safe": true,
        "paid_gate_changed": false
    })
}

fn voucher_issue_batch_response(batch_idempotency_key_hash: &str, items: Vec<Value>) -> Value {
    let total = items.len();
    let issued = items
        .iter()
        .filter(|item| item["status"] == json!("issued"))
        .count();
    let replayed = items
        .iter()
        .filter(|item| item["status"] == json!("replayed"))
        .count();
    let refused = items
        .iter()
        .filter(|item| item["status"] == json!("refused"))
        .count();

    json!({
        "schema": "recharge_voucher_batch_runtime.v1",
        "runtime_implemented": true,
        "contract_only": false,
        "route_invoked": true,
        "operation": "voucher_issue_batch",
        "status": if refused == 0 { "completed" } else { "completed_with_refusals" },
        "batch_idempotency_key_hash": batch_idempotency_key_hash,
        "batch_idempotency_key_hash_present": !batch_idempotency_key_hash.is_empty(),
        "total": total,
        "issued": issued,
        "replayed": replayed,
        "refused": refused,
        "raw_voucher_code_echoed": false,
        "raw_idempotency_key_echoed": false,
        "secret_safe": true,
        "database_writes": issued + replayed > 0,
        "items": items
    })
}

fn voucher_issue_batch_item(index: usize, outcome: Value) -> Value {
    json!({
        "index": index,
        "status": outcome
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("unknown"),
        "voucher_id": outcome.get("voucher_id").cloned().unwrap_or(Value::Null),
        "wallet_id": outcome.get("wallet_id").cloned().unwrap_or(Value::Null),
        "currency": outcome.get("currency").cloned().unwrap_or(Value::Null),
        "amount": outcome.get("amount").cloned().unwrap_or(Value::Null),
        "code_redacted": outcome.get("code_redacted").cloned().unwrap_or(Value::Null),
        "raw_voucher_code_echoed": false,
        "raw_idempotency_key_echoed": false,
        "secret_safe": true
    })
}

