async fn update_credit_grant_status_tx(
    tx: &mut Transaction<'_, Postgres>,
    credit_grant_id: Uuid,
    status: &str,
) -> Result<AdminCreditGrantRow, AdminError> {
    let row = sqlx::query(
        r#"
        update credit_grants
        set status = $3,
            updated_at = now()
        where tenant_id = $1 and id = $2
        returning id, tenant_id, wallet_id, amount::text as amount,
          remaining_amount::text as remaining_amount, currency, source,
          valid_from::text as valid_from, valid_until::text as valid_until,
          status, created_at::text as created_at, updated_at::text as updated_at,
          metadata
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(credit_grant_id)
    .bind(status)
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    admin_credit_grant_row_from_row(row)
}

