async fn insert_admin_credit_grant_tx(
    tx: &mut Transaction<'_, Postgres>,
    request: &NormalizedCreateAdminCreditGrantRequest,
) -> Result<AdminCreditGrantRow, AdminError> {
    let metadata = json!({
        "operation": "admin_credit_grant_create",
        "source": redact_secrets(&request.source),
        "reason": redact_secrets(&request.reason),
        "reason_provided": true,
        "actor_id": request.actor_id,
        "actor_type": redact_secrets(&request.actor_type),
        "idempotency_fingerprint": request.idempotency_fingerprint,
        "request_fingerprint": request.request_fingerprint,
        "raw_idempotency_material_echoed": false,
        "direct_wallet_snapshot_mutation": false,
        "secret_safe": true,
    });
    let row = sqlx::query(
        r#"
        insert into credit_grants (
          tenant_id, wallet_id, amount, remaining_amount, currency, source,
          valid_from, valid_until, status, metadata
        )
        values (
          $1, $2, $3::numeric, $3::numeric, $4, $5,
          coalesce($6::timestamptz, now()), $7::timestamptz, 'active', $8
        )
        returning id, tenant_id, wallet_id, amount::text as amount,
          remaining_amount::text as remaining_amount, currency, source,
          valid_from::text as valid_from, valid_until::text as valid_until,
          status, created_at::text as created_at, updated_at::text as updated_at,
          metadata
        "#,
    )
    .bind(request.tenant_id)
    .bind(request.wallet_id)
    .bind(&request.amount)
    .bind(&request.currency)
    .bind(&request.source)
    .bind(request.valid_from.as_deref())
    .bind(request.valid_until.as_deref())
    .bind(metadata)
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    admin_credit_grant_row_from_row(row)
}

fn admin_credit_grant_select_sql(predicate: &'static str) -> String {
    format!(
        r#"
        select id, tenant_id, wallet_id, amount::text as amount,
               remaining_amount::text as remaining_amount, currency, source,
               valid_from::text as valid_from, valid_until::text as valid_until,
               status, created_at::text as created_at, updated_at::text as updated_at,
               metadata
        from credit_grants
        where tenant_id = $1 and {predicate}
        for update
        "#
    )
}

