async fn admin_wallet_ledger_balance_window(
    state: &ControlPlaneState,
    wallet_id: Uuid,
    currency: &str,
    window_days: i64,
) -> Result<Value, AdminError> {
    let window_days_i32 = i32::try_from(window_days)
        .map_err(|_| AdminError::bad_request("ledger_window_days is out of range"))?;
    let row = sqlx::query(
        r#"
        select
          (now() - make_interval(days => $3::int))::text as window_start,
          now()::text as window_end,
          coalesce(sum(case when status = 'confirmed' and amount < 0 then abs(amount) else 0 end), 0)::text as confirmed_debit_total,
          coalesce(sum(case when status = 'confirmed' and amount > 0 then amount else 0 end), 0)::text as confirmed_credit_total,
          coalesce(sum(case when status = 'confirmed' then amount else 0 end), 0)::text as confirmed_net_amount,
          coalesce(sum(case when status = 'pending' then amount else 0 end), 0)::text as pending_amount,
          coalesce(sum(case when status = 'reversed' then amount else 0 end), 0)::text as reversed_amount,
          count(*)::bigint as ledger_entry_count,
          (
            array_agg(id order by created_at desc, id desc)
            filter (where status = 'confirmed')
          )[1] as last_confirmed_ledger_entry_id,
          max(created_at)::text as max_source_updated_at
        from ledger_entries
        where tenant_id = $1
          and wallet_id = $2
          and created_at >= now() - make_interval(days => $3::int)
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .bind(window_days_i32)
    .fetch_one(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(json!({
        "window_start": row.try_get::<String, _>("window_start").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "window_end": row.try_get::<String, _>("window_end").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "currency": currency,
        "confirmed_debit_total": admin_wallet_money_from_row(&row, "confirmed_debit_total")?,
        "confirmed_credit_total": admin_wallet_money_from_row(&row, "confirmed_credit_total")?,
        "confirmed_net_amount": admin_wallet_money_from_row(&row, "confirmed_net_amount")?,
        "pending_amount": admin_wallet_money_from_row(&row, "pending_amount")?,
        "reversed_amount": admin_wallet_money_from_row(&row, "reversed_amount")?,
        "ledger_entry_count": row.try_get::<i64, _>("ledger_entry_count").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "last_confirmed_ledger_entry_id": row.try_get::<Option<Uuid>, _>("last_confirmed_ledger_entry_id").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "max_source_updated_at": row.try_get::<Option<String>, _>("max_source_updated_at").map_err(|error| AdminError::from(DbError::Query(error)))?,
    }))
}

async fn admin_wallet_pending_reserves(
    state: &ControlPlaneState,
    wallet_id: Uuid,
) -> Result<Value, AdminError> {
    let row = sqlx::query(
        r#"
        select
          count(*)::bigint as reserve_count,
          coalesce(sum(amount), 0)::text as reserve_amount_total,
          min(created_at)::text as oldest_pending_reserve_at,
          max(created_at)::text as newest_pending_reserve_at
        from ledger_entries
        where tenant_id = $1
          and wallet_id = $2
          and entry_type = 'reserve'
          and status = 'pending'
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .fetch_one(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(json!({
        "reserve_count": row.try_get::<i64, _>("reserve_count").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "reserve_amount_total": admin_wallet_money_from_row(&row, "reserve_amount_total")?,
        "oldest_pending_reserve_at": row.try_get::<Option<String>, _>("oldest_pending_reserve_at").map_err(|error| AdminError::from(DbError::Query(error)))?,
        "newest_pending_reserve_at": row.try_get::<Option<String>, _>("newest_pending_reserve_at").map_err(|error| AdminError::from(DbError::Query(error)))?,
    }))
}

#[derive(Debug, Clone)]
struct AdminWalletPublicLedgerLinks {
    ledger_entry_ids: Vec<Uuid>,
    request_ids: Vec<Uuid>,
    trace_ids: Vec<String>,
    computed_at: String,
}

async fn admin_wallet_public_ledger_links(
    state: &ControlPlaneState,
    wallet_id: Uuid,
) -> Result<AdminWalletPublicLedgerLinks, AdminError> {
    let rows = sqlx::query(
        r#"
        select id, request_id, trace_id, now()::text as computed_at
        from ledger_entries
        where tenant_id = $1 and wallet_id = $2
        order by created_at desc, id desc
        limit $3
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(wallet_id)
    .bind(ADMIN_WALLET_LINK_LIMIT)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let computed_at = rows
        .first()
        .map(|row| row.try_get::<String, _>("computed_at"))
        .transpose()
        .map_err(|error| AdminError::from(DbError::Query(error)))?
        .unwrap_or_else(|| "unavailable".to_string());
    let mut ledger_entry_ids = Vec::new();
    let mut request_ids = Vec::new();
    let mut trace_ids = Vec::new();
    for row in rows {
        ledger_entry_ids.push(
            row.try_get("id")
                .map_err(|error| AdminError::from(DbError::Query(error)))?,
        );
        if let Some(request_id) = row
            .try_get("request_id")
            .map_err(|error| AdminError::from(DbError::Query(error)))?
        {
            request_ids.push(request_id);
        }
        if let Some(trace_id) = row
            .try_get::<Option<String>, _>("trace_id")
            .map_err(|error| AdminError::from(DbError::Query(error)))?
        {
            trace_ids.push(redact_secrets(&trace_id));
        }
    }
    request_ids.sort_unstable();
    request_ids.dedup();
    trace_ids.sort();
    trace_ids.dedup();

    Ok(AdminWalletPublicLedgerLinks {
        ledger_entry_ids,
        request_ids,
        trace_ids,
        computed_at,
    })
}

async fn admin_wallet_audit_log_ids(
    state: &ControlPlaneState,
    ledger_entry_ids: &[Uuid],
    request_ids: &[Uuid],
) -> Result<Vec<Uuid>, AdminError> {
    let rows = sqlx::query(
        r#"
        select id
        from audit_logs
        where tenant_id = $1
          and (
            (cardinality($2::uuid[]) > 0 and resource_type = 'ledger_entry' and resource_id = any($2::uuid[]))
            or (cardinality($3::uuid[]) > 0 and request_id = any($3::uuid[]))
          )
        order by created_at desc, id desc
        limit $4
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(ledger_entry_ids)
    .bind(request_ids)
    .bind(ADMIN_WALLET_LINK_LIMIT)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    rows.into_iter()
        .map(|row| {
            row.try_get("id")
                .map_err(|error| AdminError::from(DbError::Query(error)))
        })
        .collect()
}

async fn admin_wallet_budget_remaining_marker(
    state: &ControlPlaneState,
    project_id: Option<Uuid>,
    currency: &str,
) -> Result<Value, AdminError> {
    let row = sqlx::query(
        r#"
        select
          count(*)::bigint as budget_count,
          min(limit_amount)::text as remaining_amount
        from budgets
        where tenant_id = $1
          and currency = $3
          and status = 'active'
          and deleted_at is null
          and (
            scope = 'tenant'
            or (scope = 'project' and project_id is not distinct from $2)
          )
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(project_id)
    .bind(currency)
    .fetch_one(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let budget_count = row
        .try_get::<i64, _>("budget_count")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let remaining_amount = match row
        .try_get::<Option<String>, _>("remaining_amount")
        .map_err(|error| AdminError::from(DbError::Query(error)))?
    {
        Some(value) => Some(admin_wallet_fixed_money_string(&value)?),
        None => None,
    };

    Ok(json!({
        "status": if budget_count > 0 { "computed" } else { "not_configured" },
        "budget_source": if budget_count > 0 { "budget_policy" } else { "none" },
        "remaining_amount": remaining_amount,
        "deny_when_missing": false,
    }))
}

