async fn create_local_payment_demo_order(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
    Json(request): Json<LocalPaymentDemoCreateOrderRequest>,
) -> Result<Response, AdminError> {
    session
        .require_permission(Permission::BillingAdjust)
        .map_err(|_| AdminError::forbidden("billing_adjust permission is required"))?;
    let amount = normalize_local_payment_demo_amount(&request.amount)?;
    let currency = normalize_local_payment_demo_currency(&request.currency)?;
    let reason = normalize_local_payment_demo_reason(&request.reason)?;
    let idempotency_fingerprint = local_payment_demo_hash(
        "order",
        non_empty(request.idempotency_key, "idempotency_key")?,
    );
    validate_local_payment_demo_scope(request.tenant_id)?;

    let mut tx = state
        .db()
        .begin()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let body = match create_local_payment_demo_order_tx(
        &mut tx,
        &session,
        request.project_id,
        request.wallet_id,
        &currency,
        &amount,
        &reason,
        &idempotency_fingerprint,
    )
    .await
    {
        Ok(body) => body,
        Err(error) => {
            rollback_ledger_adjustment_execute_tx(tx).await;
            return Err(error);
        }
    };
    tx.commit()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let status = if body.get("outcome").and_then(Value::as_str) == Some("created") {
        StatusCode::CREATED
    } else {
        StatusCode::OK
    };
    Ok((status, Json(json!({ "data": body }))).into_response())
}

