async fn simulate_payment_provider_event(
    Extension(session): Extension<AdminSession>,
    Json(request): Json<PaymentProviderSimulatorEventRequest>,
) -> Result<Response, AdminError> {
    session
        .require_permission(Permission::BillingAdjust)
        .map_err(|_| AdminError::forbidden("billing_adjust permission is required"))?;
    validate_local_payment_demo_scope(request.tenant_id)?;

    let provider = normalize_payment_provider_name(&request.provider)?;
    let external_event_id = non_empty(request.external_event_id.clone(), "external_event_id")?;
    if looks_like_secret_value(&external_event_id) {
        return Err(AdminError::bad_request(
            "external_event_id must not contain credential material",
        ));
    }
    let amount = normalize_local_payment_demo_amount(&request.amount)?;
    let currency = normalize_local_payment_demo_currency(&request.currency)?;
    let reason = normalize_local_payment_demo_reason(&request.reason)?;
    let idempotency_key_hash = request
        .idempotency_key
        .as_ref()
        .cloned()
        .map(|key| non_empty(key, "idempotency_key"))
        .transpose()?
        .map(|key| {
            if looks_like_secret_value(&key) {
                Err(AdminError::bad_request(
                    "idempotency_key must not contain credential material",
                ))
            } else {
                Ok(sha256_hex(&format!(
                    "payment-provider-simulator:idempotency:v1:{key}"
                )))
            }
        })
        .transpose()?;
    let adapter_config = payment_provider_adapter_config_status_value()?;

    let mut readback = serde_json::to_value(plan_payment_provider_runtime_readback(
        PaymentProviderHandoffRequest {
            provider,
            event_type: request.event_type,
            external_event_id_hash: sha256_hex(&format!(
                "payment-provider-simulator:event:v1:{external_event_id}"
            )),
            amount,
            currency,
            idempotency_key_hash,
            refs: PaymentProviderRefs {
                order_id: request.order_id.map(|id| id.to_string()),
                payment_intent_id: request.payment_intent_id.map(|id| id.to_string()),
                payment_capture_id: request.payment_capture_id.map(|id| id.to_string()),
                refund_id: request.refund_id.map(|id| id.to_string()),
                credit_grant_id: request.credit_grant_id.map(|id| id.to_string()),
                ledger_entry_id: request.ledger_entry_id.map(|id| id.to_string()),
                reversal_ledger_entry_id: request.reversal_ledger_entry_id.map(|id| id.to_string()),
                invoice_id: request.invoice_id.map(|id| id.to_string()),
                audit_id: None,
            },
        },
    ))
    .map_err(|error| {
        AdminError::configuration_error(format!("serialize payment provider readback: {error}"))
    })?;

    if let Some(object) = readback.as_object_mut() {
        object.insert(
            "provider_callback_route".to_string(),
            json!("manual_simulator"),
        );
        object.insert("runtime_write_performed".to_string(), json!(false));
        object.insert("real_provider_credentials_loaded".to_string(), json!(false));
        object.insert("raw_provider_payload_echoed".to_string(), json!(false));
        object.insert("reason_provided".to_string(), json!(!reason.is_empty()));
        object.insert("audit_id".to_string(), Value::Null);
        object.insert("adapter_config".to_string(), adapter_config);
    }

    Ok(Json(json!({ "data": readback })).into_response())
}

async fn receive_payment_provider_webhook(
    State(state): State<Arc<ControlPlaneState>>,
    Path(provider): Path<String>,
    headers: HeaderMap,
    body: Bytes,
) -> Result<Response, AdminError> {
    let provider = normalize_payment_provider_name(&provider)?;
    let config_input = payment_provider_adapter_config_input()?;
    let adapter_config = serde_json::to_value(plan_payment_provider_adapter_config_status(
        config_input.clone(),
    ))
    .map_err(|error| {
        AdminError::configuration_error(format!(
            "serialize payment provider config status: {error}"
        ))
    })?;
    let adapter_readback = payment_provider_adapter_readback_value(&provider, &headers, &body)?;
    let signature_verification =
        payment_provider_webhook_signature_status_from_adapter(&adapter_readback, &config_input);

    if signature_verification != "verified_stripe_like" {
        let response_status = match signature_verification.as_str() {
            "signature_missing" | "config_needed" => StatusCode::BAD_REQUEST,
            "signature_replay_window_refused" => StatusCode::BAD_REQUEST,
            _ => StatusCode::UNAUTHORIZED,
        };
        return Ok((
            response_status,
            Json(json!({
                "data": payment_provider_webhook_refusal_response(
                    &provider,
                    &signature_verification,
                    adapter_config,
                    Some(adapter_readback),
                    None,
                )
            })),
        )
            .into_response());
    }

    if !payment_provider_webhook_provider_supported(&provider) {
        let reason = adapter_readback
            .get("unsupported_reason")
            .and_then(Value::as_str)
            .unwrap_or("provider_not_supported_by_stripe_like_sandbox_adapter")
            .to_string();
        return Ok((
            StatusCode::BAD_REQUEST,
            Json(json!({
                "data": payment_provider_webhook_unsupported_adapter_response(
                    &provider,
                    &reason,
                    &signature_verification,
                    adapter_config,
                    adapter_readback,
                )
            })),
        )
            .into_response());
    }

    if adapter_readback
        .get("normalized_event")
        .is_none_or(|value| value.is_null())
    {
        let reason = adapter_readback
            .get("unsupported_reason")
            .and_then(Value::as_str)
            .unwrap_or("unsupported_payment_provider_event")
            .to_string();
        return Ok((
            StatusCode::BAD_REQUEST,
            Json(json!({
                "data": payment_provider_webhook_unsupported_adapter_response(
                    &provider,
                    &reason,
                    &signature_verification,
                    adapter_config,
                    adapter_readback,
                )
            })),
        )
            .into_response());
    }

    let request = payment_provider_webhook_request_from_adapter_or_generic(
        &provider,
        &body,
        &adapter_readback,
    )?;
    validate_local_payment_demo_scope(request.tenant_id)?;
    let credential_source = payment_provider_merchant_credential_source_readback(
        state.db(),
        request.tenant_id,
        &provider,
    )
    .await?;
    let source_config_input =
        payment_provider_adapter_config_input_for_credential_source(&provider, &credential_source)?;
    let mut source_adapter_config =
        payment_provider_adapter_config_status_value_for_input(source_config_input.clone())?;
    let stripe_api_source_of_truth = payment_provider_stripe_api_source_of_truth_value(
        &provider,
        &credential_source,
        Some(&adapter_readback),
    )?;
    if let Some(object) = source_adapter_config.as_object_mut() {
        object.insert(
            "credential_generation".to_string(),
            payment_provider_credential_generation_value(&credential_source),
        );
        object.insert("credential_source".to_string(), credential_source.clone());
        object.insert(
            "stripe_api_source_of_truth".to_string(),
            stripe_api_source_of_truth.clone(),
        );
    }
    if let Some(refusal_reason) = payment_provider_credential_refusal_reason(&source_config_input) {
        return Ok((
            StatusCode::BAD_REQUEST,
            Json(json!({
                "data": payment_provider_webhook_refusal_response(
                    &provider,
                    refusal_reason,
                    source_adapter_config,
                    Some(adapter_readback),
                    Some(stripe_api_source_of_truth),
                )
            })),
        )
            .into_response());
    }

    let external_event_id = non_empty(request.external_event_id.clone(), "external_event_id")?;
    if looks_like_secret_value(&external_event_id) {
        return Err(AdminError::bad_request(
            "external_event_id must not contain credential material",
        ));
    }
    let amount = normalize_local_payment_demo_amount(&request.amount)?;
    let currency = normalize_local_payment_demo_currency(&request.currency)?;
    let idempotency_key_hash = request
        .idempotency_key
        .clone()
        .map(|key| non_empty(key, "idempotency_key"))
        .transpose()?
        .map(|key| {
            if looks_like_secret_value(&key) {
                Err(AdminError::bad_request(
                    "idempotency_key must not contain credential material",
                ))
            } else {
                Ok(sha256_hex(&format!(
                    "payment-provider-webhook:idempotency:v1:{key}"
                )))
            }
        })
        .transpose()?;
    let external_event_id_hash = sha256_hex(&format!(
        "payment-provider-webhook:event:v1:{provider}:{external_event_id}"
    ));
    let payload_hash = sha256_hex_bytes(&body);

    let readback = insert_verified_payment_provider_event_readback(
        state.db(),
        &provider,
        request.clone(),
        external_event_id_hash,
        payload_hash,
        amount,
        currency,
        idempotency_key_hash,
        source_adapter_config,
        adapter_readback,
        stripe_api_source_of_truth,
        signature_verification,
    )
    .await?;

    Ok((StatusCode::ACCEPTED, Json(json!({ "data": readback }))).into_response())
}

async fn get_payment_provider_config_status(
    State(state): State<Arc<ControlPlaneState>>,
    Extension(session): Extension<AdminSession>,
) -> Result<Response, AdminError> {
    session
        .require_permission(Permission::BillingAdjust)
        .map_err(|_| AdminError::forbidden("billing_adjust permission is required"))?;

    let provider = payment_provider_config_default_provider()?;
    let source = payment_provider_merchant_credential_source_readback(
        state.db(),
        session.tenant_id(),
        &provider,
    )
    .await?;
    let input = payment_provider_adapter_config_input_for_credential_source(&provider, &source)?;
    let mut status = payment_provider_adapter_config_status_value_for_input(input)?;
    if let Some(object) = status.as_object_mut() {
        object.insert(
            "credential_generation".to_string(),
            payment_provider_credential_generation_value(&source),
        );
        object.insert("credential_source".to_string(), source);
        object.insert(
            "stripe_api_source_of_truth".to_string(),
            payment_provider_stripe_api_source_of_truth_value(
                &provider,
                object.get("credential_source").unwrap_or(&Value::Null),
                None,
            )?,
        );
    }

    Ok(Json(json!({ "data": status })).into_response())
}

