fn payment_provider_object_local_ref_readback(
    request: &PaymentProviderLocalExecutorRequest,
    summary_local_refs: &Value,
    expected_local_refs: &'static [&'static str],
) -> Value {
    let mut provider_hashes = BTreeMap::new();
    if let Some(refs) = summary_local_refs.get("refs").and_then(Value::as_array) {
        for item in refs {
            let Some(name) = item.get("name").and_then(Value::as_str) else {
                continue;
            };
            let value_hash = item
                .get("value_hash")
                .and_then(Value::as_str)
                .map(ToOwned::to_owned);
            let present = item
                .get("present")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            provider_hashes.insert(name.to_string(), (present, value_hash));
        }
    }

    let request_refs = [
        ("order_id", request.order_id),
        ("project_id", request.project_id),
        ("wallet_id", request.wallet_id),
        ("payment_intent_id", request.payment_intent_id),
        ("payment_capture_id", request.payment_capture_id),
        ("refund_id", request.refund_id),
        ("credit_grant_id", request.credit_grant_id),
        ("ledger_entry_id", request.ledger_entry_id),
        ("reversal_ledger_entry_id", request.reversal_ledger_entry_id),
        ("invoice_id", request.invoice_id),
    ];
    let refs: Vec<Value> = request_refs
        .iter()
        .map(|(name, request_value)| {
            let request_hash = request_value.map(|value| sha256_hex(&value.to_string()));
            let (provider_present, provider_hash) =
                provider_hashes.get(*name).cloned().unwrap_or((false, None));
            let expected_for_action = expected_local_refs.iter().any(|expected| expected == name);
            let matches_request = match (request_hash.as_deref(), provider_hash.as_deref()) {
                (Some(request_hash), Some(provider_hash)) => Some(request_hash == provider_hash),
                (Some(_), None) => Some(false),
                (None, Some(_)) => Some(false),
                (None, None) => None,
            };
            json!({
                "name": name,
                "expected_for_action": expected_for_action,
                "request_ref_present": request_value.is_some(),
                "provider_metadata_ref_present": provider_present,
                "matches_request": matches_request,
                "request_ref_hash_present": request_hash.is_some(),
                "provider_ref_hash_present": provider_hash.is_some(),
                "raw_ref_echoed": false
            })
        })
        .collect();
    let expected_missing: Vec<&str> = expected_local_refs
        .iter()
        .copied()
        .filter(|name| {
            request_refs
                .iter()
                .find(|(request_name, _)| request_name == name)
                .and_then(|(_, value)| *value)
                .is_none()
                || !provider_hashes
                    .get(*name)
                    .is_some_and(|(present, _)| *present)
        })
        .collect();
    json!({
        "expected_ref_count": expected_local_refs.len(),
        "expected_missing": expected_missing,
        "all_expected_refs_present": expected_missing.is_empty(),
        "refs": refs
    })
}

fn billing_ledger_executor_contract_has_validation_errors(contract: &Value) -> bool {
    contract
        .get("validation_errors")
        .and_then(Value::as_array)
        .is_some_and(|errors| !errors.is_empty())
}

fn payment_provider_optional_external_ref_hash(
    value: Option<&str>,
    field: &'static str,
) -> Result<Option<String>, AdminError> {
    let Some(value) = value else {
        return Ok(None);
    };
    let value = non_empty(value.to_string(), field)?;
    if value.len() > 256 {
        return Err(AdminError::bad_request(format!(
            "{field} must be at most 256 bytes"
        )));
    }
    if looks_like_secret_value(&value) {
        return Err(AdminError::bad_request(format!(
            "{field} must not contain credential material"
        )));
    }
    Ok(Some(sha256_hex(&format!(
        "payment-provider-local-executor:{field}:v1:{value}"
    ))))
}

fn payment_provider_local_executor_refusal_reason(
    provider: &str,
    input: &PaymentProviderAdapterConfigInput,
    credential_source: &Value,
) -> Option<&'static str> {
    if !payment_provider_webhook_provider_supported(provider) {
        return Some("provider_not_supported_by_local_executor");
    }
    let source_provider = credential_source
        .get("provider")
        .and_then(Value::as_str)
        .unwrap_or(provider);
    if source_provider != provider {
        return Some("credential_provider_config_mismatch");
    }
    if !input.adapter_enabled {
        return Some("provider_disabled");
    }
    if !input.merchant_account_present {
        return Some("merchant_account_missing");
    }
    if !input.credential_present && input.webhook_secret_present {
        return Some("webhook_only_credential_source");
    }
    if !input.credential_present {
        return Some("credential_missing");
    }
    if !input.webhook_secret_present {
        return Some("webhook_secret_missing");
    }
    None
}

