async fn insert_local_payment_provider_executor_event_readback(
    db: &PgPool,
    provider: &str,
    action_label: &str,
    reason: &str,
    request: PaymentProviderWebhookEventRequest,
    external_event_id_hash: String,
    amount: String,
    currency: String,
    idempotency_key_hash: String,
    adapter_config: Value,
    credential_source: Value,
    stripe_api_source_of_truth: Value,
    dispute_ref_hash: Option<String>,
    provider_object_ref_hash: Option<String>,
    billing_ledger_executor_contract: Value,
    stripe_like_client_request_plan: Value,
    stripe_like_provider_object_summary: Value,
    stripe_like_fetch_executor: Value,
    stripe_like_response_object_reconciliation: Value,
    provider_object_source_of_truth_present: bool,
) -> Result<Value, AdminError> {
    let db_event_type = payment_provider_db_event_type(request.event_type);
    let row = sqlx::query(
        r#"
        insert into payment_events (
          tenant_id, project_id, wallet_id, order_id, payment_intent_id,
          payment_capture_id, event_type, outcome, refusal_code,
          idempotency_key_hash, audit_id, request_summary, metadata
        )
        values ($1, $2, $3, $4, $5,
                $6, $7, 'applied', null,
                $8, null, $9, $10)
        returning
          id, tenant_id, project_id, wallet_id, order_id, payment_intent_id,
          payment_capture_id, event_type, outcome, idempotency_key_hash,
          request_summary, metadata, created_at::text as created_at
        "#,
    )
    .bind(request.tenant_id)
    .bind(request.project_id)
    .bind(request.wallet_id)
    .bind(request.order_id)
    .bind(request.payment_intent_id)
    .bind(request.payment_capture_id)
    .bind(db_event_type)
    .bind(&idempotency_key_hash)
    .bind(json!({
        "provider": provider,
        "local_executor_action": action_label,
        "provider_event_type": request.event_type,
        "external_event_id_hash": external_event_id_hash,
        "provider_object_ref_hash": provider_object_ref_hash,
        "dispute_ref_hash": dispute_ref_hash,
        "amount": amount,
        "currency": currency,
        "raw_idempotency_key": "omitted",
        "provider_payload": "omitted"
    }))
    .bind(json!({
        "schema": "payment_provider_local_executor_readback.v1",
        "mode": "typed_local_executor",
        "provider": provider,
        "action": action_label,
        "reason_present": !reason.is_empty(),
        "provider_object_ref_hash": provider_object_ref_hash,
        "dispute_ref_hash": dispute_ref_hash,
        "refund_id": request.refund_id,
        "credit_grant_id": request.credit_grant_id,
        "ledger_entry_id": request.ledger_entry_id,
        "reversal_ledger_entry_id": request.reversal_ledger_entry_id,
        "invoice_id": request.invoice_id,
        "secret_safe": true
    }))
    .fetch_one(db)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let payment_event_id: Uuid = row
        .try_get("id")
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    let execution_plan = execute_verified_payment_provider_business_plan(
        db,
        provider,
        &request,
        payment_event_id,
        &external_event_id_hash,
        &amount,
        &currency,
        Some(&idempotency_key_hash),
        &stripe_api_source_of_truth,
    )
    .await?;
    let action_result = payment_provider_local_executor_action_result(&execution_plan);
    let runtime_write_performed = action_result == "applied" || action_result == "replayed";

    Ok(json!({
        "schema": "payment_provider_local_executor_readback.v1",
        "mode": "typed_local_executor",
        "provider": provider,
        "action": action_label,
        "event_type": request.event_type,
        "amount": amount,
        "currency": currency,
        "action_result": action_result,
        "billing_ledger_executor_contract": billing_ledger_executor_contract,
        "stripe_like_client_request_plan": stripe_like_client_request_plan,
        "stripe_like_provider_object_summary": stripe_like_provider_object_summary,
        "stripe_like_fetch_executor": stripe_like_fetch_executor,
        "stripe_like_response_object_reconciliation": stripe_like_response_object_reconciliation,
        "executor_request": {
            "schema": "payment_provider_local_executor_request.v1",
            "action": action_label,
            "provider": provider,
            "tenant_id": request.tenant_id,
            "idempotency_fingerprint": idempotency_key_hash,
            "external_event_id_hash": external_event_id_hash,
            "provider_object_ref_hash": provider_object_ref_hash,
            "dispute_ref_hash": dispute_ref_hash,
            "amount": amount,
            "currency": currency,
            "reason_present": !reason.is_empty(),
            "refs": {
                "order_id": request.order_id,
                "project_id": request.project_id,
                "wallet_id": request.wallet_id,
                "payment_intent_id": request.payment_intent_id,
                "payment_capture_id": request.payment_capture_id,
                "refund_id": request.refund_id,
                "credit_grant_id": request.credit_grant_id,
                "ledger_entry_id": request.ledger_entry_id,
                "reversal_ledger_entry_id": request.reversal_ledger_entry_id,
                "invoice_id": request.invoice_id
            },
            "provider_object_source_of_truth_present": provider_object_source_of_truth_present,
            "provider_object_source_of_truth_echoed": false,
            "raw_idempotency_key_echoed": false,
            "raw_provider_payload_echoed": false,
            "provider_secret_echoed": false,
            "secret_safe": true
        },
        "executor_result": {
            "status": action_result,
            "applied": action_result == "applied",
            "replayed": action_result == "replayed",
            "blocked": action_result == "blocked",
            "refused": false,
            "payment_event_id": payment_event_id,
            "runtime_write_performed": runtime_write_performed
        },
        "event_write": {
            "attempted": true,
            "written": true,
            "readback_status": "read_back",
            "payment_event_id": payment_event_id,
            "db_event_type": row.try_get::<String, _>("event_type").map_err(|error| AdminError::from(DbError::Query(error)))?,
            "provider_event_type": request.event_type,
            "outcome": row.try_get::<String, _>("outcome").map_err(|error| AdminError::from(DbError::Query(error)))?,
            "created_at": row.try_get::<String, _>("created_at").map_err(|error| AdminError::from(DbError::Query(error)))?,
            "request_summary": row.try_get::<Value, _>("request_summary").map_err(|error| AdminError::from(DbError::Query(error)))?,
            "metadata": row.try_get::<Value, _>("metadata").map_err(|error| AdminError::from(DbError::Query(error)))?
        },
        "execution_plan": execution_plan,
        "credential_source": credential_source,
        "adapter_config": adapter_config,
        "stripe_api_source_of_truth": stripe_api_source_of_truth,
        "merchant_connected": true,
        "production_payment_evidence": false,
        "secret_safe": true,
        "raw_provider_payload_echoed": false,
        "raw_idempotency_key_echoed": false,
        "authorization_echoed": false,
        "provider_secret_echoed": false,
        "db_url_echoed": false,
        "omitted_fields": [
            "provider_payload",
            "raw_idempotency_key",
            "provider_secret",
            "credential_value",
            "webhook_signing_secret",
            "authorization",
            "database_url",
            "provider_object_source_of_truth"
        ]
    }))
}

fn payment_provider_local_executor_action_result(execution_plan: &Value) -> &'static str {
    let Some(plan_result) = execution_plan.get("action_result").and_then(Value::as_str) else {
        return "blocked";
    };
    match plan_result {
        "written" => "applied",
        "replayed" => "replayed",
        "not_executed" => "blocked",
        _ => "blocked",
    }
}

fn payment_provider_webhook_provider_supported(provider: &str) -> bool {
    provider == "stripe_like" || provider == STRIPE_LIKE_SANDBOX_ADAPTER
}

fn payment_provider_webhook_refusal_response(
    provider: &str,
    signature_verification: &str,
    adapter_config: Value,
    adapter_readback: Option<Value>,
    stripe_api_source_of_truth: Option<Value>,
) -> Value {
    let stripe_api_source_of_truth = stripe_api_source_of_truth.unwrap_or_else(|| {
        json!({
            "schema": "payment_provider_stripe_api_source_of_truth.v1",
            "adapter": "stripe_api_source_of_truth",
            "provider": provider,
            "api_read_model": "stripe_api_object_fetch_plan_v1",
            "source_of_truth_status": "credential_source_not_ready",
            "source_of_truth_blocked_reason": "signature_or_pre_credential_gate_not_passed",
            "network_call_enabled": false,
            "secret_ref_required": true,
            "credential_source": "pre_credential_signature_gate",
            "credential_source_ready": false,
            "object_ref_requirements": {
                "event_id_required": true,
                "object_id_required": true,
                "merchant_account_ref_required": true,
                "credential_secret_ref_required": true,
                "webhook_secret_ref_required_for_callback": true,
                "local_intent_or_capture_ref_required_for_accounting": true
            },
            "object_ref_readback": {
                "event_type": Value::Null,
                "provider_event_id_present": false,
                "provider_object_id_present": false,
                "local_payment_intent_ref_present": false,
                "local_payment_capture_ref_present": false,
                "local_refund_ref_present": false,
                "api_object_ref_mapping": "stripe.event.id and stripe.data.object.id are required after signature verification"
            },
            "capture_source_selection": "not_selected_until_signature_and_credential_source_ready",
            "refund_source_selection": "not_selected_until_signature_and_credential_source_ready",
            "chargeback_source_selection": "not_selected_until_signature_and_credential_source_ready",
            "callback_source_selection": "not_selected_until_signature_and_credential_source_ready",
            "sandbox_local_only": true,
            "production_payment_evidence": false,
            "secret_safe": true,
            "authorization_echoed": false,
            "provider_secret_echoed": false,
            "raw_provider_payload_echoed": false,
            "raw_webhook_body_echoed": false,
            "omitted_fields": [
                "provider_api_key",
                "credential_value",
                "webhook_signing_secret",
                "authorization",
                "stripe_event_payload",
                "stripe_object_payload",
                "raw_webhook_body",
                "database_url"
            ]
        })
    });
    let action_result = match signature_verification {
        "signature_missing" => "signature_missing",
        "config_needed" => "config_needed",
        "provider_disabled" => "provider_disabled",
        "credential_missing" => "credential_missing",
        "merchant_account_missing" => "merchant_account_missing",
        "webhook_secret_missing" => "webhook_secret_missing",
        _ => "refused",
    };
    let (execution_reason, execution_detail) = match signature_verification {
        "provider_disabled"
        | "credential_missing"
        | "merchant_account_missing"
        | "webhook_secret_missing" => (
            "credential_lifecycle_not_ready",
            "payment_events write was skipped because provider credential lifecycle is not enabled",
        ),
        _ => (
            "signature_not_verified",
            "payment_events write was skipped because signature verification did not pass",
        ),
    };
    json!({
        "schema": "payment_provider_webhook_event_write_readback.v1",
        "mode": "real_provider_webhook_boundary",
        "provider": provider,
        "adapter": STRIPE_LIKE_SANDBOX_ADAPTER,
        "signature_verification": signature_verification,
        "action_result": action_result,
        "runtime_write_performed": false,
        "event_write": {
            "attempted": false,
            "written": false,
            "readback_status": "not_written",
            "reason": signature_verification
        },
        "execution_plan": payment_provider_execution_plan_not_run(execution_reason, execution_detail),
        "merchant_connected": false,
        "production_payment_evidence": false,
        "secret_safe": true,
        "raw_webhook_body_echoed": false,
        "raw_provider_payload_echoed": false,
        "authorization_echoed": false,
        "provider_secret_echoed": false,
        "db_url_echoed": false,
        "adapter_config": adapter_config,
        "adapter_readback": adapter_readback.clone(),
        "adapter_normalization": adapter_readback,
        "stripe_api_source_of_truth": stripe_api_source_of_truth,
        "omitted_fields": [
            "raw_webhook_body",
            "provider_payload",
            "authorization",
            "provider_secret",
            "webhook_signing_secret",
            "database_url"
        ]
    })
}

