async fn list_health_summary_request_logs(
    state: &ControlPlaneState,
    tenant_id: Uuid,
    filter: ProviderHealthSummaryFilter,
) -> Result<Vec<RequestLogSummary>, AdminError> {
    let window_minutes = i32::try_from(filter.window_minutes)
        .map_err(|_| AdminError::bad_request("window_minutes is out of range"))?;
    let rows = sqlx::query(
        r#"
        select
          id, tenant_id, project_id, virtual_key_id, api_key_profile_id,
          trace_id, thread_id, client_request_id, inbound_protocol, outbound_protocol,
          protocol_mode, requested_model, canonical_model_id, upstream_model,
          resolved_provider_id, resolved_channel_id, provider_key_id, route_policy_version,
          status, http_status, error_owner, error_code, retryable, partial_sent,
          stream_end_reason, input_tokens, output_tokens, final_cost::text as final_cost,
          currency, latency_ms, ttft_ms, payload_policy_id, payload_stored,
          redaction_status, request_body_hash, response_body_hash,
          created_at::text as created_at, completed_at::text as completed_at,
          route_decision_snapshot
        from request_logs
        where tenant_id = $1
          and coalesce(completed_at, created_at) >= now() - make_interval(mins => $2::int)
        order by coalesce(completed_at, created_at) desc, created_at desc, id desc
        limit $3
        "#,
    )
    .bind(tenant_id)
    .bind(window_minutes)
    .bind(filter.sample_limit)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    rows.into_iter()
        .map(health_summary_request_log_from_row)
        .collect::<Result<Vec<_>, _>>()
        .map_err(|error| AdminError::from(DbError::Query(error)))
}

fn health_summary_request_log_from_row(row: PgRow) -> Result<RequestLogSummary, sqlx::Error> {
    let partial_sent = row.try_get("partial_sent")?;
    let stream_end_reason: Option<String> = row.try_get("stream_end_reason")?;
    let ttft_ms = row.try_get("ttft_ms")?;
    let route_decision_snapshot: Value = row.try_get("route_decision_snapshot")?;
    let input_tokens = row.try_get("input_tokens")?;
    let output_tokens = row.try_get("output_tokens")?;
    let response_body_hash: Option<String> = row.try_get("response_body_hash")?;
    Ok(RequestLogSummary {
        id: row.try_get("id")?,
        tenant_id: row.try_get("tenant_id")?,
        project_id: row.try_get("project_id")?,
        virtual_key_id: row.try_get("virtual_key_id")?,
        api_key_profile_id: row.try_get("api_key_profile_id")?,
        trace_id: row.try_get("trace_id")?,
        thread_id: row.try_get("thread_id")?,
        client_request_id: row.try_get("client_request_id")?,
        inbound_protocol: row.try_get("inbound_protocol")?,
        outbound_protocol: row.try_get("outbound_protocol")?,
        protocol_mode: row.try_get("protocol_mode")?,
        requested_model: row.try_get("requested_model")?,
        canonical_model_id: row.try_get("canonical_model_id")?,
        upstream_model: row.try_get("upstream_model")?,
        resolved_provider_id: row.try_get("resolved_provider_id")?,
        resolved_channel_id: row.try_get("resolved_channel_id")?,
        provider_key_id: row.try_get("provider_key_id")?,
        route_policy_version: row.try_get("route_policy_version")?,
        status: row.try_get("status")?,
        http_status: row.try_get("http_status")?,
        error_owner: row.try_get("error_owner")?,
        error_code: row.try_get("error_code")?,
        retryable: row.try_get("retryable")?,
        partial_sent,
        stream_end_reason: stream_end_reason.clone(),
        stream_finalizer: ai_gateway_db::request_log_stream_finalizer_projection(
            partial_sent,
            stream_end_reason.as_deref(),
            ttft_ms,
            &route_decision_snapshot,
        ),
        provider_protocol_summary: ai_gateway_db::request_log_provider_protocol_summary_projection(
            partial_sent,
            stream_end_reason.as_deref(),
            &route_decision_snapshot,
        ),
        rate_limit_metadata: ai_gateway_db::request_log_rate_limit_metadata_projection(
            &route_decision_snapshot,
        ),
        openai_compat: ai_gateway_db::request_log_openai_compat_projection(
            partial_sent,
            stream_end_reason.as_deref(),
            ttft_ms,
            input_tokens,
            output_tokens,
            response_body_hash.as_deref(),
            &route_decision_snapshot,
        ),
        input_tokens,
        output_tokens,
        final_cost: row.try_get("final_cost")?,
        currency: row.try_get("currency")?,
        latency_ms: row.try_get("latency_ms")?,
        ttft_ms,
        payload_policy_id: row.try_get("payload_policy_id")?,
        payload_stored: row.try_get("payload_stored")?,
        redaction_status: row.try_get("redaction_status")?,
        request_body_hash: row.try_get("request_body_hash")?,
        response_body_hash,
        created_at: row.try_get("created_at")?,
        completed_at: row.try_get("completed_at")?,
    })
}

async fn list_audit_logs(
    state: &ControlPlaneState,
    filter: AuditLogListFilter,
) -> Result<Vec<AuditLog>, AdminError> {
    let rows = sqlx::query(
        r#"
        select
          id, tenant_id, actor_user_id, request_id, action, resource_type, resource_id,
          resource_tenant_id, before_snapshot, after_snapshot, metadata,
          created_at::text as created_at
        from audit_logs
        where tenant_id = $1
          and ($2::uuid is null or actor_user_id = $2)
          and ($3::uuid is null or metadata->>'actor_session_id' = $3::text)
          and ($4::text is null or action = $4)
          and ($5::text is null or resource_type = $5)
          and ($6::uuid is null or resource_id = $6)
          and ($7::uuid is null or resource_tenant_id = $7)
          and ($8::timestamptz is null or created_at >= $8::timestamptz)
          and ($9::timestamptz is null or created_at <= $9::timestamptz)
        order by created_at desc, id desc
        limit $10
        "#,
    )
    .bind(filter.tenant_id)
    .bind(filter.actor_user_id)
    .bind(filter.actor_session_id)
    .bind(filter.action)
    .bind(filter.resource_type)
    .bind(filter.resource_id)
    .bind(filter.resource_tenant_id)
    .bind(filter.created_from)
    .bind(filter.created_to)
    .bind(filter.limit)
    .fetch_all(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    rows.into_iter()
        .map(audit_log_from_row)
        .collect::<Result<Vec<_>, _>>()
        .map_err(|error| AdminError::from(DbError::Query(error)))
}

fn audit_log_from_row(row: PgRow) -> Result<AuditLog, sqlx::Error> {
    Ok(AuditLog {
        id: row.try_get("id")?,
        tenant_id: row.try_get("tenant_id")?,
        actor_user_id: row.try_get("actor_user_id")?,
        request_id: row.try_get("request_id")?,
        action: row.try_get("action")?,
        resource_type: row.try_get("resource_type")?,
        resource_id: row.try_get("resource_id")?,
        resource_tenant_id: row.try_get("resource_tenant_id")?,
        before_snapshot: row.try_get("before_snapshot")?,
        after_snapshot: row.try_get("after_snapshot")?,
        metadata: row.try_get("metadata")?,
        created_at: row.try_get("created_at")?,
    })
}

fn audit_log_response(audit_log: AuditLog) -> Value {
    let detail_readback = audit_log_detail_readback(&audit_log);
    json!({
        "id": audit_log.id,
        "tenant_id": audit_log.tenant_id,
        "actor_user_id": audit_log.actor_user_id,
        "request_id": audit_log.request_id,
        "action": audit_log.action,
        "resource_type": audit_log.resource_type,
        "resource_id": audit_log.resource_id,
        "resource_tenant_id": audit_log.resource_tenant_id,
        "before_snapshot": audit_log.before_snapshot.map(audit_log_safe_json_value),
        "after_snapshot": audit_log.after_snapshot.map(audit_log_safe_json_value),
        "metadata": audit_log_safe_json_value(audit_log.metadata),
        "audit_log_detail_readback": detail_readback,
        "created_at": audit_log.created_at,
    })
}

fn audit_log_detail_readback(audit_log: &AuditLog) -> Value {
    let safe_metadata = audit_log_safe_json_value(audit_log.metadata.clone());
    let safe_before = audit_log
        .before_snapshot
        .clone()
        .map(audit_log_safe_json_value)
        .unwrap_or(Value::Null);
    let safe_after = audit_log
        .after_snapshot
        .clone()
        .map(audit_log_safe_json_value)
        .unwrap_or(Value::Null);
    let safe_summary_keys = safe_audit_metadata_summary_keys(&safe_metadata);
    let action_result = first_audit_summary_value(&[
        safe_metadata.get("action_result"),
        safe_metadata.get("status"),
        safe_metadata.get("to_status"),
        safe_after.get("status"),
    ])
    .unwrap_or_else(|| "recorded".to_string());

    json!({
        "schema": "audit_log_detail_readback.v1",
        "source": "audit_logs",
        "audit_log_id": audit_log.id,
        "action": redact_secrets(&audit_log.action),
        "action_result": action_result,
        "resource_refs": {
            "resource_type": redact_secrets(&audit_log.resource_type),
            "resource_id": audit_log.resource_id,
            "resource_id_present": audit_log.resource_id.is_some(),
            "resource_tenant_id": audit_log.resource_tenant_id,
            "resource_tenant_id_present": audit_log.resource_tenant_id.is_some(),
            "request_id": audit_log.request_id,
            "request_id_present": audit_log.request_id.is_some(),
        },
        "actor_session_presence": {
            "actor_user_id_present": audit_log.actor_user_id.is_some(),
            "actor_session_id_present": safe_metadata.get("actor_session_id").is_some(),
            "raw_session_returned": false,
        },
        "metadata_redaction_summary": {
            "metadata_object": safe_metadata.is_object(),
            "safe_summary_keys": safe_summary_keys,
            "redacted_field_count": count_redacted_audit_values(&safe_metadata),
            "before_snapshot_redacted_field_count": count_redacted_audit_values(&safe_before),
            "after_snapshot_redacted_field_count": count_redacted_audit_values(&safe_after),
            "forbidden_material_omitted": [
                "raw_token",
                "raw_session",
                "api_key_secret",
                "provider_credential_material",
                "auth_header",
                "raw_payload"
            ],
            "raw_payload_returned": false,
            "raw_authorization_returned": false,
            "raw_api_key_returned": false,
            "raw_provider_key_returned": false,
        },
        "safe_next_action": audit_log_safe_next_action(audit_log),
    })
}

fn safe_audit_metadata_summary_keys(value: &Value) -> Vec<String> {
    let Some(object) = value.as_object() else {
        return Vec::new();
    };

    object
        .iter()
        .filter_map(|(key, value)| {
            if is_sensitive_audit_key(key)
                || matches!(value, Value::String(text) if text == "[REDACTED]")
            {
                None
            } else {
                Some(redact_secrets(key))
            }
        })
        .take(12)
        .collect()
}

fn first_audit_summary_value(values: &[Option<&Value>]) -> Option<String> {
    values.iter().find_map(|value| match value {
        Some(Value::String(text)) if !text.trim().is_empty() && text != &"[REDACTED]" => {
            Some(redact_secrets(text))
        }
        Some(Value::Bool(value)) => Some(value.to_string()),
        Some(Value::Number(value)) => Some(value.to_string()),
        _ => None,
    })
}

fn count_redacted_audit_values(value: &Value) -> usize {
    match value {
        Value::String(text) if text == "[REDACTED]" => 1,
        Value::Array(values) => values.iter().map(count_redacted_audit_values).sum(),
        Value::Object(object) => object.values().map(count_redacted_audit_values).sum(),
        _ => 0,
    }
}

fn audit_log_safe_next_action(audit_log: &AuditLog) -> String {
    if audit_log.request_id.is_some() {
        return "Open request detail by request_id, then correlate ledger entries and trace summary; do not fetch payload content.".to_string();
    }

    if audit_log.resource_id.is_some() {
        return format!(
            "Filter admin read models by resource_type={} and resource_id; use sanitized metadata summary only.",
            redact_secrets(&audit_log.resource_type)
        );
    }

    "Filter audit logs by action and created_at window; use approved forensic channels for any credential or raw payload investigation.".to_string()
}

fn audit_log_safe_json_value(value: Value) -> Value {
    match sanitize_audit_value(value) {
        Value::Object(object) => Value::Object(
            object
                .into_iter()
                .map(|(key, value)| {
                    if is_sensitive_audit_key(&key) {
                        (key, Value::String("[REDACTED]".to_string()))
                    } else {
                        (key, audit_log_safe_json_value(value))
                    }
                })
                .collect(),
        ),
        Value::Array(values) => {
            Value::Array(values.into_iter().map(audit_log_safe_json_value).collect())
        }
        Value::String(value) => Value::String(redact_secrets(&value)),
        value => value,
    }
}

fn canonical_model_response(model: CanonicalModel, default_price_book_id: Option<Uuid>) -> Value {
    let mut value = serde_json::to_value(model).expect("canonical model should serialize");
    if let Some(object) = value.as_object_mut() {
        object.insert(
            "default_price_book_id".to_string(),
            default_price_book_id
                .map(|id| json!(id))
                .unwrap_or(Value::Null),
        );
    }
    value
}

async fn get_model_default_price_book_id(
    repository: &DbRepository,
    model_id: Uuid,
) -> Result<Option<Uuid>, AdminError> {
    let row = sqlx::query(
        r#"
        select default_price_book_id
        from canonical_models
        where tenant_id = $1
          and id = $2
          and deleted_at is null
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(model_id)
    .fetch_optional(repository.pool())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    match row {
        Some(row) => row
            .try_get::<Option<Uuid>, _>("default_price_book_id")
            .map_err(|error| AdminError::from(DbError::Query(error))),
        None => Ok(None),
    }
}

async fn list_model_default_price_book_ids(
    repository: &DbRepository,
    models: &[CanonicalModel],
) -> Result<HashMap<Uuid, Option<Uuid>>, AdminError> {
    if models.is_empty() {
        return Ok(HashMap::new());
    }

    let model_ids = models.iter().map(|model| model.id).collect::<Vec<_>>();
    let rows = sqlx::query(
        r#"
        select id, default_price_book_id
        from canonical_models
        where tenant_id = $1
          and id = any($2)
          and deleted_at is null
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(model_ids)
    .fetch_all(repository.pool())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    rows.into_iter()
        .map(|row| Ok((row.try_get("id")?, row.try_get("default_price_book_id")?)))
        .collect::<Result<HashMap<_, _>, sqlx::Error>>()
        .map_err(|error| AdminError::from(DbError::Query(error)))
}

async fn validate_model_default_price_book_selector(
    repository: &DbRepository,
    selector_change: DefaultPriceBookSelectorChange,
) -> Result<Option<Value>, AdminError> {
    match selector_change {
        DefaultPriceBookSelectorChange::Unchanged => Ok(None),
        DefaultPriceBookSelectorChange::Set(default_price_book_id) => {
            let price_book_currency = repository
                .get_price_book_currency(DEFAULT_TENANT_ID, default_price_book_id)
                .await?
                .ok_or_else(|| AdminError::not_found("price book"))?;

            Ok(Some(json!({
                "operation": "set",
                "default_price_book_id": default_price_book_id,
                "price_book_currency": price_book_currency,
                "relationship_validated": "tenant_canonical_model_price_book",
                "price_version_selector": "active_effective_version_for_default_price_book",
                "selector_write": "transactional_with_model_audit",
                "sensitive_material_policy": "uuid_and_currency_only",
            })))
        }
        DefaultPriceBookSelectorChange::Clear => Ok(Some(json!({
            "operation": "clear",
            "default_price_book_id": Value::Null,
            "relationship_validated": "tenant_canonical_model_price_book",
            "price_version_selector": "active_effective_version_for_default_price_book",
            "selector_write": "transactional_with_model_audit",
            "sensitive_material_policy": "uuid_and_currency_only",
        }))),
    }
}

fn model_write_audit_metadata(
    upsert_semantics: bool,
    default_price_selector: Option<Value>,
) -> Value {
    let mut metadata = json!({
        "transactional_audit": true,
        "upsert_semantics": upsert_semantics,
        "default_price_config_contract": {
            "tenant_price_book_relation_required": true,
            "canonical_model_relation_required": true,
            "selector_write_transactional_with_model_audit": true,
            "write_audit_secret_safe": true,
        },
    });
    if let Some(default_price_selector) = default_price_selector {
        metadata
            .as_object_mut()
            .expect("metadata should be an object")
            .insert("default_price_selector".to_string(), default_price_selector);
    }
    metadata
}

