fn validate_opening_balance_import_request(
    request: &OpeningBalanceImportRequest,
) -> Result<(), AdminError> {
    if request.tenant_id != DEFAULT_TENANT_ID {
        return Err(AdminError::bad_request(
            "tenant_id must match the current control-plane tenant",
        ));
    }
    validate_price_version_currency(&request.currency)?;
    let amount = parse_billing_fixed_decimal(&request.opening_amount)?;
    if amount.units() <= 0 {
        return Err(AdminError::bad_request(
            "opening_amount must be a positive decimal string",
        ));
    }
    for (field, value) in [
        ("external_source", request.external_source.as_str()),
        (
            "external_reference_id",
            request.external_reference_id.as_str(),
        ),
        ("effective_at", request.effective_at.as_str()),
        ("reason", request.reason.as_str()),
        ("actor_type", request.actor_type.as_str()),
        ("idempotency_key", request.idempotency_key.as_str()),
    ] {
        if value.trim().is_empty() {
            return Err(AdminError::bad_request(format!(
                "{field} must not be empty"
            )));
        }
    }
    if request.reason.len() > LEDGER_ADJUSTMENT_REASON_MAX_BYTES {
        return Err(AdminError::bad_request(format!(
            "reason must be at most {LEDGER_ADJUSTMENT_REASON_MAX_BYTES} bytes"
        )));
    }
    Ok(())
}

