fn importer_apply_live_acceptance_skeleton(
    plan: &Value,
    session: &AdminSession,
) -> Result<Value, AdminError> {
    validate_importer_apply_live_plan(plan)?;
    let transaction_contract = plan
        .get("transaction_contract")
        .ok_or_else(|| AdminError::bad_request("transaction_contract is required"))?;
    let sql_executor_plan = plan
        .get("sql_executor_plan")
        .ok_or_else(|| AdminError::bad_request("sql_executor_plan is required"))?;
    let rollback_snapshot = plan
        .get("rollback_snapshot")
        .ok_or_else(|| AdminError::bad_request("rollback_snapshot is required"))?;
    let idempotency_manifest = plan
        .get("idempotency_manifest")
        .ok_or_else(|| AdminError::bad_request("idempotency_manifest is required"))?;

    let plan_idempotency_key = required_json_string(plan, "idempotency_key")?;
    let transaction_id = required_nested_json_string(transaction_contract, "transaction_id")?;
    let rollback_snapshot_idempotency_key =
        required_nested_json_string(rollback_snapshot, "idempotency_key")?;
    let idempotency_manifest_key =
        required_nested_json_string(idempotency_manifest, "manifest_key")?;
    let operation_count = idempotency_manifest
        .get("write_operation_count")
        .and_then(Value::as_u64)
        .unwrap_or_else(|| {
            idempotency_manifest
                .get("entries")
                .and_then(Value::as_array)
                .map(|entries| entries.len() as u64)
                .unwrap_or(0)
        });
    let journal_contract_schema = sql_executor_plan
        .get("journal_contract")
        .and_then(|journal| journal.get("schema_version"))
        .and_then(Value::as_str)
        .unwrap_or("importer.rollback-journal-contract.v1");

    Ok(json!({
        "schema_version": "control_plane.importer_apply_live.accepted_skeleton.v1",
        "status": "accepted",
        "accepted_plan": {
            "schema_version": "importer.apply-plan.v1",
            "reviewed": true,
            "preflight_status": "pass",
            "plan_idempotency_key": redact_secrets(plan_idempotency_key),
            "transaction_id": redact_secrets(transaction_id),
            "rollback_snapshot_idempotency_key": redact_secrets(rollback_snapshot_idempotency_key),
            "idempotency_manifest_key": redact_secrets(idempotency_manifest_key),
            "planned_write_operation_count": operation_count,
            "counts": plan.get("counts").cloned().unwrap_or(Value::Null),
        },
        "transaction_skeleton": {
            "schema_tables": [
                "importer_apply_runs",
                "importer_apply_operation_journal"
            ],
            "schema_migration": "db/migrations/0016_importer_apply_journal.sql",
            "transaction_id": redact_secrets(transaction_id),
            "run_status": "prepared",
            "dry_run_contract": true,
            "begin_after_admin_rbac": true,
            "sql_apply_executed": false,
            "commit_performed": false,
            "planned_steps": [
                "validate_admin_session_and_billing_adjust_rbac",
                "validate_importer_apply_plan_shape",
                "validate_review_marker",
                "validate_preflight_pass",
                "validate_no_provider_key_material",
                "prepare_importer_apply_runs_row",
                "prepare_importer_apply_operation_journal_rows"
            ],
        },
        "journal_skeleton": {
            "schema_version": "control_plane.importer_apply_operation_journal.skeleton.v1",
            "journal_contract_schema": journal_contract_schema,
            "operation_count": operation_count,
            "operation_status": "prepared",
            "rollback_snapshot_idempotency_key": redact_secrets(rollback_snapshot_idempotency_key),
            "idempotency_manifest_key": redact_secrets(idempotency_manifest_key),
            "operation_rows_inserted": false,
            "operation_sql_applied": false,
        },
        "guardrails": {
            "admin_session_required": true,
            "required_permission": "billing_adjust",
            "reviewed_apply_plan_required": true,
            "preflight_status_required": "pass",
            "provider_key_material_allowed": false,
            "provider_key_material_echoed": false,
            "raw_import_payload_echoed": false,
            "database_url_echoed": false,
            "sql_apply_executed": false,
        },
        "session_id": session.session_id(),
        "tenant_id": session.tenant_id(),
        "secret_safe": true,
    }))
}

fn importer_apply_run_readback(
    request: Option<&Value>,
    session: &AdminSession,
) -> Result<Value, AdminError> {
    if let Some(value) = request {
        if contains_provider_key_material(value) {
            return Err(AdminError::bad_request(
                "DB URLs, raw SQL, raw user keys, provider keys, Authorization, tokens, and secrets are forbidden",
            ));
        }
        if value
            .get("db_writes_performed")
            .and_then(Value::as_bool)
            .unwrap_or(false)
        {
            return Err(AdminError::bad_request(
                "db_writes_performed must be false for importer apply-plan readback",
            ));
        }
    }

    let plan_hash = request
        .and_then(|value| {
            value
                .get("plan_hash")
                .or_else(|| value.get("reviewed_plan_hash_sha256"))
                .or_else(|| {
                    value
                        .get("operator_approval_packet")
                        .and_then(|packet| packet.get("reviewed_plan_hash_sha256"))
                })
                .and_then(Value::as_str)
        })
        .map(redact_secrets)
        .or_else(|| request.map(importer_apply_readback_hash));
    let idempotency_fingerprint = request
        .and_then(importer_apply_readback_idempotency_fingerprint)
        .unwrap_or(Value::Null);
    let blocked_reasons = request
        .and_then(|value| value.get("blocked_reasons"))
        .and_then(Value::as_array)
        .map(|reasons| {
            reasons
                .iter()
                .filter_map(Value::as_str)
                .map(redact_secrets)
                .collect::<Vec<_>>()
        })
        .unwrap_or_else(|| {
            vec![
                "[!] production DB connection not opened by this readback seam".to_string(),
                "[!] operator execution window/change ticket not represented locally".to_string(),
            ]
        });
    let applied_row_counts = request
        .and_then(importer_apply_readback_applied_row_counts)
        .unwrap_or_else(|| {
            json!({
                "importer_apply_runs": 0,
                "importer_apply_operation_journal": 0,
                "target_rows": 0
            })
        });
    let rollback_journal_ref_present = request
        .map(importer_apply_readback_rollback_journal_ref_present)
        .unwrap_or(false);
    let safe_next_action = request
        .and_then(|value| value.get("safe_next_action").and_then(Value::as_str))
        .map(redact_secrets)
        .unwrap_or_else(|| {
            if blocked_reasons.is_empty() {
                "[!] hand off reviewed apply-plan readback to operator; real production DB connection and execution window remain external gaps".to_string()
            } else {
                "Resolve blocked_reasons, then rerun the dry-run readback; do not paste DB URLs, raw SQL, raw user keys, provider keys, Authorization, or secrets.".to_string()
            }
        });

    Ok(json!({
        "schema_version": "control_plane.importer_apply_plan_readback.v1",
        "status": if blocked_reasons.is_empty() { "readback-ready" } else { "blocked" },
        "tenant_id": session.tenant_id(),
        "session_id": session.session_id(),
        "plan_hash": plan_hash,
        "idempotency_fingerprint": idempotency_fingerprint,
        "apply_result": {
            "applied_row_counts": applied_row_counts,
            "db_writes_performed": false,
            "production_db_apply_performed": false,
            "raw_sql_returned": false,
        },
        "rollback_result": {
            "rollback_journal_ref_present": rollback_journal_ref_present,
            "rollback_db_writes_performed": false,
            "raw_sql_returned": false,
        },
        "applied_row_counts": applied_row_counts,
        "rollback_journal_ref_present": rollback_journal_ref_present,
        "blocked_reasons": blocked_reasons,
        "safe_next_action": safe_next_action,
        "db_writes_performed": false,
        "readback_source": "local_demo_or_operator_handoff",
        "forbidden_material_returned": false,
        "db_url_returned": false,
        "raw_sql_returned": false,
        "raw_user_key_returned": false,
        "provider_key_returned": false,
        "authorization_returned": false,
        "secret_returned": false,
        "secret_safe": true,
    }))
}

fn importer_apply_readback_hash(value: &Value) -> String {
    let bytes = serde_json::to_vec(value).unwrap_or_default();
    let mut hasher = Sha256::new();
    hasher.update(bytes);
    format!("{:x}", hasher.finalize())
}

fn importer_apply_readback_idempotency_fingerprint(value: &Value) -> Option<Value> {
    value
        .get("idempotency_fingerprint")
        .cloned()
        .or_else(|| value.get("idempotency_summary").cloned())
        .or_else(|| value.get("idempotency_readback").cloned())
        .or_else(|| {
            value
                .get("operator_approval_packet")
                .and_then(|packet| packet.get("idempotency_summary"))
                .cloned()
        })
}

fn importer_apply_readback_applied_row_counts(value: &Value) -> Option<Value> {
    let row_counts = value.get("applied_row_counts").or_else(|| {
        value
            .get("apply_result")
            .and_then(|apply| apply.get("applied_row_counts"))
    })?;
    row_counts.as_object().map(|object| {
        Value::Object(
            object
                .iter()
                .map(|(key, value)| {
                    let count = value.as_i64().unwrap_or(0).max(0);
                    (redact_secrets(key), json!(count))
                })
                .collect(),
        )
    })
}

fn importer_apply_readback_rollback_journal_ref_present(value: &Value) -> bool {
    value
        .get("rollback_journal_ref_present")
        .or_else(|| {
            value
                .get("rollback_result")
                .and_then(|rollback| rollback.get("rollback_journal_ref_present"))
        })
        .and_then(Value::as_bool)
        .unwrap_or_else(|| {
            value.get("rollback_guard").is_some() || value.get("journal_skeleton").is_some()
        })
}

fn validate_importer_apply_live_plan(plan: &Value) -> Result<(), AdminError> {
    if !plan.is_object() {
        return Err(AdminError::bad_request(
            "importer apply plan must be a JSON object",
        ));
    }
    if required_json_string(plan, "schema_version")? != "importer.apply-plan.v1" {
        return Err(AdminError::bad_request(
            "schema_version must be importer.apply-plan.v1",
        ));
    }
    if !importer_apply_plan_reviewed(plan) {
        return Err(AdminError::bad_request(
            "reviewed importer.apply-plan.v1 is required",
        ));
    }
    if plan
        .get("preflight")
        .and_then(|preflight| preflight.get("status"))
        .and_then(Value::as_str)
        != Some("pass")
    {
        return Err(AdminError::bad_request("preflight.status must be pass"));
    }
    if importer_apply_plan_has_failed_preflight_check(plan) {
        return Err(AdminError::bad_request(
            "preflight checks must not contain failed checks",
        ));
    }
    if contains_provider_key_material(plan) {
        return Err(AdminError::bad_request(
            "provider key material, credentials, tokens, and database URLs are forbidden",
        ));
    }
    Ok(())
}

fn importer_apply_plan_reviewed(plan: &Value) -> bool {
    if plan.get("reviewed").and_then(Value::as_bool) == Some(true) {
        return true;
    }
    let accepted = ["reviewed", "approved", "accepted"];
    plan.get("review")
        .and_then(|review| review.get("status").or_else(|| review.get("review_status")))
        .and_then(Value::as_str)
        .map(|status| accepted.contains(&status))
        .unwrap_or(false)
}

fn importer_apply_plan_has_failed_preflight_check(plan: &Value) -> bool {
    plan.get("preflight")
        .and_then(|preflight| preflight.get("checks"))
        .and_then(Value::as_array)
        .map(|checks| {
            checks.iter().any(|check| {
                check
                    .get("status")
                    .and_then(Value::as_str)
                    .map(|status| status == "fail" || status == "failed" || status == "blocked")
                    .unwrap_or(false)
            })
        })
        .unwrap_or(false)
}

fn required_json_string<'a>(value: &'a Value, field: &str) -> Result<&'a str, AdminError> {
    value
        .get(field)
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| AdminError::bad_request(format!("{field} is required")))
}

fn required_nested_json_string<'a>(value: &'a Value, field: &str) -> Result<&'a str, AdminError> {
    required_json_string(value, field)
}

fn contains_provider_key_material(value: &Value) -> bool {
    contains_forbidden_importer_secret_value(None, value)
}

fn contains_forbidden_importer_secret_value(key: Option<&str>, value: &Value) -> bool {
    match value {
        Value::Object(object) => object.iter().any(|(child_key, child_value)| {
            importer_apply_live_forbidden_secret_key(child_key)
                || contains_forbidden_importer_secret_value(Some(child_key), child_value)
        }),
        Value::Array(values) => values
            .iter()
            .any(|child| contains_forbidden_importer_secret_value(key, child)),
        Value::String(value) => importer_apply_live_forbidden_secret_string(key, value),
        _ => false,
    }
}

fn importer_apply_live_forbidden_secret_key(key: &str) -> bool {
    let normalized = key.to_ascii_lowercase();
    normalized.contains("raw_provider_key")
        || normalized.contains("raw_user_key")
        || normalized.contains("raw_sql")
        || normalized.contains("database_url")
        || normalized.contains("db_url")
        || normalized.contains("postgres_url")
        || normalized.contains("provider_key_secret")
        || normalized.contains("provider_key_value")
        || normalized == "provider_key"
        || normalized == "api_key"
        || normalized.ends_with("_api_key")
        || normalized.contains("authorization")
        || normalized.contains("password")
        || normalized.contains("credential")
        || normalized.contains("secret")
        || normalized.ends_with("_token")
}

fn importer_apply_live_forbidden_secret_string(key: Option<&str>, value: &str) -> bool {
    let normalized = value.to_ascii_lowercase();
    normalized.contains("postgres://")
        || normalized.contains("postgresql://")
        || normalized.contains("authorization: bearer")
        || normalized.contains("bearer sk-")
        || normalized.starts_with("sk-")
        || key
            .map(importer_apply_live_forbidden_secret_key)
            .unwrap_or(false)
}

#[allow(dead_code)]
async fn execute_opening_balance_import_internal_tx(
    tx: &mut Transaction<'_, Postgres>,
    session: &AdminSession,
    request: &OpeningBalanceImportRequest,
) -> Result<Value, AdminError> {
    validate_opening_balance_import_request(request)?;
    let wallet = get_opening_balance_import_wallet_for_update_tx(tx, request.wallet_id).await?;
    let existing_by_idempotency =
        get_opening_balance_import_by_idempotency_for_update_tx(tx, &request.idempotency_key)
            .await?;
    if existing_by_idempotency.is_some() {
        let attempt = opening_balance_import_runtime_attempt_contract_shape(
            request,
            wallet.as_ref(),
            existing_by_idempotency.as_ref(),
            None,
        )?;
        return Ok(opening_balance_import_mark_runtime_invoked(attempt, false));
    }

    let existing_by_external_reference =
        get_opening_balance_import_by_external_reference_for_update_tx(
            tx,
            &request.external_source,
            &request.external_reference_id,
        )
        .await?;
    if existing_by_external_reference.is_some() || wallet.is_none() {
        let attempt = opening_balance_import_runtime_attempt_contract_shape(
            request,
            wallet.as_ref(),
            None,
            existing_by_external_reference.as_ref(),
        )?;
        return Ok(opening_balance_import_mark_runtime_invoked(attempt, false));
    }

    let attempt = opening_balance_import_runtime_attempt_contract_shape(
        request,
        wallet.as_ref(),
        None,
        None,
    )?;
    if attempt["outcome"] != json!("apply") {
        return Ok(opening_balance_import_mark_runtime_invoked(attempt, false));
    }

    let request_summary = opening_balance_import_safe_request_summary(request)?;
    let opening_import_id =
        insert_opening_balance_import_row_tx(tx, request, request_summary.clone()).await?;
    let metadata = opening_balance_import_ledger_metadata(opening_import_id, request);
    let ledger_entry =
        insert_opening_balance_import_ledger_entry_tx(tx, request, opening_import_id, metadata)
            .await?;
    let audit_resource = OpeningBalanceImportAuditResource {
        tenant_id: request.tenant_id,
        id: opening_import_id,
        summary: json!({
            "opening_import_id": opening_import_id,
            "wallet_id": request.wallet_id,
            "project_id": request.project_id,
            "ledger_entry_id": ledger_entry.id,
            "currency": request.currency,
            "opening_amount": admin_wallet_fixed_money_string(&request.opening_amount)?,
            "external_source": redact_secrets(&request.external_source),
            "external_reference_id": redact_secrets(&request.external_reference_id),
            "idempotency_key": "omitted",
            "secret_safe": true,
        }),
    };
    let audit_log_id = insert_admin_audit_log_tx(
        tx,
        new_admin_audit_log(
            session,
            "billing.opening_balance_import",
            None,
            &audit_resource,
            opening_balance_import_audit_metadata(),
            None,
        ),
    )
    .await?;
    link_opening_balance_import_tx(tx, opening_import_id, ledger_entry.id, audit_log_id).await?;

    Ok(opening_balance_import_mark_runtime_invoked(
        opening_balance_import_runtime_applied_response(
            request,
            opening_import_id,
            ledger_entry.id,
            audit_log_id,
        )?,
        false,
    ))
}

fn opening_balance_import_mark_runtime_invoked(mut body: Value, route_invoked: bool) -> Value {
    let status = body
        .get("status")
        .and_then(Value::as_str)
        .unwrap_or("unknown")
        .to_string();
    let outcome = body
        .get("outcome")
        .and_then(Value::as_str)
        .unwrap_or("unknown")
        .to_string();
    let opening_import_readback = body
        .get("opening_import_id")
        .is_some_and(|value| !value.is_null());
    let ledger_readback = body
        .get("ledger_entry_id")
        .is_some_and(|value| !value.is_null());
    let audit_readback = body.get("audit_id").is_some_and(|value| !value.is_null());

    if let Some(object) = body.as_object_mut() {
        object.insert("runtime_implemented".to_string(), json!(true));
        object.insert("contract_only".to_string(), json!(false));
        object.insert("route_executes_sql".to_string(), json!(true));
        object.insert("route_invoked".to_string(), json!(route_invoked));
        object.insert("internal_sqlx_function_invoked".to_string(), json!(true));
        object.insert("paid_gate_changed".to_string(), json!(false));
        object.insert("secret_safe".to_string(), json!(true));
        object.insert(
            "runtime_invocation".to_string(),
            json!({
                "public_route_wired": true,
                "route_invoked": route_invoked,
                "internal_sqlx_function_invoked": true,
                "transaction_function": "execute_opening_balance_import_internal_tx",
                "contract_only": false,
                "paid_gate_changed": false
            }),
        );
        object.insert(
            "readback".to_string(),
            json!({
                "opening_import_readback": opening_import_readback,
                "ledger_entry_readback": ledger_readback,
                "audit_log_readback": audit_readback,
                "replay_same_key_body_supported": status == "replayed",
                "idempotency_conflict_refusal_supported": outcome == "idempotency_conflict",
                "external_reference_conflict_refusal_supported": outcome == "external_reference_conflict",
                "wallet_currency_refusal_no_ledger_write": outcome == "wallet_or_currency_refusal",
                "direct_wallet_snapshot_mutation": false,
                "rollback_containment": "transaction_scoped"
            }),
        );
    }

    body
}

fn opening_balance_import_runtime_applied_response(
    request: &OpeningBalanceImportRequest,
    opening_import_id: Uuid,
    ledger_entry_id: Uuid,
    audit_id: Uuid,
) -> Result<Value, AdminError> {
    Ok(json!({
        "schema_version": "opening_balance_import_runtime_attempt.v1",
        "runtime_implemented": true,
        "route_executes_sql": true,
        "status": "imported",
        "outcome": "apply",
        "opening_import_id": opening_import_id,
        "ledger_entry_id": ledger_entry_id,
        "admin_adjustment_entry_id": ledger_entry_id,
        "audit_id": audit_id,
        "request_summary": opening_balance_import_safe_request_summary(request)?,
        "idempotency": {
            "required": true,
            "result": "applied",
            "raw_key_echoed": false,
        },
        "db_effects": {
            "would_lock_wallet": true,
            "would_read_opening_import": true,
            "would_insert_opening_import": true,
            "would_insert_ledger_entry": true,
            "would_insert_audit": true,
            "would_link_import": true,
            "would_mutate_wallet_snapshot": false,
        },
        "secret_safe": true,
    }))
}

