#[allow(dead_code)]
async fn insert_opening_balance_import_row_tx(
    tx: &mut Transaction<'_, Postgres>,
    request: &OpeningBalanceImportRequest,
    request_summary: Value,
) -> Result<Uuid, AdminError> {
    let row = sqlx::query(
        r#"
        insert into opening_balance_imports (
          tenant_id, project_id, wallet_id, currency, opening_amount,
          external_source, external_reference_id, effective_at, reason,
          actor_id, actor_type, idempotency_key, status, request_summary, metadata
        )
        values ($1, $2, $3, $4, $5::numeric, $6, $7, $8::timestamptz, $9,
                $10, $11, $12, 'imported', $13, $14)
        returning id
        "#,
    )
    .bind(request.tenant_id)
    .bind(request.project_id)
    .bind(request.wallet_id)
    .bind(&request.currency)
    .bind(&request.opening_amount)
    .bind(&request.external_source)
    .bind(&request.external_reference_id)
    .bind(&request.effective_at)
    .bind(&request.reason)
    .bind(request.actor_id)
    .bind(&request.actor_type)
    .bind(&request.idempotency_key)
    .bind(request_summary)
    .bind(opening_balance_import_metadata(request))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.try_get("id")
        .map_err(|error| AdminError::from(DbError::Query(error)))
}

