fn opening_balance_import_existing_matches_request(
    existing: &OpeningBalanceImportRuntimeExistingInput,
    request: &OpeningBalanceImportRequest,
) -> Result<bool, AdminError> {
    Ok(existing.tenant_id == request.tenant_id
        && existing.project_id == request.project_id
        && existing.wallet_id == request.wallet_id
        && existing.currency == request.currency
        && admin_wallet_fixed_money_string(&existing.opening_amount)?
            == admin_wallet_fixed_money_string(&request.opening_amount)?
        && existing.external_source == request.external_source
        && existing.external_reference_id == request.external_reference_id
        && canonical_opening_balance_import_effective_at(&existing.effective_at)
            == canonical_opening_balance_import_effective_at(&request.effective_at)
        && existing.reason == request.reason
        && existing.actor_id == request.actor_id
        && existing.actor_type == request.actor_type
        && existing.idempotency_key == request.idempotency_key)
}

fn canonical_opening_balance_import_effective_at(value: &str) -> String {
    let mut normalized = value.trim().replace('T', " ");
    if let Some(stripped) = normalized.strip_suffix('Z') {
        normalized = format!("{stripped}+00");
    }
    for suffix in ["+00:00", "-00:00"] {
        if let Some(stripped) = normalized.strip_suffix(suffix) {
            normalized = format!("{stripped}+00");
        }
    }
    if let Some((prefix, suffix)) = normalized.split_once('.') {
        if let Some(offset_index) = suffix.find(['+', '-']) {
            normalized = format!("{prefix}{}", &suffix[offset_index..]);
        }
    }
    normalized
}

