fn opening_balance_import_runtime_sql_contract() -> Value {
    json!({
        "schema_version": "opening_balance_import_sql_contract.v1",
        "db_free_contract_only": true,
        "route_executes_sql": false,
        "transaction": {
            "begin_after_admin_rbac": true,
            "commit_after": [
                "opening_balance_imports_insert_or_replay_readback",
                "confirmed_adjust_ledger_entry_insert",
                "audit_log_insert",
                "opening_balance_imports_link_update"
            ],
            "rollback_on": [
                "wallet_missing_or_currency_mismatch",
                "idempotency_conflict",
                "external_reference_conflict",
                "ledger_insert_failure",
                "audit_insert_failure",
                "opening_import_link_update_failure"
            ]
        },
        "statements": {
            "lock_wallet": "select id, tenant_id, project_id, currency, status from wallets where tenant_id = $1 and id = $2 for update",
            "read_by_idempotency": "select id, tenant_id, project_id, wallet_id, currency, opening_amount::text as opening_amount, external_source, external_reference_id, idempotency_key, status, ledger_entry_id, admin_adjustment_entry_id, audit_id, request_summary, metadata from opening_balance_imports where tenant_id = $1 and idempotency_key = $2 for update",
            "read_by_external_reference": "select id, tenant_id, project_id, wallet_id, currency, opening_amount::text as opening_amount, external_source, external_reference_id, idempotency_key, status, ledger_entry_id, admin_adjustment_entry_id, audit_id, request_summary, metadata from opening_balance_imports where tenant_id = $1 and external_source = $2 and external_reference_id = $3 for update",
            "insert_opening_import": "insert into opening_balance_imports (tenant_id, project_id, wallet_id, currency, opening_amount, external_source, external_reference_id, effective_at, reason, actor_id, actor_type, idempotency_key, status, request_summary, metadata) values ($1, $2, $3, $4, $5::numeric, $6, $7, $8::timestamptz, $9, $10, $11, $12, 'imported', $13, $14) returning id",
            "insert_ledger_entry": "insert into ledger_entries (tenant_id, project_id, wallet_id, entry_type, amount, currency, status, idempotency_key, metadata) values ($1, $2, $3, 'adjust', $4::numeric, $5, 'confirmed', $6, $7) returning id",
            "insert_audit_log": "insert into audit_logs (tenant_id, actor_user_id, action, resource_type, resource_id, resource_tenant_id, after_snapshot, metadata) values ($1, $2, 'billing.opening_balance_import', 'opening_balance_import', $3, $1, $4, $5) returning id",
            "link_import": "update opening_balance_imports set ledger_entry_id = $3, admin_adjustment_entry_id = $3, audit_id = $4, updated_at = now() where tenant_id = $1 and id = $2 returning id, ledger_entry_id, admin_adjustment_entry_id, audit_id, status"
        },
        "outcome_contract": {
            "apply": {
                "status": "imported",
                "requires_new_opening_import": true,
                "requires_new_ledger_entry": true,
                "requires_new_audit": true,
                "response_ids_required": ["opening_import_id", "ledger_entry_id", "audit_id"]
            },
            "replay": {
                "status": "replayed",
                "source": "read_by_idempotency",
                "same_body_required": true,
                "writes_new_ledger_or_audit": false
            },
            "idempotency_conflict": {
                "status": "refused",
                "source": "read_by_idempotency",
                "different_body_refused": true,
                "writes_new_ledger": false
            },
            "external_reference_conflict": {
                "status": "refused",
                "source": "read_by_external_reference",
                "different_idempotency_key_refused": true,
                "writes_new_ledger": false
            },
            "wallet_or_currency_refusal": {
                "status": "refused",
                "source": "lock_wallet",
                "writes_new_ledger": false
            }
        },
        "secret_safe": {
            "raw_import_payload_echoed": false,
            "raw_idempotency_material_echoed": false,
            "authorization_or_cookie_echoed": false,
            "db_url_echoed": false,
            "provider_or_virtual_key_echoed": false
        }
    })
}

