async fn insert_ledger_adjustment_entry_tx(
    tx: &mut Transaction<'_, Postgres>,
    operation: LedgerAdjustmentOperation,
    amount: &str,
    currency: &str,
    project_id: Option<Uuid>,
    wallet_id: Option<Uuid>,
    request_id: Option<Uuid>,
    related_ledger_entry_id: Option<Uuid>,
    dedupe_key: &str,
    metadata: Value,
) -> Result<LedgerEntry, AdminError> {
    let row = sqlx::query(
        r#"
        insert into ledger_entries (
          tenant_id, project_id, wallet_id, request_id, related_ledger_entry_id,
          entry_type, amount, currency, status, idempotency_key, metadata
        )
        values ($1, $2, $3, $4, $5, $6, $7::numeric, $8, 'confirmed', $9, $10)
        on conflict (tenant_id, idempotency_key) do nothing
        returning
          id, tenant_id, project_id, wallet_id, request_id, virtual_key_id, trace_id,
          related_ledger_entry_id, entry_type, amount::text as amount, currency, status,
          idempotency_key, price_version_id, usage_snapshot, policy_snapshot, metadata,
          occurred_at::text as occurred_at, created_at::text as created_at
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(project_id)
    .bind(wallet_id)
    .bind(request_id)
    .bind(related_ledger_entry_id)
    .bind(operation.planned_entry_type())
    .bind(amount)
    .bind(currency)
    .bind(dedupe_key)
    .bind(metadata)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    match row {
        Some(row) => {
            ledger_entry_from_row(row).map_err(|error| AdminError::from(DbError::Query(error)))
        }
        None => Err(AdminError::bad_request(
            "ledger adjustment execute request already exists",
        )),
    }
}

async fn insert_admin_audit_log_tx(
    tx: &mut Transaction<'_, Postgres>,
    audit: NewAuditLog,
) -> Result<Uuid, AdminError> {
    let row = sqlx::query(
        r#"
        insert into audit_logs (
          tenant_id, actor_user_id, request_id, action, resource_type, resource_id,
          resource_tenant_id, before_snapshot, after_snapshot, metadata
        )
        values (
          $1,
          (
            select s.user_id
            from user_sessions s
            where s.tenant_id = $1 and s.id = $2
          ),
          $3, $4, $5, $6, $7, $8, $9, $10
        )
        returning id
        "#,
    )
    .bind(audit.tenant_id)
    .bind(audit.actor_session_id)
    .bind(audit.request_id)
    .bind(audit.action)
    .bind(audit.resource_type)
    .bind(audit.resource_id)
    .bind(audit.resource_tenant_id)
    .bind(audit.before_snapshot)
    .bind(audit.after_snapshot)
    .bind(audit.metadata)
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    row.try_get("id")
        .map_err(|error| AdminError::from(DbError::Query(error)))
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct RefundRemainingSummary {
    source_debit_amount: String,
    confirmed_credit_amount: String,
    requested_refund_amount: String,
    remaining_refundable_amount: String,
    currency: String,
    confirmed_credit_count: i64,
}

fn ledger_adjustment_dry_run_response(
    operation: LedgerAdjustmentOperation,
    amount: &str,
    currency: &str,
    project_id: Option<Uuid>,
    wallet_id: Option<Uuid>,
    request_id: Option<Uuid>,
    related_ledger_entry: Option<&LedgerEntry>,
    refund_remaining_summary: Option<&RefundRemainingSummary>,
    reason_provided: bool,
) -> Value {
    let mut response = json!({
        "operation": operation.as_str(),
        "plan_only": true,
        "ledger_write": false,
        "upstream_call": false,
        "request_log_write": false,
        "audit_log_write": false,
        "tenant_id": DEFAULT_TENANT_ID,
        "project_id": project_id,
        "wallet_id": wallet_id,
        "request_id": request_id,
        "related_ledger_entry": related_ledger_entry.map(ledger_adjustment_related_entry_summary),
        "refund_remaining_summary": refund_remaining_summary.map(refund_remaining_summary_response),
        "planned_ledger_entry": {
            "entry_type": operation.planned_entry_type(),
            "amount": amount,
            "currency": currency,
            "status": "planned",
            "related_ledger_entry_id": related_ledger_entry.map(|entry| entry.id),
            "project_id": project_id,
            "wallet_id": wallet_id,
            "request_id": request_id,
            "dedupe_policy": "server_generated_on_execute",
            "metadata_policy": "bounded_admin_adjustment_metadata_only"
        },
        "validation": {
            "amount_checked": true,
            "currency_checked": true,
            "related_ledger_entry_checked": related_ledger_entry.is_some(),
            "refund_remaining_checked": refund_remaining_summary.is_some(),
            "reason_provided": reason_provided,
            "sensitive_material_policy": "rejected_by_schema"
        },
        "future_write_contract": {
            "business_and_success_audit_share_transaction": true,
            "success_audit_only_after_ledger_write": true,
            "audit_insert_failure_rolls_back_ledger_write": true,
            "refusal_does_not_build_success_audit": true,
            "audit_action": operation.future_audit_action(),
            "audit_snapshot_policy": "bounded public ids and amounts only",
            "omitted_material_policy": "no raw request, raw ledger snapshot, raw metadata, or credential material",
            "ledger_write": false,
            "upstream_call": false
        },
        "omitted_material": [
            "dedupe material",
            "ledger snapshots",
            "raw metadata",
            "raw request material",
            "credential material"
        ]
    });
    let readback = ledger_adjustment_execution_readback(
        "dry_run",
        "dry_run",
        None,
        &response,
        None,
        Vec::new(),
    );
    if let Some(object) = response.as_object_mut() {
        object.insert("ledger_adjustment_execution_readback".to_string(), readback);
    }
    response
}

fn ledger_adjustment_execution_readback(
    mode: &'static str,
    outcome: &'static str,
    entry: Option<&LedgerEntry>,
    validated_plan: &Value,
    idempotency_material: Option<&str>,
    blocked_reasons: Vec<&'static str>,
) -> Value {
    let planned_entry = validated_plan.get("planned_ledger_entry");
    let wallet_ref_present = entry.and_then(|entry| entry.wallet_id).is_some()
        || validated_plan
            .get("wallet_id")
            .or_else(|| planned_entry.and_then(|entry| entry.get("wallet_id")))
            .is_some_and(|value| !value.is_null());
    let ledger_entry_ref_present = entry.is_some();
    let request_ref_present = entry.and_then(|entry| entry.request_id).is_some()
        || validated_plan
            .get("request_id")
            .or_else(|| planned_entry.and_then(|entry| entry.get("request_id")))
            .is_some_and(|value| !value.is_null());
    let related_ledger_entry_ref_present = entry
        .and_then(|entry| entry.related_ledger_entry_id)
        .is_some()
        || validated_plan
            .get("related_ledger_entry")
            .is_some_and(|value| !value.is_null())
        || planned_entry
            .and_then(|entry| entry.get("related_ledger_entry_id"))
            .is_some_and(|value| !value.is_null());
    let fingerprint_source = idempotency_material.map(str::to_string).unwrap_or_else(|| {
        format!(
            "ledger-adjustment-readback:v1:{}:{}:{}:{}:{}",
            mode,
            outcome,
            validated_plan
                .get("operation")
                .and_then(Value::as_str)
                .unwrap_or("unknown"),
            validated_plan
                .get("wallet_id")
                .and_then(Value::as_str)
                .unwrap_or("none"),
            validated_plan
                .get("request_id")
                .and_then(Value::as_str)
                .unwrap_or("none")
        )
    });
    let idempotency_fingerprint =
        subscription_scheduler_public_fingerprint(&sha256_hex(&fingerprint_source));
    let safe_next_action = match outcome {
        "dry_run" => "review_plan_then_check_execute_contract_or_execute",
        "applied" => "refresh_wallet_ledger_and_audit_readback",
        "idempotent" => "show_existing_ledger_entry_readback_without_retry_write",
        "refused_preflight" => "fix_blocked_reasons_before_execute",
        "refused_rollback" => "inspect_executor_summary_and_retry_after_review",
        _ => "inspect_safe_response_before_next_action",
    };

    json!({
        "schema": "ledger_adjustment_execution_readback.v1",
        "mode": mode,
        "outcome": outcome,
        "status": match outcome {
            "applied" | "idempotent" => "readback_ready",
            "dry_run" => "plan_only",
            _ => "refused",
        },
        "refs_presence": {
            "wallet_ref_present": wallet_ref_present,
            "credit_grant_ref_present": false,
            "budget_ref_present": false,
            "ledger_entry_ref_present": ledger_entry_ref_present,
            "request_ref_present": request_ref_present,
            "related_ledger_entry_ref_present": related_ledger_entry_ref_present,
            "ref_values_policy": "public_ids_or_presence_only"
        },
        "idempotency": {
            "fingerprint": idempotency_fingerprint,
            "source": "server_generated_dedupe_fingerprint",
            "raw_idempotency_returned": false,
            "raw_idempotency_hash_returned": false
        },
        "blocked_reasons": blocked_reasons,
        "safe_next_action": safe_next_action,
        "secret_safety": {
            "raw_sql_returned": false,
            "wallet_secret_returned": false,
            "authorization_returned": false,
            "provider_key_returned": false,
            "raw_metadata_returned": false,
            "raw_idempotency_returned": false
        }
    })
}

