fn ledger_adjustment_execute_success_response(
    entry: &LedgerEntry,
    audit_log_id: Uuid,
    validated_plan: Value,
    refund_remaining_summary: Option<&RefundRemainingSummary>,
    persistent_cutover_state_readback: Value,
) -> Value {
    let billing_ledger_writer_adapter_boundary =
        ledger_adjustment_billing_ledger_writer_adapter_boundary(&validated_plan, "applied");
    let billing_ledger_writer_shadow_invocation =
        ledger_adjustment_billing_ledger_writer_shadow_invocation(
            &validated_plan,
            "applied",
            false,
        );
    let billing_ledger_writer_cutover_preflight =
        ledger_adjustment_billing_ledger_writer_cutover_preflight_from_runtime_env_provider(
            &validated_plan,
            &LedgerAdjustmentBillingLedgerWriterRuntimeEnvProvider::disabled_default(),
            None,
        );
    let billing_ledger_writer_cutover_preflight =
        ledger_adjustment_billing_ledger_writer_cutover_preflight_with_persistent_readback(
            billing_ledger_writer_cutover_preflight,
            persistent_cutover_state_readback,
        );
    json!({
        "mode": "execute",
        "outcome": "applied",
        "ledger_write": true,
        "audit_log_write": true,
        "request_log_write": false,
        "upstream_call": false,
        "business_and_success_audit_share_transaction": true,
        "success_audit_only_after_ledger_write": true,
        "audit_insert_failure_rolls_back_ledger_write": true,
        "refusal_does_not_build_success_audit": true,
        "dedupe_material_echoed": false,
        "dedupe_public_output": "omitted",
        "ledger_adjustment_execution_readback": ledger_adjustment_execution_readback(
            "execute",
            "applied",
            Some(entry),
            &validated_plan,
            Some(entry.idempotency_key.as_str()),
            Vec::new(),
        ),
        "ledger_executor_summary_contract": ledger_adjustment_executor_summary_contract(),
        "billing_ledger_runtime_writer_mapping_contract": ledger_adjustment_billing_runtime_writer_mapping_contract(),
        "billing_ledger_writer_adapter_boundary": billing_ledger_writer_adapter_boundary,
        "billing_ledger_writer_shadow_invocation": billing_ledger_writer_shadow_invocation,
        "billing_ledger_writer_cutover_preflight": billing_ledger_writer_cutover_preflight,
        "transaction_contract": ledger_adjustment_execute_transaction_contract(true),
        "ledger_entry": ledger_adjustment_executed_entry_response(entry),
        "ledger_executor_summary": ledger_adjustment_executor_summary_for_entry_type(
            entry.entry_type.as_str(),
            "applied",
            true,
            true,
            false,
        ),
        "audit_log_id": audit_log_id,
        "refund_remaining_summary": refund_remaining_summary.map(refund_remaining_summary_response),
        "validated_plan": validated_plan
    })
}

