fn ledger_adjustment_billing_ledger_writer_cutover_preflight_from_config(
    validated_plan: &Value,
    raw_cutover_mode: Option<&str>,
    failure_kind: Option<&'static str>,
) -> Value {
    let (mode, mode_parser_guard) =
        ledger_adjustment_billing_ledger_writer_cutover_mode_parser_guard(raw_cutover_mode);
    let state = mode.as_str();
    let preflight_failed = failure_kind.is_some();
    let source_of_truth = mode.source_of_truth(preflight_failed);
    let billing_ledger_writer_commit_allowed_after_cutover =
        mode == LedgerAdjustmentBillingLedgerWriterCutoverMode::Ready && !preflight_failed;
    let shadow_invocation_enabled = mode.shadow_invocation_enabled();
    let target_operation = ledger_adjustment_billing_runtime_operation_mapping(validated_plan);
    let writer_request = target_operation
        .get("writer_request")
        .cloned()
        .unwrap_or_else(|| {
            json!({
                "variant": "unmapped",
                "operation_key": "bind_only",
                "public_operation_key_output": "omitted"
            })
        });
    let refusal_mapping = failure_kind
        .map(|failure_kind| {
            ledger_adjustment_billing_ledger_writer_adapter_refusal_boundary(
                validated_plan,
                failure_kind,
            )
        })
        .unwrap_or(Value::Null);
    let local_writer_remains_source_of_truth = state != "ready" || preflight_failed;
    let handoff_performance_summary =
        ledger_adjustment_billing_ledger_writer_handoff_performance_summary(
            validated_plan,
            mode,
            failure_kind,
        );

    json!({
        "schema_version": CONTROL_PLANE_BILLING_LEDGER_WRITER_CUTOVER_PREFLIGHT_SCHEMA,
        "source": "control_plane_execute_validated_plan",
        "target": "billing_ledger_runtime_writer_cutover",
        "state": state,
        "db_io_performed": false,
        "production_writer_replaced": false,
        "configuration_summary": {
            "feature_flag": "billing_ledger_writer_cutover",
            "env_var": CONTROL_PLANE_BILLING_LEDGER_WRITER_CUTOVER_MODE_ENV_VAR,
            "allowed_values": ["disabled", "shadow", "ready"],
            "effective_value": state,
            "default_mode": "disabled",
            "normalization_policy": "trim_ascii_whitespace_then_ascii_lowercase",
            "missing_value_policy": "default_disabled",
            "blank_value_policy": "default_disabled",
            "invalid_value_policy": "disabled_guard_refusal",
            "invalid_value_enters_ready": false,
            "env_value_output": "omitted",
            "raw_env_value_echoed": false,
            "secret_value_echoed": false
        },
        "mode_parser_guard": mode_parser_guard,
        "adapter_input": {
            "source_operation": ledger_adjustment_validated_plan_operation(validated_plan),
            "source_entry_type": ledger_adjustment_validated_plan_entry_type(validated_plan),
            "billing_ledger_operation": target_operation
                .get("billing_ledger_operation")
                .cloned()
                .unwrap_or_else(|| json!("unmapped")),
            "writer_request": writer_request,
            "operation_key": {
                "runtime_bind_marker": "operation_key_bind",
                "public_output": "omitted",
                "raw_operation_key_echoed": false
            },
            "metadata": {
                "metadata_policy": "bounded_admin_adjustment_metadata_only",
                "raw_metadata_echoed": false,
                "credential_material_echoed": false
            },
            "dedupe_material_echoed": false
        },
        "source_of_truth": source_of_truth,
        "current_execution_source_of_truth": "control_plane_local_sql_writer",
        "persistent_cutover_state_readback": ledger_adjustment_billing_ledger_writer_persistent_cutover_state_readback_contract(),
        "cutover": {
            "disabled": state == "disabled",
            "shadow": state == "shadow",
            "ready": state == "ready",
            "shadow_invocation_enabled": shadow_invocation_enabled,
            "cutover_allowed": mode == LedgerAdjustmentBillingLedgerWriterCutoverMode::Ready && failure_kind.is_none(),
            "billing_ledger_writer_commit_allowed_after_cutover": billing_ledger_writer_commit_allowed_after_cutover && failure_kind.is_none(),
            "billing_ledger_writer_commit_allowed_in_this_contract": false,
            "local_writer_remains_source_of_truth": local_writer_remains_source_of_truth
        },
        "no_double_write": {
            "dual_commit_allowed": false,
            "local_and_billing_ledger_commit_same_request_allowed": false,
            "active_writer_before_explicit_cutover": "control_plane_local_sql_writer",
            "active_writer_after_ready_cutover": if mode == LedgerAdjustmentBillingLedgerWriterCutoverMode::Ready && failure_kind.is_none() {
                "billing_ledger_runtime_writer"
            } else {
                "control_plane_local_sql_writer"
            },
            "local_sql_writer_commit_allowed_before_cutover": true,
            "local_sql_writer_commit_allowed_after_ready_cutover": !(mode == LedgerAdjustmentBillingLedgerWriterCutoverMode::Ready && failure_kind.is_none()),
            "billing_ledger_writer_commit_allowed_after_ready_cutover": mode == LedgerAdjustmentBillingLedgerWriterCutoverMode::Ready && failure_kind.is_none(),
            "rollback_to_local_before_billing_commit_allowed": true,
            "fallback_after_billing_commit_allowed": false
        },
        "preflight_checks": {
            "adapter_contract_present": true,
            "writer_request_mapping_present": true,
            "shadow_parity_required_before_ready": state == "shadow" || state == "ready",
            "response_summary_shape_preserved": true,
            "audit_summary_shape_preserved": true,
            "failure_refusal_mapping_present": true,
            "raw_env_value_echoed": false,
            "live_db_required_for_this_contract": false
        },
        "rollback_to_local_writer": {
            "on_adapter_unavailable": "refused_preflight",
            "on_sqlx_validation_refusal": "refused_preflight",
            "on_row_count_mismatch": "refused_rollback",
            "summary_shape": BILLING_LEDGER_EXECUTOR_SUMMARY_SCHEMA,
            "operation_key_output": "omitted",
            "error_detail_output": "omitted",
            "raw_executor_error_detail_echoed": false
        },
        "handoff_performance_summary": handoff_performance_summary,
        "refusal_mapping": refusal_mapping,
        "safe_output_contract": {
            "operation_key_output": "omitted",
            "operation_key_bind_only": true,
            "dedupe_material_echoed": false,
            "raw_metadata_echoed": false,
            "credential_material_echoed": false,
            "raw_executor_error_detail_echoed": false
        }
    })
}

fn ledger_adjustment_billing_ledger_writer_cutover_preflight_from_env_config(
    validated_plan: &Value,
    raw_cutover_mode: Option<&str>,
    failure_kind: Option<&'static str>,
) -> Value {
    let mut preflight = ledger_adjustment_billing_ledger_writer_cutover_preflight_from_config(
        validated_plan,
        raw_cutover_mode,
        failure_kind,
    );
    if let Some(preflight) = preflight.as_object_mut() {
        preflight.insert(
            "env_config_summary".to_string(),
            ledger_adjustment_billing_ledger_writer_cutover_env_config_summary(raw_cutover_mode),
        );
    }
    preflight
}

fn ledger_adjustment_billing_ledger_writer_cutover_preflight_from_runtime_env_provider(
    validated_plan: &Value,
    provider: &LedgerAdjustmentBillingLedgerWriterRuntimeEnvProvider,
    failure_kind: Option<&'static str>,
) -> Value {
    let mut preflight = ledger_adjustment_billing_ledger_writer_cutover_preflight_from_env_config(
        validated_plan,
        provider.cutover_mode(),
        failure_kind,
    );
    let runtime_env_provider_preflight =
        ledger_adjustment_billing_ledger_writer_runtime_env_provider_preflight(
            &preflight,
            provider,
            failure_kind,
        );
    if let Some(preflight) = preflight.as_object_mut() {
        preflight.insert(
            "runtime_env_provider_preflight".to_string(),
            runtime_env_provider_preflight,
        );
        preflight.insert(
            "persistent_cutover_state_readback".to_string(),
            ledger_adjustment_billing_ledger_writer_persistent_cutover_state_readback_contract(),
        );
    }
    preflight
}

fn ledger_adjustment_billing_ledger_writer_cutover_preflight_with_persistent_readback(
    mut preflight: Value,
    persistent_cutover_state_readback: Value,
) -> Value {
    let dispatch_decision = persistent_cutover_state_readback
        .get("dispatch_decision")
        .cloned()
        .unwrap_or_else(|| {
            ledger_adjustment_billing_ledger_writer_persistent_cutover_state_unavailable(
                "persistent_cutover_state_dispatch_decision_missing",
                "production",
            )["dispatch_decision"]
                .clone()
        });
    let runtime_writer_dispatch_blocker = dispatch_decision
        .get("runtime_writer_dispatch_blocker")
        .cloned()
        .unwrap_or_else(|| json!("runtime_writer_dispatch_not_enabled"));
    let runtime_writer_dispatch_not_enabled =
        runtime_writer_dispatch_blocker == json!("runtime_writer_dispatch_not_enabled");

    if let Some(preflight) = preflight.as_object_mut() {
        preflight.insert(
            "persistent_cutover_state_readback".to_string(),
            persistent_cutover_state_readback,
        );
        preflight.insert("writer_dispatch_decision".to_string(), dispatch_decision);
        preflight.insert(
            "runtime_writer_dispatch_status".to_string(),
            runtime_writer_dispatch_blocker,
        );
        preflight.insert(
            "runtime_writer_dispatch_not_enabled".to_string(),
            json!(runtime_writer_dispatch_not_enabled),
        );
    }
    preflight
}

fn ledger_adjustment_billing_runtime_writer_mapping(
    validated_plan: &Value,
    outcome: &'static str,
) -> Value {
    let source_operation = ledger_adjustment_validated_plan_operation(validated_plan);
    let source_entry_type = ledger_adjustment_validated_plan_entry_type(validated_plan);
    let response_summary =
        ledger_adjustment_billing_runtime_writer_response_summary(validated_plan, outcome);

    json!({
        "schema_version": CONTROL_PLANE_BILLING_LEDGER_RUNTIME_MAPPING_SCHEMA,
        "source": "control_plane_ledger_adjustment_validated_plan",
        "target": "billing_ledger_runtime_writer",
        "db_io_performed": false,
        "production_writer_replaced": false,
        "source_operation": source_operation,
        "source_entry_type": source_entry_type,
        "target_operation": ledger_adjustment_billing_runtime_operation_mapping(validated_plan),
        "operation_key_mapping": {
            "runtime_bind_marker": "operation_key_bind",
            "public_output": "omitted",
            "dedupe_material_echoed": false
        },
        "metadata_mapping": {
            "metadata_policy": "bounded_admin_adjustment_metadata_only",
            "raw_metadata_echoed": false,
            "credential_material_echoed": false
        },
        "response_summary": response_summary,
        "summary_contract": ledger_adjustment_executor_summary_contract(),
        "safe_output_contract": {
            "operation_key_output": "omitted",
            "dedupe_material_echoed": false,
            "raw_metadata_echoed": false,
            "credential_material_echoed": false,
            "raw_executor_error_detail_echoed": false
        }
    })
}

fn ledger_adjustment_billing_runtime_writer_response_summary(
    validated_plan: &Value,
    outcome: &'static str,
) -> Value {
    let source_entry_type = ledger_adjustment_validated_plan_entry_type(validated_plan);
    match outcome {
        "applied" => ledger_adjustment_executor_summary_for_entry_type(
            source_entry_type.as_str(),
            "applied",
            true,
            true,
            false,
        ),
        "idempotent" => ledger_adjustment_executor_summary_for_entry_type(
            source_entry_type.as_str(),
            "idempotent",
            false,
            true,
            false,
        ),
        "refused_preflight" => ledger_adjustment_executor_refusal_summary(
            source_entry_type.as_str(),
            "refused_preflight",
            false,
            0,
            false,
        ),
        "refused_rollback" => ledger_adjustment_executor_refusal_summary(
            source_entry_type.as_str(),
            "refused_rollback",
            true,
            1,
            true,
        ),
        _ => ledger_adjustment_executor_refusal_summary(
            source_entry_type.as_str(),
            "refused_preflight",
            false,
            0,
            false,
        ),
    }
}

fn ledger_adjustment_billing_runtime_operation_mapping(validated_plan: &Value) -> Value {
    let source_operation = ledger_adjustment_validated_plan_operation(validated_plan);
    let source_entry_type = ledger_adjustment_validated_plan_entry_type(validated_plan);
    let planned_entry = validated_plan
        .get("planned_ledger_entry")
        .and_then(Value::as_object);

    match source_operation.as_str() {
        "refund" => json!({
            "control_plane_operation": source_operation,
            "control_plane_entry_type": source_entry_type,
            "billing_ledger_operation": "refund_partial",
            "billing_ledger_write_request_variant": "ConsistentLedgerWriteRequest::RefundPartial",
            "current_billing_ledger_writer_support": true,
            "writer_request": {
                "variant": "ConsistentLedgerWriteRequest::RefundPartial",
                "operation_id_field": "refund_operation_id",
                "operation_id_source": "server_generated_execute_operation_id_or_existing_replay_entry_id",
                "scope": {
                    "tenant_id": validated_plan.get("tenant_id").is_some(),
                    "project_id": validated_plan.get("project_id").is_some(),
                    "virtual_key_id": "not_available_in_control_plane_adjustment_plan"
                },
                "request_id": validated_plan.get("request_id").is_some(),
                "related_ledger_entry_id": planned_entry
                    .and_then(|entry| entry.get("related_ledger_entry_id"))
                    .is_some_and(|value| !value.is_null()),
                "amount": planned_entry
                    .and_then(|entry| entry.get("amount"))
                    .is_some(),
                "currency": planned_entry
                    .and_then(|entry| entry.get("currency"))
                    .is_some(),
                "operation_key": "bind_only",
                "public_operation_key_output": "omitted"
            },
            "response_summary_operation": "refund",
            "binds": {
                "tenant_id": validated_plan.get("tenant_id").is_some(),
                "project_id": validated_plan.get("project_id").is_some(),
                "wallet_id": validated_plan.get("wallet_id").is_some(),
                "request_id": validated_plan.get("request_id").is_some(),
                "related_ledger_entry_id": planned_entry
                    .and_then(|entry| entry.get("related_ledger_entry_id"))
                    .is_some_and(|value| !value.is_null()),
                "amount": planned_entry
                    .and_then(|entry| entry.get("amount"))
                    .is_some(),
                "currency": planned_entry
                    .and_then(|entry| entry.get("currency"))
                    .is_some(),
                "operation_key_bind": true,
                "metadata": true
            },
            "operation_key_output": "omitted",
            "dedupe_material_echoed": false
        }),
        "adjust" => json!({
            "control_plane_operation": source_operation,
            "control_plane_entry_type": source_entry_type,
            "billing_ledger_operation": "admin_adjustment",
            "billing_ledger_write_request_variant": "ConsistentLedgerWriteRequest::AdminAdjustment",
            "current_billing_ledger_writer_support": true,
            "writer_request": {
                "variant": "ConsistentLedgerWriteRequest::AdminAdjustment",
                "operation_id_field": "adjustment_operation_id",
                "operation_id_source": "server_generated_execute_operation_id_or_existing_replay_entry_id",
                "scope": {
                    "tenant_id": validated_plan.get("tenant_id").is_some(),
                    "project_id": validated_plan.get("project_id").is_some(),
                    "virtual_key_id": "not_available_in_control_plane_adjustment_plan"
                },
                "request_id": validated_plan.get("request_id").is_some(),
                "related_ledger_entry_id": planned_entry
                    .and_then(|entry| entry.get("related_ledger_entry_id"))
                    .is_some_and(|value| !value.is_null()),
                "amount": planned_entry
                    .and_then(|entry| entry.get("amount"))
                    .is_some(),
                "amount_policy": "signed_control_plane_adjust_amount_maps_to_credit_or_debit",
                "currency": planned_entry
                    .and_then(|entry| entry.get("currency"))
                    .is_some(),
                "operation_key": "bind_only",
                "public_operation_key_output": "omitted"
            },
            "response_summary_operation": "adjust",
            "binds": {
                "tenant_id": validated_plan.get("tenant_id").is_some(),
                "project_id": validated_plan.get("project_id").is_some(),
                "wallet_id": validated_plan.get("wallet_id").is_some(),
                "request_id": validated_plan.get("request_id").is_some(),
                "related_ledger_entry_id": planned_entry
                    .and_then(|entry| entry.get("related_ledger_entry_id"))
                    .is_some_and(|value| !value.is_null()),
                "amount": planned_entry
                    .and_then(|entry| entry.get("amount"))
                    .is_some(),
                "currency": planned_entry
                    .and_then(|entry| entry.get("currency"))
                    .is_some(),
                "operation_key_bind": true,
                "metadata": true
            },
            "operation_key_output": "omitted",
            "dedupe_material_echoed": false
        }),
        _ => json!({
            "control_plane_operation": source_operation,
            "control_plane_entry_type": source_entry_type,
            "billing_ledger_operation": "unmapped",
            "billing_ledger_write_request_variant": "unmapped",
            "current_billing_ledger_writer_support": false,
            "operation_key_output": "omitted",
            "dedupe_material_echoed": false
        }),
    }
}

fn ledger_adjustment_validated_plan_operation(validated_plan: &Value) -> String {
    validated_plan
        .get("operation")
        .and_then(Value::as_str)
        .unwrap_or("unknown")
        .to_string()
}

fn ledger_adjustment_validated_plan_entry_type(validated_plan: &Value) -> String {
    validated_plan
        .get("planned_ledger_entry")
        .and_then(|entry| entry.get("entry_type"))
        .and_then(Value::as_str)
        .or_else(|| validated_plan.get("operation").and_then(Value::as_str))
        .unwrap_or("unknown")
        .to_string()
}

fn ledger_adjustment_execute_transaction_contract(write_performed: bool) -> Value {
    json!({
        "writer": "control_plane_transactional_admin_ledger_adjustment_writer",
        "write_performed": write_performed,
        "isolation": "read_committed_or_stronger",
        "begin_before_locking": true,
        "commit_only_after_ledger_and_success_audit": write_performed,
        "rollback_on_ledger_write_failure": true,
        "rollback_on_audit_insert_failure": true,
        "rollback_on_refund_remaining_change": true,
        "bounded_lock_order": [
            "source_ledger_entry_for_update",
            "same_source_confirmed_credit_entries_for_update",
            "wallet_for_update",
            "dedupe_reservation_for_update",
            "ledger_insert",
            "success_audit_insert"
        ],
        "bounded_by": [
            "tenant_id",
            "related_ledger_entry_id",
            "currency",
            "request_id",
            "wallet_id",
            "server_generated_dedupe_material"
        ],
        "dedupe_material_echoed": false,
        "unbounded_scan_allowed": false,
        "rollback_executor_summary_contract": ledger_adjustment_executor_rollback_summary_contract()
    })
}

fn ledger_adjustment_executed_entry_response(entry: &LedgerEntry) -> Value {
    json!({
        "id": entry.id,
        "tenant_id": entry.tenant_id,
        "project_id": entry.project_id,
        "wallet_id": entry.wallet_id,
        "request_id": entry.request_id,
        "related_ledger_entry_id": entry.related_ledger_entry_id,
        "entry_type": entry.entry_type,
        "amount": entry.amount,
        "currency": entry.currency,
        "status": entry.status,
        "omitted_material": [
            "dedupe material",
            "ledger snapshots",
            "raw metadata"
        ]
    })
}

fn ledger_adjustment_execute_dedupe_key(
    operation: LedgerAdjustmentOperation,
    amount: &str,
    currency: &str,
    project_id: Option<Uuid>,
    wallet_id: Option<Uuid>,
    request_id: Option<Uuid>,
    related_ledger_entry_id: Option<Uuid>,
) -> String {
    format!(
        "admin-ledger-adjustment:v1:{}:{amount}:{currency}:project:{}:wallet:{}:request:{}:related:{}",
        operation.as_str(),
        optional_uuid_dedupe_part(project_id),
        optional_uuid_dedupe_part(wallet_id),
        optional_uuid_dedupe_part(request_id),
        optional_uuid_dedupe_part(related_ledger_entry_id),
    )
}

fn optional_uuid_dedupe_part(value: Option<Uuid>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "none".to_string())
}

fn ledger_adjustment_execute_metadata(
    operation: LedgerAdjustmentOperation,
    reason_provided: bool,
    related_ledger_entry_id: Option<Uuid>,
    request_id: Option<Uuid>,
) -> Value {
    json!({
        "source": "admin_ledger_adjustment_execute",
        "operation": operation.as_str(),
        "reason_provided": reason_provided,
        "request_id": request_id,
        "related_ledger_entry_id": related_ledger_entry_id,
        "dedupe_policy": "server_generated_not_echoed",
        "metadata_policy": "bounded_admin_adjustment_metadata_only",
        "sensitive_material_policy": "reason_value_not_echoed"
    })
}

fn ledger_adjustment_success_audit_metadata(
    operation: LedgerAdjustmentOperation,
    refund_remaining_summary: Option<&RefundRemainingSummary>,
    reason_provided: bool,
) -> Value {
    let ledger_executor_summary = ledger_adjustment_executor_summary_for_entry_type(
        operation.planned_entry_type(),
        "applied",
        true,
        true,
        false,
    );
    json!({
        "transactional_audit": true,
        "ledger_adjustment_execute": true,
        "operation": operation.as_str(),
        "reason_provided": reason_provided,
        "dedupe_material_echoed": false,
        "dedupe_public_output": "omitted",
        "ledger_executor_summary_contract": ledger_adjustment_executor_summary_contract(),
        "ledger_executor_summary": ledger_executor_summary.clone(),
        "billing_ledger_writer_adapter_boundary_contract": ledger_adjustment_billing_ledger_writer_adapter_boundary_contract(),
        "billing_ledger_writer_adapter_audit_summary": ledger_executor_summary.clone(),
        "billing_ledger_writer_adapter_audit_summary_source": "response_ledger_executor_summary",
        "billing_ledger_writer_shadow_invocation_contract": ledger_adjustment_billing_ledger_writer_shadow_invocation_contract(),
        "billing_ledger_writer_shadow_audit_parity_summary": {
            "schema_version": CONTROL_PLANE_BILLING_LEDGER_WRITER_SHADOW_INVOCATION_SCHEMA,
            "shadow_enabled": false,
            "status": "shadow_disabled_not_compared",
            "source_of_truth": "control_plane_local_sql_writer",
            "success_audit_write": true,
            "local_audit_executor_summary": ledger_executor_summary,
            "shadow_audit_executor_summary": null,
            "billing_ledger_shadow_audit_write_allowed": false,
            "billing_ledger_shadow_transaction_commit_allowed": false,
            "dual_commit_allowed": false,
            "operation_key_output": "omitted",
            "error_detail_output": "omitted"
        },
        "success_audit_same_transaction": true,
        "audit_insert_failure_rolls_back_ledger_write": true,
        "refund_remaining_recomputed_after_locks": refund_remaining_summary.is_some(),
        "refund_remaining_summary": refund_remaining_summary.map(refund_remaining_summary_response),
        "sensitive_material_policy": "no raw request, raw metadata, payload, authorization, credential, or dedupe key"
    })
}

fn ledger_entry_from_row(row: PgRow) -> Result<LedgerEntry, sqlx::Error> {
    Ok(LedgerEntry {
        id: row.try_get("id")?,
        tenant_id: row.try_get("tenant_id")?,
        project_id: row.try_get("project_id")?,
        wallet_id: row.try_get("wallet_id")?,
        request_id: row.try_get("request_id")?,
        virtual_key_id: row.try_get("virtual_key_id")?,
        trace_id: row.try_get("trace_id")?,
        related_ledger_entry_id: row.try_get("related_ledger_entry_id")?,
        entry_type: row.try_get("entry_type")?,
        amount: row.try_get("amount")?,
        currency: row.try_get("currency")?,
        status: row.try_get("status")?,
        idempotency_key: row.try_get("idempotency_key")?,
        price_version_id: row.try_get("price_version_id")?,
        usage_snapshot: row.try_get("usage_snapshot")?,
        policy_snapshot: row.try_get("policy_snapshot")?,
        metadata: row.try_get("metadata")?,
        occurred_at: row.try_get("occurred_at")?,
        created_at: row.try_get("created_at")?,
    })
}

fn ledger_summary_response(entries: &[LedgerEntry], limit: i64) -> Value {
    let currencies = entries
        .iter()
        .map(|entry| health_summary_string(&entry.currency))
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let request_ids = entries
        .iter()
        .filter_map(|entry| entry.request_id)
        .collect::<BTreeSet<_>>();

    json!({
        "limit": limit,
        "limit_reached": entries.len() as i64 == limit,
        "returned_count": entries.len(),
        "request_count": request_ids.len(),
        "currencies": currencies,
        "omitted_fields": [
            "idempotency_key",
            "usage_snapshot",
            "policy_snapshot",
            "metadata"
        ],
        "entries": entries
            .iter()
            .map(ledger_entry_summary_response)
            .collect::<Vec<_>>(),
    })
}

fn ledger_entry_summary_response(entry: &LedgerEntry) -> Value {
    json!({
        "id": entry.id,
        "project_id": entry.project_id,
        "wallet_id": entry.wallet_id,
        "request_id": entry.request_id,
        "virtual_key_id": entry.virtual_key_id,
        "trace_id": entry.trace_id.as_ref().map(|trace_id| redact_secrets(trace_id)),
        "related_ledger_entry_id": entry.related_ledger_entry_id,
        "price_version_id": entry.price_version_id,
        "entry_type": health_summary_string(&entry.entry_type),
        "amount": health_summary_string(&entry.amount),
        "currency": health_summary_string(&entry.currency),
        "status": health_summary_string(&entry.status),
        "balance": ledger_entry_balance_summary(entry),
        "refs": ledger_entry_safe_refs(entry),
        "occurred_at": health_summary_string(&entry.occurred_at),
        "created_at": health_summary_string(&entry.created_at),
    })
}

fn ledger_entry_balance_summary(entry: &LedgerEntry) -> Value {
    let reason = if entry.wallet_id.is_some() {
        "historical wallet balance snapshots are not stored on ledger_entries"
    } else {
        "ledger entry is not linked to a wallet"
    };
    let status = if entry.wallet_id.is_some() {
        "config-needed"
    } else {
        "no-ledger"
    };

    json!({
        "before": Value::Null,
        "after": Value::Null,
        "currency": health_summary_string(&entry.currency),
        "status": status,
        "source": "ledger_entry_summary.v1",
        "reason": reason,
    })
}

fn ledger_entry_safe_refs(entry: &LedgerEntry) -> Value {
    json!({
        "ledger_entry_id": entry.id,
        "wallet_id": entry.wallet_id,
        "project_id": entry.project_id,
        "request_id": entry.request_id,
        "virtual_key_id": entry.virtual_key_id,
        "trace_id": entry.trace_id.as_ref().map(|trace_id| redact_secrets(trace_id)),
        "related_ledger_entry_id": entry.related_ledger_entry_id,
        "price_version_id": entry.price_version_id,
        "credit_grant_id": ledger_metadata_uuid(&entry.metadata, &["credit_grant_id"]),
        "voucher_id": ledger_metadata_uuid(&entry.metadata, &["voucher_id"]),
        "voucher_redemption_id": ledger_metadata_uuid(&entry.metadata, &["voucher_redemption_id", "redemption_id"]),
        "order_id": ledger_metadata_uuid(&entry.metadata, &["order_id", "payment_order_id"]),
        "payment_intent_id": ledger_metadata_uuid(&entry.metadata, &["payment_intent_id"]),
        "payment_capture_id": ledger_metadata_uuid(&entry.metadata, &["payment_capture_id"]),
        "invoice_id": ledger_metadata_uuid(&entry.metadata, &["invoice_id"]),
        "refund_id": ledger_metadata_uuid(&entry.metadata, &["refund_id"]),
        "ref_source": "ledger_entry_columns_and_safe_metadata_refs",
    })
}

fn ledger_metadata_uuid(metadata: &Value, keys: &[&str]) -> Option<Uuid> {
    keys.iter().find_map(|key| {
        metadata
            .get(*key)
            .and_then(Value::as_str)
            .and_then(|value| Uuid::parse_str(value).ok())
    })
}

fn billing_safe_json_value(value: Value) -> Value {
    match value {
        Value::Object(object) => Value::Object(
            object
                .into_iter()
                .map(|(key, value)| {
                    if is_sensitive_billing_json_key(&key) {
                        (key, Value::String("[REDACTED]".to_string()))
                    } else {
                        (key, billing_safe_json_value(value))
                    }
                })
                .collect(),
        ),
        Value::Array(values) => {
            Value::Array(values.into_iter().map(billing_safe_json_value).collect())
        }
        Value::String(value) => Value::String(redact_secrets(&value)),
        value => value,
    }
}

fn subscription_plan_select_sql(where_clause: &str, suffix: &str) -> String {
    format!(
        r#"
        select id, tenant_id, plan_code, display_name, status, currency, billing_interval,
               unit_price::text as unit_price,
               included_credit_amount::text as included_credit_amount,
               trial_days, request_summary, metadata,
               created_at::text as created_at, updated_at::text as updated_at
        from subscription_plans
        {where_clause}
        {suffix}
        "#
    )
}

