fn normalize_subscription_scheduler_mode(mode: Option<String>) -> Result<String, AdminError> {
    match mode
        .unwrap_or_else(|| "dry_run".to_string())
        .trim()
        .to_ascii_lowercase()
        .as_str()
    {
        "dry_run" | "dry-run" | "plan" => Ok("dry_run".to_string()),
        "apply" => Ok("apply".to_string()),
        _ => Err(AdminError::bad_request("mode must be dry_run or apply")),
    }
}

fn normalize_subscription_scheduler_execute_mode(
    mode: Option<String>,
) -> Result<String, AdminError> {
    match mode
        .unwrap_or_else(|| "dry_run".to_string())
        .trim()
        .to_ascii_lowercase()
        .as_str()
    {
        "dry_run" | "dry-run" | "plan" => Ok("dry_run".to_string()),
        "apply" | "applied" => Ok("apply".to_string()),
        "refuse" | "refused" => Ok("refuse".to_string()),
        "replay" | "replayed" => Ok("replay".to_string()),
        _ => Err(AdminError::bad_request(
            "mode must be dry_run, apply, refuse, or replay",
        )),
    }
}

fn subscription_scheduler_execute_target_status(mode: &str) -> &'static str {
    match mode {
        "apply" => "applied",
        "refuse" => "refused",
        "replay" => "replayed",
        _ => "scheduled",
    }
}

