async fn subscription_scheduler_upsert_supervisor_run(
    db: &PgPool,
    tenant_id: Uuid,
    worker_id: &str,
    mode: &str,
    event_status_filter: &[String],
    event_type_filter: &[String],
    next_run_at: Option<&str>,
    processed_count: usize,
    skipped_count: usize,
    blocked_count: usize,
    worker_status: &str,
) -> Result<Value, AdminError> {
    let run_summary = json!({
        "schema": "admin_subscription_scheduler_supervisor_run_summary.v1",
        "mode": mode,
        "processed_count": processed_count,
        "skipped_count": skipped_count,
        "blocked_count": blocked_count,
        "next_run_at": next_run_at,
        "event_status_filter": event_status_filter,
        "event_type_filter": event_type_filter,
        "bounded_runner_endpoint": "/admin/subscriptions/run-due-scheduler-events",
        "background_process_started": false
    });
    let row = sqlx::query(
        r#"
        insert into subscription_scheduler_worker_supervisors (
            tenant_id, worker_id, worker_status, lease_heartbeat_at, last_run_at,
            next_run_at, processed_count, skipped_count, blocked_count, last_mode,
            last_event_status_filter, last_event_type_filter, last_run_summary, metadata
        )
        values (
            $1, $2, $3, now(), now(), $4::timestamptz,
            $5, $6, $7, $8, $9, $10, $11,
            jsonb_build_object(
                'schema', 'admin_subscription_scheduler_supervisor_metadata.v1',
                'durable_state', true,
                'external_worker_loop_supported', true,
                'background_process_started', false
            )
        )
        on conflict (tenant_id, worker_id) do update
        set worker_status = excluded.worker_status,
            lease_heartbeat_at = now(),
            last_run_at = now(),
            next_run_at = excluded.next_run_at,
            processed_count = subscription_scheduler_worker_supervisors.processed_count + excluded.processed_count,
            skipped_count = subscription_scheduler_worker_supervisors.skipped_count + excluded.skipped_count,
            blocked_count = subscription_scheduler_worker_supervisors.blocked_count + excluded.blocked_count,
            last_mode = excluded.last_mode,
            last_event_status_filter = excluded.last_event_status_filter,
            last_event_type_filter = excluded.last_event_type_filter,
            last_run_summary = excluded.last_run_summary,
            metadata = subscription_scheduler_worker_supervisors.metadata || excluded.metadata,
            updated_at = now()
        returning worker_id,
                  worker_status,
                  lease_heartbeat_at::text as lease_heartbeat_at,
                  last_run_at::text as last_run_at,
                  next_run_at::text as next_run_at,
                  processed_count,
                  skipped_count,
                  blocked_count,
                  last_mode,
                  last_event_status_filter,
                  last_event_type_filter,
                  last_run_summary,
                  updated_at::text as updated_at
        "#,
    )
    .bind(tenant_id)
    .bind(worker_id)
    .bind(worker_status)
    .bind(next_run_at.map(str::to_string))
    .bind(processed_count as i64)
    .bind(skipped_count as i64)
    .bind(blocked_count as i64)
    .bind(mode)
    .bind(event_status_filter)
    .bind(event_type_filter)
    .bind(run_summary)
    .fetch_one(db)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    subscription_scheduler_supervisor_row_response(&row, true)
}

async fn subscription_scheduler_supervisor_readback(
    db: &PgPool,
    tenant_id: Uuid,
    worker_id: Option<&str>,
    _next_run_at: Option<&str>,
) -> Result<Value, AdminError> {
    if let Some(worker_id) = worker_id {
        let row = sqlx::query(
            r#"
            select worker_id,
                   worker_status,
                   lease_heartbeat_at::text as lease_heartbeat_at,
                   last_run_at::text as last_run_at,
                   next_run_at::text as next_run_at,
                   processed_count,
                   skipped_count,
                   blocked_count,
                   last_mode,
                   last_event_status_filter,
                   last_event_type_filter,
                   last_run_summary,
                   updated_at::text as updated_at
            from subscription_scheduler_worker_supervisors
            where tenant_id = $1 and worker_id = $2
            "#,
        )
        .bind(tenant_id)
        .bind(worker_id)
        .fetch_optional(db)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        return match row {
            Some(row) => subscription_scheduler_supervisor_row_response(&row, true),
            None => Ok(json!({
                "schema": "admin_subscription_scheduler_supervisor_state.v1",
                "state_available": false,
                "worker_id": redact_secrets(worker_id),
                "status": "not_initialized",
                "durable_state_table": "subscription_scheduler_worker_supervisors",
                "external_worker_loop_supported": true,
                "background_process_started": false
            })),
        };
    }

    let rows = sqlx::query(
        r#"
        select worker_id,
               worker_status,
               lease_heartbeat_at::text as lease_heartbeat_at,
               last_run_at::text as last_run_at,
               next_run_at::text as next_run_at,
               processed_count,
               skipped_count,
               blocked_count,
               last_mode,
               last_event_status_filter,
               last_event_type_filter,
               last_run_summary,
               updated_at::text as updated_at
        from subscription_scheduler_worker_supervisors
        where tenant_id = $1
        order by updated_at desc
        limit 5
        "#,
    )
    .bind(tenant_id)
    .fetch_all(db)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let mut workers = Vec::new();
    for row in rows {
        workers.push(subscription_scheduler_supervisor_row_response(&row, false)?);
    }

    Ok(json!({
        "schema": "admin_subscription_scheduler_supervisor_state.v1",
        "state_available": !workers.is_empty(),
        "status": if workers.is_empty() { "not_initialized" } else { "recent_workers_available" },
        "durable_state_table": "subscription_scheduler_worker_supervisors",
        "latest_workers": workers,
        "external_worker_loop_supported": true,
        "background_process_started": false
    }))
}

fn subscription_scheduler_supervisor_row_response(
    row: &PgRow,
    include_detail: bool,
) -> Result<Value, AdminError> {
    let worker_id: String = row.try_get("worker_id").map_err(db_row_error)?;
    let worker_status: String = row.try_get("worker_status").map_err(db_row_error)?;
    let lease_heartbeat_at: Option<String> =
        row.try_get("lease_heartbeat_at").map_err(db_row_error)?;
    let last_run_at: Option<String> = row.try_get("last_run_at").map_err(db_row_error)?;
    let next_run_at: Option<String> = row.try_get("next_run_at").map_err(db_row_error)?;
    let processed_count: i64 = row.try_get("processed_count").map_err(db_row_error)?;
    let skipped_count: i64 = row.try_get("skipped_count").map_err(db_row_error)?;
    let blocked_count: i64 = row.try_get("blocked_count").map_err(db_row_error)?;
    let last_mode: Option<String> = row.try_get("last_mode").map_err(db_row_error)?;
    let last_event_status_filter: Vec<String> = row
        .try_get("last_event_status_filter")
        .map_err(db_row_error)?;
    let last_event_type_filter: Vec<String> = row
        .try_get("last_event_type_filter")
        .map_err(db_row_error)?;
    let last_run_summary: Value = row.try_get("last_run_summary").map_err(db_row_error)?;
    let updated_at: String = row.try_get("updated_at").map_err(db_row_error)?;

    let mut response = json!({
        "schema": "admin_subscription_scheduler_supervisor_state.v1",
        "state_available": true,
        "worker_id": redact_secrets(&worker_id),
        "status": worker_status,
        "lease_heartbeat_at": lease_heartbeat_at,
        "last_run_at": last_run_at,
        "next_run_at": next_run_at,
        "processed_count": processed_count,
        "skipped_count": skipped_count,
        "blocked_count": blocked_count,
        "last_mode": last_mode,
        "last_event_status_filter": last_event_status_filter,
        "last_event_type_filter": last_event_type_filter,
        "updated_at": updated_at,
        "durable_state_table": "subscription_scheduler_worker_supervisors",
        "external_worker_loop_supported": true,
        "background_process_started": false,
        "secret_safe": true,
        "raw_payment_payload_returned": false,
        "raw_provider_payload_returned": false,
        "authorization_returned": false,
        "raw_idempotency_key_echoed": false
    });
    if include_detail {
        response["last_run_summary"] = last_run_summary;
    }
    Ok(response)
}

async fn apply_subscription_scheduler_local_execution(
    pool: &PgPool,
    tenant_id: Uuid,
    event_id: Uuid,
    mode: &str,
    reason: &str,
    worker_id: &str,
) -> Result<Value, AdminError> {
    let mut tx = pool
        .begin()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let row = sqlx::query(
        r#"
        select e.id,
               e.subscription_id,
               e.event_type,
               e.event_status,
               e.effective_at::text as effective_at,
               e.idempotency_key_hash,
               e.credit_grant_id,
               e.ledger_entry_id,
               e.invoice_id,
               e.order_id,
               e.audit_id,
               e.refusal_code,
               e.request_summary,
               e.metadata,
               e.updated_at::text as updated_at,
               s.project_id,
               s.wallet_id,
               s.plan_id,
               s.status as subscription_status,
               s.current_period_start::text as current_period_start,
               s.current_period_end::text as current_period_end,
               p.plan_code,
               p.billing_interval,
               p.currency,
               p.unit_price::text as unit_price,
               p.included_credit_amount::text as included_credit_amount
        from subscription_events_or_schedules e
        join subscriptions s on s.tenant_id = e.tenant_id and s.id = e.subscription_id
        join subscription_plans p on p.tenant_id = s.tenant_id and p.id = s.plan_id
        where e.tenant_id = $1
          and e.id = $2
        for update of e, s
        "#,
    )
    .bind(tenant_id)
    .bind(event_id)
    .fetch_optional(&mut *tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?
    .ok_or_else(|| AdminError::not_found("subscription scheduler event"))?;

    let before_status: String = row.try_get("event_status").map_err(db_row_error)?;
    let event_type: String = row.try_get("event_type").map_err(db_row_error)?;
    let claimable = before_status == "scheduled" || before_status == "replayed";
    if !claimable {
        let readback = json!({
            "status": "idempotent_noop",
            "event_mutated": false,
            "event_status": before_status,
            "event_updated_at": row.try_get::<String, _>("updated_at").map_err(db_row_error)?,
            "mode": mode,
            "execution_plan_readback": plan_subscription_scheduler_execution(&event_type, mode, &before_status),
            "runtime_implemented": true,
            "payment_capture_executed": false,
            "payment_status": "not_attempted_already_terminal",
            "subscription_rows_updated": 0,
            "ledger_or_credit_readback": {
                "status": "read_back_existing_refs",
                "credit_grant_id": row.try_get::<Option<Uuid>, _>("credit_grant_id").map_err(db_row_error)?,
                "ledger_entry_id": row.try_get::<Option<Uuid>, _>("ledger_entry_id").map_err(db_row_error)?
            },
            "invoice_order_readback": subscription_scheduler_invoice_order_readback_tx(&mut tx, tenant_id, &row).await?,
            "dunning_retry_readback": subscription_scheduler_dunning_retry_existing_readback(&row)?,
            "proration_delta_readback": subscription_scheduler_proration_delta_existing_readback(&row)?,
            "negative_proration_readback": subscription_scheduler_negative_proration_existing_readback(&row)?,
            "refs": {
                "credit_grant_id": row.try_get::<Option<Uuid>, _>("credit_grant_id").map_err(db_row_error)?,
                "ledger_entry_id": row.try_get::<Option<Uuid>, _>("ledger_entry_id").map_err(db_row_error)?,
                "invoice_id": row.try_get::<Option<Uuid>, _>("invoice_id").map_err(db_row_error)?,
                "order_id": row.try_get::<Option<Uuid>, _>("order_id").map_err(db_row_error)?,
                "audit_id": row.try_get::<Option<Uuid>, _>("audit_id").map_err(db_row_error)?
            },
            "writes_limited_to": [],
            "executor_steps": subscription_scheduler_local_executor_steps(&event_type, false, false, false, false)
        });
        tx.commit()
            .await
            .map_err(|error| AdminError::from(DbError::Query(error)))?;
        return Ok(readback);
    }

    let target_status = subscription_scheduler_execute_target_status(mode);
    let mut credit_grant_id: Option<Uuid> = row.try_get("credit_grant_id").map_err(db_row_error)?;
    let mut ledger_entry_id: Option<Uuid> = row.try_get("ledger_entry_id").map_err(db_row_error)?;
    let mut invoice_id: Option<Uuid> = row.try_get("invoice_id").map_err(db_row_error)?;
    let mut order_id: Option<Uuid> = row.try_get("order_id").map_err(db_row_error)?;
    let mut subscription_rows_updated: u64 = 0;
    let mut local_status = match mode {
        "apply" => "local_execution_applied",
        "refuse" => "refused",
        "replay" => "replayed",
        _ => "status_recorded",
    };
    let mut local_detail = json!({
        "status": local_status,
        "payment_status": "not_applicable",
        "subscription_mutation": "not_applicable"
    });
    let mut invoice_order_readback = json!({
        "status": "not_applicable",
        "payment_capture_executed": false,
        "payment_status": "not_applicable"
    });
    let mut dunning_retry_readback =
        subscription_scheduler_dunning_retry_dry_run_readback(&event_type);
    let mut proration_delta_readback =
        subscription_scheduler_proration_delta_dry_run_readback(&event_type);
    let mut negative_proration_readback =
        subscription_scheduler_negative_proration_dry_run_readback(&event_type);

    if mode == "apply" {
        match event_type.as_str() {
            "renew" => {
                let result = apply_subscription_renewal_local_settlement_tx(
                    &mut tx,
                    tenant_id,
                    &row,
                    credit_grant_id,
                    ledger_entry_id,
                )
                .await?;
                credit_grant_id = result.credit_grant_id;
                ledger_entry_id = result.ledger_entry_id;
                invoice_order_readback = result.invoice_order_readback;
                invoice_id = invoice_order_readback
                    .get("invoice_id")
                    .and_then(Value::as_str)
                    .and_then(|value| Uuid::parse_str(value).ok())
                    .or(invoice_id);
                order_id = invoice_order_readback
                    .get("order_id")
                    .and_then(Value::as_str)
                    .and_then(|value| Uuid::parse_str(value).ok())
                    .or(order_id);
                subscription_rows_updated = result.subscription_rows_updated;
                local_status = "local_settlement_recorded";
                local_detail = result.readback;
            }
            "payment_failed" | "dunning" | "expire" => {
                let result =
                    apply_subscription_status_local_mutation_tx(&mut tx, tenant_id, &row).await?;
                subscription_rows_updated = result.subscription_rows_updated;
                invoice_order_readback = result.invoice_order_readback;
                dunning_retry_readback = result.dunning_retry_readback;
                proration_delta_readback = result.proration_delta_readback;
                local_status = result.status;
                local_detail = result.readback;
            }
            "prorate" => {
                let result =
                    apply_subscription_proration_local_mutation_tx(&mut tx, tenant_id, &row)
                        .await?;
                subscription_rows_updated = result.subscription_rows_updated;
                invoice_order_readback = result.invoice_order_readback;
                proration_delta_readback = result.proration_delta_readback;
                negative_proration_readback = result.negative_proration_readback;
                credit_grant_id = result.credit_grant_id.or(credit_grant_id);
                ledger_entry_id = result.ledger_entry_id.or(ledger_entry_id);
                invoice_id = invoice_order_readback
                    .get("invoice_id")
                    .and_then(Value::as_str)
                    .and_then(|value| Uuid::parse_str(value).ok())
                    .or(invoice_id);
                order_id = invoice_order_readback
                    .get("order_id")
                    .and_then(Value::as_str)
                    .and_then(|value| Uuid::parse_str(value).ok())
                    .or(order_id);
                local_status = result.status;
                local_detail = result.readback;
            }
            _ => {
                local_status = "event_status_recorded";
                local_detail = json!({
                    "status": "event_type_has_no_local_mutation",
                    "event_type": event_type
                });
            }
        }
    }

    let metadata_patch = subscription_scheduler_execute_metadata_patch(
        mode,
        reason,
        &before_status,
        target_status,
        worker_id,
    );
    let local_patch = json!({
        "local_execution": {
            "schema": "admin_subscription_scheduler_local_execution.v1",
            "status": local_status,
            "execution_plan_readback": plan_subscription_scheduler_execution(&event_type, mode, &before_status),
            "runtime_implemented": true,
            "payment_capture_executed": false,
            "payment_status": if event_type == "renew" { "payment_provider_capture_required" } else { "not_applicable" },
            "subscription_rows_updated": subscription_rows_updated,
            "credit_grant_id": credit_grant_id,
            "ledger_entry_id": ledger_entry_id,
            "invoice_id": invoice_id,
            "order_id": order_id,
            "invoice_order_readback": invoice_order_readback.clone(),
            "dunning_retry_readback": dunning_retry_readback.clone(),
            "proration_delta_readback": proration_delta_readback.clone(),
            "negative_proration_readback": negative_proration_readback.clone(),
            "secret_safe": true
        }
    });
    let updated = sqlx::query(
        r#"
        update subscription_events_or_schedules
        set event_status = $3,
            refusal_code = case when $3 = 'refused' then coalesce(refusal_code, 'admin_subscription_scheduler_refused') else refusal_code end,
            credit_grant_id = coalesce(credit_grant_id, $4),
            ledger_entry_id = coalesce(ledger_entry_id, $5),
            invoice_id = coalesce(invoice_id, $6),
            order_id = coalesce(order_id, $7),
            metadata = metadata || $8::jsonb || $9::jsonb,
            updated_at = now()
        where tenant_id = $1
          and id = $2
          and event_status in ('scheduled', 'replayed')
        returning event_status, updated_at::text as updated_at,
                  credit_grant_id, ledger_entry_id, invoice_id, order_id, audit_id
        "#,
    )
    .bind(tenant_id)
    .bind(event_id)
    .bind(target_status)
    .bind(credit_grant_id)
    .bind(ledger_entry_id)
    .bind(invoice_id)
    .bind(order_id)
    .bind(metadata_patch)
    .bind(local_patch)
    .fetch_optional(&mut *tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let Some(updated) = updated else {
        tx.commit()
            .await
            .map_err(|error| AdminError::from(DbError::Query(error)))?;
        return Ok(json!({
            "status": "idempotent_noop",
            "event_mutated": false,
            "event_status": before_status,
            "mode": mode,
            "execution_plan_readback": plan_subscription_scheduler_execution(&event_type, mode, &before_status),
            "runtime_implemented": true,
            "payment_capture_executed": false,
            "subscription_rows_updated": 0,
            "ledger_or_credit_readback": {"status": "event_status_changed_before_update"},
            "invoice_order_readback": {"status": "event_status_changed_before_update", "payment_capture_executed": false},
            "dunning_retry_readback": {"status": "event_status_changed_before_update", "payment_capture_executed": false},
            "proration_delta_readback": {"status": "event_status_changed_before_update", "payment_capture_executed": false},
            "negative_proration_readback": {"status": "event_status_changed_before_update", "payment_capture_executed": false, "refund_executed": false},
            "refs": {},
            "writes_limited_to": [],
            "executor_steps": subscription_scheduler_local_executor_steps(&event_type, false, false, false, false)
        }));
    };

    let readback = json!({
        "status": local_status,
        "event_mutated": true,
        "event_status": updated.try_get::<String, _>("event_status").map_err(db_row_error)?,
        "event_updated_at": updated.try_get::<String, _>("updated_at").map_err(db_row_error)?,
        "mode": mode,
        "execution_plan_readback": plan_subscription_scheduler_execution(&event_type, mode, &before_status),
        "runtime_implemented": true,
        "payment_capture_executed": false,
        "payment_status": if event_type == "renew" { "payment_provider_capture_required" } else { "not_applicable" },
        "subscription_rows_updated": subscription_rows_updated,
        "ledger_or_credit_readback": {
            "status": if credit_grant_id.is_some() || ledger_entry_id.is_some() { "read_back" } else { "not_written_for_event_type" },
            "credit_grant_id": credit_grant_id,
            "ledger_entry_id": ledger_entry_id,
            "detail": local_detail
        },
        "invoice_order_readback": invoice_order_readback,
        "dunning_retry_readback": dunning_retry_readback,
        "proration_delta_readback": proration_delta_readback,
        "negative_proration_readback": negative_proration_readback,
        "refs": {
            "credit_grant_id": updated.try_get::<Option<Uuid>, _>("credit_grant_id").map_err(db_row_error)?,
            "ledger_entry_id": updated.try_get::<Option<Uuid>, _>("ledger_entry_id").map_err(db_row_error)?,
            "invoice_id": updated.try_get::<Option<Uuid>, _>("invoice_id").map_err(db_row_error)?,
            "order_id": updated.try_get::<Option<Uuid>, _>("order_id").map_err(db_row_error)?,
            "audit_id": updated.try_get::<Option<Uuid>, _>("audit_id").map_err(db_row_error)?
        },
        "writes_limited_to": subscription_scheduler_local_writes_limited_to(mode, &event_type, credit_grant_id, ledger_entry_id, invoice_id, order_id, subscription_rows_updated),
        "executor_steps": subscription_scheduler_local_executor_steps(
            &event_type,
            subscription_rows_updated > 0,
            ledger_entry_id.is_some(),
            credit_grant_id.is_some(),
            invoice_id.is_some() || order_id.is_some()
        )
    });

    tx.commit()
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
    Ok(readback)
}

struct SubscriptionSchedulerLocalMutationResult {
    status: &'static str,
    subscription_rows_updated: u64,
    credit_grant_id: Option<Uuid>,
    ledger_entry_id: Option<Uuid>,
    invoice_order_readback: Value,
    dunning_retry_readback: Value,
    proration_delta_readback: Value,
    negative_proration_readback: Value,
    readback: Value,
}

async fn apply_subscription_renewal_local_settlement_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    row: &PgRow,
    existing_credit_grant_id: Option<Uuid>,
    existing_ledger_entry_id: Option<Uuid>,
) -> Result<SubscriptionSchedulerLocalMutationResult, AdminError> {
    let event_id: Uuid = row.try_get("id").map_err(db_row_error)?;
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;
    let project_id: Option<Uuid> = row.try_get("project_id").map_err(db_row_error)?;
    let wallet_id: Uuid = row.try_get("wallet_id").map_err(db_row_error)?;
    let currency: String = row.try_get("currency").map_err(db_row_error)?;
    let included_credit_amount: String = row
        .try_get("included_credit_amount")
        .map_err(db_row_error)?;
    let idempotency_hash: String = row.try_get("idempotency_key_hash").map_err(db_row_error)?;

    let credit_grant_id = if existing_credit_grant_id.is_some() {
        existing_credit_grant_id
    } else {
        sqlx::query_scalar::<_, Uuid>(
            r#"
            insert into credit_grants (
              tenant_id, wallet_id, amount, remaining_amount, currency, source,
              valid_from, valid_until, status, metadata
            )
            select $1, $2, $3::numeric, $3::numeric, $4, 'subscription_renewal_local_settlement',
                   now(), null, 'active', $5::jsonb
            where $3::numeric > 0
            returning id
            "#,
        )
        .bind(tenant_id)
        .bind(wallet_id)
        .bind(&included_credit_amount)
        .bind(&currency)
        .bind(json!({
            "schema": "admin_subscription_scheduler_local_credit.v1",
            "subscription_id": subscription_id,
            "event_id": event_id,
            "operation": "renewal_local_settlement",
            "payment_capture_executed": false,
            "payment_provider_capture_required": true,
            "secret_safe": true
        }))
        .fetch_optional(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?
    };

    let ledger_entry_id = if existing_ledger_entry_id.is_some() {
        existing_ledger_entry_id
    } else {
        sqlx::query_scalar::<_, Uuid>(
            r#"
            insert into ledger_entries (
              tenant_id, project_id, wallet_id, request_id, virtual_key_id, trace_id,
              related_ledger_entry_id, entry_type, amount, currency, status,
              idempotency_key, usage_snapshot, policy_snapshot, metadata
            )
            select $1, $2, $3, null, null, null,
                   null, 'credit_grant', $4::numeric, $5, 'confirmed',
                   $6, '{}'::jsonb, '{}'::jsonb, $7::jsonb
            where $4::numeric > 0
            on conflict (tenant_id, idempotency_key) do update
              set metadata = ledger_entries.metadata
            returning id
            "#,
        )
        .bind(tenant_id)
        .bind(project_id)
        .bind(wallet_id)
        .bind(&included_credit_amount)
        .bind(&currency)
        .bind(format!("subscription-scheduler-renewal-ledger:{idempotency_hash}"))
        .bind(json!({
            "schema": "admin_subscription_scheduler_local_ledger.v1",
            "subscription_id": subscription_id,
            "event_id": event_id,
            "credit_grant_id": credit_grant_id,
            "operation": "renewal_local_settlement",
            "entry_explanation": "local subscription renewal credit; external payment capture is still required",
            "payment_capture_executed": false,
            "payment_provider_capture_required": true,
            "secret_safe": true
        }))
        .fetch_optional(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?
    };

    let updated = sqlx::query(
        r#"
        update subscriptions
        set status = 'renewed',
            current_period_start = current_period_end,
            current_period_end = case
              when $3 = 'year' then current_period_end + interval '1 year'
              when $3 = 'month' then current_period_end + interval '1 month'
              else current_period_end
            end,
            latest_credit_grant_id = coalesce($4, latest_credit_grant_id),
            latest_ledger_entry_id = coalesce($5, latest_ledger_entry_id),
            metadata = metadata || $6::jsonb,
            updated_at = now()
        where tenant_id = $1
          and id = $2
          and status in ('trialing', 'active', 'renewed', 'resumed', 'payment_failed')
        returning current_period_start::text as current_period_start,
                  current_period_end::text as current_period_end
        "#,
    )
    .bind(tenant_id)
    .bind(subscription_id)
    .bind(
        row.try_get::<String, _>("billing_interval")
            .map_err(db_row_error)?,
    )
    .bind(credit_grant_id)
    .bind(ledger_entry_id)
    .bind(json!({
        "last_scheduler_execution": {
            "event_id": event_id,
            "event_type": "renew",
            "local_settlement": true,
            "payment_provider_capture_required": true,
            "credit_grant_id": credit_grant_id,
            "ledger_entry_id": ledger_entry_id
        }
    }))
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let invoice_order_readback = subscription_scheduler_ensure_invoice_order_linkage_tx(
        tx,
        tenant_id,
        row,
        "renewal",
        &row.try_get::<String, _>("unit_price")
            .map_err(db_row_error)?,
        &currency,
        &json!({
            "line_type": "subscription_renewal",
            "subscription_id": subscription_id,
            "event_id": event_id,
            "plan_id": row.try_get::<Uuid, _>("plan_id").map_err(db_row_error)?,
            "plan_code": row.try_get::<String, _>("plan_code").map_err(db_row_error)?,
            "billing_interval": row.try_get::<String, _>("billing_interval").map_err(db_row_error)?,
            "credit_grant_id": credit_grant_id,
            "ledger_entry_id": ledger_entry_id
        }),
    )
    .await?;

    Ok(SubscriptionSchedulerLocalMutationResult {
        status: "local_settlement_recorded",
        subscription_rows_updated: u64::from(updated.is_some()),
        credit_grant_id,
        ledger_entry_id,
        invoice_order_readback,
        dunning_retry_readback: subscription_scheduler_dunning_retry_dry_run_readback("renew"),
        proration_delta_readback: subscription_scheduler_proration_delta_dry_run_readback("renew"),
        negative_proration_readback: subscription_scheduler_negative_proration_dry_run_readback(
            "renew",
        ),
        readback: json!({
            "status": "local_settlement_recorded",
            "payment_status": "payment_provider_capture_required",
            "credit_grant_id": credit_grant_id,
            "ledger_entry_id": ledger_entry_id,
            "subscription_period": updated.map(|row| json!({
                "start": row.try_get::<String, _>("current_period_start").unwrap_or_default(),
                "end": row.try_get::<String, _>("current_period_end").unwrap_or_default()
            })),
            "included_credit_amount": included_credit_amount,
            "currency": currency
        }),
    })
}

async fn apply_subscription_status_local_mutation_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    row: &PgRow,
) -> Result<SubscriptionSchedulerLocalMutationResult, AdminError> {
    let event_id: Uuid = row.try_get("id").map_err(db_row_error)?;
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;
    let event_type: String = row.try_get("event_type").map_err(db_row_error)?;
    let target_subscription_status = match event_type.as_str() {
        "expire" => "expired",
        "payment_failed" | "dunning" => "payment_failed",
        _ => "active",
    };
    let invoice_order_readback = if event_type == "payment_failed" || event_type == "dunning" {
        subscription_scheduler_invoice_order_readback_tx(tx, tenant_id, row).await?
    } else {
        json!({
            "status": "not_applicable",
            "event_type": event_type,
            "payment_capture_executed": false
        })
    };
    let dunning_retry_readback = apply_subscription_dunning_retry_state_tx(
        tx,
        tenant_id,
        row,
        &event_type,
        &invoice_order_readback,
    )
    .await?;
    let final_subscription_status = dunning_retry_readback
        .get("subscription_status_after_retry")
        .and_then(Value::as_str)
        .unwrap_or(target_subscription_status);
    let updated = sqlx::query(
        r#"
        update subscriptions
        set status = $3,
            metadata = metadata || $4::jsonb,
            updated_at = now()
        where tenant_id = $1
          and id = $2
        returning status
        "#,
    )
    .bind(tenant_id)
    .bind(subscription_id)
    .bind(final_subscription_status)
    .bind(json!({
        "last_scheduler_execution": {
            "event_id": event_id,
            "event_type": event_type,
            "subscription_status": final_subscription_status,
            "payment_capture_executed": false,
            "dunning_retry": dunning_retry_readback,
            "secret_safe": true
        }
    }))
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(SubscriptionSchedulerLocalMutationResult {
        status: "subscription_status_recorded",
        subscription_rows_updated: u64::from(updated.is_some()),
        credit_grant_id: None,
        ledger_entry_id: None,
        invoice_order_readback,
        dunning_retry_readback: dunning_retry_readback.clone(),
        proration_delta_readback: subscription_scheduler_proration_delta_dry_run_readback(
            &event_type,
        ),
        negative_proration_readback: subscription_scheduler_negative_proration_dry_run_readback(
            &event_type,
        ),
        readback: json!({
            "status": "subscription_status_recorded",
            "event_type": event_type,
            "subscription_status": final_subscription_status,
            "payment_status": if final_subscription_status == "payment_failed" { "payment_provider_capture_required" } else { "not_applicable" },
            "dunning_retry_readback": dunning_retry_readback
        }),
    })
}

fn subscription_scheduler_dunning_retry_dry_run_readback(event_type: &str) -> Value {
    match event_type {
        "payment_failed" | "dunning" => json!({
            "schema": "admin_subscription_scheduler_dunning_retry_readback.v1",
            "status": "dry_run_not_mutated",
            "event_type": event_type,
            "attempt_count": null,
            "next_retry_at": null,
            "max_attempts": 3,
            "final_dunning_action": "expire_subscription",
            "payment_capture_executed": false,
            "payment_status": "payment_provider_capture_required",
            "secret_safe": true
        }),
        "expire" => json!({
            "schema": "admin_subscription_scheduler_dunning_retry_readback.v1",
            "status": "expiration_event",
            "event_type": event_type,
            "attempt_count": null,
            "next_retry_at": null,
            "max_attempts": 3,
            "final_dunning_action": "expire_subscription",
            "payment_capture_executed": false,
            "secret_safe": true
        }),
        _ => json!({
            "schema": "admin_subscription_scheduler_dunning_retry_readback.v1",
            "status": "not_applicable",
            "event_type": event_type,
            "payment_capture_executed": false,
            "secret_safe": true
        }),
    }
}

fn subscription_scheduler_dunning_retry_existing_readback(
    row: &PgRow,
) -> Result<Value, AdminError> {
    let event_type: String = row.try_get("event_type").map_err(db_row_error)?;
    let metadata: Value = row.try_get("metadata").unwrap_or_else(|_| json!({}));
    if let Some(readback) = metadata
        .get("local_execution")
        .and_then(|value| value.get("dunning_retry_readback"))
        .cloned()
        .or_else(|| metadata.get("dunning_retry").cloned())
    {
        Ok(readback)
    } else {
        Ok(subscription_scheduler_dunning_retry_dry_run_readback(
            &event_type,
        ))
    }
}

