async fn apply_subscription_dunning_retry_state_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    row: &PgRow,
    event_type: &str,
    invoice_order_readback: &Value,
) -> Result<Value, AdminError> {
    if !matches!(event_type, "payment_failed" | "dunning" | "expire") {
        return Ok(subscription_scheduler_dunning_retry_dry_run_readback(
            event_type,
        ));
    }

    let max_attempts: i64 = 3;
    let retry_interval_hours: i64 = 24;
    let event_id: Uuid = row.try_get("id").map_err(db_row_error)?;
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;
    let applied_attempts = sqlx::query_scalar::<_, i64>(
        r#"
        select count(*)::bigint
        from subscription_events_or_schedules
        where tenant_id = $1
          and subscription_id = $2
          and event_type = 'dunning'
          and event_status = 'applied'
          and id <> $3
        "#,
    )
    .bind(tenant_id)
    .bind(subscription_id)
    .bind(event_id)
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    if event_type == "expire" {
        return Ok(json!({
            "schema": "admin_subscription_scheduler_dunning_retry_readback.v1",
            "status": "final_action_recorded",
            "event_type": event_type,
            "attempt_count": applied_attempts,
            "max_attempts": max_attempts,
            "next_retry_at": null,
            "final_dunning_action": "expire_subscription",
            "subscription_status_after_retry": "expired",
            "payment_capture_executed": false,
            "secret_safe": true
        }));
    }

    let current_attempt_count = if event_type == "dunning" {
        applied_attempts + 1
    } else {
        applied_attempts
    };
    let next_attempt_count = current_attempt_count + 1;
    let has_local_order = invoice_order_readback
        .get("order_id")
        .and_then(Value::as_str)
        .is_some();
    let has_local_invoice = invoice_order_readback
        .get("invoice_id")
        .and_then(Value::as_str)
        .is_some();

    if current_attempt_count >= max_attempts {
        return Ok(json!({
            "schema": "admin_subscription_scheduler_dunning_retry_readback.v1",
            "status": "max_attempts_reached",
            "event_type": event_type,
            "attempt_count": current_attempt_count,
            "next_attempt_count": null,
            "next_retry_at": null,
            "max_attempts": max_attempts,
            "final_dunning_action": "expire_subscription",
            "subscription_status_after_retry": "expired",
            "invoice_order_basis": {
                "has_local_order": has_local_order,
                "has_local_invoice": has_local_invoice
            },
            "payment_capture_executed": false,
            "payment_status": "payment_provider_capture_required",
            "secret_safe": true
        }));
    }

    let idempotency_key_hash = subscription_scheduler_idempotency_hash(
        tenant_id,
        subscription_id,
        "dunning",
        &format!("retry-attempt-{next_attempt_count}"),
        None,
    );
    let next_event = sqlx::query(
        r#"
        insert into subscription_events_or_schedules (
          tenant_id, subscription_id, event_type, event_status, effective_at,
          idempotency_key_hash, request_summary, metadata
        )
        values (
          $1, $2, 'dunning', 'scheduled', now() + ($3::text || ' hours')::interval,
          $4, $5::jsonb, $6::jsonb
        )
        on conflict (tenant_id, idempotency_key_hash) do update
          set updated_at = subscription_events_or_schedules.updated_at
        returning id, event_status, effective_at::text as effective_at
        "#,
    )
    .bind(tenant_id)
    .bind(subscription_id)
    .bind(retry_interval_hours.to_string())
    .bind(&idempotency_key_hash)
    .bind(json!({
        "source": "admin_subscription_scheduler_dunning_retry_executor",
        "source_event_id": event_id,
        "attempt_count": next_attempt_count,
        "max_attempts": max_attempts,
        "raw_payment_payload": "omitted",
        "raw_provider_payload": "omitted",
        "raw_idempotency_key": "omitted"
    }))
    .bind(json!({
        "schema": "admin_subscription_scheduler_dunning_retry_event.v1",
        "source_event_id": event_id,
        "attempt_count": next_attempt_count,
        "max_attempts": max_attempts,
        "local_only": true,
        "payment_capture_executed": false,
        "payment_provider_capture_required": true,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(json!({
        "schema": "admin_subscription_scheduler_dunning_retry_readback.v1",
        "status": if event_type == "payment_failed" { "retry_started" } else { "retry_attempt_recorded" },
        "event_type": event_type,
        "attempt_count": current_attempt_count,
        "next_attempt_count": next_attempt_count,
        "next_retry_at": next_event.try_get::<String, _>("effective_at").map_err(db_row_error)?,
        "next_retry_event": {
            "id": next_event.try_get::<Uuid, _>("id").map_err(db_row_error)?,
            "event_status": next_event.try_get::<String, _>("event_status").map_err(db_row_error)?,
            "idempotency_key_fingerprint": subscription_scheduler_public_fingerprint(&idempotency_key_hash)
        },
        "max_attempts": max_attempts,
        "retry_interval_hours": retry_interval_hours,
        "final_dunning_action": "expire_subscription",
        "subscription_status_after_retry": "payment_failed",
        "invoice_order_basis": {
            "has_local_order": has_local_order,
            "has_local_invoice": has_local_invoice
        },
        "payment_capture_executed": false,
        "payment_status": "payment_provider_capture_required",
        "secret_safe": true
    }))
}

async fn apply_subscription_proration_local_mutation_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    row: &PgRow,
) -> Result<SubscriptionSchedulerLocalMutationResult, AdminError> {
    let event_id: Uuid = row.try_get("id").map_err(db_row_error)?;
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;
    let request_summary: Value = row.try_get("request_summary").unwrap_or_else(|_| json!({}));
    let target_plan_id = request_summary
        .get("target_plan_id")
        .and_then(|value| value.as_str())
        .and_then(|value| Uuid::parse_str(value).ok());
    let Some(target_plan_id) = target_plan_id else {
        return Ok(SubscriptionSchedulerLocalMutationResult {
            status: "proration_missing_target_plan",
            subscription_rows_updated: 0,
            credit_grant_id: None,
            ledger_entry_id: None,
            invoice_order_readback: json!({
                "status": "blocked",
                "code": "target_plan_id_missing",
                "payment_capture_executed": false
            }),
            dunning_retry_readback: subscription_scheduler_dunning_retry_dry_run_readback(
                "prorate",
            ),
            proration_delta_readback: json!({
                "schema": "admin_subscription_scheduler_proration_delta_readback.v1",
                "status": "blocked",
                "code": "target_plan_id_missing",
                "payment_capture_executed": false,
                "payment_status": "payment_provider_capture_required",
                "secret_safe": true
            }),
            negative_proration_readback: subscription_scheduler_negative_proration_dry_run_readback(
                "prorate",
            ),
            readback: json!({
                "status": "blocked",
                "code": "target_plan_id_missing",
                "subscription_mutation": "not_attempted"
            }),
        });
    };

    let delta = sqlx::query(
        r#"
        select s.plan_id as current_plan_id,
               current_plan.plan_code as current_plan_code,
               current_plan.unit_price::text as current_unit_price,
               current_plan.currency as current_currency,
               target_plan.id as target_plan_id,
               target_plan.plan_code as target_plan_code,
               target_plan.status as target_plan_status,
               target_plan.unit_price::text as target_unit_price,
               target_plan.currency as target_currency,
               s.current_period_start::text as current_period_start,
               s.current_period_end::text as current_period_end,
               greatest(0, extract(epoch from (s.current_period_end - s.current_period_start)))::bigint as total_period_seconds,
               greatest(0, extract(epoch from (s.current_period_end - greatest(now(), s.current_period_start))))::bigint as remaining_period_seconds,
               round(
                 (
                   (target_plan.unit_price - current_plan.unit_price)
                   * greatest(0, extract(epoch from (s.current_period_end - greatest(now(), s.current_period_start))))
                   / nullif(extract(epoch from (s.current_period_end - s.current_period_start)), 0)
                 )::numeric,
                 $4
               )::text as delta_amount,
               (target_plan.unit_price - current_plan.unit_price)::text as full_period_delta_amount,
               now()::text as calculated_at
        from subscriptions s
        join subscription_plans current_plan
          on current_plan.tenant_id = s.tenant_id
         and current_plan.id = s.plan_id
        left join subscription_plans target_plan
          on target_plan.tenant_id = s.tenant_id
         and target_plan.id = $3
        where s.tenant_id = $1
          and s.id = $2
        "#,
    )
    .bind(tenant_id)
    .bind(subscription_id)
    .bind(target_plan_id)
    .bind(DEFAULT_MONEY_SCALE as i32)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let Some(delta) = delta else {
        let proration_delta_readback = json!({
            "schema": "admin_subscription_scheduler_proration_delta_readback.v1",
            "status": "blocked",
            "code": "subscription_not_found",
            "target_plan_id": target_plan_id,
            "payment_capture_executed": false,
            "payment_status": "payment_provider_capture_required",
            "secret_safe": true
        });
        return Ok(SubscriptionSchedulerLocalMutationResult {
            status: "proration_subscription_not_found",
            subscription_rows_updated: 0,
            credit_grant_id: None,
            ledger_entry_id: None,
            invoice_order_readback: json!({
                "status": "blocked",
                "code": "subscription_not_found",
                "payment_capture_executed": false
            }),
            dunning_retry_readback: subscription_scheduler_dunning_retry_dry_run_readback(
                "prorate",
            ),
            proration_delta_readback: proration_delta_readback.clone(),
            negative_proration_readback: subscription_scheduler_negative_proration_dry_run_readback(
                "prorate",
            ),
            readback: proration_delta_readback,
        });
    };

    let target_plan_code: Option<String> =
        delta.try_get("target_plan_code").map_err(db_row_error)?;
    let target_plan_status: Option<String> =
        delta.try_get("target_plan_status").map_err(db_row_error)?;
    let current_currency: String = delta.try_get("current_currency").map_err(db_row_error)?;
    let target_currency: Option<String> = delta.try_get("target_currency").map_err(db_row_error)?;
    let total_period_seconds: i64 = delta
        .try_get("total_period_seconds")
        .map_err(db_row_error)?;
    let remaining_period_seconds: i64 = delta
        .try_get("remaining_period_seconds")
        .map_err(db_row_error)?;
    let delta_amount: Option<String> = delta.try_get("delta_amount").map_err(db_row_error)?;
    let full_period_delta_amount: Option<String> = delta
        .try_get("full_period_delta_amount")
        .map_err(db_row_error)?;

    let mut blocked_code: Option<&'static str> = None;
    if target_plan_code.is_none() {
        blocked_code = Some("target_plan_not_found");
    } else if target_plan_status.as_deref() != Some("active") {
        blocked_code = Some("target_plan_not_active");
    } else if target_currency.as_deref() != Some(current_currency.as_str()) {
        blocked_code = Some("currency_mismatch");
    } else if total_period_seconds <= 0 {
        blocked_code = Some("period_time_invalid");
    } else if remaining_period_seconds <= 0 {
        blocked_code = Some("no_remaining_period");
    }

    let delta_money = delta_amount.as_deref().and_then(money_str);
    if blocked_code.is_none() && delta_money.map(|money| money.units() == 0).unwrap_or(true) {
        blocked_code = Some("zero_proration_delta");
    }

    let proration_delta_readback = json!({
        "schema": "admin_subscription_scheduler_proration_delta_readback.v1",
        "status": if blocked_code.is_some() { "blocked" } else { "calculated" },
        "code": blocked_code,
        "calculation": "target_minus_current_unit_price_times_remaining_period_ratio",
        "current_plan_id": delta.try_get::<Uuid, _>("current_plan_id").map_err(db_row_error)?,
        "current_plan_code": delta.try_get::<String, _>("current_plan_code").map_err(db_row_error)?,
        "target_plan_id": target_plan_id,
        "target_plan_code": target_plan_code,
        "current_unit_price": delta.try_get::<String, _>("current_unit_price").map_err(db_row_error)?,
        "target_unit_price": delta.try_get::<Option<String>, _>("target_unit_price").map_err(db_row_error)?,
        "full_period_delta_amount": full_period_delta_amount,
        "delta_amount": delta_amount,
        "currency": current_currency,
        "period": {
            "start": delta.try_get::<String, _>("current_period_start").map_err(db_row_error)?,
            "end": delta.try_get::<String, _>("current_period_end").map_err(db_row_error)?,
            "total_seconds": total_period_seconds,
            "remaining_seconds": remaining_period_seconds,
            "remaining_ratio_basis": "remaining_seconds / total_seconds"
        },
        "calculated_at": delta.try_get::<String, _>("calculated_at").map_err(db_row_error)?,
        "negative_or_zero_delta_policy": "negative_delta_creates_local_credit_adjustment_and_pending_refund_readback_zero_delta_blocked",
        "payment_capture_executed": false,
        "payment_status": "payment_provider_capture_required",
        "secret_safe": true
    });

    let is_negative_proration = blocked_code.is_none()
        && delta_money
            .as_ref()
            .map(|money| money.units() < 0)
            .unwrap_or(false);

    if is_negative_proration {
        let updated = sqlx::query(
            r#"
            update subscriptions s
            set plan_id = p.id,
                currency = p.currency,
                status = case when s.status in ('created', 'trialing') then s.status else 'active' end,
                metadata = s.metadata || $4::jsonb,
                updated_at = now()
            from subscription_plans p
            where s.tenant_id = $1
              and s.id = $2
              and p.tenant_id = s.tenant_id
              and p.id = $3
              and p.status = 'active'
              and p.currency = s.currency
            returning s.plan_id, p.plan_code, p.unit_price::text as unit_price, p.currency
            "#,
        )
        .bind(tenant_id)
        .bind(subscription_id)
        .bind(target_plan_id)
        .bind(json!({
            "last_scheduler_execution": {
                "event_id": event_id,
                "event_type": "prorate",
                "target_plan_id": target_plan_id,
                "local_plan_change": true,
                "proration_delta_readback": proration_delta_readback.clone(),
                "negative_proration_policy": "local_credit_adjustment_pending_refund",
                "payment_capture_executed": false,
                "refund_executed": false,
                "secret_safe": true
            }
        }))
        .fetch_optional(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let (credit_grant_id, ledger_entry_id, negative_proration_readback) =
            if let Some(updated_row) = updated.as_ref() {
                let currency: String = updated_row.try_get("currency").map_err(db_row_error)?;
                subscription_scheduler_apply_negative_proration_credit_tx(
                    tx,
                    tenant_id,
                    row,
                    target_plan_id,
                    &proration_delta_readback,
                    &currency,
                )
                .await?
            } else {
                (
                    None,
                    None,
                    json!({
                        "schema": "admin_subscription_scheduler_negative_proration_readback.v1",
                        "status": "blocked",
                        "code": "proration_target_not_applicable",
                        "credit_adjustment_executed": false,
                        "refund_executed": false,
                        "payment_capture_executed": false,
                        "secret_safe": true
                    }),
                )
            };

        return Ok(SubscriptionSchedulerLocalMutationResult {
            status: if updated.is_some() {
                "local_negative_proration_credit_recorded"
            } else {
                "proration_target_not_applicable"
            },
            subscription_rows_updated: u64::from(updated.is_some()),
            credit_grant_id,
            ledger_entry_id,
            invoice_order_readback: json!({
                "status": "not_created_for_negative_proration",
                "source_of_truth": "credit_grants + ledger_entries + subscription_events_or_schedules.metadata",
                "payment_capture_executed": false,
                "refund_executed": false
            }),
            dunning_retry_readback: subscription_scheduler_dunning_retry_dry_run_readback(
                "prorate",
            ),
            proration_delta_readback: proration_delta_readback.clone(),
            negative_proration_readback: negative_proration_readback.clone(),
            readback: json!({
                "status": if updated.is_some() { "local_negative_proration_credit_recorded" } else { "blocked" },
                "target_plan_id": target_plan_id,
                "subscription_mutation": if updated.is_some() { "plan_id_updated" } else { "not_attempted_or_currency_mismatch" },
                "proration_delta_readback": proration_delta_readback,
                "negative_proration_readback": negative_proration_readback,
                "payment_status": "pending_refund_or_credit_adjustment_recorded"
            }),
        });
    }

    let Some(amount) = proration_delta_readback
        .get("delta_amount")
        .and_then(Value::as_str)
        .filter(|_| blocked_code.is_none())
        .map(str::to_string)
    else {
        return Ok(SubscriptionSchedulerLocalMutationResult {
            status: "proration_delta_blocked",
            subscription_rows_updated: 0,
            credit_grant_id: None,
            ledger_entry_id: None,
            invoice_order_readback: json!({
                "status": "blocked",
                "code": blocked_code.unwrap_or("proration_delta_not_chargeable"),
                "payment_capture_executed": false,
                "payment_status": "payment_provider_capture_required"
            }),
            dunning_retry_readback: subscription_scheduler_dunning_retry_dry_run_readback(
                "prorate",
            ),
            proration_delta_readback: proration_delta_readback.clone(),
            negative_proration_readback: subscription_scheduler_negative_proration_dry_run_readback(
                "prorate",
            ),
            readback: json!({
                "status": "blocked",
                "target_plan_id": target_plan_id,
                "subscription_mutation": "not_attempted",
                "proration_delta_readback": proration_delta_readback,
                "payment_status": "payment_provider_capture_required"
            }),
        });
    };

    let updated = sqlx::query(
        r#"
        update subscriptions s
        set plan_id = p.id,
            currency = p.currency,
            status = case when s.status in ('created', 'trialing') then s.status else 'active' end,
            metadata = s.metadata || $4::jsonb,
            updated_at = now()
        from subscription_plans p
        where s.tenant_id = $1
          and s.id = $2
          and p.tenant_id = s.tenant_id
          and p.id = $3
          and p.status = 'active'
          and p.currency = s.currency
        returning s.plan_id, p.plan_code, p.unit_price::text as unit_price, p.currency
        "#,
    )
    .bind(tenant_id)
    .bind(subscription_id)
    .bind(target_plan_id)
    .bind(json!({
        "last_scheduler_execution": {
            "event_id": event_id,
            "event_type": "prorate",
            "target_plan_id": target_plan_id,
            "local_plan_change": true,
            "proration_delta_readback": proration_delta_readback.clone(),
            "payment_capture_executed": false,
            "payment_provider_capture_required": true,
            "secret_safe": true
        }
    }))
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let invoice_order_readback = if let Some(updated_row) = updated.as_ref() {
        let currency: String = updated_row.try_get("currency").map_err(db_row_error)?;
        subscription_scheduler_ensure_invoice_order_linkage_tx(
            tx,
            tenant_id,
            row,
            "proration",
            &amount,
            &currency,
            &json!({
                "line_type": "subscription_proration",
                "subscription_id": subscription_id,
                "event_id": event_id,
                "target_plan_id": target_plan_id,
                "target_plan_code": updated_row.try_get::<String, _>("plan_code").map_err(db_row_error)?,
                "amount_policy": "bounded_proration_delta",
                "proration_delta_readback": proration_delta_readback
            }),
        )
        .await?
    } else {
        json!({
            "status": "blocked",
            "code": "proration_target_not_applicable",
            "payment_capture_executed": false
        })
    };

    Ok(SubscriptionSchedulerLocalMutationResult {
        status: if updated.is_some() {
            "local_proration_plan_change_recorded"
        } else {
            "proration_target_not_applicable"
        },
        subscription_rows_updated: u64::from(updated.is_some()),
        credit_grant_id: None,
        ledger_entry_id: None,
        invoice_order_readback,
        dunning_retry_readback: subscription_scheduler_dunning_retry_dry_run_readback("prorate"),
        proration_delta_readback: proration_delta_readback.clone(),
        negative_proration_readback: subscription_scheduler_negative_proration_dry_run_readback(
            "prorate",
        ),
        readback: json!({
            "status": if updated.is_some() { "local_proration_plan_change_recorded" } else { "blocked" },
            "target_plan_id": target_plan_id,
            "subscription_mutation": if updated.is_some() { "plan_id_updated" } else { "not_attempted_or_currency_mismatch" },
            "proration_delta_readback": proration_delta_readback,
            "payment_status": "payment_provider_capture_required"
        }),
    })
}

async fn subscription_scheduler_ensure_invoice_order_linkage_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    row: &PgRow,
    linkage_kind: &str,
    amount: &str,
    currency: &str,
    line_item: &Value,
) -> Result<Value, AdminError> {
    let event_id: Uuid = row.try_get("id").map_err(db_row_error)?;
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;
    let project_id: Option<Uuid> = row.try_get("project_id").map_err(db_row_error)?;
    let wallet_id: Uuid = row.try_get("wallet_id").map_err(db_row_error)?;
    let idempotency_hash: String = row.try_get("idempotency_key_hash").map_err(db_row_error)?;
    let event_type: String = row.try_get("event_type").map_err(db_row_error)?;

    let order_idempotency_hash = sha256_hex(&format!(
        "subscription-scheduler:{linkage_kind}:order:v1:{tenant_id}:{idempotency_hash}"
    ));
    let intent_idempotency_hash = sha256_hex(&format!(
        "subscription-scheduler:{linkage_kind}:intent:v1:{tenant_id}:{idempotency_hash}"
    ));
    let invoice_number = format!("SUB-{}-{}", linkage_kind.to_ascii_uppercase(), event_id);
    let provider_reference_hash = sha256_hex(&format!(
        "subscription-scheduler:{linkage_kind}:provider-reference:v1:{tenant_id}:{event_id}"
    ));
    let provider_reference_redacted = format!(
        "sub_sched_{}_{}",
        linkage_kind,
        subscription_scheduler_public_fingerprint(&provider_reference_hash)
    );
    let source = match linkage_kind {
        "proration" => "subscription_scheduler_proration",
        _ => "subscription_scheduler_renewal",
    };
    let external_reference_id = format!("subscription-scheduler-{linkage_kind}-{event_id}");

    let order_id: Uuid = sqlx::query_scalar(
        r#"
        insert into payment_orders (
          tenant_id, project_id, wallet_id, currency, amount, status, source,
          external_reference_id, idempotency_key_hash, request_summary, metadata
        )
        values ($1, $2, $3, $4, $5::numeric, 'pending_payment', $6,
                $7, $8, $9::jsonb, $10::jsonb)
        on conflict (tenant_id, idempotency_key_hash) do update
          set updated_at = payment_orders.updated_at
        returning id
        "#,
    )
    .bind(tenant_id)
    .bind(project_id)
    .bind(wallet_id)
    .bind(currency)
    .bind(amount)
    .bind(source)
    .bind(external_reference_id)
    .bind(&order_idempotency_hash)
    .bind(json!({
        "schema": "admin_subscription_scheduler_invoice_order_linkage.v1",
        "linkage_kind": linkage_kind,
        "event_type": event_type.clone(),
        "subscription_id": subscription_id,
        "event_id": event_id,
        "raw_idempotency_key": "omitted",
        "raw_provider_payload": "omitted"
    }))
    .bind(json!({
        "operation": "subscription_scheduler_invoice_order_linkage",
        "linkage_kind": linkage_kind,
        "subscription_id": subscription_id,
        "event_id": event_id,
        "payment_capture_executed": false,
        "payment_provider_capture_required": true,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let payment_intent_id: Uuid = sqlx::query_scalar(
        r#"
        insert into payment_intents (
          tenant_id, project_id, wallet_id, order_id, provider, provider_reference_hash,
          provider_reference_redacted, currency, amount, status, idempotency_key_hash,
          request_summary, metadata
        )
        values ($1, $2, $3, $4, 'subscription_scheduler_local',
                $5, $6, $7, $8::numeric, 'provider_handoff', $9,
                $10::jsonb, $11::jsonb)
        on conflict (tenant_id, idempotency_key_hash) do update
          set updated_at = payment_intents.updated_at
        returning id
        "#,
    )
    .bind(tenant_id)
    .bind(project_id)
    .bind(wallet_id)
    .bind(order_id)
    .bind(&provider_reference_hash)
    .bind(&provider_reference_redacted)
    .bind(currency)
    .bind(amount)
    .bind(&intent_idempotency_hash)
    .bind(json!({
        "schema": "admin_subscription_scheduler_payment_intent.v1",
        "provider": "subscription_scheduler_local",
        "provider_payload": "omitted",
        "client_secret": "omitted",
        "payment_capture_executed": false
    }))
    .bind(json!({
        "operation": "subscription_scheduler_payment_intent_handoff",
        "linkage_kind": linkage_kind,
        "subscription_id": subscription_id,
        "event_id": event_id,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let invoice_id: Uuid = sqlx::query_scalar(
        r#"
        insert into invoices (
          tenant_id, project_id, wallet_id, order_id, invoice_number, currency,
          total_amount, status, line_items, request_summary, metadata
        )
        values ($1, $2, $3, $4, $5, $6, $7::numeric, 'issued',
                jsonb_build_array($8::jsonb), $9::jsonb, $10::jsonb)
        on conflict (tenant_id, invoice_number) do update
          set updated_at = invoices.updated_at
        returning id
        "#,
    )
    .bind(tenant_id)
    .bind(project_id)
    .bind(wallet_id)
    .bind(order_id)
    .bind(&invoice_number)
    .bind(currency)
    .bind(amount)
    .bind(line_item)
    .bind(json!({
        "schema": "admin_subscription_scheduler_invoice.v1",
        "linkage_kind": linkage_kind,
        "subscription_id": subscription_id,
        "event_id": event_id,
        "raw_invoice_metadata": "omitted"
    }))
    .bind(json!({
        "operation": "subscription_scheduler_invoice_issue",
        "linkage_kind": linkage_kind,
        "subscription_id": subscription_id,
        "event_id": event_id,
        "payment_capture_executed": false,
        "secret_safe": true
    }))
    .fetch_one(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    sqlx::query(
        r#"
        update payment_orders
        set payment_intent_id = coalesce(payment_intent_id, $3),
            invoice_id = coalesce(invoice_id, $4),
            updated_at = now()
        where tenant_id = $1
          and id = $2
        "#,
    )
    .bind(tenant_id)
    .bind(order_id)
    .bind(payment_intent_id)
    .bind(invoice_id)
    .execute(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    sqlx::query(
        r#"
        update subscriptions
        set latest_invoice_id = coalesce($3, latest_invoice_id),
            latest_order_id = coalesce($4, latest_order_id),
            metadata = metadata || $5::jsonb,
            updated_at = now()
        where tenant_id = $1
          and id = $2
        "#,
    )
    .bind(tenant_id)
    .bind(subscription_id)
    .bind(invoice_id)
    .bind(order_id)
    .bind(json!({
        "last_invoice_order_linkage": {
            "schema": "admin_subscription_scheduler_invoice_order_linkage.v1",
            "event_id": event_id,
            "event_type": event_type,
            "linkage_kind": linkage_kind,
            "invoice_id": invoice_id,
            "order_id": order_id,
            "payment_intent_id": payment_intent_id,
            "payment_capture_executed": false
        }
    }))
    .execute(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    Ok(json!({
        "schema": "admin_subscription_scheduler_invoice_order_readback.v1",
        "status": "linked",
        "linkage_kind": linkage_kind,
        "order_id": order_id,
        "order_status": "pending_payment",
        "invoice_id": invoice_id,
        "invoice_status": "issued",
        "invoice_number": invoice_number,
        "payment_intent_id": payment_intent_id,
        "payment_intent_status": "provider_handoff",
        "amount": amount,
        "currency": currency,
        "line_item": line_item,
        "payment_capture_executed": false,
        "payment_status": "payment_provider_capture_required",
        "idempotency": {
            "source": "subscription_events_or_schedules.idempotency_key_hash",
            "order_idempotency_fingerprint": subscription_scheduler_public_fingerprint(&order_idempotency_hash),
            "intent_idempotency_fingerprint": subscription_scheduler_public_fingerprint(&intent_idempotency_hash),
            "raw_idempotency_key_echoed": false
        },
        "omitted_fields": [
            "raw_payment_payload",
            "raw_provider_payload",
            "authorization",
            "raw_invoice_metadata",
            "raw_idempotency_key",
            "provider_secret",
            "client_secret"
        ],
        "secret_safe": true
    }))
}

async fn subscription_scheduler_apply_negative_proration_credit_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    row: &PgRow,
    target_plan_id: Uuid,
    proration_delta_readback: &Value,
    currency: &str,
) -> Result<(Option<Uuid>, Option<Uuid>, Value), AdminError> {
    let event_id: Uuid = row.try_get("id").map_err(db_row_error)?;
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;
    let project_id: Option<Uuid> = row.try_get("project_id").map_err(db_row_error)?;
    let wallet_id: Uuid = row.try_get("wallet_id").map_err(db_row_error)?;
    let idempotency_hash: String = row.try_get("idempotency_key_hash").map_err(db_row_error)?;
    let Some(delta_amount) = proration_delta_readback
        .get("delta_amount")
        .and_then(Value::as_str)
    else {
        return Ok((
            None,
            None,
            json!({
                "schema": "admin_subscription_scheduler_negative_proration_readback.v1",
                "status": "blocked",
                "code": "delta_amount_missing",
                "credit_adjustment_executed": false,
                "refund_executed": false,
                "payment_capture_executed": false,
                "secret_safe": true
            }),
        ));
    };

    let credit_grant_id = sqlx::query_scalar::<_, Uuid>(
        r#"
        insert into credit_grants (
          tenant_id, wallet_id, amount, remaining_amount, currency, source,
          valid_from, valid_until, status, metadata
        )
        select $1, $2, abs($3::numeric), abs($3::numeric), $4,
               'subscription_negative_proration_credit',
               now(), null, 'active', $5::jsonb
        where $3::numeric < 0
        returning id
        "#,
    )
    .bind(tenant_id)
    .bind(wallet_id)
    .bind(delta_amount)
    .bind(currency)
    .bind(json!({
        "schema": "admin_subscription_scheduler_negative_proration_credit.v1",
        "subscription_id": subscription_id,
        "event_id": event_id,
        "target_plan_id": target_plan_id,
        "source_of_truth": "subscription_events_or_schedules.idempotency_key_hash",
        "proration_delta_readback": proration_delta_readback,
        "refund_intent_status": "pending_provider_refund_or_operator_credit_policy",
        "refund_executed": false,
        "payment_capture_executed": false,
        "secret_safe": true
    }))
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let ledger_entry_id = sqlx::query_scalar::<_, Uuid>(
        r#"
        insert into ledger_entries (
          tenant_id, project_id, wallet_id, request_id, virtual_key_id, trace_id,
          related_ledger_entry_id, entry_type, amount, currency, status,
          idempotency_key, usage_snapshot, policy_snapshot, metadata
        )
        select $1, $2, $3, null, null, null,
               null, 'adjust', abs($4::numeric), $5, 'confirmed',
               $6, '{}'::jsonb, '{}'::jsonb, $7::jsonb
        where $4::numeric < 0
        on conflict (tenant_id, idempotency_key) do update
          set metadata = ledger_entries.metadata
        returning id
        "#,
    )
    .bind(tenant_id)
    .bind(project_id)
    .bind(wallet_id)
    .bind(delta_amount)
    .bind(currency)
    .bind(format!(
        "subscription-scheduler-negative-proration-ledger:{idempotency_hash}"
    ))
    .bind(json!({
        "schema": "admin_subscription_scheduler_negative_proration_ledger.v1",
        "subscription_id": subscription_id,
        "event_id": event_id,
        "target_plan_id": target_plan_id,
        "credit_grant_id": credit_grant_id,
        "operation": "negative_proration_local_credit_adjustment",
        "entry_explanation": "local subscription downgrade credit; external refund is not marked successful",
        "proration_delta_readback": proration_delta_readback,
        "refund_executed": false,
        "payment_capture_executed": false,
        "secret_safe": true
    }))
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let readback = json!({
        "schema": "admin_subscription_scheduler_negative_proration_readback.v1",
        "status": if credit_grant_id.is_some() || ledger_entry_id.is_some() {
            "local_credit_adjustment_recorded"
        } else {
            "blocked"
        },
        "source_of_truth": "credit_grants + ledger_entries + subscription_events_or_schedules.metadata",
        "policy": "downgrade_delta_becomes_wallet_credit_and_pending_refund_intent",
        "delta_amount": delta_amount,
        "credit_amount": {
            "source": "abs(delta_amount)",
            "currency": currency
        },
        "credit_grant_id": credit_grant_id,
        "ledger_entry_id": ledger_entry_id,
        "refund_intent": {
            "status": "pending_provider_refund_or_operator_credit_policy",
            "payment_refund_id": null,
            "reason": "no_verified_provider_capture_ref_for_scheduler_proration",
            "refund_executed": false
        },
        "credit_adjustment_executed": credit_grant_id.is_some() || ledger_entry_id.is_some(),
        "refund_executed": false,
        "payment_capture_executed": false,
        "idempotency_key_fingerprint": subscription_scheduler_public_fingerprint(&idempotency_hash),
        "secret_safe": true
    });

    Ok((credit_grant_id, ledger_entry_id, readback))
}

async fn subscription_scheduler_invoice_order_readback_tx(
    tx: &mut Transaction<'_, Postgres>,
    tenant_id: Uuid,
    row: &PgRow,
) -> Result<Value, AdminError> {
    let event_invoice_id: Option<Uuid> = row.try_get("invoice_id").map_err(db_row_error)?;
    let event_order_id: Option<Uuid> = row.try_get("order_id").map_err(db_row_error)?;
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;

    let readback = sqlx::query(
        r#"
        with refs as (
          select
            coalesce($3, s.latest_order_id) as order_id,
            coalesce($4, s.latest_invoice_id) as invoice_id
          from subscriptions s
          where s.tenant_id = $1
            and s.id = $2
        )
        select o.id as order_id,
               o.status as order_status,
               i.id as invoice_id,
               i.status as invoice_status,
               i.invoice_number,
               i.line_items,
               pi.id as payment_intent_id,
               pi.status as payment_intent_status,
               coalesce(i.total_amount::text, o.amount::text) as amount,
               coalesce(i.currency, o.currency) as currency
        from refs
        left join payment_orders o on o.tenant_id = $1 and o.id = refs.order_id
        left join invoices i on i.tenant_id = $1 and i.id = refs.invoice_id
        left join payment_intents pi on pi.tenant_id = $1 and pi.order_id = o.id
        "#,
    )
    .bind(tenant_id)
    .bind(subscription_id)
    .bind(event_order_id)
    .bind(event_invoice_id)
    .fetch_optional(&mut **tx)
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let Some(readback) = readback else {
        return Ok(json!({
            "status": "not_found",
            "payment_capture_executed": false,
            "payment_status": "payment_provider_capture_required"
        }));
    };
    let order_id: Option<Uuid> = readback.try_get("order_id").map_err(db_row_error)?;
    let invoice_id: Option<Uuid> = readback.try_get("invoice_id").map_err(db_row_error)?;
    Ok(json!({
        "schema": "admin_subscription_scheduler_invoice_order_readback.v1",
        "status": if order_id.is_some() || invoice_id.is_some() { "read_back" } else { "not_linked" },
        "order_id": order_id,
        "order_status": readback.try_get::<Option<String>, _>("order_status").map_err(db_row_error)?,
        "invoice_id": invoice_id,
        "invoice_status": readback.try_get::<Option<String>, _>("invoice_status").map_err(db_row_error)?,
        "invoice_number": readback.try_get::<Option<String>, _>("invoice_number").map_err(db_row_error)?,
        "invoice_line_items": readback.try_get::<Option<Value>, _>("line_items").map_err(db_row_error)?,
        "payment_intent_id": readback.try_get::<Option<Uuid>, _>("payment_intent_id").map_err(db_row_error)?,
        "payment_intent_status": readback.try_get::<Option<String>, _>("payment_intent_status").map_err(db_row_error)?,
        "amount": readback.try_get::<Option<String>, _>("amount").map_err(db_row_error)?,
        "currency": readback.try_get::<Option<String>, _>("currency").map_err(db_row_error)?,
        "dunning_retry_basis": {
            "has_local_order": order_id.is_some(),
            "has_local_invoice": invoice_id.is_some(),
            "payment_provider_capture_required": true
        },
        "payment_capture_executed": false,
        "payment_status": "payment_provider_capture_required",
        "secret_safe": true
    }))
}

struct SubscriptionSchedulerProviderSourceRefPlan {
    provider_object_ref_present: bool,
    provider_object_ref_source: &'static str,
    provider_reference_hash: Option<String>,
    provider_reference_redacted: Option<String>,
    provider_reference_fingerprint: Option<String>,
    metadata_ref_marker_present: bool,
}

impl SubscriptionSchedulerProviderSourceRefPlan {
    fn safe_executor_ref(&self) -> PaymentProviderSafeRef {
        payment_provider_safe_ref_from_hash(self.provider_reference_hash.clone())
    }
}

async fn subscription_scheduler_provider_source_ref_plan(
    db: &PgPool,
    tenant_id: Uuid,
    order_id: Option<Uuid>,
    payment_intent_id: Option<Uuid>,
) -> Result<SubscriptionSchedulerProviderSourceRefPlan, AdminError> {
    let mut provider_reference_hash = None;
    let mut provider_reference_redacted = None;
    let mut metadata_ref_marker_present = false;
    let mut provider_object_ref_source = "missing_real_provider_payment_intent_ref";

    if let Some(payment_intent_id) = payment_intent_id {
        if let Some(row) = sqlx::query(
            r#"
            select provider_reference_hash, provider_reference_redacted, metadata, request_summary
            from payment_intents
            where tenant_id = $1 and id = $2
            "#,
        )
        .bind(tenant_id)
        .bind(payment_intent_id)
        .fetch_optional(db)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?
        {
            provider_reference_hash = row
                .try_get::<Option<String>, _>("provider_reference_hash")
                .map_err(db_row_error)?
                .and_then(non_empty_string);
            provider_reference_redacted = row
                .try_get::<Option<String>, _>("provider_reference_redacted")
                .map_err(db_row_error)?
                .and_then(non_empty_string);
            let metadata = row
                .try_get::<Option<Value>, _>("metadata")
                .map_err(db_row_error)?;
            let request_summary = row
                .try_get::<Option<Value>, _>("request_summary")
                .map_err(db_row_error)?;
            metadata_ref_marker_present = json_contains_provider_ref_marker(metadata.as_ref())
                || json_contains_provider_ref_marker(request_summary.as_ref());

            provider_object_ref_source = if provider_reference_hash.is_some() {
                "payment_intents.provider_reference_hash"
            } else if provider_reference_redacted.is_some() {
                "payment_intents.provider_reference_redacted"
            } else if metadata_ref_marker_present {
                "payment_intents.metadata_candidate_requires_safe_hash_or_redacted_ref"
            } else {
                "missing_real_provider_payment_intent_ref"
            };
        }
    }

    if !metadata_ref_marker_present {
        if let Some(order_id) = order_id {
            if let Some(row) = sqlx::query(
                r#"
                select po.metadata as order_metadata, po.request_summary as order_request_summary,
                       i.metadata as invoice_metadata
                from payment_orders po
                left join invoices i on i.tenant_id = po.tenant_id and i.order_id = po.id
                where po.tenant_id = $1 and po.id = $2
                order by i.created_at desc nulls last
                limit 1
                "#,
            )
            .bind(tenant_id)
            .bind(order_id)
            .fetch_optional(db)
            .await
            .map_err(|error| AdminError::from(DbError::Query(error)))?
            {
                let order_metadata = row
                    .try_get::<Option<Value>, _>("order_metadata")
                    .map_err(db_row_error)?;
                let order_request_summary = row
                    .try_get::<Option<Value>, _>("order_request_summary")
                    .map_err(db_row_error)?;
                let invoice_metadata = row
                    .try_get::<Option<Value>, _>("invoice_metadata")
                    .map_err(db_row_error)?;
                metadata_ref_marker_present =
                    json_contains_provider_ref_marker(order_metadata.as_ref())
                        || json_contains_provider_ref_marker(order_request_summary.as_ref())
                        || json_contains_provider_ref_marker(invoice_metadata.as_ref());
                if provider_reference_hash.is_none()
                    && provider_reference_redacted.is_none()
                    && metadata_ref_marker_present
                {
                    provider_object_ref_source = "payment_orders_or_invoices.metadata_candidate_requires_safe_hash_or_redacted_ref";
                }
            }
        }
    }

    let provider_object_ref_present =
        provider_reference_hash.is_some() || provider_reference_redacted.is_some();
    let provider_reference_fingerprint = provider_reference_hash
        .as_deref()
        .map(subscription_scheduler_public_fingerprint);

    Ok(SubscriptionSchedulerProviderSourceRefPlan {
        provider_object_ref_present,
        provider_object_ref_source,
        provider_reference_hash,
        provider_reference_redacted,
        provider_reference_fingerprint,
        metadata_ref_marker_present,
    })
}

fn non_empty_string(value: String) -> Option<String> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        None
    } else {
        Some(trimmed.to_string())
    }
}

fn json_contains_provider_ref_marker(value: Option<&Value>) -> bool {
    let Some(value) = value else {
        return false;
    };
    match value {
        Value::Object(object) => object.iter().any(|(key, value)| {
            let key = key.to_ascii_lowercase();
            (key.contains("provider")
                && key.contains("ref")
                && !matches!(value, Value::Null)
                && !matches!(value.as_str(), Some("omitted" | "redacted")))
                || json_contains_provider_ref_marker(Some(value))
        }),
        Value::Array(values) => values
            .iter()
            .any(|value| json_contains_provider_ref_marker(Some(value))),
        _ => false,
    }
}

async fn subscription_scheduler_refund_or_credit_note_handoff_readback(
    db: &PgPool,
    tenant_id: Uuid,
    row: &PgRow,
    local_execution: &Value,
) -> Result<Value, AdminError> {
    let event_id: Uuid = row.try_get("id").map_err(db_row_error)?;
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;
    let event_type: String = row.try_get("event_type").map_err(db_row_error)?;
    let event_status: String = row.try_get("event_status").map_err(db_row_error)?;
    let due_now: bool = row.try_get("due_now").unwrap_or(false);
    let source_hash: String = row.try_get("idempotency_key_hash").map_err(db_row_error)?;
    let negative_proration = local_execution
        .get("negative_proration_readback")
        .cloned()
        .unwrap_or_else(|| subscription_scheduler_negative_proration_dry_run_readback(&event_type));
    let is_negative_proration_handoff = event_type == "prorate"
        && matches!(
            negative_proration.get("status").and_then(Value::as_str),
            Some("local_credit_adjustment_recorded")
                | Some("dry_run_not_mutated")
                | Some("blocked")
        );
    let credit_grant_id = value_uuid(local_execution.pointer("/refs/credit_grant_id"))
        .or_else(|| value_uuid(negative_proration.get("credit_grant_id")));
    let ledger_entry_id = value_uuid(local_execution.pointer("/refs/ledger_entry_id"))
        .or_else(|| value_uuid(negative_proration.get("ledger_entry_id")));
    let payment_refund_row = if credit_grant_id.is_some() || ledger_entry_id.is_some() {
        sqlx::query(
            r#"
            select id,
                   status,
                   idempotency_key_hash,
                   request_summary,
                   metadata
            from payment_refunds
            where tenant_id = $1
              and (
                ($2::uuid is not null and credit_grant_id = $2)
                or ($3::uuid is not null and (ledger_entry_id = $3 or reversal_ledger_entry_id = $3))
              )
            order by updated_at desc
            limit 1
            "#,
        )
        .bind(tenant_id)
        .bind(credit_grant_id)
        .bind(ledger_entry_id)
        .fetch_optional(db)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?
    } else {
        None
    };
    let payment_refund_id = payment_refund_row
        .as_ref()
        .map(|row| row.try_get::<Uuid, _>("id"))
        .transpose()
        .map_err(db_row_error)?;
    let payment_refund_status = payment_refund_row
        .as_ref()
        .map(|row| row.try_get::<String, _>("status"))
        .transpose()
        .map_err(db_row_error)?;
    let payment_refund_hash = payment_refund_row
        .as_ref()
        .map(|row| row.try_get::<String, _>("idempotency_key_hash"))
        .transpose()
        .map_err(db_row_error)?;
    let payment_refund_request_summary = payment_refund_row
        .as_ref()
        .map(|row| row.try_get::<Value, _>("request_summary"))
        .transpose()
        .unwrap_or(None)
        .unwrap_or_else(|| json!({}));
    let payment_refund_metadata = payment_refund_row
        .as_ref()
        .map(|row| row.try_get::<Value, _>("metadata"))
        .transpose()
        .unwrap_or(None)
        .unwrap_or_else(|| json!({}));
    let provider_refund_ref_present =
        json_contains_provider_ref_marker(Some(&payment_refund_request_summary))
            || json_contains_provider_ref_marker(Some(&payment_refund_metadata));
    let unit_price: String = row.try_get("unit_price").map_err(db_row_error)?;
    let plan_currency: String = row.try_get("currency").map_err(db_row_error)?;
    let amount = subscription_scheduler_abs_decimal_string(
        negative_proration
            .get("delta_amount")
            .and_then(Value::as_str)
            .or_else(|| {
                local_execution
                    .pointer("/invoice_order_readback/amount")
                    .and_then(Value::as_str)
            })
            .or(Some(unit_price.as_str())),
    )
    .unwrap_or_else(|| unit_price.clone());
    let currency = negative_proration
        .pointer("/credit_amount/currency")
        .and_then(Value::as_str)
        .or_else(|| {
            local_execution
                .pointer("/invoice_order_readback/currency")
                .and_then(Value::as_str)
        })
        .unwrap_or(&plan_currency);
    let order_id = value_uuid(local_execution.pointer("/refs/order_id"))
        .or_else(|| value_uuid(local_execution.pointer("/invoice_order_readback/order_id")));
    let invoice_id = value_uuid(local_execution.pointer("/refs/invoice_id"))
        .or_else(|| value_uuid(local_execution.pointer("/invoice_order_readback/invoice_id")));
    let payment_intent_id =
        value_uuid(local_execution.pointer("/invoice_order_readback/payment_intent_id"));
    let provider_source_ref =
        subscription_scheduler_provider_source_ref_plan(db, tenant_id, order_id, payment_intent_id)
            .await?;
    let provider = payment_provider_config_default_provider()?;
    let credential_source =
        payment_provider_merchant_credential_source_readback(db, tenant_id, &provider).await?;
    let credential_config =
        payment_provider_adapter_config_input_for_credential_source(&provider, &credential_source)?;
    let credential_refusal_reason = payment_provider_credential_refusal_reason(&credential_config);
    let handoff_hash = sha256_hex(&format!(
        "subscription-scheduler:refund-credit-note-handoff:v1:{tenant_id}:{event_id}:{source_hash}"
    ));
    let fingerprint = subscription_scheduler_public_fingerprint(&handoff_hash);
    let mut blocked_reasons = Vec::new();
    if !is_negative_proration_handoff {
        blocked_reasons.push("event_type_not_refund_or_credit_note");
    }
    if !due_now {
        blocked_reasons.push("event_not_due");
    }
    if !matches!(event_status.as_str(), "scheduled" | "applied" | "replayed") {
        blocked_reasons.push("event_status_not_refund_candidate");
    }
    if credit_grant_id.is_none() {
        blocked_reasons.push("local_credit_grant_ref_missing");
    }
    if ledger_entry_id.is_none() {
        blocked_reasons.push("local_ledger_ref_missing");
    }
    if payment_refund_id.is_none() {
        blocked_reasons.push("local_payment_refund_ref_missing");
    }
    if !provider_source_ref.provider_object_ref_present {
        blocked_reasons.push("provider_payment_source_ref_missing");
    }
    if !provider_refund_ref_present {
        blocked_reasons.push("provider_refund_ref_missing_until_executor_response");
    }
    if is_negative_proration_handoff {
        blocked_reasons.push("provider_refund_execution_disabled");
    }
    if let Some(reason) = credential_refusal_reason {
        blocked_reasons.push(reason);
    }
    let local_refs = PaymentProviderRefs {
        order_id: order_id.map(|value| value.to_string()),
        payment_intent_id: payment_intent_id.map(|value| value.to_string()),
        payment_capture_id: None,
        refund_id: payment_refund_id.map(|value| value.to_string()),
        credit_grant_id: credit_grant_id.map(|value| value.to_string()),
        ledger_entry_id: ledger_entry_id.map(|value| value.to_string()),
        reversal_ledger_entry_id: None,
        invoice_id: invoice_id.map(|value| value.to_string()),
        audit_id: value_uuid(local_execution.pointer("/refs/audit_id"))
            .map(|value| value.to_string()),
    };
    let executor_contract = serde_json::to_value(plan_payment_provider_executor_contract(
        PaymentProviderExecutorRequest {
            provider: provider.clone(),
            action: PaymentProviderExecutorAction::Refund,
            amount: amount.clone(),
            currency: currency.to_string(),
            reason: "subscription scheduler refund or credit-note handoff".to_string(),
            idempotency: PaymentProviderExecutorIdempotency::hashed(handoff_hash.clone()),
            provider_refs: PaymentProviderExecutorProviderRefs {
                provider_object_ref: provider_source_ref.safe_executor_ref(),
                refund_ref: PaymentProviderSafeRef::default(),
                ..PaymentProviderExecutorProviderRefs::default()
            },
            local_refs: local_refs.clone(),
            gate: PaymentProviderExecutorGateInput {
                adapter_enabled: credential_config.adapter_enabled,
                merchant_connected: credential_config.merchant_account_present,
                credential_present: credential_config.credential_present,
                credential_fingerprint_present: credential_config
                    .credential_fingerprint_prefix
                    .is_some(),
                signature_verified: credential_config.webhook_secret_present,
            },
        },
    ))
    .map_err(|error| {
        AdminError::configuration_error(format!("serialize refund handoff: {error}"))
    })?;
    let stripe_like_client_request_plan =
        serde_json::to_value(plan_stripe_like_client_request(StripeLikeClientRequest {
            provider: provider.clone(),
            operation: StripeLikeClientOperation::CreateRefund,
            credential_source: credential_source
                .get("source")
                .and_then(Value::as_str)
                .unwrap_or("unknown")
                .to_string(),
            credential_source_ready: credential_refusal_reason.is_none(),
            merchant_account_ref_present: credential_source
                .get("merchant_account_ref_present")
                .and_then(Value::as_bool)
                .unwrap_or(false),
            idempotency: PaymentProviderExecutorIdempotency::hashed(handoff_hash.clone()),
            provider_refs: PaymentProviderExecutorProviderRefs {
                provider_object_ref: provider_source_ref.safe_executor_ref(),
                refund_ref: PaymentProviderSafeRef::default(),
                ..PaymentProviderExecutorProviderRefs::default()
            },
            amount: Some(amount.clone()),
            currency: Some(currency.to_string()),
            reason: Some("subscription scheduler refund or credit-note handoff".to_string()),
            local_refs: local_refs.clone(),
        }))
        .map_err(|error| {
            AdminError::configuration_error(format!(
                "serialize refund stripe-like handoff plan: {error}"
            ))
        })?;

    Ok(json!({
        "schema": "admin_subscription_scheduler_refund_or_credit_note_handoff.v1",
        "status": if is_negative_proration_handoff { "blocked" } else { "not_applicable" },
        "event_id": event_id,
        "subscription_id": subscription_id,
        "event_type": event_type,
        "event_status": event_status,
        "due_now": due_now,
        "scenario": if is_negative_proration_handoff { "negative_proration_refund_or_credit_note" } else { "not_applicable" },
        "next_provider_executor_action": "refund_or_credit_note",
        "ready_for_provider_executor": false,
        "blocked_reasons": blocked_reasons,
        "next_action": if provider_source_ref.provider_object_ref_present && payment_refund_id.is_some() && provider_refund_ref_present {
            "Fetch provider refund object source-of-truth and reconcile before any local refund success readback is trusted."
        } else if credit_grant_id.is_some() || ledger_entry_id.is_some() {
            "Keep local credit-note readback as pending; provider refund requires a real executor/fetch readback before settlement success."
        } else {
            "No local negative proration credit-note refs are available for provider refund handoff."
        },
        "operator_api_call": {
            "method": "POST",
            "path": "/admin/billing/payment-provider/executor",
            "action": "refund",
            "idempotency_fingerprint": fingerprint,
            "raw_idempotency_key_required_from_ui": false
        },
        "local_refs": {
            "credit_grant_id": local_refs.credit_grant_id,
            "ledger_entry_id": local_refs.ledger_entry_id,
            "payment_refund_id": local_refs.refund_id,
            "order_id": local_refs.order_id,
            "invoice_id": local_refs.invoice_id,
            "payment_intent_id": local_refs.payment_intent_id,
            "local_credit_note_refs_present": credit_grant_id.is_some() || ledger_entry_id.is_some(),
            "local_payment_refund_ref_present": payment_refund_id.is_some()
        },
        "payment_refund": {
            "id": payment_refund_id,
            "status": payment_refund_status,
            "idempotency_fingerprint": payment_refund_hash
                .as_deref()
                .map(subscription_scheduler_public_fingerprint),
            "provider_refund_ref_present": provider_refund_ref_present,
            "raw_provider_ref_echoed": false
        },
        "provider_refs": {
            "provider_payment_source_ref_present": provider_source_ref.provider_object_ref_present,
            "provider_payment_source_ref_source": provider_source_ref.provider_object_ref_source,
            "provider_payment_source_reference_fingerprint": provider_source_ref.provider_reference_fingerprint,
            "provider_refund_ref_present": provider_refund_ref_present,
            "provider_refund_ref_raw_echoed": false,
            "provider_payment_source_ref_raw_echoed": false
        },
        "provider_object_fetch_requirement": {
            "required_before_refund_success": true,
            "provider_payment_object_summary_required": true,
            "provider_refund_object_summary_required": true,
            "provider_object_fetch_summary_schema": "payment_provider_stripe_like_source_of_truth_summary.v1",
            "expected_reconciliation_schema": PAYMENT_PROVIDER_STRIPE_LIKE_RESPONSE_OBJECT_RECONCILIATION_SCHEMA,
            "network_call_enabled": false,
            "network_call_performed": false
        },
        "source_of_truth_policy": {
            "scheduler_source_of_truth": false,
            "local_credit_note_source": "credit_grants + ledger_entries + subscription_events_or_schedules.metadata",
            "provider_refund_source": "payment_provider_executor.stripe_like_response_object_reconciliation",
            "provider_api_readback_required": true,
            "webhook_or_fetch_evidence_required": true,
            "production_refund_evidence": false,
            "success_must_not_be_inferred_from_local_credit": true
        },
        "negative_proration_readback": negative_proration,
        "billing_ledger_executor_contract": executor_contract,
        "stripe_like_client_request_plan": stripe_like_client_request_plan,
        "idempotency": {
            "source": "subscription_events_or_schedules.idempotency_key_hash",
            "fingerprint": fingerprint,
            "raw_idempotency_key_echoed": false,
            "key_hash_returned": false
        },
        "writes": {
            "payment_refunds": "read_back_only",
            "payment_events": "not_written",
            "payment_captures": "not_written",
            "ledger_entries": "read_back_only",
            "credit_grants": "read_back_only",
            "payment_reconciliations": "not_written"
        },
        "refund_executed": false,
        "credit_note_recorded_locally": credit_grant_id.is_some() || ledger_entry_id.is_some(),
        "network_call_enabled": false,
        "network_call_performed": false,
        "secret_safe": true,
        "raw_payment_payload_returned": false,
        "raw_provider_payload_returned": false,
        "authorization_returned": false,
        "provider_secret_returned": false,
        "raw_idempotency_key_echoed": false
    }))
}

fn subscription_scheduler_abs_decimal_string(value: Option<&str>) -> Option<String> {
    let value = value?.trim();
    if value.is_empty() {
        None
    } else {
        Some(value.strip_prefix('-').unwrap_or(value).to_string())
    }
}

async fn subscription_scheduler_payment_capture_handoff_readback(
    db: &PgPool,
    tenant_id: Uuid,
    row: &PgRow,
    local_execution: &Value,
) -> Result<Value, AdminError> {
    let event_id: Uuid = row.try_get("id").map_err(db_row_error)?;
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;
    let event_type: String = row.try_get("event_type").map_err(db_row_error)?;
    let event_status: String = row.try_get("event_status").map_err(db_row_error)?;
    let due_now: bool = row.try_get("due_now").unwrap_or(false);
    let source_hash: String = row.try_get("idempotency_key_hash").map_err(db_row_error)?;
    let unit_price: String = row.try_get("unit_price").map_err(db_row_error)?;
    let plan_currency: String = row.try_get("currency").map_err(db_row_error)?;
    let amount = local_execution
        .pointer("/invoice_order_readback/amount")
        .and_then(Value::as_str)
        .unwrap_or(&unit_price);
    let currency = local_execution
        .pointer("/invoice_order_readback/currency")
        .and_then(Value::as_str)
        .unwrap_or(&plan_currency);
    let order_id = value_uuid(local_execution.pointer("/refs/order_id"))
        .or_else(|| value_uuid(local_execution.pointer("/invoice_order_readback/order_id")));
    let invoice_id = value_uuid(local_execution.pointer("/refs/invoice_id"))
        .or_else(|| value_uuid(local_execution.pointer("/invoice_order_readback/invoice_id")));
    let payment_intent_id =
        value_uuid(local_execution.pointer("/invoice_order_readback/payment_intent_id"));
    let provider_source_ref =
        subscription_scheduler_provider_source_ref_plan(db, tenant_id, order_id, payment_intent_id)
            .await?;
    let provider = payment_provider_config_default_provider()?;
    let credential_source =
        payment_provider_merchant_credential_source_readback(db, tenant_id, &provider).await?;
    let credential_config =
        payment_provider_adapter_config_input_for_credential_source(&provider, &credential_source)?;
    let credential_refusal_reason = payment_provider_credential_refusal_reason(&credential_config);
    let handoff_hash = sha256_hex(&format!(
        "subscription-scheduler:payment-capture-handoff:v1:{tenant_id}:{event_id}:{source_hash}"
    ));
    let fingerprint = subscription_scheduler_public_fingerprint(&handoff_hash);
    let local_refs = PaymentProviderRefs {
        order_id: order_id.map(|value| value.to_string()),
        payment_intent_id: payment_intent_id.map(|value| value.to_string()),
        payment_capture_id: None,
        refund_id: None,
        credit_grant_id: value_uuid(local_execution.pointer("/refs/credit_grant_id"))
            .map(|value| value.to_string()),
        ledger_entry_id: value_uuid(local_execution.pointer("/refs/ledger_entry_id"))
            .map(|value| value.to_string()),
        reversal_ledger_entry_id: None,
        invoice_id: invoice_id.map(|value| value.to_string()),
        audit_id: value_uuid(local_execution.pointer("/refs/audit_id"))
            .map(|value| value.to_string()),
    };
    let executor_contract = serde_json::to_value(plan_payment_provider_executor_contract(
        PaymentProviderExecutorRequest {
            provider: provider.clone(),
            action: PaymentProviderExecutorAction::Capture,
            amount: amount.to_string(),
            currency: currency.to_string(),
            reason: "subscription scheduler payment capture handoff".to_string(),
            idempotency: PaymentProviderExecutorIdempotency::hashed(handoff_hash.clone()),
            provider_refs: PaymentProviderExecutorProviderRefs {
                provider_object_ref: provider_source_ref.safe_executor_ref(),
                ..PaymentProviderExecutorProviderRefs::default()
            },
            local_refs: local_refs.clone(),
            gate: PaymentProviderExecutorGateInput {
                adapter_enabled: credential_config.adapter_enabled,
                merchant_connected: credential_config.merchant_account_present,
                credential_present: credential_config.credential_present,
                credential_fingerprint_present: credential_config
                    .credential_fingerprint_prefix
                    .is_some(),
                signature_verified: credential_config.webhook_secret_present,
            },
        },
    ))
    .map_err(|error| AdminError::configuration_error(format!("serialize handoff: {error}")))?;

    let applies_to_capture = matches!(event_type.as_str(), "renew" | "dunning");
    let mut blocked_reasons = Vec::new();
    if !applies_to_capture {
        blocked_reasons.push("event_type_not_payment_capture");
    }
    if !due_now {
        blocked_reasons.push("event_not_due");
    }
    if !matches!(event_status.as_str(), "scheduled" | "replayed") {
        blocked_reasons.push("event_status_not_claimable");
    }
    if local_refs.order_id.is_none() {
        blocked_reasons.push("local_order_ref_missing");
    }
    if local_refs.invoice_id.is_none() {
        blocked_reasons.push("local_invoice_ref_missing");
    }
    if local_refs.payment_intent_id.is_none() {
        blocked_reasons.push("local_payment_intent_ref_missing");
    }
    let provider_source_ready_waiting_fetch = applies_to_capture
        && due_now
        && matches!(event_status.as_str(), "scheduled" | "replayed")
        && local_refs.order_id.is_some()
        && local_refs.invoice_id.is_some()
        && local_refs.payment_intent_id.is_some()
        && provider_source_ref.provider_object_ref_present;

    if !provider_source_ref.provider_object_ref_present {
        blocked_reasons.push("provider_payment_intent_ref_missing");
    }
    if applies_to_capture {
        blocked_reasons.push("provider_capture_execution_disabled");
    }
    if let Some(reason) = credential_refusal_reason {
        blocked_reasons.push(reason);
    }
    let stripe_like_client_request_plan =
        serde_json::to_value(plan_stripe_like_client_request(StripeLikeClientRequest {
            provider: provider.clone(),
            operation: StripeLikeClientOperation::CapturePaymentIntent,
            credential_source: credential_source
                .get("source")
                .and_then(Value::as_str)
                .unwrap_or("unknown")
                .to_string(),
            credential_source_ready: credential_refusal_reason.is_none(),
            merchant_account_ref_present: credential_source
                .get("merchant_account_ref_present")
                .and_then(Value::as_bool)
                .unwrap_or(false),
            idempotency: PaymentProviderExecutorIdempotency::hashed(handoff_hash.clone()),
            provider_refs: PaymentProviderExecutorProviderRefs {
                provider_object_ref: provider_source_ref.safe_executor_ref(),
                ..PaymentProviderExecutorProviderRefs::default()
            },
            amount: Some(amount.to_string()),
            currency: Some(currency.to_string()),
            reason: Some("subscription scheduler payment capture handoff".to_string()),
            local_refs: local_refs.clone(),
        }))
        .map_err(|error| {
            AdminError::configuration_error(format!("serialize stripe-like handoff plan: {error}"))
        })?;
    let provider_capture_reconciliation_plan =
        subscription_scheduler_provider_capture_reconciliation_plan(
            &provider,
            amount,
            currency,
            fingerprint.as_str(),
            &provider_source_ref,
            &local_refs,
            &stripe_like_client_request_plan,
        );

    Ok(json!({
        "schema": "admin_subscription_scheduler_payment_capture_handoff.v1",
        "status": if provider_source_ready_waiting_fetch {
            "provider_source_ready_waiting_fetch"
        } else if applies_to_capture {
            "blocked"
        } else {
            "not_applicable"
        },
        "event_id": event_id,
        "subscription_id": subscription_id,
        "event_type": event_type,
        "event_status": event_status,
        "due_now": due_now,
        "next_provider_executor_action": "capture",
        "ready_for_provider_executor": false,
        "blocked_reasons": blocked_reasons,
        "operator_api_call": {
            "method": "POST",
            "path": "/admin/billing/payment-provider/executor",
            "action": "capture",
            "idempotency_fingerprint": fingerprint,
            "raw_idempotency_key_required_from_ui": false
        },
        "local_refs": {
            "order_id": local_refs.order_id,
            "invoice_id": local_refs.invoice_id,
            "payment_intent_id": local_refs.payment_intent_id,
            "payment_capture_id": Value::Null,
            "local_refs_complete": local_refs.order_id.is_some()
                && local_refs.invoice_id.is_some()
                && local_refs.payment_intent_id.is_some()
        },
        "provider_refs": {
            "provider_object_ref_present": provider_source_ref.provider_object_ref_present,
            "provider_object_ref_source": provider_source_ref.provider_object_ref_source,
            "provider_reference_redacted": provider_source_ref.provider_reference_redacted,
            "provider_reference_fingerprint": provider_source_ref.provider_reference_fingerprint,
            "provider_reference_hash_present": provider_source_ref.provider_reference_hash.is_some(),
            "provider_object_ref_raw_echoed": false
        },
        "provider_source_ref_plan": {
            "schema": "admin_subscription_scheduler_provider_source_ref_plan.v1",
            "status": if provider_source_ref.provider_object_ref_present {
                "provider_source_ready_waiting_fetch"
            } else {
                "blocked"
            },
            "source_priority": [
                "payment_intents.provider_reference_hash",
                "payment_intents.provider_reference_redacted",
                "payment_intents.metadata safe provider ref markers",
                "payment_orders.metadata safe provider ref markers",
                "invoices.metadata safe provider ref markers"
            ],
            "selected_source": provider_source_ref.provider_object_ref_source,
            "payment_intent_id": local_refs.payment_intent_id,
            "order_id": local_refs.order_id,
            "invoice_id": local_refs.invoice_id,
            "provider_object_ref_present": provider_source_ref.provider_object_ref_present,
            "provider_reference_hash_present": provider_source_ref.provider_reference_hash.is_some(),
            "provider_reference_redacted_present": provider_source_ref.provider_reference_redacted.is_some(),
            "provider_reference_redacted": provider_source_ref.provider_reference_redacted,
            "provider_reference_fingerprint": provider_source_ref.provider_reference_fingerprint,
            "metadata_ref_marker_present": provider_source_ref.metadata_ref_marker_present,
            "raw_provider_ref_echoed": false,
            "raw_provider_payload_echoed": false,
            "network_call_enabled": false,
            "network_call_performed": false,
            "writes": {
                "payment_intents": "read_back_only",
                "payment_orders": "read_back_only",
                "invoices": "read_back_only",
                "payment_events": "not_written",
                "payment_captures": "not_written",
                "ledger_entries": "not_written",
                "credit_grants": "not_written"
            }
        },
        "credential_source": {
            "source": credential_source.get("source").cloned().unwrap_or(Value::Null),
            "status": credential_source.get("status").cloned().unwrap_or(Value::Null),
            "ready": credential_refusal_reason.is_none(),
            "adapter_enabled": credential_config.adapter_enabled,
            "merchant_account_ref_present": credential_config.merchant_account_present,
            "credential_secret_ref_present": credential_config.credential_present,
            "credential_fingerprint_prefix_present": credential_config.credential_fingerprint_prefix.is_some()
        },
        "source_of_truth": {
            "provider_object_fetch_required_before_capture": true,
            "provider_object_fetch_summary_required": true,
            "provider_object_fetch_summary_schema": "payment_provider_stripe_like_source_of_truth_summary.v1",
            "expected_reconciliation_schema": PAYMENT_PROVIDER_STRIPE_LIKE_RESPONSE_OBJECT_RECONCILIATION_SCHEMA,
            "network_call_enabled": false,
            "network_call_performed": false,
            "production_payment_evidence": false
        },
        "expected_payment_reconciliation": subscription_scheduler_expected_payment_reconciliation(
            &provider,
            amount,
            currency,
            &provider_source_ref,
            &local_refs,
        ),
        "provider_capture_reconciliation_plan": provider_capture_reconciliation_plan,
        "billing_ledger_executor_contract": executor_contract,
        "stripe_like_client_request_plan": stripe_like_client_request_plan,
        "idempotency": {
            "source": "subscription_events_or_schedules.idempotency_key_hash",
            "fingerprint": fingerprint,
            "raw_idempotency_key_echoed": false,
            "key_hash_returned": false
        },
        "writes": {
            "payment_events": "not_written",
            "payment_captures": "not_written",
            "payment_orders": "read_back_only",
            "payment_intents": "read_back_only",
            "invoices": "read_back_only",
            "ledger_entries": "not_written",
            "credit_grants": "not_written"
        },
        "payment_capture_executed": false,
        "network_call_enabled": false,
        "network_call_performed": false,
        "secret_safe": true,
        "raw_payment_payload_returned": false,
        "raw_provider_payload_returned": false,
        "authorization_returned": false,
        "provider_secret_returned": false,
        "raw_idempotency_key_echoed": false
    }))
}

fn subscription_scheduler_provider_capture_reconciliation_plan(
    provider: &str,
    amount: &str,
    currency: &str,
    idempotency_fingerprint: &str,
    provider_source_ref: &SubscriptionSchedulerProviderSourceRefPlan,
    local_refs: &PaymentProviderRefs,
    stripe_like_client_request_plan: &Value,
) -> Value {
    json!({
        "schema": "admin_subscription_scheduler_provider_capture_reconciliation_plan.v1",
        "status": if provider_source_ref.provider_object_ref_present {
            "provider_source_ready_waiting_fetch"
        } else {
            "blocked"
        },
        "provider": provider,
        "action": "capture",
        "operator_api_call": {
            "method": "POST",
            "path": "/admin/billing/payment-provider/executor",
            "mode": "source_of_truth_fetch_then_capture_plan",
            "action": "capture",
            "idempotency_fingerprint": idempotency_fingerprint,
            "request_fields": {
                "provider": provider,
                "action": "capture",
                "amount": amount,
                "currency": currency,
                "reason": "subscription scheduler provider-backed capture reconciliation",
                "provider_refs": {
                    "provider_object_ref": "safe_hash_or_redacted_ref_from_provider_source_ref_plan"
                },
                "local_refs": "order_id invoice_id payment_intent_id from scheduler handoff"
            },
            "raw_idempotency_key_required_from_ui": false
        },
        "provider_object_fetch_summary": {
            "required_before_capture": true,
            "schema": "payment_provider_stripe_like_source_of_truth_summary.v1",
            "accepted_sources": [
                "stripe_like_fetch_executor",
                "production_reconciliation_readback"
            ],
            "required_fields": [
                "provider_object_ref_present",
                "provider_object_type",
                "amount",
                "currency",
                "capture_status",
                "source_of_truth_status"
            ],
            "raw_provider_payload_allowed": false,
            "network_call_performed_by_scheduler": false
        },
        "executor_source_of_truth": {
            "executor_endpoint": "/admin/billing/payment-provider/executor",
            "executor_contract_schema": "payment_provider_executor_contract.v1",
            "stripe_like_client_request_plan_schema": stripe_like_client_request_plan.get("schema").cloned().unwrap_or(Value::Null),
            "fetch_executor_schema": "payment_provider_stripe_like_fetch_executor.v1",
            "response_object_reconciliation_schema": PAYMENT_PROVIDER_STRIPE_LIKE_RESPONSE_OBJECT_RECONCILIATION_SCHEMA,
            "scheduler_is_not_source_of_truth": true
        },
        "expected_payment_reconciliation": subscription_scheduler_expected_payment_reconciliation(
            provider,
            amount,
            currency,
            provider_source_ref,
            local_refs,
        ),
        "expected_reconciliation_schema": PAYMENT_PROVIDER_STRIPE_LIKE_RESPONSE_OBJECT_RECONCILIATION_SCHEMA,
        "status_mapping": {
            "payment_reconciliation_matched": {
                "candidate_status": "matched",
                "subscription_handoff_status": "provider_capture_reconciliation_matched_waiting_executor_apply",
                "local_write_allowed_by_scheduler_handoff": false,
                "next_action": "operator_or_payment_executor_may_apply_capture_using_reconciled_candidate"
            },
            "payment_reconciliation_mismatch": {
                "candidate_status": "mismatch",
                "subscription_handoff_status": "blocked",
                "local_write_allowed_by_scheduler_handoff": false,
                "next_action": "do_not_apply_subscription_capture_review_payment_mismatch"
            },
            "payment_reconciliation_blocked": {
                "candidate_status": "blocked",
                "subscription_handoff_status": "provider_source_ready_waiting_fetch",
                "local_write_allowed_by_scheduler_handoff": false,
                "next_action": "load_provider_object_summary_or_retry_fetch_before_local_write"
            }
        },
        "next_action": if provider_source_ref.provider_object_ref_present {
            "call_payment_provider_executor_with_fixture_or_real_provider_readback_then_consume_stripe_like_response_object_reconciliation"
        } else {
            "attach_safe_provider_payment_intent_ref_before_payment_reconciliation"
        },
        "success_local_ref_updates": {
            "payment_intents": [
                "status",
                "provider_reference_hash/provider_reference_redacted readback marker when executor returns safe ref"
            ],
            "payment_orders": [
                "status",
                "payment_intent_id linkage readback"
            ],
            "invoices": [
                "status",
                "order_id/payment_intent_id linkage readback"
            ],
            "subscription_events_or_schedules": [
                "metadata.provider_capture_reconciliation",
                "event_status only after executor readback is accepted"
            ],
            "payment_captures": "not_written_by_scheduler_handoff",
            "ledger_entries": "not_written_by_scheduler_handoff",
            "credit_grants": "not_written_by_scheduler_handoff"
        },
        "preconditions": {
            "provider_object_ref_present": provider_source_ref.provider_object_ref_present,
            "provider_reference_hash_present": provider_source_ref.provider_reference_hash.is_some(),
            "provider_reference_redacted_present": provider_source_ref.provider_reference_redacted.is_some(),
            "local_refs_complete": local_refs.order_id.is_some()
                && local_refs.invoice_id.is_some()
                && local_refs.payment_intent_id.is_some()
        },
        "blocked_reasons": if provider_source_ref.provider_object_ref_present {
            json!(["expected_payment_reconciliation_missing", "provider_object_fetch_summary_missing", "provider_capture_not_executed_by_scheduler"])
        } else {
            json!(["provider_payment_intent_ref_missing"])
        },
        "writes": {
            "scheduler_handoff": "readback_only",
            "payment_events": "not_written",
            "payment_captures": "not_written",
            "ledger_entries": "not_written",
            "credit_grants": "not_written"
        },
        "network_call_enabled": false,
        "network_call_performed": false,
        "secret_safe": true,
        "raw_provider_ref_echoed": false,
        "raw_provider_payload_echoed": false,
        "authorization_returned": false,
        "provider_secret_returned": false,
        "raw_idempotency_key_echoed": false
    })
}

fn subscription_scheduler_expected_payment_reconciliation(
    provider: &str,
    amount: &str,
    currency: &str,
    provider_source_ref: &SubscriptionSchedulerProviderSourceRefPlan,
    local_refs: &PaymentProviderRefs,
) -> Value {
    json!({
        "schema": "admin_subscription_scheduler_expected_payment_reconciliation.v1",
        "status": if provider_source_ref.provider_object_ref_present {
            "waiting_for_payment_reconciliation_candidate"
        } else {
            "blocked_provider_object_ref_missing"
        },
        "candidate_schema": PAYMENT_PROVIDER_STRIPE_LIKE_RESPONSE_OBJECT_RECONCILIATION_SCHEMA,
        "candidate_source": "/admin/billing/payment-provider/executor.data.stripe_like_response_object_reconciliation",
        "provider": provider,
        "action": "capture",
        "amount": amount,
        "currency": currency,
        "expected_provider_object_types": ["payment_intent", "charge"],
        "expected_provider_statuses": ["succeeded"],
        "expected_local_refs": ["payment_intent_id"],
        "local_refs": {
            "order_id_present": local_refs.order_id.is_some(),
            "invoice_id_present": local_refs.invoice_id.is_some(),
            "payment_intent_id_present": local_refs.payment_intent_id.is_some(),
            "payment_capture_id_present": local_refs.payment_capture_id.is_some()
        },
        "status_mapping": {
            "matched": "provider_capture_reconciliation_matched_waiting_executor_apply",
            "mismatch": "blocked_review_payment_reconciliation_mismatch",
            "blocked": "provider_source_ready_waiting_fetch"
        },
        "safe_next_action_mapping": {
            "matched": "accept_reconciliation_candidate_then_apply_or_replay_local_action_in_payment_executor",
            "mismatch": "do_not_apply_local_action_review_mismatch_reasons",
            "blocked_retryable": "retry_provider_object_fetch_after_backoff_without_local_write",
            "blocked_missing_summary": "load_provider_object_summary_before_local_write"
        },
        "scheduler_handoff_consumes_candidate_only": true,
        "payment_logic_reimplemented_by_subscription": false,
        "network_call_enabled": false,
        "network_call_performed": false,
        "writes": {
            "payment_captures": "not_written_by_subscription_handoff",
            "ledger_entries": "not_written_by_subscription_handoff",
            "credit_grants": "not_written_by_subscription_handoff"
        },
        "secret_safe": true,
        "raw_provider_payload_echoed": false,
        "raw_provider_ref_echoed": false,
        "authorization_returned": false,
        "provider_secret_returned": false
    })
}

fn subscription_scheduler_local_writes_limited_to(
    mode: &str,
    event_type: &str,
    credit_grant_id: Option<Uuid>,
    ledger_entry_id: Option<Uuid>,
    invoice_id: Option<Uuid>,
    order_id: Option<Uuid>,
    subscription_rows_updated: u64,
) -> Value {
    let mut writes = vec![
        "subscription_events_or_schedules.event_status",
        "subscription_events_or_schedules.metadata",
        "subscription_events_or_schedules.refusal_code",
    ];
    if subscription_rows_updated > 0 {
        writes.push("subscriptions");
    }
    if mode == "apply" && matches!(event_type, "renew" | "prorate") && credit_grant_id.is_some() {
        writes.push("credit_grants");
    }
    if mode == "apply" && matches!(event_type, "renew" | "prorate") && ledger_entry_id.is_some() {
        writes.push("ledger_entries");
    }
    if mode == "apply" && matches!(event_type, "renew" | "prorate") && order_id.is_some() {
        writes.push("payment_orders");
        writes.push("payment_intents");
    }
    if mode == "apply" && matches!(event_type, "renew" | "prorate") && invoice_id.is_some() {
        writes.push("invoices");
    }
    json!(writes)
}

fn subscription_scheduler_local_executor_steps(
    event_type: &str,
    subscription_updated: bool,
    ledger_written: bool,
    credit_written: bool,
    invoice_order_linked: bool,
) -> Value {
    match event_type {
        "renew" => json!([
            {"name": "payment_capture", "status": "payment_provider_capture_required", "executed": false},
            {"name": "invoice_order_linkage", "status": if invoice_order_linked { "linked" } else { "not_linked" }, "executed": invoice_order_linked},
            {"name": "subscription_period_advance", "status": if subscription_updated { "applied" } else { "not_applied" }, "executed": subscription_updated},
            {"name": "credit_grant", "status": if credit_written { "read_back" } else { "not_written" }, "executed": credit_written},
            {"name": "ledger_credit_grant_entry", "status": if ledger_written { "read_back" } else { "not_written" }, "executed": ledger_written}
        ]),
        "payment_failed" | "dunning" => json!([
            {"name": "payment_capture", "status": "payment_provider_capture_required", "executed": false},
            {"name": "subscription_status_update", "status": if subscription_updated { "payment_failed_recorded" } else { "not_applied" }, "executed": subscription_updated},
            {"name": "retry_or_dunning_marker", "status": "metadata_recorded", "executed": subscription_updated}
        ]),
        "prorate" => json!([
            {"name": "calculate_proration_delta", "status": "bounded_plan_change_only", "executed": subscription_updated},
            {"name": "invoice_order_linkage", "status": if invoice_order_linked { "linked" } else { "not_linked" }, "executed": invoice_order_linked},
            {"name": "negative_proration_credit_adjustment", "status": if credit_written || ledger_written { "recorded" } else { "not_written" }, "executed": credit_written || ledger_written},
            {"name": "payment_capture", "status": "payment_provider_capture_required", "executed": false},
            {"name": "subscription_plan_change", "status": if subscription_updated { "applied" } else { "not_applied" }, "executed": subscription_updated}
        ]),
        "expire" => json!([
            {"name": "expire_subscription_access", "status": if subscription_updated { "applied" } else { "not_applied" }, "executed": subscription_updated},
            {"name": "stop_future_renewal", "status": "local_status_recorded", "executed": subscription_updated}
        ]),
        _ => json!([
            {"name": "record_lifecycle_event", "status": "event_status_recorded", "executed": subscription_updated}
        ]),
    }
}

fn normalize_subscription_scheduler_action(action: Option<String>) -> Result<String, AdminError> {
    match action
        .unwrap_or_else(|| "all".to_string())
        .trim()
        .to_ascii_lowercase()
        .as_str()
    {
        "all" => Ok("all".to_string()),
        "renewal" | "renew" => Ok("renewal".to_string()),
        "grace" => Ok("grace".to_string()),
        "dunning" => Ok("dunning".to_string()),
        "proration" | "prorate" => Ok("proration".to_string()),
        _ => Err(AdminError::bad_request(
            "action must be all, renewal, grace, dunning, or proration",
        )),
    }
}

fn subscription_scheduler_candidate_response(
    row: &PgRow,
    action: &str,
    target_plan_id: Option<Uuid>,
) -> Result<Value, AdminError> {
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;
    let status: String = row.try_get("status").map_err(db_row_error)?;
    let renewal_due: bool = row.try_get("renewal_due").map_err(db_row_error)?;
    let renewal_upcoming: bool = row.try_get("renewal_upcoming").map_err(db_row_error)?;
    let in_grace: bool = row.try_get("in_grace").map_err(db_row_error)?;
    let in_dunning: bool = row.try_get("in_dunning").map_err(db_row_error)?;
    let current_period_end: String = row.try_get("current_period_end").map_err(db_row_error)?;
    let grace_ends_at: String = row.try_get("grace_ends_at").map_err(db_row_error)?;
    let next_dunning_attempt_at: String = row
        .try_get("next_dunning_attempt_at")
        .map_err(db_row_error)?;
    let expire_at: String = row.try_get("expire_at").map_err(db_row_error)?;
    let plan_id: Uuid = row.try_get("plan_id").map_err(db_row_error)?;
    let scheduled_event_count: i64 = row.try_get("scheduled_event_count").map_err(db_row_error)?;
    let proration_status = if target_plan_id.is_some_and(|id| id != plan_id) {
        "plan_change_pending_proration"
    } else if target_plan_id == Some(plan_id) {
        "same_plan_no_proration"
    } else {
        "not_requested"
    };
    let planned_events =
        subscription_scheduler_planned_event_types(&status, action, target_plan_id, plan_id);
    let execution_plan_readbacks = planned_events
        .iter()
        .map(|event_type| plan_subscription_scheduler_execution(event_type, "dry_run", "scheduled"))
        .collect::<Vec<_>>();

    Ok(json!({
        "subscription_id": subscription_id,
        "project_id": row.try_get::<Option<Uuid>, _>("project_id").map_err(db_row_error)?,
        "wallet_id": row.try_get::<Uuid, _>("wallet_id").map_err(db_row_error)?,
        "plan_id": plan_id,
        "target_plan_id": target_plan_id,
        "plan_code": row.try_get::<String, _>("plan_code").map_err(db_row_error)?,
        "status": status,
        "currency": row.try_get::<String, _>("currency").map_err(db_row_error)?,
        "billing_interval": row.try_get::<String, _>("billing_interval").map_err(db_row_error)?,
        "period": {
            "start": row.try_get::<String, _>("current_period_start").map_err(db_row_error)?,
            "end": current_period_end
        },
        "renewal": {
            "status": if renewal_due {
                "due_now"
            } else if renewal_upcoming {
                "upcoming"
            } else {
                "scheduled"
            },
            "next_action": if planned_events.iter().any(|event| *event == "renew") {
                "schedule_renew_event"
            } else {
                "readback_only"
            },
            "effective_at": row.try_get::<String, _>("current_period_end").map_err(db_row_error)?,
            "invoice_order_ledger_credit_writes": false
        },
        "grace": {
            "status": if in_grace { "in_grace" } else { "not_in_grace" },
            "grace_days": 3,
            "ends_at": grace_ends_at,
            "next_action": if action == "grace" { "schedule_payment_failed_grace_marker" } else { "readback_only" },
            "subscription_status_update": false
        },
        "dunning": {
            "status": if in_dunning { "in_dunning" } else if status == "payment_failed" { "pending_grace_window" } else { "not_in_dunning" },
            "next_attempt_at": next_dunning_attempt_at,
            "max_attempts": 3,
            "next_action": if planned_events.iter().any(|event| *event == "dunning") { "schedule_dunning_event" } else { "readback_only" },
            "provider_charge_attempt": false
        },
        "proration": {
            "status": proration_status,
            "next_action": if planned_events.iter().any(|event| *event == "prorate") { "schedule_proration_event" } else { "readback_only" },
            "target_plan_id": target_plan_id,
            "estimated_amount": null,
            "ledger_write": false
        },
        "expire": {
            "status": if in_dunning { "eligible_after_dunning_window" } else { "not_scheduled" },
            "effective_at": expire_at,
            "next_action": if planned_events.iter().any(|event| *event == "expire") { "schedule_expire_event" } else { "readback_only" }
        },
        "planned_event_types": planned_events,
        "execution_plan_readbacks": execution_plan_readbacks,
        "existing_scheduled_event_count": scheduled_event_count,
        "subscription_lifecycle_readback": subscription_scheduler_candidate_lifecycle_readback(
            subscription_id,
            plan_id,
            row.try_get::<String, _>("plan_code").map_err(db_row_error)?,
            status.clone(),
            row.try_get::<String, _>("current_period_start").map_err(db_row_error)?,
            current_period_end.clone(),
            row.try_get::<String, _>("billing_interval").map_err(db_row_error)?,
            row.try_get::<String, _>("currency").map_err(db_row_error)?,
            row.try_get::<String, _>("included_credit_amount").map_err(db_row_error)?,
            scheduled_event_count,
            &planned_events,
            proration_status,
        ),
        "next_action": "Use mode=apply to write scheduled event rows only; payment provider, invoice/order, ledger, and credit grant effects remain disabled.",
        "secret_safe": true,
        "raw_payment_payload_returned": false,
        "raw_provider_payload_returned": false,
        "raw_idempotency_key_echoed": false
    }))
}

fn subscription_scheduler_candidate_lifecycle_readback(
    subscription_id: Uuid,
    plan_id: Uuid,
    plan_code: String,
    subscription_status: String,
    current_period_start: String,
    current_period_end: String,
    billing_interval: String,
    currency: String,
    included_credit_amount: String,
    scheduled_event_count: i64,
    planned_events: &[&str],
    proration_status: &str,
) -> Value {
    json!({
        "schema": "subscription_lifecycle_readback.v1",
        "source": "subscription_scheduler_plan_candidate",
        "current_plan": {
            "subscription_id": subscription_id,
            "plan_id": plan_id,
            "plan_code": plan_code,
            "subscription_status": subscription_status,
            "billing_interval": billing_interval,
            "currency": currency
        },
        "period_status": {
            "status": if planned_events.iter().any(|event| *event == "renew") { "renewal_candidate" } else if proration_status == "plan_change_pending_proration" { "proration_candidate" } else { "readback_only" },
            "current_period_start": current_period_start,
            "current_period_end": current_period_end
        },
        "quota_or_credit_grant_refs_presence": {
            "included_credit_amount": included_credit_amount,
            "credit_grant_ref_present": false,
            "ledger_entry_ref_present": false,
            "quota_ref_present": false,
            "credit_automation_status": "not_written_by_scheduler_plan"
        },
        "scheduler_event_refs_presence": {
            "subscription_event_ref_present": scheduled_event_count > 0,
            "scheduled_event_count": scheduled_event_count,
            "planned_event_types": planned_events,
            "scheduler_status": if planned_events.is_empty() { "no_event_planned" } else { "event_plannable" }
        },
        "payment_handoff_status": {
            "status": "not_started",
            "payment_capture_handoff_present": false,
            "payment_provider_executor_handoff_present": false,
            "refund_or_credit_note_handoff_present": false,
            "provider_source_ref_present": false,
            "network_call_performed": false
        },
        "safe_next_action": if planned_events.is_empty() { "No scheduler event is needed for the selected action; keep this as readback only." } else { "Use mode=apply to create bounded scheduler event refs only, then execute the event through the worker/readback endpoints." },
        "forbidden_material_returned": false,
        "secret_safe": true,
        "raw_provider_payload_returned": false,
        "authorization_returned": false,
        "raw_invoice_metadata_returned": false,
        "provider_secret_returned": false
    })
}

fn subscription_scheduler_planned_event_types(
    status: &str,
    action: &str,
    target_plan_id: Option<Uuid>,
    current_plan_id: Uuid,
) -> Vec<&'static str> {
    match action {
        "renewal" => vec!["renew"],
        "grace" => vec!["payment_failed"],
        "dunning" => {
            if status == "payment_failed" {
                vec!["dunning", "expire"]
            } else {
                Vec::new()
            }
        }
        "proration" => {
            if target_plan_id.is_some_and(|id| id != current_plan_id) {
                vec!["prorate"]
            } else {
                Vec::new()
            }
        }
        _ => {
            if status == "payment_failed" {
                vec!["dunning", "expire"]
            } else {
                vec!["renew"]
            }
        }
    }
}

fn subscription_scheduler_event_execute_response(
    row: &PgRow,
    mode: &str,
    before_status: &str,
) -> Result<Value, AdminError> {
    let event_type: String = row.try_get("event_type").map_err(db_row_error)?;
    let idempotency_key_hash: String = row.try_get("idempotency_key_hash").map_err(db_row_error)?;
    let execution_plan_readback =
        plan_subscription_scheduler_execution(&event_type, mode, before_status);
    let execution_plan = match event_type.as_str() {
        "renew" => json!({
            "kind": "renewal",
            "steps": [
                {"name": "payment_capture", "status": "boundary_only", "executed": false},
                {"name": "invoice_order_linkage", "status": "boundary_only", "executed": false},
                {"name": "ledger_settlement", "status": "boundary_only", "executed": false},
                {"name": "credit_grant", "status": "boundary_only", "executed": false},
                {"name": "subscription_period_advance", "status": "boundary_only", "executed": false}
            ],
            "worker_handoff_status": if before_status == "scheduled" || before_status == "replayed" { "ready" } else { "readback_only" },
            "next_worker_status": "applied_or_refused"
        }),
        "payment_failed" => json!({
            "kind": "grace",
            "steps": [
                {"name": "mark_payment_failed", "status": "boundary_only", "executed": false},
                {"name": "start_grace_window", "status": "boundary_only", "executed": false}
            ],
            "worker_handoff_status": if before_status == "scheduled" || before_status == "replayed" { "ready" } else { "readback_only" },
            "next_worker_status": "applied_or_refused"
        }),
        "dunning" => json!({
            "kind": "dunning",
            "steps": [
                {"name": "retry_payment_capture", "status": "boundary_only", "executed": false},
                {"name": "record_retry_attempt", "status": "boundary_only", "executed": false},
                {"name": "schedule_next_retry_or_expire", "status": "boundary_only", "executed": false}
            ],
            "max_attempts": 3,
            "worker_handoff_status": if before_status == "scheduled" || before_status == "replayed" { "ready" } else { "readback_only" },
            "next_worker_status": "applied_or_refused"
        }),
        "prorate" => json!({
            "kind": "proration",
            "steps": [
                {"name": "calculate_proration_delta", "status": "boundary_only", "executed": false},
                {"name": "invoice_or_credit_adjustment", "status": "boundary_only", "executed": false},
                {"name": "ledger_adjustment", "status": "boundary_only", "executed": false},
                {"name": "plan_change_commit", "status": "boundary_only", "executed": false}
            ],
            "estimated_amount": null,
            "worker_handoff_status": if before_status == "scheduled" || before_status == "replayed" { "ready" } else { "readback_only" },
            "next_worker_status": "applied_or_refused"
        }),
        "expire" => json!({
            "kind": "expiration",
            "steps": [
                {"name": "expire_subscription_access", "status": "boundary_only", "executed": false},
                {"name": "stop_future_renewal", "status": "boundary_only", "executed": false}
            ],
            "worker_handoff_status": if before_status == "scheduled" || before_status == "replayed" { "ready" } else { "readback_only" },
            "next_worker_status": "applied_or_refused"
        }),
        _ => json!({
            "kind": "lifecycle",
            "steps": [
                {"name": "record_lifecycle_event", "status": "boundary_only", "executed": false}
            ],
            "worker_handoff_status": "readback_only",
            "next_worker_status": "applied_or_refused"
        }),
    };

    let refs = json!({
        "credit_grant_id": row.try_get::<Option<Uuid>, _>("credit_grant_id").map_err(db_row_error)?,
        "ledger_entry_id": row.try_get::<Option<Uuid>, _>("ledger_entry_id").map_err(db_row_error)?,
        "invoice_id": row.try_get::<Option<Uuid>, _>("invoice_id").map_err(db_row_error)?,
        "order_id": row.try_get::<Option<Uuid>, _>("order_id").map_err(db_row_error)?,
        "audit_id": row.try_get::<Option<Uuid>, _>("audit_id").map_err(db_row_error)?,
        "refusal_code": row.try_get::<Option<String>, _>("refusal_code").map_err(db_row_error)?
    });

    Ok(json!({
        "id": row.try_get::<Uuid, _>("id").map_err(db_row_error)?,
        "subscription_id": row.try_get::<Uuid, _>("subscription_id").map_err(db_row_error)?,
        "project_id": row.try_get::<Option<Uuid>, _>("project_id").map_err(db_row_error)?,
        "wallet_id": row.try_get::<Uuid, _>("wallet_id").map_err(db_row_error)?,
        "plan_id": row.try_get::<Uuid, _>("plan_id").map_err(db_row_error)?,
        "plan_code": row.try_get::<String, _>("plan_code").map_err(db_row_error)?,
        "event_type": event_type,
        "event_status": before_status,
        "effective_at": row.try_get::<String, _>("effective_at").map_err(db_row_error)?,
        "created_at": row.try_get::<String, _>("created_at").map_err(db_row_error)?,
        "updated_at": row.try_get::<String, _>("updated_at").map_err(db_row_error)?,
        "subscription_status": row.try_get::<String, _>("subscription_status").map_err(db_row_error)?,
        "period": {
            "start": row.try_get::<String, _>("current_period_start").map_err(db_row_error)?,
            "end": row.try_get::<String, _>("current_period_end").map_err(db_row_error)?
        },
        "billing": {
            "currency": row.try_get::<String, _>("currency").map_err(db_row_error)?,
            "billing_interval": row.try_get::<String, _>("billing_interval").map_err(db_row_error)?,
            "unit_price": row.try_get::<String, _>("unit_price").map_err(db_row_error)?,
            "included_credit_amount": row.try_get::<String, _>("included_credit_amount").map_err(db_row_error)?
        },
        "refs": refs.clone(),
        "subscription_lifecycle_readback": subscription_scheduler_event_lifecycle_readback(
            row.try_get::<Uuid, _>("subscription_id").map_err(db_row_error)?,
            row.try_get::<Uuid, _>("plan_id").map_err(db_row_error)?,
            row.try_get::<String, _>("plan_code").map_err(db_row_error)?,
            row.try_get::<String, _>("subscription_status").map_err(db_row_error)?,
            row.try_get::<String, _>("current_period_start").map_err(db_row_error)?,
            row.try_get::<String, _>("current_period_end").map_err(db_row_error)?,
            row.try_get::<String, _>("billing_interval").map_err(db_row_error)?,
            row.try_get::<String, _>("currency").map_err(db_row_error)?,
            row.try_get::<String, _>("included_credit_amount").map_err(db_row_error)?,
            event_type.as_str(),
            before_status,
            mode,
            &refs,
        ),
        "execute_mode": mode,
        "target_event_status": subscription_scheduler_execute_target_status(mode),
        "execution_plan": execution_plan_readback,
        "legacy_execution_plan": execution_plan,
        "idempotency_key_fingerprint": subscription_scheduler_public_fingerprint(&idempotency_key_hash),
        "metadata_policy": {
            "request_summary_returned": false,
            "raw_metadata_returned": false,
            "safe_metadata_recordable": true
        },
        "secret_safe": true,
        "raw_payment_payload_returned": false,
        "raw_provider_payload_returned": false,
        "authorization_returned": false,
        "raw_invoice_metadata_returned": false,
        "raw_idempotency_key_echoed": false
    }))
}

fn subscription_scheduler_event_lifecycle_readback(
    subscription_id: Uuid,
    plan_id: Uuid,
    plan_code: String,
    subscription_status: String,
    current_period_start: String,
    current_period_end: String,
    billing_interval: String,
    currency: String,
    included_credit_amount: String,
    event_type: &str,
    event_status: &str,
    mode: &str,
    refs: &Value,
) -> Value {
    let credit_grant_ref_present = refs
        .get("credit_grant_id")
        .is_some_and(|value| !value.is_null());
    let ledger_entry_ref_present = refs
        .get("ledger_entry_id")
        .is_some_and(|value| !value.is_null());
    let invoice_ref_present = refs.get("invoice_id").is_some_and(|value| !value.is_null());
    let order_ref_present = refs.get("order_id").is_some_and(|value| !value.is_null());
    let audit_ref_present = refs.get("audit_id").is_some_and(|value| !value.is_null());
    let payment_handoff_expected = matches!(event_type, "renew" | "dunning");
    let refund_handoff_expected = event_type == "prorate";

    json!({
        "schema": "subscription_lifecycle_readback.v1",
        "source": "subscription_scheduler_event",
        "current_plan": {
            "subscription_id": subscription_id,
            "plan_id": plan_id,
            "plan_code": plan_code,
            "subscription_status": subscription_status,
            "billing_interval": billing_interval,
            "currency": currency
        },
        "period_status": {
            "status": match event_type {
                "renew" => "renewal_event",
                "payment_failed" => "payment_failed_grace_event",
                "dunning" => "dunning_event",
                "expire" => "expiration_event",
                "prorate" => "proration_event",
                _ => "lifecycle_event"
            },
            "current_period_start": current_period_start,
            "current_period_end": current_period_end,
            "event_type": event_type,
            "event_status": event_status,
            "execute_mode": mode
        },
        "quota_or_credit_grant_refs_presence": {
            "included_credit_amount": included_credit_amount,
            "credit_grant_ref_present": credit_grant_ref_present,
            "ledger_entry_ref_present": ledger_entry_ref_present,
            "quota_ref_present": credit_grant_ref_present || ledger_entry_ref_present,
            "credit_automation_status": if credit_grant_ref_present || ledger_entry_ref_present { "local_ref_present" } else { "not_recorded_or_not_applicable" }
        },
        "scheduler_event_refs_presence": {
            "subscription_event_ref_present": true,
            "audit_ref_present": audit_ref_present,
            "invoice_ref_present": invoice_ref_present,
            "order_ref_present": order_ref_present,
            "scheduler_status": event_status
        },
        "payment_handoff_status": {
            "status": if payment_handoff_expected { "provider_capture_handoff_required" } else if refund_handoff_expected { "refund_or_credit_note_handoff_required_if_negative_proration" } else { "not_applicable" },
            "payment_capture_handoff_present": payment_handoff_expected,
            "payment_provider_executor_handoff_present": payment_handoff_expected || refund_handoff_expected,
            "refund_or_credit_note_handoff_present": refund_handoff_expected,
            "provider_source_ref_present": invoice_ref_present || order_ref_present,
            "network_call_performed": false
        },
        "safe_next_action": match (mode, event_status) {
            ("dry_run", _) => "Review the lifecycle refs, then call execute-plan with apply/refuse/replay and a reason if a local status transition is intended.",
            (_, "scheduled") | (_, "replayed") => "Use the bounded scheduler worker execution readback; do not treat provider capture as complete without payment executor reconciliation.",
            _ => "Read back local refs and payment executor handoff status before any provider-backed capture or refund decision."
        },
        "forbidden_material_returned": false,
        "secret_safe": true,
        "raw_provider_payload_returned": false,
        "authorization_returned": false,
        "raw_invoice_metadata_returned": false,
        "provider_secret_returned": false
    })
}

fn subscription_scheduler_worker_event_response(row: &PgRow) -> Result<Value, AdminError> {
    let event_status: String = row.try_get("event_status").map_err(db_row_error)?;
    let event_type: String = row.try_get("event_type").map_err(db_row_error)?;
    let idempotency_key_hash: String = row.try_get("idempotency_key_hash").map_err(db_row_error)?;
    let metadata = row
        .try_get::<Value, _>("metadata")
        .unwrap_or_else(|_| json!({}));
    let lease_readback = metadata
        .get("worker_lease")
        .and_then(|value| value.as_object())
        .map(|lease| {
            json!({
                "status": "metadata_present",
                "worker_id": lease.get("worker_id").cloned().unwrap_or(json!("omitted")),
                "lease_seconds": lease.get("lease_seconds").cloned().unwrap_or(json!(null)),
                "event_status_changed": lease.get("event_status_changed").cloned().unwrap_or(json!(false))
            })
        })
        .unwrap_or_else(|| {
            json!({
                "status": "not_leased",
                "worker_id": null,
                "lease_seconds": null,
                "event_status_changed": false
            })
        });

    Ok(json!({
        "id": row.try_get::<Uuid, _>("id").map_err(db_row_error)?,
        "subscription_id": row.try_get::<Uuid, _>("subscription_id").map_err(db_row_error)?,
        "project_id": row.try_get::<Option<Uuid>, _>("project_id").map_err(db_row_error)?,
        "wallet_id": row.try_get::<Uuid, _>("wallet_id").map_err(db_row_error)?,
        "plan_id": row.try_get::<Uuid, _>("plan_id").map_err(db_row_error)?,
        "plan_code": row.try_get::<String, _>("plan_code").map_err(db_row_error)?,
        "event_type": event_type,
        "event_status": event_status,
        "effective_at": row.try_get::<String, _>("effective_at").map_err(db_row_error)?,
        "due_now": row.try_get::<bool, _>("due_now").map_err(db_row_error)?,
        "created_at": row.try_get::<String, _>("created_at").map_err(db_row_error)?,
        "updated_at": row.try_get::<String, _>("updated_at").map_err(db_row_error)?,
        "subscription_status": row.try_get::<String, _>("subscription_status").map_err(db_row_error)?,
        "billing": {
            "currency": row.try_get::<String, _>("currency").map_err(db_row_error)?,
            "billing_interval": row.try_get::<String, _>("billing_interval").map_err(db_row_error)?,
            "unit_price": row.try_get::<String, _>("unit_price").map_err(db_row_error)?,
            "included_credit_amount": row.try_get::<String, _>("included_credit_amount").map_err(db_row_error)?
        },
        "worker_handoff": {
            "claimable": event_status == "scheduled" || event_status == "replayed",
            "lease": lease_readback,
            "execute_plan_available": true,
            "payment_capture_executed": false,
            "invoice_order_ledger_credit_writes": false
        },
        "execution_plan": plan_subscription_scheduler_execution(&event_type, "dry_run", &event_status),
        "idempotency_key_fingerprint": subscription_scheduler_public_fingerprint(&idempotency_key_hash),
        "secret_safe": true,
        "raw_payment_payload_returned": false,
        "raw_provider_payload_returned": false,
        "authorization_returned": false,
        "raw_invoice_metadata_returned": false,
        "raw_idempotency_key_echoed": false
    }))
}

async fn subscription_scheduler_apply_events(
    pool: &PgPool,
    row: &PgRow,
    action: &str,
    target_plan_id: Option<Uuid>,
    reason: &str,
) -> Result<Vec<Value>, AdminError> {
    let subscription_id: Uuid = row.try_get("subscription_id").map_err(db_row_error)?;
    let plan_id: Uuid = row.try_get("plan_id").map_err(db_row_error)?;
    let status: String = row.try_get("status").map_err(db_row_error)?;
    let events =
        subscription_scheduler_planned_event_types(&status, action, target_plan_id, plan_id);
    let mut written = Vec::new();
    for event_type in events {
        let effective_at = subscription_scheduler_event_effective_at(row, event_type)?;
        let idempotency_key_hash = subscription_scheduler_idempotency_hash(
            DEFAULT_TENANT_ID,
            subscription_id,
            event_type,
            effective_at.as_deref().unwrap_or("now"),
            target_plan_id,
        );
        let request_summary = json!({
            "source": "admin_subscription_scheduler_plan",
            "mode": "apply",
            "action": action,
            "event_type": event_type,
            "target_plan_id": target_plan_id,
            "reason_present": true,
            "raw_idempotency_key": "omitted",
            "raw_payment_payload": "omitted",
            "raw_provider_payload": "omitted"
        });
        let safe_reason = redact_secrets(reason);
        let metadata = json!({
            "schema": "admin_subscription_scheduler_event_metadata.v1",
            "reason": safe_reason,
            "local_only": true,
            "merchant_connected": false,
            "provider_payload": "omitted",
            "authorization": "omitted",
            "invoice_order_ledger_credit_writes": false
        });
        let row = sqlx::query(
            r#"
            insert into subscription_events_or_schedules (
              tenant_id, subscription_id, event_type, event_status, effective_at,
              idempotency_key_hash, request_summary, metadata
            )
            values (
              $1, $2, $3, 'scheduled',
              case when $3 in ('prorate', 'payment_failed') then now() else $4::timestamptz end,
              $5, $6::jsonb, $7::jsonb
            )
            on conflict (tenant_id, idempotency_key_hash) do update
              set updated_at = subscription_events_or_schedules.updated_at
            returning id, event_type, event_status, effective_at::text as effective_at, created_at::text as created_at
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(subscription_id)
        .bind(event_type)
        .bind(effective_at)
        .bind(&idempotency_key_hash)
        .bind(request_summary)
        .bind(metadata)
        .fetch_one(pool)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;
        written.push(json!({
            "id": row.try_get::<Uuid, _>("id").map_err(db_row_error)?,
            "subscription_id": subscription_id,
            "event_type": row.try_get::<String, _>("event_type").map_err(db_row_error)?,
            "event_status": row.try_get::<String, _>("event_status").map_err(db_row_error)?,
            "effective_at": row.try_get::<String, _>("effective_at").map_err(db_row_error)?,
            "idempotency_key_fingerprint": subscription_scheduler_public_fingerprint(&idempotency_key_hash),
            "raw_idempotency_key_echoed": false,
            "secret_safe": true
        }));
    }
    Ok(written)
}

fn subscription_scheduler_event_effective_at(
    row: &PgRow,
    event_type: &str,
) -> Result<Option<String>, AdminError> {
    match event_type {
        "renew" => row
            .try_get::<String, _>("current_period_end")
            .map(Some)
            .map_err(db_row_error),
        "dunning" => row
            .try_get::<String, _>("next_dunning_attempt_at")
            .map(Some)
            .map_err(db_row_error),
        "expire" => row
            .try_get::<String, _>("expire_at")
            .map(Some)
            .map_err(db_row_error),
        "prorate" | "payment_failed" => Ok(None),
        _ => Ok(None),
    }
}

fn subscription_scheduler_idempotency_hash(
    tenant_id: Uuid,
    subscription_id: Uuid,
    event_type: &str,
    effective_at: &str,
    target_plan_id: Option<Uuid>,
) -> String {
    let material = format!(
        "subscription-scheduler:v1:{tenant_id}:{subscription_id}:{event_type}:{effective_at}:{}",
        target_plan_id
            .map(|id| id.to_string())
            .unwrap_or_else(|| "none".to_string())
    );
    format!("{:x}", Sha256::digest(material.as_bytes()))
}

fn subscription_scheduler_public_fingerprint(hash: &str) -> String {
    hash.chars().take(16).collect()
}

fn normalize_subscription_scheduler_worker_status(
    status: Option<String>,
) -> Result<String, AdminError> {
    let normalized = status
        .unwrap_or_else(|| "scheduled".to_string())
        .trim()
        .to_ascii_lowercase();
    match normalized.as_str() {
        "scheduled" | "replayed" => Ok(normalized),
        _ => Err(AdminError::bad_request(
            "event_status must be scheduled or replayed for worker handoff",
        )),
    }
}

fn normalize_subscription_scheduler_run_due_statuses(
    status: Option<String>,
) -> Result<Vec<String>, AdminError> {
    let Some(status) = status else {
        return Ok(vec!["scheduled".to_string(), "replayed".to_string()]);
    };
    let normalized = status.trim().to_ascii_lowercase();
    match normalized.as_str() {
        "all" | "claimable" => Ok(vec!["scheduled".to_string(), "replayed".to_string()]),
        "scheduled" | "replayed" => Ok(vec![normalized]),
        _ => Err(AdminError::bad_request(
            "event_status must be all, scheduled, or replayed for run-due",
        )),
    }
}

fn normalize_subscription_scheduler_worker_event_type(
    event_type: Option<String>,
) -> Result<Vec<String>, AdminError> {
    let Some(event_type) = event_type else {
        return Ok(vec![
            "renew".to_string(),
            "payment_failed".to_string(),
            "dunning".to_string(),
            "expire".to_string(),
            "prorate".to_string(),
        ]);
    };
    let normalized = event_type.trim().to_ascii_lowercase();
    match normalized.as_str() {
        "all" => Ok(vec![
            "renew".to_string(),
            "payment_failed".to_string(),
            "dunning".to_string(),
            "expire".to_string(),
            "prorate".to_string(),
        ]),
        "renew" | "payment_failed" | "dunning" | "expire" | "prorate" => Ok(vec![normalized]),
        _ => Err(AdminError::bad_request(
            "event_type must be all, renew, payment_failed, dunning, expire, or prorate",
        )),
    }
}

