fn db_row_error(error: sqlx::Error) -> AdminError {
    AdminError::from(DbError::Query(error))
}

fn is_sensitive_billing_json_key(key: &str) -> bool {
    let normalized = key.to_ascii_lowercase();
    normalized.contains("secret")
        || normalized.contains("credential")
        || normalized.contains("password")
        || normalized.contains("authorization")
        || normalized.contains("cookie")
        || normalized.contains("private_key")
        || normalized.contains("raw_key")
        || normalized.contains("secret_hash")
        || normalized.contains("encrypted_secret")
        || normalized.contains("fingerprint")
        || normalized.contains("payload")
        || normalized == "body"
        || normalized.ends_with("_body")
        || normalized == "api_key"
        || normalized.contains("apikey")
        || normalized.contains("access_token")
        || normalized.contains("refresh_token")
        || normalized.contains("session_token")
        || normalized.contains("bearer_token")
}

fn normalize_ledger_adjustment_operation(
    operation: String,
) -> Result<LedgerAdjustmentOperation, AdminError> {
    match operation.trim().to_ascii_lowercase().as_str() {
        "adjust" | "adjustment" => Ok(LedgerAdjustmentOperation::Adjust),
        "refund" => Ok(LedgerAdjustmentOperation::Refund),
        _ => Err(AdminError::bad_request(
            "operation must be adjust or refund",
        )),
    }
}

fn normalize_ledger_adjustment_request_mode(
    mode: Option<&str>,
) -> Result<LedgerAdjustmentRequestMode, AdminError> {
    match mode.map(str::trim).filter(|mode| !mode.is_empty()) {
        None | Some("dry_run") | Some("plan") => Ok(LedgerAdjustmentRequestMode::DryRun),
        Some("execute") => Ok(LedgerAdjustmentRequestMode::Execute),
        Some("execute_contract") => Ok(LedgerAdjustmentRequestMode::ExecuteContract),
        Some(_) => Err(AdminError::bad_request(
            "mode must be dry_run, execute_contract, or execute",
        )),
    }
}

fn normalize_ledger_adjustment_currency(currency: String) -> Result<String, AdminError> {
    let currency = non_empty(currency, "currency")?;
    validate_price_version_currency(&currency)
        .map_err(|_| AdminError::bad_request("currency must be an uppercase currency code"))?;
    Ok(currency)
}

fn normalize_ledger_adjustment_amount(
    amount: String,
    operation: LedgerAdjustmentOperation,
) -> Result<String, AdminError> {
    let amount = non_empty(amount, "amount")?;
    validate_decimal_amount_string("amount", &amount, PRICE_VERSION_DEFAULT_MONEY_SCALE)?;
    if decimal_amount_is_zero(&amount) {
        return Err(AdminError::bad_request("amount must not be zero"));
    }
    if operation == LedgerAdjustmentOperation::Refund && amount.starts_with('-') {
        return Err(AdminError::bad_request(
            "refund amount must be a positive credit amount",
        ));
    }
    Ok(amount)
}

fn normalize_ledger_adjustment_reason(
    reason: Option<String>,
) -> Result<Option<String>, AdminError> {
    let Some(reason) = reason else {
        return Ok(None);
    };
    let reason = reason.trim();
    if reason.is_empty() {
        return Ok(None);
    }
    if reason.len() > LEDGER_ADJUSTMENT_REASON_MAX_BYTES {
        return Err(AdminError::bad_request(format!(
            "reason must be at most {LEDGER_ADJUSTMENT_REASON_MAX_BYTES} bytes"
        )));
    }
    if looks_like_secret_value(reason) {
        return Err(AdminError::bad_request(
            "reason must not contain credential material",
        ));
    }

    Ok(Some(reason.to_string()))
}

fn validate_decimal_amount_string(
    field: &'static str,
    value: &str,
    scale: u32,
) -> Result<(), AdminError> {
    if value.starts_with('+') {
        return Err(AdminError::bad_request(format!(
            "{field} must be a decimal string"
        )));
    }
    let unsigned = value.strip_prefix('-').unwrap_or(value);
    if unsigned.is_empty() || unsigned == "." {
        return Err(AdminError::bad_request(format!(
            "{field} must be a decimal string"
        )));
    }
    let mut parts = unsigned.split('.');
    let whole = parts.next().unwrap_or_default();
    let fraction = parts.next();
    if parts.next().is_some() || whole.is_empty() || !whole.chars().all(|ch| ch.is_ascii_digit()) {
        return Err(AdminError::bad_request(format!(
            "{field} must be a decimal string"
        )));
    }
    if let Some(fraction) = fraction {
        if fraction.is_empty() || !fraction.chars().all(|ch| ch.is_ascii_digit()) {
            return Err(AdminError::bad_request(format!(
                "{field} must be a decimal string"
            )));
        }
        if fraction.len() > scale as usize {
            return Err(AdminError::bad_request(format!(
                "{field} has more than {scale} fractional digits"
            )));
        }
    }
    if whole.len() > 18 {
        return Err(AdminError::bad_request(format!(
            "{field} has too many whole-number digits"
        )));
    }
    Ok(())
}

fn decimal_amount_is_zero(value: &str) -> bool {
    value
        .trim_start_matches('-')
        .chars()
        .filter(|ch| *ch != '.')
        .all(|ch| ch == '0')
}

fn decimal_amount_units(value: &str, scale: u32) -> Result<i128, AdminError> {
    validate_decimal_amount_string("amount", value, scale)?;
    let negative = value.starts_with('-');
    let unsigned = value.strip_prefix('-').unwrap_or(value);
    let (whole, fraction) = unsigned.split_once('.').unwrap_or((unsigned, ""));
    let scale_factor = 10_i128.pow(scale);
    let whole_units = whole
        .parse::<i128>()
        .map_err(|_| AdminError::bad_request("amount must be a decimal string"))?
        .checked_mul(scale_factor)
        .ok_or_else(|| AdminError::bad_request("amount is too large"))?;
    let mut fraction_string = fraction.to_string();
    while fraction_string.len() < scale as usize {
        fraction_string.push('0');
    }
    let fraction_units = if fraction_string.is_empty() {
        0
    } else {
        fraction_string
            .parse::<i128>()
            .map_err(|_| AdminError::bad_request("amount must be a decimal string"))?
    };
    let units = whole_units
        .checked_add(fraction_units)
        .ok_or_else(|| AdminError::bad_request("amount is too large"))?;

    Ok(if negative { -units } else { units })
}

fn format_decimal_units(units: i128, scale: u32) -> String {
    let negative = units < 0;
    let absolute = units.abs();
    let scale_factor = 10_i128.pow(scale);
    let whole = absolute / scale_factor;
    let fraction = absolute % scale_factor;
    let sign = if negative { "-" } else { "" };

    format!("{sign}{whole}.{fraction:0width$}", width = scale as usize)
}

fn validate_refund_remaining_amount(
    requested_refund_amount: &str,
    source_debit_amount: &str,
    confirmed_credit_amount: &str,
    confirmed_credit_count: i64,
    currency: &str,
) -> Result<RefundRemainingSummary, AdminError> {
    let requested_units = decimal_amount_units(requested_refund_amount, LEDGER_AMOUNT_SCALE)?;
    let source_units = decimal_amount_units(source_debit_amount, LEDGER_AMOUNT_SCALE)?;
    let confirmed_credit_units =
        decimal_amount_units(confirmed_credit_amount, LEDGER_AMOUNT_SCALE)?;
    if requested_units <= 0 {
        return Err(AdminError::bad_request(
            "refund amount must be a positive credit amount",
        ));
    }
    if source_units >= 0 {
        return Err(AdminError::bad_request(
            "refund related ledger entry must be a confirmed debit",
        ));
    }
    if confirmed_credit_units < 0 {
        return Err(AdminError::bad_request(
            "confirmed refund credit amount must not be negative",
        ));
    }

    let source_debit_units = source_units.abs();
    let remaining_units = (source_debit_units - confirmed_credit_units).max(0);
    if requested_units > remaining_units {
        return Err(AdminError::bad_request(
            "refund amount exceeds remaining refundable amount",
        ));
    }

    Ok(RefundRemainingSummary {
        source_debit_amount: format_decimal_units(source_debit_units, LEDGER_AMOUNT_SCALE),
        confirmed_credit_amount: format_decimal_units(confirmed_credit_units, LEDGER_AMOUNT_SCALE),
        requested_refund_amount: format_decimal_units(requested_units, LEDGER_AMOUNT_SCALE),
        remaining_refundable_amount: format_decimal_units(remaining_units, LEDGER_AMOUNT_SCALE),
        currency: currency.to_string(),
        confirmed_credit_count,
    })
}

fn validate_related_ledger_entry_for_adjustment_plan(
    operation: LedgerAdjustmentOperation,
    entry: &LedgerEntry,
    currency: &str,
    project_id: Option<Uuid>,
    wallet_id: Option<Uuid>,
    request_id: Option<Uuid>,
) -> Result<(), AdminError> {
    if entry.currency != currency {
        return Err(AdminError::bad_request(
            "currency must match related ledger entry currency",
        ));
    }
    if let Some(project_id) = project_id
        && entry.project_id != Some(project_id)
    {
        return Err(AdminError::bad_request(
            "project_id must match related ledger entry",
        ));
    }
    if let Some(wallet_id) = wallet_id
        && entry.wallet_id != Some(wallet_id)
    {
        return Err(AdminError::bad_request(
            "wallet_id must match related ledger entry",
        ));
    }
    if let Some(request_id) = request_id
        && entry.request_id != Some(request_id)
    {
        return Err(AdminError::bad_request(
            "request_id must match related ledger entry",
        ));
    }
    if operation == LedgerAdjustmentOperation::Refund {
        if entry.status != "confirmed" || !entry.amount.starts_with('-') {
            return Err(AdminError::bad_request(
                "refund related ledger entry must be a confirmed debit",
            ));
        }
        if !matches!(entry.entry_type.as_str(), "settle" | "adjust") {
            return Err(AdminError::bad_request(
                "refund related ledger entry must be settle or adjust",
            ));
        }
    }
    Ok(())
}

fn validate_price_version_pricing_rules(value: Value) -> Result<Value, AdminError> {
    let value = validate_json_object(value, "pricing_rules")?;
    if contains_sensitive_billing_json_key(&value) {
        return Err(AdminError::bad_request(
            "pricing_rules must not contain payload, secret, or raw key fields",
        ));
    }

    let object = value
        .as_object()
        .expect("validate_json_object ensures object");
    let scale = price_version_rules_scale(object.get("scale"))?;
    validate_price_version_currency(pricing_rules_currency(&value)?)?;

    let mut has_rate_field = false;
    for (key, field_value) in object {
        match price_version_pricing_rule_field(key) {
            PriceVersionPricingRuleField::Currency => {}
            PriceVersionPricingRuleField::Scale => {}
            PriceVersionPricingRuleField::Rate(field) => {
                if !field_value.is_null() {
                    has_rate_field = true;
                    validate_price_version_money_field(field, field_value, scale)?;
                }
            }
            PriceVersionPricingRuleField::Unknown => {
                return Err(AdminError::bad_request(format!(
                    "unsupported pricing_rules field `{key}`"
                )));
            }
        }
    }

    if !has_rate_field {
        return Err(AdminError::bad_request(
            "pricing_rules must include at least one rate field",
        ));
    }

    Ok(value)
}

fn contains_sensitive_billing_json_key(value: &Value) -> bool {
    match value {
        Value::Object(object) => object.iter().any(|(key, value)| {
            is_sensitive_billing_json_key(key) || contains_sensitive_billing_json_key(value)
        }),
        Value::Array(values) => values.iter().any(contains_sensitive_billing_json_key),
        _ => false,
    }
}

fn pricing_rules_currency(value: &Value) -> Result<&str, AdminError> {
    value
        .get("currency")
        .and_then(Value::as_str)
        .filter(|currency| !currency.is_empty())
        .ok_or_else(|| AdminError::bad_request("pricing_rules.currency is required"))
}

fn validate_price_version_currency(currency: &str) -> Result<(), AdminError> {
    let mut characters = currency.chars();
    let Some(first) = characters.next() else {
        return Err(AdminError::bad_request(
            "pricing_rules.currency is required",
        ));
    };
    let valid = first.is_ascii_uppercase()
        && currency.len() >= 3
        && currency.len() <= 32
        && characters.all(|character| {
            character.is_ascii_uppercase() || character.is_ascii_digit() || character == '_'
        });
    if valid {
        Ok(())
    } else {
        Err(AdminError::bad_request(
            "pricing_rules.currency must be an uppercase currency code",
        ))
    }
}

fn price_version_rules_scale(value: Option<&Value>) -> Result<u32, AdminError> {
    match value {
        None | Some(Value::Null) => Ok(PRICE_VERSION_DEFAULT_MONEY_SCALE),
        Some(Value::Number(number)) => {
            let Some(scale) = number.as_u64() else {
                return Err(AdminError::bad_request(
                    "pricing_rules.scale must be an integer",
                ));
            };
            if scale > u64::from(PRICE_VERSION_MAX_MONEY_SCALE) {
                return Err(AdminError::bad_request(
                    "pricing_rules.scale must be between 0 and 18",
                ));
            }
            Ok(scale as u32)
        }
        Some(_) => Err(AdminError::bad_request(
            "pricing_rules.scale must be an integer",
        )),
    }
}

enum PriceVersionPricingRuleField {
    Currency,
    Scale,
    Rate(&'static str),
    Unknown,
}

fn price_version_pricing_rule_field(key: &str) -> PriceVersionPricingRuleField {
    match key {
        "currency" => PriceVersionPricingRuleField::Currency,
        "scale" => PriceVersionPricingRuleField::Scale,
        "input_token_rate_per_1m" | "input_token_rate_per_million" | "input_tokens_per_1m" => {
            PriceVersionPricingRuleField::Rate("input_token_rate_per_1m")
        }
        "output_token_rate_per_1m" | "output_token_rate_per_million" | "output_tokens_per_1m" => {
            PriceVersionPricingRuleField::Rate("output_token_rate_per_1m")
        }
        "cache_token_rate_per_1m"
        | "cache_token_rate_per_million"
        | "cache_tokens_per_1m"
        | "cached_token_rate_per_1m"
        | "cached_token_rate_per_million"
        | "cached_input_token_rate_per_1m"
        | "cached_input_token_rate_per_million"
        | "input_cache_token_rate_per_1m"
        | "input_cache_token_rate_per_million" => {
            PriceVersionPricingRuleField::Rate("cache_token_rate_per_1m")
        }
        "reasoning_token_rate_per_1m"
        | "reasoning_token_rate_per_million"
        | "reasoning_tokens_per_1m" => {
            PriceVersionPricingRuleField::Rate("reasoning_token_rate_per_1m")
        }
        "fixed_request_cost" => PriceVersionPricingRuleField::Rate("fixed_request_cost"),
        _ => PriceVersionPricingRuleField::Unknown,
    }
}

fn validate_price_version_money_field(
    field: &'static str,
    value: &Value,
    scale: u32,
) -> Result<(), AdminError> {
    match value {
        Value::Null => Ok(()),
        Value::String(value) => validate_price_version_decimal_string(field, value, scale),
        Value::Number(number) => {
            if let Some(units) = number.as_i64() {
                if units < 0 {
                    return Err(AdminError::bad_request(format!(
                        "pricing_rules.{field} must not be negative"
                    )));
                }
                return Ok(());
            }
            if number.as_u64().is_some() {
                return Ok(());
            }
            Err(AdminError::bad_request(format!(
                "pricing_rules.{field} must be a decimal string or integer fixed-unit value"
            )))
        }
        _ => Err(AdminError::bad_request(format!(
            "pricing_rules.{field} must be a decimal string or integer fixed-unit value"
        ))),
    }
}

fn validate_price_version_decimal_string(
    field: &'static str,
    value: &str,
    scale: u32,
) -> Result<(), AdminError> {
    let value = value.trim();
    if value.is_empty() {
        return Err(AdminError::bad_request(format!(
            "pricing_rules.{field} must not be empty"
        )));
    }

    let unsigned = if let Some(unsigned) = value.strip_prefix('-') {
        let _ = unsigned;
        return Err(AdminError::bad_request(format!(
            "pricing_rules.{field} must not be negative"
        )));
    } else if let Some(unsigned) = value.strip_prefix('+') {
        unsigned
    } else {
        value
    };

    let mut parts = unsigned.split('.');
    let whole = parts.next().expect("split always yields one part");
    let fraction = parts.next();
    if parts.next().is_some()
        || whole.is_empty()
        || !whole.chars().all(|character| character.is_ascii_digit())
        || !fraction
            .unwrap_or_default()
            .chars()
            .all(|character| character.is_ascii_digit())
    {
        return Err(AdminError::bad_request(format!(
            "pricing_rules.{field} must be a valid decimal string"
        )));
    }
    if fraction.unwrap_or_default().len() > scale as usize {
        return Err(AdminError::bad_request(format!(
            "pricing_rules.{field} has more than {scale} fractional digits"
        )));
    }

    Ok(())
}

fn price_version_create_audit_metadata(pricing_rules: &Value, price_book_currency: &str) -> Value {
    json!({
        "price_book_currency": price_book_currency,
        "pricing_rule_keys": object_keys(pricing_rules),
        "pricing_currency": pricing_rules_currency(pricing_rules).unwrap_or(""),
        "transactional_audit": true,
        "sensitive_material_policy": "rejected_by_schema",
    })
}

