fn quota_pricing_distribution_readback(
    active_price_versions: usize,
    price_version_count: usize,
    configured_virtual_key_policies: usize,
    configured_virtual_key_budgets: usize,
    provider_key_limit_guardrails: usize,
    provider_key_count: usize,
) -> Value {
    let ready = active_price_versions > 0
        || configured_virtual_key_policies > 0
        || configured_virtual_key_budgets > 0
        || provider_key_limit_guardrails > 0;
    json!({
        "schema": "quota_pricing_guardrails_readback.v1",
        "status": if ready { "ready" } else { "blocked" },
        "active_price_version_count": active_price_versions,
        "price_version_count": price_version_count,
        "configured_virtual_key_rate_limit_policy_count": configured_virtual_key_policies,
        "configured_virtual_key_budget_policy_count": configured_virtual_key_budgets,
        "provider_key_limit_guardrail_count": provider_key_limit_guardrails,
        "provider_key_count": provider_key_count,
        "pricing_rules_returned": false,
        "raw_policy_payload_returned": false,
        "safe_next_action": if ready { "Review prices, quotas, and provider limits before widening distribution" } else { "Add an active price version or quota/rate/budget guardrail before public distribution" },
        "secret_safe": true
    })
}

fn distribution_safe_next_action(
    blockers: &[String],
    voucher_readback_available: bool,
    virtual_key_ready: bool,
    quota_pricing_ready: bool,
    request_log_present: bool,
) -> &'static str {
    if !blockers.is_empty() {
        "Fix blocking upstream/provider/model/profile checks before user handoff"
    } else if !virtual_key_ready {
        "Create an active API key profile so users can issue keys"
    } else if !voucher_readback_available {
        "Apply voucher migrations and refresh voucher readiness readback"
    } else if !quota_pricing_ready {
        "Add pricing or quota/rate/budget guardrails before public distribution"
    } else if !request_log_present {
        "Run one Gateway request and refresh sanitized request-log readback"
    } else {
        "Proceed with a bounded user handoff; release evidence remains a separate operator task"
    }
}

fn json_object_has_keys(value: &Value) -> bool {
    value.as_object().is_some_and(|object| !object.is_empty())
}

fn distribution_readiness_check(
    id: &'static str,
    label: &'static str,
    is_ready: bool,
    blocking: bool,
    detail: &'static str,
    evidence: String,
    next_action: impl Into<String>,
) -> Value {
    json!({
        "id": id,
        "label": label,
        "status": if is_ready { "online" } else if blocking { "offline" } else { "pending" },
        "blocking": blocking,
        "detail": detail,
        "evidence": evidence,
        "next_action": next_action.into(),
    })
}

fn setup_readback_response(
    admin_user_exists: bool,
    providers: &[Provider],
    channels: &[Channel],
    provider_keys: &[ProviderKey],
    models: &[CanonicalModel],
    associations: &[ModelAssociation],
    profiles: &[ApiKeyProfile],
    virtual_keys: &[VirtualKey],
    request_logs: &[RequestLogSummary],
) -> Value {
    let mock_provider = providers
        .iter()
        .find(|provider| provider.code == "mock-openai" && provider.status == "enabled");
    let mock_channel = mock_provider.and_then(|provider| {
        channels.iter().find(|channel| {
            channel.provider_id == provider.id
                && channel.name == "mock-openai-default"
                && channel.status == "enabled"
        })
    });
    let mock_provider_key_ready = mock_channel.is_some_and(|channel| {
        provider_keys.iter().any(|provider_key| {
            provider_key.channel_id == channel.id
                && provider_key.key_alias == "mock-dev-key"
                && provider_key.status == "enabled"
                && provider_key.has_secret_fingerprint
        })
    });
    let default_model = models
        .iter()
        .find(|model| model.model_key == "mock-gpt-4o-mini" && model.status == "active");
    let default_model_association_ready =
        default_model
            .zip(mock_channel)
            .is_some_and(|(model, channel)| {
                associations.iter().any(|association| {
                    association.canonical_model_id == model.id
                        && association.channel_id == Some(channel.id)
                        && association.status == "enabled"
                })
            });
    let test_key = virtual_keys
        .iter()
        .find(|virtual_key| virtual_key.key_prefix == "dev_test_key");
    let active_test_key_present =
        test_key.is_some_and(|virtual_key| virtual_key.status == "active");
    let active_profile_present = profiles.iter().any(|profile| profile.status == "active");
    let gateway_model_ready = default_model.is_some()
        && default_model_association_ready
        && active_profile_present
        && active_test_key_present;
    let successful_chat_requests = request_logs
        .iter()
        .filter(|log| {
            log.requested_model.as_deref() == Some("mock-gpt-4o-mini")
                && (request_log_counts_as_success(log) || log.http_status == Some(200))
        })
        .count();
    let gateway_chat_ready = gateway_model_ready && successful_chat_requests > 0;

    let admin_status = if admin_user_exists {
        "ready"
    } else {
        "blocked"
    };
    let mock_stack_ready = mock_provider.is_some()
        && mock_channel.is_some()
        && mock_provider_key_ready
        && default_model.is_some()
        && default_model_association_ready;
    let mock_stack_status = if mock_stack_ready { "ready" } else { "blocked" };
    let test_key_status = if active_test_key_present {
        "ready"
    } else {
        "blocked"
    };
    let gateway_status = if gateway_chat_ready {
        "ready"
    } else if gateway_model_ready {
        "attention"
    } else {
        "blocked"
    };
    let checks = vec![
        setup_readback_check_with_status(
            "admin_exists",
            "Local admin",
            admin_status,
            "admin@example.com active account exists",
            if admin_user_exists {
                "Login to Admin UI"
            } else {
                "Run scripts/setup_local_mvp.ps1"
            },
        ),
        setup_readback_check_with_status(
            "mock_provider",
            "Mock provider/channel/key",
            if mock_provider.is_some() && mock_channel.is_some() && mock_provider_key_ready {
                "ready"
            } else {
                "blocked"
            },
            "mock-openai provider, mock-openai-default channel, and mock-dev-key credential presence",
            if mock_provider_key_ready {
                "Keep mock provider running for local smoke"
            } else {
                "Run scripts/setup_local_mvp.ps1 and start mock-provider"
            },
        ),
        setup_readback_check_with_status(
            "default_model",
            "Default model association",
            if default_model.is_some() && default_model_association_ready {
                "ready"
            } else {
                "blocked"
            },
            "mock-gpt-4o-mini active model is bound to the mock channel",
            if default_model_association_ready {
                "Use mock-gpt-4o-mini for local Gateway tests"
            } else {
                "Run scripts/setup_local_mvp.ps1"
            },
        ),
        setup_readback_check_with_status(
            "test_key",
            "Local test key",
            test_key_status,
            "dev_test_key prefix is present on an active default-project key",
            if active_test_key_present {
                "Use scripts/dev_login_check.ps1 for the dev-only secret input"
            } else {
                "Run scripts/setup_local_mvp.ps1"
            },
        ),
        setup_readback_check_with_status(
            "gateway_model",
            "Gateway model list",
            if gateway_model_ready {
                "ready"
            } else {
                "blocked"
            },
            "profile, active test key, active model, and enabled association are ready",
            if gateway_model_ready {
                "GET /v1/models should list mock-gpt-4o-mini with the dev key"
            } else {
                "Repair profile/key/model association through setup seed"
            },
        ),
        setup_readback_check_with_status(
            "gateway_chat",
            "Gateway chat readback",
            if gateway_chat_ready {
                "ready"
            } else if gateway_model_ready {
                "attention"
            } else {
                "blocked"
            },
            "recent successful mock-gpt-4o-mini request log exists",
            if gateway_chat_ready {
                "Open request logs for the latest local smoke request"
            } else {
                "Run scripts/dev_login_check.ps1 to create a local Gateway request"
            },
        ),
    ];
    let blockers = checks
        .iter()
        .filter(|check| {
            check
                .get("status")
                .and_then(Value::as_str)
                .is_some_and(|status| status == "blocked")
        })
        .filter_map(|check| {
            check
                .get("code")
                .and_then(Value::as_str)
                .map(str::to_string)
        })
        .collect::<Vec<_>>();
    let ready_count = checks
        .iter()
        .filter(|check| {
            check
                .get("status")
                .and_then(Value::as_str)
                .is_some_and(|status| status == "ready")
        })
        .count();
    let state = if blockers.is_empty() {
        "ready"
    } else if ready_count > 0 {
        "attention"
    } else {
        "blocked"
    };
    let first_run_status = if blockers.is_empty() && gateway_chat_ready {
        "ready"
    } else if blockers.is_empty() || ready_count > 0 {
        "attention"
    } else {
        "blocked"
    };
    let first_run_readiness = json!({
        "schema": "admin_setup_first_run_readiness.v1",
        "status": first_run_status,
        "secret_safe": true,
        "safe_next_action": if blockers.is_empty() {
            "Run scripts/dev_login_check.ps1 when you need a fresh local Gateway readback."
        } else {
            "Run scripts/setup_local_mvp.ps1, then refresh setup readback."
        },
        "blocked_reasons": blockers.clone(),
        "admin": setup_first_run_readiness_item(
            admin_user_exists,
            vec!["admin_account_missing"],
            if admin_user_exists { "Login to Admin UI." } else { "Run scripts/setup_local_mvp.ps1." },
        ),
        "mock_provider": setup_first_run_readiness_item(
            mock_provider.is_some(),
            vec!["mock_provider_missing_or_disabled"],
            if mock_provider.is_some() { "Keep mock-openai enabled." } else { "Run scripts/setup_local_mvp.ps1." },
        ),
        "mock_channel": setup_first_run_readiness_item(
            mock_channel.is_some(),
            vec!["mock_channel_missing_or_disabled"],
            if mock_channel.is_some() { "Keep mock-openai-default enabled." } else { "Run scripts/setup_local_mvp.ps1." },
        ),
        "mock_model": setup_first_run_readiness_item(
            default_model.is_some() && default_model_association_ready,
            vec!["mock_model_missing_or_unbound"],
            if default_model.is_some() && default_model_association_ready {
                "Use mock-gpt-4o-mini for local Gateway checks."
            } else {
                "Run scripts/setup_local_mvp.ps1 to seed the model association."
            },
        ),
        "test_key": setup_first_run_readiness_item(
            active_test_key_present,
            vec!["test_key_missing_or_inactive"],
            if active_test_key_present {
                "Use the dev-only key through scripts/dev_login_check.ps1; no key secret is returned here."
            } else {
                "Run scripts/setup_local_mvp.ps1 to create the local test key."
            },
        ),
        "gateway_chat": setup_first_run_readiness_item_with_status(
            if gateway_chat_ready { "ready" } else if gateway_model_ready { "attention" } else { "blocked" },
            if gateway_model_ready { vec![] } else { vec!["gateway_model_stack_blocked"] },
            if gateway_chat_ready {
                "Open request logs for the latest local chat readback."
            } else if gateway_model_ready {
                "Run scripts/dev_login_check.ps1 to exercise /v1/chat/completions."
            } else {
                "Repair setup seed before running Gateway chat."
            },
        ),
        "gateway_responses": setup_first_run_readiness_item(
            gateway_model_ready,
            vec!["gateway_model_stack_blocked"],
            if gateway_model_ready {
                "Use the same mock model stack for /v1/responses local smoke when needed."
            } else {
                "Repair setup seed before testing /v1/responses."
            },
        ),
        "gateway_embeddings": setup_first_run_readiness_item(
            gateway_model_ready,
            vec!["gateway_model_stack_blocked"],
            if gateway_model_ready {
                "Use the same mock model stack for /v1/embeddings local smoke when needed."
            } else {
                "Repair setup seed before testing /v1/embeddings."
            },
        ),
        "omitted_fields": [
            "raw_admin_password",
            "api_key_secret",
            "api_key_secret_hash",
            "provider_secret",
            "provider_secret_hash",
            "authorization_header",
            "raw_payload"
        ],
        "raw_admin_password_returned": false,
        "api_key_secret_returned": false,
        "api_key_secret_hash_returned": false,
        "provider_secret_returned": false,
        "provider_secret_hash_returned": false,
        "authorization_returned": false,
        "raw_payload_returned": false,
    });

    json!({
        "schema": "admin_setup_readback.v1",
        "source": "control_plane_local_seed_readback",
        "tenant_id": DEFAULT_TENANT_ID,
        "default_project_id": DEFAULT_PROJECT_ID,
        "secret_safe": true,
        "state": state,
        "next_action": if blockers.is_empty() {
            "Open User Portal or run a Gateway chat smoke with the local dev key."
        } else {
            "Run scripts/setup_local_mvp.ps1, then scripts/dev_login_check.ps1."
        },
        "counts": {
            "ready": ready_count,
            "blocked": blockers.len(),
            "total": checks.len(),
            "recent_mock_chat_successes": successful_chat_requests,
        },
        "first_run_readiness": first_run_readiness,
        "local_seed": {
            "admin_exists": admin_user_exists,
            "mock_provider": {
                "code": "mock-openai",
                "exists": mock_provider.is_some(),
                "enabled": mock_provider.is_some(),
            },
            "mock_channel": {
                "name": "mock-openai-default",
                "exists": mock_channel.is_some(),
                "enabled": mock_channel.is_some(),
            },
            "mock_provider_key": {
                "alias": "mock-dev-key",
                "exists": mock_provider_key_ready,
                "credential_configured": mock_provider_key_ready,
            },
            "default_model": {
                "model_key": "mock-gpt-4o-mini",
                "exists": default_model.is_some(),
                "active": default_model.is_some(),
                "association_enabled": default_model_association_ready,
            },
            "test_key": {
                "key_prefix": test_key.map(|key| key.key_prefix.as_str()).unwrap_or("dev_test_key"),
                "present": active_test_key_present,
                "active": active_test_key_present,
                "secret_returned": false,
            },
        },
        "wizard_steps": [
            {
                "code": "admin",
                "label": "Admin",
                "status": admin_status,
                "detail": "Local admin account exists and can log in to the Admin UI.",
                "evidence": if admin_user_exists { "admin account present; raw password omitted" } else { "admin account missing" },
                "next_action": if admin_user_exists { "Login to Admin UI" } else { "Run scripts/setup_local_mvp.ps1" },
                "production_credentials_required": false
            },
            {
                "code": "mock_provider_channel_model",
                "label": "Mock provider/channel/model",
                "status": mock_stack_status,
                "detail": "mock-openai provider, mock-openai-default channel, mock-dev-key placeholder, and mock-gpt-4o-mini route are present.",
                "evidence": format!(
                    "provider={} channel={} provider_key={} model={} association={}",
                    readiness_word(mock_provider.is_some()),
                    readiness_word(mock_channel.is_some()),
                    readiness_word(mock_provider_key_ready),
                    readiness_word(default_model.is_some()),
                    readiness_word(default_model_association_ready)
                ),
                "next_action": if mock_stack_ready { "Keep the local mock provider running for smoke tests" } else { "Run scripts/setup_local_mvp.ps1" },
                "production_credentials_required": false
            },
            {
                "code": "test_key",
                "label": "Test key",
                "status": test_key_status,
                "detail": "Default project has an active dev_test_key virtual key; the raw key secret is never returned.",
                "evidence": if active_test_key_present { "dev_test_key active; raw secret omitted" } else { "dev_test_key missing or inactive" },
                "next_action": if active_test_key_present { "Use scripts/dev_login_check.ps1 for local smoke" } else { "Run scripts/setup_local_mvp.ps1" },
                "production_credentials_required": false
            },
            {
                "code": "gateway_model_chat_readiness",
                "label": "Gateway model/chat readiness",
                "status": gateway_status,
                "detail": "Gateway can list the mock model when model readiness is ready; chat readiness is complete after a local mock chat request is read back.",
                "evidence": format!(
                    "model={} chat_successes={}",
                    readiness_word(gateway_model_ready),
                    successful_chat_requests
                ),
                "next_action": if gateway_chat_ready {
                    "Open request logs for readback"
                } else if gateway_model_ready {
                    "Run scripts/dev_login_check.ps1 to exercise /v1/chat/completions"
                } else {
                    "Repair local seed/model/profile/key readiness with scripts/setup_local_mvp.ps1"
                },
                "production_credentials_required": false
            }
        ],
        "gateway": {
            "model_readiness": {
                "status": if gateway_model_ready { "ready" } else { "blocked" },
                "model": "mock-gpt-4o-mini",
                "requires_authorization_header": true,
                "authorization_returned": false,
            },
            "chat_readiness": {
                "status": if gateway_chat_ready { "ready" } else if gateway_model_ready { "attention" } else { "blocked" },
                "recent_success_count": successful_chat_requests,
                "raw_payload_returned": false,
                "next_action": if gateway_chat_ready {
                    "Open request logs for readback."
                } else if gateway_model_ready {
                    "Run scripts/dev_login_check.ps1 to exercise /v1/chat/completions."
                } else {
                    "Run scripts/setup_local_mvp.ps1 before Gateway chat smoke."
                },
            },
        },
        "handoff": {
            "admin_ui_target": "overview",
            "user_portal_target": "/?mode=developer-console",
            "script_next_check": "pwsh -NoProfile -ExecutionPolicy Bypass -File .\\scripts\\dev_login_check.ps1",
            "production_credentials_required": false,
            "omitted_fields": [
                "raw_admin_password",
                "provider_secret",
                "test_key_secret",
                "authorization",
                "raw_payload"
            ],
        },
        "checks": checks,
        "blockers": blockers,
        "raw_admin_password_returned": false,
        "raw_provider_key_returned": false,
        "raw_test_key_secret_returned": false,
        "authorization_returned": false,
        "raw_request_payload_returned": false,
    })
}

fn setup_first_run_readiness_item(
    ready: bool,
    blocked_reasons: Vec<&'static str>,
    safe_next_action: &'static str,
) -> Value {
    setup_first_run_readiness_item_with_status(
        if ready { "ready" } else { "blocked" },
        if ready { Vec::new() } else { blocked_reasons },
        safe_next_action,
    )
}

fn setup_first_run_readiness_item_with_status(
    status: &'static str,
    blocked_reasons: Vec<&'static str>,
    safe_next_action: &'static str,
) -> Value {
    json!({
        "status": status,
        "blocked_reasons": blocked_reasons,
        "safe_next_action": safe_next_action,
        "secret_safe": true,
    })
}

fn setup_readback_check_with_status(
    code: &'static str,
    label: &'static str,
    status: &'static str,
    detail: &'static str,
    next_action: &'static str,
) -> Value {
    json!({
        "code": code,
        "label": label,
        "status": status,
        "detail": detail,
        "next_action": next_action,
    })
}

fn readiness_word(ready: bool) -> &'static str {
    if ready { "ready" } else { "missing" }
}

fn recent_stats_by_entity(request_logs: &[RequestLogSummary]) -> RecentStatsByEntity {
    let mut recent = RecentStatsByEntity::default();

    for log in request_logs {
        if let Some(provider_id) = log.resolved_provider_id {
            recent
                .providers
                .entry(provider_id)
                .or_default()
                .observe(log);
        }
        if let Some(channel_id) = log.resolved_channel_id {
            recent.channels.entry(channel_id).or_default().observe(log);
        }
        if let Some(provider_key_id) = log.provider_key_id {
            recent
                .provider_keys
                .entry(provider_key_id)
                .or_default()
                .observe(log);
        }
        if let Some(model_id) = log.canonical_model_id {
            recent.models.entry(model_id).or_default().observe(log);
        }
    }

    recent
}

fn request_log_counts_as_error(log: &RequestLogSummary) -> bool {
    log.error_code.is_some()
        || matches!(
            log.status.as_str(),
            "failed" | "cancelled" | "partial" | "rejected"
        )
}

fn request_log_counts_as_success(log: &RequestLogSummary) -> bool {
    log.error_code.is_none() && matches!(log.status.as_str(), "succeeded")
}

fn request_log_error_summary_code(log: &RequestLogSummary) -> String {
    log.error_code
        .as_deref()
        .map(health_summary_string)
        .or_else(|| log.http_status.map(|status| format!("http_{status}")))
        .unwrap_or_else(|| health_summary_string(&log.status))
}

fn success_rate_value(stats: &RecentHealthStats) -> Value {
    if stats.request_count == 0 {
        return Value::Null;
    }

    json!(stats.success_count as f64 / stats.request_count as f64)
}

fn average_latency_value(stats: &RecentHealthStats) -> Value {
    if stats.latency_samples_ms.is_empty() {
        return Value::Null;
    }

    let total: i64 = stats
        .latency_samples_ms
        .iter()
        .map(|value| *value as i64)
        .sum();
    json!(total as f64 / stats.latency_samples_ms.len() as f64)
}

fn p95_latency_value(stats: &RecentHealthStats) -> Value {
    if stats.latency_samples_ms.is_empty() {
        return Value::Null;
    }

    let mut samples = stats.latency_samples_ms.clone();
    samples.sort_unstable();
    let index = ((samples.len() as f64 * 0.95).ceil() as usize).saturating_sub(1);
    json!(samples[index.min(samples.len() - 1)])
}

fn error_top_value(stats: &RecentHealthStats) -> Value {
    let mut rows = stats
        .error_codes
        .iter()
        .map(|(code, count)| (code.as_str(), *count))
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| right.1.cmp(&left.1).then_with(|| left.0.cmp(right.0)));

    Value::Array(
        rows.into_iter()
            .take(5)
            .map(|(code, count)| {
                json!({
                    "code": code,
                    "count": count,
                })
            })
            .collect(),
    )
}

fn recent_last_error_value(error: Option<&RecentHealthError>) -> Value {
    match error {
        Some(error) => json!({
            "code": health_summary_optional_string(error.code.as_deref()),
            "owner": health_summary_optional_string(error.owner.as_deref()),
            "status": health_summary_string(&error.status),
            "http_status": error.http_status,
            "observed_at": health_summary_string(&error.observed_at),
        }),
        None => Value::Null,
    }
}

fn recent_stats_value(stats: Option<&RecentHealthStats>) -> Value {
    json!({
        "request_count": stats.map(|stats| stats.request_count).unwrap_or_default(),
        "success_count": stats.map(|stats| stats.success_count).unwrap_or_default(),
        "error_count": stats.map(|stats| stats.error_count).unwrap_or_default(),
        "success_rate": stats.map(success_rate_value).unwrap_or(Value::Null),
        "avg_latency_ms": stats.map(average_latency_value).unwrap_or(Value::Null),
        "p95_latency_ms": stats.map(p95_latency_value).unwrap_or(Value::Null),
        "error_top": stats.map(error_top_value).unwrap_or_else(|| json!([])),
        "last_error": recent_last_error_value(stats.and_then(|stats| stats.last_error.as_ref())),
    })
}

fn trace_request_summary_response(
    trace_id: &str,
    request_logs: &[RequestLogSummary],
    limit: i64,
    ledger_entries: &[LedgerEntry],
) -> Value {
    let mut stats = RecentHealthStats::default();
    for log in request_logs {
        stats.observe(log);
    }

    let first_request_at = request_logs
        .iter()
        .map(|log| log.created_at.as_str())
        .min()
        .map(health_summary_string);
    let last_request_at = request_logs
        .iter()
        .map(request_log_observed_at)
        .max()
        .map(health_summary_string);
    let currencies = request_logs
        .iter()
        .map(|log| health_summary_string(&log.currency))
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let tenant_id = request_logs
        .first()
        .map(|log| log.tenant_id)
        .unwrap_or(DEFAULT_TENANT_ID);

    json!({
        "tenant_id": tenant_id,
        "trace_id": health_summary_string(trace_id),
        "limit": limit,
        "limit_reached": request_logs.len() as i64 == limit,
        "request_count": stats.request_count,
        "error_count": stats.error_count,
        "last_error": recent_last_error_value(stats.last_error.as_ref()),
        "total_input_tokens": request_logs.iter().map(|log| log.input_tokens).sum::<i64>(),
        "total_output_tokens": request_logs.iter().map(|log| log.output_tokens).sum::<i64>(),
        "currencies": currencies,
        "first_request_at": first_request_at,
        "last_request_at": last_request_at,
        "ledger": ledger_summary_response(ledger_entries, TRACE_REQUEST_LEDGER_LIMIT),
        "requests": request_logs
            .iter()
            .map(request_log_summary_safe_value)
            .collect::<Vec<_>>(),
    })
}

fn request_log_observed_at(log: &RequestLogSummary) -> &str {
    log.completed_at.as_deref().unwrap_or(&log.created_at)
}

fn request_log_summary_safe_value(log: &RequestLogSummary) -> Value {
    let mut value =
        redact_json_string_values(serde_json::to_value(log).unwrap_or_else(|_| json!({})));
    if let Value::Object(object) = &mut value {
        for key in [
            "route_decision_snapshot",
            "payload_object_ref",
            "payload",
            "request_body",
            "response_body",
            "body",
        ] {
            object.remove(key);
        }
    }
    value
}

fn redact_json_string_values(value: Value) -> Value {
    match value {
        Value::String(value) => Value::String(redact_secrets(&value)),
        Value::Array(values) => Value::Array(
            values
                .into_iter()
                .map(redact_json_string_values)
                .collect::<Vec<_>>(),
        ),
        Value::Object(object) => Value::Object(
            object
                .into_iter()
                .map(|(key, value)| (key, redact_json_string_values(value)))
                .collect(),
        ),
        value => value,
    }
}

fn health_summary_string(value: &str) -> String {
    redact_secrets(value)
}

fn health_summary_optional_string(value: Option<&str>) -> Option<String> {
    value.map(health_summary_string)
}

fn status_counts_value<'a>(statuses: impl Iterator<Item = &'a str>) -> Value {
    let mut counts = BTreeMap::<String, usize>::new();
    for status in statuses {
        *counts.entry(status.to_string()).or_default() += 1;
    }

    json!(counts)
}

fn average_health_score(scores: impl Iterator<Item = f64>) -> Option<f64> {
    let mut total = 0.0;
    let mut count = 0_usize;

    for score in scores {
        if score.is_finite() {
            total += score;
            count += 1;
        }
    }

    (count > 0).then(|| total / count as f64)
}

fn health_state_for_score(score: Option<f64>) -> &'static str {
    match score {
        Some(score) if !score.is_finite() || score <= 0.0 => "unhealthy",
        Some(score) if score < 0.5 => "degraded",
        Some(_) => "healthy",
        None => "no_signal",
    }
}

fn model_routing_state(
    status: &str,
    enabled_association_count: usize,
    routable_channel_count: usize,
) -> &'static str {
    if status != "active" {
        "disabled"
    } else if enabled_association_count == 0 || routable_channel_count == 0 {
        "no_route"
    } else {
        "routable"
    }
}

fn association_counts_by_model(
    associations: &[ModelAssociation],
    enabled_only: bool,
) -> HashMap<Uuid, usize> {
    let mut counts = HashMap::<Uuid, usize>::new();

    for association in associations {
        if enabled_only && association.status != "enabled" {
            continue;
        }
        *counts.entry(association.canonical_model_id).or_default() += 1;
    }

    counts
}

fn model_channel_index(
    channels: &[Channel],
    associations: &[ModelAssociation],
) -> HashMap<Uuid, BTreeSet<Uuid>> {
    let mut index = HashMap::<Uuid, BTreeSet<Uuid>>::new();

    for association in associations
        .iter()
        .filter(|association| association.status == "enabled")
    {
        let channel_ids = channel_ids_for_association(association, channels);
        if channel_ids.is_empty() {
            continue;
        }
        index
            .entry(association.canonical_model_id)
            .or_default()
            .extend(channel_ids);
    }

    index
}

fn channel_model_index(
    model_channel_ids: &HashMap<Uuid, BTreeSet<Uuid>>,
) -> HashMap<Uuid, BTreeSet<Uuid>> {
    let mut index = HashMap::<Uuid, BTreeSet<Uuid>>::new();

    for (model_id, channel_ids) in model_channel_ids {
        for channel_id in channel_ids {
            index.entry(*channel_id).or_default().insert(*model_id);
        }
    }

    index
}

fn channel_ids_for_association(
    association: &ModelAssociation,
    channels: &[Channel],
) -> BTreeSet<Uuid> {
    match association.association_type.as_str() {
        "explicit_channel" => association
            .channel_id
            .into_iter()
            .filter(|channel_id| channels.iter().any(|channel| channel.id == *channel_id))
            .collect(),
        "channel_tag" => association
            .channel_tag
            .as_deref()
            .map(|tag| {
                channels
                    .iter()
                    .filter(|channel| channel_has_tag(channel, tag))
                    .map(|channel| channel.id)
                    .collect()
            })
            .unwrap_or_default(),
        "global" | "model_pattern" => channels.iter().map(|channel| channel.id).collect(),
        _ => BTreeSet::new(),
    }
}

fn channel_has_tag(channel: &Channel, tag: &str) -> bool {
    match &channel.tags {
        Value::Array(values) => values.iter().any(|value| value.as_str() == Some(tag)),
        Value::Object(object) => object.contains_key(tag),
        _ => false,
    }
}

fn provider_key_response(provider_key: ProviderKey) -> Value {
    let recovery_probe = provider_key_recovery_probe_summary(&provider_key.metadata);
    let lifecycle_state = provider_key_lifecycle_state(&provider_key);
    let rotation_needed = provider_key_rotation_needed(&provider_key, &recovery_probe);

    json!({
        "id": provider_key.id,
        "tenant_id": provider_key.tenant_id,
        "channel_id": provider_key.channel_id,
        "key_alias": provider_key.key_alias,
        "credential_configured": provider_key.has_secret_fingerprint,
        "credential_generation": provider_key_credential_generation(&provider_key.metadata),
        "status": provider_key.status,
        "lifecycle_state": lifecycle_state,
        "health_score": provider_key.health_score,
        "cooldown_until": provider_key.cooldown_until,
        "last_error_code": provider_key.last_error_code,
        "rpm_limit": provider_key.rpm_limit,
        "tpm_limit": provider_key.tpm_limit,
        "concurrency_limit": provider_key.concurrency_limit,
        "recovery_probe": recovery_probe.clone(),
        "last_probe_summary": recovery_probe,
        "rotation_needed": rotation_needed,
        "safe_next_action": provider_key_safe_next_action(&provider_key, &rotation_needed),
        "omitted_secret_policy": provider_key_omitted_secret_policy(),
        "secret_redacted": provider_key.secret_redacted,
    })
}

fn provider_key_lifecycle_state(provider_key: &ProviderKey) -> &'static str {
    match provider_key.status.as_str() {
        "enabled" if provider_key.has_secret_fingerprint => "active",
        "enabled" => "credential_missing",
        "manual_disabled" => "operator_disabled",
        "degraded" => "degraded",
        "cooldown" => "cooldown",
        "recovery_probe" => "recovery_probe",
        "auth_failed" => "credential_failed",
        "quota_exhausted" => "quota_exhausted",
        "deleted" => "deleted",
        _ => "unknown",
    }
}

fn provider_key_credential_generation(metadata: &Value) -> Value {
    let generation = metadata
        .get("credential_generation")
        .and_then(Value::as_i64)
        .or_else(|| {
            metadata
                .get("rotation")
                .and_then(|rotation| rotation.get("credential_generation"))
                .and_then(Value::as_i64)
        });
    let source = if generation.is_some() {
        "metadata"
    } else if metadata.get("rotation").is_some() {
        "rotation_metadata_without_generation"
    } else {
        "not_recorded"
    };

    json!({
        "value": generation,
        "source": source,
        "secret_material_returned": false,
    })
}

fn provider_key_recovery_probe_summary(metadata: &Value) -> Value {
    let Some(probe) = metadata.get("recovery_probe").and_then(Value::as_object) else {
        return Value::Null;
    };

    let result = probe
        .get("result")
        .and_then(Value::as_str)
        .map(health_summary_string);
    let error_code = probe
        .get("error_code")
        .and_then(Value::as_str)
        .map(health_summary_string);
    let last_checked_at = probe
        .get("last_checked_at")
        .or_else(|| probe.get("checked_at"))
        .and_then(Value::as_str)
        .map(health_summary_string);

    json!({
        "result": result,
        "error_code": error_code,
        "last_checked_at": last_checked_at,
    })
}

fn provider_key_rotation_needed(provider_key: &ProviderKey, recovery_probe: &Value) -> Value {
    let (needed, reason) = if !provider_key.has_secret_fingerprint {
        (true, "credential_missing")
    } else if provider_key.status == "auth_failed" {
        (true, "auth_failed")
    } else if provider_key.status == "manual_disabled" || provider_key.status == "deleted" {
        (false, "operator_disabled_or_deleted")
    } else if provider_key
        .last_error_code
        .as_deref()
        .is_some_and(is_rotation_error_code)
    {
        (true, "last_error_indicates_credential")
    } else if recovery_probe
        .get("error_code")
        .and_then(Value::as_str)
        .is_some_and(is_rotation_error_code)
    {
        (true, "probe_indicates_credential")
    } else {
        (false, "no_rotation_signal")
    };

    json!({
        "needed": needed,
        "reason": reason,
    })
}

fn is_rotation_error_code(error_code: &str) -> bool {
    let normalized = error_code.to_ascii_lowercase();
    normalized.contains("auth")
        || normalized.contains("credential")
        || normalized.contains("unauthorized")
        || normalized.contains("forbidden")
        || normalized.contains("401")
        || normalized.contains("403")
}

fn provider_key_safe_next_action(
    provider_key: &ProviderKey,
    rotation_needed: &Value,
) -> &'static str {
    if rotation_needed
        .get("needed")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        return "rotate_provider_key_secret_then_request_recovery_probe";
    }

    match provider_key.status.as_str() {
        "cooldown" => "wait_for_cooldown_or_request_recovery_probe",
        "degraded" | "recovery_probe" => "request_non_billable_recovery_probe_readback",
        "enabled" => "monitor_request_logs_and_provider_attempts",
        "manual_disabled" => "operator_review_before_reenable",
        "quota_exhausted" => "check_provider_quota_and_limits",
        "deleted" => "create_replacement_provider_key",
        _ => "operator_review_provider_key_state",
    }
}

fn provider_key_recovery_action_readback(
    provider_key: &ProviderKey,
    rotation_needed: &Value,
) -> Value {
    let safe_next_action = provider_key_safe_next_action(provider_key, rotation_needed);
    let suggested_action = provider_key_recovery_suggested_action(provider_key, rotation_needed);
    let operator_confirmation_required = !matches!(
        suggested_action,
        "monitor_request_logs"
            | "create_replacement_provider_key"
            | "check_provider_quota_and_limits"
    );
    let recovery_probe = provider_key_recovery_probe_summary(&provider_key.metadata);
    let last_probe_status = recovery_probe
        .get("result")
        .and_then(Value::as_str)
        .filter(|value| !value.is_empty())
        .unwrap_or("no_probe_recorded");
    let cooldown_or_refusal_reason = provider_key_cooldown_or_refusal_reason(provider_key);

    json!({
        "schema": "provider_key_recovery_action_readback.v1",
        "suggested_action": suggested_action,
        "operator_confirmation_required": operator_confirmation_required,
        "last_probe_status": health_summary_string(last_probe_status),
        "cooldown_or_refusal_reason": cooldown_or_refusal_reason,
        "safe_next_action": safe_next_action,
        "upstream_probe_executed": false,
        "secret_safe": true,
        "omitted_secret_policy": provider_key_omitted_secret_policy(),
    })
}

fn provider_key_recovery_apply_plan_readback(
    provider_key: &ProviderKey,
    rotation_needed: &Value,
) -> Value {
    let suggested_action = provider_key_recovery_suggested_action(provider_key, rotation_needed);
    let safe_next_action = provider_key_safe_next_action(provider_key, rotation_needed);
    let recovery_probe = provider_key_recovery_probe_summary(&provider_key.metadata);
    let last_probe_status = recovery_probe
        .get("result")
        .and_then(Value::as_str)
        .filter(|value| !value.is_empty())
        .unwrap_or("no_probe_recorded");
    let rotation_needed_bool = rotation_needed
        .get("needed")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let recovery_endpoint_source_allowed = matches!(
        provider_key.status.as_str(),
        "cooldown" | "degraded" | "recovery_probe"
    );
    let would_enable = recovery_endpoint_source_allowed
        && !rotation_needed_bool
        && matches!(last_probe_status, "success" | "passed" | "ok");
    let would_rotate = suggested_action == "rotate_provider_key_secret";
    let would_probe =
        suggested_action == "request_recovery_probe" || safe_next_action.contains("recovery_probe");
    let would_refuse = matches!(
        provider_key.status.as_str(),
        "manual_disabled" | "quota_exhausted" | "deleted"
    ) || suggested_action == "operator_review_provider_key_state";
    let operator_confirmation_required = !matches!(
        suggested_action,
        "monitor_request_logs"
            | "create_replacement_provider_key"
            | "check_provider_quota_and_limits"
    );

    let mut preconditions = vec![
        "operator_confirmation_required",
        "local_status_transition_only",
        "provider_network_call_forbidden",
        "live_provider_smoke_forbidden",
    ];
    if provider_key.has_secret_fingerprint {
        preconditions.push("credential_configured");
    } else {
        preconditions.push("credential_required_before_enable");
    }
    if recovery_endpoint_source_allowed {
        preconditions.push("recovery_endpoint_source_status_allowed");
    } else {
        preconditions.push("recovery_endpoint_source_status_not_allowed");
    }
    if would_rotate {
        preconditions.push("new_secret_material_required_for_rotate_endpoint");
    }

    let mut blocked_reasons = Vec::new();
    if !provider_key.has_secret_fingerprint && !would_rotate {
        blocked_reasons.push("credential_missing");
    }
    if provider_key.cooldown_until.is_some() {
        blocked_reasons.push("cooldown_until_present");
    }
    match provider_key.status.as_str() {
        "enabled" => blocked_reasons.push("provider_key_already_enabled"),
        "manual_disabled" => blocked_reasons.push("operator_disabled"),
        "quota_exhausted" => blocked_reasons.push("provider_quota_exhausted"),
        "deleted" => blocked_reasons.push("provider_key_deleted"),
        "auth_failed" if !would_rotate => blocked_reasons.push("credential_refused_or_auth_failed"),
        _ => {}
    }
    if would_refuse && blocked_reasons.is_empty() {
        blocked_reasons.push("operator_review_required");
    }

    json!({
        "schema": "provider_key_recovery_apply_plan_readback.v1",
        "suggested_action": suggested_action,
        "preconditions": preconditions,
        "would_enable": would_enable,
        "would_rotate": would_rotate,
        "would_probe": would_probe,
        "would_refuse": would_refuse,
        "operator_confirmation_required": operator_confirmation_required,
        "blocked_reasons": blocked_reasons,
        "safe_next_action": safe_next_action,
        "local_execution_boundary": {
            "status_write_allowed": recovery_endpoint_source_allowed && !would_refuse,
            "secret_write_allowed": would_rotate,
            "provider_network_call": false,
            "upstream_probe_executed": false,
            "live_provider_smoke": false,
            "request_log_write": false,
            "billing_ledger_write": false
        },
        "secret_safe": true,
        "omitted_secret_policy": provider_key_omitted_secret_policy(),
    })
}

fn provider_key_recovery_suggested_action(
    provider_key: &ProviderKey,
    rotation_needed: &Value,
) -> &'static str {
    if rotation_needed
        .get("needed")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        return "rotate_provider_key_secret";
    }

    match provider_key.status.as_str() {
        "cooldown" | "degraded" | "recovery_probe" => "request_recovery_probe",
        "manual_disabled" => "operator_review_reenable",
        "enabled" => "monitor_request_logs",
        "quota_exhausted" => "check_provider_quota_and_limits",
        "deleted" => "create_replacement_provider_key",
        _ => "operator_review_provider_key_state",
    }
}

fn provider_key_cooldown_or_refusal_reason(provider_key: &ProviderKey) -> String {
    if provider_key.cooldown_until.is_some() {
        return "cooldown_until_present".to_string();
    }

    match provider_key.status.as_str() {
        "auth_failed" => "credential_refused_or_auth_failed".to_string(),
        "quota_exhausted" => "provider_quota_exhausted".to_string(),
        "manual_disabled" => "operator_disabled".to_string(),
        "deleted" => "provider_key_deleted".to_string(),
        "cooldown" => "cooldown_without_timestamp".to_string(),
        "recovery_probe" => "recovery_probe_pending".to_string(),
        "degraded" => provider_key
            .last_error_code
            .as_deref()
            .map(health_summary_string)
            .unwrap_or_else(|| "degraded_without_error_code".to_string()),
        _ => provider_key
            .last_error_code
            .as_deref()
            .map(health_summary_string)
            .unwrap_or_else(|| "none".to_string()),
    }
}

fn provider_key_omitted_secret_policy() -> Value {
    json!({
        "key_secret_returned": false,
        "authorization_header_returned": false,
        "raw_endpoint_returned": false,
        "raw_payload_returned": false,
        "sealed_secret_returned": false,
        "fingerprint_returned": false,
        "public_credential_indicator": "credential_configured",
    })
}

fn provider_key_recovery_response(
    provider_key: &ProviderKey,
    previous_status: &str,
    target_status: &str,
    reason: Option<&str>,
) -> Value {
    let recovery_probe = provider_key_recovery_probe_summary(&provider_key.metadata);
    let rotation_needed = provider_key_rotation_needed(provider_key, &recovery_probe);

    json!({
        "dry_run": false,
        "controlled_status_transition": true,
        "target_status": target_status,
        "reason": reason,
        "transition": {
            "from_status": previous_status,
            "to_status": target_status,
            "allowed_source_statuses": ["cooldown", "degraded", "recovery_probe"],
            "allowed_target_statuses": ["recovery_probe", "enabled"],
        },
        "provider_key": provider_key_response(provider_key.clone()),
        "upstream_probe": {
            "executed": false,
            "mode": "not_implemented",
            "billable": false,
            "request_log_write": false,
        },
        "billing": {
            "billable": false,
            "ledger_write": false,
        },
        "credential_material": {
            "omitted": true,
            "policy": provider_key_omitted_secret_policy(),
        },
        "recovery_apply_plan_readback": provider_key_recovery_apply_plan_readback(
            provider_key,
            &rotation_needed,
        ),
        "safe_next_action": provider_key_safe_next_action(provider_key, &rotation_needed),
    })
}

fn provider_key_rotation_response(
    old_provider_key: &ProviderKey,
    new_provider_key: &ProviderKey,
    reason: Option<&str>,
) -> Value {
    json!({
        "controlled_rotation": true,
        "runtime_rotate_endpoint_implemented": true,
        "production_rotation_closure_allowed": false,
        "reason": reason,
        "old_provider_key": provider_key_response(old_provider_key.clone()),
        "new_provider_key": provider_key_response(new_provider_key.clone()),
        "old_key_transition": {
            "to_status": old_provider_key.status,
            "disabled_by_rotate_endpoint": true,
        },
        "new_key_transition": {
            "from_status": "pending_create",
            "to_status": new_provider_key.status,
        },
        "credential_material": {
            "omitted": true,
            "encrypted_at_rest": true,
            "fingerprint_returned": false,
            "policy": provider_key_omitted_secret_policy(),
        },
        "safe_next_action": "run_new_key_traffic_readback_before_retiring_old_key",
        "rotation_needed": {
            "needed": false,
            "reason": "new_key_created_by_rotation",
        },
        "audit": {
            "action": "provider_key.rotate",
            "secret_safe": true,
        },
        "production_closure_blockers": [
            "kms_or_master_key_custody_policy_missing",
            "production_live_traffic_readback_missing",
            "old_key_disable_audit_readback_missing",
        ],
    })
}

fn channel_manual_test_response(
    channel: &Channel,
    provider: &Provider,
    requested_model: &str,
    upstream_model: &str,
    has_enabled_provider_key: bool,
) -> Value {
    let protocol = channel_manual_test_protocol(&channel.protocol_mode);
    let status = channel_manual_test_status(protocol, has_enabled_provider_key);
    let next_step = channel_manual_test_next_step(protocol, has_enabled_provider_key);
    let request_plan = channel_manual_test_request_plan(protocol, upstream_model);
    let protocol_readiness =
        channel_protocol_readiness(&channel.protocol_mode, has_enabled_provider_key);
    let endpoint_capabilities =
        channel_endpoint_capabilities(&channel.protocol_mode, has_enabled_provider_key);
    let manual_test_explainability = channel_manual_test_explainability(
        protocol,
        status,
        next_step,
        has_enabled_provider_key,
        &request_plan,
        &protocol_readiness,
        &endpoint_capabilities,
    );

    json!({
        "dry_run": true,
        "test_mode": "channel_manual_test",
        "upstream_call": false,
        "protocol": protocol,
        "status": status,
        "next_step": next_step,
        "requested_model": requested_model,
        "upstream_model": upstream_model,
        "channel": {
            "id": channel.id,
            "name": channel.name,
            "status": channel.status,
            "protocol_mode": channel.protocol_mode,
            "endpoint": "omitted",
            "priority": channel.priority,
            "weight": channel.weight,
            "health_score": channel.health_score,
        },
        "provider": {
            "id": provider.id,
            "code": provider.code,
            "name": provider.name,
            "status": provider.status,
        },
        "billing": {
            "billable": false,
            "ledger_write": false,
            "request_log_write": false,
        },
        "credential_material": {
            "provider_key_secret": "omitted",
            "secret_fingerprint": "omitted",
            "authorization_header": "omitted",
            "configured": has_enabled_provider_key,
        },
        "manual_test_explainability": manual_test_explainability,
        "protocol_readiness": protocol_readiness,
        "endpoint_capabilities": endpoint_capabilities,
        "request_plan": request_plan,
        "next_steps": [
            "Dry-run only: no upstream provider call was made.",
            next_step
        ],
    })
}

fn channel_manual_test_explainability(
    protocol: &str,
    status: &str,
    safe_next_action: &str,
    has_enabled_provider_key: bool,
    request_plan: &Value,
    protocol_readiness: &Value,
    endpoint_capabilities: &Value,
) -> Value {
    json!({
        "schema": "channel_manual_test_explainability.v1",
        "protocol": protocol,
        "status": status,
        "execution_mode": "dry_run_only",
        "mock_status": protocol_readiness
            .get("mockable_config_status")
            .and_then(Value::as_str)
            .unwrap_or("unknown"),
        "live_status": protocol_readiness
            .get("live_config_status")
            .and_then(Value::as_str)
            .unwrap_or("unknown"),
        "config_needed": protocol_readiness
            .get("known_missing_pieces")
            .cloned()
            .unwrap_or_else(|| json!([])),
        "provider_key_lifecycle_summary": {
            "enabled_provider_key_present": has_enabled_provider_key,
            "secret_available_to_runtime": has_enabled_provider_key,
            "secret_returned": false,
            "fingerprint_returned": false,
            "authorization_returned": false,
            "summary": if has_enabled_provider_key {
                "enabled provider key exists for a future explicit non-billable live probe; dry-run did not open or return it"
            } else {
                "no enabled provider key is configured; dry-run can explain mock contract only"
            },
        },
        "endpoint_capability": {
            "method": request_plan.get("method").cloned().unwrap_or_else(|| json!("POST")),
            "path_template": request_plan.get("path").cloned().unwrap_or_else(|| json!("/unsupported-protocol")),
            "operation": request_plan.get("operation").cloned().unwrap_or(Value::Null),
            "mock_contract": request_plan.get("mock_contract").cloned().unwrap_or(Value::Null),
            "capabilities": endpoint_capabilities
                .get("endpoints")
                .cloned()
                .unwrap_or_else(|| json!([])),
            "raw_endpoint_returned": false,
            "raw_payload_returned": false,
        },
        "safe_next_action": safe_next_action,
        "omitted_secret_policy": {
            "provider_key_returned": false,
            "provider_key_secret_returned": false,
            "provider_key_fingerprint_returned": false,
            "authorization_header_returned": false,
            "raw_endpoint_returned": false,
            "raw_payload_returned": false,
            "omitted_fields": [
                "provider_key",
                "provider_key_secret",
                "provider_key_fingerprint",
                "authorization",
                "raw_endpoint",
                "raw_payload",
                "request_body",
                "headers"
            ],
            "policy": "presence_and_status_only",
        },
        "secret_safe": true,
    })
}

fn channel_manual_test_protocol(protocol_mode: &str) -> &'static str {
    match protocol_mode.trim() {
        "openai" | "openai_compatible" | "openai-compatible" => "openai",
        "anthropic" | "anthropic_messages" => "anthropic_messages",
        "gemini" | "gemini_generate_content" => "gemini_generate_content",
        "claude_mock" | "claude-compatible" | "claude_compatible" => "claude_compatible",
        _ => "unknown",
    }
}

fn channel_manual_test_status(protocol: &str, has_enabled_provider_key: bool) -> &'static str {
    match (protocol, has_enabled_provider_key) {
        ("unknown", _) => "config-needed",
        ("openai", false) => "config-needed",
        _ => "contract-ready",
    }
}

fn channel_manual_test_next_step(protocol: &str, has_enabled_provider_key: bool) -> &'static str {
    match (protocol, has_enabled_provider_key) {
        ("unknown", _) => "Confirm channel protocol_mode is supported before running a live probe.",
        ("openai", false) => {
            "Add an enabled provider key before running OpenAI-compatible models/chat live traffic."
        }
        ("openai", true) => {
            "OpenAI-compatible models/chat dry-run contract is ready; live probe remains explicit and non-billable."
        }
        ("anthropic_messages", false) => {
            "Anthropic Messages mock contract is ready; add a real key only when switching to live probe."
        }
        ("anthropic_messages", true) => {
            "Anthropic Messages contract is ready; live probe remains explicit and non-billable."
        }
        ("gemini_generate_content", false) => {
            "Gemini generateContent mock contract is ready; add a real key only when switching to live probe."
        }
        ("gemini_generate_content", true) => {
            "Gemini generateContent contract is ready; live probe remains explicit and non-billable."
        }
        ("claude_compatible", false) => {
            "Claude-compatible mock contract is ready; add a real key only when switching to live probe."
        }
        ("claude_compatible", true) => {
            "Claude-compatible contract is ready; live probe remains explicit and non-billable."
        }
        _ => "Review channel protocol and provider key configuration before live probe.",
    }
}

fn channel_manual_test_request_plan(protocol: &str, upstream_model: &str) -> Value {
    match protocol {
        "anthropic_messages" => json!({
            "method": "POST",
            "path": "/v1/messages",
            "protocol_mode": protocol,
            "operation": "Anthropic Messages",
            "model": upstream_model,
            "mock_contract": "anthropic.messages.v1",
        }),
        "gemini_generate_content" => json!({
            "method": "POST",
            "path": "/v1beta/models/{model}:generateContent",
            "protocol_mode": protocol,
            "operation": "Gemini generateContent",
            "model": upstream_model,
            "mock_contract": "gemini.generateContent.v1",
        }),
        "claude_compatible" => json!({
            "method": "POST",
            "path": "/v1/messages",
            "protocol_mode": protocol,
            "operation": "Claude-compatible Messages",
            "model": upstream_model,
            "mock_contract": "claude-compatible.messages.v1",
        }),
        "openai" => json!({
            "method": "POST",
            "path": "/v1/chat/completions",
            "protocol_mode": protocol,
            "operation": "OpenAI models/chat",
            "model": upstream_model,
            "mock_contract": "openai.chat.completions.v1",
        }),
        _ => json!({
            "method": "POST",
            "path": "/unsupported-protocol",
            "protocol_mode": protocol,
            "operation": "Unsupported protocol",
            "model": upstream_model,
            "mock_contract": "config-needed",
        }),
    }
}

fn channel_protocol_readiness(protocol_mode: &str, has_enabled_provider_key: bool) -> Value {
    let protocol = channel_manual_test_protocol(protocol_mode);
    let supported_endpoint_count = endpoint_capability_specs(protocol)
        .iter()
        .filter(|spec| spec.supported)
        .count();
    let status = match (protocol, supported_endpoint_count, has_enabled_provider_key) {
        ("unknown", _, _) | (_, 0, _) => "blocked",
        (_, _, true) => "live-config-ready",
        _ => "mockable-config-ready",
    };
    let live_config_status = match (protocol, supported_endpoint_count, has_enabled_provider_key) {
        ("unknown", _, _) | (_, 0, _) => "unsupported_protocol",
        (_, _, true) => "ready",
        _ => "provider_key_missing",
    };

    json!({
        "schema": "provider_channel_protocol_readiness.v1",
        "protocol_mode": health_summary_string(protocol_mode),
        "normalized_protocol": protocol,
        "status": status,
        "supported_endpoint_count": supported_endpoint_count,
        "mockable_config_status": if supported_endpoint_count > 0 { "ready" } else { "unsupported_protocol" },
        "live_config_status": live_config_status,
        "provider_key_present": has_enabled_provider_key,
        "known_missing_pieces": protocol_known_missing_pieces(protocol, has_enabled_provider_key),
        "safe_next_action": protocol_safe_next_action(protocol, has_enabled_provider_key),
        "secret_safe": true,
        "raw_endpoint_returned": false,
        "raw_payload_returned": false,
        "authorization_returned": false,
        "provider_key_returned": false,
    })
}

fn channel_endpoint_capabilities(protocol_mode: &str, has_enabled_provider_key: bool) -> Value {
    let protocol = channel_manual_test_protocol(protocol_mode);
    let capabilities = endpoint_capability_specs(protocol)
        .iter()
        .map(|spec| endpoint_capability_value(spec, protocol, has_enabled_provider_key))
        .collect::<Vec<_>>();

    json!({
        "schema": "provider_channel_endpoint_capabilities.v1",
        "protocol": protocol,
        "endpoints": capabilities,
    })
}

fn provider_protocol_readiness(channels: &[&Channel], provider_keys: &[&ProviderKey]) -> Value {
    let live_ready_channels = channels
        .iter()
        .filter(|channel| channel_has_enabled_provider_key(channel.id, provider_keys))
        .count();
    let supported_channels = channels
        .iter()
        .filter(|channel| channel_manual_test_protocol(&channel.protocol_mode) != "unknown")
        .count();
    let known_missing_pieces = if channels.is_empty() {
        vec!["enabled_channel_missing"]
    } else if supported_channels == 0 {
        vec!["supported_channel_protocol_mode_missing"]
    } else if live_ready_channels == 0 {
        vec!["enabled_provider_key_missing_for_live"]
    } else {
        Vec::new()
    };

    json!({
        "schema": "provider_protocol_readiness.v1",
        "status": if known_missing_pieces.is_empty() { "live-config-ready" } else { "attention" },
        "channel_count": channels.len(),
        "supported_protocol_channel_count": supported_channels,
        "live_ready_channel_count": live_ready_channels,
        "provider_key_present": live_ready_channels > 0,
        "known_missing_pieces": known_missing_pieces,
        "safe_next_action": if channels.is_empty() {
            "Create a channel with a supported protocol mode."
        } else if live_ready_channels > 0 {
            "Use routing dry-run before changing protocol or model bindings."
        } else {
            "Add an enabled provider key to at least one supported channel."
        },
        "secret_safe": true,
        "raw_endpoint_returned": false,
        "raw_payload_returned": false,
        "authorization_returned": false,
        "provider_key_returned": false,
    })
}

fn provider_endpoint_capabilities(channels: &[&Channel], provider_keys: &[&ProviderKey]) -> Value {
    let endpoints = [
        "chat",
        "responses",
        "embeddings",
        "anthropic_messages",
        "gemini_native",
    ]
    .into_iter()
    .map(|endpoint| {
        let supported_channel_count = channels
            .iter()
            .filter(|channel| endpoint_supported_by_protocol(endpoint, &channel.protocol_mode))
            .count();
        let live_ready_channel_count = channels
            .iter()
            .filter(|channel| {
                endpoint_supported_by_protocol(endpoint, &channel.protocol_mode)
                    && channel_has_enabled_provider_key(channel.id, provider_keys)
            })
            .count();
        let known_missing_pieces = if supported_channel_count == 0 {
            vec!["supporting_channel_protocol_missing"]
        } else if live_ready_channel_count == 0 {
            vec!["enabled_provider_key_missing_for_live"]
        } else {
            Vec::new()
        };

        json!({
            "endpoint": endpoint,
            "supported": supported_channel_count > 0,
            "supported_channel_count": supported_channel_count,
            "mockable_config_status": if supported_channel_count > 0 { "ready" } else { "unsupported_by_provider_channels" },
            "live_config_status": if live_ready_channel_count > 0 {
                "ready"
            } else if supported_channel_count > 0 {
                "blocked_provider_key_missing"
            } else {
                "unsupported_by_provider_channels"
            },
            "live_ready_channel_count": live_ready_channel_count,
            "provider_key_present": live_ready_channel_count > 0,
            "known_missing_pieces": known_missing_pieces,
            "safe_next_action": if live_ready_channel_count > 0 {
                "Use routing dry-run before live traffic."
            } else if supported_channel_count > 0 {
                "Add an enabled provider key to a supporting channel."
            } else {
                "Create or switch to a channel protocol that supports this endpoint."
            },
            "raw_endpoint_returned": false,
            "raw_payload_returned": false,
            "authorization_returned": false,
            "provider_key_returned": false,
        })
    })
    .collect::<Vec<_>>();

    json!({
        "schema": "provider_endpoint_capabilities.v1",
        "endpoints": endpoints,
    })
}

fn channel_has_enabled_provider_key(channel_id: Uuid, provider_keys: &[&ProviderKey]) -> bool {
    provider_keys.iter().any(|provider_key| {
        provider_key.channel_id == channel_id
            && provider_key.status == "enabled"
            && provider_key.has_secret_fingerprint
    })
}

fn endpoint_supported_by_protocol(endpoint: &str, protocol_mode: &str) -> bool {
    let protocol = channel_manual_test_protocol(protocol_mode);
    endpoint_capability_specs(protocol)
        .iter()
        .any(|spec| spec.endpoint == endpoint && spec.supported)
}

struct EndpointCapabilitySpec {
    endpoint: &'static str,
    operation: &'static str,
    path_template: &'static str,
    mock_contract: &'static str,
    supported: bool,
}

fn endpoint_capability_specs(protocol: &str) -> Vec<EndpointCapabilitySpec> {
    let supports_openai = protocol == "openai";
    let supports_anthropic = protocol == "anthropic_messages" || protocol == "claude_compatible";
    let supports_gemini = protocol == "gemini_generate_content";

    vec![
        EndpointCapabilitySpec {
            endpoint: "chat",
            operation: "OpenAI Chat Completions",
            path_template: "/v1/chat/completions",
            mock_contract: "openai.chat.completions.v1",
            supported: supports_openai,
        },
        EndpointCapabilitySpec {
            endpoint: "responses",
            operation: "OpenAI Responses",
            path_template: "/v1/responses",
            mock_contract: "openai.responses.v1",
            supported: supports_openai,
        },
        EndpointCapabilitySpec {
            endpoint: "embeddings",
            operation: "OpenAI Embeddings",
            path_template: "/v1/embeddings",
            mock_contract: "openai.embeddings.v1",
            supported: supports_openai,
        },
        EndpointCapabilitySpec {
            endpoint: "anthropic_messages",
            operation: "Anthropic Messages",
            path_template: "/v1/messages",
            mock_contract: "anthropic.messages.v1",
            supported: supports_anthropic,
        },
        EndpointCapabilitySpec {
            endpoint: "gemini_native",
            operation: "Gemini generateContent",
            path_template: "/v1beta/models/{model}:generateContent",
            mock_contract: "gemini.generateContent.v1",
            supported: supports_gemini,
        },
    ]
}

fn endpoint_capability_value(
    spec: &EndpointCapabilitySpec,
    protocol: &str,
    has_enabled_provider_key: bool,
) -> Value {
    let known_missing_pieces = if !spec.supported {
        vec!["channel_protocol_does_not_support_endpoint"]
    } else if has_enabled_provider_key {
        Vec::new()
    } else {
        vec!["enabled_provider_key_missing_for_live"]
    };
    let live_config_status = if !spec.supported {
        "unsupported_by_channel_protocol"
    } else if has_enabled_provider_key {
        "ready"
    } else {
        "blocked_provider_key_missing"
    };

    json!({
        "endpoint": spec.endpoint,
        "operation": spec.operation,
        "supported": spec.supported,
        "protocol": protocol,
        "path_template": spec.path_template,
        "mockable_config_status": if spec.supported { "ready" } else { "unsupported_by_channel_protocol" },
        "mock_contract": if spec.supported { spec.mock_contract } else { "unsupported_by_channel_protocol" },
        "live_config_status": live_config_status,
        "provider_key_present": has_enabled_provider_key,
        "known_missing_pieces": known_missing_pieces,
        "safe_next_action": endpoint_safe_next_action(spec.supported, has_enabled_provider_key),
        "raw_endpoint_returned": false,
        "raw_payload_returned": false,
        "authorization_returned": false,
        "provider_key_returned": false,
    })
}

fn matrix_endpoint_name(endpoint: &str) -> &'static str {
    match endpoint {
        "gemini_native" => "gemini_generate_content",
        "chat" => "chat",
        "responses" => "responses",
        "embeddings" => "embeddings",
        "anthropic_messages" => "anthropic_messages",
        _ => "unknown",
    }
}

fn protocol_capability_matrix_endpoints(
    protocol_mode: &str,
    has_enabled_provider_key: bool,
    row_blocked_reasons: &[&'static str],
) -> Vec<Value> {
    let protocol = channel_manual_test_protocol(protocol_mode);

    endpoint_capability_specs(protocol)
        .iter()
        .map(|spec| {
            let known_missing_pieces = if !spec.supported {
                vec!["channel_protocol_does_not_support_endpoint"]
            } else if !row_blocked_reasons.is_empty() {
                row_blocked_reasons.to_vec()
            } else if has_enabled_provider_key {
                Vec::new()
            } else {
                vec!["enabled_provider_key_missing_for_live"]
            };
            let status = if !spec.supported {
                "blocked"
            } else if !row_blocked_reasons.is_empty() {
                "blocked"
            } else if has_enabled_provider_key {
                "supported"
            } else {
                "config-needed"
            };

            json!({
                "endpoint": matrix_endpoint_name(spec.endpoint),
                "operation": spec.operation,
                "protocol": protocol,
                "supported": spec.supported,
                "mockable": spec.supported,
                "config_needed": spec.supported && !has_enabled_provider_key,
                "status": status,
                "mockable_config_status": if spec.supported { "ready" } else { "unsupported_by_channel_protocol" },
                "live_config_status": if !spec.supported {
                    "unsupported_by_channel_protocol"
                } else if !row_blocked_reasons.is_empty() {
                    "blocked_by_provider_channel_model_or_profile"
                } else if has_enabled_provider_key {
                    "ready"
                } else {
                    "blocked_provider_key_missing"
                },
                "blocked_reason": known_missing_pieces.first().copied(),
                "known_missing_pieces": known_missing_pieces,
                "path_template": spec.path_template,
                "raw_endpoint_returned": false,
                "raw_payload_returned": false,
                "authorization_returned": false,
                "provider_key_returned": false,
            })
        })
        .collect()
}

fn protocol_capability_matrix_row_blocked_reasons(
    provider: Option<&Provider>,
    channel: &Channel,
    model: Option<&CanonicalModel>,
    profile: Option<&ApiKeyProfile>,
) -> Vec<&'static str> {
    let mut reasons = Vec::new();
    if provider
        .map(|provider| provider.status.as_str() != "enabled")
        .unwrap_or(true)
    {
        reasons.push("provider_status_not_enabled");
    }
    if channel.status.as_str() != "enabled" {
        reasons.push("channel_status_not_enabled");
    }
    if model
        .map(|model| model.status.as_str() != "active")
        .unwrap_or(false)
    {
        reasons.push("model_status_not_active");
    }
    if profile
        .map(|profile| profile.status.as_str() != "active")
        .unwrap_or(false)
    {
        reasons.push("profile_status_not_active");
    }

    reasons
}

fn protocol_capability_matrix_row(
    provider: Option<&Provider>,
    channel: &Channel,
    model: Option<&CanonicalModel>,
    profile: Option<&ApiKeyProfile>,
    provider_keys: &[ProviderKey],
) -> Value {
    let channel_provider_keys = provider_keys
        .iter()
        .filter(|provider_key| provider_key.channel_id == channel.id)
        .collect::<Vec<_>>();
    let has_enabled_provider_key =
        channel_has_enabled_provider_key(channel.id, &channel_provider_keys);
    let protocol = channel_manual_test_protocol(&channel.protocol_mode);
    let hard_blocked_reasons =
        protocol_capability_matrix_row_blocked_reasons(provider, channel, model, profile);
    let mut blocked_reasons = hard_blocked_reasons.clone();
    blocked_reasons.extend(protocol_known_missing_pieces(
        protocol,
        has_enabled_provider_key,
    ));
    blocked_reasons.sort_unstable();
    blocked_reasons.dedup();
    let endpoints = protocol_capability_matrix_endpoints(
        &channel.protocol_mode,
        has_enabled_provider_key,
        &hard_blocked_reasons,
    );
    let supported_endpoint_count = endpoints
        .iter()
        .filter(|endpoint| {
            endpoint
                .get("supported")
                .and_then(Value::as_bool)
                .unwrap_or(false)
        })
        .count();
    json!({
        "provider_id": provider.map(|provider| provider.id),
        "provider_code": provider.map(|provider| route_dry_run_safe_text(&provider.code)),
        "provider_status": provider.map(|provider| route_dry_run_safe_text(&provider.status)),
        "channel_id": channel.id,
        "channel_name": route_dry_run_safe_text(&channel.name),
        "channel_status": route_dry_run_safe_text(&channel.status),
        "protocol_mode": route_dry_run_safe_text(&channel.protocol_mode),
        "normalized_protocol": protocol,
        "model_id": model.map(|model| model.id),
        "model_key": model.map(|model| route_dry_run_safe_text(&model.model_key)),
        "model_status": model.map(|model| route_dry_run_safe_text(&model.status)),
        "profile_id": profile.map(|profile| profile.id),
        "profile_status": profile.map(|profile| route_dry_run_safe_text(&profile.status)),
        "profile_inbound_protocol": profile.map(|profile| route_dry_run_safe_text(&profile.inbound_protocol)),
        "profile_default_protocol_mode": profile.map(|profile| route_dry_run_safe_text(&profile.default_protocol_mode)),
        "provider_key_present": has_enabled_provider_key,
        "supported_endpoint_count": supported_endpoint_count,
        "status": if !hard_blocked_reasons.is_empty() || protocol == "unknown" || supported_endpoint_count == 0 {
            "blocked"
        } else if has_enabled_provider_key {
            "supported"
        } else {
            "config-needed"
        },
        "blocked_reasons": blocked_reasons,
        "endpoints": endpoints,
        "secret_safe": true,
        "raw_endpoint_returned": false,
        "raw_payload_returned": false,
        "authorization_returned": false,
        "provider_key_returned": false,
    })
}

fn health_protocol_capability_matrix(
    providers: &[Provider],
    channels: &[Channel],
    provider_keys: &[ProviderKey],
    models: &[CanonicalModel],
    associations: &[ModelAssociation],
) -> Value {
    let provider_by_id = providers
        .iter()
        .map(|provider| (provider.id, provider))
        .collect::<BTreeMap<_, _>>();
    let channel_by_id = channels
        .iter()
        .map(|channel| (channel.id, channel))
        .collect::<BTreeMap<_, _>>();
    let model_by_id = models
        .iter()
        .map(|model| (model.id, model))
        .collect::<BTreeMap<_, _>>();
    let associated_channel_ids = associations
        .iter()
        .filter_map(|association| association.channel_id)
        .collect::<BTreeSet<_>>();
    let mut rows = Vec::new();

    for association in associations {
        if let Some(channel_id) = association.channel_id {
            let Some(channel) = channel_by_id.get(&channel_id) else {
                continue;
            };
            rows.push(protocol_capability_matrix_row(
                provider_by_id.get(&channel.provider_id).copied(),
                channel,
                model_by_id.get(&association.canonical_model_id).copied(),
                None,
                provider_keys,
            ));
        }
    }

    for channel in channels {
        if !associated_channel_ids.contains(&channel.id) {
            rows.push(protocol_capability_matrix_row(
                provider_by_id.get(&channel.provider_id).copied(),
                channel,
                None,
                None,
                provider_keys,
            ));
        }
    }

    json!({
        "schema": "provider_protocol_capability_matrix.v1",
        "dimensions": ["provider", "channel", "model"],
        "endpoints": ["chat", "responses", "embeddings", "anthropic_messages", "gemini_generate_content"],
        "row_count": rows.len(),
        "rows": rows,
        "secret_safe": true,
        "raw_endpoint_returned": false,
        "raw_payload_returned": false,
        "authorization_returned": false,
        "provider_key_returned": false,
    })
}

fn protocol_known_missing_pieces(
    protocol: &str,
    has_enabled_provider_key: bool,
) -> Vec<&'static str> {
    if protocol == "unknown" {
        vec!["supported_channel_protocol_mode_missing"]
    } else if has_enabled_provider_key {
        Vec::new()
    } else {
        vec!["enabled_provider_key_missing_for_live"]
    }
}

fn protocol_safe_next_action(protocol: &str, has_enabled_provider_key: bool) -> &'static str {
    match (protocol, has_enabled_provider_key) {
        ("unknown", _) => {
            "Set channel protocol_mode to a supported OpenAI, Anthropic, or Gemini native mode."
        }
        (_, true) => {
            "Use routing dry-run or manual-test before an explicit non-billable live probe."
        }
        _ => "Add an enabled provider key, or continue with mock-only contract checks.",
    }
}

fn endpoint_safe_next_action(supported: bool, has_enabled_provider_key: bool) -> &'static str {
    match (supported, has_enabled_provider_key) {
        (false, _) => "Choose a channel whose protocol supports this endpoint.",
        (true, true) => {
            "Use routing dry-run or manual-test before an explicit non-billable live probe."
        }
        (true, false) => {
            "Add an enabled provider key for live use, or keep this endpoint in mock-only validation."
        }
    }
}

fn channel_manual_test_upstream_model(channel: &Channel, requested_model: &str) -> String {
    channel
        .model_mappings
        .get(requested_model)
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or(requested_model)
        .to_string()
}

fn route_dry_run_response(
    project_id: Uuid,
    profile: &ApiKeyProfile,
    requested_model: String,
    seed: u64,
    context: RouteSelectionContext,
    route_candidates: Option<DbRouteCandidates>,
    fallback_canonical_model: Option<CanonicalModel>,
    default_price_book_id: Option<Uuid>,
    provider_keys: &[ProviderKey],
) -> Value {
    let (canonical_model, db_candidates) = match route_candidates {
        Some(route_candidates) => (
            Some(route_candidates.canonical_model),
            route_candidates.candidates,
        ),
        None => (fallback_canonical_model, Vec::new()),
    };
    let routing_candidates = db_candidates
        .iter()
        .map(routing_candidate_from_db_candidate)
        .collect::<Vec<_>>();
    let mut route_request = RouteRequest::new(requested_model.clone(), seed);
    if let Some(canonical_model) = canonical_model.as_ref() {
        route_request = route_request.with_canonical_model(canonical_model.model_key.clone());
    }
    let decision = select_route_with_context(route_request, routing_candidates, context);
    let snapshot = decision.snapshot();
    let candidates = db_candidates
        .iter()
        .map(|candidate| {
            route_dry_run_candidate_response(
                candidate,
                snapshot_candidate_for(&snapshot, candidate),
                profile,
                provider_keys,
            )
        })
        .collect::<Vec<_>>();
    let selected_candidate = candidates
        .iter()
        .find(|candidate| {
            candidate
                .get("selected")
                .and_then(Value::as_bool)
                .unwrap_or(false)
        })
        .cloned();

    json!({
        "project_id": project_id,
        "profile_id": profile.id,
        "requested_model": route_dry_run_safe_text(&requested_model),
        "canonical_model": canonical_model.as_ref().map(route_dry_run_canonical_model_response),
        "profile_visibility_readback": route_dry_run_profile_visibility_readback(
            profile,
            &requested_model,
            canonical_model.as_ref(),
        ),
        "price_config_presence": route_dry_run_price_config_presence(default_price_book_id),
        "diagnostic_readback": route_dry_run_diagnostic_readback(
            profile,
            &requested_model,
            canonical_model.as_ref(),
            &db_candidates,
            &candidates,
            default_price_book_id,
            provider_keys,
        ),
        "protocol_capability_matrix": route_dry_run_protocol_capability_matrix(
            profile,
            canonical_model.as_ref(),
            &db_candidates,
            provider_keys,
        ),
        "route_policy_version": ROUTE_POLICY_VERSION,
        "decision_snapshot_version": ROUTE_DECISION_SNAPSHOT_VERSION,
        "policy": route_dry_run_safe_json(&snapshot.policy),
        "trace_id": snapshot.trace_id.as_deref().map(route_dry_run_safe_text),
        "trace_affinity": route_dry_run_safe_json(&snapshot.trace_affinity),
        "selection": {
            "status": route_dry_run_selection_status(canonical_model.as_ref(), &snapshot),
            "selected_channel_id": snapshot.selected_channel_id.as_deref(),
            "selected": route_dry_run_safe_json(&snapshot.selected),
        },
        "selected_candidate": selected_candidate,
        "candidates": candidates,
        "route_decision_snapshot": route_dry_run_safe_value(route_decision_snapshot_value(&snapshot)),
    })
}

fn route_dry_run_canonical_model_response(model: &CanonicalModel) -> Value {
    json!({
        "id": model.id,
        "model_key": route_dry_run_safe_text(&model.model_key),
        "display_name": route_dry_run_safe_text(&model.display_name),
        "family": model.family.as_deref().map(route_dry_run_safe_text),
        "status": route_dry_run_safe_text(&model.status),
    })
}

fn route_dry_run_protocol_capability_matrix(
    profile: &ApiKeyProfile,
    canonical_model: Option<&CanonicalModel>,
    candidates: &[ai_gateway_db::RouteCandidate],
    provider_keys: &[ProviderKey],
) -> Value {
    let rows = candidates
        .iter()
        .map(|candidate| {
            protocol_capability_matrix_row(
                Some(&candidate.provider),
                &candidate.channel,
                canonical_model
                    .filter(|model| model.id == candidate.association.canonical_model_id),
                Some(profile),
                provider_keys,
            )
        })
        .collect::<Vec<_>>();

    json!({
        "schema": "provider_protocol_capability_matrix.v1",
        "dimensions": ["provider", "channel", "model", "profile"],
        "endpoints": ["chat", "responses", "embeddings", "anthropic_messages", "gemini_generate_content"],
        "profile_id": profile.id,
        "profile_inbound_protocol": route_dry_run_safe_text(&profile.inbound_protocol),
        "profile_default_protocol_mode": route_dry_run_safe_text(&profile.default_protocol_mode),
        "row_count": rows.len(),
        "rows": rows,
        "secret_safe": true,
        "raw_endpoint_returned": false,
        "raw_payload_returned": false,
        "authorization_returned": false,
        "provider_key_returned": false,
    })
}

fn route_dry_run_candidate_response(
    candidate: &ai_gateway_db::RouteCandidate,
    snapshot: Option<&RouteDecisionSnapshotCandidate>,
    profile: &ApiKeyProfile,
    provider_keys: &[ProviderKey],
) -> Value {
    let upstream_model = candidate.resolved_upstream_model_name.clone();
    let channel_provider_keys = provider_keys
        .iter()
        .filter(|provider_key| provider_key.channel_id == candidate.channel.id)
        .collect::<Vec<_>>();
    let has_enabled_provider_key =
        channel_has_enabled_provider_key(candidate.channel.id, &channel_provider_keys);

    json!({
        "association_id": candidate.association.id,
        "association_type": candidate.association.association_type,
        "association_priority": candidate.association.priority,
        "fallback_allowed": candidate.association.fallback_allowed,
        "canonical_model_id": candidate.association.canonical_model_id,
        "channel_id": candidate.channel.id,
        "channel_name": route_dry_run_safe_text(&candidate.channel.name),
        "channel_status": route_dry_run_safe_text(&candidate.channel.status),
        "channel_priority": candidate.channel.priority,
        "channel_weight": candidate.channel.weight,
        "channel_health_score": candidate.channel.health_score,
        "provider_id": candidate.provider.id,
        "provider_code": route_dry_run_safe_text(&candidate.provider.code),
        "provider_name": route_dry_run_safe_text(&candidate.provider.name),
        "provider_status": route_dry_run_safe_text(&candidate.provider.status),
        "provider_model": route_dry_run_safe_text(&upstream_model),
        "upstream_model": route_dry_run_safe_text(&candidate.resolved_upstream_model_name),
        "protocol_mode": route_dry_run_safe_text(&candidate.channel.protocol_mode),
        "priority": snapshot.map(|candidate| candidate.priority),
        "weight": snapshot.map(|candidate| candidate.weight),
        "routing_status": snapshot.map(|candidate| candidate.status),
        "routing_health": snapshot.map(|candidate| candidate.health),
        "rate_limit_available": snapshot.map(|candidate| candidate.rate_limit_available),
        "filtered": snapshot.map(|candidate| candidate.filtered).unwrap_or(true),
        "filter_reason": snapshot.and_then(|candidate| candidate.filter_reason),
        "score": snapshot
            .and_then(|candidate| candidate.score)
            .map(route_dry_run_safe_json),
        "selected": snapshot.map(|candidate| candidate.selected).unwrap_or(false),
        "trace_affinity_match": snapshot
            .map(|candidate| candidate.trace_affinity_match)
            .unwrap_or(false),
        "provider_key_presence": {
            "configured": channel_provider_keys.iter().any(|provider_key| provider_key.has_secret_fingerprint),
            "enabled_configured": has_enabled_provider_key,
            "provider_key_count": channel_provider_keys.len(),
            "enabled_provider_key_count": channel_provider_keys
                .iter()
                .filter(|provider_key| provider_key.status == "enabled" && provider_key.has_secret_fingerprint)
                .count(),
            "credential_material_returned": false,
        },
        "blocked_reasons": route_dry_run_candidate_blocked_reasons(
            candidate,
            snapshot,
            profile,
            has_enabled_provider_key,
        ),
        "protocol_endpoint_capability_readiness": channel_endpoint_capabilities(
            &candidate.channel.protocol_mode,
            has_enabled_provider_key,
        ),
        "endpoint_configured": !candidate.channel.endpoint.trim().is_empty(),
        "safe_next_action": route_dry_run_candidate_safe_next_action(
            candidate,
            snapshot,
            has_enabled_provider_key,
        ),
    })
}

fn route_dry_run_profile_visibility_readback(
    profile: &ApiKeyProfile,
    requested_model: &str,
    canonical_model: Option<&CanonicalModel>,
) -> Value {
    let allowed_models = json_string_array(&profile.allowed_models);
    let denied_models = json_string_array(&profile.denied_models);
    let allowed_channel_tags = json_string_array(&profile.allowed_channel_tags);
    let blocked_provider_ids = json_string_array(&profile.blocked_provider_ids);
    let canonical_model_key = canonical_model.map(|model| model.model_key.as_str());
    let requested_model_decision = match canonical_model_key {
        Some(model_key) if denied_models.iter().any(|denied| denied == model_key) => "denied",
        Some(model_key)
            if allowed_models.is_empty()
                || allowed_models.iter().any(|allowed| allowed == model_key) =>
        {
            "allowed"
        }
        Some(_) => "not_in_allowed_models",
        None => "model_not_found_or_not_allowed",
    };

    json!({
        "schema": "model_profile_visibility_diagnostics.v1",
        "profile_id": profile.id,
        "project_id": profile.project_id,
        "profile_status": route_dry_run_safe_text(&profile.status),
        "credential_scope": "profile",
        "requested_model": route_dry_run_safe_text(requested_model),
        "canonical_model_key": canonical_model_key.map(route_dry_run_safe_text),
        "requested_model_decision": requested_model_decision,
        "allowed_models": {
            "mode": if allowed_models.is_empty() { "all_visible_models" } else { "explicit_list" },
            "models": allowed_models.iter().map(|value| route_dry_run_safe_text(value)).collect::<Vec<_>>(),
            "count": allowed_models.len(),
        },
        "denied_models": {
            "models": denied_models.iter().map(|value| route_dry_run_safe_text(value)).collect::<Vec<_>>(),
            "count": denied_models.len(),
        },
        "allowed_channel_tags": {
            "mode": if allowed_channel_tags.is_empty() { "all_channel_tags" } else { "explicit_list" },
            "tags": allowed_channel_tags.iter().map(|value| route_dry_run_safe_text(value)).collect::<Vec<_>>(),
            "count": allowed_channel_tags.len(),
        },
        "blocked_provider_ids": {
            "ids": blocked_provider_ids.iter().map(|value| route_dry_run_safe_text(value)).collect::<Vec<_>>(),
            "count": blocked_provider_ids.len(),
        },
        "credential_material_returned": false,
        "authorization_returned": false,
        "raw_upstream_model_payload_returned": false,
    })
}

fn route_dry_run_price_config_presence(default_price_book_id: Option<Uuid>) -> Value {
    json!({
        "schema": "model_price_config_presence.v1",
        "default_price_book_configured": default_price_book_id.is_some(),
        "default_price_book_id": default_price_book_id,
        "active_price_version_selector": "active_effective_version_for_default_price_book",
        "pricing_rules_returned": false,
        "safe_next_action": if default_price_book_id.is_some() {
            "Use model price versions to verify active/effective pricing before billing-sensitive traffic."
        } else {
            "Attach a default price book to the canonical model before billing-sensitive traffic."
        },
    })
}

fn route_dry_run_diagnostic_readback(
    profile: &ApiKeyProfile,
    requested_model: &str,
    canonical_model: Option<&CanonicalModel>,
    db_candidates: &[ai_gateway_db::RouteCandidate],
    candidate_values: &[Value],
    default_price_book_id: Option<Uuid>,
    provider_keys: &[ProviderKey],
) -> Value {
    let selected_count = candidate_values
        .iter()
        .filter(|candidate| {
            candidate
                .get("selected")
                .and_then(Value::as_bool)
                .unwrap_or(false)
        })
        .count();
    let filtered_count = candidate_values
        .iter()
        .filter(|candidate| {
            candidate
                .get("filtered")
                .and_then(Value::as_bool)
                .unwrap_or(false)
        })
        .count();
    let blocked_reasons = candidate_values
        .iter()
        .filter_map(|candidate| candidate.get("blocked_reasons").and_then(Value::as_array))
        .flat_map(|reasons| reasons.iter().filter_map(Value::as_str))
        .map(ToString::to_string)
        .collect::<BTreeSet<_>>();
    let candidate_channel_ids = db_candidates
        .iter()
        .map(|candidate| candidate.channel.id)
        .collect::<BTreeSet<_>>();
    let enabled_configured_provider_key_count = provider_keys
        .iter()
        .filter(|provider_key| {
            candidate_channel_ids.contains(&provider_key.channel_id)
                && provider_key.status == "enabled"
                && provider_key.has_secret_fingerprint
        })
        .count();
    let safe_next_action = route_dry_run_safe_next_action(
        canonical_model,
        selected_count,
        db_candidates.len(),
        filtered_count,
        default_price_book_id,
        enabled_configured_provider_key_count,
    );

    json!({
        "schema": "model_profile_visibility_diagnostics_readback.v1",
        "profile_id": profile.id,
        "project_id": profile.project_id,
        "requested_model": route_dry_run_safe_text(requested_model),
        "candidate_count": db_candidates.len(),
        "selected_candidate_count": selected_count,
        "filtered_candidate_count": filtered_count,
        "blocked_provider_channel_reasons": blocked_reasons.into_iter().collect::<Vec<_>>(),
        "provider_key_presence": {
            "candidate_channel_count": candidate_channel_ids.len(),
            "enabled_configured_provider_key_count": enabled_configured_provider_key_count,
            "credential_material_returned": false,
        },
        "price_config_present": default_price_book_id.is_some(),
        "protocol_endpoint_capability_readiness_present": candidate_values.iter().any(|candidate| {
            candidate.get("protocol_endpoint_capability_readiness").is_some()
        }),
        "safe_next_action": safe_next_action,
        "secret_safety": {
            "provider_key_returned": false,
            "authorization_returned": false,
            "raw_upstream_model_payload_returned": false,
            "raw_channel_endpoint_returned": false,
        },
    })
}

fn route_dry_run_candidate_blocked_reasons(
    candidate: &ai_gateway_db::RouteCandidate,
    snapshot: Option<&RouteDecisionSnapshotCandidate>,
    profile: &ApiKeyProfile,
    has_enabled_provider_key: bool,
) -> Vec<&'static str> {
    let mut reasons = Vec::new();
    if candidate.provider.status != "enabled" {
        reasons.push("provider_status_not_enabled");
    }
    if matches!(
        candidate.channel.status.as_str(),
        "disabled" | "manual_disabled" | "deleted"
    ) {
        reasons.push("channel_status_not_enabled");
    }
    if !has_enabled_provider_key {
        reasons.push("enabled_provider_key_missing_for_live");
    }
    if !profile_allowed_channel_tags_match(profile, &candidate.channel) {
        reasons.push("profile_allowed_channel_tags_do_not_match");
    }
    if json_string_array(&profile.blocked_provider_ids)
        .iter()
        .any(|provider_id| provider_id == &candidate.provider.id.to_string())
    {
        reasons.push("profile_blocks_provider");
    }
    if snapshot
        .and_then(|snapshot| snapshot.filter_reason)
        .is_some()
    {
        reasons.push("routing_policy_filtered_candidate");
    }

    reasons
}

fn route_dry_run_candidate_safe_next_action(
    candidate: &ai_gateway_db::RouteCandidate,
    snapshot: Option<&RouteDecisionSnapshotCandidate>,
    has_enabled_provider_key: bool,
) -> &'static str {
    if snapshot
        .map(|candidate| candidate.selected)
        .unwrap_or(false)
    {
        "Use a non-billable manual test before sending live traffic."
    } else if snapshot
        .and_then(|candidate| candidate.filter_reason)
        .is_some()
    {
        "Inspect routing status, health, and rate-limit availability for this channel."
    } else if candidate.channel.status != "enabled" {
        "Enable or recover the channel before live traffic."
    } else if !has_enabled_provider_key {
        "Add an enabled configured provider key for this channel."
    } else {
        "Review priority, weight, and trace affinity against the selected candidate."
    }
}

fn route_dry_run_safe_next_action(
    canonical_model: Option<&CanonicalModel>,
    selected_count: usize,
    candidate_count: usize,
    filtered_count: usize,
    default_price_book_id: Option<Uuid>,
    enabled_configured_provider_key_count: usize,
) -> &'static str {
    if canonical_model.is_none() {
        "Check profile allowed/denied models and canonical model visibility."
    } else if candidate_count == 0 {
        "Create or enable a model association and matching channel for this profile."
    } else if selected_count == 0 && filtered_count == candidate_count {
        "Inspect blocked provider/channel reasons, health, rate limits, and profile channel tags."
    } else if enabled_configured_provider_key_count == 0 {
        "Add an enabled configured provider key before live traffic."
    } else if default_price_book_id.is_none() {
        "Attach a default price book before billing-sensitive traffic."
    } else {
        "Run manual-test or a bounded gateway smoke before changing live traffic."
    }
}

fn profile_allowed_channel_tags_match(profile: &ApiKeyProfile, channel: &Channel) -> bool {
    let allowed_tags = json_string_array(&profile.allowed_channel_tags);
    if allowed_tags.is_empty() {
        return true;
    }

    allowed_tags.iter().any(|tag| {
        channel.tags.get(tag).is_some() || json_string_array(&channel.tags).contains(tag)
    })
}

fn json_string_array(value: &Value) -> Vec<String> {
    value
        .as_array()
        .map(|values| {
            values
                .iter()
                .filter_map(Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(ToString::to_string)
                .collect()
        })
        .unwrap_or_default()
}

fn snapshot_candidate_for<'a>(
    snapshot: &'a RouteDecisionSnapshot,
    candidate: &ai_gateway_db::RouteCandidate,
) -> Option<&'a RouteDecisionSnapshotCandidate> {
    snapshot.candidates.iter().find(|snapshot_candidate| {
        snapshot_candidate.channel_id == candidate.channel.id.to_string()
            && snapshot_candidate.provider_id == candidate.provider.id.to_string()
            && snapshot_candidate.provider_model == candidate.resolved_upstream_model_name
    })
}

fn route_dry_run_selection_status(
    canonical_model: Option<&CanonicalModel>,
    snapshot: &RouteDecisionSnapshot,
) -> &'static str {
    if snapshot.selected.is_some() {
        "selected"
    } else if snapshot.candidates.is_empty() {
        if canonical_model.is_some() {
            "no_route_candidates"
        } else {
            "model_not_found_or_not_allowed"
        }
    } else {
        "all_candidates_filtered"
    }
}

fn route_selection_context(
    trace_id: Option<String>,
    previous_successful_channel_id: Option<String>,
) -> RouteSelectionContext {
    let mut context = RouteSelectionContext::new();
    if let Some(trace_id) = trace_id {
        context = context.with_trace_id(trace_id);
    }
    if let Some(channel_id) = previous_successful_channel_id {
        context = context.with_trace_affinity_channel(channel_id);
    }
    context
}

fn routing_candidate_from_db_candidate(
    candidate: &ai_gateway_db::RouteCandidate,
) -> RoutingRouteCandidate {
    RoutingRouteCandidate::new(
        candidate.channel.id.to_string(),
        candidate.provider.id.to_string(),
        candidate.resolved_upstream_model_name.clone(),
        route_priority_for_routing(&candidate.association, &candidate.channel),
        u32::try_from(candidate.channel.weight).unwrap_or(0),
    )
    .with_status(channel_status_for_routing(&candidate.channel.status))
    .with_health(channel_health_for_routing(candidate.channel.health_score))
}

fn route_priority_for_routing(association: &ModelAssociation, channel: &Channel) -> i32 {
    association
        .priority
        .saturating_mul(ROUTE_PRIORITY_ASSOCIATION_MULTIPLIER)
        .saturating_add(channel.priority)
}

fn channel_status_for_routing(status: &str) -> ChannelStatus {
    match status {
        "enabled" => ChannelStatus::Enabled,
        "degraded" => ChannelStatus::Degraded,
        "disabled" => ChannelStatus::Disabled,
        "cooldown" | "cooling_down" => ChannelStatus::CoolingDown,
        "recovery_probe" => ChannelStatus::RecoveryProbe,
        "auth_failed" => ChannelStatus::AuthFailed,
        "quota_exhausted" => ChannelStatus::QuotaExhausted,
        "manual_disabled" => ChannelStatus::ManualDisabled,
        "deleted" => ChannelStatus::Deleted,
        _ => ChannelStatus::Disabled,
    }
}

fn channel_health_for_routing(health_score: f64) -> ChannelHealth {
    if !health_score.is_finite() || health_score <= 0.0 {
        ChannelHealth::Unhealthy
    } else if health_score < 0.5 {
        ChannelHealth::Degraded
    } else {
        ChannelHealth::Healthy
    }
}

fn route_decision_snapshot_value(snapshot: &RouteDecisionSnapshot) -> Value {
    serde_json::to_value(snapshot).unwrap_or_else(|_| json!({}))
}

fn route_dry_run_safe_text(value: &str) -> String {
    redact_secrets(value)
        .replace("Authorization", "[REDACTED]")
        .replace("authorization", "[REDACTED]")
        .replace("api_key", "[REDACTED]")
}

fn route_dry_run_safe_value(value: Value) -> Value {
    route_dry_run_scrub_safe_value(redact_payload_value(&value))
}

fn route_dry_run_scrub_safe_value(value: Value) -> Value {
    match value {
        Value::String(value) => Value::String(route_dry_run_safe_text(&value)),
        Value::Array(values) => Value::Array(
            values
                .into_iter()
                .map(route_dry_run_scrub_safe_value)
                .collect(),
        ),
        Value::Object(map) => Value::Object(
            map.into_iter()
                .map(|(key, value)| (key, route_dry_run_scrub_safe_value(value)))
                .collect(),
        ),
        value => value,
    }
}

fn route_dry_run_safe_json(value: impl Serialize) -> Value {
    route_dry_run_safe_value(serde_json::to_value(value).unwrap_or(Value::Null))
}

fn virtual_key_response(virtual_key: VirtualKey, secret: Option<String>) -> Value {
    let policy_diagnostics = virtual_key_policy_diagnostics(&virtual_key);
    let mut response = json!({
        "id": virtual_key.id,
        "tenant_id": virtual_key.tenant_id,
        "project_id": virtual_key.project_id,
        "name": virtual_key.name,
        "key_prefix": virtual_key.key_prefix,
        "status": normalize_virtual_key_status_for_response(&virtual_key.status),
        "default_profile_id": virtual_key.default_profile_id,
        "ip_allowlist": virtual_key.ip_allowlist,
        "rate_limit_policy": virtual_key.rate_limit_policy,
        "budget_policy": virtual_key.budget_policy,
        "policy_diagnostics": policy_diagnostics,
        "metadata": redact_provider_key_metadata(virtual_key.metadata),
        "secret_redacted": secret.is_none(),
    });

    if let Some(secret) = secret {
        let object = response
            .as_object_mut()
            .expect("virtual key response must be a JSON object");
        object.insert("secret".to_string(), Value::String(secret));
        object.insert("secret_once".to_string(), Value::Bool(true));
    }

    response
}

fn virtual_key_policy_diagnostics(virtual_key: &VirtualKey) -> Value {
    let rate_limit = virtual_key_rate_limit_diagnostics(&virtual_key.rate_limit_policy);
    let budget = virtual_key_budget_diagnostics(&virtual_key.budget_policy);
    let active = normalize_virtual_key_status_for_response(&virtual_key.status) == "active";
    let mut blocked_reasons = Vec::new();

    if !active {
        blocked_reasons.push("virtual_key_not_active");
    }
    if budget["status"] == "not_configured" {
        blocked_reasons.push("budget_policy_not_configured");
    }

    let safe_next_action = if !active {
        "restore_or_create_active_virtual_key"
    } else if budget["status"] == "not_configured" {
        "configure_project_or_virtual_key_budget_policy_before_budget_enforcement"
    } else if rate_limit["status"] == "not_configured" {
        "configure_rate_limit_policy_before_traffic_ramp"
    } else {
        "inspect_request_log_preauthorize_and_rate_limit_explainability_for_runtime_rejects"
    };

    json!({
        "schema": "virtual_key_project_budget_policy_diagnostics_readback.v1",
        "budget": budget,
        "rate_limit": rate_limit,
        "profile": {
            "default_profile_present": virtual_key.default_profile_id.is_some(),
            "blocked_reason": if virtual_key.default_profile_id.is_some() { Value::Null } else { Value::String("default_profile_missing".to_string()) },
        },
        "current_usage_summary": {
            "status": "not_loaded_for_virtual_key_readback",
            "source": "request_log_and_ledger_diagnostics_required",
            "raw_window_state_returned": false,
            "raw_payload_returned": false,
        },
        "blocked_reasons": blocked_reasons,
        "reject_reason": if active { Value::Null } else { Value::String("virtual_key_not_active".to_string()) },
        "safe_next_action": safe_next_action,
        "refs_presence": {
            "ledger_ref_present": false,
            "preauth_ref_present": false,
            "request_log_ref_present": false,
            "source": "virtual_key_readback_does_not_load_runtime_refs",
        },
        "omitted_fields": [
            "raw_api_key_secret",
            "secret_hash",
            "authorization",
            "provider_key",
            "raw_payload",
            "raw_rate_limit_current_window_state",
            "raw_ledger_metadata"
        ],
        "secret_safe": true,
    })
}

fn virtual_key_rate_limit_diagnostics(policy: &Value) -> Value {
    let policy_present = json_object_has_entries(policy);
    let rpm_limit_present =
        json_number_or_string_present(policy, &["rpm", "rpm_limit", "requests_per_minute"]);
    let tpm_limit_present =
        json_number_or_string_present(policy, &["tpm", "tpm_limit", "tokens_per_minute"]);
    let concurrency_limit_present = json_number_or_string_present(
        policy,
        &[
            "concurrency",
            "concurrency_limit",
            "concurrent_requests",
            "max_concurrency",
        ],
    );
    let limit_present = rpm_limit_present || tpm_limit_present || concurrency_limit_present;
    let window_present = json_number_or_string_present(
        policy,
        &[
            "window_seconds",
            "window",
            "rpm_window_seconds",
            "tpm_window_seconds",
        ],
    );
    let status = if limit_present {
        "configured"
    } else if policy_present {
        "policy_present_limit_missing"
    } else {
        "not_configured"
    };

    json!({
        "status": status,
        "policy_present": policy_present,
        "limit_present": limit_present,
        "window_present": window_present,
        "limits": {
            "rpm_limit_present": rpm_limit_present,
            "tpm_limit_present": tpm_limit_present,
            "concurrency_limit_present": concurrency_limit_present,
        },
        "current_usage_summary": {
            "status": "not_loaded_for_virtual_key_readback",
            "raw_window_state_returned": false,
        },
        "blocked_reason": if policy_present && !limit_present { Value::String("rate_limit_policy_has_no_known_limits".to_string()) } else { Value::Null },
        "reject_reason": Value::Null,
        "safe_next_action": if limit_present { "monitor_request_log_rate_limit_diagnostics" } else { "set_rpm_tpm_or_concurrency_limit" },
    })
}

fn virtual_key_budget_diagnostics(policy: &Value) -> Value {
    let policy_present = json_object_has_entries(policy);
    let limit_present = json_number_or_string_present(
        policy,
        &[
            "max_cost",
            "monthly_budget",
            "budget",
            "limit",
            "amount",
            "daily_budget",
        ],
    );
    let window_present =
        json_number_or_string_present(policy, &["window", "window_seconds", "period", "interval"]);
    let status = if limit_present {
        "configured"
    } else if policy_present {
        "policy_present_limit_missing"
    } else {
        "not_configured"
    };

    json!({
        "status": status,
        "policy_present": policy_present,
        "limit_present": limit_present,
        "window_present": window_present,
        "current_usage_summary": {
            "status": "not_loaded_for_virtual_key_readback",
            "source": "ledger_window_not_loaded",
        },
        "blocked_reason": if policy_present && !limit_present { Value::String("budget_policy_has_no_known_limit".to_string()) } else { Value::Null },
        "reject_reason": Value::Null,
        "safe_next_action": if limit_present { "inspect_request_log_preauthorize_diagnostics_for_runtime_budget_status" } else { "set_budget_limit_and_window" },
    })
}

fn json_object_has_entries(value: &Value) -> bool {
    value.as_object().is_some_and(|object| !object.is_empty())
}

fn json_number_or_string_present(value: &Value, fields: &[&str]) -> bool {
    fields.iter().any(|field| {
        value.get(*field).is_some_and(|candidate| {
            candidate.is_number()
                || candidate
                    .as_str()
                    .is_some_and(|text| !text.trim().is_empty())
        })
    })
}

fn virtual_key_leak_action_response(
    virtual_key: &VirtualKey,
    action_result: &str,
    audit_log_id: Option<Uuid>,
) -> Value {
    json!({
        "key_id": virtual_key.id,
        "key_prefix": virtual_key.key_prefix,
        "status": normalize_virtual_key_status_for_response(&virtual_key.status),
        "action_result": action_result,
        "audit_log_id": audit_log_id,
    })
}

fn virtual_key_leak_action_missing_response(key_id: Uuid, action_result: &str) -> Value {
    json!({
        "key_id": key_id,
        "key_prefix": null,
        "status": null,
        "action_result": action_result,
        "audit_log_id": null,
    })
}

fn virtual_key_leak_candidate_response(virtual_key: &VirtualKey) -> Option<Value> {
    let leak_detection = virtual_key.metadata.get("leak_detection")?;
    if !leak_detection
        .get("suspected_leaked")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        return None;
    }

    let status = normalize_virtual_key_status_for_response(&virtual_key.status);
    let confidence = leak_detection
        .get("confidence")
        .and_then(Value::as_f64)
        .unwrap_or(0.7)
        .clamp(0.0, 1.0);
    let action_recommendation = if status == "active" && confidence >= 0.85 {
        "operator_confirm_disable_or_revoke"
    } else if status == "active" {
        "operator_review_then_confirm"
    } else {
        "monitor_or_close_after_review"
    };

    Some(json!({
        "key_id": virtual_key.id,
        "key_prefix": virtual_key.key_prefix,
        "status": status,
        "reason": leak_detection_text(leak_detection, "reason", "operator marked suspected leaked"),
        "source": leak_detection_text(leak_detection, "source", "operator_report"),
        "safe_markers": virtual_key_leak_safe_markers(leak_detection),
        "rule_status": virtual_key_leak_rule_status(leak_detection),
        "next_step": leak_detection_text(
            leak_detection,
            "next_step",
            "operator_review_then_confirm_disable_or_revoke"
        ),
        "first_seen": leak_detection.get("first_seen").and_then(Value::as_str),
        "last_seen": leak_detection.get("last_seen").and_then(Value::as_str),
        "confidence": confidence,
        "action_recommendation": action_recommendation,
        "operator_confirmation_required": true,
        "automatic_action": false,
    }))
}

const VIRTUAL_KEY_SCANNER_PROVIDER_ENV: &str = "AI_GATEWAY_VIRTUAL_KEY_SCANNER_PROVIDER";
const VIRTUAL_KEY_SCANNER_STATUS_ENV: &str = "AI_GATEWAY_VIRTUAL_KEY_SCANNER_STATUS";
const VIRTUAL_KEY_SCANNER_ENDPOINT_REF_ENV: &str = "AI_GATEWAY_VIRTUAL_KEY_SCANNER_ENDPOINT_REF";
const VIRTUAL_KEY_SCANNER_SECRET_REF_ENV: &str = "AI_GATEWAY_VIRTUAL_KEY_SCANNER_SECRET_REF";
const VIRTUAL_KEY_SCANNER_WEBHOOK_REF_ENV: &str = "AI_GATEWAY_VIRTUAL_KEY_SCANNER_WEBHOOK_REF";
const VIRTUAL_KEY_SCANNER_SYNC_DIRECTION_ENV: &str =
    "AI_GATEWAY_VIRTUAL_KEY_SCANNER_SYNC_DIRECTION";
const VIRTUAL_KEY_EXTERNAL_SCANNER_HANDOFF_MAX_FINDINGS: u32 = 10_000;
const VIRTUAL_KEY_EXTERNAL_SCANNER_HANDOFF_HASH_MAX_BYTES: usize = 128;

#[derive(Debug)]
struct NormalizedVirtualKeyExternalScannerHandoff {
    provider: String,
    finding_count: u32,
    key_prefix_present: bool,
    key_hash_present: bool,
    repo_ref_hash: String,
    severity: String,
    detected_at: String,
    signature_validated: bool,
    virtual_key_id: Option<Uuid>,
}

fn virtual_key_leak_candidate_source_policy() -> Value {
    let scanner_adapter = virtual_key_external_scanner_adapter_readback(None);
    json!({
        "source_policy_version": "virtual-key-leak-detection-rules-v1",
        "accepted_candidate_sources": [
            "operator_report",
            "internal_audit_handoff",
            "external_scanner_handoff",
            "support_ticket_handoff"
        ],
        "safe_markers": [
            {
                "marker": "manual_marker",
                "status": "active",
                "next_step": "operator_review_then_confirm_disable_or_revoke"
            },
            {
                "marker": "audit_marker",
                "status": "active",
                "next_step": "read_admin_audit_log_then_confirm_action"
            },
            {
                "marker": "external_scanner_config_needed",
                "status": "config-needed",
                "next_step": "configure_external_scanner_adapter_handoff_without_raw_payloads"
            }
        ],
        "scanner_adapter": scanner_adapter,
        "candidate_only_until_confirmed": true,
        "forbidden_response_material": [
            "virtual_key_secret",
            "secret_hash",
            "key_hash",
            "raw_token",
            "authorization_header",
            "scanner_secret",
            "raw_leak_payload",
            "raw_finding",
            "request_body"
        ],
        "destructive_actions_require_operator_confirmation": ["disable", "revoke"],
    })
}

fn virtual_key_external_scanner_adapter_readback(last_scan_marker: Option<Value>) -> Value {
    let provider = normalize_virtual_key_scanner_provider(
        std::env::var(VIRTUAL_KEY_SCANNER_PROVIDER_ENV)
            .ok()
            .as_deref(),
    );
    let requested_status = normalize_virtual_key_scanner_status(
        std::env::var(VIRTUAL_KEY_SCANNER_STATUS_ENV)
            .ok()
            .as_deref(),
    );
    let endpoint_ref_present = env_ref_present(VIRTUAL_KEY_SCANNER_ENDPOINT_REF_ENV);
    let secret_ref_present = env_ref_present(VIRTUAL_KEY_SCANNER_SECRET_REF_ENV);
    let webhook_ref_present = env_ref_present(VIRTUAL_KEY_SCANNER_WEBHOOK_REF_ENV);
    let sync_direction = normalize_virtual_key_scanner_sync_direction(
        std::env::var(VIRTUAL_KEY_SCANNER_SYNC_DIRECTION_ENV)
            .ok()
            .as_deref(),
    );
    let blocked_reason = virtual_key_scanner_blocked_reason(
        &provider,
        endpoint_ref_present,
        secret_ref_present,
        webhook_ref_present,
    );
    let readiness = if blocked_reason.is_none() && requested_status == "configured" {
        "ready-for-metadata-handoff"
    } else {
        "blocked"
    };
    let status = if readiness == "ready-for-metadata-handoff" {
        "configured"
    } else {
        "config-needed"
    };

    json!({
        "provider": provider,
        "status": status,
        "endpoint_ref_present": endpoint_ref_present,
        "secret_ref_present": secret_ref_present,
        "webhook_ref_present": webhook_ref_present,
        "sync_direction": sync_direction,
        "last_scan_marker": last_scan_marker.unwrap_or_else(|| json!({
            "status": "not_run",
            "source": "external_scanner_adapter",
            "marker_present": false,
            "raw_findings_returned": false
        })),
        "readiness": readiness,
        "blocked_reason": blocked_reason,
        "external_scanner_connected": false,
        "accepts_raw_payloads": false,
        "network_call_performed": false,
        "raw_findings_returned": false,
        "next_step": "configure external scanner refs and submit bounded handoff metadata only"
    })
}

fn virtual_key_leak_last_scan_marker(leak_candidates: &[Value]) -> Value {
    let external_candidate_count = leak_candidates
        .iter()
        .filter(|candidate| {
            candidate.get("source").and_then(Value::as_str) == Some("external_scanner_handoff")
        })
        .count();
    let last_seen = leak_candidates
        .iter()
        .filter(|candidate| {
            candidate.get("source").and_then(Value::as_str) == Some("external_scanner_handoff")
        })
        .filter_map(|candidate| candidate.get("last_seen").and_then(Value::as_str))
        .max()
        .map(str::to_string);
    let marker_counts = virtual_key_leak_marker_counts(leak_candidates);

    json!({
        "status": if external_candidate_count > 0 { "metadata_seen" } else { "not_run" },
        "source": "virtual_keys.metadata.leak_detection",
        "marker_present": external_candidate_count > 0,
        "external_candidate_count": external_candidate_count,
        "marker_counts": marker_counts,
        "last_seen": last_seen,
        "raw_findings_returned": false
    })
}

fn virtual_key_leak_marker_counts(leak_candidates: &[Value]) -> Value {
    let mut counts: BTreeMap<String, usize> = BTreeMap::new();
    for marker in leak_candidates
        .iter()
        .filter_map(|candidate| candidate.get("safe_markers").and_then(Value::as_array))
        .flatten()
        .filter_map(Value::as_str)
    {
        *counts.entry(marker.to_string()).or_default() += 1;
    }
    json!(counts)
}

fn env_ref_present(name: &str) -> bool {
    std::env::var(name)
        .ok()
        .map(|value| !value.trim().is_empty())
        .unwrap_or(false)
}

fn normalize_virtual_key_scanner_provider(value: Option<&str>) -> String {
    match value.map(str::trim).filter(|value| !value.is_empty()) {
        Some("github_secret_scanning") => "github_secret_scanning".to_string(),
        Some("gitleaks") => "gitleaks".to_string(),
        Some("trufflehog") => "trufflehog".to_string(),
        Some("custom") => "custom".to_string(),
        _ => "unconfigured".to_string(),
    }
}

fn normalize_virtual_key_scanner_status(value: Option<&str>) -> String {
    match value.map(str::trim).filter(|value| !value.is_empty()) {
        Some("configured") | Some("ready") => "configured".to_string(),
        Some("disabled") => "disabled".to_string(),
        _ => "config-needed".to_string(),
    }
}

fn normalize_virtual_key_scanner_sync_direction(value: Option<&str>) -> String {
    match value.map(str::trim).filter(|value| !value.is_empty()) {
        Some("external_to_control_plane") | Some("external_to_control_plane_metadata_only") => {
            "external_to_control_plane_metadata_only".to_string()
        }
        Some("control_plane_to_external") => "control_plane_to_external_disabled".to_string(),
        _ => "external_to_control_plane_metadata_only".to_string(),
    }
}

fn virtual_key_scanner_blocked_reason(
    provider: &str,
    endpoint_ref_present: bool,
    secret_ref_present: bool,
    webhook_ref_present: bool,
) -> Option<&'static str> {
    if provider == "unconfigured" {
        Some("provider_config_missing")
    } else if !endpoint_ref_present {
        Some("endpoint_ref_missing")
    } else if !secret_ref_present {
        Some("secret_ref_missing")
    } else if !webhook_ref_present {
        Some("webhook_ref_missing")
    } else {
        None
    }
}

fn normalize_virtual_key_external_scanner_handoff(
    request: VirtualKeyExternalScannerHandoffRequest,
) -> Result<NormalizedVirtualKeyExternalScannerHandoff, AdminError> {
    let provider = normalize_virtual_key_scanner_provider(Some(&request.provider));
    if provider == "unconfigured" {
        return Err(AdminError::bad_request(
            "provider must be github_secret_scanning, gitleaks, trufflehog, or custom",
        ));
    }
    if request.finding_count == 0
        || request.finding_count > VIRTUAL_KEY_EXTERNAL_SCANNER_HANDOFF_MAX_FINDINGS
    {
        return Err(AdminError::bad_request(
            "finding_count must be between 1 and 10000",
        ));
    }
    if !request.key_prefix_present && !request.key_hash_present {
        return Err(AdminError::bad_request(
            "key_prefix_present or key_hash_present must be true",
        ));
    }
    let repo_ref_hash = request.repo_ref_hash.trim();
    if !is_safe_external_scanner_hash_ref(repo_ref_hash) {
        return Err(AdminError::bad_request(
            "repo_ref_hash must be a bounded hex/base64url hash reference",
        ));
    }
    let severity = normalize_virtual_key_external_scanner_severity(&request.severity)?;
    let detected_at = request.detected_at.trim();
    if !is_bounded_timestamp_text(detected_at) {
        return Err(AdminError::bad_request(
            "detected_at must be a bounded timestamp string",
        ));
    }

    Ok(NormalizedVirtualKeyExternalScannerHandoff {
        provider,
        finding_count: request.finding_count,
        key_prefix_present: request.key_prefix_present,
        key_hash_present: request.key_hash_present,
        repo_ref_hash: repo_ref_hash.to_string(),
        severity,
        detected_at: detected_at.to_string(),
        signature_validated: request.signature_validated,
        virtual_key_id: request.virtual_key_id,
    })
}

fn normalize_virtual_key_external_scanner_severity(value: &str) -> Result<String, AdminError> {
    match value.trim().to_ascii_lowercase().as_str() {
        "info" | "low" | "medium" | "high" | "critical" => Ok(value.trim().to_ascii_lowercase()),
        _ => Err(AdminError::bad_request(
            "severity must be info, low, medium, high, or critical",
        )),
    }
}

fn is_safe_external_scanner_hash_ref(value: &str) -> bool {
    !value.is_empty()
        && value.len() <= VIRTUAL_KEY_EXTERNAL_SCANNER_HANDOFF_HASH_MAX_BYTES
        && value
            .bytes()
            .all(|byte| byte.is_ascii_alphanumeric() || matches!(byte, b'-' | b'_'))
}

fn is_bounded_timestamp_text(value: &str) -> bool {
    !value.is_empty()
        && value.len() <= 64
        && value.bytes().all(|byte| {
            byte.is_ascii_alphanumeric() || matches!(byte, b'-' | b':' | b'.' | b'+' | b'Z')
        })
}

fn virtual_key_external_scanner_handoff_forbidden_field(value: &Value) -> Option<String> {
    match value {
        Value::Object(map) => map.iter().find_map(|(key, nested)| {
            if virtual_key_external_scanner_handoff_forbidden_name(key) {
                Some(key.clone())
            } else if let Some(text) = nested.as_str() {
                virtual_key_external_scanner_handoff_forbidden_text(text)
                    .then(|| key.clone())
                    .or_else(|| virtual_key_external_scanner_handoff_forbidden_field(nested))
            } else {
                virtual_key_external_scanner_handoff_forbidden_field(nested)
            }
        }),
        Value::Array(values) => values
            .iter()
            .find_map(virtual_key_external_scanner_handoff_forbidden_field),
        Value::String(text) => {
            virtual_key_external_scanner_handoff_forbidden_text(text).then(|| "value".to_string())
        }
        _ => None,
    }
}

fn virtual_key_external_scanner_handoff_forbidden_name(name: &str) -> bool {
    let normalized = name
        .chars()
        .filter(|character| character.is_ascii_alphanumeric())
        .collect::<String>()
        .to_ascii_lowercase();
    matches!(
        normalized.as_str(),
        "rawfinding"
            | "rawfindings"
            | "finding"
            | "findings"
            | "rawtoken"
            | "token"
            | "rawkey"
            | "key"
            | "secret"
            | "scannersecret"
            | "authorization"
            | "authorizationheader"
            | "webhookbody"
            | "body"
            | "payload"
            | "rawpayload"
            | "secretkey"
            | "secrethash"
            | "hash"
    )
}

fn virtual_key_external_scanner_handoff_forbidden_text(text: &str) -> bool {
    let lower = text.to_ascii_lowercase();
    lower.contains("authorization:")
        || lower.contains("bearer ")
        || lower.contains("vk_")
        || lower.contains("secret=")
        || lower.contains("token=")
        || lower.contains("-----begin ")
}

fn virtual_key_external_scanner_handoff_omitted_fields() -> Value {
    json!([
        "raw_finding",
        "raw_findings",
        "raw_token",
        "raw_key",
        "virtual_key_secret",
        "secret_hash",
        "key_hash_value",
        "Authorization",
        "scanner_secret",
        "webhook_body",
        "request_body",
        "raw_payload"
    ])
}

fn virtual_key_leak_safe_markers(leak_detection: &Value) -> Vec<String> {
    let mut markers = leak_detection
        .get("safe_markers")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_str)
        .map(str::trim)
        .filter(|marker| {
            matches!(
                *marker,
                "manual_marker"
                    | "audit_marker"
                    | "external_scanner_config_needed"
                    | "external_scanner_summary_marker"
            )
        })
        .map(str::to_string)
        .collect::<Vec<_>>();

    if markers.is_empty() {
        let source = leak_detection_text(leak_detection, "source", "operator_report");
        match source {
            "internal_audit_handoff" => markers.push("audit_marker".to_string()),
            "external_scanner_handoff" => {
                markers.push("external_scanner_summary_marker".to_string())
            }
            _ => markers.push("manual_marker".to_string()),
        }
    }

    markers.sort();
    markers.dedup();
    markers
}

fn virtual_key_leak_rule_status(leak_detection: &Value) -> &str {
    if let Some(status) = leak_detection
        .get("rule_status")
        .and_then(Value::as_str)
        .filter(|status| {
            matches!(
                status.trim(),
                "manual_marker_active" | "audit_marker_active" | "external_scanner_config_needed"
            )
        })
    {
        return status;
    }

    match leak_detection_text(leak_detection, "source", "operator_report") {
        "internal_audit_handoff" => "audit_marker_active",
        "external_scanner_handoff" => "external_scanner_config_needed",
        _ => "manual_marker_active",
    }
}

fn leak_detection_text<'a>(value: &'a Value, field: &str, fallback: &'a str) -> &'a str {
    value
        .get(field)
        .and_then(Value::as_str)
        .filter(|text| !text.trim().is_empty())
        .unwrap_or(fallback)
}

fn bulk_virtual_key_leak_action_result_summary(
    operation_id: Uuid,
    action: &str,
    results: &[Value],
    audit_log_ids: &[Uuid],
) -> Value {
    let failed_count = results
        .iter()
        .filter(|result| result.get("action_result").and_then(Value::as_str) == Some("not_found"))
        .count();
    let affected_count = results.len().saturating_sub(failed_count);

    json!({
        "operation_id": operation_id,
        "action": action,
        "affected_count": affected_count,
        "failed_count": failed_count,
        "audit_log_ids": audit_log_ids,
        "request_id": null,
        "secret_safe": true,
        "payload_omitted": true,
    })
}

fn virtual_key_restore_response(
    virtual_key: &VirtualKey,
    action_result: &str,
    audit_log_id: Uuid,
    safety_reason: Option<&str>,
) -> Value {
    json!({
        "key_id": virtual_key.id,
        "id": virtual_key.id,
        "key_prefix": virtual_key.key_prefix,
        "status": normalize_virtual_key_status_for_response(&virtual_key.status),
        "action_result": action_result,
        "audit_log_id": audit_log_id,
        "restore_supported": action_result == "restored" || action_result == "unchanged_active",
        "safety_reason": safety_reason,
        "secret_returned": false,
    })
}

