async fn get_admin_managed_user_detail_response(
    state: &ControlPlaneState,
    user: AdminManagedUserRow,
) -> Result<Value, AdminError> {
    let user_id = user.id;
    let project_ids = user.project_ids.clone();
    let summaries = get_admin_managed_user_detail_summaries(state, user_id, &project_ids).await?;
    let tenant_boundary = admin_managed_user_tenant_boundary_summary(&user, &summaries);
    let risk_policy_summary = admin_managed_user_risk_policy_summary(&user, &summaries);
    let membership_summary = admin_user_membership_compact_summary(state, &user).await?;

    Ok(json!({
        "schema": "admin_managed_user_detail.v1",
        "user": admin_managed_user_response(user),
        "membership_summary": membership_summary,
        "wallet_summary": summaries.wallet_summary,
        "funding_source_readback": summaries.funding_source_readback,
        "key_summary": summaries.key_summary,
        "request_summary": summaries.request_summary,
        "ledger_summary": summaries.ledger_summary,
        "recent_audit_summary": summaries.recent_audit_summary,
        "risk_policy_summary": risk_policy_summary,
        "tenant_boundary": tenant_boundary,
        "project_rollup_fallback": {
            "supported": true,
            "source": "wallet_virtual_key_request_ledger_rollup",
            "write_allowed": false,
            "requires_user_id_for_status_write": true
        },
        "omitted_fields": admin_managed_user_detail_omitted_fields(),
        "secret_safe": true,
        "production_audit_report": {
            "schema": "admin_user_production_audit_report_minimal.v1",
            "status": "minimal-readback",
            "source": "audit_logs",
            "external_siem_connected": false,
            "raw_snapshots_returned": false,
            "next_step": "connect production audit export or SIEM adapter when operator evidence is required"
        }
    }))
}

struct AdminManagedUserDetailSummaries {
    wallet_summary: Value,
    funding_source_readback: Value,
    key_summary: Value,
    request_summary: Value,
    ledger_summary: Value,
    recent_audit_summary: Value,
}

async fn get_admin_managed_user_detail_summaries(
    state: &ControlPlaneState,
    user_id: Uuid,
    project_ids: &[Uuid],
) -> Result<AdminManagedUserDetailSummaries, AdminError> {
    let row = sqlx::query(
        r#"
        with project_scope as (
          select unnest($2::uuid[]) as project_id
        ),
        wallet_stats as (
          select
            count(*)::bigint as wallet_count,
            count(*) filter (where w.status = 'active')::bigint as active_wallet_count,
            coalesce(jsonb_agg(distinct w.currency) filter (where w.currency is not null), '[]'::jsonb) as wallet_currencies,
            min(w.created_at)::text as first_wallet_created_at,
            max(w.updated_at)::text as last_wallet_updated_at
          from wallets w
          join project_scope ps on ps.project_id = w.project_id
          where w.tenant_id = $1 and w.deleted_at is null
        ),
        key_stats as (
          select
            count(*)::bigint as key_count,
            count(*) filter (where vk.status = 'active')::bigint as active_key_count,
            count(*) filter (where vk.status in ('disabled', 'revoked', 'expired'))::bigint as inactive_key_count,
            max(vk.last_used_at)::text as last_key_used_at,
            coalesce(jsonb_agg(distinct jsonb_build_object(
              'key_id', vk.id,
              'key_prefix', vk.key_prefix,
              'status', vk.status,
              'project_id', vk.project_id,
              'last_used_at', vk.last_used_at::text
            )) filter (where vk.id is not null), '[]'::jsonb) as recent_keys
          from virtual_keys vk
          join project_scope ps on ps.project_id = vk.project_id
          where vk.tenant_id = $1 and vk.deleted_at is null
        ),
        request_stats as (
          select
            count(*)::bigint as request_count,
            count(*) filter (where rl.status = 'succeeded')::bigint as succeeded_count,
            count(*) filter (where rl.status in ('failed', 'rejected', 'cancelled'))::bigint as failed_count,
            coalesce(sum(rl.input_tokens), 0)::bigint as input_tokens,
            coalesce(sum(rl.output_tokens), 0)::bigint as output_tokens,
            coalesce(sum(rl.final_cost), 0)::text as final_cost,
            max(rl.created_at)::text as last_request_at,
            coalesce(jsonb_agg(distinct rl.currency) filter (where rl.currency is not null), '[]'::jsonb) as request_currencies,
            coalesce(jsonb_agg(distinct rl.error_code) filter (where rl.error_code is not null), '[]'::jsonb) as recent_error_codes
          from request_logs rl
          join project_scope ps on ps.project_id = rl.project_id
          where rl.tenant_id = $1
        ),
        ledger_stats as (
          select
            count(*)::bigint as ledger_entry_count,
            count(*) filter (where le.status = 'confirmed')::bigint as confirmed_entry_count,
            coalesce(sum(case when le.status = 'confirmed' and le.amount > 0 then le.amount else 0 end), 0)::text as confirmed_credit_total,
            coalesce(sum(case when le.status = 'confirmed' and le.amount < 0 then -le.amount else 0 end), 0)::text as confirmed_debit_total,
            max(le.created_at)::text as last_ledger_entry_at,
            coalesce(jsonb_agg(distinct le.currency) filter (where le.currency is not null), '[]'::jsonb) as ledger_currencies
          from ledger_entries le
          join project_scope ps on ps.project_id = le.project_id
          where le.tenant_id = $1
        ),
        audit_stats as (
          select
            count(*)::bigint as audit_log_count,
            max(al.created_at)::text as last_audit_at,
            coalesce(jsonb_agg(distinct al.action) filter (where al.action is not null), '[]'::jsonb) as recent_actions
          from audit_logs al
          where al.tenant_id = $1
            and (
              (al.resource_type = 'user' and al.resource_id = $3)
              or (al.actor_user_id = $3)
            )
        )
        select
          wallet_stats.*,
          key_stats.*,
          request_stats.*,
          ledger_stats.*,
          audit_stats.*
        from wallet_stats, key_stats, request_stats, ledger_stats, audit_stats
        "#,
    )
    .bind(DEFAULT_TENANT_ID)
    .bind(project_ids.to_vec())
    .bind(user_id)
    .fetch_one(state.db())
    .await
    .map_err(|error| AdminError::from(DbError::Query(error)))?;

    let wallet_count: i64 = row.try_get("wallet_count").map_err(DbError::Query)?;
    let active_wallet_count: i64 = row.try_get("active_wallet_count").map_err(DbError::Query)?;
    let key_count: i64 = row.try_get("key_count").map_err(DbError::Query)?;
    let active_key_count: i64 = row.try_get("active_key_count").map_err(DbError::Query)?;
    let inactive_key_count: i64 = row.try_get("inactive_key_count").map_err(DbError::Query)?;
    let request_count: i64 = row.try_get("request_count").map_err(DbError::Query)?;
    let succeeded_count: i64 = row.try_get("succeeded_count").map_err(DbError::Query)?;
    let failed_count: i64 = row.try_get("failed_count").map_err(DbError::Query)?;
    let ledger_entry_count: i64 = row.try_get("ledger_entry_count").map_err(DbError::Query)?;
    let confirmed_entry_count: i64 = row
        .try_get("confirmed_entry_count")
        .map_err(DbError::Query)?;
    let audit_log_count: i64 = row.try_get("audit_log_count").map_err(DbError::Query)?;
    let funding_source_readback =
        admin_wallet_funding_source_readback(state, None, project_ids).await?;

    Ok(AdminManagedUserDetailSummaries {
        wallet_summary: json!({
            "source": "wallets",
            "project_scoped": true,
            "wallet_count": wallet_count,
            "active_wallet_count": active_wallet_count,
            "currencies": row.try_get::<Value, _>("wallet_currencies").map_err(DbError::Query)?,
            "first_wallet_created_at": row.try_get::<Option<String>, _>("first_wallet_created_at").map_err(DbError::Query)?,
            "last_wallet_updated_at": row.try_get::<Option<String>, _>("last_wallet_updated_at").map_err(DbError::Query)?,
            "readback_status": if project_ids.is_empty() { "no-project-membership" } else { "ready" },
        }),
        funding_source_readback,
        key_summary: json!({
            "source": "virtual_keys",
            "project_scoped": true,
            "key_count": key_count,
            "active_key_count": active_key_count,
            "inactive_key_count": inactive_key_count,
            "last_key_used_at": row.try_get::<Option<String>, _>("last_key_used_at").map_err(DbError::Query)?,
            "recent_keys": row.try_get::<Value, _>("recent_keys").map_err(DbError::Query)?,
            "secret_returned": false,
        }),
        request_summary: json!({
            "source": "request_logs",
            "project_scoped": true,
            "request_count": request_count,
            "succeeded_count": succeeded_count,
            "failed_count": failed_count,
            "success_rate": ratio_value(succeeded_count, request_count),
            "input_tokens": row.try_get::<i64, _>("input_tokens").map_err(DbError::Query)?,
            "output_tokens": row.try_get::<i64, _>("output_tokens").map_err(DbError::Query)?,
            "final_cost": row.try_get::<String, _>("final_cost").map_err(DbError::Query)?,
            "currencies": row.try_get::<Value, _>("request_currencies").map_err(DbError::Query)?,
            "last_request_at": row.try_get::<Option<String>, _>("last_request_at").map_err(DbError::Query)?,
            "recent_error_codes": row.try_get::<Value, _>("recent_error_codes").map_err(DbError::Query)?,
            "payload_returned": false,
        }),
        ledger_summary: json!({
            "source": "ledger_entries",
            "project_scoped": true,
            "ledger_entry_count": ledger_entry_count,
            "confirmed_entry_count": confirmed_entry_count,
            "confirmed_credit_total": row.try_get::<String, _>("confirmed_credit_total").map_err(DbError::Query)?,
            "confirmed_debit_total": row.try_get::<String, _>("confirmed_debit_total").map_err(DbError::Query)?,
            "currencies": row.try_get::<Value, _>("ledger_currencies").map_err(DbError::Query)?,
            "last_ledger_entry_at": row.try_get::<Option<String>, _>("last_ledger_entry_at").map_err(DbError::Query)?,
            "idempotency_key_returned": false,
        }),
        recent_audit_summary: json!({
            "schema": "admin_user_recent_audit_summary.v1",
            "source": "audit_logs",
            "audit_log_count": audit_log_count,
            "last_audit_at": row.try_get::<Option<String>, _>("last_audit_at").map_err(DbError::Query)?,
            "recent_actions": row.try_get::<Value, _>("recent_actions").map_err(DbError::Query)?,
            "raw_snapshots_returned": false,
            "metadata_sanitized": true,
        }),
    })
}

fn ratio_value(numerator: i64, denominator: i64) -> Option<f64> {
    if denominator <= 0 {
        None
    } else {
        Some((numerator as f64 / denominator as f64 * 10_000.0).round() / 10_000.0)
    }
}

fn admin_managed_user_tenant_boundary_summary(
    user: &AdminManagedUserRow,
    summaries: &AdminManagedUserDetailSummaries,
) -> Value {
    json!({
        "schema": "admin_user_tenant_boundary.v1",
        "tenant_id": user.tenant_id,
        "requested_user_id": user.id,
        "tenant_scope": "current_admin_tenant",
        "cross_tenant_lookup_allowed": false,
        "cross_tenant_result_count": 0,
        "project_ids": user.project_ids,
        "project_count": user.project_ids.len(),
        "project_rollup_fallback_write_allowed": false,
        "source_tables": ["users", "project_members", "wallets", "virtual_keys", "request_logs", "ledger_entries", "audit_logs"],
        "boundary_status": if summaries.wallet_summary.get("readback_status").and_then(Value::as_str) == Some("no-project-membership") {
            "no-project-membership"
        } else {
            "tenant-scoped"
        },
    })
}

fn admin_managed_user_risk_policy_summary(
    user: &AdminManagedUserRow,
    summaries: &AdminManagedUserDetailSummaries,
) -> Value {
    let active_key_count = summaries
        .key_summary
        .get("active_key_count")
        .and_then(Value::as_i64)
        .unwrap_or_default();
    let failed_count = summaries
        .request_summary
        .get("failed_count")
        .and_then(Value::as_i64)
        .unwrap_or_default();
    let risk_level = if user.status == "disabled" {
        "attention"
    } else if active_key_count == 0 {
        "config-needed"
    } else if failed_count >= 10 {
        "attention"
    } else {
        "normal"
    };

    json!({
        "schema": "admin_user_risk_policy_summary.v1",
        "status": risk_level,
        "policy_source": "local_readback_rules",
        "external_ml_connected": false,
        "external_siem_connected": false,
        "automatic_enforcement": false,
        "operator_confirmation_required": true,
        "signals": {
            "user_status": user.status,
            "active_key_count": active_key_count,
            "failed_request_count": failed_count,
            "project_count": user.project_ids.len(),
        },
        "recommendation": match risk_level {
            "attention" => "operator_review_user_status_keys_and_recent_failures",
            "config-needed" => "issue_or_restore_an_api_key_before_gateway_use",
            _ => "monitor",
        },
        "forbidden_material_returned": false,
    })
}

