    #[test]
    fn production_read_model_status_and_next_step_do_not_claim_live_clickhouse_smoke() {
        let postgres = PostgresReadModelStatus {
            status: "ready",
            request_count: 1,
            tokenized_request_count: 1,
            latest_request_created_at: Some("2026-06-12T12:00:00Z".to_string()),
            latest_completed_at: Some("2026-06-12T12:00:01Z".to_string()),
            lag_seconds: Some(30),
            staleness: "fresh",
        };
        let tokenizer = tokenizer_read_model_status(
            1,
            1,
            TokenizerConfigPresence {
                backend: false,
                model: false,
                config_path: false,
            },
        );

        assert_eq!(
            production_read_model_status("clickhouse", &tokenizer, &postgres),
            "ready"
        );
        assert_eq!(
            production_read_model_next_step("clickhouse", &tokenizer, &postgres),
            "ClickHouse config is present; live ClickHouse connectivity remains an explicit operator smoke outside this endpoint."
        );
        assert_eq!(read_model_staleness(None), "no-signal");
        assert_eq!(read_model_staleness(Some(300)), "fresh");
        assert_eq!(read_model_staleness(Some(3600)), "stale");
        assert_eq!(read_model_staleness(Some(3601)), "very-stale");
    }

