    #[test]
    fn enterprise_oidc_jwt_jwks_executor_boundary_blocks_unsupported_alg_and_network() {
        let now = enterprise_oidc_current_unix_seconds();
        let (adapter, crypto_result, parser_passed, failure_reasons) =
            enterprise_oidc_jwt_jwks_parser_fetch_adapter_readback(
                Some(EnterpriseOidcJwtJwksParserFetchRequest {
                    issuer: Some("https://idp.example.com".to_string()),
                    issuer_url: None,
                    jwks_uri: Some("https://idp.example.com/.well-known/jwks.json".to_string()),
                    jwks_uri_ref: None,
                    kid: Some("kid-1".to_string()),
                    alg: Some("HS256".to_string()),
                    audience: Some("control-plane".to_string()),
                    nonce: Some("nonce-hash-marker".to_string()),
                    subject_hash: Some(
                        "0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef"
                            .to_string(),
                    ),
                    crypto_parser: Some(EnterpriseOidcJwtJwksCryptoParserMetadata {
                        header_alg: Some("HS256".to_string()),
                        header_kid: Some("kid-1".to_string()),
                        jwks_key_kid: Some("kid-1".to_string()),
                        jwks_key_alg: Some("HS256".to_string()),
                        claims_issuer_url: Some("https://idp.example.com".to_string()),
                        claims_audience: Some("control-plane".to_string()),
                        claims_nonce_present: Some(true),
                        claims_nonce_matches_request: Some(false),
                        claims_exp_unix: Some(now - 600),
                        claims_iat_unix: Some(now - 60),
                        claims_subject_hash: Some(
                            "0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef"
                                .to_string(),
                        ),
                        signature_verified: Some(true),
                    }),
                }),
                None,
                "0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef",
            )
            .expect("unsupported alg should return blocked readback");

        assert!(!parser_passed);
        assert_eq!(
            adapter["executor_boundary"],
            json!("typed_fetch_parse_executor")
        );
        assert_eq!(
            adapter["fetch_request_plan"]["network_enabled"],
            json!(false)
        );
        assert_eq!(
            adapter["fetch_request_plan"]["network_call_performed"],
            json!(false)
        );
        assert_eq!(adapter["fetch_request_plan"]["alg"], json!("HS256"));
        assert_eq!(
            adapter["fetch_request_plan"]["alg_allowlisted"],
            json!(false)
        );
        assert_eq!(adapter["blocked"], json!(true));
        assert!(
            adapter["blocked_reasons"]
                .as_array()
                .unwrap()
                .contains(&json!("unsupported_alg"))
        );
        assert!(
            adapter["blocked_reasons"]
                .as_array()
                .unwrap()
                .contains(&json!("nonce_mismatch"))
        );
        assert!(
            adapter["blocked_reasons"]
                .as_array()
                .unwrap()
                .contains(&json!("expired_token_metadata"))
        );
        assert!(
            adapter["blocked_reasons"]
                .as_array()
                .unwrap()
                .contains(&json!("network_disabled"))
        );
        assert_eq!(
            adapter["parser_input_summary"]["raw_jwks_body_present"],
            json!(false)
        );
        assert_eq!(adapter["crypto_result_readback"], crypto_result);
        assert!(failure_reasons.contains(&"header_alg_not_allowlisted".to_string()));
    }

