    #[test]
    fn workers_jobs_dashboard_route_and_contract_are_wired() {
        let source = include_str!("admin.rs");
        assert!(source.contains("\"/admin/workers/jobs-dashboard\""));
        assert!(source.contains("get(get_workers_jobs_dashboard)"));
        assert!(source.contains("\"schema\": \"admin_workers_jobs_dashboard.v1\""));
        for expected in [
            "\"runtime_daemon_started\": false",
            "\"network_requests_executed\": false",
            "\"business_table_writes_performed\": false",
            "\"authorization_returned\": false",
            "\"session_token_returned\": false",
            "\"provider_key_returned\": false",
            "\"db_url_returned\": false",
            "\"raw_payload_returned\": false",
            "\"raw_sql_returned\": false",
            "\"raw_webhook_body_returned\": false",
            "\"raw_metadata_returned\": false",
        ] {
            assert!(
                source.contains(expected),
                "workers/jobs dashboard source missing {expected}"
            );
        }

        let openapi = include_str!("../../../examples/openapi_admin_skeleton.yaml");
        assert!(openapi.contains("/admin/workers/jobs-dashboard"));
        assert!(openapi.contains("AdminWorkersJobsDashboard"));
        assert!(openapi.contains("admin_workers_jobs_dashboard.v1"));
        assert!(openapi.contains("admin_workers_jobs_dashboard_section.v1"));

        let client = include_str!("../../../web/admin-ui/src/api/client.ts");
        assert!(client.contains("export type AdminWorkersJobsDashboard"));
        assert!(client.contains("getAdminWorkersJobsDashboard"));
        assert!(client.contains("/admin/workers/jobs-dashboard"));
    }

    #[test]
    fn setup_readback_response_reports_local_seed_without_secrets() {
        let mut provider = provider_fixture();
        provider.code = "mock-openai".to_string();
        provider.status = "enabled".to_string();
        let mut channel = channel_fixture();
        channel.id = Uuid::from_u128(0x70);
        channel.provider_id = provider.id;
        channel.name = "mock-openai-default".to_string();
        channel.status = "enabled".to_string();
        let mut provider_key = provider_key_fixture(channel.id);
        provider_key.key_alias = "mock-dev-key".to_string();
        provider_key.status = "enabled".to_string();
        provider_key.has_secret_fingerprint = true;
        let mut model = canonical_model_fixture();
        model.id = Uuid::from_u128(0x80);
        model.model_key = "mock-gpt-4o-mini".to_string();
        model.status = "active".to_string();
        let mut association = model_association_fixture();
        association.canonical_model_id = model.id;
        association.channel_id = Some(channel.id);
        association.status = "enabled".to_string();
        let mut profile = api_key_profile_fixture();
        profile.status = "active".to_string();
        let mut virtual_key = virtual_key_fixture();
        virtual_key.key_prefix = "dev_test_key".to_string();
        virtual_key.status = "active".to_string();
        let mut request_log = request_log_summary_fixture(
            91,
            "succeeded",
            None,
            provider.id,
            channel.id,
            provider_key.id,
            model.id,
        );
        request_log.requested_model = Some("mock-gpt-4o-mini".to_string());

        let response = setup_readback_response(
            true,
            &[provider],
            &[channel],
            &[provider_key],
            &[model],
            &[association],
            &[profile],
            &[virtual_key],
            &[request_log],
        );
        let serialized = serde_json::to_string(&response).expect("setup readback should serialize");

        assert_eq!(response["schema"], json!("admin_setup_readback.v1"));
        assert_eq!(response["state"], json!("ready"));
        assert_eq!(response["local_seed"]["admin_exists"], json!(true));
        assert_eq!(
            response["local_seed"]["test_key"]["secret_returned"],
            json!(false)
        );
        assert_eq!(
            response["gateway"]["model_readiness"]["status"],
            json!("ready")
        );
        assert_eq!(
            response["gateway"]["chat_readiness"]["status"],
            json!("ready")
        );
        assert_eq!(
            response["first_run_readiness"]["schema"],
            json!("admin_setup_first_run_readiness.v1")
        );
        assert_eq!(response["first_run_readiness"]["status"], json!("ready"));
        assert_eq!(
            response["first_run_readiness"]["admin"]["status"],
            json!("ready")
        );
        assert_eq!(
            response["first_run_readiness"]["mock_provider"]["status"],
            json!("ready")
        );
        assert_eq!(
            response["first_run_readiness"]["mock_channel"]["status"],
            json!("ready")
        );
        assert_eq!(
            response["first_run_readiness"]["mock_model"]["status"],
            json!("ready")
        );
        assert_eq!(
            response["first_run_readiness"]["test_key"]["status"],
            json!("ready")
        );
        assert_eq!(
            response["first_run_readiness"]["gateway_chat"]["status"],
            json!("ready")
        );
        assert_eq!(
            response["first_run_readiness"]["gateway_responses"]["status"],
            json!("ready")
        );
        assert_eq!(
            response["first_run_readiness"]["gateway_embeddings"]["status"],
            json!("ready")
        );
        assert_eq!(
            response["first_run_readiness"]["api_key_secret_returned"],
            json!(false)
        );
        assert_eq!(
            response["first_run_readiness"]["api_key_secret_hash_returned"],
            json!(false)
        );
        assert_eq!(
            response["first_run_readiness"]["provider_secret_returned"],
            json!(false)
        );
        assert_eq!(
            response["first_run_readiness"]["provider_secret_hash_returned"],
            json!(false)
        );
        assert!(response["blockers"].as_array().is_some_and(Vec::is_empty));
        for forbidden in [
            "sk-live",
            "Bearer ",
            "secret-hash-never-return",
            "raw body never audit",
            "raw payload never audit",
            "provider_key_secret",
            "Authorization",
            "api_key_hash",
            "provider_key_hash",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "setup readback must not contain {forbidden}"
            );
        }
    }

