    #[test]
    fn health_summary_response_counts_entities_and_omits_secret_material() {
        let candidate = route_candidate_fixture(401, "enabled", 100, 1.0);
        let provider = Provider {
            name: "Provider sk-live-provider-name-never-return".to_string(),
            metadata: json!({
                "secret": "sk-live-provider-metadata-never-return",
                "secret_fingerprint": "fingerprint-never-return"
            }),
            ..candidate.provider
        };
        let mut channel = candidate.channel;
        channel.endpoint = "https://provider.example/v1?api_key=sk-live-endpoint".to_string();
        let mut provider_key = provider_key_fixture(channel.id);
        provider_key.key_alias = "sk-live-provider-key-alias-never-return".to_string();
        let model = canonical_model_fixture();
        let association = ModelAssociation {
            id: Uuid::from_u128(301),
            tenant_id: DEFAULT_TENANT_ID,
            canonical_model_id: model.id,
            association_type: "explicit_channel".to_string(),
            channel_id: Some(channel.id),
            channel_tag: None,
            model_pattern: None,
            upstream_model_name: Some("upstream-gpt".to_string()),
            priority: 1,
            conditions: json!({}),
            fallback_allowed: true,
            canary_percent: 100.0,
            status: "enabled".to_string(),
        };
        let logs = vec![
            request_log_summary_fixture(
                2,
                "failed",
                Some("provider_auth_failed"),
                provider.id,
                channel.id,
                provider_key.id,
                model.id,
            ),
            request_log_summary_fixture(
                1,
                "succeeded",
                None,
                provider.id,
                channel.id,
                provider_key.id,
                model.id,
            ),
        ];

        let response = health_summary_response(
            &[provider],
            &[channel],
            &[provider_key],
            &[model],
            &[association],
            &logs,
            ProviderHealthSummaryFilter {
                window_minutes: 15,
                sample_limit: 500,
            },
        );
        let serialized = serde_json::to_string(&response).expect("response should serialize");

        assert_eq!(response["summary_version"], json!(1));
        assert_eq!(
            response["probe_status"],
            json!({
                "status": "scheduler_pending",
                "probe_source": "request_logs",
                "scheduler_pending": true,
                "next_probe": null
            })
        );
        assert_eq!(response["recent_window"]["window_minutes"], json!(15));
        assert_eq!(
            response["recent_window"]["window"],
            json!({ "unit": "minutes", "minutes": 15 })
        );
        assert_eq!(response["recent_window"]["sample_count"], json!(2));
        assert_eq!(response["recent_window"]["success_count"], json!(1));
        assert_eq!(response["recent_window"]["error_count"], json!(1));
        assert_eq!(response["recent_window"]["success_rate"], json!(0.5));
        assert_eq!(response["recent_window"]["avg_latency_ms"], json!(12.0));
        assert_eq!(response["recent_window"]["p95_latency_ms"], json!(12));
        assert_eq!(
            response["recent_window"]["error_top"],
            json!([{ "code": "provider_auth_failed", "count": 1 }])
        );
        assert_eq!(response["status_counts"]["providers"]["enabled"], json!(1));
        assert_eq!(response["status_counts"]["channels"]["enabled"], json!(1));
        assert_eq!(
            response["status_counts"]["provider_keys"]["auth_failed"],
            json!(1)
        );
        assert_eq!(response["status_counts"]["models"]["active"], json!(1));
        assert_eq!(
            response["providers"][0]["recent"]["request_count"],
            json!(2)
        );
        assert_eq!(
            response["providers"][0]["recent"]["success_count"],
            json!(1)
        );
        assert_eq!(response["providers"][0]["recent"]["error_count"], json!(1));
        assert_eq!(
            response["providers"][0]["recent"]["success_rate"],
            json!(0.5)
        );
        assert_eq!(
            response["providers"][0]["recent"]["avg_latency_ms"],
            json!(12.0)
        );
        assert_eq!(
            response["providers"][0]["recent"]["error_top"],
            json!([{ "code": "provider_auth_failed", "count": 1 }])
        );
        assert_eq!(
            response["provider_keys"][0]["credential_configured"],
            json!(true)
        );
        assert_eq!(
            response["provider_keys"][0]["configured_last_error_code"],
            json!("provider_auth_failed")
        );
        assert_eq!(
            response["provider_keys"][0]["recovery_probe"],
            json!({
                "result": "failure",
                "error_code": "provider_auth_failed",
                "last_checked_at": "2026-06-02T12:04:00.000000Z"
            })
        );
        assert_eq!(
            response["provider_keys"][0]["recovery_action_readback"],
            json!({
                "schema": "provider_key_recovery_action_readback.v1",
                "suggested_action": "rotate_provider_key_secret",
                "operator_confirmation_required": true,
                "last_probe_status": "failure",
                "cooldown_or_refusal_reason": "cooldown_until_present",
                "safe_next_action": "rotate_provider_key_secret_then_request_recovery_probe",
                "upstream_probe_executed": false,
                "secret_safe": true,
                "omitted_secret_policy": {
                    "key_secret_returned": false,
                    "authorization_header_returned": false,
                    "raw_endpoint_returned": false,
                    "raw_payload_returned": false,
                    "sealed_secret_returned": false,
                    "fingerprint_returned": false,
                    "public_credential_indicator": "credential_configured"
                }
            })
        );
        assert_eq!(
            response["provider_keys"][0]["recovery_apply_plan_readback"],
            json!({
                "schema": "provider_key_recovery_apply_plan_readback.v1",
                "suggested_action": "rotate_provider_key_secret",
                "preconditions": [
                    "operator_confirmation_required",
                    "local_status_transition_only",
                    "provider_network_call_forbidden",
                    "live_provider_smoke_forbidden",
                    "credential_configured",
                    "recovery_endpoint_source_status_not_allowed",
                    "new_secret_material_required_for_rotate_endpoint"
                ],
                "would_enable": false,
                "would_rotate": true,
                "would_probe": true,
                "would_refuse": false,
                "operator_confirmation_required": true,
                "blocked_reasons": ["cooldown_until_present"],
                "safe_next_action": "rotate_provider_key_secret_then_request_recovery_probe",
                "local_execution_boundary": {
                    "status_write_allowed": false,
                    "secret_write_allowed": true,
                    "provider_network_call": false,
                    "upstream_probe_executed": false,
                    "live_provider_smoke": false,
                    "request_log_write": false,
                    "billing_ledger_write": false
                },
                "secret_safe": true,
                "omitted_secret_policy": {
                    "key_secret_returned": false,
                    "authorization_header_returned": false,
                    "raw_endpoint_returned": false,
                    "raw_payload_returned": false,
                    "sealed_secret_returned": false,
                    "fingerprint_returned": false,
                    "public_credential_indicator": "credential_configured"
                }
            })
        );
        assert_eq!(
            response["provider_keys"][0]["recovery_probe"].get("endpoint"),
            None
        );
        assert_eq!(
            response["provider_keys"][0]["recent"]["last_error"]["code"],
            json!("provider_auth_failed")
        );
        assert_eq!(response["channels"][0]["model_count"], json!(1));
        assert_eq!(response["models"][0]["routing_state"], json!("routable"));

        for forbidden in [
            "sk-live",
            "encrypted_secret",
            "secret_fingerprint",
            "has_secret_fingerprint",
            "api_key",
            "fingerprint-never-return",
            "current_window_state",
            "provider.example",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "health summary response must not contain {forbidden}"
            );
        }
    }

