    #[test]
    fn provider_key_rotate_builds_new_secret_safe_enabled_key() {
        let channel = Channel {
            id: Uuid::from_u128(3),
            tenant_id: DEFAULT_TENANT_ID,
            provider_id: Uuid::from_u128(5),
            name: "primary".to_string(),
            endpoint: "http://provider.test/v1".to_string(),
            protocol_mode: "openai".to_string(),
            status: "enabled".to_string(),
            region: None,
            priority: 10,
            weight: 100,
            tags: json!([]),
            model_mappings: json!({}),
            request_overrides: json!({}),
            timeout_policy: json!({}),
            probe_policy: json!({}),
            health_score: 1.0,
        };
        let current = provider_key_fixture(channel.id);
        let request = ProviderKeyRotateRequest {
            secret: Some("sk-live-rotated-secret-never-return".to_string()),
            api_key: None,
            key_alias: None,
            reason: Some("scheduled rotate for sk-live-redacted".to_string()),
            encrypted_secret_supplied: false,
            secret_fingerprint_supplied: false,
        };
        let provider_key_id = Uuid::from_u128(0xabc);
        let reason = normalize_provider_key_rotation_reason(request.reason.clone())
            .expect("reason should normalize");
        let rotated = build_rotated_provider_key(
            &current,
            &channel,
            request,
            provider_key_id,
            reason.as_deref(),
            &provider_key_master_key_config(),
        )
        .expect("rotated key should build");

        assert_eq!(rotated.id, provider_key_id);
        assert_eq!(rotated.channel_id, current.channel_id);
        assert_eq!(rotated.status, "enabled");
        assert!(rotated.key_alias.starts_with("primary-rotated-"));
        assert!(
            rotated
                .encrypted_secret
                .contains(PROVIDER_KEY_ENCRYPTION_ALGORITHM)
        );
        assert!(
            !rotated
                .encrypted_secret
                .contains("sk-live-rotated-secret-never-return")
        );
        assert!(
            !rotated
                .secret_fingerprint
                .contains("sk-live-rotated-secret-never-return")
        );
        assert_eq!(
            rotated.metadata["rotation"]["previous_id"],
            json!(current.id)
        );
        assert_eq!(rotated.metadata["rotation"]["server_sealed"], json!(true));

        let serialized = serde_json::to_string(&rotated).expect("rotated key serializes");
        assert!(!serialized.contains("sk-live-rotated-secret-never-return"));
        assert!(!serialized.contains("sk-live-redacted"));
    }

