    #[test]
    fn audit_log_contract_fixture_captures_transaction_and_safe_metadata() {
        let fixture = serde_json::from_str::<Value>(include_str!(
            "../../../tests/fixtures/control-plane/audit_log_contract.json"
        ))
        .expect("fixture should be valid json");
        let serialized_examples =
            serde_json::to_string(&fixture["examples"]).expect("fixture examples should serialize");

        assert_eq!(fixture["todo"], json!("E1-004"));
        assert_eq!(
            fixture["transaction_contract"]["business_and_audit_share_transaction"],
            json!(true)
        );
        assert_eq!(
            fixture["metadata_contract"]["raw_headers_omitted"],
            json!(true)
        );
        let fields = fixture["metadata_contract"]["request_context_fields"]
            .as_array()
            .expect("request context fields should be an array");
        for expected in ["user_agent_sha256", "client_ip_sha256", "client_ip_scope"] {
            assert!(
                fields.iter().any(|field| field.as_str() == Some(expected)),
                "fixture should require {expected}"
            );
        }
        let paths = fixture["transaction_contract"]["paths"]
            .as_array()
            .expect("transaction paths should be an array");
        for expected in [
            "POST /admin/providers",
            "PATCH /admin/providers/{id}",
            "DELETE /admin/providers/{id}",
            "POST /admin/channels",
            "PATCH /admin/channels/{id}",
            "DELETE /admin/channels/{id}",
            "POST /admin/api-key-profiles",
            "PATCH /admin/api-key-profiles/{id}",
            "DELETE /admin/api-key-profiles/{id}",
            "POST /admin/model-associations",
            "PATCH /admin/model-associations/{id}",
            "DELETE /admin/model-associations/{id}",
            "POST /admin/models",
            "PATCH /admin/models/{id}",
            "DELETE /admin/models/{id}",
            "POST /admin/price-versions",
        ] {
            assert!(
                paths.iter().any(|path| path.as_str() == Some(expected)),
                "audit fixture should include transactional path {expected}"
            );
        }
        assert_eq!(
            fixture["examples"]["provider_update_success_audit"]["metadata"]["transactional_audit"],
            json!(true)
        );
        assert_eq!(
            fixture["examples"]["channel_update_success_audit"]["metadata"]["transactional_audit"],
            json!(true)
        );
        assert_eq!(
            fixture["examples"]["api_key_profile_update_success_audit"]["metadata"]["transactional_audit"],
            json!(true)
        );
        assert_eq!(
            fixture["examples"]["model_association_update_success_audit"]["metadata"]["transactional_audit"],
            json!(true)
        );
        assert_eq!(
            fixture["examples"]["canonical_model_update_success_audit"]["metadata"]["transactional_audit"],
            json!(true)
        );
        assert_eq!(
            fixture["examples"]["canonical_model_update_success_audit"]["metadata"]["default_price_config_contract"]
                ["selector_write_transactional_with_model_audit"],
            json!(true)
        );
        assert_eq!(
            fixture["examples"]["canonical_model_update_success_audit"]["metadata"]["default_price_selector"]
                ["operation"],
            json!("clear")
        );
        for snapshot in ["before_snapshot", "after_snapshot"] {
            assert!(
                !fixture["examples"]["channel_update_success_audit"][snapshot]
                    .as_object()
                    .expect("channel audit snapshot should be an object")
                    .contains_key("endpoint"),
                "channel audit fixture must not expose endpoint in {snapshot}"
            );
        }
        assert_eq!(
            fixture["query_contract"]["path"],
            json!("GET /admin/audit-logs")
        );
        assert_eq!(
            fixture["query_contract"]["required_permission"],
            json!("audit_read")
        );
        assert_eq!(fixture["query_contract"]["max_limit"], json!(500));
        let filters = fixture["query_contract"]["filters"]
            .as_array()
            .expect("query filters should be an array");
        for expected in ["tenant_id", "actor_user_id", "action", "created_from"] {
            assert!(
                filters.iter().any(|field| field.as_str() == Some(expected)),
                "fixture should include audit query filter {expected}"
            );
        }
        let request_context = &fixture["examples"]["provider_key_update_success_audit"]["metadata"]
            ["request_context"];
        assert_eq!(
            request_context["user_agent_sha256"]
                .as_str()
                .expect("user agent digest should be string")
                .len(),
            64
        );
        assert_eq!(
            request_context["client_ip_sha256"]
                .as_str()
                .expect("client ip digest should be string")
                .len(),
            64
        );

        for forbidden in [
            "AdminBrowser/9.1",
            "203.0.113.42",
            "10.0.0.8",
            "Bearer",
            "Cookie",
            "Authorization",
            "authorization",
            "sk-",
            "encrypted_secret",
            "raw body never audit",
            "raw payload never audit",
            "internal-provider.example",
            "https://",
            "fingerprint-never",
            "203.0.113.42",
            "2001:db8",
            "raw_headers",
            "base_url",
            "endpoint",
            "endpoint_url",
            "sid=never-audit",
            "provider_key_fingerprint",
        ] {
            assert!(
                !serialized_examples.contains(forbidden),
                "audit fixture examples must not contain {forbidden}"
            );
        }
    }

