    #[test]
    fn ledger_adjustment_dry_run_response_is_plan_only_and_secret_safe() {
        let request_id = Uuid::from_u128(90);
        let related_entry =
            ledger_entry_fixture(91, request_id, "settle", "-0.25000000", "confirmed");
        let refund_summary = validate_refund_remaining_amount(
            "0.15000000",
            &related_entry.amount,
            "0.10000000",
            1,
            "USD",
        )
        .expect("refund should fit remaining amount");
        let response = ledger_adjustment_dry_run_response(
            LedgerAdjustmentOperation::Refund,
            "0.15000000",
            "USD",
            related_entry.project_id,
            related_entry.wallet_id,
            related_entry.request_id,
            Some(&related_entry),
            Some(&refund_summary),
            true,
        );
        let serialized = serde_json::to_string(&response).expect("response should serialize");

        assert_eq!(response["operation"], json!("refund"));
        assert_eq!(response["plan_only"], json!(true));
        assert_eq!(response["ledger_write"], json!(false));
        assert_eq!(response["upstream_call"], json!(false));
        assert_eq!(response["audit_log_write"], json!(false));
        assert_eq!(
            response["planned_ledger_entry"]["entry_type"],
            json!("refund")
        );
        assert_eq!(
            response["refund_remaining_summary"]["remaining_refundable_amount"],
            json!("0.15000000")
        );
        assert_eq!(
            response["refund_remaining_summary"]["confirmed_credit_count"],
            json!(1)
        );
        assert_eq!(
            response["future_write_contract"]["business_and_success_audit_share_transaction"],
            json!(true)
        );
        assert_eq!(
            response["future_write_contract"]["refusal_does_not_build_success_audit"],
            json!(true)
        );

        for forbidden in [
            "ledger-idempotency-never-return",
            "raw ledger payload",
            "Bearer ledger-never-return",
            "sk-live-ledger-never-return",
            "sk-live-metadata-never-return",
            "usage_snapshot",
            "policy_snapshot",
            "idempotency_key",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "ledger adjustment dry-run response must not contain {forbidden}"
            );
        }
    }

    #[test]
    fn ledger_adjustment_dry_run_validation_rejects_bad_amounts_and_sensitive_fields() {
        assert_eq!(
            normalize_ledger_adjustment_request_mode(None).unwrap(),
            LedgerAdjustmentRequestMode::DryRun
        );
        assert_eq!(
            normalize_ledger_adjustment_request_mode(Some("execute_contract")).unwrap(),
            LedgerAdjustmentRequestMode::ExecuteContract
        );
        assert_eq!(
            normalize_ledger_adjustment_request_mode(Some("execute")).unwrap(),
            LedgerAdjustmentRequestMode::Execute
        );
        assert!(normalize_ledger_adjustment_request_mode(Some("write_now")).is_err());
        assert_eq!(
            normalize_ledger_adjustment_operation(" adjustment ".to_string()).unwrap(),
            LedgerAdjustmentOperation::Adjust
        );
        assert!(normalize_ledger_adjustment_operation("settle".to_string()).is_err());
        assert!(
            normalize_ledger_adjustment_amount(
                "-0.01000000".to_string(),
                LedgerAdjustmentOperation::Refund
            )
            .is_err()
        );
        assert!(
            normalize_ledger_adjustment_amount(
                "0.00000000".to_string(),
                LedgerAdjustmentOperation::Adjust
            )
            .is_err()
        );
        assert!(
            normalize_ledger_adjustment_amount(
                "0.000000001".to_string(),
                LedgerAdjustmentOperation::Adjust
            )
            .is_err()
        );
        assert!(normalize_ledger_adjustment_currency("usd".to_string()).is_err());
        assert_eq!(
            normalize_ledger_adjustment_reason(Some(" customer credit ".to_string())).unwrap(),
            Some("customer credit".to_string())
        );
        assert!(
            normalize_ledger_adjustment_reason(Some("sk-live-never-accept".to_string())).is_err()
        );
        assert!(
            normalize_ledger_adjustment_reason(Some(
                "x".repeat(LEDGER_ADJUSTMENT_REASON_MAX_BYTES + 1)
            ))
            .is_err()
        );
        let remaining =
            validate_refund_remaining_amount("0.15000000", "-0.25000000", "0.10000000", 2, "USD")
                .expect("requested refund should fit remaining amount");
        assert_eq!(remaining.source_debit_amount, "0.25000000");
        assert_eq!(remaining.confirmed_credit_amount, "0.10000000");
        assert_eq!(remaining.requested_refund_amount, "0.15000000");
        assert_eq!(remaining.remaining_refundable_amount, "0.15000000");
        assert_eq!(remaining.confirmed_credit_count, 2);
        assert!(
            validate_refund_remaining_amount("0.15000001", "-0.25000000", "0.10000000", 2, "USD")
                .is_err()
        );
        assert!(
            validate_refund_remaining_amount("0.01000000", "-0.25000000", "0.25000000", 1, "USD")
                .is_err()
        );
        assert!(
            validate_refund_remaining_amount("0.01000000", "-0.25000000", "0.26000000", 2, "USD")
                .is_err()
        );
        assert!(
            LEDGER_REFUND_CONFIRMED_CREDIT_SUM_SQL.contains("where tenant_id = $1"),
            "refund credit SQL must stay tenant bounded"
        );
        assert!(
            LEDGER_REFUND_CONFIRMED_CREDIT_SUM_SQL.contains("related_ledger_entry_id = $2"),
            "refund credit SQL must stay source-entry bounded"
        );
        assert!(
            LEDGER_REFUND_CONFIRMED_CREDIT_SUM_SQL.contains("currency = $3"),
            "refund credit SQL must stay currency bounded"
        );
        assert!(LEDGER_REFUND_CONFIRMED_CREDIT_SUM_SQL.contains("status = 'confirmed'"));
        assert!(
            LEDGER_REFUND_CONFIRMED_CREDIT_SUM_SQL.contains("entry_type in ('refund', 'adjust')")
        );
        assert!(LEDGER_REFUND_CONFIRMED_CREDIT_SUM_SQL.contains("amount > 0"));

        for field in [
            "idempotency_key",
            "payload",
            "authorization",
            "provider_key",
            "secret",
        ] {
            let mut request = serde_json::Map::new();
            request.insert("mode".to_string(), json!("dry_run"));
            request.insert("operation".to_string(), json!("adjust"));
            request.insert("amount".to_string(), json!("1.00000000"));
            request.insert("currency".to_string(), json!("USD"));
            request.insert("wallet_id".to_string(), json!(Uuid::from_u128(40)));
            request.insert(field.to_string(), json!("never-return"));
            assert!(
                serde_json::from_value::<LedgerAdjustmentDryRunRequest>(Value::Object(request))
                    .is_err(),
                "request must reject unexpected sensitive field {field}"
            );
        }
    }

