    fn voucher_code_lookup_prefix(raw_code: &str) -> Result<String, AdminError> {
        let trimmed = raw_code.trim();
        if trimmed.is_empty() {
            return Err(AdminError::bad_request("voucher code is required"));
        }
        Ok(sha256_hex(&format!("voucher-code-prefix:v1:{trimmed}"))[..12].to_string())
    }

    fn voucher_code_hash(raw_code: &str) -> Result<String, AdminError> {
        let trimmed = raw_code.trim();
        if trimmed.is_empty() {
            return Err(AdminError::bad_request("voucher code is required"));
        }
        Ok(sha256_hex(&format!("voucher-code:v1:{trimmed}")))
    }

    fn voucher_code_redacted(raw_code: &str) -> Result<String, AdminError> {
        let trimmed = raw_code.trim();
        if trimmed.is_empty() {
            return Err(AdminError::bad_request("voucher code is required"));
        }
        let suffix = trimmed
            .chars()
            .rev()
            .take(4)
            .collect::<Vec<_>>()
            .into_iter()
            .rev()
            .collect::<String>();
        Ok(format!("redacted:last4:{suffix}"))
    }

    fn voucher_issue_contract_plan(
        request: &VoucherIssueContractRequest,
    ) -> Result<(VoucherContractState, Value), AdminError> {
        let amount = parse_billing_fixed_decimal(&request.amount)?;
        if amount.units() <= 0 {
            return Ok((
                VoucherContractState {
                    voucher_id: Uuid::nil(),
                    tenant_id: request.tenant_id,
                    project_id: request.project_id,
                    wallet_id: request.wallet_id,
                    currency: request.currency.clone(),
                    amount: parse_billing_fixed_decimal(&request.amount)?.to_string(),
                    code_hash: "omitted".to_string(),
                    code_lookup_prefix: "omitted".to_string(),
                    code_redacted: "omitted".to_string(),
                    issue_idempotency_key_hash: sha256_hex(&format!(
                        "voucher-issue:v1:{}",
                        request.idempotency_key
                    )),
                    issue_request_hash: "omitted".to_string(),
                    status: "refused".to_string(),
                    credit_grant_id: None,
                    ledger_entry_id: None,
                    audit_id: None,
                },
                voucher_contract_refusal_response(
                    "voucher_issue",
                    "non_positive_voucher_amount",
                    true,
                ),
            ));
        }
        if !request.currency.chars().all(|c| c.is_ascii_uppercase()) {
            return Err(AdminError::bad_request("currency must be uppercase"));
        }

        let code_hash = voucher_code_hash(&request.raw_voucher_code)?;
        let code_lookup_prefix = voucher_code_lookup_prefix(&request.raw_voucher_code)?;
        let code_redacted = voucher_code_redacted(&request.raw_voucher_code)?;
        let idempotency_key_hash =
            sha256_hex(&format!("voucher-issue:v1:{}", request.idempotency_key));
        let request_hash = sha256_hex(&format!(
            "voucher-issue-request:v1:{}:{}:{}:{}:{:?}:{:?}",
            request.tenant_id,
            request.wallet_id,
            request.currency,
            parse_billing_fixed_decimal(&request.amount)?,
            request.project_id,
            request.campaign_id
        ));

        let state = VoucherContractState {
            voucher_id: Uuid::from_u128(3210),
            tenant_id: request.tenant_id,
            project_id: request.project_id,
            wallet_id: request.wallet_id,
            currency: request.currency.clone(),
            amount: parse_billing_fixed_decimal(&request.amount)?.to_string(),
            code_hash,
            code_lookup_prefix,
            code_redacted,
            issue_idempotency_key_hash: idempotency_key_hash,
            issue_request_hash: request_hash,
            status: "issued".to_string(),
            credit_grant_id: None,
            ledger_entry_id: None,
            audit_id: Some(Uuid::from_u128(3211)),
        };
        let response = json!({
            "schema": "recharge_voucher_runtime.v1",
            "runtime_implemented": false,
            "contract_only": true,
            "operation": "voucher_issue",
            "status": "issued",
            "voucher_id": state.voucher_id,
            "tenant_id": state.tenant_id,
            "wallet_id": state.wallet_id,
            "currency": state.currency,
            "amount": state.amount,
            "code_hash_present": true,
            "code_lookup_prefix_present": true,
            "code_redacted": state.code_redacted,
            "raw_voucher_code_echoed": false,
            "idempotency": {
                "result": "applied",
                "key_hash_present": true,
                "raw_key_echoed": false
            },
            "transaction_order": [
                "validate",
                "lock_wallet",
                "read_voucher_issuance_by_idempotency_key_hash_for_update",
                "read_voucher_issuance_by_code_hash_for_update",
                "insert_voucher_issuances",
                "insert_admin_audit_log",
                "commit_readback"
            ],
            "readback": {
                "voucher_issuance_row": true,
                "code_hash": true,
                "code_lookup_prefix": true,
                "code_redacted": true,
                "audit_log": true,
                "credit_grant_or_ledger_effect": false,
                "direct_wallet_snapshot_mutation": false
            },
            "secret_safe": true,
            "paid_gate_changed": false
        });
        Ok((state, response))
    }

    fn voucher_redeem_contract_plan(
        request: &VoucherRedeemContractRequest,
        existing: &VoucherContractState,
        prior_redemption: Option<&Value>,
    ) -> Result<Value, AdminError> {
        let request_code_hash = voucher_code_hash(&request.raw_voucher_code)?;
        let idempotency_key_hash =
            sha256_hex(&format!("voucher-redeem:v1:{}", request.idempotency_key));
        let request_hash = sha256_hex(&format!(
            "voucher-redeem-request:v1:{}:{}:{}:{}:{:?}",
            request.tenant_id,
            request.wallet_id,
            request.currency,
            request_code_hash,
            request.redeemer_user_id
        ));

        if let Some(prior) = prior_redemption {
            if prior["idempotency"]["key_hash"] == json!(idempotency_key_hash)
                && prior["idempotency"]["request_hash"] == json!(request_hash)
            {
                let mut replay = prior.clone();
                replay["status"] = json!("replayed");
                replay["idempotency"]["result"] = json!("replayed");
                replay["new_credit_grant_row_written"] = json!(false);
                replay["new_ledger_entry_written"] = json!(false);
                return Ok(replay);
            }
            return Ok(voucher_contract_refusal_response(
                "voucher_redeem",
                "idempotency_conflict",
                true,
            ));
        }

        if request_code_hash != existing.code_hash {
            return Ok(voucher_contract_refusal_response(
                "voucher_redeem",
                "voucher_not_found",
                true,
            ));
        }
        if existing.status == "expired" {
            return Ok(voucher_contract_refusal_response(
                "voucher_redeem",
                "voucher_expired",
                true,
            ));
        }
        if existing.status == "revoked" {
            return Ok(voucher_contract_refusal_response(
                "voucher_redeem",
                "voucher_revoked",
                true,
            ));
        }
        if request.currency != existing.currency {
            return Ok(voucher_contract_refusal_response(
                "voucher_redeem",
                "voucher_currency_mismatch",
                true,
            ));
        }
        if request.wallet_id != existing.wallet_id || request.project_id != existing.project_id {
            return Ok(voucher_contract_refusal_response(
                "voucher_redeem",
                "voucher_scope_ownership_mismatch",
                true,
            ));
        }
        let amount = parse_billing_fixed_decimal(&existing.amount)?;
        if amount.units() <= 0 {
            return Ok(voucher_contract_refusal_response(
                "voucher_redeem",
                "non_positive_voucher_amount",
                true,
            ));
        }

        Ok(json!({
            "schema": "recharge_voucher_runtime.v1",
            "runtime_implemented": false,
            "contract_only": true,
            "operation": "voucher_redeem",
            "status": "redeemed",
            "voucher_id": existing.voucher_id,
            "redemption_id": Uuid::from_u128(3220),
            "tenant_id": request.tenant_id,
            "wallet_id": request.wallet_id,
            "currency": request.currency,
            "amount": existing.amount,
            "credit_grant_id": Uuid::from_u128(3221),
            "ledger_entry_id": Uuid::from_u128(3222),
            "audit_id": Uuid::from_u128(3223),
            "raw_voucher_code_echoed": false,
            "idempotency": {
                "result": "applied",
                "key_hash": idempotency_key_hash,
                "request_hash": request_hash,
                "raw_key_echoed": false
            },
            "transaction_order": [
                "validate",
                "insert_voucher_redeem_attempts",
                "lock_voucher_issuance_by_code_hash_for_update",
                "read_voucher_redemption_by_idempotency_key_hash_for_update",
                "validate_scope_status_currency_amount",
                "insert_voucher_redemptions",
                "insert_credit_grant_or_ledger_entry",
                "insert_admin_audit_log",
                "update_voucher_issuance_redemption_count",
                "commit_readback"
            ],
            "readback": {
                "voucher_redemption_row": true,
                "voucher_redeem_attempts_row": true,
                "credit_grant_or_ledger_effect": true,
                "audit_log": true,
                "direct_wallet_snapshot_mutation": false,
                "refusal_no_credit_or_ledger_write": false
            },
            "new_credit_grant_row_written": true,
            "new_ledger_entry_written": true,
            "secret_safe": true,
            "paid_gate_changed": false
        }))
    }

    fn voucher_contract_refusal_response(
        operation: &str,
        refusal_code: &str,
        abuse_attempt_recorded: bool,
    ) -> Value {
        json!({
            "schema": "recharge_voucher_runtime.v1",
            "runtime_implemented": false,
            "contract_only": true,
            "operation": operation,
            "status": "refused",
            "refusal_code": refusal_code,
            "voucher_id": Value::Null,
            "redemption_id": Value::Null,
            "credit_grant_id": Value::Null,
            "ledger_entry_id": Value::Null,
            "audit_id": Value::Null,
            "raw_voucher_code_echoed": false,
            "raw_provider_payload_echoed": false,
            "idempotency": {
                "result": "refused",
                "key_hash_present": true,
                "raw_key_echoed": false
            },
            "transaction_order": [
                "validate",
                "insert_voucher_redeem_attempts",
                "refuse_without_credit_or_ledger_write",
                "audit_refusal_or_attempt",
                "commit_readback"
            ],
            "readback": {
                "voucher_redemption_row": false,
                "voucher_redeem_attempts_row": abuse_attempt_recorded,
                "credit_grant_or_ledger_effect": false,
                "audit_log": abuse_attempt_recorded,
                "direct_wallet_snapshot_mutation": false,
                "refusal_no_credit_or_ledger_write": true
            },
            "secret_safe": true,
            "paid_gate_changed": false
        })
    }

    #[derive(Clone)]
