    #[test]
    fn admin_credit_grant_create_contract_is_idempotent_and_secret_safe() {
        let normalized =
            normalize_create_admin_credit_grant_request(admin_credit_grant_create_test_request())
                .expect("credit grant request normalizes");
        assert_eq!(normalized.amount, "15.25000000");
        assert_ne!(
            normalized.idempotency_fingerprint,
            "credit-grant-create:secret-material"
        );
        assert_ne!(
            normalized.request_fingerprint,
            "credit-grant-create:secret-material"
        );

        let row = admin_credit_grant_row_from_request(&normalized);
        let create = admin_credit_grant_runtime_response(
            row.clone(),
            Some(Uuid::from_u128(412)),
            "active",
            "create",
        )
        .expect("create response");
        assert_eq!(create["schema"], json!("credit_grant_crud_runtime.v1"));
        assert_eq!(create["runtime_implemented"], json!(true));
        assert_eq!(create["contract_only"], json!(false));
        assert_eq!(create["outcome"], json!("create"));
        assert_eq!(create["idempotency"]["raw_key_echoed"], json!(false));
        assert_eq!(
            create["readback"]["direct_wallet_snapshot_mutation"],
            json!(false)
        );

        let replay = admin_credit_grant_runtime_response(
            row.clone(),
            Some(Uuid::from_u128(413)),
            "replayed",
            "replay",
        )
        .expect("replay response");
        assert_eq!(replay["status"], json!("replayed"));
        assert_eq!(replay["idempotency"]["result"], json!("replayed"));
        assert_eq!(replay["readback"]["audit_log"], json!(true));

        let refusal = admin_credit_grant_refusal_response(&normalized, "idempotency_conflict")
            .expect("refusal response");
        assert_eq!(refusal["status"], json!("refused"));
        assert_eq!(refusal["outcome"], json!("idempotency_conflict"));
        assert_eq!(
            refusal["request_summary"]["idempotency_key"],
            json!("omitted")
        );

        let serialized = serde_json::to_string(&json!([create, replay, refusal]))
            .expect("credit grant responses serialize");
        for forbidden in [
            "secret-material",
            "Authorization",
            "Cookie",
            "Bearer",
            "sk-live",
            "postgres://",
            "provider key",
            "virtual key",
            "raw import payload",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "credit grant CRUD response must not expose {forbidden}"
            );
        }
    }

