    #[test]
    fn admin_credit_grant_lifecycle_contract_is_idempotent_and_secret_safe() {
        let request = CreditGrantLifecycleRequest {
            tenant_id: DEFAULT_TENANT_ID,
            wallet_id: Some(Uuid::from_u128(40)),
            currency: Some("USD".to_string()),
            reason: "expired by operator".to_string(),
            actor_id: Uuid::from_u128(77),
            actor_type: "operator".to_string(),
            idempotency_key: "credit-grant-expire:secret-material".to_string(),
        };
        let normalized = normalize_credit_grant_lifecycle_request(
            Uuid::from_u128(411),
            request,
            CreditGrantLifecycleOperation::Expire,
        )
        .expect("lifecycle request normalizes");
        assert_ne!(
            normalized.idempotency_fingerprint,
            "credit-grant-expire:secret-material"
        );
        assert_ne!(
            normalized.request_fingerprint,
            "credit-grant-expire:secret-material"
        );

        let create_request =
            normalize_create_admin_credit_grant_request(admin_credit_grant_create_test_request())
                .expect("create request normalizes");
        let mut row = admin_credit_grant_row_from_request(&create_request);
        row.id = normalized.credit_grant_id;
        row.status = "expired".to_string();
        let response = admin_credit_grant_runtime_response(
            row.clone(),
            Some(Uuid::from_u128(414)),
            "expired",
            "expire",
        )
        .expect("expire response");
        assert_eq!(response["outcome"], json!("expire"));
        assert_eq!(response["status"], json!("expired"));
        assert_eq!(response["readback"]["audit_log"], json!(true));
        assert_eq!(response["paid_gate_changed"], json!(false));

        let replay = admin_credit_grant_runtime_response(
            row.clone(),
            Some(Uuid::from_u128(414)),
            "replayed",
            "replay",
        )
        .expect("replay response");
        assert_eq!(replay["idempotency"]["result"], json!("replayed"));
        assert_eq!(replay["readback"]["audit_log"], json!(true));

        let refusal = admin_credit_grant_lifecycle_refusal_response(
            &normalized,
            Some(&row),
            "idempotency_conflict",
        )
        .expect("lifecycle refusal");
        assert_eq!(refusal["status"], json!("refused"));
        assert_eq!(refusal["outcome"], json!("idempotency_conflict"));
        assert_eq!(refusal["readback"]["audit_log"], json!(false));
        assert_eq!(
            refusal["request_summary"]["idempotency_key"],
            json!("omitted")
        );

        let mut invalid = CreditGrantLifecycleRequest {
            tenant_id: DEFAULT_TENANT_ID,
            wallet_id: None,
            currency: Some("usd".to_string()),
            reason: "invalid".to_string(),
            actor_id: Uuid::from_u128(77),
            actor_type: "operator".to_string(),
            idempotency_key: "credit-grant-expire:invalid".to_string(),
        };
        assert!(
            normalize_credit_grant_lifecycle_request(
                Uuid::from_u128(411),
                invalid.clone(),
                CreditGrantLifecycleOperation::Expire,
            )
            .is_err()
        );
        invalid.currency = Some("USD".to_string());
        invalid.idempotency_key = "   ".to_string();
        assert!(
            normalize_credit_grant_lifecycle_request(
                Uuid::from_u128(411),
                invalid,
                CreditGrantLifecycleOperation::Revoke,
            )
            .is_err()
        );

        let serialized =
            serde_json::to_string(&json!([response, replay, refusal])).expect("serialize");
        for forbidden in [
            "secret-material",
            "Authorization",
            "Cookie",
            "Bearer",
            "sk-live",
            "postgres://",
            "provider key",
            "virtual key",
            "raw import payload",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "credit grant lifecycle response must not expose {forbidden}"
            );
        }
    }

