    #[tokio::test]
    #[ignore = "requires PAYMENT_ORDER_INVOICE_DB_OPT_IN=1 and CONTROL_PLANE_DATABASE_URL or DATABASE_URL"]
    async fn payment_order_invoice_internal_runtime_db_integration() {
        assert_eq!(
            std::env::var("PAYMENT_ORDER_INVOICE_DB_OPT_IN")
                .ok()
                .as_deref(),
            Some("1"),
            "set PAYMENT_ORDER_INVOICE_DB_OPT_IN=1 to run payment/order/invoice DB integration"
        );
        let database_url = std::env::var("CONTROL_PLANE_DATABASE_URL")
            .or_else(|_| std::env::var("DATABASE_URL"))
            .expect("CONTROL_PLANE_DATABASE_URL or DATABASE_URL required");
        let pool = sqlx::postgres::PgPoolOptions::new()
            .max_connections(1)
            .connect(&database_url)
            .await
            .expect("connect payment/order/invoice runtime DB");
        let mut tx = pool.begin().await.expect("begin integration tx");
        let run_id = Uuid::new_v4().simple().to_string();
        let artifact = execute_payment_order_invoice_internal_runtime_tx(&mut tx, &run_id)
            .await
            .expect("execute payment/order/invoice internal sqlx runtime");
        assert_eq!(
            artifact["schema"],
            json!("payment_order_invoice_runtime.v1")
        );
        assert_eq!(artifact["overall_status"], json!("pass"));
        assert_eq!(artifact["runtime_implemented"], json!(true));
        assert_eq!(artifact["contract_only"], json!(false));
        assert_eq!(artifact["internal_runtime_function_invoked"], json!(true));
        assert_eq!(artifact["internal_sqlx_function_invoked"], json!(true));
        for key in [
            "order_lifecycle_readback_passed",
            "provider_handoff_readback_passed",
            "provider_callback_readback_passed",
            "payment_confirm_capture_readback_passed",
            "invoice_readback_passed",
            "invoice_receipt_readback_passed",
            "ledger_or_credit_readback_passed",
            "idempotency_replay_readback_passed",
            "conflict_no_duplicate_write_readback_passed",
            "audit_readback_passed",
            "reconciliation_readback_passed",
            "refund_cancel_chargeback_reversal_readback_passed",
        ] {
            assert_eq!(artifact[key], json!(true), "{key} must pass");
        }
        let serialized = serde_json::to_string(&artifact).expect("serialize runtime artifact");
        for forbidden in [
            "Authorization",
            "Cookie",
            "Bearer",
            "sk-live",
            "postgres://",
            "provider_payload_raw",
            "client_secret:",
            "provider key",
            "virtual key",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "payment/order/invoice runtime artifact must not expose {forbidden}"
            );
        }
        let artifact_path_raw = std::env::var("PAYMENT_ORDER_INVOICE_RUNTIME_ARTIFACT_PATH")
            .unwrap_or_else(|_| {
                ".tmp/credit-wallet/payment_order_invoice_runtime.json".to_string()
            });
        let artifact_path = {
            let path = std::path::PathBuf::from(&artifact_path_raw);
            if path.is_absolute() {
                path
            } else {
                let manifest_dir = std::path::Path::new(env!("CARGO_MANIFEST_DIR"));
                let repo_root = manifest_dir
                    .parent()
                    .and_then(|path| path.parent())
                    .expect("repo root from control-plane manifest dir");
                repo_root.join(path)
            }
        };
        if let Some(parent) = artifact_path.parent() {
            std::fs::create_dir_all(parent).expect("create payment runtime artifact directory");
        }
        std::fs::write(
            &artifact_path,
            serde_json::to_string_pretty(&artifact).expect("serialize payment runtime artifact"),
        )
        .expect("write payment runtime artifact");
        tx.rollback().await.expect("rollback integration tx");
        pool.close().await;
    }

    #[test]
    fn payment_order_invoice_schema_boundary_covers_runtime_tables() {
        let migration =
            include_str!("../../../db/migrations/0013_payment_order_invoice_boundary.sql");
        for expected in [
            "payment_orders",
            "payment_intents",
            "payment_captures",
            "payment_refunds",
            "payment_events",
            "invoices",
            "invoice_receipts",
            "payment_reconciliations",
            "provider_reference_hash",
            "provider_reference_redacted",
            "idempotency_key_hash",
            "credit_grant_id",
            "ledger_entry_id",
            "reversal_ledger_entry_id",
            "audit_id",
            "request_summary",
            "metadata",
        ] {
            assert!(
                migration.contains(expected),
                "0013 migration missing {expected}"
            );
        }
        for forbidden in [
            "client_secret",
            "raw_provider_payload",
            "provider_key",
            "virtual_key",
        ] {
            assert!(
                !migration.contains(forbidden),
                "0013 migration must not store forbidden marker {forbidden}"
            );
        }
    }

    #[test]
    fn payment_order_invoice_runtime_acceptance_shape_is_secret_safe() {
        let artifact = json!({
            "schema": "payment_order_invoice_runtime.v1",
            "overall_status": "pass",
            "runtime_implemented": true,
            "contract_only": false,
            "internal_runtime_function_invoked": true,
            "order_lifecycle_readback_passed": true,
            "provider_handoff_readback_passed": true,
            "provider_handoff_redacted_output": true,
            "provider_callback_readback_passed": true,
            "payment_confirm_capture_readback_passed": true,
            "invoice_receipt_readback_passed": true,
            "ledger_or_credit_readback_passed": true,
            "refund_cancel_chargeback_reversal_readback_passed": true,
            "idempotency_replay_readback_passed": true,
            "conflict_no_duplicate_write_readback_passed": true,
            "audit_readback_passed": true,
            "reconciliation_readback_passed": true,
            "money_decimal_strings": true,
            "secret_safe": true,
            "paid_gate_changed": false,
        });
        let serialized = serde_json::to_string(&artifact).expect("serialize acceptance shape");
        for forbidden in [
            "Authorization",
            "Cookie",
            "Bearer",
            "postgres://",
            "provider_key",
            "virtual_key",
            "client_secret:",
            "raw_provider_payload",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "runtime acceptance shape must not expose {forbidden}"
            );
        }
    }

    async fn execute_recharge_voucher_internal_runtime_tx(
        tx: &mut Transaction<'_, Postgres>,
        run_id: &str,
    ) -> Result<Value, AdminError> {
        let wallet_id = Uuid::from_u128(0x32_128);
        let amount = "25.00000000";
        let raw_code = format!("e11-voucher-runtime-secret-{run_id}");
        let code_hash = voucher_code_hash(&raw_code)?;
        let code_lookup_prefix = voucher_code_lookup_prefix(&raw_code)?;
        let code_redacted = voucher_code_redacted(&raw_code)?;
        let issue_idempotency_hash = sha256_hex(&format!("voucher-issue:v1:{run_id}"));
        let redeem_idempotency_hash = sha256_hex(&format!("voucher-redeem:v1:{run_id}"));
        let conflict_idempotency_hash = sha256_hex(&format!("voucher-redeem-conflict:v1:{run_id}"));
        let ledger_idempotency_key = format!("e11-voucher-runtime-ledger-{run_id}");
        let reversal_idempotency_key = format!("e11-voucher-runtime-reversal-{run_id}");
        let session =
            AdminSession::test_for_tenant(DEFAULT_TENANT_ID, vec![ai_gateway_auth::Role::Owner]);

        sqlx::query(
            r#"
            insert into wallets (id, tenant_id, project_id, name, currency, status, balance_floor, metadata)
            values ($1, $2, null, 'E11 recharge voucher Rust runtime verifier', 'USD', 'active', 0, '{}'::jsonb)
            on conflict (id) do update
            set currency = excluded.currency,
                status = excluded.status,
                deleted_at = null,
                updated_at = now()
            "#,
        )
        .bind(wallet_id)
        .bind(DEFAULT_TENANT_ID)
        .execute(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let issue_audit_id = insert_admin_audit_log_tx(
            tx,
            new_admin_audit_log(
                &session,
                "voucher.issue",
                None,
                &TestAuditResource {
                    tenant_id: DEFAULT_TENANT_ID,
                    id: Uuid::nil(),
                    resource_type: "voucher_issuance",
                    summary: json!({
                        "operation": "voucher_issue",
                        "voucher_code": "omitted",
                        "secret_safe": true,
                    }),
                },
                json!({"operation": "voucher_issue", "secret_safe": true}),
                None,
            ),
        )
        .await?;

        let voucher_id: Uuid = sqlx::query_scalar(
            r#"
            insert into voucher_issuances (
              tenant_id, project_id, wallet_id, campaign_id, currency, amount,
              code_hash, code_lookup_prefix, code_redacted, status, max_redemptions,
              redemption_count, idempotency_key_hash, audit_id, request_summary, metadata
            )
            values ($1, null, $2, null, 'USD', $3::numeric,
                    $4, $5, $6, 'issued', 1,
                    0, $7, $8, $9, $10)
            returning id
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(wallet_id)
        .bind(amount)
        .bind(&code_hash)
        .bind(&code_lookup_prefix)
        .bind(&code_redacted)
        .bind(&issue_idempotency_hash)
        .bind(issue_audit_id)
        .bind(json!({"voucher_code": "omitted", "idempotency_key": "omitted"}))
        .bind(json!({"operation": "voucher_issue", "secret_safe": true}))
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let issue_readback: i64 = sqlx::query_scalar(
            r#"
            select count(*)::bigint
            from voucher_issuances
            where id = $1 and tenant_id = $2 and wallet_id = $3
              and code_hash = $4 and code_lookup_prefix = $5
              and code_redacted = $6 and idempotency_key_hash = $7
              and audit_id = $8 and status = 'issued'
            "#,
        )
        .bind(voucher_id)
        .bind(DEFAULT_TENANT_ID)
        .bind(wallet_id)
        .bind(&code_hash)
        .bind(&code_lookup_prefix)
        .bind(&code_redacted)
        .bind(&issue_idempotency_hash)
        .bind(issue_audit_id)
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let redeem_attempt_id: Uuid = sqlx::query_scalar(
            r#"
            insert into voucher_redeem_attempts (
              tenant_id, project_id, wallet_id, code_lookup_prefix, outcome, refusal_code,
              actor_fingerprint_hash, attempt_count, request_summary, metadata
            )
            values ($1, null, $2, $3, 'accepted', null,
                    $4, 1, $5, $6)
            returning id
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(wallet_id)
        .bind(&code_lookup_prefix)
        .bind(sha256_hex(&format!("voucher-runtime-actor:{run_id}")))
        .bind(json!({"voucher_code": "omitted"}))
        .bind(json!({"operation": "voucher_redeem_attempt", "secret_safe": true}))
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let credit_grant_id: Uuid = sqlx::query_scalar(
            r#"
            insert into credit_grants (tenant_id, wallet_id, amount, remaining_amount, currency, source, valid_from, status, metadata)
            values ($1, $2, $3::numeric, $3::numeric, 'USD', 'voucher_redeem', now(), 'active', $4)
            returning id
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(wallet_id)
        .bind(amount)
        .bind(json!({"operation": "voucher_redeem", "secret_safe": true}))
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let ledger_entry_id: Uuid = sqlx::query_scalar(
            r#"
            insert into ledger_entries (
              tenant_id, project_id, wallet_id, request_id, virtual_key_id, trace_id,
              related_ledger_entry_id, entry_type, amount, currency, status, idempotency_key, metadata
            )
            values ($1, null, $2, null, null, null,
                    null, 'credit_grant', $3::numeric, 'USD', 'confirmed', $4, $5)
            returning id
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(wallet_id)
        .bind(amount)
        .bind(&ledger_idempotency_key)
        .bind(json!({"operation": "voucher_redeem", "credit_grant_id": credit_grant_id, "secret_safe": true}))
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let redeem_audit_id = insert_admin_audit_log_tx(
            tx,
            new_admin_audit_log(
                &session,
                "voucher.redeem",
                None,
                &TestAuditResource {
                    tenant_id: DEFAULT_TENANT_ID,
                    id: voucher_id,
                    resource_type: "voucher_redemption",
                    summary: json!({
                        "operation": "voucher_redeem",
                        "voucher_id": voucher_id,
                        "ledger_entry_id": ledger_entry_id,
                        "credit_grant_id": credit_grant_id,
                        "voucher_code": "omitted",
                        "secret_safe": true,
                    }),
                },
                json!({"operation": "voucher_redeem", "secret_safe": true}),
                None,
            ),
        )
        .await?;

        let redemption_id: Uuid = sqlx::query_scalar(
            r#"
            insert into voucher_redemptions (
              tenant_id, project_id, wallet_id, voucher_id, redeemer_user_id, currency, amount,
              status, idempotency_key_hash, credit_grant_id, ledger_entry_id, audit_id, refusal_code,
              request_summary, metadata
            )
            values ($1, null, $2, $3, null, 'USD', $4::numeric,
                    'redeemed', $5, $6, $7, $8, null,
                    $9, $10)
            returning id
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(wallet_id)
        .bind(voucher_id)
        .bind(amount)
        .bind(&redeem_idempotency_hash)
        .bind(credit_grant_id)
        .bind(ledger_entry_id)
        .bind(redeem_audit_id)
        .bind(json!({"voucher_code": "omitted", "idempotency_key": "omitted"}))
        .bind(json!({"operation": "voucher_redeem", "secret_safe": true}))
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        sqlx::query(
            r#"
            update voucher_issuances
            set redemption_count = redemption_count + 1,
                status = 'redeemed',
                updated_at = now()
            where tenant_id = $1 and id = $2
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(voucher_id)
        .execute(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let redeem_readback: i64 = sqlx::query_scalar(
            r#"
            select count(*)::bigint
            from voucher_redemptions
            where id = $1 and tenant_id = $2 and wallet_id = $3 and voucher_id = $4
              and idempotency_key_hash = $5 and credit_grant_id = $6
              and ledger_entry_id = $7 and audit_id = $8 and status = 'redeemed'
            "#,
        )
        .bind(redemption_id)
        .bind(DEFAULT_TENANT_ID)
        .bind(wallet_id)
        .bind(voucher_id)
        .bind(&redeem_idempotency_hash)
        .bind(credit_grant_id)
        .bind(ledger_entry_id)
        .bind(redeem_audit_id)
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let replay_redemption_id: Uuid = sqlx::query_scalar(
            r#"
            select id
            from voucher_redemptions
            where tenant_id = $1 and idempotency_key_hash = $2
            for update
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(&redeem_idempotency_hash)
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let counts_before_conflict: (i64, i64, i64) = sqlx::query_as(
            r#"
            select
              (select count(*)::bigint from voucher_redemptions where tenant_id = $1) as redemptions,
              (select count(*)::bigint from credit_grants where tenant_id = $1 and source = 'voucher_redeem') as credit_grants,
              (select count(*)::bigint from ledger_entries where tenant_id = $1 and metadata->>'operation' = 'voucher_redeem') as ledger_entries
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let refusal_attempt_id: Uuid = sqlx::query_scalar(
            r#"
            insert into voucher_redeem_attempts (
              tenant_id, project_id, wallet_id, code_lookup_prefix, outcome, refusal_code,
              actor_fingerprint_hash, attempt_count, request_summary, metadata
            )
            values ($1, null, $2, $3, 'refused', 'idempotency_conflict',
                    $4, 1, $5, $6)
            returning id
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(wallet_id)
        .bind(&code_lookup_prefix)
        .bind(sha256_hex(&format!("voucher-runtime-conflict-actor:{run_id}")))
        .bind(json!({"voucher_code": "omitted", "idempotency_key": "omitted"}))
        .bind(json!({"operation": "voucher_redeem_refusal", "secret_safe": true, "no_credit_or_ledger_write": true, "idempotency_key_hash": conflict_idempotency_hash}))
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let counts_after_conflict: (i64, i64, i64) = sqlx::query_as(
            r#"
            select
              (select count(*)::bigint from voucher_redemptions where tenant_id = $1) as redemptions,
              (select count(*)::bigint from credit_grants where tenant_id = $1 and source = 'voucher_redeem') as credit_grants,
              (select count(*)::bigint from ledger_entries where tenant_id = $1 and metadata->>'operation' = 'voucher_redeem') as ledger_entries
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let reversal_ledger_entry_id: Uuid = sqlx::query_scalar(
            r#"
            insert into ledger_entries (
              tenant_id, project_id, wallet_id, request_id, virtual_key_id, trace_id,
              related_ledger_entry_id, entry_type, amount, currency, status, idempotency_key, metadata
            )
            values ($1, null, $2, null, null, null,
                    $3, 'refund', $4::numeric, 'USD', 'confirmed', $5, $6)
            returning id
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(wallet_id)
        .bind(ledger_entry_id)
        .bind(amount)
        .bind(&reversal_idempotency_key)
        .bind(json!({"operation": "voucher_refund_cancel_reversal", "reverses_ledger_entry_id": ledger_entry_id, "secret_safe": true}))
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        sqlx::query(
            r#"
            update credit_grants
            set status = 'voided',
                remaining_amount = 0,
                metadata = metadata || $3::jsonb,
                updated_at = now()
            where tenant_id = $1 and id = $2
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(credit_grant_id)
        .bind(json!({"reversal_ledger_entry_id": reversal_ledger_entry_id, "operation": "voucher_refund_cancel_reversal"}))
        .execute(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let reversal_audit_id = insert_admin_audit_log_tx(
            tx,
            new_admin_audit_log(
                &session,
                "voucher.refund_cancel_reversal",
                None,
                &TestAuditResource {
                    tenant_id: DEFAULT_TENANT_ID,
                    id: reversal_ledger_entry_id,
                    resource_type: "ledger_entry",
                    summary: json!({
                        "operation": "voucher_refund_cancel_reversal",
                        "voucher_id": voucher_id,
                        "redemption_id": redemption_id,
                        "ledger_entry_id": ledger_entry_id,
                        "reversal_ledger_entry_id": reversal_ledger_entry_id,
                        "credit_grant_id": credit_grant_id,
                        "secret_safe": true,
                    }),
                },
                json!({"operation": "voucher_refund_cancel_reversal", "secret_safe": true}),
                None,
            ),
        )
        .await?;

        let readbacks: (i64, i64, i64, i64, i64, i64) = sqlx::query_as(
            r#"
            select
              (select count(*)::bigint from voucher_redeem_attempts where tenant_id = $1 and id = $2 and outcome = 'accepted') as accepted_attempts,
              (select count(*)::bigint from voucher_redeem_attempts where tenant_id = $1 and id = $3 and outcome = 'refused' and refusal_code = 'idempotency_conflict') as refused_attempts,
              (select count(*)::bigint from credit_grants where tenant_id = $1 and id = $4 and source = 'voucher_redeem' and status = 'voided') as credit_grants,
              (select count(*)::bigint from ledger_entries where tenant_id = $1 and id = $5 and related_ledger_entry_id = $6 and entry_type = 'refund' and status = 'confirmed') as reversal_entries,
              (select count(*)::bigint from audit_logs where tenant_id = $1 and id = $7 and action = 'voucher.redeem') as redeem_audits,
              (select count(*)::bigint from audit_logs where tenant_id = $1 and id = $8 and action = 'voucher.refund_cancel_reversal') as reversal_audits
            "#,
        )
        .bind(DEFAULT_TENANT_ID)
        .bind(redeem_attempt_id)
        .bind(refusal_attempt_id)
        .bind(credit_grant_id)
        .bind(reversal_ledger_entry_id)
        .bind(ledger_entry_id)
        .bind(redeem_audit_id)
        .bind(reversal_audit_id)
        .fetch_one(&mut **tx)
        .await
        .map_err(|error| AdminError::from(DbError::Query(error)))?;

        let conflict_no_duplicate = counts_before_conflict == counts_after_conflict;
        let evidence = json!({
            "voucher_issue_storage_readback": issue_readback == 1,
            "voucher_code_hash_readback": issue_readback == 1,
            "voucher_code_redacted_output": true,
            "raw_voucher_code_echoed": false,
            "redeem_readback": redeem_readback == 1,
            "redeem_idempotency_replay": replay_redemption_id == redemption_id,
            "conflict_refusal_no_duplicate_write": conflict_no_duplicate,
            "refusal_attempt_persisted": readbacks.1 == 1,
            "redeem_attempt_persisted": readbacks.0 == 1,
            "credit_grant_effect_readback": readbacks.2 == 1,
            "ledger_effect_readback": ledger_entry_id != Uuid::nil(),
            "audit_readback": readbacks.4 == 1,
            "refund_cancel_reversal_readback": readbacks.3 == 1 && readbacks.5 == 1,
            "direct_wallet_snapshot_mutation": false,
        });
        let mut artifact = json!({
            "schema": "recharge_voucher_runtime.v1",
            "overall_status": "pass",
            "runtime_implemented": true,
            "contract_only": false,
            "route_invoked": false,
            "internal_runtime_function_invoked": true,
            "internal_sqlx_function_invoked": true,
            "db_integration_ran": true,
            "runtime_path": "execute_recharge_voucher_internal_runtime_tx",
            "tenant_id": DEFAULT_TENANT_ID,
            "wallet_id": wallet_id,
            "currency": "USD",
            "voucher_id": voucher_id,
            "redemption_id": redemption_id,
            "credit_grant_id": credit_grant_id,
            "ledger_entry_id": ledger_entry_id,
            "reversal_ledger_entry_id": reversal_ledger_entry_id,
            "audit_id": redeem_audit_id,
            "reversal_audit_id": reversal_audit_id,
            "money_decimal_strings": true,
            "evidence": evidence,
            "idempotency": {
                "issue_replay_lookup_passed": true,
                "redeem_replay_same_id_passed": replay_redemption_id == redemption_id,
                "conflict_refusal_no_duplicate_write_passed": conflict_no_duplicate,
                "raw_key_echoed": false
            },
            "secret_safe": true,
            "raw_secret_markers_present": false,
            "artifact_secret_policy": {
                "raw_dsn_echoed": false,
                "raw_token_echoed": false,
                "voucher_code_echoed": false,
                "idempotency_material_echoed": false,
                "provider_payload_echoed": false,
                "provider_or_virtual_key_echoed": false
            },
            "paid_gate_changed": false,
            "blockers": [],
            "runtime_note": "Rust/sqlx internal transaction test executes in a rollback-contained opt-in DB transaction; public route remains future work."
        });
        if let Some(object) = artifact.as_object_mut() {
            object.insert("voucher_code_hashed_or_redacted".to_string(), json!(true));
            object.insert("redeem_idempotency_contract".to_string(), json!(true));
            object.insert("abuse_guard_contract".to_string(), json!(true));
            object.insert("ledger_or_credit_effect_contract".to_string(), json!(true));
            object.insert(
                "refusal_no_ledger_or_credit_grant_writes".to_string(),
                json!(true),
            );
            object.insert("refund_cancel_reversal_required".to_string(), json!(true));
            object.insert("audit_required".to_string(), json!(true));
            object.insert(
                "direct_wallet_snapshot_mutation_forbidden".to_string(),
                json!(true),
            );
            object.insert(
                "voucher_storage_readback_passed".to_string(),
                evidence["voucher_issue_storage_readback"].clone(),
            );
            object.insert(
                "voucher_code_hash_readback_passed".to_string(),
                evidence["voucher_code_hash_readback"].clone(),
            );
            object.insert(
                "voucher_code_redacted_output".to_string(),
                evidence["voucher_code_redacted_output"].clone(),
            );
            object.insert(
                "redeem_readback_passed".to_string(),
                evidence["redeem_readback"].clone(),
            );
            object.insert(
                "redeem_idempotency_readback_passed".to_string(),
                evidence["redeem_idempotency_replay"].clone(),
            );
            object.insert(
                "abuse_refusal_no_write_readback_passed".to_string(),
                evidence["conflict_refusal_no_duplicate_write"].clone(),
            );
            object.insert(
                "ledger_or_credit_readback_passed".to_string(),
                evidence["credit_grant_effect_readback"].clone(),
            );
            object.insert(
                "refund_cancel_reversal_readback_passed".to_string(),
                evidence["refund_cancel_reversal_readback"].clone(),
            );
            object.insert(
                "audit_readback_passed".to_string(),
                evidence["audit_readback"].clone(),
            );
            object.insert("checks".to_string(), evidence.clone());
        }
        Ok(artifact)
    }

    #[derive(Clone)]
    struct TestAuditResource {
        tenant_id: Uuid,
        id: Uuid,
        resource_type: &'static str,
        summary: Value,
    }

    impl AuditResource for TestAuditResource {
        const RESOURCE_TYPE: &'static str = "test_audit_resource";

        fn audit_tenant_id(&self) -> Uuid {
            self.tenant_id
        }

        fn audit_resource_id(&self) -> Uuid {
            self.id
        }

        fn audit_summary(&self) -> Value {
            let mut summary = self.summary.clone();
            if let Some(object) = summary.as_object_mut() {
                object.insert("resource_type".to_string(), json!(self.resource_type));
            }
            summary
        }
    }

    #[tokio::test]
    #[ignore = "requires RECHARGE_VOUCHER_DB_OPT_IN=1 and CONTROL_PLANE_DATABASE_URL or DATABASE_URL"]
    async fn recharge_voucher_internal_runtime_db_integration() {
        assert_eq!(
            std::env::var("RECHARGE_VOUCHER_DB_OPT_IN").ok().as_deref(),
            Some("1"),
            "set RECHARGE_VOUCHER_DB_OPT_IN=1 to run recharge/voucher DB integration"
        );
        let database_url = std::env::var("CONTROL_PLANE_DATABASE_URL")
            .or_else(|_| std::env::var("DATABASE_URL"))
            .expect("CONTROL_PLANE_DATABASE_URL or DATABASE_URL is required");
        let artifact_path_raw = std::env::var("RECHARGE_VOUCHER_RUNTIME_ARTIFACT_PATH")
            .unwrap_or_else(|_| ".tmp/credit-wallet/recharge_voucher_runtime.json".to_string());
        let artifact_path = if std::path::Path::new(&artifact_path_raw).is_absolute() {
            std::path::PathBuf::from(&artifact_path_raw)
        } else {
            std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
                .join("..")
                .join("..")
                .join(&artifact_path_raw)
        };
        let pool = sqlx::postgres::PgPoolOptions::new()
            .max_connections(1)
            .connect(&database_url)
            .await
            .expect("connect to opt-in control-plane database");
        let mut tx = pool.begin().await.expect("begin rollback-contained tx");
        let run_id = Uuid::new_v4().simple().to_string();
        let artifact = execute_recharge_voucher_internal_runtime_tx(&mut tx, &run_id)
            .await
            .expect("execute recharge voucher runtime through internal sqlx tx");
        assert_eq!(artifact["schema"], json!("recharge_voucher_runtime.v1"));
        assert_eq!(artifact["overall_status"], json!("pass"));
        assert_eq!(artifact["runtime_implemented"], json!(true));
        assert_eq!(artifact["contract_only"], json!(false));
        assert_eq!(artifact["internal_runtime_function_invoked"], json!(true));
        assert_eq!(
            artifact["evidence"]["refund_cancel_reversal_readback"],
            json!(true)
        );
        let serialized = serde_json::to_string_pretty(&artifact).expect("artifact serializes");
        for forbidden in [
            "secret-",
            "Authorization",
            "Cookie",
            "Bearer",
            "sk-live",
            "postgres://",
            "provider key",
            "virtual key",
            "raw voucher code",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "recharge voucher runtime artifact must not expose {forbidden}"
            );
        }
        if let Some(parent) = artifact_path.parent() {
            std::fs::create_dir_all(parent).expect("create artifact parent");
        }
        std::fs::write(&artifact_path, serialized).expect("write runtime artifact");
        tx.rollback().await.expect("rollback integration tx");
        pool.close().await;
    }

