    #[test]
    fn voucher_issue_runtime_response_exposes_secret_safe_readback_markers() {
        let voucher = VoucherIssuanceRow {
            id: Uuid::from_u128(4101),
            tenant_id: DEFAULT_TENANT_ID,
            project_id: Some(Uuid::from_u128(4102)),
            wallet_id: Some(Uuid::from_u128(4103)),
            campaign_id: Some(Uuid::from_u128(4104)),
            currency: "USD".to_string(),
            amount: "25.00000000".to_string(),
            code_redacted: "redacted:last4:SAFE".to_string(),
            status: "issued".to_string(),
            max_redemptions: 1,
            redemption_count: 0,
            expires_at: Some("2026-07-06T00:00:00Z".to_string()),
            audit_id: Some(Uuid::from_u128(4105)),
            metadata: json!({"request_fingerprint": "bounded-request-hash"}),
            expired_by_time: false,
        };

        let issued = voucher_issue_response(&voucher, "issued");
        assert_eq!(issued["runtime_implemented"], json!(true));
        assert_eq!(issued["contract_only"], json!(false));
        assert_eq!(issued["route_invoked"], json!(true));
        assert_eq!(issued["code_hash_present"], json!(true));
        assert_eq!(issued["code_lookup_prefix_present"], json!(true));
        assert_eq!(issued["raw_voucher_code_echoed"], json!(false));
        assert_eq!(issued["idempotency"]["key_hash_present"], json!(true));
        assert_eq!(issued["idempotency"]["request_hash_present"], json!(true));
        assert_eq!(issued["idempotency"]["raw_key_echoed"], json!(false));
        assert_eq!(issued["readback"]["voucher_issuance_row"], json!(true));
        assert_eq!(issued["readback"]["audit_log"], json!(true));
        assert_eq!(
            issued["readback"]["refusal_no_credit_or_ledger_write"],
            json!(false)
        );
        assert_eq!(issued["secret_safe"], json!(true));
        assert_eq!(issued["paid_gate_changed"], json!(false));

        let refused = voucher_issue_refusal_response(
            "wallet_currency_mismatch",
            voucher.wallet_id,
            Some("USD"),
        );
        assert_eq!(refused["status"], json!("refused"));
        assert_eq!(refused["idempotency"]["key_hash_present"], json!(true));
        assert_eq!(refused["readback"]["voucher_issuance_row"], json!(false));
        assert_eq!(
            refused["readback"]["refusal_no_credit_or_ledger_write"],
            json!(true)
        );
        assert_eq!(refused["credit_grant_id"], Value::Null);
        assert_eq!(refused["ledger_entry_id"], Value::Null);

        let serialized = serde_json::to_string(&json!([issued, refused])).expect("serialize");
        for forbidden in [
            "raw-voucher-code",
            "raw idempotency",
            "Authorization",
            "Cookie",
            "Bearer",
            "postgres://",
            "provider key",
            "virtual key",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "voucher issue runtime response must not expose {forbidden}"
            );
        }
    }

